!==============================================================!
!  Type TEnsemble                                              !
!==============================================================!

  type TEnsemble

    ! Number of ensemble
    integer :: EnsembleNumber

    ! I/O unit for result file
    type(TFile) :: resultFile

    ! I/O unit for running average result file
    type(TFile) :: runaveFile

    ! I/O unit for final result file
    type(TFile) :: errorsFile

    ! I/O unit for visualization file
    type(TFile) :: visualFile

    ! I/O unit for RDF file
    type(TFile) :: rdfFile

    ! I/O unit for ODF file
    type(TFile) :: odfFile

    ! I/O unit for KBI file
    type(TFile) :: kbiravFile
    type(TFile) :: kbirdfFile

    ! I/O unit for alpha2 file
    type(TFile) :: a2ravFile

    ! I/0 Unit for EinsteinCoef data
    type(TFile) :: ecoefFile !EinsteinCoef

    ! I/O unit for ThermoInt File
    type(TFile) :: thermointFile

    ! I/O unit for result ACF
    type(TFile) :: rescfFile

    ! I/O unit for visualization H-bonding file
    type(TFile) :: visualHBFile

    ! I/O unit for Profile file
    type(TFile) :: dcpFile

    !DC NOTE- I/O unit for cluster crit files
    type(TFile) :: ccFile
    !DC NOTE- I/O unit for cluster crit files
    type(TFile) :: ccgridFile


#if  TRANS == 1
    logical :: EConductivity
    logical :: MolarEnthConduct
    logical :: Bulkviscosity
#endif

    ! Maximum number of particles
    integer, pointer :: NPartMax
    integer, pointer :: NPartMaxFluct

    ! Number of particles in ensemble
    integer :: NPart, NPartInitial
    integer :: NPartLBound, NPartUBound

    ! Maximum number of test particles
    integer :: NTestMax

    ! Maximum number of fluctuating states
    integer :: NFluctMax

    ! Number of degrees of freedom
    integer :: NDFTran, NDFRot, NDF

    ! Mass of piston
    real(RK) :: PistonMass

    ! Positions and orientations of test particles
    real(RK), pointer, contiguous :: P0Test(:, :), Q0Test(:, :)

    ! Number of components in ensemble
    integer :: NComponents, NRealComponents, NGradInsComp

    ! Maximum numbers of sites in components
    integer :: NMIEnmMax, NTT68Max, NChargeMax, NDipoleMax, NQuadrupoleMax

    ! Components
    type(TComponent), pointer, contiguous :: Component(:)

    ! Interactions
    type(TInteraction), pointer, contiguous :: Interaction(:, :)

    ! Initial values of temperature, pressure, density, hamiltonian and enthalpy
    real(RK) :: RefTemperature, RefPressure, RefDensity, RefHamiltonian, RefEnthalpy, RefHill, RefRay

    ! Values of density, enthalpy, betaT, dHdp and their uncertainties
    ! in corresponding liquid simulation (for GE ensemble only)
    real(RK) :: LiqDensity, VarLiqDensity, LiqEnthalpy, VarLiqEnthalpy
    real(RK) :: LiqBetaT, VarLiqBetaT, LiqdHdP, VarLiqdHdP

    ! Current values of temperature, pressure, density
    real(RK) :: Temperature, Pressure, Density

    ! Velocity scaling factor for temperature control
    real(RK) :: scale

#if OSMOP > 0
    real(RK) :: OsmoticPressure
#if OSMOP == 2
    real(RK), pointer, contiguous :: VirialProfile(:)
    real(RK), pointer, contiguous :: PressureProfile(:)
#endif
#endif

    ! Virial
    real(RK) :: Virial

    ! Sampling of Dielectric Constant
    real(RK) :: DielectricConstant
    real(RK) :: TotalDipoleMoment,TotalDipoleMomentSquared

    ! Scale coefficients for MIEnm epsilon and sigma
    real(RK), pointer, contiguous :: ScaleEpsilon(:, :), ScaleSigma(:, :)

    ! Cutoff radii
    real(RK) :: RCutoffMIEnmMIEnm
    real(RK) :: RCutoffTT68TT68
    real(RK) :: RCutoffDipoleDipole
    real(RK) :: RCutoffDipoleQuadrupole
    real(RK) :: RCutoffQuadrupoleQuadrupole

    !RDF Hilfsvariable
    real(RK) :: RDFdr
    real(RK), pointer, contiguous :: RDFVSchale(:)
    real(RK), pointer, contiguous :: RDFValue(:)

    !ODF Hilfsvariable
    real(RK) :: dPhi
    real(RK) :: dGamma
    real(RK) :: dR
    real(RK), pointer, contiguous :: ODFvalue(:,:,:,:)

    !KBI Hilfsvariable
    real(RK) :: KBIdr
    real(RK), pointer, contiguous :: KBIVSchale(:)
    real(RK), pointer, contiguous :: KBIRDFextra(:,:)
    real(RK), pointer, contiguous :: KBIRDFvdVextra(:,:)
    real(RK), pointer, contiguous :: KBIRDFvdVshfextra(:,:)
    real(RK), pointer, contiguous :: TDF(:,:)
    real(RK), pointer, contiguous :: dTDF(:,:)
    real(RK), pointer, contiguous :: TDF0(:,:)
    real(RK), pointer, contiguous :: partialmolV(:,:)
    real(RK), pointer, contiguous :: partialmolV0(:,:)
    real(RK), pointer, contiguous :: dpartialmolV(:,:)
    integer                       :: KBIBlockCount

    !Alpha2 displacement
    real(RK), pointer, contiguous :: dispR2(:,:)
    real(RK), pointer, contiguous :: dispR2inv(:,:)
    real(RK), pointer, contiguous :: dispR4(:,:)
    real(RK), pointer, contiguous :: dispR2Ave(:)
    real(RK), pointer, contiguous :: dispR2invAve(:)
    real(RK), pointer, contiguous :: dispR4Ave(:)
    integer,  pointer, contiguous :: alpha2tempstep(:)
    integer                       :: alpha2aveCount

#if TRANS==1
    !EinsteinCoef definition
    real(RK), pointer, contiguous :: DselfEinstein(:,:,:) !some current sample of Dself coefficients, index 1 - length, 2 - number of samples, 3 - number of component
    real(RK), pointer, contiguous :: DselfEinsteinAve(:,:) !final averaged result for Dself coefficients, index 1 - length, 2 - number of component
    real(RK), pointer, contiguous :: OnsagerEinstein(:,:,:,:) !yep, 4 dim. array seems not very good, but let's try, index 1 - length, 2 - number of samples, 3,4 - elements of Onsager matrix
    real(RK), pointer, contiguous :: OnsagerEinsteinAve(:,:,:) !a little bit better than 4 dim. array, index 1 - length, 2,3 - elements of Onsager matrix
    integer,  pointer, contiguous :: EinsteinCoefTimeStep(:) !index 1 - length
    integer                       :: EinsteinCoefAveCount

    real(RK), pointer, contiguous :: DselfEinsteinCurrent(:)
    real(RK), pointer, contiguous :: OnsagerEinsteinCurrent(:,:)
    real(RK)                      :: ShearEinsteinCurrent

    real(RK), pointer, contiguous :: EinsteinShearAve(:)
    real(RK), pointer, contiguous :: EinsteinShear(:)
    real(RK), pointer, contiguous :: EinsteinShearInt(:)

    type(TAccumulator),pointer, contiguous :: EinsteinDSelfAcc(:)
    type(TAccumulator),pointer, contiguous :: EinsteinOnsagerAcc(:,:)
    type(TAccumulator)                     :: EinsteinShearAcc
#endif

    ! Characteristic dielectric constant for reaction field method
    real(RK) :: RFEpsilon

    ! Maximum cutoff radius
    real(RK) :: RCutoffMax2
    integer  :: NRCutoffMax

    ! Volume of simulation box and its derivatives
    real(RK) :: Volume0, Volume1, Volume2, Volume3, Volume4, Volume5

    ! Length of simulation box
    real(RK), pointer :: BoxLength

    ! Maximum allowed MC displacements
    real(RK) :: DispVol

    ! Number of MC attempts and successes
    integer :: NResizeAttempts, NResizeSuccesses
    integer :: NInsertAttempts, NInsertSuccesses
    integer :: NDeleteAttempts, NDeleteSuccesses
    integer :: NTransferAttempts, NTransferSuccesses

    ! Kinetic energy
    real(RK) :: EKin, EKinTran, EKinRot

    ! Potential energy
    real(RK) :: EPot

    ! d2EpotdV2
    real(RK) :: d2EpotdV2

    ! Potential energy of test particles
    real(RK), pointer, contiguous :: EPotTest(:)

    ! Long-range corrections
    real(RK) :: EPotCorrMIE, VirialCorrMIE, d2EpotdV2CorrMIE
    real(RK) :: EPotCorrTT68, VirialCorrTT68, d2EpotdV2CorrTT68
    real(RK) :: EPotCorrRF
    real(RK) :: EPotCorrRFPart, EPotCorrRFVol
    real(RK) :: VirialCorrRF

