!==============================================================!
!  Subroutine TEnsemble_Construct                              !
!==============================================================!

  subroutine TEnsemble_Construct( this, ne )

    implicit none

    ! Include MPI header
#if HBOND > 0
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif
#endif

    ! Declare arguments
    type(TEnsemble)     :: this
    integer, intent(in) :: ne

    ! Declare local variables
    integer :: i, j
    integer :: stat
    character( IOBufferLength ) :: str
    real(RK) :: EPot, d2EdV2, Virial
    integer :: counter

    ! Nullify EPot, d2EPotdV2 and Virial
    this%EPot = 0._RK
    this%d2EPotdV2 = 0._RK
    this%Virial = 0._RK

    ! Allocate simulation box length
    allocate( this%BoxLength, STAT = stat )
    call AllocationError( stat, 'simulation box length' )

    ! Allocate maximum number of particles
    allocate( this%NPartMax, STAT = stat )
    call AllocationError( stat, 'maximum number of particles' )
    allocate( this%NPartMaxFluct, STAT = stat )
    call AllocationError( stat, 'maximum number of particles' )


    ! Set number of ensemble
    this%EnsembleNumber = ne
    if (EnsembleType .eq. EnsembleTypeNPTSVC) then
    EnsembleNum = ne
    end if
    call LogWriteBlank
    write( IOBuffer, '(72("-"))')
    call LogWrite
    write( IOBuffer, '(T14, "Reading parameters of ensemble", I3)' ) this%EnsembleNumber
    call LogWrite

    ! Read temperature
    call FileReadParameter( this%RefTemperature, paramsFile%iounit , IdRefTemperature, .false. )

    if( .not. UseReducedUnits ) then
      this%RefTemperature = this%RefTemperature / UnitTemperature
    end if

    ! Read pressure
    if( EnsembleType .eq. EnsembleTypeGE ) then
      call FileReadParameter( this%RefPressure, paramsFile%iounit , IdPressure0, .false. )

      if( .not. UseReducedUnits ) then
        this%RefPressure = this%RefPressure * 1E6_RK / UnitPressure
      end if

    end if

    ! Read hamiltonian
    if( EnsembleType .eq. EnsembleTypeNVE .or. EnsembleType .eq. EnsembleTypeMUVL ) then !.and. SimulationType .eq. MonteCarlo
      call FileReadParameter( this%RefHamiltonian, paramsFile%iounit , IdRefHamiltonian, .false. )
      if( .not. UseReducedUnits ) then
        this%RefHamiltonian = this%RefHamiltonian / UnitEnergy / NAvogadro
      end if
    end if

    ! Read Enthalpy (NPH)
    if( EnsembleType .eq. EnsembleTypeNPH .or. EnsembleType .eq. EnsembleTypeMUPR ) then
      call FileReadParameter( this%RefEnthalpy, paramsFile%iounit , IdRefEnthalpy, .false. )
      if( .not. UseReducedUnits ) then
        this%RefEnthalpy = this%RefEnthalpy / UnitEnergy / NAvogadro
      end if
    end if

    if( ConstantPressure ) then
      call FileReadParameter( this%RefPressure, paramsFile%iounit , IdRefPressure, .false. )

      if( .not. UseReducedUnits ) then
        this%RefPressure = this%RefPressure * 1E6_RK / UnitPressure
      end if

    end if

    ! Read liquid simulation data
    if( EnsembleType .eq. EnsembleTypeGE ) then
      call FileReadParameter( this%LiqDensity, paramsFile%iounit , IdLiqDensity, .false. )

      if( .not. UseReducedUnits ) then
        this%LiqDensity = this%LiqDensity / UnitDensity
      end if

      call FileReadParameter( this%VarLiqDensity, paramsFile%iounit , IdVarLiqDensity, .false. )

      if( .not. UseReducedUnits ) then
        this%VarLiqDensity = this%VarLiqDensity / UnitDensity
      end if

      call FileReadParameter( this%LiqEnthalpy, paramsFile%iounit , IdLiqEnthalpy, .false. )

      if( .not. UseReducedUnits ) then
        this%LiqEnthalpy = this%LiqEnthalpy / ( UnitEnergy * NAvogadro )
      end if

      call FileReadParameter( this%VarLiqEnthalpy, paramsFile%iounit , IdVarLiqEnthalpy, .false. )

      if( .not. UseReducedUnits ) then
        this%VarLiqEnthalpy = this%VarLiqEnthalpy / ( UnitEnergy * NAvogadro )
      end if

      call FileReadParameter( this%LiqBetaT, paramsFile%iounit , IdLiqBetaT, .false. )

      if( .not. UseReducedUnits ) then
        this%LiqBetaT = this%LiqBetaT * UnitPressure * 1E-6_RK
      end if

      call FileReadParameter( this%VarLiqBetaT, paramsFile%iounit , IdVarLiqBetaT, .false. )

      if( .not. UseReducedUnits ) then
        this%VarLiqBetaT = this%VarLiqBetaT * UnitPressure * 1E-6_RK
      end if

      call FileReadParameter( this%LiqdHdP, paramsFile%iounit , IdLiqdHdP, .false. )

      if( .not. UseReducedUnits ) then
        this%LiqdHdP = this%LiqdHdP * UnitDensity
      end if

      call FileReadParameter( this%VarLiqdHdP, paramsFile%iounit , IdVarLiqdHdP, .false. )

      if( .not. UseReducedUnits ) then
        this%VarLiqdHdP = this%VarLiqdHdP * UnitDensity
      end if
    end if

    ! Read density
    call FileReadParameter( this%RefDensity, paramsFile%iounit , IdRefDensity, .false. )

    if( .not. UseReducedUnits ) then
      this%RefDensity = this%RefDensity / UnitDensity
    end if

    ! Update log file
    write( IOBuffer, '("Temperature: ",T26, F9.3, " K")' ) this%RefTemperature * UnitTemperature
    call LogWrite

    if( ConstantPressure ) then
      write( IOBuffer, '("Pressure: ",T26, F9.3, " MPa")' ) this%RefPressure * UnitPressure * 1E-6_RK
      call LogWrite
    end if

    if( EnsembleType .eq. EnsembleTypeGE ) then

      write( IOBuffer, '("Pressure0: ",T26, F12.6, " MPa")' ) this%RefPressure * UnitPressure * 1E-6_RK
      call LogWrite
      write( IOBuffer, '("Liquid density: ",T26, F12.6, " (", F13.6, ") mol/l")' ) &
&       this%LiqDensity * UnitDensity, this%VarLiqDensity * UnitDensity
      call LogWrite
      write( IOBuffer, '("Liquid enthalpy: ",T22, F16.6, " (", F13.6, ") J/mol")' ) this%LiqEnthalpy * UnitEnergy * NAvogadro, &
&       this%VarLiqEnthalpy * UnitEnergy * NAvogadro
      call LogWrite
      write( IOBuffer, '("Liquid betaT: ",T26, F12.6, " (", F13.6, ") 1/MPa")' ) this%LiqBetaT / UnitPressure * 1E6_RK, &
&       this%VarLiqBetaT / UnitPressure * 1E6_RK
      call LogWrite
      write( IOBuffer, '("Liquid dHdP: ",T26, F12.6, " (", F13.6, ") l/mol")' ) &
&       this%LiqdHdP / UnitDensity, this%VarLiqdHdP / UnitDensity
      call LogWrite
    end if

    write( IOBuffer, '("Density: ", T26, F9.3, " mol/l")' ) this%RefDensity * UnitDensity
    call LogWrite

    if( EnsembleType .eq. EnsembleTypeNPH ) then
      write( IOBuffer, '("Enthalpy: ",T26, F9.3, " J/mol")' ) this%RefEnthalpy * UnitEnergy * NAvogadro
      call LogWrite
    end if

    if( EnsembleType .eq. EnsembleTypeNVE .or. EnsembleType .eq. EnsembleTypeMUVL ) then
      write( IOBuffer, '("Hamiltonian: ",T26, F9.3, " J/mol")' ) this%RefHamiltonian * UnitEnergy * NAvogadro
      call LogWrite
    end if

    write( IOBuffer, '("Reduced temperature: ", T26, F12.6)' ) this%RefTemperature
    call LogWrite

    if( ConstantPressure ) then
      write( IOBuffer, '("Reduced pressure: ",T26, F12.6)' ) this%RefPressure
      call LogWrite
    end if

    if( EnsembleType .eq. EnsembleTypeGE ) then
      write( IOBuffer, '("Reduced pressure0: ",T26, F12.6)' ) this%RefPressure
      call LogWrite
      write( IOBuffer, '("Reduced liquid density: ",T29, F9.6, " (", F13.6, ")")' ) this%LiqDensity, this%VarLiqDensity
      call LogWrite
      write( IOBuffer, '("Reduced liquid enthalpy: ", T28, F10.6, " (", F13.6, ")")' ) &
&       this%LiqEnthalpy, this%VarLiqEnthalpy
      call LogWrite
      write( IOBuffer, '("Reduced liquid betaT: ",T26, F12.6, " (", F13.6, ")")' ) this%LiqBetaT, this%VarLiqBetaT
      call LogWrite
      write( IOBuffer, '("Reduced liquid dHdP: ",T26, F12.6, " (", F13.4, ")")' ) this%LiqdHdP, this%VarLiqdHdP
      call LogWrite
    end if

    write( IOBuffer, '("Reduced density: ",T26, F12.6)' ) this%RefDensity
    call LogWrite
    if( EnsembleType .eq. EnsembleTypeNPH .or. EnsembleType .eq. EnsembleTypeMUPR ) then
      write( IOBuffer, '("Reduced Enthalpy: ",T26, F12.6)' ) this%RefEnthalpy
      call LogWrite
    end if
    if( EnsembleType .eq. EnsembleTypeNVE .or. EnsembleType .eq. EnsembleTypeMUVL ) then
      write( IOBuffer, '("Reduced Hamiltonian: ",T26, F9.3, " J/mol")' ) this%RefHamiltonian
      call LogWrite
    end if

    ! Read mass of piston
    if( SimulationType .eq. MolecularDynamics .and. ConstantPressure ) then
      call FileReadParameter( this%PistonMass, paramsFile%iounit , IdPistonMass, .false. )
      write( IOBuffer, '("Mass of piston (reduced): ",T26, F15.9)' ) this%PistonMass
      call LogWrite
      write( IOBuffer, '("Mass of piston: ",T26, F15.9, " kg/m^4")' ) this%PistonMass * UnitMass / UnitLength**4
      call LogWrite
    end if

    ! Read calculation of residence time
    this%ResidenceTime = .false.
    if( SimulationType .eq. MolecularDynamics ) then
      call FileReadParameter( str, paramsFile%iounit , IdResidTime, .false., "no" )
      select case( str )
        case( 'YES', 'Yes', 'yes' )
          this%ResidenceTime = .true.
          write( IOBuffer, '("Calculation of residence time: ",A)' ) trim( str )
          call LogWrite
          write( IOBuffer, '("Maximum molecules in hydration shell: 10 (default in code)")' )
          call LogWrite
          call FileReadParameter( this%ResidComp1, paramsFile%iounit , IdResidComp1, .false. )
          call FileReadParameter( this%ResidSite1, paramsFile%iounit , IdResidSite1, .false. )
          call FileReadParameter( this%ResidComp2, paramsFile%iounit , IdResidComp2, .false. )
          call FileReadParameter( this%ResidSite2, paramsFile%iounit , IdResidSite2, .false. )
          write( IOBuffer, '("For component",I2,", site:",I2)' ) this%ResidComp1, this%ResidSite1
          call LogWrite
          write( IOBuffer, '("and component",I2,", site:",I2)' ) this%ResidComp2, this%ResidSite2
          call LogWrite
          call FileReadParameter( this%ResidPeriod, paramsFile%iounit , IdResidPeriod, .false. )
          write( IOBuffer, '("Update period / steps: ",T25, I6)' ) this%ResidPeriod
          call LogWrite
          call FileReadParameter( this%ResidLength, paramsFile%iounit , IdResidLength, .false. )
          write( IOBuffer, '("Pairing at distances lower: ",T28, F9.5)' ) this%ResidLength
          call LogWrite
          this%ResidLength = this%ResidLength / UnitLength * Angstroem
          call FileReadParameter( this%ResidBreak, paramsFile%iounit , IdResidBreak, .false., 0 )
          write( IOBuffer, '("Pairing can be invalid for steps: ",T28, I7)' ) this%ResidBreak
          call LogWrite

        case( 'NO', 'No', 'no')
          this%ResidenceTime = .false.
          write( IOBuffer, '("Calculation of residence time: ",A)' ) trim( str )
          call LogWrite
        case default
          call Error( 'Select yes/no for calculation of residence time'// ProgramFileName//ConfigFileExtension )
      end select
    end if

    ! Read whether to perform the MC equilibration in parallel
    call FileReadParameter( str, paramsFile%iounit , IdCommonEqui, .false., "no" )
    select case( str )
      case( 'YES', 'Yes', 'yes' )
        CommonEqui = .true.
        if( SimulationType .eq. MonteCarlo ) then
          write( IOBuffer, '("Common equilibration: ",T30, A)' ) trim( str )
          call LogWrite
#if MPI_VER > 0
          if ( mpiMCCommonGroups > 1) then
            !it does not make any sense to use mpiMCCommonGroups with CommonEqui
            !because mpiMCCommonGroups acts like CommonEqui just for standard equilibration and run
            CommonEqui = .false.
            write( IOBuffer, '("Common equilibration is set to: No because mpiMCCommonGroups > 1")' )
            call LogWrite
          end if
#endif
        endif
      case( 'NO', 'No', 'no')
        if( SimulationType .eq. MolecularDynamics ) then
          CommonEqui = .true.
          write(IOBuffer, '("MD simulation: Logical CommonEqui no is invalid, set to yes")' )
          call LogWrite
        else
          CommonEqui = .false.
          write( IOBuffer, '("Common equilibration: ",T30, A)' ) trim( str )
          call LogWrite
        endif
      case default
        call Error( 'Select yes/no for common equilibration '// ProgramFileName//ConfigFileExtension )
    end select

    ! Read initial number of particles in ensemble
    call FileReadParameter( this%NPart, paramsFile%iounit , IdNPart, .false. )
    if( OpenSystem .or. EnsembleType .eq. EnsembleTypeHA .or. SimulationType .eq. Gibbs) then
      this%NPartInitial = this%NPart
      this%NPartLBound = int( real( this%NPart, RK ) / 1.3_RK )
      this%NPartUBound = int( real( this%NPart, RK ) * 1.3_RK )
    end if

    ! Read number of components in ensemble
    call FileReadParameter( this%NComponents, paramsFile%iounit , IdNComponents, .false. )
    write( IOBuffer, '("Number of components:",T28, I3)' ) this%NComponents
    call LogWrite
    if( this%NComponents <= 0 ) then
      write( ErrorBuffer, '("There must be at least 1 component in ensemble", I2)' ) this%EnsembleNumber
      call Error
    end if

    if( this%NComponents > 999 ) call Error( 'Cannot work with more than 999 components on '//Hardware )

    !DC NOTE- Enasemble reading of parameters if not CC valid skip the reading
    this%isStopSimulation = .false.
    if (this%isCCSimulation .eqv. .true.) then
    !DC NOTE- if the visualization frequency is nonsense skip it is not valid CC case
      call FileReadParameter( this%CCFrequency, paramsFile%iounit , IdCCUpdateFrequency, .false., -10 )
      if( this%CCFrequency .gt. 0 ) then
        write( IOBuffer, '("Calculate Cluster Criteria and update each", I7, " time steps")' ) this%CCFrequency
      else
        this%isCCSimulation = .false.
        write( IOBuffer, '("Simulation does not have valid calculation frequency -> taken as normal ensemble ")' )
      end if
      call LogWrite

      if (this%isCCSimulation .eqv. .true.) then
        !DC NOTE- parse the criteria type
        call FileReadParameter( str, paramsFile%iounit , IdCcrittype, .false., 'None' )
        select case( str )
          case( 'GRIDVAP', 'VAPGRID', 'gridvap', 'vapgrid', 'Gridvap', 'Vapgrid' )
            this%Ccrittype = CCritTypeGridvap
            str = 'Grid vapor'

          case( 'GRIDLIQ', 'LIQGRID', 'gridliq', 'liqgrid', 'Gridliq', 'Liqgrid' )
            this%Ccrittype = CCritTypeGridliq
            str = 'Grid liquid'

          case default
            call Error( 'Invalid cluster criteria type argument: '//trim( str )//NEW_LINE('A')//'       should be one of: gridvap, gridliq' )

        end select

        call LogWriteBlank
        write( IOBuffer, '("Cluster Criteria options for enasemble:",T49, I3)' ) this%EnsembleNumber
        call LogWrite

        write( IOBuffer, '("Cluster criteria type: ",T51, A)' ) trim( str )
        call LogWrite

        call FileReadParameter( this%Ccritdist, paramsFile%iounit , IdCcritdist, .false., -1.0_RK )
        if (this%Ccritdist .le. 0.0_RK) then
          call Error('Invalid or missing '//trim(IdCcritdist)//NEW_LINE('A')//'       control option')
        else
          write( IOBuffer, '("Reading Cluster criteria dist: ",T45, F16.8)' ) this%Ccritdist
          call LogWrite
        end if

        call FileReadParameter( this%Ccount, paramsFile%iounit , IdCcount, .false. , -1 )
        if (this%Ccount .lt. 0) then
          call Error('Invalid or missing '//trim(IdCcount)//NEW_LINE('A')//'       control option should be >= 0')
        else
          write( IOBuffer, '("Reading molecule count for cluster",T46, I6)' ) this%Ccount
          call LogWrite
        end if

        call FileReadParameter( this%Cmax , paramsFile%iounit , IdCmax, .false., -1.0_RK )
        if (this%Cmax .lt. 0.0_RK .or. this%Cmax .gt. 100.0_RK) then
          call Error('Invalid or missing '//trim(IdCcritdist)//NEW_LINE('A')//'       control option should be within <0.0, 100.0> range')
        else
          write( IOBuffer, '("Reading maximal allowed cluster count",T47, E14.4, " %")' ) this%Cmax
          call LogWrite
        end if
      end if
    end if

#if  TRANS == 1

    call LogWriteBlank
    if ( parVersionNr .ge. 2.0_RK ) then
      call FileReadParameter( str , paramsFile%iounit , IdCorrFun, .false. , 'no' )
      select case( str )

      case( 'yes' , 'ok', 'ja' )
        this%CorrFunMode = .true.
        str = 'Include transport properties'

      case( 'no', 'nein' )
        this%CorrFunMode = .false.
        str = 'No transport properties'

      case default
        call Error( 'Unknown transport properties ('//trim(IdCorrFun)//'='//trim(str)//')' )
      end select
      write( IOBuffer, '("Transport properties:",T26, A)' ) trim(str)
      call LogWrite
    endif

    ! Read correlation function
    if( this%CorrfunMode ) then

      ! Calculate correlation function every n-th time step
      call FileReadParameter( this%NStepCorr , paramsFile%iounit , IdNStepcf )

      ! Read legth of the correlation function
      call FileReadParameter( this%NCorr , paramsFile%iounit , IdCorrlength )

      ! Read time span between correlations
      call FileReadParameter( this%NSpanCF , paramsFile%iounit , IdSpanCF )

      ! Calculation of the correlation function every n-th time step

      if(mod(this%NSpanCF, this%NStepCorr) .eq. 0) then
        this%NSpanCF = this%NSpanCF/this%NStepCorr
        this%NCorr = this%NCorr/this%NStepCorr
        write( IOBuffer, '("Correlation Functions (CF) are calculated every",I3,"-th time step")') this%NStepCorr
        call LogWrite
      else
        this%NStepCorr = 1
        write( IOBuffer, '("Correlation Functions (CF) are calculated every time step")')
        call LogWrite
        write( IOBuffer, '("StepsCorrfun is set to 1. SpanCorrfun is not divisible by StepsCorrfun")')
        call LogWrite
      endif

      this%TimeStepCorr = TimeStep * this%NStepCorr

      if(mod(this%NCorr, this%NSpanCF) .eq. 0) then
        write( IOBuffer, '("Length of CF:",T26, I7)' ) this%NCorr*this%NStepCorr
        call LogWrite
      else
        this%NCorr = (AINT(real( this%NCorr, RK )/real( this%NSpanCF, RK ))+1)*this%NSpanCF
        write( IOBuffer, '("Length of CF is extended to:",T40, I7)') this%NCorr*this%NStepCorr
        call LogWrite
      endif

      ! Correlation length output
      write( IOBuffer, '("Time Span between CF:",T26, I7)' ) this%NSpanCF*this%NStepCorr
      call LogWrite

      call FileReadParameter( this%Nviewcf , paramsFile%iounit , IdNviewcf )
      write( IOBuffer, '("Print CF each:",T26, I7)' ) this%Nviewcf
      call LogWrite

      if ( ((this%Nviewcf*this%NSpanCF*this%NStepCorr+this%NCorr*this%NStepCorr) > NSteps) .or. (this%Nviewcf .eq. 0) ) then
        write(IOBuffer, '("Warning: Updates of CF not sufficient - Output once at the end of simulation")')
        call LogWrite
        this%Nviewcf = int((NSteps-this%NCorr*this%NStepCorr)/(this%NSpanCF*this%NStepCorr))
        write( IOBuffer, '("Print after", I7," CF")' ) this%Nviewcf
        call LogWrite
      end if

      ! Read frequency of updating result file CF
      call FileReadParameter( BlockSizeCF , paramsFile%iounit , IdBlockSizeCF, .false., 1 )
      if( BlockSizeCF > 0 ) then
        write( IOBuffer, '("Transport results will be updated each", I3, " CF")' ) BlockSizeCF
      else
        write( IOBuffer, '("Transport results will not be created")' )
      end if
      call LogWrite

      ! Calculate max of Mmess for BlockSize determination
      this%Mmess = int((((NSteps+this%NStepCorr-1)/this%NStepCorr)-this%NCorr)/this%NSpanCF)

      if( BlockSizeCF > 0 ) then
        NBlocksMaxCF = int(this%Mmess / BlockSizeCF)
        NBlockSizesMaxCF = int( sqrt( real(NBlocksMaxCF,RK) ) )

      else
        NBlocksMaxCF = 0
        NBlockSizesMaxCF = 0
      end if

      ! Initialization of Mmess
      this%Mmess = 0
    end if
#endif

#if MPI_VER > 0
    if ((LongRange .eq. Ewald) .or. (LongRange .eq. PME))then
      allocate(this%NBox0,STAT=stat)
      call AllocationError( stat, 'NProcs' )
      allocate(this%NBox1,STAT=stat)
      call AllocationError( stat, 'NProcs' )
      allocate(this%NBox2,STAT=stat)
      call AllocationError( stat, 'NProcs' )
    end if
#endif
    ! Create components
    call CreateComponents( this )

    ! Calculate initial number of particles of each component
    call CalculateNPart( this )

    ! LongRange-Corrections need electro-neutral system
    call LongRangeCheck ( this )

    ! Calculate maximum numbers of sites in components
    call FindNSiteMax( this )

    ! calculate Hill energy for MUVL ensemble
    if( EnsembleType .eq. EnsembleTypeMUVL ) then
      do i = 1, this%NComponents
        this%Component(i)%Chempot0 = this%Component(i)%Chempot0 * this%RefTemperature
      end do
      this%RefHill = (this%RefHamiltonian - this%Component(1)%ChemPot0 ) * this%NPartInitial
    end if

    ! calculate Ray energy for MUPR ensemble
    if( EnsembleType .eq. EnsembleTypeMUPR ) then
      do i = 1, this%NComponents
        this%Component(i)%Chempot0 = this%Component(i)%Chempot0 * this%RefTemperature
      end do
      this%RefRay = (this%RefEnthalpy - this%Component(1)%ChemPot0 ) * this%NPartInitial
    end if

    ! Charge sites need center of mass cutoff
    if(( CutoffMode .ne. CenterofMass ) .and. ( this%NChargeMax .gt. 0 )) &
&     call Error( 'Center of mass correction is necessary when using charges')

    ! Allocate arrays
    call Allocate( this )

    ! Read scale coefficients for MIEnm epsilon and sigma
    if( this%NMIEnmMax > 0 ) then
        this%ScaleSigma(:, :) = 1._RK
        this%ScaleEpsilon(:, :) = 1._RK
        do i = 1, this%NRealComponents - 1
          do j = i + 1, this%NRealComponents
            call FileReadParameter( this%ScaleSigma(i, j), paramsFile%iounit , IdScaleSigma, .false. )
            if( i /= j ) this%ScaleSigma(j, i) = this%ScaleSigma(i, j)
            call FileReadParameter( this%ScaleEpsilon(i, j), paramsFile%iounit , IdScaleEpsilon, .false. )
            if( i /= j ) this%ScaleEpsilon(j, i) = this%ScaleEpsilon(i, j)
            write( IOBuffer, &
&             '(A, "-", A, " ", A, " interaction:  eta =", F6.3, ", xi =", F6.3)' ) &
&             trim( this%Component(i)%PotModFileName ), &
&             trim( this%Component(j)%PotModFileName ), &
&            trim(LJorMIE), this%ScaleSigma(i, j), this%ScaleEpsilon(i, j)
            call LogWrite
          end do
        end do
        ! Setting scale coefficients for ThermoInt-Components
        j = this%NRealComponents+1
        do i = 1, this%NRealComponents
          if (this%Component(i)%ChemPotMethod == ChemPotMethodThermoInt ) then
            this%ScaleSigma(j, :) = this%ScaleSigma(i, :)
            this%ScaleSigma(:, j) = this%ScaleSigma(:, i)
            this%ScaleEpsilon(j, :) = this%ScaleEpsilon(i, :)
            this%ScaleEpsilon(:, j) = this%ScaleEpsilon(:, i)
            j = j+1
          end if
        end do
    end if

#if HBOND > 0
    call FileReadParameter( this%NHBondCrit, paramsFile%iounit , IdNHBonds, .false. )
    call LogWriteBlank
    write( IOBuffer, '("Reading ", I2, " H-Bonding criteria:")' ) this%NHBondCrit
    call LogWrite
    write( IOBuffer, '("CritNo.  AccComp  AccAccSite AccDonSite  DonComp  DonAccSite  DonDonSite  DistCrit1  DistCrit2  AngleCrit")' )
    call LogWrite

    !Allocate H-Bond Arrays
    allocate( this%AccComp( this%NHBondCrit ), STAT = stat )
    call AllocationError( stat, 'components', this%NHBondCrit )
    allocate( this%AccAccSite( this%NHBondCrit ), STAT = stat )
    call AllocationError( stat, 'components', this%NHBondCrit )
    allocate( this%AccDonSite( this%NHBondCrit ), STAT = stat )
    call AllocationError( stat, 'components', this%NHBondCrit )
    allocate( this%DonComp( this%NHBondCrit ), STAT = stat )
    call AllocationError( stat, 'components', this%NHBondCrit )
    allocate( this%DonAccSite( this%NHBondCrit ), STAT = stat )
    call AllocationError( stat, 'components', this%NHBondCrit )
    allocate( this%DonDonSite( this%NHBondCrit ), STAT = stat )
    call AllocationError( stat, 'components', this%NHBondCrit )
    allocate( this%DistCrit1( this%NHBondCrit ), STAT = stat )
    call AllocationError( stat, 'components', this%NHBondCrit )
    allocate( this%DistCrit2( this%NHBondCrit ), STAT = stat )
    call AllocationError( stat, 'components', this%NHBondCrit )
    allocate( this%AngleCrit( this%NHBondCrit ), STAT = stat )
    call AllocationError( stat, 'components', this%NHBondCrit )

    if (RootProc) then
      do i = 1, this%NHBondCrit
        read( paramsFile%iounit, * ) this%AccComp(i), this%AccAccSite(i), this%AccDonSite(i), this%DonComp(i), &
  &           this%DonAccSite(i), this%DonDonSite(i), this%DistCrit1(i), this%DistCrit2(i), this%AngleCrit(i)
        if ( (this%AngleCrit(i) .le. 0._RK) .or. (this%AngleCrit(i) .gt. 180._RK) ) then
          call Error('Angle of the H-Bonding criteria(s) should be between 0 and 180.')
        else
          this%AngleCrit(i) = cos(this%AngleCrit(i)*PI/180._RK)
        end if
        write( IOBuffer, '("  ", I3, "      ", I2, "         ", I2, "         ", I2, "       ", I2, "         ", I2, "         ", I2, "     ", F9.4, "   ", F9.4, "   ", F9.4)' ) i, &
  &              this%AccComp(i), this%AccAccSite(i), this%AccDonSite(i), this%DonComp(i), this%DonAccSite(i), this%DonDonSite(i), &
  &              this%DistCrit1(i), this%DistCrit2(i), this%AngleCrit(i)
        call LogWrite
        if (.not. UseReducedUnits ) then
          this%DistCrit1(i) = this%DistCrit1(i)*Angstroem/UnitLength
          this%DistCrit2(i) = this%DistCrit2(i)*Angstroem/UnitLength
        end if
      end do
    end if
#if MPI_VER > 0
    call MPI_Bcast( this%AccComp,    this%NHBondCrit, MPI_INTEGER, NRootProc, Communicator, ierror )
    call MPI_Bcast( this%AccAccSite, this%NHBondCrit, MPI_INTEGER, NRootProc, Communicator, ierror )
    call MPI_Bcast( this%AccDonSite, this%NHBondCrit, MPI_INTEGER, NRootProc, Communicator, ierror )
    call MPI_Bcast( this%DonComp,    this%NHBondCrit, MPI_INTEGER, NRootProc, Communicator, ierror )
    call MPI_Bcast( this%DonAccSite, this%NHBondCrit, MPI_INTEGER, NRootProc, Communicator, ierror )
    call MPI_Bcast( this%DonDonSite, this%NHBondCrit, MPI_INTEGER, NRootProc, Communicator, ierror )
    call MPI_Bcast( this%DistCrit1,  this%NHBondCrit, MPI_RK, NRootProc, Communicator, ierror )
    call MPI_Bcast( this%DistCrit2,  this%NHBondCrit, MPI_RK, NRootProc, Communicator, ierror )
    call MPI_Bcast( this%AngleCrit,  this%NHBondCrit, MPI_RK, NRootProc, Communicator, ierror )
#endif
#endif

    ! Read cutoff radii
    this%RCutoffMIEnmMIEnm = 0._RK
    this%RCutoffTT68TT68 = 0._RK
    this%RCutoffDipoleDipole = 0._RK
    this%RCutoffDipoleQuadrupole = 0._RK
    this%RCutoffQuadrupoleQuadrupole = 0._RK
    if( CutoffMode .eq. CenterofMass ) then
      if( this%NMIEnmMax > 0 ) then
        call FileReadParameter( this%RCutoffMIEnmMIEnm, paramsFile%iounit , IdRCutoffCOM, .false. )
        if (this%RCutoffMIEnmMIEnm < 0._RK) then
          this%RCutoffMIEnmMIEnm = 0.9*0.5*(this%NPart / &
  &          (NAvogadro*this%RefDensity*UnitDensity*1000))**(1._RK/3._RK)/UnitLength
        end if
        call LogWriteBlank
        write( IOBuffer, '("Reduced center of mass cutoff radius: ",T45, F6.3)' ) this%RCutoffMIEnmMIEnm
        call LogWrite
        this%RCutoffDipoleDipole = this%RCutoffMIEnmMIEnm
        this%RCutoffDipoleQuadrupole = this%RCutoffMIEnmMIEnm
        this%RCutoffQuadrupoleQuadrupole = this%RCutoffMIEnmMIEnm
      endif
      if( this%NTT68Max > 0 ) then
        call FileReadParameter( this%RCutoffTT68TT68, paramsFile%iounit , IdRCutoffCOM, .false. )
        if (this%RCutoffTT68TT68 < 0._RK) then
          this%RCutoffTT68TT68 = 0.9*0.5*(this%NPart / &
        &          (NAvogadro*this%RefDensity*UnitDensity*1000))**(1._RK/3._RK)/UnitLength
        end if
        call LogWriteBlank
        write( IOBuffer, '("Reduced center of mass cutoff radius: ",T45, F6.3)' ) this%RCutoffTT68TT68
        call LogWrite
        this%RCutoffDipoleDipole = this%RCutoffTT68TT68
        this%RCutoffDipoleQuadrupole = this%RCutoffTT68TT68
        this%RCutoffQuadrupoleQuadrupole = this%RCutoffTT68TT68
      endif

    else

      if( this%NMIEnmMax > 0 ) then
        call FileReadParameter( this%RCutoffMIEnmMIEnm, paramsFile%iounit , IdRCutoffMIEnmMIEnm, .false. )
        write( IOBuffer, '(A, " cutoff radius: ",T45, F6.3, " sigma")' ) trim(LJorMIE), this%RCutoffMIEnmMIEnm
        call LogWrite
      end if

      if( this%NTT68Max > 0 ) then
        call FileReadParameter( this%RCutoffTT68TT68, paramsFile%iounit , IdRCutoffTT68TT68, .false. )
        write( IOBuffer, '("TT68 cutoff radius: ",T42, F8.3)' )  this%RCutoffTT68TT68
        call LogWrite
      end if

      if( this%NDipoleMax > 0 ) then
        call FileReadParameter( this%RCutoffDipoleDipole, paramsFile%iounit , IdRCutoffDipoleDipole, .false. )
        write( IOBuffer, '("Reduced dipole-dipole cutoff radius: ",T42, F8.3)' ) this%RCutoffDipoleDipole
        call LogWrite

        if( this%NQuadrupoleMax > 0 ) then
          call FileReadParameter( this%RCutoffDipoleQuadrupole, paramsFile%iounit , IdRCutoffDipoleQuadrupole, .false. )
          write( IOBuffer, '("Reduced dipole-quadrupole cutoff radius: ",T42, F8.3)' ) this%RCutoffDipoleQuadrupole
          call LogWrite
        end if

      end if

      if( this%NQuadrupoleMax > 0 ) then
        call FileReadParameter( this%RCutoffQuadrupoleQuadrupole, paramsFile%iounit , IdRCutoffQuadrupoleQuadrupole, .false. )
        write( IOBuffer, '("Reduced quadrupole-quadrupole cutoff radius: ",T42, F8.3)' ) this%RCutoffQuadrupoleQuadrupole
        call LogWrite
      end if
    end if

    ! Read characteristic dielectric constant
    this%RFEpsilon = 0._RK

    if(( this%NDipoleMax > 0 ) .or. ( this%NChargeMax > 0 )) then
      call LogWriteBlank
      call FileReadParameter( this%RFEpsilon, paramsFile%iounit , IdRFEpsilon, .false. )
      write( IOBuffer, '("Characteristic dielectric constant: ",T41, E16.5)' ) this%RFEpsilon
      call LogWrite
    end if

! Initialization of the transport property "Conductivity" and "EConductivity"
#if TRANS == 1

     this%Bulkviscosity = .true.
     this%MolarEnthConduct = .true.
     this%EConductivity = .false.

     if (EnsembleType .eq. EnsembleTypeNVE) then
         this%Bulkviscosity = .true.
     else
         this%Bulkviscosity = .false.
     end if


!      if (LongRange .eq. Rfield) then
!         this%Conductivity = .true.
!      else
!         this%Conductivity = .false.
!      end if


      if ( this%NComponents > 1 .and. LongRange .eq. RField) then
       do i = 1, this%NComponents
            if (this%Component(i)%PartialMolarEnthalpy .eq. 0._RK) then
               this%MolarEnthConduct = .false.
            end if
       end do
      end if


      if ((LongRange .eq. Ewald) .and. (TransMethod .eq. GreenKubo)) then
        do i = 1, this%NComponents
          if ( abs(this%Component(i)%Molecule%Charge) .gt. 1e-7) then
             this%EConductivity = .true.
          end if
        end do
      end if

#endif

    ! Create potentials
    call CreatePotentials( this )

    ! Calculate long-range corrections
    call CalculateCorr( this )
    call LogWriteBlank
    write( IOBuffer, '("Cutoff correction to")' )
    call LogWrite

    if( this%NMIEnmMax > 0 ) then
      if ( SimulationType .eq. MonteCarlo .and. (.not.(mpiMCCommonGroups > 0)))  then
        write( IOBuffer, '("- potential energy from ", A, T44, F12.8)' ) LJorMIE, this%EPotCorrMIE  / this%NPart

      else
        write( IOBuffer, '("- potential energy from ", A, T44, F12.8)' ) LJorMIE, this%EPotCorrMIE * Nprocs/ this%NPart
      endif
    endif

    if( this%NTT68Max > 0 ) then
      if ( SimulationType .eq. MonteCarlo .and. (.not.(mpiMCCommonGroups > 0)))  then
        write( IOBuffer, '("- potential energy from TT68", T44, F12.8)' ) this%EPotCorrTT68  / this%NPart

      else
        write( IOBuffer, '("- potential energy from TT68", T44, F12.8)' )  this%EPotCorrTT68 * Nprocs/ this%NPart
      endif
    endif

    call LogWrite

    if( this%NMIEnmMax > 0 ) then
      if ( SimulationType .eq. MonteCarlo .and. (.not.(mpiMCCommonGroups > 0)))  then
        write( IOBuffer, '("- pressure from ", A, T44, F12.8)' ) LJorMIE, this%VirialCorrMIE  / this%NPart
      else
        write( IOBuffer, '("- pressure from ", A, T44, F12.8)' ) LJorMIE, this%VirialCorrMIE * NProcs / this%NPart
      endif
    endif

    if( this%NTT68Max > 0 ) then
      if ( SimulationType .eq. MonteCarlo .and. (.not.(mpiMCCommonGroups > 0)))  then
        write( IOBuffer, '("- pressure from TT68", T44, F12.8)' )  this%VirialCorrTT68  / this%NPart
      else
        write( IOBuffer, '("- pressure from TT68", T44, F12.8)' )  this%VirialCorrTT68 * NProcs / this%NPart
      endif
    endif

    call LogWrite

    do i = 1, this%NRealComponents
      if( this%NMIEnmMax > 0 ) then
        write( IOBuffer, '("- chem. pot. of ", A, " from ", A, T44, F12.8)' ) trim( this%Component(i)%PotModFileName ), &
  &        trim(LJorMIE), this%Component(i)%EPotTestCorrMIE
        call LogWrite
      endif

      if( this%NTT68Max > 0 ) then
        write( IOBuffer, '("- chem. pot. of ", A, " from TT68", T44, F12.8)' ) trim( this%Component(i)%PotModFileName ), &
  &        this%Component(i)%EPotTestCorrTT68
        call LogWrite
      endif
    end do

    if ( SimulationType .eq. MonteCarlo .and. (.not.(mpiMCCommonGroups > 0)))  then
      write( IOBuffer, '("- potential energy from reaction field (RF)",T44, F12.8)' ) &
&       this%EPotCorrRF  / this%NPart
    else
      write( IOBuffer, '("- potential energy from reaction field (RF)",T44, F12.8)' ) &
&       this%EPotCorrRF / NProcs / this%NPart
    endif
    call LogWrite

    if ( SimulationType .eq. MonteCarlo .and. (.not.(mpiMCCommonGroups > 0)))  then
       write( IOBuffer, '("- pressure from reaction field:",T44, F12.8)' ) this%VirialCorrRF / this%NPart
    else
       write( IOBuffer, '("- pressure from reaction field:",T44, F12.8)' ) this%VirialCorrRF * NProcs / this%NPart
    endif
    call LogWrite

    do i = 1, this%NRealComponents
      write( IOBuffer, '("- chem. pot. of ", A, " from RF",T44, F12.8)' ) trim( this%Component(i)%PotModFileName ), &
&       this%Component(i)%EPotTestCorrRF
      call LogWrite
    end do

    ! Calculate maximum cutoff radius
    if( this%NDipoleMax > 0 ) then
      this%RCutoffMax2 = max(this%RCutoffMax2, 2._RK * this%RCutoffDipoleDipole )

      if( this%NQuadrupoleMax > 0 ) then
        this%RCutoffMax2 = max(this%RCutoffMax2, 2._RK * this%RCutoffDipoleQuadrupole )
      end if

    end if

    if( this%NQuadrupoleMax > 0 ) then
      this%RCutoffMax2 = max(this%RCutoffMax2, 2._RK * this%RCutoffQuadrupoleQuadrupole )
    end if

    if( .not. Restart ) then

      ! Update all BoxLength-dependent constants
      call UpdateBoxLength( this )

      ! Abort, if maximum cutoff larger than boxlength
      if (this%RCutoffMax2 > this%BoxLength) then
          write(ErrorBuffer, '(A, f0.6, A, f0.6, A, I0.1)') "Cut-off diameter (", this%RCutoffMax2 , &
                ") is larger than the boxsize (", this%BoxLength ,") for ensemble ", this%EnsembleNumber
          call Error(ErrorBuffer)
      end if

      ! Set initial positions of particles in simulation box
      call InitPositions( this )

      ! Set initial orientations of particles in simulation box
      call InitOrientations( this )

      ! Calculate initial energies for the Ewald Summation
      if (LongRange .eq. Ewald) then

         if (this%KappaL .eq. 0.) then
            this%Kappa = sqrt(PI) * (4.0_RK*this%NPart / this%Volume0**2)**(1._RK/6._RK)
            this%KappaL = this%Kappa*this%BoxLength
         else
            this%Kappa = this%KappaL/this%BoxLength   !Boxlength bereits normiert
         end if

         do i=1,this%NComponents
           do j=1,this%NComponents
             this%Interaction(i,j)%Kappa = this%Kappa
           end do
         end do

         call EwaldSelfTerm( this )

        ! Memory Allocation for Ewald Summation
         nullify ( this%U_fourierLocal )
         nullify ( this%SSin )
         nullify ( this%SCos )
         nullify ( this%rold )
         nullify ( this%Vec2 )

         allocate(this%U_fourierLocal(this%BoxenAnzahlMax),STAT=stat)
         if(stat >0) write(*,*) 'Allocation Error U_fourier'
         allocate(this%SSin(this%BoxenAnzahlMax),STAT=stat)
         if(stat >0) write(*,*) 'Allocation Error SSin'
         allocate(this%SCos(this%BoxenAnzahlMax),STAT=stat)
         if(stat >0) write(*,*) 'Allocation Error SCos'
         allocate(this%rold(5,3),STAT=stat)
         if(stat >0) write(*,*) 'Allocation Error rold'
         allocate(this%Vec2(this%BoxenAnzahlMax),STAT=stat)
         if(stat >0) write(*,*) 'Allocation Error Vec2'

#if SPME > 0
      else if (LongRange .eq. PME) then

         if (this%KappaL .eq. 0.) then
            this%Kappa = sqrt(PI) * (4.0_RK*this%NPart / this%Volume0**2)**(1._RK/6._RK)
            this%KappaL = this%Kappa*this%BoxLength
         else
            this%Kappa = this%KappaL/this%BoxLength   !Boxlength bereits normiert
         end if

         do i=1,this%NComponents
           do j=1,this%NComponents
             this%Interaction(i,j)%Kappa = this%Kappa
           end do
         end do

         allocate(this%bsp_arr(this%gridx+5),STAT=stat)
         if(stat >0) write(*,*) 'Allocation Error bsp_arr'
         allocate(this%bsp_modx(this%gridx+5),STAT=stat)
         if(stat >0) write(*,*) 'Allocation Error bsp_modx'
         allocate(this%bsp_mody(this%gridy+5),STAT=stat)
         if(stat >0) write(*,*) 'Allocation Error bsp_mody'
         allocate(this%bsp_modz(this%gridz+5),STAT=stat)
         if(stat >0) write(*,*) 'Allocation Error bsp_modz'

! Setup SPME calculation
         call PMESetup (this)
#endif
      else if (LongRange .eq. ExtRField) then
         do i=1,this%NComponents
           do j=1,this%NComponents
             this%Interaction(i,j)%DebyeLen = this%DebyeLen
           end do
         end do

      else if (LongRange .eq. Rodgers) then
         do i=1,this%NComponents
           do j=1,this%NComponents
             this%Interaction(i,j)%Kappa = this%Kappa
           end do
         end do
      end if

      if( SimulationType .eq. MolecularDynamics .and. .not. MCOverlapReduction ) then

        ! Initialize molecular dynamics simulation
        call InitMolecularDynamics( this, .false. )

      else

        ! Set temperature
        this%Temperature = this%RefTemperature

        ! Convert molecular coordinates to atom positions
        call Mol2Atom( this )
        ! Set potential energy

        call Energy( this, this%EPot, d2EdV2, Virial )

        ! Set initial values of maximum allowed MC displacements
        this%DispVol = DispVolStart
        do i = 1, this%NRealComponents
          this%Component(i)%DispTran = DispTranStart
          this%Component(i)%DispRot = DispRotStart
        end do

      end if
    else        ! Restart
      ! Calculate initial energies for the Ewald Summation
    end if         ! Restart

    ! Set I/O unit numbers
    i = FilesPerEnsemble * this%EnsembleNumber
    this%resultFile%iounit    = resultFile%iounit    + i
    this%runaveFile%iounit    = runaveFile%iounit    + i
    this%errorsFile%iounit    = errorsFile%iounit    + i
    this%visualFile%iounit    = visualFile%iounit    + i
    this%rdfFile%iounit       = rdfFile%iounit       + i
    this%thermointFile%iounit = thermointFile%iounit + i
    this%rescfFile%iounit     = rescfFile%iounit     + i
    this%visualHBFile%iounit  = visualHBFile%iounit  + i
    this%dcpFile%iounit       = dcpFile%iounit       + i
    this%kbiravFile%iounit    = kbiravFile%iounit    + i
    this%kbirdfFile%iounit    = kbirdfFile%iounit    + i
    this%a2ravFile%iounit     = a2ravFile%iounit     + i
    this%ecoefFile%iounit     = ecoefFile%iounit     + i  !EinsteinCoef
    this%ccFile%iounit        = ccFile%iounit        + i !DC edit
    this%ccgridFile%iounit    = ccgridFile%iounit    + i !DC edit

    ! Calculate RDF VSchale
    if( this%NMIEnmMax > 0 ) then
      this%RDFdr = this%RCutoffMIEnmMIEnm / RDFNumberShells
    end if
    if( this%NTT68Max > 0 ) then
      this%RDFdr = this%RCutoffTT68TT68 / RDFNumberShells
    end if
    do i = 1, RDFNumberShells
      this%RDFVSchale(i) = 4./3.*pi* this%RDFdr**3 *(i**3 - (i-1)**3)
    end do

    ! Calculate bin sizes for ODF
    this%dR = this%RCutoffDipoleDipole / nR
    this%dPhi = 2._RK / nPhi
    this%dGamma = pi / nGamma

    ! Calculate KBI VSchale
    this%KBIdr = (0.5*(this%NPart / (NAvogadro*this%RefDensity*UnitDensity*1000))**(1._RK/3._RK)/UnitLength) &
&                / KBINumberShells
    do i = 1, KBINumberShells
       this%KBIVSchale(i) = 4./3.*pi* this%KBIdr**3 *(i**3 - (i-1)**3)
    end do

    do i = KBINumberShells+1, KBINShellsCubeEdge !Volume correction for shells outside simulation box
       this%KBIVSchale(i) = 2.*pi*this%KBIdr**3*(2./3.*i**3-(i-KBINumberShells)**2*(2*i+KBINumberShells)-2./3.*(i-1)**3+(i-1-KBINumberShells)**2*(2*(i-1)+KBINumberShells))
    end do

    write( IOBuffer, '(T15, "Reading ensemble ", I3, " successful")') this%EnsembleNumber
    call LogWrite
    write( IOBuffer, '(72("-"))')
    call LogWrite

  if (this%isCCSimulation .eqv. .true.) then
    !DC NOTE- prepare the gird neighbours if it is needed
    !DC BEWARE this relies on the box lenght to calculate the grid
    if (this%Ccrittype .eq. CCritTypeGridliq .or. this%Ccrittype .eq. CCritTypeGridvap ) then

      this%NGridPoints = 1+ int(this%BoxLength/this%Ccritdist)
      this%NGridPointsAll = this%NGridPoints**3
      !DC OPTIM- at this moment 21.08.2019 the cmax is used only by root so this is wasting on the rest of PU
      this%Cmax = int(this%NGridPointsAll * (this%Cmax/100.0))

      this%NGridPoints1 = ProcRange( this%NGridPointsAll, this%NGridPoints0, this%NGridPoints2 )

      if (NProc .eq. NRootProc) then
        !DC NOTE- OPEN section for .grid file
        write( IOBuffer, '(I16)' ) this%EnsembleNumber
        call FileRewrite(this%ccgridFile, trim( OutputNameTag )//'_'//'CC'//'_'//trim( adjustl( IOBuffer ) )//GridFileExtension )

        write( IOBuffer, '("# Cluster criteria grid output file generated by D. Celny into ms2")' )
        call FileWrite(this%ccgridFile)
        call FileWriteBlank(this%ccgridFile)

        !DC NOTE- UPDATE section for .grid file
        write( IOBuffer, '("# Edge:", I6," NGridPoints:", I6," New Cmax criteria number:", I6)' ) this%NGridPoints, this%NGridPointsAll, int(this%Cmax)
        call FileWrite(this%ccgridFile)
        write( IOBuffer, '("# Debug boxsize: ", F16.10," griddistance: ", F16.10)' ) this%BoxLength, (this%Ccritdist/this%BoxLength)
        call FileWrite(this%ccgridFile)
        write( IOBuffer, '("# position    X,        Y,        Z    [reduced box_size] ")' )
        call FileWrite(this%ccgridFile)

        !DC NOTE- the grid is recalculated again as it is done on root processor preventing mixed writeous of the grid
        do i = 0 , this%NGridPointsAll - 1
          write( IOBuffer, '( F16.10, F16.10, F16.10)' ) -0.5_RK + (this%Ccritdist/this%BoxLength) * MOD(i, this%NGridPoints),&
          &                                              -0.5_RK + (this%Ccritdist/this%BoxLength) * (MOD(i, this%NGridPoints**2)/ this%NGridPoints),&
          &                                              -0.5_RK + (this%Ccritdist/this%BoxLength) * (i / this%NGridPoints**2 )
          call FileWrite(this%ccgridFile)
        end do
        call FileWriteBlank(this%ccgridFile)

        !DC NOTE- CLOSE section for .grid file
        call FileClose(this%ccgridFile)

      end if
    end if
  end if

#if MPI_VER > 0
! Abortion of simulation run due to wall-time Constraints
    call time_left(time_limit)
#endif


  end subroutine TEnsemble_Construct


!==============================================================!
!  Subroutine TEnsemble_ConstructSVC                           !
!==============================================================!

  subroutine TEnsemble_ConstructSVC( this, ne )

    implicit none

    ! Declare arguments
    type(TEnsemble)     :: this
    integer, intent(in) :: ne

    ! Declare local variables
    integer                   :: i, j
    integer                   :: stat
    type(TComponent), pointer :: pc
    character(FileNameLength) :: PotModFileName
    real(RK)                  :: scaleSigma, scaleEpsilon

    ! Allocate simulation box length
    allocate( this%BoxLength, STAT = stat )
    call AllocationError( stat, 'simulation box length' )

    ! Allocate maximum number of particles
    allocate( this%NPartMax, STAT = stat )
    call AllocationError( stat, 'maximum number of particles' )

    ! Set number of ensemble
    this%EnsembleNumber = ne
    call LogWriteBlank
    write( IOBuffer, '(72("-"))')
    call LogWrite
    write( IOBuffer, '(T14, "Reading parameters of ensemble", I3)' ) this%EnsembleNumber
    call LogWrite

    ! Read temperature
    call FileReadParameter( this%Temperature, paramsFile%iounit , IdRefTemperature, .false. )

    if( .not. UseReducedUnits ) then
      this%Temperature = this%Temperature / UnitTemperature
    end if

    ! Update log file
    write( IOBuffer, '("Temperature: ",T26, F9.3, " K")' ) this%RefTemperature * UnitTemperature
    call LogWrite
    write( IOBuffer, '("Reduced temperature: ",T26, F12.6)' ) this%RefTemperature
    call LogWrite

    ! Read number of components in ensemble
    call FileReadParameter( this%NComponents, paramsFile%iounit , IdNComponents, .false. )
    write( IOBuffer, '("Number of components:",T28, I3)' ) this%NComponents
    call LogWrite

    if( this%NComponents <= 0 ) then
      write( ErrorBuffer, '("There must be at least 1 component in ensemble", I2)' ) &
&       this%EnsembleNumber
      call Error
    end if

    if( this%NComponents > 999 ) call Error( 'Cannot work with more than 999 components on '//Hardware )

    ! Create components
    this%NComponents = 2 * this%NComponents
    allocate( this%Component(this%NComponents), STAT = stat )
    call AllocationError( stat, 'components', this%NComponents )

    do i = 1, this%NComponents, 2

      ! Read file name for potential model
      call FileReadParameter( PotModFileName, paramsFile%iounit , IdPotModFileName, .false. )
      call Construct( this%Component(i), PotModFileName )
      call Construct( this%Component(i+1), PotModFileName )

      if( (this%Component(i)%ChemPotMethod .eq. ChemPotMethodWidom) .and. (LongRange .ne. RField) ) &
&     call Error( 'Widom cannot be used with Ewald Summation or its Deriavtes ' )

    end do

    ! Calculate number of particles in each process
     do i = 1, this%NComponents
      pc => this%Component(i)
      pc%NPart = NOrient ! jeder Core berechnet dasselbe
      pc%NPart1 = NOrient
      pc%NPart0 = 1
      pc%NPart2 = NOrient
      !pc%NPart1 = ProcRange( pc%NPart, pc%NPart0, pc%NPart2 ) ! Parallelisierung (alt)
    end do

    this%NPartMax = NOrient
    this%NTestMax = 0

    ! Calculate maximum numbers of sites in components
    call FindNSiteMax( this )

    ! Allocate arrays
    call Allocate( this )

    ! Read scale coefficients for MIEnm epsilon and sigma
    if( this%NMIEnmMax > 0 ) then
      this%ScaleSigma(:, :) = 1._RK
      this%ScaleEpsilon(:, :) = 1._RK
      do i = 1, this%NComponents - 2, 2
        do j = i + 2, this%NComponents, 2

          call FileReadParameter( scaleSigma, paramsFile%iounit , IdScaleSigma, .false. )
          this%ScaleSigma(i:i+1, j:j+1) = scaleSigma

          if( i /= j ) this%ScaleSigma(j:j+1, i:i+1) = scaleSigma
          call FileReadParameter( scaleEpsilon, paramsFile%iounit , IdScaleEpsilon, .false. )
          this%ScaleEpsilon(i:i+1, j:j+1) = scaleEpsilon

          if( i /= j ) this%ScaleEpsilon(j:j+1, i:i+1) = scaleEpsilon
          write( IOBuffer, '(A, "-", A, " ", A, " interaction:  eta =", F6.3, ", xi =", F6.3)' ) &
&          trim( this%Component(i)%PotModFileName ), trim( this%Component(j)%PotModFileName ), &
&          trim(LJorMIE), this%ScaleSigma(i, j), this%ScaleEpsilon(i, j)
          call LogWrite

        end do
      end do
    endif

    ! Set cutoff radii
    if( this%NMIEnmMax > 0 ) then
      this%RCutoffMIEnmMIEnm = MaxRadius
    endif
    if( this%NTT68Max > 0 ) then
      this%RCutoffTT68TT68 = MaxRadius
    endif

    ! Disable reaction field
    this%RFEpsilon = 0._RK

    ! Create potentials
    call CreatePotentials( this )

    ! Calculate long-range corrections
    do i = 1, this%NComponents, 2
      do j = i + 1, this%NComponents, 2

        if( this%NMIEnmMax > 0 ) then
          this%Interaction(i, j)%EPotCorrMIE = sum( this%Interaction(i, j)%PotMIEnmMIEnm(:, :)%EPotCorr )
          write( IOBuffer, '("Cutoff correction to SVC of ", A, "-", A, " from ", A, ":", F12.8)' ) &
  &         trim( this%Component(i)%Molecule%PotModFileName ), trim( this%Component(j)%Molecule%PotModFileName ), &
  &         trim(LJorMIE), .5_RK * this%Interaction(i, j)%EPotCorrMIE / this%Temperature
        endif

        if( this%NTT68Max > 0 ) then
          this%Interaction(i, j)%EPotCorrTT68 = sum( this%Interaction(i, j)%PotTT68TT68(:, :)%EPotCorr )
          write( IOBuffer, '("Cutoff correction to SVC of ", A, "-", A, " from  TT68:", F12.8)' ) &
  &         trim( this%Component(i)%Molecule%PotModFileName ), trim( this%Component(j)%Molecule%PotModFileName ), &
  &         .5_RK * this%Interaction(i, j)%EPotCorrTT68 / this%Temperature
        endif
        call LogWrite

      end do
    end do

    ! Update all BoxLength-dependent constants
    call UpdateBoxLength( this )
    ! Set initial positions of particles
    do i = 1, this%NComponents
      this%Component(i)%P0 = 0._RK
    end do

    ! Set initial orientations of particles
    call InitOrientations( this )

    ! Convert molecular coordinates to atom positions
    call Mol2Atom( this )

    ! Set I/O unit numbers
    i = FilesPerEnsemble * this%EnsembleNumber
    this%resultFile%iounit = resultFile%iounit + i
    this%runaveFile%iounit = runaveFile%iounit + i
    this%errorsFile%iounit = errorsFile%iounit + i
    this%visualFile%iounit = visualFile%iounit + i
    this%visualHBFile%iounit = visualHBFile%iounit + i
    this%ccFile%iounit     = ccFile%iounit    + i !DC edit
    this%ccgridFile%iounit = ccgridFile%iounit+ i !DC edit

  end subroutine TEnsemble_ConstructSVC


!==============================================================!
!  Subroutine TEnsemble_Destruct                               !
!==============================================================!

  subroutine TEnsemble_Destruct( this )

    implicit none
#if SPME > 0
    include 'fftw3.f'
#endif

    ! Declare arguments
    type(TEnsemble) :: this

    ! Destroy potentials
    call DestroyPotentials( this )

    ! Deallocate arrays
    call Deallocate( this )

    ! Destroy components
    call DestroyComponents( this )

    ! Deallocate maximum number of particles
    if( associated( this%NPartMax ) ) then
      deallocate( this%NPartMax )
    end if

    if( associated( this%NPartMaxFluct ) ) then
      deallocate( this%NPartMaxFluct )
    end if

    ! Deallocate simulation box length
    if( associated( this%BoxLength ) ) then
      deallocate( this%BoxLength )
    end if

    if (LongRange .eq. Ewald) then

      if ( associated ( this%Ewald_Prefac ) ) then
         deallocate( this%Ewald_Prefac )
      end if

      if ( associated ( this%Ewald_Vec ) ) then
         deallocate( this%Ewald_Vec )
      end if

#if MPI_VER > 0
      if ( associated ( this%NBox0 ) ) then
         deallocate( this%NBox0 )
      end if

      if ( associated ( this%NBox1 ) ) then
         deallocate( this%NBox1 )
      end if

      if ( associated ( this%NBox2 ) ) then
         deallocate( this%NBox2 )
      end if

#endif

      if ( associated ( this%U_fourierLocal ) ) then
         deallocate( this%U_fourierLocal )
      end if

      if ( associated ( this%SSin ) ) then
         deallocate( this%SSin )
      end if

      if ( associated ( this%SCos ) ) then
         deallocate( this%SCos )
      end if

      if ( associated ( this%rold ) ) then
         deallocate( this%rold )
      end if

      if ( associated ( this%Vec2 ) ) then
         deallocate( this%Vec2 )
      end if

    end if

#if SPME > 0
    if (LongRange .eq. PME) then
      call dfftw_destroy_plan(this%qgrid_forward)
      call dfftw_destroy_plan(this%qgrid_backward)
      if ( associated ( this%qgrida ) ) then
         deallocate( this%qgrida )
      end if

      if ( associated ( this%qgrida_old ) ) then
         deallocate( this%qgrida_old )
      end if

      if ( associated ( this%bsp_arr ) ) then
         deallocate( this%bsp_arr )
      end if

      if ( associated ( this%bsp_modx ) ) then
         deallocate( this%bsp_modx )
      end if

      if ( associated ( this%bsp_mody ) ) then
         deallocate( this%bsp_mody )
      end if

      if ( associated ( this%bsp_modz ) ) then
         deallocate( this%bsp_modz )
      end if

    endif
#endif

  end subroutine TEnsemble_Destruct



!==============================================================!
!  Subroutine TEnsemble_CreateComponents                       !
!==============================================================!

  subroutine TEnsemble_CreateComponents( this )

    implicit none

    ! Declare arguments
    type(TEnsemble) :: this

    ! Declare local variables
    integer :: i, j, nfluct, ncomp
    integer :: stat
    real(RK):: q
    type(TComponent), pointer, contiguous :: reallocate(:)

    ! Create components
    ncomp = this%NComponents
    allocate( this%Component(ncomp), STAT = stat )
    call AllocationError( stat, 'components', ncomp )
    do i = 1, ncomp
      call Construct( this%Component(i), i )
    end do

    ! Create components for fluctuating particle states
    this%NGradInsComp = 0
    this%NRealComponents = ncomp
    do i = 1, this%NRealComponents
      q = 0._RK

      if( this%Component(i)%ChemPotMethod .eq. ChemPotMethodGradIns ) then
        ! LongRange Check
        do j=1,this%Component(i)%Molecule%NCharge
          q = q + this%Component(i)%Molecule%SiteCharge(j)%e
        end do

        if (abs(q) .gt. 1e-7) call Error ('Gradual Insertion not possible for charged molecule! No Electroneutrality')

        this%Component(i)%NGradThis = this%NGradInsComp
        this%NGradInsComp = this%NGradInsComp + 1
        nfluct = this%Component(i)%Molecule%NFluct
        ncomp = ncomp + nfluct

        ! Reallocate component array
        allocate( reallocate(ncomp), STAT = stat )
        ! reallocate will be stored in this%Component, which thus has to be deallocated
        call AllocationError( stat, 'components', ncomp )
        reallocate( 1:size(this%Component) ) = this%Component(:)
        deallocate( this%Component )
        this%Component => reallocate

        do j = 1, nfluct
          call Construct( this%Component(ncomp - nfluct + j), this%Component(i), j )
          this%Component(i)%NFluctComp(j) = ncomp - nfluct + j
        end do
        this%Component(i)%NFluctComp(0) = i
      end if

      if( this%Component(i)%ChemPotMethod .eq. ChemPotMethodThermoInt ) then

        ! LongRange Check
        do j=1,this%Component(i)%Molecule%NCharge
          q = q + this%Component(i)%Molecule%SiteCharge(j)%e
        end do

        if (abs(q) .gt. 1e-7) call Error ('Thermodynamic Integration not possible for charged molecule! No Electroneutrality')

        ncomp = ncomp + 1

        ! Reallocate component array
        allocate( reallocate(ncomp), STAT = stat )
        ! reallocate will be stored in this%Component, which thus has to be deallocated
        call AllocationError( stat, 'components', ncomp )
        reallocate( 1:size(this%Component) ) = this%Component(:)
        deallocate( this%Component )
        this%Component => reallocate
        call Construct( this%Component(ncomp), this%Component(i))
      end if

    end do

#if OSMOP > 0
    if (SimulationType .eq. MolecularDynamics ) then
      j = 0._RK
      do i = 1, this%NRealComponents
        if (this%Component(i)%permeable) then
          j = 1._RK
        end if
      end do
      if (j == 0._RK ) call Error ('At least one component has to be permeable.')
    end if
#endif
#if OSMOP == 2
    do i = 1, this%NRealComponents
      if ( this%Component(i)%ChemPotMethod .ne. ChemPotMethodWidom ) then
        call LogWriteBlank
        write( IOBuffer, '("Chem. Pot.-Profile for", A, " cannot be calculated if Widom is not used!")' ) trim(this%Component(i)%PotModFileName)
        call LogWrite
        call LogWriteBlank
        this%Component(i)%ChemPotProfile(:) = 0._RK
      end if
    end do
#endif

    ! Set new number of components (including fluctuating particles)
    this%NComponents = ncomp

#if TRANS==1
    !EinsteinCoef NEinstein
    if ((TransMethod .eq. Einstein) .or. (TransMethod .eq. GKEinstein)) then
      do i = 1, this%NRealComponents
        this%Component(i)%NEinstein = this%NCorr / this%NSpanCF
      end do
    end if
#endif

  end subroutine TEnsemble_CreateComponents



!==============================================================!
!  Subroutine TEnsemble_DestroyComponents                      !
!==============================================================!

  subroutine TEnsemble_DestroyComponents( this )

    implicit none

    ! Declare arguments
    type(TEnsemble) :: this

    ! Declare local variables
    integer :: i

    ! Destroy components
    do i = 1, this%NComponents
      if ( i .le. this%NRealComponents ) then
        call Destruct( this%Component(i) )
      else
        call DestructFluct( this%Component(i) )
      end if
    end do
    if( associated( this%Component ) ) then
      deallocate( this%Component )
    end if

  end subroutine TEnsemble_DestroyComponents



!==============================================================!
!  Subroutine TEnsemble_CreatePotentials                       !
!==============================================================!

  subroutine TEnsemble_CreatePotentials( this )

    implicit none

    ! Declare arguments
    type(TEnsemble) :: this

    ! Declare local variables
    integer :: i, j
    integer :: stat
#if OSMOP == 2
    integer :: j1, j2
#endif

    ! Create interactions
    allocate( this%Interaction(this%NComponents, this%NComponents ), STAT = stat )
    call AllocationError( stat, 'components', this%NComponents )

    if( SimulationType .eq. SecondVirialCoeff ) then
      do i = 1, this%NComponents, 2
        do j = i + 1, this%NComponents, 2
          call Construct(this%Interaction(i, j), i, j, &
&           this%Component(i), this%Component(j), &
&           this%RCutoffMIEnmMIEnm, &
&           this%RCutoffTT68TT68, &
&           this%RCutoffDipoleDipole, &
&           this%RCutoffDipoleQuadrupole, &
&           this%RCutoffQuadrupoleQuadrupole, &
&           this%ScaleSigma(i, j), &
&           this%ScaleEpsilon(i, j), &
&           this%RFEpsilon )
          call UpdateBoxLength( this%Interaction( j, i ), this%BoxLength )
        end do
      end do

    else
      do i = 1, this%NComponents
        do j = 1, this%NComponents

          if (LongRange .eq. ExtRField) this%Interaction(i,j)%DebyeLen = this%DebyeLen
          call Construct(this%Interaction(i, j), i, j, &
&           this%Component(i), this%Component(j), &
&           this%RCutoffMIEnmMIEnm, &
&           this%RCutoffTT68TT68, &
&           this%RCutoffDipoleDipole, &
&           this%RCutoffDipoleQuadrupole, &
&           this%RCutoffQuadrupoleQuadrupole, &
&           this%ScaleSigma(i, j), &
&           this%ScaleEpsilon(i, j), &
&           this%RFEpsilon )
        end do
      end do
    end if

#if OSMOP == 2
    ! set pointers for virial profile
    do i = 1, this%NComponents
      do j = 1, this%NComponents

        if( this%Interaction(i,j)%N1MIEnm > 0 .and. this%Interaction(i,j)%N2MIEnm > 0 ) then
          do j1 = 1, this%Interaction(i,j)%N1MIEnm
            do j2 = 1, this%Interaction(i,j)%N2MIEnm
              this%Interaction(i,j)%PotMIEnmMIEnm(j1, j2)%VirialProfile => this%VirialProfile
            end do
          end do
        end if
        if( this%Interaction(i,j)%N1TT68 > 0 .and. this%Interaction(i,j)%N2TT68 > 0 ) then
          do j1 = 1, this%Interaction(i,j)%N1TT68
            do j2 = 1, this%Interaction(i,j)%N2TT68
              this%Interaction(i,j)%PotTT68TT68(j1, j2)%VirialProfile => this%VirialProfile
            end do
          end do
        end if
        if( this%Interaction(i,j)%N1Charge > 0 .and. this%Interaction(i,j)%N2Charge > 0 ) then
          do j1 = 1, this%Interaction(i,j)%N1Charge
            do j2 = 1, this%Interaction(i,j)%N2Charge
              this%Interaction(i,j)%PotChargeCharge(j1, j2)%VirialProfile => this%VirialProfile
            end do
          end do
        end if
        if( this%Interaction(i,j)%N1Charge > 0 .and. this%Interaction(i,j)%N2Dipole > 0 ) then
          do j1 = 1, this%Interaction(i,j)%N1Charge
            do j2 = 1, this%Interaction(i,j)%N2Dipole
              this%Interaction(i,j)%PotChargeDipole(j1, j2)%VirialProfile => this%VirialProfile
            end do
          end do
        end if
        if( this%Interaction(i,j)%N1Charge > 0 .and. this%Interaction(i,j)%N2Quadrupole > 0 ) then
          do j1 = 1, this%Interaction(i,j)%N1Charge
            do j2 = 1, this%Interaction(i,j)%N2Quadrupole
              this%Interaction(i,j)%PotChargeQuadrupole(j1, j2)%VirialProfile => this%VirialProfile
            end do
          end do
        end if
        if( this%Interaction(i,j)%N1Dipole > 0 .and. this%Interaction(i,j)%N2Charge > 0 ) then
          do j1 = 1, this%Interaction(i,j)%N1Dipole
            do j2 = 1, this%Interaction(i,j)%N2Charge
              this%Interaction(i,j)%PotDipoleCharge(j1, j2)%VirialProfile => this%VirialProfile
            end do
          end do
        end if
        if( this%Interaction(i,j)%N1Dipole > 0 .and. this%Interaction(i,j)%N2Dipole > 0 ) then
          do j1 = 1, this%Interaction(i,j)%N1Dipole
            do j2 = 1, this%Interaction(i,j)%N2Dipole
              this%Interaction(i,j)%PotDipoleDipole(j1, j2)%VirialProfile => this%VirialProfile
            end do
          end do
        end if
        if( this%Interaction(i,j)%N1Dipole > 0 .and. this%Interaction(i,j)%N2Quadrupole > 0 ) then
          do j1 = 1, this%Interaction(i,j)%N1Dipole
            do j2 = 1, this%Interaction(i,j)%N2Quadrupole
              this%Interaction(i,j)%PotDipoleQuadrupole(j1, j2)%VirialProfile => this%VirialProfile
            end do
          end do
        end if
        if( this%Interaction(i,j)%N1Quadrupole > 0 .and. this%Interaction(i,j)%N2Charge > 0 ) then
          do j1 = 1, this%Interaction(i,j)%N1Quadrupole
            do j2 = 1, this%Interaction(i,j)%N2Charge
              this%Interaction(i,j)%PotQuadrupoleCharge(j1, j2)%VirialProfile => this%VirialProfile
            end do
          end do
        end if
        if( this%Interaction(i,j)%N1Quadrupole > 0 .and. this%Interaction(i,j)%N2Dipole > 0 ) then
          do j1 = 1, this%Interaction(i,j)%N1Quadrupole
            do j2 = 1, this%Interaction(i,j)%N2Dipole
              this%Interaction(i,j)%PotQuadrupoleDipole(j1, j2)%VirialProfile => this%VirialProfile
            end do
          end do
        end if
        if( this%Interaction(i,j)%N1Quadrupole > 0 .and. this%Interaction(i,j)%N2Quadrupole > 0 ) then
          do j1 = 1, this%Interaction(i,j)%N1Quadrupole
            do j2 = 1, this%Interaction(i,j)%N2Quadrupole
              this%Interaction(i,j)%PotQuadrupoleQuadrupole(j1, j2)%VirialProfile => this%VirialProfile
            end do
          end do
        end if

      end do
    end do
#endif

  end subroutine TEnsemble_CreatePotentials



!==============================================================!
!  Subroutine TEnsemble_DestroyPotentials                      !
!==============================================================!

  subroutine TEnsemble_DestroyPotentials( this )

    implicit none

    ! Declare arguments
    type(TEnsemble) :: this

    ! Declare local variables
    integer :: i, j

    ! Destroy interactions
    if( SimulationType .eq. SecondVirialCoeff ) then
      do i = 1, this%NComponents, 2
        do j = i + 1, this%NComponents, 2
          call Destruct( this%Interaction(i, j) )
        end do
      end do

    else
      do i = 1, this%NComponents
        do j = 1, this%NComponents
          call Destruct( this%Interaction(i, j) )
        end do
      end do
    end if

    if( associated( this%Interaction ) ) then
      deallocate( this%Interaction )
    end if

  end subroutine TEnsemble_DestroyPotentials


!==============================================================!
!  Subroutine TEnsemble_CreateAccumulators                     !
!==============================================================!

  subroutine TEnsemble_CreateAccumulators( this )

    implicit none

    ! Declare arguments
    type(TEnsemble) :: this

    ! Declare local variables
    integer   :: i, j
#if HBOND > 0
    integer   :: k, l, m, stat

    allocate( this%SumHBond0(this%NComponents ), STAT = stat )
    call AllocationError( stat, 'components', this%NComponents )
    allocate( this%SumHBond1(this%NComponents, this%NComponents ), STAT = stat )
    call AllocationError( stat, 'components', this%NComponents**2 )
    allocate( this%SumHBond2(this%NComponents, this%NComponents, this%NComponents ), STAT = stat )
    call AllocationError( stat, 'components', (this%NComponents**2)*this%NComponents )
    allocate( this%SumHBond3(this%NComponents, this%NComponents, this%NComponents, this%NComponents ), STAT = stat )
    call AllocationError( stat, 'components', (this%NComponents**2)*(this%NComponents**2) )
    allocate( this%SumHBond4(this%NComponents, this%NComponents, this%NComponents, this%NComponents, this%NComponents), STAT = stat )
    call AllocationError( stat, 'components', (this%NComponents**2)*(this%NComponents**2)*this%NComponents )
    allocate( this%SumHBondN(this%NComponents ), STAT = stat )
    call AllocationError( stat, 'components', this%NComponents )
#endif
#if OSMOP == 2
#if HBOND == 0
    integer   :: stat
#endif

    allocate( this%SumPressureProfile(NBinsDen ), STAT = stat )
    call AllocationError( stat, 'NBinsDen', NBinsDen )
#endif

    ! Construct accumulators
    if( .not. SimulationType .eq. SecondVirialCoeff ) then

      ! 1.) Basic sums
      call Construct( this%SumPressure, .false. )
      call Construct( this%SumDensity, .false. )
      call Construct( this%SumTemperature, .false. )
      call Construct( this%SumEPot, .false. )
      call Construct( this%SumEPotDeltaSquared, .false. )
      call Construct( this%SumEnthalpy, .false. )
      call Construct( this%SumConfEnthalpy, .false. )
      call Construct( this%SumVolume, .false. )
      call Construct( this%SumVirial, .false. )
      call Construct( this%SumVirialDeltaSquared, .false. )
      call Construct( this%SumdEpotdV, .false. )
      call Construct( this%Sumd2EpotdV2, .false. )
#if OSMOP > 0
      call Construct( this%SumOsmoticPressure, .false. )
#if OSMOP == 2
      do i = 1, NBinsDen
         call Construct( this%SumPressureProfile(i), .false. )
      end do
#endif
#endif

#if HBOND > 0
      do i = 1, this%NComponents
        call Construct( this%SumHBond0(i), .false. )
        do j = 1, this%NComponents
          call Construct( this%SumHBond1(i,j), .false. )
          do k = j, this%NComponents
            call Construct( this%SumHBond2(i,j,k), .false. )
            do l = k, this%NComponents
              call Construct( this%SumHBond3(i,j,k,l), .false. )
              do m = l, this%NComponents
                call Construct( this%SumHBond4(i,j,k,l,m), .false. )
              end do
            end do
          end do
        end do
        call Construct( this%SumHBondN(i), .false. )
      end do
#endif

      if( OpenSystem .or. EnsembleType .eq. EnsembleTypeHA .or. SimulationType .eq. Gibbs) then
        call Construct( this%SumNPart, .false. )
        call Construct( this%SumP100, .true. )
        call Construct( this%SumP200, .true. )
        call Construct( this%SumP020, .true. )
        call Construct( this%SumP001, .true. )
        call Construct( this%SumP002, .true. )
        call Construct( this%SumP101, .true. )
        call Construct( this%SumP010, .true. )
        call Construct( this%SumP110, .true. )
        call Construct( this%SumP011, .true. )
        if( EnsembleType .eq. EnsembleTypeGE .or. EnsembleType .eq. EnsembleTypeMUVT ) then
          call Construct( this%SumNPart2, .false. )
          call Construct( this%SumNPart3, .false. )
          call Construct( this%SumEPotTot, .false. )
          call Construct( this%SumEPot2Tot, .false. )
          call Construct( this%SumdEPotdVTot, .false. )
          call Construct( this%SumdEPotdV2Tot, .false. )
          call Construct( this%SumUdEPotdVTot, .false. )
          call Construct( this%Sumd2EPotdV2Tot, .false. )
          call Construct( this%SumNPartEPot, .false. )
          call Construct( this%SumNPartEPot2, .false. )
          call Construct( this%SumNPart2EPot, .false. )
          call Construct( this%SumNPartdEpotdV, .false. )
        else if( EnsembleType .eq. EnsembleTypeMUVL ) then
          call Construct( this%SumOmega000, .false. )
          call Construct( this%SumOmega200, .false. )
          call Construct( this%SumOmega010, .false. )
          call Construct( this%SumdEPotdVTot, .false. )
          call Construct( this%SumOmega0201, .false. )
          call Construct( this%Sumd2EPotdV2Tot, .false. )
          call Construct( this%SumOmega0202, .false. )
          call Construct( this%Sum2NVdUdV, .false. )
          call Construct( this%SumOmega002, .false. )
          call Construct( this%SumOmega101, .false. )
          call Construct( this%SumOmega110, .false. )
          call Construct( this%SumOmega011, .false. )
          call Construct( this%SumNPartV, .false. )
          call Construct( this%SumNPart2V, .false. )
        else if( EnsembleType .eq. EnsembleTypeMUPR ) then
          call Construct( this%SumOmega000, .false. )
          call Construct( this%SumOmega200, .false. )
          call Construct( this%SumOmega010, .false. )
          call Construct( this%SumOmega020, .false. )
          call Construct( this%SumOmega002, .false. )
          call Construct( this%SumOmega101, .false. )
          call Construct( this%SumOmega110, .false. )
          call Construct( this%SumOmega011, .false. )
        else if( EnsembleType .eq. EnsembleTypeMUPT ) then
          call Construct( this%SumNPart2, .false. )
          call Construct( this%SumZero, .false. )
          call Construct( this%SumZeroN, .false. )
          call Construct( this%SumZeroV, .false. )
          call Construct( this%SumZero2, .false. )
          call Construct( this%SumVext, .false. )
          call Construct( this%SumVext2, .false. )
          call Construct( this%SumN2pN, .false. )
          call Construct( this%SumNVmV, .false. )
          call Construct( this%SumNmN2, .false. )
          call Construct( this%SumNV, .false. )
        end if
      end if

      ! 2.) Combined sums
      call Construct( this%SumEPotSquared, .false. )
      call Construct( this%SumEPotV, .false. )
      call Construct( this%SumEPotVirial, .false. )
      call Construct( this%SumEPotDeltaVirialDelta, .false. )
      call Construct( this%SumEnthalpySquared, .false. )
      call Construct( this%SumEnthalpyV, .false. )
      call Construct( this%SumVolumeSquared, .false. )
      call Construct( this%SumEPotCubic, .false. )
      call Construct( this%SumdEpotdVSquared, .false. )
      call Construct( this%SumEPotdEpotdV, .false. )
      call Construct( this%SumEPotSquareddEpotdV, .false. )
      call Construct( this%SumEPotdEpotdVSquared, .false. )
      call Construct( this%SumEPotd2EpotdV2, .false. )
      if( EnsembleType .eq. EnsembleTypeNVE .and. LongRange .eq. Rfield) then
        call Construct( this%SumHmU, .false. )
        call Construct( this%SumHmUm1, .false. )
        call Construct( this%SumHmUm2, .false. )
        call Construct( this%SumHmUm3, .false. )
        call Construct( this%SumHmUm1dUdV, .false. )
        call Construct( this%SumHmUm1dUdV2, .false. )
        call Construct( this%SumHmUm1d2UdV2, .false. )
        call Construct( this%SumHmUm2dUdV, .false. )
        call Construct( this%SumHmUm2dUdV2, .false. )
        call Construct( this%SumHmUm2d2UdV2, .false. )
        call Construct( this%SumHmUm3dUdV, .false. )
        call Construct( this%SumHmUm3dUdV2, .false. )
      end if

      ! KBI sum Gij
      if( EnsembleType .eq. EnsembleTypeNVT .and.  KBIUpdateFrequency > 0) then
        do i= 1, this%NRealComponents*(this%NRealComponents+1)/2 !Number of comb., e.g. 11 12 22
            call Construct( this%SumKBIGij1(i), .false., .false., .true.)
            call Construct( this%SumKBIGij2(i), .false., .false., .true.)
            call Construct( this%SumKBIGij3(i), .false., .false., .true.)
        end do
      end if


      ! 3.) Derived sums
      call Construct( this%SumBetaT, .true. )
      call Construct( this%SumdHdP, .true. )
      call Construct( this%SumdUdV, .true. )
      call Construct( this%SumCV, .true. )
      call Construct( this%SumCorCoefR, .true. )
      call Construct( this%SumCP, .true. )
      call Construct( this%SumAlphaP, .true. )
      call Construct( this%SumGammaVsm, .true. )
      call Construct( this%SumBetaTsm, .true. )
      call Construct( this%SumCVsm, .true. )
      call Construct( this%SumCPsm, .true. )
      call Construct( this%SumAlphaPsm, .true. )
      if( LongRange .eq. Rfield) then
        if ( EnsembleType .eq. EnsembleTypeNVT ) then
          call Construct( this%SumA10resI, .true. )
          call Construct( this%SumA01resI, .true. )
          call Construct( this%SumA20resI, .true. )
          call Construct( this%SumA11resI, .true. )
          call Construct( this%SumA02resI, .true. )
          call Construct( this%SumA30resI, .true. )
          call Construct( this%SumA21resI, .true. )
          call Construct( this%SumA12resI, .true. )
        elseif ( EnsembleType .eq. EnsembleTypeNVE ) then
          call Construct( this%SumA10resI, .true. )
          call Construct( this%SumA01resI, .true. )
          call Construct( this%SumA20resI, .true. )
          call Construct( this%SumA11resI, .true. )
          call Construct( this%SumA02resI, .true. )
          call Construct( this%SumA30resI, .true. )
          call Construct( this%SumA21resI, .true. )
          call Construct( this%SumA12resI, .true. )
          call Construct( this%SumA10resII, .true. )
          call Construct( this%SumA01resII, .true. )
          call Construct( this%SumA20resII, .true. )
          call Construct( this%SumA11resII, .true. )
          call Construct( this%SumA02resII, .true. )
          call Construct( this%SumA30resII, .true. )
          call Construct( this%SumA21resII, .true. )
          call Construct( this%SumA12resII, .true. )
        elseif ( EnsembleType .eq. EnsembleTypeNPT ) then
          call Construct( this%SumConfEnthalpyTot, .false. )
          call Construct( this%SumConfEnthalpy2, .false. )
          call Construct( this%SumConfEnthalpyV, .false. )
          call Construct( this%SumG10, .true. )
          call Construct( this%SumG01, .true. )
          call Construct( this%SumG11, .true. )
          call Construct( this%SumG20, .true. )
          call Construct( this%SumG02, .true. )
        elseif ( EnsembleType .eq. EnsembleTypeNPH ) then
          call Construct( this%SumHmUmpV, .false. )
          call Construct( this%SumHmUmpVInv, .false. )
          call Construct( this%SumHmUmpVInvV, .false. )
          call Construct( this%SumHmUmpVInvV2, .false. )
          call Construct( this%SumS10, .true. )
          call Construct( this%SumS01, .true. )
          call Construct( this%SumS11, .true. )
          call Construct( this%SumS20, .true. )
          call Construct( this%SumS02, .true. )
        end if
      end if

#if  TRANS == 1
    ! Transport properties
    if( this%CorrfunMode ) then
      if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
        do i = 1, this%NComponents
          call Construct( this%Sumself_i(i),  .false., .true. )
        end do
           call Construct( this%SumVisco_s, .false., .true. )
      end if

      if (this%NComponents .gt. 1) then
        if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
          do i = 1, this%NComponents
            do j = 1, this%NComponents
              call Construct( this%SumOnsager(i,j), .false., .true. )
            end do
          end do
        end if

        do i = 1, this%NComponents
          call Construct( this%SumSoret(i), .false., .true. )
        end do
      end if

      call Construct( this%SumVisco_b, .false., .true. )
      call Construct( this%SumConduct, .false., .true. )
      call Construct( this%SumEConduct,.false., .true. )

    end if

    !EinsteinCoef Construct acc
    if ((TransMethod .eq. Einstein).or. (TransMethod .eq. GKEinstein)) then
       do i = 1, this%NComponents
          call Construct( this%EinsteinDSelfAcc(i),  .false., .true. )
       end do

       if (this%NComponents .gt. 1) then
          do i = 1, this%NComponents
             do j = 1, this%NComponents
                call Construct( this%EinsteinOnsagerAcc(i,j), .false., .true. )
             end do
          end do
       end if

       call Construct( this%EinsteinShearAcc, .false., .true. )
    end if

#endif

! 5.) Sampling of Dielectric Constant
    call Construct( this%SumTotalDipoleMoment, .false. )
    call Construct( this%SumTotalDipoleMomentSquared, .false. )
    call Construct( this%SumDielectricConstant, .false. )

! Calculation of residence times
     if (this%ResidenceTime) then
      call Construct( this%SumResidenceDuration, .false. )
      call Construct( this%SumResidencePairs, .false. )
     end if

      do i = 1, this%NRealComponents
        call CreateAccumulators( this%Component(i) )
      end do

    end if

  end subroutine TEnsemble_CreateAccumulators


!==============================================================!
!  Subroutine TEnsemble_DestroyAccumulators                    !
!==============================================================!

  subroutine TEnsemble_DestroyAccumulators( this )

    implicit none

    ! Declare arguments
    type(TEnsemble) :: this

    ! Declare local variables
    integer :: i, j
#if HBOND > 0
    integer :: k, l, m
#endif

    ! Destruct accumulators
    ! 1.) Basic sums
    call Destruct( this%SumPressure )
    call Destruct( this%SumDensity )
    call Destruct( this%SumTemperature )
    call Destruct( this%SumEPot )
    call Destruct( this%SumEPotDeltaSquared )
    call Destruct( this%SumEnthalpy )
    call Destruct( this%SumConfEnthalpy )
    call Destruct( this%SumVolume )
    call Destruct( this%SumVirial )
    call Destruct( this%SumVirialDeltaSquared )
    call Destruct( this%SumdEpotdV )
    call Destruct( this%Sumd2EpotdV2 )
#if OSMOP > 0
      call Destruct( this%SumOsmoticPressure )
#if OSMOP == 2
      do i = 1, NBinsDen
         call Destruct( this%SumPressureProfile(i) )
      end do
#endif
#endif

#if HBOND > 0
      do i = 1, this%NComponents
        call Destruct( this%SumHBond0(i) )
        do j = 1, this%NComponents
          call Destruct( this%SumHBond1(i,j) )
          do k = j, this%NComponents
            call Destruct( this%SumHBond2(i,j,k) )
            do l = k, this%NComponents
              call Destruct( this%SumHBond3(i,j,k,l) )
              do m = l, this%NComponents
                call Destruct( this%SumHBond4(i,j,k,l,m) )
              end do
            end do
          end do
        end do
        call Destruct( this%SumHBondN(i) )
      end do
#endif

    if( OpenSystem .or. EnsembleType .eq. EnsembleTypeHA .or. SimulationType .eq. Gibbs) then
      call Destruct( this%SumNPart )
      call Destruct( this%SumP100 )
      call Destruct( this%SumP200 )
      call Destruct( this%SumP020 )
      call Destruct( this%SumP001 )
      call Destruct( this%SumP002 )
      call Destruct( this%SumP101 )
      call Destruct( this%SumP010 )
      call Destruct( this%SumP110 )
      call Destruct( this%SumP011 )
      if( EnsembleType .eq. EnsembleTypeGE .or. EnsembleType .eq. EnsembleTypeMUVT ) then
        call Destruct( this%SumNPart2 )
        call Destruct( this%SumNPart3 )
        call Destruct( this%SumEPotTot )
        call Destruct( this%SumEPot2Tot )
        call Destruct( this%SumdEPotdVTot )
        call Destruct( this%SumdEPotdV2Tot )
        call Destruct( this%SumUdEPotdVTot )
        call Destruct( this%Sumd2EPotdV2Tot )
        call Destruct( this%SumNPartEPot )
        call Destruct( this%SumNPartEPot2 )
        call Destruct( this%SumNPart2EPot )
        call Destruct( this%SumNPartdEpotdV )
      else if( EnsembleType .eq. EnsembleTypeMUVL ) then
        call Destruct( this%SumOmega000 )
        call Destruct( this%SumOmega200 )
        call Destruct( this%SumOmega010 )
        call Destruct( this%SumdEPotdVTot )
        call Destruct( this%SumOmega0201 )
        call Destruct( this%Sumd2EPotdV2Tot )
        call Destruct( this%SumOmega0202 )
        call Destruct( this%Sum2NVdUdV )
        call Destruct( this%SumOmega002 )
        call Destruct( this%SumOmega101 )
        call Destruct( this%SumOmega110 )
        call Destruct( this%SumOmega011 )
        call Destruct( this%SumNPartV )
        call Destruct( this%SumNPart2V )
      else if( EnsembleType .eq. EnsembleTypeMUPR ) then
        call Destruct( this%SumOmega000 )
        call Destruct( this%SumOmega200 )
        call Destruct( this%SumOmega010 )
        call Destruct( this%SumOmega020 )
        call Destruct( this%SumOmega002 )
        call Destruct( this%SumOmega101 )
        call Destruct( this%SumOmega110 )
        call Destruct( this%SumOmega011 )
      else if( EnsembleType .eq. EnsembleTypeMUPT ) then
        call Destruct( this%SumNPart2 )
        call Destruct( this%SumZero )
        call Destruct( this%SumZeroN )
        call Destruct( this%SumZeroV )
        call Destruct( this%SumZero2 )
        call Destruct( this%SumVext )
        call Destruct( this%SumVext2 )
        call Destruct( this%SumN2pN )
        call Destruct( this%SumNVmV )
        call Destruct( this%SumNmN2 )
        call Destruct( this%SumNV )
      end if
    end if

    ! 2.) Combined sums
    call Destruct( this%SumEPotSquared )
    call Destruct( this%SumEPotV )
    call Destruct( this%SumEPotVirial )
    call Destruct( this%SumEPotDeltaVirialDelta )
    call Destruct( this%SumEnthalpySquared )
    call Destruct( this%SumEnthalpyV )
    call Destruct( this%SumVolumeSquared )
    call Destruct( this%SumEPotCubic )
    call Destruct( this%SumdEpotdVSquared )
    call Destruct( this%SumEPotdEpotdV )
    call Destruct( this%SumEPotSquareddEpotdV )
    call Destruct( this%SumEPotdEpotdVSquared )
    call Destruct( this%SumEPotd2EpotdV2 )
    if( EnsembleType .eq. EnsembleTypeNVE .and. LongRange .eq. Rfield) then
      call Destruct( this%SumHmU )
      call Destruct( this%SumHmUm1)
      call Destruct( this%SumHmUm2 )
      call Destruct( this%SumHmUm3 )
      call Destruct( this%SumHmUm1dUdV )
      call Destruct( this%SumHmUm1dUdV2 )
      call Destruct( this%SumHmUm1d2UdV2 )
      call Destruct( this%SumHmUm2dUdV )
      call Destruct( this%SumHmUm2dUdV2 )
      call Destruct( this%SumHmUm2d2UdV2 )
      call Destruct( this%SumHmUm3dUdV )
      call Destruct( this%SumHmUm3dUdV2 )
    end if

    ! KBI sum Gij
      if( EnsembleType .eq. EnsembleTypeNVT .and.  KBIUpdateFrequency > 0) then
        do i= 1, this%NRealComponents*(this%NRealComponents+1)/2!Number of comb., e.g. 11 12 22
            call Destruct( this%SumKBIGij1(i) )
            call Destruct( this%SumKBIGij2(i) )
            call Destruct( this%SumKBIGij3(i) )
        end do
      end if

    ! 3.) Derived sums
    call Destruct( this%SumBetaT )
    call Destruct( this%SumdHdP )
    call Destruct( this%SumdUdV )
    call Destruct( this%SumCV )
    call Destruct( this%SumCorCoefR )
    call Destruct( this%SumCP )
    call Destruct( this%SumAlphaP )
    call Destruct( this%SumGammaVsm )
    call Destruct( this%SumBetaTsm )
    call Destruct( this%SumCVsm )
    call Destruct( this%SumCPsm )
    call Destruct( this%SumAlphaPsm )
    if( LongRange .eq. Rfield) then
      if ( EnsembleType .eq. EnsembleTypeNVT ) then
        call Destruct( this%SumA10resI )
        call Destruct( this%SumA01resI )
        call Destruct( this%SumA20resI )
        call Destruct( this%SumA11resI )
        call Destruct( this%SumA02resI )
        call Destruct( this%SumA30resI )
        call Destruct( this%SumA21resI )
        call Destruct( this%SumA12resI )
      elseif ( EnsembleType .eq. EnsembleTypeNVE ) then
        call Destruct( this%SumA10resI )
        call Destruct( this%SumA01resI )
        call Destruct( this%SumA20resI )
        call Destruct( this%SumA11resI )
        call Destruct( this%SumA02resI )
        call Destruct( this%SumA30resI )
        call Destruct( this%SumA21resI )
        call Destruct( this%SumA12resI )
        call Destruct( this%SumA10resII )
        call Destruct( this%SumA01resII )
        call Destruct( this%SumA20resII )
        call Destruct( this%SumA11resII )
        call Destruct( this%SumA02resII )
        call Destruct( this%SumA30resII )
        call Destruct( this%SumA21resII )
        call Destruct( this%SumA12resII )
      elseif ( EnsembleType .eq. EnsembleTypeNPT ) then
        call Destruct( this%SumConfEnthalpyTot )
        call Destruct( this%SumConfEnthalpy2 )
        call Destruct( this%SumConfEnthalpyV )
        call Destruct( this%SumG10 )
        call Destruct( this%SumG01 )
        call Destruct( this%SumG11 )
        call Destruct( this%SumG02 )
        call Destruct( this%SumG20 )
      elseif ( EnsembleType .eq. EnsembleTypeNPH ) then
        call Destruct( this%SumHmUmpV )
        call Destruct( this%SumHmUmpVInv )
        call Destruct( this%SumHmUmpVInvV )
        call Destruct( this%SumHmUmpVInvV2 )
        call Destruct( this%SumS10 )
        call Destruct( this%SumS01 )
        call Destruct( this%SumS11 )
        call Destruct( this%SumS02 )
        call Destruct( this%SumS20 )
      end if
    end if

#if  TRANS == 1

    if( this%CorrfunMode ) then
       if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
          do i = 1, this%NComponents
            call Destruct( this%Sumself_i(i) )
          end do
          call Destruct( this%SumVisco_s )
       end if

       if (this%NComponents .gt. 1) then
          if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
            do i = 1, this%NComponents
              do j = 1, this%NComponents
                call Destruct( this%SumOnsager(i,j) )
              end do
            end do
          end if
          do i = 1, this%NComponents
            call Destruct( this%SumSoret(i) )
          end do
       end if

      call Destruct( this%SumVisco_b )
      call Destruct( this%SumConduct )
      call Destruct( this%SumEConduct )
    end if

    !EinsteinCoef destruct acc
    if ( (TransMethod .eq. Einstein) .or. (TransMethod .eq. GKEinstein)) then
       do i = 1, this%NComponents
         call Destruct( this%EinsteinDSelfAcc(i) )
       end do

       if (this%NComponents .gt. 1) then
          do i = 1, this%NComponents
            do j = 1, this%NComponents
              call Destruct( this%EinsteinOnsagerAcc(i,j) )
            end do
          end do
        end if
        call Destruct( this%EinsteinShearAcc )
    end if
#endif

    ! 5.) Sampling of Dielectric Constant
    call Destruct( this%SumTotalDipoleMoment )
    call Destruct( this%SumTotalDipoleMomentSquared )
    call Destruct( this%SumDielectricConstant )

! Calculation of residence times
    if ( this%ResidenceTime ) then
      call Destruct( this%SumResidenceDuration )
      call Destruct( this%SumResidencePairs )
    end if

    do i = 1, this%NRealComponents
      call DestroyAccumulators( this%Component(i) )
    end do

#if OSMOP == 2
    if( associated( this%SumPressureProfile ) ) then
      deallocate( this%SumPressureProfile )
    end if
#endif

  end subroutine TEnsemble_DestroyAccumulators



!==============================================================!
!  Subroutine TEnsemble_CalculateNPart                         !
!==============================================================!

  subroutine TEnsemble_CalculateNPart( this )

    implicit none

    ! Declare arguments
    type(TEnsemble) :: this

    ! Declare local variables
    real(RK)                  :: s
    type(TComponent), pointer :: pc
    integer                   :: i,t

    ! Adjust number of cells to cube of integer
    if( this%NPart < NPartInCell ) this%NPart = NPartInCell

    ! Set maximum number of particles
    if( OpenSystem .or. EnsembleType .eq. EnsembleTypeHA .or. SimulationType .eq. Gibbs) then
      this%NPartMax = 2 * this%NPart

  ! Max. number of particles of component i in a fluctuating state
      this%NPartMaxFluct = 1
    else
      this%NPartMax = this%NPart
  ! Max. number of particles of component i in a fluctuating state
      this%NPartMaxFluct = 1
    end if

    ! Normalize mole fractions
    s = 0
    do i = 1, this%NRealComponents
      pc => this%Component(i)
      s = s + pc%Fraction
    end do

    if ( s /= 1_RK) then
      write(IOBuffer, '("Warning: Mole fraction sum of the considered fluid is not unity")')
      call LogWrite
    endif

    do i = 1, this%NRealComponents
      pc => this%Component(i)
      pc%Fraction = pc%Fraction / s
      if ( s /= 1_RK) then
        write( IOBuffer, '("Mole fraction of ", A, " was set to:",T45, F6.3)' ) trim( pc%PotModFileName ), pc%Fraction
        call LogWrite
      endif
    end do

    ! Calculate number of particles in each component
    ! according to mole fraction
    this%Component(this%NRealComponents)%NPart = this%NPart
    do i = 1, this%NRealComponents - 1
      pc => this%Component(i)
      pc%NPart = nint( this%NPart * pc%Fraction )
      this%Component(this%NRealComponents)%NPart = this%Component(this%NRealComponents)%NPart - pc%NPart
    end do

    ! Setting Particles for ThermoInt
    t = this%NRealComponents+1
    do i = 1, this%NRealComponents
      pc => this%Component(i)
      if ( pc%ChemPotMethod == ChemPotMethodThermoInt ) then
        if ( pc%NPart >= 1) then
          pc%NPart = pc%NPart - 1
          this%Component(t)%NPart = 1
          t = t+1
        else
          write (ErrorBuffer,'("At least one particle of ", A, " is required for Thermodynamic Integration" ,T45)' ) trim( pc%PotModFileName )
          call Error
        end if
      end if
    end do

    ! Set mole fractions according to real number of particles
    ! and calculate number of degrees of freedom
    write( IOBuffer, '("The mole fraction(s) may be slightly changed due to the number of particle(s).")' )
    call LogWrite

    this%NDFTran = 0
    this%NDFRot = 0
    do i = 1, this%NComponents
      pc => this%Component(i)
      pc%Fraction = real( pc%NPart, RK ) / real( this%NPart, RK )
      pc%NDFTran = pc%NPart * 3
      pc%NDFRot = pc%NPart * pc%Molecule%NDFRot
      pc%NDF = pc%NDFTran + pc%NDFRot
      this%NDFTran = this%NDFTran + pc%NDFTran
      this%NDFRot = this%NDFRot + pc%NDFRot
    end do
    this%NDF = this%NDFTran + this%NDFRot

    ! Calculate number of particles and test particles in each process
    ! and maximum number of test particles and fluctuating states
    this%NTestMax = 0
    this%NFluctMax = 0
    do i = 1, this%NComponents
      pc => this%Component(i)
      pc%NPart1 = ProcRange( pc%NPart, pc%NPart0, pc%NPart2 )

!      if( pc%NTest > 0 ) pc%NTest = 1 + (pc%NTest - 1) / NProcs
      pc%NTestAll = NProcs * pc%NTest
      this%NTestMax = max( pc%NTest, this%NTestMax )
      this%NFluctMax = max( pc%NFluctMax, this%NFluctMax )
    end do

    ! Calculate volume of simulation box
    this%Volume0 = this%NPart / this%RefDensity

    ! Update log file
    write( IOBuffer, '("Number of particles:",T36, I11)' ) this%NPart
    call LogWrite
    do i = 1, this%NRealComponents
      pc => this%Component(i)
      write( IOBuffer, '("Mole fraction of ", A, ":",T45, F6.3)' ) trim( pc%PotModFileName ), pc%Fraction
      call LogWrite
      write( IOBuffer, '(T10,"->  number of particles: ",T36, I11)' ) pc%NPart
      call LogWrite

      if( pc%NTestAll > 0 ) then
         if (SimulationType .eq. MolecularDynamics) then
           write( IOBuffer, '("Number of test particles:",T36, I11)' ) pc%NTestAll
         else
           write( IOBuffer, '("Number of test particles:",T36, I11)' ) pc%NTest
         end if
         call LogWrite
      end if

    end do

  end subroutine TEnsemble_CalculateNPart



!==============================================================!
!  Subroutine TEnsemble_LongRangeCheck                         !
!==============================================================!

   subroutine TEnsemble_LongRangeCheck ( this )

   implicit none
   type(TEnsemble)            :: this
   integer                    :: i
   real(RK)                   :: q

! Calculation
   q = 0._RK
   do i=1,this%NComponents
     call LongRangeCheck ( this%Component(i), q)
   end do

! Error Analysis
   if (abs(q) .ge. 1e-1) then
     write (ErrorBuffer,'("You have a non-neutral system.\n NetCharge normred = ", &
&                 F20.10, "\n Conflicts arise applying long range corrections")') q
     call Error
   end if

   end subroutine TEnsemble_LongRangeCheck



!==============================================================!
!  Subroutine TEnsemble_UpdateBoxLength                        !
!==============================================================!

  subroutine TEnsemble_UpdateBoxLength( this )

    implicit none

    ! Declare arguments
    type(TEnsemble) :: this

    ! Declare local variables
    integer :: i, j

    ! Update size of the simulation box
    if( SimulationType .eq. SecondVirialCoeff ) then
      this%BoxLength = 100._RK
    else
      this%Density = this%NPart / this%Volume0
      this%BoxLength = this%Volume0**Third

      if (LongRange .eq. Ewald) then
        this%Kappa = this%KappaL / this%BoxLength
        do i=1,this%NComponents
          do j=1,this%NComponents
            this%Interaction(i,j)%Kappa = this%Kappa
          end do
        end do
        call EwaldSelfTerm(this)

#if SPME > 0
      else if (LongRange .eq. PME ) then
        this%Kappa = this%KappaL / this%BoxLength
        do i=1,this%NComponents
          do j=1,this%NComponents
            this%Interaction(i,j)%Kappa = this%Kappa
          end do
        end do
        call PMESelfTermMC ( this )
#endif

      else if (LongRange .eq. Rodgers ) then
        this%EPotCorrRF = this%EPotCorrRFVol*this%Volume0 + this%EPotCorrRFPart
      end if

    end if

    do i = 1, this%NComponents
      do j = 1, this%NComponents
        call UpdateBoxLength( this%Interaction( j, i ), this%BoxLength )
      end do
    end do

  end subroutine TEnsemble_UpdateBoxLength



!==============================================================!
!  Subroutine TEnsemble_UpdateFractions                        !
!==============================================================!

  subroutine TEnsemble_UpdateFractions( this )

    implicit none

    ! Declare arguments
    type(TEnsemble) :: this

    ! Declare local variables
    integer                   :: i
    type(TComponent), pointer :: pc

    ! Set mole fractions according to real number of particles
    ! and calculate number of degrees of freedom
    this%NDFTran = 0
    this%NDFRot = 0
    do i = 1, this%NComponents
      pc => this%Component(i)
      this%Component(i)%Fraction = real( pc%NPart, RK ) / real( this%NPart, RK )
      pc%NDFTran = pc%NPart * 3
      pc%NDFRot = pc%NPart * pc%Molecule%NDFRot
      pc%NDF = pc%NDFTran + pc%NDFRot
      this%NDFTran = this%NDFTran + pc%NDFTran
      this%NDFRot = this%NDFRot + pc%NDFRot
    end do
    this%NDF = this%NDFTran + this%NDFRot

  end subroutine TEnsemble_UpdateFractions



!==============================================================!
!  Subroutine TEnsemble_FindNSiteMax                           !
!==============================================================!

  subroutine TEnsemble_FindNSiteMax( this )

    implicit none

    ! Declare arguments
    type(TEnsemble) :: this

    ! Declare local variables
    integer                   :: i
    type(TComponent), pointer :: pc

    ! Calculate maximum numbers of sites in components
    this%NMIEnmMax      = 0
    this%NTT68Max       = 0
    this%NChargeMax     = 0
    this%NDipoleMax     = 0
    this%NQuadrupoleMax = 0
    do i = 1, this%NComponents
      pc => this%Component(i)
      if( pc%Molecule%NMIEnm > this%NMIEnmMax ) this%NMIEnmMax = pc%Molecule%NMIEnm
      if( pc%Molecule%NTT68 > this%NTT68Max ) this%NTT68Max = pc%Molecule%NTT68
      if( pc%Molecule%NCharge > this%NChargeMax ) this%NChargeMax = pc%Molecule%NCharge
      if( pc%Molecule%NDipole > this%NDipoleMax ) this%NDipoleMax = pc%Molecule%NDipole
      if( pc%Molecule%NQuadrupole > this%NQuadrupoleMax ) this%NQuadrupoleMax = pc%Molecule%NQuadrupole
    end do

  end subroutine TEnsemble_FindNSiteMax



!==============================================================!
!  Subroutine TEnsemble_Allocate                               !
!==============================================================!

  subroutine TEnsemble_Allocate( this )

    implicit none

    ! Declare arguments
    type(TEnsemble) :: this

    ! Declare local variables
    integer :: i
    integer :: stat
    integer :: number
#if TRANS ==1
    integer :: NPart3
    integer :: NComp2, NC
#endif


    ! Nullify pointers
    nullify( this%P0Test )
    nullify( this%Q0Test )
    nullify( this%EPotTest )
    nullify( this%BiasedPartners )
    nullify( this%ODFvalue )
    nullify( this%RDFValue )
    nullify( this%RDFVSchale )
    nullify( this%KBIVSchale )
    nullify( this%KBIRDFextra )
    nullify( this%KBIRDFvdVextra )
    nullify( this%KBIRDFvdVshfextra )
    nullify( this%TDF )
    nullify( this%dTDF )
    nullify( this%TDF0 )
    nullify( this%partialmolV )
    nullify( this%partialmolV0 )
    nullify( this%dpartialmolV )
    nullify( this%dispR2 )
    nullify( this%dispR2inv )
    nullify( this%dispR4 )
    nullify( this%dispR2Ave )
    nullify( this%dispR2invAve )
    nullify( this%dispR4Ave )
    nullify( this%alpha2tempstep )

#if TRANS==1
    !EinsteinCoef nullify
    if ((TransMethod .eq. Einstein) .or. (TransMethod .eq. GKEinstein)) then
      nullify( this%DselfEinstein)
      nullify( this%DselfEinsteinAve)
      nullify( this%OnsagerEinstein)
      nullify( this%OnsagerEinsteinAve)
      nullify( this%EinsteinCoefTimeStep)
      nullify( this%DselfEinsteinCurrent)
      nullify( this%OnsagerEinsteinCurrent)
      nullify( this%EinsteinShear)
      nullify( this%EinsteinShearAve)
      nullify( this%EinsteinShearInt)
    end if
#endif


    ! Allocate scale coefficients for sigma and epsilon
    allocate( this%ScaleSigma(this%NComponents, this%NComponents), STAT = stat )
    call AllocationError( stat, 'components', this%NComponents )
    allocate( this%ScaleEpsilon(this%NComponents, this%NComponents), STAT = stat )
    call AllocationError( stat, 'components', this%NComponents )
    allocate( this%BiasedPartners(this%NPartMax), STAT = stat )
    call AllocationError( stat, 'NPartMax', this%NPartMax )

    ! Allocate ODF arrays
    if( ODFUpdateFrequency > 0 ) then
      allocate( this%ODFvalue(nPhi,nPhi, nGamma,nR), STAT = stat )
      call AllocationError( stat, 'components', nPhi*nPhi*nGamma*nR )
    endif

    ! Allocate RDF arrays
    if( RDFUpdateFrequency > 0 ) then
      allocate( this%RDFVSchale(RDFNumberShells), STAT = stat )
      call AllocationError( stat, 'components', RDFNumberShells )
      allocate( this%RDFValue(RDFNumberShells), STAT = stat )
      call AllocationError( stat, 'components', RDFNumberShells )
    endif

    ! Allocate KBI arrays
    if( KBIUpdateFrequency > 0 ) then
      allocate( this%KBIVSchale(KBINShellsCubeEdge), STAT = stat )
      call AllocationError( stat, 'KBI shells', KBINShellsCubeEdge )
      allocate( this%KBIRDFextra(0:KBINShellsCubeEdge, this%NRealComponents*(this%NRealComponents+1)/2), STAT = stat )
      call AllocationError( stat, 'KBI RDF extrap.', KBINShellsCubeEdge )
      allocate( this%KBIRDFvdVextra(0:KBINShellsCubeEdge, this%NRealComponents*(this%NRealComponents+1)/2), STAT = stat )
      call AllocationError( stat, 'KBI RDFvdV extrap.', KBINShellsCubeEdge )
      allocate( this%KBIRDFvdVshfextra(0:KBINShellsCubeEdge, this%NRealComponents*(this%NRealComponents+1)/2), STAT = stat )
      call AllocationError( stat, 'KBI RDFvdVshf extrap.', KBINShellsCubeEdge )
      allocate( this%TDF(3, (this%NRealComponents-1)**2), STAT = stat ) !3 Methods:1RDF,2:RDFvdV,3:RDFvdVshf; Number of TDF values
      call AllocationError( stat, 'TDF' )
      allocate( this%dTDF(3, (this%NRealComponents-1)**2), STAT = stat ) !3 Methods:1RDF,2:RDFvdV,3:RDFvdVshf; Number of TDF values
      call AllocationError( stat, 'dTDF' )
      allocate( this%TDF0(3, (this%NRealComponents-1)**2), STAT = stat ) !3 Methods:1RDF,2:RDFvdV,3:RDFvdVshf; Number of TDF values
      call AllocationError( stat, 'TDF0' )
      allocate( this%partialmolV(3, this%NRealComponents), STAT = stat ) !3 Methods:1RDF,2:RDFvdV,3:RDFvdVshf
      call AllocationError( stat, 'partialmolV' )
      allocate( this%partialmolV0(3, this%NRealComponents), STAT = stat ) !3 Methods:1RDF,2:RDFvdV,3:RDFvdVshf
      call AllocationError( stat, 'partialmolV0' )
      allocate( this%dpartialmolV(3, this%NRealComponents), STAT = stat ) !3 Methods:1RDF,2:RDFvdV,3:RDFvdVshf
      call AllocationError( stat, 'dpartialmolV' )
      allocate( this%SumKBIGij1(this%NRealComponents*(this%NRealComponents+1)/2), STAT = stat )
      call AllocationError( stat, 'Sum KBI Gij1', this%NRealComponents )
      allocate( this%SumKBIGij2(this%NRealComponents*(this%NRealComponents+1)/2), STAT = stat )
      call AllocationError( stat, 'Sum KBI Gij2', this%NRealComponents )
      allocate( this%SumKBIGij3(this%NRealComponents*(this%NRealComponents+1)/2), STAT = stat )
      call AllocationError( stat, 'Sum KBI Gij3', this%NRealComponents )
    endif

    if( ALPHA2UpdateFrequency > 0 ) then
      allocate( this%dispR2(ALPHA2Length/ALPHA2UpdateFrequency, 0:ALPHA2Length/ALPHA2Shift-1), STAT = stat )
      call AllocationError( stat, 'dispR2' )
      allocate( this%dispR2inv(ALPHA2Length/ALPHA2UpdateFrequency, 0:ALPHA2Length/ALPHA2Shift-1), STAT = stat )
      call AllocationError( stat, 'dispR2inv' )
      allocate( this%dispR4(ALPHA2Length/ALPHA2UpdateFrequency, 0:ALPHA2Length/ALPHA2Shift-1), STAT = stat )
      call AllocationError( stat, 'dispR4' )
      allocate( this%dispR2Ave(ALPHA2Length/ALPHA2UpdateFrequency), STAT = stat ) !average
      call AllocationError( stat, 'dispR2Ave' )
      allocate( this%dispR2invAve(ALPHA2Length/ALPHA2UpdateFrequency), STAT = stat )
      call AllocationError( stat, 'dispR2invAve' )
      allocate( this%dispR4Ave(ALPHA2Length/ALPHA2UpdateFrequency), STAT = stat )
      call AllocationError( stat, 'dispR4Ave' )
      allocate( this%alpha2tempstep(0:ALPHA2Length/ALPHA2Shift-1), STAT = stat ) !alpha2tempstep displacement
      call AllocationError( stat, 'alpha2tempstep' )
      this%alpha2tempstep(:)=0
      this%alpha2aveCount=0
    end if

#if TRANS==1
    !EinsteinCoef allocate
    if( (TransMethod .eq. Einstein) .or. (TransMethod .eq. GKEinstein)) then
        allocate( this%DselfEinstein(this%NCorr, 0:this%NCorr/this%NSpanCF-1, this%NComponents), STAT = stat )
        call AllocationError( stat, 'DselfEinstein' )
        allocate( this%DselfEinsteinAve(this%NCorr, this%NComponents), STAT = stat )
        call AllocationError( stat, 'DselfEinsteinAve' )
        allocate( this%OnsagerEinstein(this%NCorr, 0:this%NCorr/this%NSpanCF-1, this%NComponents, this%NComponents ), STAT = stat )
        call AllocationError( stat, 'OnsagerEinstein' )
        allocate( this%OnsagerEinsteinAve(this%NCorr, this%NComponents, this%NComponents), STAT = stat )
        call AllocationError( stat, 'OnsagerEinsteinAve' )
        allocate( this%EinsteinCoefTimeStep(0:this%NCorr/this%NSpanCF-1), STAT = stat)
        call AllocationError (stat, 'EinsteinCoefTimeStep')
        this%EinsteinCoefAveCount = 0
        this%EinsteinCoefTimeStep(:) = 0
        this%DselfEinstein(:,:,:) = 0
        this%DselfEinsteinAve(:,:) = 0
        this%OnsagerEinstein(:,:,:,:) = 0
        this%OnsagerEinsteinAve(:,:,:) = 0

        allocate( this%DselfEinsteinCurrent(this%NComponents), STAT = stat)
        call AllocationError (stat, 'DselfEinsteinCurrent')
        allocate( this%OnsagerEinsteinCurrent(this%NComponents,this%NComponents), STAT = stat)
        call AllocationError (stat, 'OnsagerEinsteinCurrent')
        this%DselfEinsteinCurrent(:) = 0
        this%OnsagerEinsteinCurrent(:,:) = 0
        this%ShearEinsteinCurrent = 0

        allocate( this%EinsteinShear(this%NCorr), STAT = stat)
        call AllocationError (stat, 'EinsteinShear')
        allocate( this%EinsteinShearAve(this%NCorr), STAT = stat)
        call AllocationError (stat, 'EinsteinShearAve')
        allocate( this%EinsteinShearInt(this%NCorr), STAT = stat)
        call AllocationError (stat, 'EinsteinShearInt')
        this%EinsteinShear = 0
        this%EinsteinShearAve = 0
        this%EinsteinShearInt = 0
    end if
#endif

    ! Allocate test particles
    if( this%NTestMax > 0 ) then
      allocate( this%P0Test( this%NTestMax, 3 ), STAT = stat )
      call AllocationError( stat, 'test particles', this%NTestMax )
      allocate( this%Q0Test( this%NTestMax, 4 ), STAT = stat )
      call AllocationError( stat, 'test particles', this%NTestMax )
      allocate( this%EPotTest( this%NTestMax ), STAT = stat )
      call AllocationError( stat, 'test particles', this%NTestMax )
      call LogWriteBlank
      write( IOBuffer, '("Memory for test particles allocated successfully")' )
      call LogWrite
    end if

    ! Allocate components
    if( OpenSystem .or. EnsembleType .eq. EnsembleTypeHA .or. &
&       SimulationType .eq. Gibbs .or. SimulationType .eq. SecondVirialCoeff ) then

       do i = 1, this%NComponents
         this%Component(i)%NPartMax => this%NPartMax

         if( this%Component(i)%NTest > 0 ) then
           this%Component(i)%P0Test => this%P0Test
           this%Component(i)%Q0Test => this%Q0Test
         end if

         this%Component(i)%BoxLength => this%BoxLength
         call Allocate( this%Component(i) )
       end do

    else
       do i = 1, this%NComponents
         if (i .le. this%NRealComponents) then
           this%Component(i)%NPartMax => this%Component(i)%NPart

         else
           this%Component(i)%NPartMax => this%NPartMaxFluct
         end if

         if( this%Component(i)%NTest > 0 ) then
           this%Component(i)%P0Test => this%P0Test
           this%Component(i)%Q0Test => this%Q0Test
         end if

         this%Component(i)%BoxLength => this%BoxLength
         call Allocate( this%Component(i) )

       end do
    end if


    ! Ewald Summation - we allocate  - look above in the variable declaration
    if (LongRange .eq. Ewald) then
     allocate(this%Ewald_Prefac(this%NVecMax),STAT=stat)
     allocate(this%Ewald_Vec(3,this%NVecMax),STAT=stat)
    end if


#if HBOND > 0
    !Allocate H-Bond counters
    allocate( this%NHBond0( this%NComponents ), STAT = stat )
    call AllocationError( stat, 'components', this%NComponents )
    allocate( this%NHBond1( this%NComponents, this%NComponents ), STAT = stat )
    call AllocationError( stat, 'components', this%NComponents**2 )
    allocate( this%NHBond2( this%NComponents, this%NComponents, this%NComponents ), STAT = stat )
    call AllocationError( stat, 'components', this%NComponents**2*this%NComponents )
    allocate( this%NHBond3( this%NComponents, this%NComponents, this%NComponents, this%NComponents ), STAT = stat )
    call AllocationError( stat, 'components', this%NComponents**2*this%NComponents**2 )
    allocate( this%NHBond4( this%NComponents, this%NComponents, this%NComponents, this%NComponents, this%NComponents ), STAT = stat )
    call AllocationError( stat, 'components', this%NComponents**2*this%NComponents**2*this%NComponents )
    allocate( this%NHBondN( this%NComponents ), STAT = stat )
    call AllocationError( stat, 'components', this%NComponents )
#endif

#if OSMOP == 2
    !Allocate pressure in the bins of the pressureprofile
    allocate( this%VirialProfile( NBinsDen ), STAT = stat )
    call AllocationError( stat, 'viral profile', NBinsDen )
    this%VirialProfile(:) = 0._RK
    allocate( this%PressureProfile( NBinsDen ), STAT = stat )
    call AllocationError( stat, 'pressure profile', NBinsDen )
    this%PressureProfile(:) = 0._RK
#endif

#if  TRANS == 1

      NPart3 = 3*this%NPart
      NComp2 = this%NComponents*this%NComponents
      NC     = this%NComponents

    ! Allocate correlation fucntions
     if( this%CorrfunMode ) then

       if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
         allocate( this%cf_vs(this%NCorr), STAT = stat )
         call AllocationError( stat, 'viscosity_shear_cf_vs', this%NCorr )

         allocate( this%average_cf_vs(this%NCorr), STAT = stat )
         call AllocationError( stat, 'viscosity_shear_cf_vs', this%NCorr )

         allocate( this%cf_d( this%NComponents, this%NCorr), STAT = stat )
         call AllocationError( stat, 'self_diffusion', this%NCorr )

         allocate( this%average_cf_d( this%NComponents, this%NCorr), STAT = stat )
         call AllocationError( stat, 'self_diffusion', this%NCorr )

         allocate( this%lamda( NComp2, this%NCorr ), STAT = stat )
         call AllocationError( stat, 'onsager_coefficient', this%NCorr )

         allocate( this%average_lamda( NComp2, this%NCorr ), STAT = stat )
         call AllocationError( stat, 'onsager_coefficient', this%NCorr )

         allocate( this%sinte_i( this%NComponents, this%NCorr), STAT = stat )
         call AllocationError( stat, 'self_diffusion_integrated', this%NCorr )

         allocate( this%average_sinte_i( this%NComponents, this%NCorr), STAT = stat )
         call AllocationError( stat, 'self_diffusion_integrated', this%NCorr )

         allocate( this%sinte_lamda( NComp2, this%NCorr), STAT = stat )
         call AllocationError( stat, 'mutual diffusion integrated', this%NCorr )

         allocate( this%average_sinte_lamda( NComp2, this%NCorr), STAT = stat )
         call AllocationError( stat, 'mutual diffusion integrated', this%NCorr )

         allocate( this%sinte_vs( this%NCorr), STAT = stat )
         call AllocationError( stat, 'shear_viscosity_integrated', this%NCorr )

         allocate( this%average_sinte_vs( this%NCorr), STAT = stat )
         call AllocationError( stat, 'shear_viscosity_integrated', this%NCorr )

         allocate( this%a( NPart3, this%NCorr), STAT = stat  )
         call AllocationError( stat, 'diffusion_matrix', NPart3 )

         allocate( this%A_SpanCF( NPart3, this%NSpanCF), STAT = stat  )
         call AllocationError( stat, 'diffusion_matrix', NPart3 )
      end if


      allocate( this%cf_vb(this%NCorr), STAT = stat )
      call AllocationError( stat, 'viscosity_bulk_cf_vb', this%NCorr )

      allocate( this%average_cf_vb(this%NCorr), STAT = stat )
      call AllocationError( stat, 'viscosity_bulk_cf_vb', this%NCorr )

      allocate( this%cf_c(this%NCorr), STAT = stat )
      call AllocationError( stat, 'conductivity_cf_c', this%NCorr )

      allocate( this%average_cf_c(this%NCorr), STAT = stat )
      call AllocationError( stat, 'conductivity_cf_c', this%NCorr )

      allocate( this%cf_ec(this%NCorr), STAT = stat )
      call AllocationError( stat, 'conductivity_cf_ec', this%NCorr )

      allocate( this%average_cf_ec(this%NCorr), STAT = stat )
      call AllocationError( stat, 'conductivity_cf_ec', this%NCorr )

      allocate( this%cf_soret( NC, this%NCorr), STAT = stat )
      call AllocationError( stat, 'thermal_diffusion', this%NCorr )

      allocate( this%average_cf_soret(NC, this%NCorr), STAT = stat )
      call AllocationError( stat, 'thermal_diffusion', this%NCorr )

      allocate( this%sinte_soret(NC, this%NCorr), STAT = stat )
      call AllocationError( stat, 'thermal_diffusion integrated', this%NCorr )

      allocate( this%average_sinte_soret( NC, this%NCorr), STAT = stat )
      call AllocationError( stat, 'thermal_diffusion integrated', this%NCorr )

      allocate( this%sinte_vb( this%NCorr), STAT = stat )
      call AllocationError( stat, 'bulk_viscosity_integrated', this%NCorr )

      allocate( this%average_sinte_vb( this%NCorr), STAT = stat )
      call AllocationError( stat, 'bulk_viscosity_integrated', this%NCorr )

      allocate( this%sinte_c( this%NCorr), STAT = stat )
      call AllocationError( stat, 'Thermal_conductivity_integrated', this%NCorr )

      allocate( this%average_sinte_c( this%NCorr), STAT = stat )
      call AllocationError( stat, 'Thermal_conductivity_integrated', this%NCorr )

      allocate( this%sinte_ec( this%NCorr), STAT = stat )
      call AllocationError( stat, 'Electric_conductivity_integrated', this%NCorr )

      allocate( this%average_sinte_ec( this%NCorr), STAT = stat )
      call AllocationError( stat, 'Electric_conductivity_integrated', this%NCorr )

      allocate( this%vsk(this%NCorr, 3), STAT = stat  )
      call AllocationError( stat, 'vsk', this%NPart )

      allocate( this%vsp(this%NCorr, 3), STAT = stat  )
      call AllocationError( stat, 'vsp', this%NPart )

      allocate( this%vbk(this%NCorr, 3), STAT = stat  )
      call AllocationError( stat, 'vbk', this%NPart )

      allocate( this%vbp(this%NCorr, 3), STAT = stat  )
      call AllocationError( stat, 'vbp', this%NPart )

      allocate( this%vckt(this%NCorr, 3), STAT = stat  )
      call AllocationError( stat, 'vckt', this%NPart )

      allocate( this%vckr(this%NCorr, 3), STAT = stat  )
      call AllocationError( stat, 'vckr', this%NPart )

      allocate( this%vcpt(this%NCorr, 3), STAT = stat  )
      call AllocationError( stat, 'vcpt', this%NPart )

      allocate( this%vcpr(this%NCorr, 3), STAT = stat  )
      call AllocationError( stat, 'vcpr', this%NPart )

      allocate( this%vcmt(this%NCorr, 3), STAT = stat  )
      call AllocationError( stat, 'vcmt', this%NPart )

      if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
        allocate( this%selfd_i(this%NComponents), STAT = stat  )
        call AllocationError( stat, 'selfd_i', this%NComponents )

        allocate( this%Sumself_i(this%NComponents), STAT = stat  )
        call AllocationError( stat, 'Sumselfd_i', this%NComponents )

        allocate( this%Onsager(this%NComponents,this%NComponents), STAT = stat  )
        call AllocationError( stat, 'Onsager', this%NComponents )

        allocate( this%SumOnsager(this%NComponents,this%NComponents), STAT = stat  )
        call AllocationError( stat, 'SumOnsager', this%NComponents )
      end if

      allocate( this%soret(NC), STAT = stat )
      call AllocationError( stat, 'Soret', this%NComponents )

      allocate( this%SumSoret(NC), STAT = stat )
      call AllocationError( stat, 'SumSoret', this%NComponents )

      if (TransMethod .eq. Einstein) then
         allocate( this%velcompX(NC, this%NCorr), STAT = stat )
         call AllocationError( stat, 'thermal_diffusion', this%NCorr )

         allocate( this%velcompY(NC, this%NCorr), STAT = stat )
         call AllocationError( stat, 'thermal_diffusion', this%NCorr )

         allocate( this%velcompZ(NC, this%NCorr), STAT = stat )
         call AllocationError( stat, 'thermal_diffusion', this%NCorr )
      end if

      !Einsteincoef allocate
      if ((TransMethod .eq. Einstein) .or. (TransMethod .eq. GKEinstein)) then
          allocate( this%EinsteinDSelfAcc(this%NComponents), STAT = stat  )
          call AllocationError( stat, 'EinsteinDSelfAcc', this%NComponents )
          allocate( this%EinsteinOnsagerAcc(this%NComponents,this%NComponents), STAT = stat  )
          call AllocationError( stat, 'EinsteinOnsagerAcc', this%NComponents )
      end if

      ! Set correlation-fucntion vectors

      this%cf_soret(:,:)  = 0._RK
      this%cf_vb(:)       = 0._RK
      this%cf_c(:)        = 0._RK
      this%cf_ec(:)       = 0._RK

      this%average_cf_soret(:,:) = 0._RK
      this%average_cf_vb(:)      = 0._RK
      this%average_cf_c(:)       = 0._RK
      this%average_cf_ec(:)      = 0._RK

      this%sinte_soret(:,:) = 0._RK
      this%sinte_vb(:)      = 0._RK
      this%sinte_c(:)       = 0._RK
      this%sinte_ec(:)      = 0._RK

      this%average_sinte_soret(:,:) = 0._RK
      this%average_sinte_vb(:)      = 0._RK
      this%average_sinte_c(:)       = 0._RK
      this%average_sinte_ec(:)      = 0._RK

      if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
        this%cf_d(:,:)      = 0._RK
        this%lamda(:,:)     = 0._RK
        this%cf_vs(:)       = 0._RK

        this%average_cf_d(:,:)     = 0._RK
        this%average_lamda(:,:)    = 0._RK
        this%average_cf_vs(:)      = 0._RK

        this%a(:,:)           = 0._RK
        this%A_SpanCF(:,:)    = 0._RK
        this%sinte_i(:,:)     = 0._RK
        this%sinte_lamda(:,:) = 0._RK
        this%sinte_vs(:)      = 0._RK

        this%average_sinte_i(:,:)     = 0._RK
        this%average_sinte_lamda(:,:) = 0._RK
        this%average_sinte_vs(:)      = 0._RK
        this%selfd_i(:)  = 0._RK
      end if

      this%vsk(:,:)    = 0._RK
      this%vsp(:,:)    = 0._RK
      this%vbk(:,:)    = 0._RK
      this%vbp(:,:)    = 0._RK
      this%vckt(:,:)   = 0._RK
      this%vckr(:,:)   = 0._RK
      this%vcpt(:,:)   = 0._RK
      this%vcpr(:,:)   = 0._RK
      this%vcmt(:,:)   = 0._RK

      this%sc(:) = 0._RK
      this%sp(:) = 0._RK
    end if

#endif

! Calculation of residence times
    if ( this%ResidenceTime ) then

      nullify( this%CompPair )
      nullify( this%CompPair_Old )
      nullify( this%ResidTimesStart )
      nullify( this%ResidTimesStart_Old )
      nullify( this%ResidPairsCem )

      allocate(this%CompPair(this%Component(this%ResidComp1)%NPart*10,2),STAT=stat)
      if(stat >0) write(*,*) 'Allocation Error this%CompPair'
      allocate(this%CompPair_Old(this%Component(this%ResidComp1)%NPart*10,2),STAT=stat)
      if(stat >0) write(*,*) 'Allocation Error this%CompPair'
      allocate(this%ResidTimesStart(this%Component(this%ResidComp1)%NPart*10),STAT=stat)
      if(stat >0) write(*,*) 'Allocation Error this%CompPair'
      allocate(this%ResidTimesStart_Old(this%Component(this%ResidComp1)%NPart*10),STAT=stat)
      if(stat >0) write(*,*) 'Allocation Error this%CompPair'
      allocate(this%ResidPairsCem(this%Component(this%ResidComp1)%NPart*10,4),STAT=stat)
      if(stat >0) write(*,*) 'Allocation Error this%CompPair'
    end if

  end subroutine TEnsemble_Allocate



