!==============================================================!
!  Subroutine TEnsemble_Force                                  !
!==============================================================!

  subroutine TEnsemble_Force( this )

    implicit none

    ! Include MPI header
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif

    ! Declare arguments
    type(TEnsemble) :: this

    ! Declare local variables
    type(TComponent), pointer :: pc
    real(RK)            :: EPot, Virial, d2EpotdV2
    integer             :: i, j

! #if MPI_VER > 0
!     integer             :: i0, i1, np, np1, n
! #endif
#if OSMOP == 2
#if MPI_VER > 0
    real(RK),allocatable :: VirialProfile(:)

    allocate( VirialProfile(NBinsDen) )
    VirialProfile(:) = 0._RK
#endif
#endif

! Zero forces
    do i = 1, this%NComponents
      pc => this%Component(i)
      do j = 1, this%Component(i)%Molecule%NMIEnm
        pc%Molecule%SiteMIEnm(j)%FX(1:pc%NPart) = 0._RK
        pc%Molecule%SiteMIEnm(j)%FY(1:pc%NPart) = 0._RK
        pc%Molecule%SiteMIEnm(j)%FZ(1:pc%NPart) = 0._RK

#if  TRANS == 1
        if(mod((Step+this%NStepCorr-1),this%NStepCorr) .eq. 0) then
          pc%Molecule%SiteMIEnm(j)%vsMIEx(1:pc%NPart) = 0._RK
          pc%Molecule%SiteMIEnm(j)%vsMIEy(1:pc%NPart) = 0._RK
          pc%Molecule%SiteMIEnm(j)%vsMIEz(1:pc%NPart) = 0._RK
          pc%Molecule%SiteMIEnm(j)%vbMIEx(1:pc%NPart) = 0._RK
          pc%Molecule%SiteMIEnm(j)%vbMIEy(1:pc%NPart) = 0._RK
          pc%Molecule%SiteMIEnm(j)%vbMIEz(1:pc%NPart) = 0._RK
  !        if ( this%Conductivity ) then
            pc%Molecule%SiteMIEnm(j)%vsuMIEx(1:pc%NPart)= 0._RK
            pc%Molecule%SiteMIEnm(j)%vsuMIEy(1:pc%NPart)= 0._RK
            pc%Molecule%SiteMIEnm(j)%vsuMIEz(1:pc%NPart)= 0._RK
            pc%Molecule%SiteMIEnm(j)%cMIEx(1:pc%NPart)  = 0._RK
            pc%Molecule%SiteMIEnm(j)%cMIEy(1:pc%NPart)  = 0._RK
            pc%Molecule%SiteMIEnm(j)%cMIEz(1:pc%NPart)  = 0._RK
            pc%Molecule%SiteMIEnm(j)%tuMIEx(1:pc%NPart) = 0._RK
            pc%Molecule%SiteMIEnm(j)%tuMIEy(1:pc%NPart) = 0._RK
            pc%Molecule%SiteMIEnm(j)%tuMIEz(1:pc%NPart) = 0._RK
            pc%Molecule%SiteMIEnm(j)%tlMIEx(1:pc%NPart) = 0._RK
            pc%Molecule%SiteMIEnm(j)%tlMIEy(1:pc%NPart) = 0._RK
            pc%Molecule%SiteMIEnm(j)%tlMIEz(1:pc%NPart) = 0._RK
            pc%Molecule%SiteMIEnm(j)%tdMIEx(1:pc%NPart) = 0._RK
            pc%Molecule%SiteMIEnm(j)%tdMIEy(1:pc%NPart) = 0._RK
            pc%Molecule%SiteMIEnm(j)%tdMIEz(1:pc%NPart) = 0._RK
   !       end if
        end if
#endif
      end do
      do j = 1, this%Component(i)%Molecule%NTT68
        pc%Molecule%SiteTT68(j)%FX(1:pc%NPart) = 0._RK
        pc%Molecule%SiteTT68(j)%FY(1:pc%NPart) = 0._RK
        pc%Molecule%SiteTT68(j)%FZ(1:pc%NPart) = 0._RK
#if  TRANS == 1
        if(mod((Step+this%NStepCorr-1),this%NStepCorr) .eq. 0) then
          pc%Molecule%SiteTT68(j)%vsTTx(1:pc%NPart) = 0._RK
          pc%Molecule%SiteTT68(j)%vsTTy(1:pc%NPart) = 0._RK
          pc%Molecule%SiteTT68(j)%vsTTz(1:pc%NPart) = 0._RK
          pc%Molecule%SiteTT68(j)%vbTTx(1:pc%NPart) = 0._RK
          pc%Molecule%SiteTT68(j)%vbTTy(1:pc%NPart) = 0._RK
          pc%Molecule%SiteTT68(j)%vbTTz(1:pc%NPart) = 0._RK
    !        if ( this%Conductivity ) then
            pc%Molecule%SiteTT68(j)%vsuTTx(1:pc%NPart)= 0._RK
            pc%Molecule%SiteTT68(j)%vsuTTy(1:pc%NPart)= 0._RK
            pc%Molecule%SiteTT68(j)%vsuTTz(1:pc%NPart)= 0._RK
            pc%Molecule%SiteTT68(j)%cTTx(1:pc%NPart)  = 0._RK
            pc%Molecule%SiteTT68(j)%cTTy(1:pc%NPart)  = 0._RK
            pc%Molecule%SiteTT68(j)%cTTz(1:pc%NPart)  = 0._RK
            pc%Molecule%SiteTT68(j)%tuTTx(1:pc%NPart) = 0._RK
            pc%Molecule%SiteTT68(j)%tuTTy(1:pc%NPart) = 0._RK
            pc%Molecule%SiteTT68(j)%tuTTz(1:pc%NPart) = 0._RK
            pc%Molecule%SiteTT68(j)%tlTTx(1:pc%NPart) = 0._RK
            pc%Molecule%SiteTT68(j)%tlTTy(1:pc%NPart) = 0._RK
            pc%Molecule%SiteTT68(j)%tlTTz(1:pc%NPart) = 0._RK
            pc%Molecule%SiteTT68(j)%tdTTx(1:pc%NPart) = 0._RK
            pc%Molecule%SiteTT68(j)%tdTTy(1:pc%NPart) = 0._RK
            pc%Molecule%SiteTT68(j)%tdTTz(1:pc%NPart) = 0._RK
    !       end if
        end if
#endif
      end do
      do j = 1, this%Component(i)%Molecule%NCharge
        pc%Molecule%SiteCharge(j)%FX(1:pc%NPart) = 0._RK
        pc%Molecule%SiteCharge(j)%FY(1:pc%NPart) = 0._RK
        pc%Molecule%SiteCharge(j)%FZ(1:pc%NPart) = 0._RK
#if  TRANS == 1
        if(mod((Step+this%NStepCorr-1),this%NStepCorr) .eq. 0) then
          pc%Molecule%SiteCharge(j)%vsCx(1:pc%NPart) = 0._RK
          pc%Molecule%SiteCharge(j)%vsCy(1:pc%NPart) = 0._RK
          pc%Molecule%SiteCharge(j)%vsCz(1:pc%NPart) = 0._RK
          pc%Molecule%SiteCharge(j)%vbCx(1:pc%NPart) = 0._RK
          pc%Molecule%SiteCharge(j)%vbCy(1:pc%NPart) = 0._RK
          pc%Molecule%SiteCharge(j)%vbCz(1:pc%NPart) = 0._RK
    !      if ( this%Conductivity ) then
            pc%Molecule%SiteCharge(j)%vsuCx(1:pc%NPart)= 0._RK
            pc%Molecule%SiteCharge(j)%vsuCy(1:pc%NPart)= 0._RK
            pc%Molecule%SiteCharge(j)%vsuCz(1:pc%NPart)= 0._RK
            pc%Molecule%SiteCharge(j)%cCx(1:pc%NPart)  = 0._RK
            pc%Molecule%SiteCharge(j)%cCy(1:pc%NPart)  = 0._RK
            pc%Molecule%SiteCharge(j)%cCz(1:pc%NPart)  = 0._RK
            pc%Molecule%SiteCharge(j)%tuCx(1:pc%NPart) = 0._RK
            pc%Molecule%SiteCharge(j)%tuCy(1:pc%NPart) = 0._RK
            pc%Molecule%SiteCharge(j)%tuCz(1:pc%NPart) = 0._RK
            pc%Molecule%SiteCharge(j)%tlCx(1:pc%NPart) = 0._RK
            pc%Molecule%SiteCharge(j)%tlCy(1:pc%NPart) = 0._RK
            pc%Molecule%SiteCharge(j)%tlCz(1:pc%NPart) = 0._RK
            pc%Molecule%SiteCharge(j)%tdCx(1:pc%NPart) = 0._RK
            pc%Molecule%SiteCharge(j)%tdCy(1:pc%NPart) = 0._RK
            pc%Molecule%SiteCharge(j)%tdCz(1:pc%NPart) = 0._RK
     !     end if
        end if
#endif
      end do
      do j = 1, this%Component(i)%Molecule%NDipole
        pc%Molecule%SiteDipole(j)%FX(1:pc%NPart) = 0._RK
        pc%Molecule%SiteDipole(j)%FY(1:pc%NPart) = 0._RK
        pc%Molecule%SiteDipole(j)%FZ(1:pc%NPart) = 0._RK
        pc%Molecule%SiteDipole(j)%TX(1:pc%NPart) = 0._RK
        pc%Molecule%SiteDipole(j)%TY(1:pc%NPart) = 0._RK
        pc%Molecule%SiteDipole(j)%TZ(1:pc%NPart) = 0._RK
#if  TRANS == 1
        if(mod((Step+this%NStepCorr-1),this%NStepCorr) .eq. 0) then
          pc%Molecule%SiteDipole(j)%vsDx(1:pc%NPart) = 0._RK
          pc%Molecule%SiteDipole(j)%vsDy(1:pc%NPart) = 0._RK
          pc%Molecule%SiteDipole(j)%vsDz(1:pc%NPart) = 0._RK
          pc%Molecule%SiteDipole(j)%vbDx(1:pc%NPart) = 0._RK
          pc%Molecule%SiteDipole(j)%vbDy(1:pc%NPart) = 0._RK
          pc%Molecule%SiteDipole(j)%vbDz(1:pc%NPart) = 0._RK
      !    if ( this%Conductivity ) then
            pc%Molecule%SiteDipole(j)%vsuDx(1:pc%NPart)= 0._RK
            pc%Molecule%SiteDipole(j)%vsuDy(1:pc%NPart)= 0._RK
            pc%Molecule%SiteDipole(j)%vsuDz(1:pc%NPart)= 0._RK
            pc%Molecule%SiteDipole(j)%cDx(1:pc%NPart)  = 0._RK
            pc%Molecule%SiteDipole(j)%cDy(1:pc%NPart)  = 0._RK
            pc%Molecule%SiteDipole(j)%cDz(1:pc%NPart)  = 0._RK
            pc%Molecule%SiteDipole(j)%tuDx(1:pc%NPart) = 0._RK
            pc%Molecule%SiteDipole(j)%tuDy(1:pc%NPart) = 0._RK
            pc%Molecule%SiteDipole(j)%tuDz(1:pc%NPart) = 0._RK
            pc%Molecule%SiteDipole(j)%tlDx(1:pc%NPart) = 0._RK
            pc%Molecule%SiteDipole(j)%tlDy(1:pc%NPart) = 0._RK
            pc%Molecule%SiteDipole(j)%tlDz(1:pc%NPart) = 0._RK
            pc%Molecule%SiteDipole(j)%tdDx(1:pc%NPart) = 0._RK
            pc%Molecule%SiteDipole(j)%tdDy(1:pc%NPart) = 0._RK
            pc%Molecule%SiteDipole(j)%tdDz(1:pc%NPart) = 0._RK
       !   end if
        end if
#endif
      end do
      do j = 1, this%Component(i)%Molecule%NQuadrupole
        pc%Molecule%SiteQuadrupole(j)%FX(1:pc%NPart) = 0._RK
        pc%Molecule%SiteQuadrupole(j)%FY(1:pc%NPart) = 0._RK
        pc%Molecule%SiteQuadrupole(j)%FZ(1:pc%NPart) = 0._RK
        pc%Molecule%SiteQuadrupole(j)%TX(1:pc%NPart) = 0._RK
        pc%Molecule%SiteQuadrupole(j)%TY(1:pc%NPart) = 0._RK
        pc%Molecule%SiteQuadrupole(j)%TZ(1:pc%NPart) = 0._RK
#if  TRANS == 1
        if(mod((Step+this%NStepCorr-1),this%NStepCorr) .eq. 0) then
          pc%Molecule%SiteQuadrupole(j)%vsQx(1:pc%NPart) = 0._RK
          pc%Molecule%SiteQuadrupole(j)%vsQy(1:pc%NPart) = 0._RK
          pc%Molecule%SiteQuadrupole(j)%vsQz(1:pc%NPart) = 0._RK
          pc%Molecule%SiteQuadrupole(j)%vbQx(1:pc%NPart) = 0._RK
          pc%Molecule%SiteQuadrupole(j)%vbQy(1:pc%NPart) = 0._RK
          pc%Molecule%SiteQuadrupole(j)%vbQz(1:pc%NPart) = 0._RK
        !  if ( this%Conductivity ) then
            pc%Molecule%SiteQuadrupole(j)%vsuQx(1:pc%NPart)= 0._RK
            pc%Molecule%SiteQuadrupole(j)%vsuQy(1:pc%NPart)= 0._RK
            pc%Molecule%SiteQuadrupole(j)%vsuQz(1:pc%NPart)= 0._RK
            pc%Molecule%SiteQuadrupole(j)%cQx(1:pc%NPart)  = 0._RK
            pc%Molecule%SiteQuadrupole(j)%cQy(1:pc%NPart)  = 0._RK
            pc%Molecule%SiteQuadrupole(j)%cQz(1:pc%NPart)  = 0._RK
            pc%Molecule%SiteQuadrupole(j)%tuQx(1:pc%NPart) = 0._RK
            pc%Molecule%SiteQuadrupole(j)%tuQy(1:pc%NPart) = 0._RK
            pc%Molecule%SiteQuadrupole(j)%tuQz(1:pc%NPart) = 0._RK
            pc%Molecule%SiteQuadrupole(j)%tlQx(1:pc%NPart) = 0._RK
            pc%Molecule%SiteQuadrupole(j)%tlQy(1:pc%NPart) = 0._RK
            pc%Molecule%SiteQuadrupole(j)%tlQz(1:pc%NPart) = 0._RK
            pc%Molecule%SiteQuadrupole(j)%tdQx(1:pc%NPart) = 0._RK
            pc%Molecule%SiteQuadrupole(j)%tdQy(1:pc%NPart) = 0._RK
            pc%Molecule%SiteQuadrupole(j)%tdQz(1:pc%NPart) = 0._RK
         ! end if
        end if
#endif
      end do
      if( pc%Molecule%isElongated ) then
        pc%tRFX(:) = 0._RK
        pc%tRFY(:) = 0._RK
        pc%tRFZ(:) = 0._RK
      end if
#if  TRANS == 1
      if(mod((Step+this%NStepCorr-1),this%NStepCorr) .eq. 0) then
        do j = 1, this%Component(i)%NPart
          this%Component(i)%FS(j, 1)    = 0._RK
          this%Component(i)%FS(j, 2)    = 0._RK
          this%Component(i)%FS(j, 3)    = 0._RK
          this%Component(i)%FB(j, 1)    = 0._RK
          this%Component(i)%FB(j, 2)    = 0._RK
          this%Component(i)%FB(j, 3)    = 0._RK
    !      if ( this%Conductivity ) then
            this%Component(i)%FTC(j, 1)   = 0._RK
            this%Component(i)%FTC(j, 2)   = 0._RK
            this%Component(i)%FTC(j, 3)   = 0._RK
            this%Component(i)%FRC(j, 1)   = 0._RK
            this%Component(i)%FRC(j, 2)   = 0._RK
            this%Component(i)%FRC(j, 3)   = 0._RK
     !     end if
        end do
      end if
#endif
    end do

    if( this%NMIEnmMax > 0 ) then
      ! potential energy correction
      EPot = this%Density * this%EPotCorrMIE + this%EPotCorrRF

      ! virial correction
      Virial = this%Density * this%VirialCorrMIE + Third*this%VirialCorrRF

      ! d2Epot/dV2 correction
      d2EpotdV2 = this%Density * this%d2EpotdV2CorrMIE
    endif
    if( this%NTT68Max > 0 ) then
     ! potential energy correction
      EPot = this%Density * this%EPotCorrTT68 + this%EPotCorrRF

      ! virial correction
      Virial = this%Density * this%VirialCorrTT68 + Third*this%VirialCorrRF

      ! d2Epot/dV2 correction
      d2EpotdV2 = this%Density * this%d2EpotdV2CorrTT68
    endif

    ! Loop over components
    do i = 1, this%NComponents
      do j = i, this%NComponents
#if TRANS == 1
        if(.not. Equilibration) then
           if((mod((Step+this%NStepCorr-1),this%NStepCorr) .eq. 0)) then
              call Force_Trans( this%Interaction( i, j ), EPot, Virial, d2EpotdV2, this%BoxLength, this%BoxLength/this%KBIdr)!L/KBIdr is optional if MD with KBI is active
            else
              call Force( this%Interaction( i, j ), EPot, Virial, d2EpotdV2, this%BoxLength, this%BoxLength/this%KBIdr)!L/KBIdr is optional if MD with KBI is active
            endif
        else
          call Force( this%Interaction( i, j ), EPot, Virial, d2EpotdV2, this%BoxLength)
        endif
#else
        call Force( this%Interaction( i, j ), EPot, Virial, d2EpotdV2, this%BoxLength, this%BoxLength/this%KBIdr)!L/KBIdr is optional if MD with KBI is active
#endif

      end do
    end do

    if (LongRange .eq. Ewald) then
      call EwaldFourierTerm (this)
#if SPME > 0
    else if (LongRange .eq. PME) then
      call PMEFourierTerm (this)
#endif
    end if


    ! Collect sums from all processes
#if MPI_VER > 0
    ! use MPI_RK (cmp. ms2_global.F90) instead of MPI_RK
    call MPI_Reduce( EPot, this%EPot, 1, MPI_RK, MPI_SUM, NRootProc, Communicator, ierror )
    call MPI_Reduce( Virial, this%Virial, 1, MPI_RK, MPI_SUM, NRootProc, Communicator, ierror )
    call MPI_Reduce( d2EpotdV2, this%d2EpotdV2, 1, MPI_RK, MPI_SUM, NRootProc, Communicator, ierror )
#if OSMOP == 2
    call MPI_Reduce( this%VirialProfile(:), VirialProfile(:), NBinsDen, MPI_RK, MPI_SUM, NRootProc, Communicator, ierror )
    if (RootProc) this%VirialProfile(:) = VirialProfile(:)
#endif
#else
    this%EPot = EPot
    this%Virial = Virial
    this%d2EpotdV2 = d2EpotdV2
#endif

    if (RootProc) then
      if (LongRange .eq. Ewald) then
        this%EPot   = this%EPot   + this%UFourier + this%USelbstTerm + this%UIntra
        this%Virial = this%Virial + this%EVirial
#if SPME > 0
      else if (LongRange .eq. PME) then
        this%EPot   = this%EPot   + this%UFourier + this%USelbstTerm + this%UIntra
        this%Virial = this%Virial + this%EVirial
#endif
      end if
    end if

    ! Calculate pressure
    this%Pressure = this%Density * this%Temperature + this%Virial / this%Volume0

  end subroutine TEnsemble_Force



!==============================================================!
!  Subroutine TEnsemble_ChemicalPotential                      !
!==============================================================!

  subroutine TEnsemble_ChemicalPotential( this )

    implicit none

    ! Include MPI header
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif

    ! Declare arguments
    type(TEnsemble) :: this

    ! Declare local variables
    real(RK)                  :: ChemPot, qsum, ExpMinusBetaEnLaMin, factor
    real(RK)                  :: HW_H_local, HW_V_local, HW_counter_local, HW_denom_local
    integer                   :: i, j, t
    integer                   :: ndf, ndfmove, ndfbiased, ndffluct, ndfchange, ndfcp
    integer                   :: r, s, nc, np, ncf, npf
    integer                   :: ratio, sndf, nuh
    type(TComponent), pointer :: pc
    integer                   :: nstate( 0:this%NFluctMax )
#if MPI_VER > 0
#if MPI_USE_MODULE
    TYPE(MPI_Comm)            :: tempComm
#else
    integer                   :: tempComm
#endif
    integer                   :: tempVec(0:this%NFluctMax)
    integer                   :: tempVec1(this%NFluctMax), tempVec2(this%NFluctMax)
    integer                   :: tempVec3(this%NFluctMax), tempVec4(this%NFluctMax)
#endif
#if OSMOP == 2
    real(RK)                  :: ChemPotProfile(NBinsDen)
    integer                   :: NTestBinDen, m
#if MPI_VER > 0
    integer                   :: NTestBinDenAll
#endif
#endif

    ! No calculation of chemical potential in equilibration
    if( Equilibration ) then
      do i = 1, this%NRealComponents
        this%Component(i)%CalcChemPot = .false.
        this%Component(i)%ChemPot = 0._RK
        this%Component(i)%ChemPot1 = 0._RK
        this%Component(i)%ChemPot2 = 0._RK
      end do
      return
    end if

    if( Equilibration ) return

    ! Throw test particles
    do i = 1, this%NTestMax
      do j = 1, 3
        this%P0Test( i, j ) = tprnd( -.5_RK, .5_RK )
      end do
      do
        qsum = 0._RK
        do j = 1, 4
          this%Q0Test(i, j) = tprnd( -1._RK, 1._RK )
        end do
        qsum = sum( this%Q0Test(i, :)**2 )
        if( qsum <= 1._RK ) exit
      end do
      this%Q0Test(i, :) = this%Q0Test(i, :) / sqrt( qsum )
    end do

#if MPI_VER > 0
    tempComm = Communicator
#endif

    t = this%NRealComponents+1  ! pseudo component identifier for ThermoInt (ThermoInt does not function together with GradIns)

    ! Outer loop over components
componentLoop:       do i = 1, this%NRealComponents
      pc => this%Component(i)
      if( Equilibration .and. pc%WFMethod .ne. WFMethodGuess ) cycle
      select case( pc%ChemPotMethod )

      ! Chemical potential by gradual insertion
      case( ChemPotMethodGradIns )
        if( (((pc%GradInsInit .eq. 0) .or. (Step .gt. pc%GradInsInit)) .and. GradInsInitialization) .or. (pc%WFMethod .ne. WFMethodGuess)) cycle componentLoop

        ! Reset variables
        if( Step == 1 ) then
          pc%ProbW0      = 0._RK
          pc%ProbW1      = 0._RK
          pc%ProbW0V     = 0._RK
          pc%ProbW1Rho   = 0._RK
          pc%NStateWF(:) = 0
        end if

        ! determine, if chemical potential has to be calculated
        pc%CalcChemPot = .false.

        if( GradInsFrequency > 0 ) then
          if( mod( Step, GradInsFrequency ) == 0 ) pc%CalcChemPot = .true.
        end if

        if (GradInsInitialization) then
          pc%CalcChemPot = .true.
        end if

#if MPI_VER > 0
        ! Per Process we calculate GI only for one component
        if (mod(NProc,this%NGradInsComp)/= pc%NGradThis) pc%CalcChemPot = .false.
#endif

        if( pc%CalcChemPot ) then

          ! Set fluctuating particle
          ncf = pc%NFluctComp( pc%NFluctState )
          if( ncf == i ) then
            npf = rnd( pc%NPart )
            call Move2End(pc, npf)
          else
            npf = 1
          end if

          ! Specify max amount of biased interaction partners
          call BiasedPartners(this, ncf, npf)

          ! Specify ratio of biased Moves
          ratio = (this%NGradIns * 50 / this%NDF )
          ndfmove = this%NDF
          ndfbiased = this%NDF * ratio
          ndffluct = this%NDF * 10
          ndfchange = this%NDF * 10
          ndfcp = ndfmove + ndfbiased + ndffluct + ndfchange
          pc%NState(:) = 1
          nstate = 0

giloop:   do j = 1, NFullFluct * ndfcp

            ! Update List for Biased Moves
            if (mod(j,ndfcp) == 0) call BiasedPartners(this, ncf, npf)

            ! Choose particle randomly
            s = 0
            sndf = 0
            r = rnd( ndfcp )

            if( r <= ndfmove ) then
loop1:        do nc = 1, this%NComponents
                s = s + this%Component(nc)%NDF
                if( r <= s ) exit loop1
              end do loop1
              ndf = this%Component(nc)%Molecule%NDF
              np = 1 + (s - r) / ndf

              ! Acceleration of MC Moves
              if (np .gt. this%Component(nc)%NPart) cycle

              ! Move or rotate
              if( mod( s - r, ndf ) < 3 ) then
                call Move( this, nc, np )
              else
                call Rotate( this, nc, np )
              end if

            else if( r <= (ndfmove + ndfbiased) ) then
              r = (r - ndfmove - 1) / ratio + 1
              nuh = int( (r-1)* this%NGradIns / (ndfbiased/ratio) )
loop2:        do nc = 1, this%NComponents
                s = s + this%Component(nc)%BiasedPartners
                if( nuh < s ) exit loop2
                sndf = sndf + this%Component(nc)%BiasedPartners
              end do loop2
              ndf = this%Component(nc)%Molecule%NDF
              np = this%BiasedPartners(int((nuh-sndf)*this%Component(nc)%BiasedPartnersNum / this%Component(nc)%BiasedPartners)+1)

              ! Acceleration of MC Moves
              if (np .gt. this%Component(nc)%NPart) cycle

              ! Move or rotate biased
              if( mod( sndf - r, ndf ) < 3 ) then
                call MoveBiased( this, nc, np, ncf, npf )
              else
                call RotateBiased( this, nc, np, ncf, npf )
              end if

            else if( r <= (ndfmove + ndfbiased + ndffluct) ) then
              r = r - ndfmove - ndfbiased
              ndf = this%Component(ncf)%Molecule%NDF

              ! Move or rotate fluctuating particle
              if( mod( r, ndf ) < 3 ) then
                call Move( this, ncf, npf )
              else
                call Rotate( this, ncf, npf )
              end if

            else

              ! Change fluctuating particle
              call ChangeFluct( this, i, ncf, npf )
              nstate(pc%NFluctState) = nstate(pc%NFluctState) + 1

            end if

          end do giloop

          pc%NStateWF = pc%NStateWF + nstate(0:pc%NFluctMax)
          pc%NState = pc%NState + nstate(0:pc%NFluctMax)


          ! Calculate weighted propabilities
          pc%ProbW0 = pc%ProbW0 + real(pc%NState(0), RK)
          pc%ProbW1 = pc%ProbW1 + real( pc%NState(pc%NFluctMax), RK ) / pc%WF( pc%NFluctMax )
          pc%ProbW0V = pc%ProbW0V + real(pc%NState(0), RK) / this%Density
          pc%ProbW1Rho = pc%ProbW1Rho + real( pc%NState(pc%NFluctMax), RK ) / pc%WF(pc%NFluctMax) * this%Density

          ! Calculate chemical potential
          ! (long range correction already done in ChangeFluct)
          pc%ChemPot = pc%ProbW0 / pc%ProbW1Rho
          pc%ChemPot1 = pc%ProbW0 / pc%ProbW1
          pc%ChemPot2 = pc%ProbW0V / pc%ProbW1

        else
!           pc%CalcChemPot = .false.
          pc%ChemPot = 0._RK
        end if

         if( mod( Step, ErrorsUpdateFrequency ) == 0 .or. ( GradInsInitialization))  then
          ! Here we sum up the NStateWF over all processes
          ! dealing with a specific component to improve statistics
#if MPI_VER > 0
          call MPI_Allreduce(pc%NStateWF,tempVec(0:pc%NFluctMax),size(pc%NStateWF),MPI_INTEGER, MPI_SUM, Communicator, ierror)
          pc%NStateWF = tempVec(0:pc%NFluctMax)
          call MPI_Reduce( pc%NFluctUpSuccesses(:),tempVec1(1:pc%NFluctMax), pc%NFluctMax, MPI_INTEGER, MPI_SUM, NRootProc, Communicator, ierror )
          call MPI_Reduce( pc%NFluctUpAttempts(:),tempVec2(1:pc%NFluctMax), pc%NFluctMax, MPI_INTEGER,  MPI_SUM, NRootProc, Communicator, ierror )
          call MPI_Reduce( pc%NFluctDownSuccesses(:),tempVec3(1:pc%NFluctMax), pc%NFluctMax, MPI_INTEGER, MPI_SUM, NRootProc, Communicator, ierror )
          call MPI_Reduce( pc%NFluctDownAttempts(:),tempVec4(1:pc%NFluctMax), pc%NFluctMax, MPI_INTEGER, MPI_SUM, NRootProc, Communicator, ierror )

           do j = 1, pc%NFluctMax
            pc%WF(j) = pc%WF(j) * real(pc%NStateWF(0) + 1, RK) / real(pc%NStateWF(j) + 1, RK)
           end do
          write( IOBuffer, '("New weighting factors for ",A," calculated:")' ) trim( pc%PotModFileName )
          call LogWrite
          write( IOBuffer, '("   State      NState      new WF     up        down (%)")' )
          call LogWrite
          write( IOBuffer, '("   --------------------------------  --------  --------")' )
          call LogWrite
          j = pc%NFluctMax
          write( IOBuffer, '(I8, I12, F15.2, 2F10.4)' ) j, pc%NStateWF(j), pc%WF(j), 0._RK, real(tempVec3(j), RK) / &
&             real(tempVec4(j), RK) * 100._RK
            call LogWrite

          do j = pc%NFluctMax - 1, 1, -1
            write( IOBuffer, '(I8, I12, F15.2, 2F10.4)' ) j, pc%NStateWF(j), pc%WF(j), real(tempVec1(j+1), RK) / &
&               real(tempVec2(j+1), RK) * 100._RK, real(tempVec3(j), RK) / real(tempVec4(j), RK) * 100._RK
            call LogWrite
          end do
          write( IOBuffer, '(I8, I12, F15.2, 2F10.4)' ) 0, pc%NStateWF(0), pc%WF(0), real(tempVec1(1), RK) / &
&             real(tempVec2(1), RK) * 100._RK, 0._RK
          call LogWrite
          call LogWriteBlank
          pc%NStateWF(:) = 0

#else
          do j = 1, pc%NFluctMax
            pc%WF(j) = pc%WF(j) * real(pc%NStateWF(0) + 1, RK) / real(pc%NStateWF(j) + 1, RK)
          end do
          write( IOBuffer, '("New weighting factors for ",A," calculated:")' ) trim( pc%PotModFileName )
          call LogWrite
          write( IOBuffer, '("   State      NState      new WF     up        down (%)")' )
          call LogWrite
          write( IOBuffer, '("   --------------------------------  --------  --------")' )
          call LogWrite
          j = pc%NFluctMax
          write( IOBuffer, '(I8, I12, F15.2, 2F10.4)' ) j, pc%NStateWF(j), pc%WF(j), 0._RK, real(pc%NFluctDownSuccesses(j), RK) / &
&             real(pc%NFluctDownAttempts(j), RK) * 100._RK
            call LogWrite

          do j = pc%NFluctMax - 1, 1, -1
            write( IOBuffer, '(I8, I12, F15.2, 2F10.4)' ) j, pc%NStateWF(j), pc%WF(j), real(pc%NFluctUpSuccesses(j+1), RK) / &
&               real(pc%NFluctUpAttempts(j+1), RK) * 100._RK, real(pc%NFluctDownSuccesses(j), RK) / &
&               real(pc%NFluctDownAttempts(j), RK) * 100._RK
            call LogWrite
          end do

          write( IOBuffer, '(I8, I12, F15.2, 2F10.4)' ) 0, pc%NStateWF(0), pc%WF(0), &
&           real(pc%NFluctUpSuccesses(1), RK) / real(pc%NFluctUpAttempts(1), RK) * 100._RK, 0._RK
          call LogWrite
          call LogWriteBlank
          pc%NStateWF(:) = 0
#endif
        end if


      ! Chemical potential by Widom's test particle method
      ! Just applicable for ReactionField Method.
      ! - otherwise you cannot calculate the energy of only 1 particle
      ! Check earlier in ms2_ensemble (right after component construction

      case( ChemPotMethodWidom )
        pc%CalcChemPot = .true.
        call Mol2AtomTest( this%Component(i), this%Component(i)%NTest )

        if( this%NMIEnmMax > 0 ) then
          this%EPotTest(:) = this%Density * pc%EPotTestCorrMIE + pc%EPotTestCorrRF
        endif
        if( this%NTT68Max > 0 ) then
          this%EPotTest(:) = this%Density * pc%EPotTestCorrTT68 + pc%EPotTestCorrRF
        endif

        do j = 1, this%NRealComponents
          call ChemicalPotential( this%Interaction( i, j ), this%EPotTest, this%BoxLength )
        end do

        ChemPot = 0.0
        do j = 1, this%Component(i)%NTest
          ChemPot = ChemPot + exp( -( this%EPotTest(j) ) / this%Temperature )
        end do
        ChemPot = ChemPot/pc%NTest

#if MPI_VER > 0
        if ( SimulationType .ne. MonteCarlo .or. (Equilibration .and. CommonEqui) .or. (mpiMCCommonGroups > 0)) then
          call MPI_Bcast( this%Density, 1, MPI_RK, NRootProc, Communicator, ierror )
          call MPI_Bcast( this%EPot, 1, MPI_RK,  NRootProc, Communicator, ierror )
        endif
#endif

        ! partial molar enthalpy
       HW_H_local = this%EPot + ( this%RefPressure / this%Density ) * real( this%NPart, RK )
       HW_V_local = (1.0 / this%Density) * this%NPart
       HW_denom_local = 0
       HW_counter_local = 0

       do j=1, pc%NTest
          HW_counter_local= HW_counter_local + ( HW_H_local + this%EPotTest(j) ) * exp( - this%EPotTest(j) / this%RefTemperature )
          HW_denom_local = HW_denom_local + exp( - this%EPotTest(j) / this%RefTemperature )
       end do

       HW_counter_local = HW_V_local * HW_counter_local / pc%NTest
       HW_denom_local = HW_V_local * HW_denom_local / pc%NTest

#if MPI_VER > 0
        if ( SimulationType .ne. MonteCarlo .or. (Equilibration .and. CommonEqui) .or. (mpiMCCommonGroups > 0)) then
          ! use MPI_RK (cmp. ms2_global.F90) instead of MPI_RK
          call MPI_Reduce( ChemPot, pc%ChemPot, 1, MPI_RK, MPI_SUM, NRootProc, Communicator, ierror )
          call MPI_Reduce( HW_counter_local, pc%HW_counter, 1, MPI_RK, MPI_SUM, NRootProc, Communicator, ierror )
          call MPI_Reduce( HW_denom_local, pc%HW_denom, 1, MPI_RK, MPI_SUM, NRootProc, Communicator, ierror )
          pc%ChemPot = pc%ChemPot/NProcs
          pc%HW_counter = pc%HW_counter/NProcs
          pc%HW_denom = pc%HW_denom/NProcs
        else
          pc%ChemPot = ChemPot
          pc%HW_counter = HW_counter_local
          pc%HW_denom = HW_denom_local
        endif
#else
        pc%ChemPot = ChemPot
        pc%HW_counter = HW_counter_local
        pc%HW_denom = HW_denom_local
#endif

#if OSMOP == 2
        ! Profile of  the chemical potential
        ! Initialize local arrays
        if (SimulationType .eq. MolecularDynamics ) then
          ChemPotProfile(:) = 0._RK

          do j=1, NBinsDen

            NTestBinDen = 0

            do m=1, pc%NTest
              if (this%P0Test(m,1) .ge. real(j-1)/NBinsDen) then
                if (this%P0Test(m,1) < real(j)/NBinsDen) then
                  ChemPotProfile(j) = ChemPotProfile(j) + (exp( -( this%EPotTest(m)) /  this%Temperature))
                  NTestBinDen = NTestBinDen + 1
                end if
              end if
            end do

#if MPI_VER > 0
            call MPI_Allreduce(NTestBinDen,NTestBinDenAll,1,MPI_INTEGER, MPI_SUM, Communicator, ierror)
            if ( NTestBinDenAll > 1) then
              ChemPotProfile(j)= ChemPotProfile(j) / NTestBinDenAll
            end if
            call MPI_Reduce( ChemPotProfile(j), pc%ChemPotProfile(j), 1, MPI_RK, MPI_SUM, NRootProc, Communicator, ierror )
#else
            if ( NTestBinDen > 1) then
              ChemPotProfile(j)= ChemPotProfile(j) / NTestBinDen
            end if
            pc%ChemPotProfile(j) = ChemPotProfile(j)
#endif

          end do !NBinsDen
        end if
#endif

      case( ChemPotMethodThermoInt )

        if (Step == 1) then
          pc%BinsVisit(:)=0
          pc%BinsEn(:)=0.0_RK
          pc%BinsdEndLa(:)=0.0_RK
          pc%BinsIntdEndLa(:)=0.0_RK
          pc%BinsdEndLaV(:)=0.0_RK
          pc%BinsdEndLaH(:)=0.0_RK
          pc%BinsIntVW(:)=0.0_RK
          pc%BinsIntHW(:)=0.0_RK
          pc%CalcChemPot= .true.
        end if

        call ChangeLambda( this, t, i )
        t=t+1

        ! chemPot with LambdaMin by Widom
        call Mol2AtomTest( this%Component(i), this%Component(i)%NTest )

        if( this%NMIEnmMax > 0 ) then
          this%EPotTest(:) = this%Density * pc%EPotTestCorrMIE + pc%EPotTestCorrRF
        endif
        if( this%NTT68Max > 0 ) then
          this%EPotTest(:) = this%Density * pc%EPotTestCorrTT68 + pc%EPotTestCorrRF
        endif

        do j = 1, this%NComponents
          call ChemicalPotential( this%Interaction( i, j ), this%EPotTest, this%BoxLength )
        end do
        factor=pc%LaMin**pc%LambdaExponent
        ExpMinusBetaEnLaMin = sum( exp( -( factor*this%EPotTest(:) ) / this%Temperature ) ) / pc%NTest

#if MPI_VER > 0
        if ( SimulationType .ne. MonteCarlo .or. (Equilibration .and. CommonEqui) .or. (mpiMCCommonGroups > 0)) then
          call MPI_Bcast( this%Density, 1, MPI_RK, NRootProc, Communicator, ierror )
          call MPI_Bcast( this%EPot, 1, MPI_RK,  NRootProc, Communicator, ierror )
        endif
#endif

        ! partial molar enthalpy
       HW_H_local = this%EPot + ( this%RefPressure / this%Density ) * real( this%NPart, RK )
       HW_V_local = (1.0 / this%Density) * this%NPart
       HW_denom_local = 0
       HW_counter_local = 0

       do j=1, pc%NTest
          HW_counter_local= HW_counter_local + HW_V_local * ( HW_H_local + factor*this%EPotTest(j) ) * exp( - factor*this%EPotTest(j) / this%RefTemperature )
          HW_denom_local = HW_denom_local + HW_V_local * exp( - factor*this%EPotTest(j) / this%RefTemperature )
       end do

       HW_counter_local = HW_counter_local / pc%NTest
       HW_denom_local = HW_V_local * HW_denom_local / pc%NTest

#if MPI_VER > 0
        if ( SimulationType .eq. MolecularDynamics .or. (Equilibration .and. CommonEqui) .or. (mpiMCCommonGroups > 0) ) then
          ! use MPI_RK (cmp. ms2_global.F90) instead of MPI_RK
          call MPI_Reduce( ExpMinusBetaEnLaMin, pc%ExpMinusBetaEnLaMin, 1, MPI_RK, MPI_SUM, NRootProc, Communicator, ierror )
          call MPI_Reduce( HW_counter_local, pc%HW_counter, 1, MPI_RK, MPI_SUM, NRootProc, Communicator, ierror )
          call MPI_Reduce( HW_denom_local, pc%HW_denom, 1, MPI_RK, MPI_SUM, NRootProc, Communicator, ierror )
          pc%ExpMinusBetaEnLaMin = pc%ExpMinusBetaEnLaMin/NProcs
          pc%HW_counter = pc%HW_counter/NProcs
          pc%HW_denom = pc%HW_denom/NProcs
        else
          pc%ExpMinusBetaEnLaMin = ExpMinusBetaEnLaMin
          pc%HW_counter = HW_counter_local
          pc%HW_denom = HW_denom_local
        endif
#else
        pc%ExpMinusBetaEnLaMin = ExpMinusBetaEnLaMin
        pc%HW_counter = HW_counter_local
        pc%HW_denom = HW_denom_local
#endif
        ! end of Widom for ThermoInt with LambdaMin

      case default
        pc%CalcChemPot = .false.
        pc%ChemPot = 0._RK
        pc%HW_counter = 0._RK
        pc%HW_denom = 0._RK
      end select

    end do  componentLoop

    contains

    function tprnd( l_range, h_range ) result( rharvest )

      implicit none

      ! Declare arguments
      real(RK), intent(in) :: l_range, h_range

      ! Declare result
      real(RK) :: rharvest

      ! Declare local variables
      integer(K4B), parameter :: IA=16807, IM=2147483647, IQ=127773, IR=2836

      ! Generate fast random number
      tpix = ieor(tpix, ishft(tpix, 13))
      tpix = ieor(tpix, ishft(tpix, -17))
      tpix = ieor(tpix, ishft(tpix, 5))
      rharvest = l_range + am * ior(iand(IM, tpix), 1) * (h_range - l_range)

    end function tprnd

  end subroutine TEnsemble_ChemicalPotential



!==============================================================!
!  Subroutine TEnsemble_Energy                                 !
!==============================================================!

  subroutine TEnsemble_Energy( this, E, d2EdV2, V )

    implicit none

    ! Declare arguments
    type(TEnsemble)       :: this
    real(RK), intent(out) :: E
    real(RK), intent(out) :: d2EdV2
    real(RK), intent(out) :: V

    ! Declare local variables
    type(TInteraction), pointer :: pi
    integer                     :: nc, np
    integer                     :: i
    logical                     :: matrixhalf

    ! Initialize new energy
    E = 0._RK
    d2EdV2 = 0._RK
    V = 0._RK

    if (LongRange .eq. Ewald) then
      call EwaldSelfTerm_Energy ( this )
#if SPME > 0
    else if (LongRange .eq. PME) then
      call PMESelfTermMC ( this )
#endif
    end if

    ! Loop over components
    do nc = 1, this%NComponents
      do i = nc, this%NComponents
        pi => this%Interaction(nc, i)
        matrixhalf = nc == i !SameComponent => matrixhalf=.true.
        ! Loop over particles
        do np = 1, this%Component(nc)%NPart
          call Energy( pi, np, this%BoxLength, matrixhalf )
          ! Sum energy
          E = E + pi%EPot
          d2EdV2 = d2EdV2 + pi%d2EpotdV2
          V = V + pi%Virial
        end do
      end do
    end do

    ! Calculate new energy
    if( this%NMIEnmMax > 0 ) then
      !selfterm ReactionField contribution to pressure and EPot was turned off for MC
      !because it does not need selfterm correction
      E =  E + this%Density * this%EPotCorrMIE !+ this%EPotCorrRF
      d2EdV2 =  d2EdV2 + this%Density * this%d2EpotdV2CorrMIE
      V =  V + this%Density * this%VirialCorrMIE !+ Third*this%VirialCorrRF
    endif
    if( this%NTT68Max > 0 ) then
      !selfterm ReactionField contribution to pressure and EPot was turned off for MC
      !because it does not need selfterm correction
      E = E + this%Density * this%EPotCorrTT68 !+ this%EPotCorrRF
      d2EdV2 = d2EdV2 + this%Density * this%d2EpotdV2CorrTT68
      V = V + this%Density * this%VirialCorrTT68 !+ Third*this%VirialCorrRF
    endif



! Ewald
    if (LongRange .eq. Ewald) then
      call EwaldFourierEnergy(this)
      E = E + this%UFourier + this%UIntra + this%USelbstTerm
#if SPME > 0
    else if (LongRange .eq. PME) then
      call charge_grid_MCall ( this )
      call PMEFourierTermMC ( this )
      E = E + this%UFourier + this%UIntra + this%USelbstTerm
#endif
    end if

  end subroutine TEnsemble_Energy



!==============================================================!
!  Subroutine TEnsemble_Energy1                                !
!==============================================================!

  subroutine TEnsemble_Energy1( this, nc, np, EPotNew )

    implicit none

    ! Declare arguments
    type(TEnsemble)       :: this
    integer, intent(in)   :: nc, np
    real(RK), intent(out) :: EPotNew

    ! Declare local variables
    type(TInteraction), pointer :: pi
    integer                     :: i

    ! Initialize new energy
    EPotNew = 0._RK

    ! Loop over components
    do i = 1, this%NComponents
      pi => this%Interaction(nc, i)

      call Energy( pi, np, this%BoxLength, .false. )

      ! Calculate new energy
      EPotNew = EPotNew + pi%EPot
    end do

    if (LongRange .eq. Ewald) then
       call EwaldFourierEnergy(this,nc,np)
       EPotNew = EPotnew + this%UFourier
#if SPME > 0
    else if (LongRange .eq. PME) then
       call PMEFourierTermMC ( this )
       EPotNew = EPotnew + this%UFourier
#endif
    end if
  end subroutine TEnsemble_Energy1


!==============================================================!
!  Subroutine TEnsemble_EwaldEnergy1                           !
!==============================================================!

  subroutine TEnsemble_EwaldEnergy1( this, nc, np, EPotNew, m )

    implicit none

    ! Declare arguments
    type(TEnsemble)       :: this
    integer, intent(in)   :: nc, np,m
    real(RK), intent(out) :: EPotNew

    ! Declare local variables
    type(TInteraction), pointer :: pi
    integer                     :: i

    ! Initialize new energy
    EPotNew = 0._RK

    ! Loop over components
    do i = 1, this%NComponents
      pi => this%Interaction(nc, i)
      call Energy( pi, np, this%BoxLength, .false. )
      ! Calculate new energy
      EPotNew = EPotNew + pi%EPot
    end do

    if (LongRange .eq. Ewald) then
       call EwaldFourierEnergy(this,nc,np,m)
       EPotNew = EPotnew + this%UFourier
#if SPME > 0
    else if (LongRange .eq. PME) then
       call PMEFourierTermMC ( this )
       EPotNew = EPotnew + this%UFourier
#endif
    end if
  end subroutine TEnsemble_EwaldEnergy1



!==============================================================!
!  Subroutine TEnsemble_Energy_CF                              !
!==============================================================!

  subroutine TEnsemble_Energy1_CF( this, nc, np, ncold, npold, EPotNew )

    implicit none

    ! Declare arguments
    type(TEnsemble)       :: this
    integer, intent(in)   :: nc, np
    integer, intent(in)   :: ncold, npold
    real(RK), intent(out) :: EPotNew

    ! Declare local variables
    type(TInteraction), pointer :: pi
    integer                     :: i

    ! Initialize new energy
    EPotNew = 0._RK

    ! Loop over components
    do i = 1, this%NComponents
      pi => this%Interaction(nc, i)
      call Energy( pi, np, this%BoxLength, .false. )

      ! Calculate new energy
      EPotNew = EPotNew + pi%EPot
    end do

    if (LongRange .eq. Ewald) then
       call EwaldFourierEnergy(this,nc,np,ncold,npold)
       EPotNew = EPotnew + this%UFourier + this%USelbstTerm + this%UIntra
#if SPME > 0
    else if (LongRange .eq. PME) then
       call PMEFourierTermMC ( this )
       EPotNew = EPotnew + this%UFourier
#endif
    end if
  end subroutine TEnsemble_Energy1_CF



!==============================================================!
!  Subroutine TEnsemble_Move                                   !
!==============================================================!

  subroutine TEnsemble_Move( this, nc, np )

    implicit none

    ! Include MPI header
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif

    ! Declare arguments
    type(TEnsemble)     :: this
    integer, intent(in) :: nc, np

    ! Declare local variables
    real(RK)                  :: r(3)
    real(RK)                  :: EPotOld, EPotNew
    real(RK)                  :: EFourier, EVirial
    real(RK)                  :: EPotDelta
    type(TComponent), pointer :: pc
    integer                   :: i
    logical                   :: accepted

    ! Assign local variables
    pc => this%Component(nc)

    ! Update number of move attempts
    pc%NMoveAttempts = pc%NMoveAttempts + 1

    ! Save current particle position and energy
    r(:) = pc%P0(np, :)

    call EnergyinRC( this, nc, np, EPotOld )

    ! Save the Energies and Virials for a faster MoveRejection
    if (LongRange .eq. Ewald) then
      EFourier = this%UFourier
      DO i=1,pc%Molecule%NCharge
        this%rold(i,1) = pc%Molecule%SiteCharge(i)%RX(np)
        this%rold(i,2) = pc%Molecule%SiteCharge(i)%RY(np)
        this%rold(i,3) = pc%Molecule%SiteCharge(i)%RZ(np)
      END DO

#if SPME > 0
    else if (LongRange .eq. PME) then
      EFourier = this%UFourier
      EVirial  = this%EVirial
      call chargegrid_min  (this, nc, np)
#endif
    end if

    ! Generate a trial displacement
    do i = 1, 3
      pc%P0(np, i) = pc%P0(np, i) + rnd( -pc%DispTran, pc%DispTran )
    end do

    ! Apply periodic boundary conditions
    pc%P0(np, :) = pc%P0(np, :) - anint( pc%P0(np, :) )

    ! Convert molecular coordinates to atom positions
    call Mol2Atom1( pc, np )

#if SPME > 0
    ! Calculate changes in the SPME grid
    if (LongRange .eq. PME) then
      call chargegrid_plus (this, nc, np)
    end if
#endif

    ! Calculate particle energy at trial position
    MCOverlapDetected = .FALSE.
    call EnergyinRC( this, nc, np, EPotNew )

    ! Apply Metropolis acceptance criterion
#if MPI_VER > 0
    if ( (Equilibration .and. CommonEqui) .or. (mpiMCCommonGroups > 0)) then
      call MPI_Allreduce( EPotOld - EPotNew, EPotDelta, 1, MPI_RK, MPI_SUM, Communicator, ierror )

    else
          EPotDelta = EPotOld - EPotNew
    endif
#else
    EPotDelta = EPotOld - EPotNew
#endif

    accepted = EPotDelta > 0._RK
    if( .not. accepted ) accepted = exp( EPotDelta / this%Temperature ) > rnd( 0._RK, 1._RK ) .AND. .NOT. MCOverlapDetected
    if( accepted ) then
      ! Accept move
      pc%NMoveSuccesses = pc%NMoveSuccesses + 1

    else

      ! Reject move
      if (LongRange .eq. Ewald) then
          this%UFourier = EFourier

          DO i=1,pc%Molecule%NCharge
            this%rold(i,1) = pc%Molecule%SiteCharge(i)%RX(np)
            this%rold(i,2) = pc%Molecule%SiteCharge(i)%RY(np)
            this%rold(i,3) = pc%Molecule%SiteCharge(i)%RZ(np)
          END DO

          pc%P0(np, :) = r(:)
          call Mol2Atom1( pc, np )
          call EwaldFourierEnergy(this,nc,np)

#if SPME > 0
      else if (LongRange .eq. PME) then
          this%UFourier = EFourier
          this%EVirial  = EVirial
          call chargegrid_min  (this, nc, np)
          pc%P0(np, :) = r(:)
          call Mol2Atom1( pc, np )
          call chargegrid_plus (this, nc, np)
#endif
      else
          pc%P0(np, :) = r(:)
          call Mol2Atom1( pc, np )
      end if
    end if

  end subroutine TEnsemble_Move


  subroutine moveOrRotateParticle(this, nc, s, randomNumber)

    implicit none

    ! Include MPI header
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif

    ! Declare arguments
    type(TEnsemble)     :: this
    integer, intent(in) :: nc, s, randomNumber

    ! Declare local variables
    real(RK)                  :: r(3), q(4), dq(3)
    real(RK)                  :: EPotOld, EPotNew, NewTheta, NewOmega
    real(RK)                  :: StateAlpha, StateBeta
    real(RK)                  :: EPot, d2EdV2, Virial
    real(RK)                  :: EFourier, EVirial
    real(RK)                  :: EPotDelta
    type(TComponent), pointer :: pc
    integer                   :: i, np
    integer, pointer          :: successCounter
    logical                   :: accepted, moveParticle

    pc => this%Component(nc)

    np = 1 + (s - randomNumber) / pc%Molecule%NDF

    moveParticle = mod(s - randomNumber, pc%Molecule%NDF) < 3

    call EnergyinRC(this, nc, np, EPotOld)

    ! Save the Energies and Virials for a faster MoveRejction
    if (LongRange .eq. Ewald) then

        EFourier = this%UFourier

        do i = 1, pc%Molecule%NCharge

            this%rold(i, 1) = pc%Molecule%SiteCharge(i)%RX(np)
            this%rold(i, 2) = pc%Molecule%SiteCharge(i)%RY(np)
            this%rold(i, 3) = pc%Molecule%SiteCharge(i)%RZ(np)

        end do

#if SPME > 0
    else if (LongRange .eq. PME) then

        EFourier = this%UFourier
        EVirial  = this%EVirial

        call chargegrid_min(this, nc, np)
#endif
    end if

    if (moveParticle) then

        ! Update number of move attempts
        pc%NMoveAttempts = pc%NMoveAttempts + 1
        successCounter => pc%NMoveSuccesses

        ! Save current particle position and energy
        r(:) = pc%P0(np, :)

        ! Generate a trial displacement
        do i = 1, 3

            pc%P0(np, i) = pc%P0(np, i) + rnd(-pc%DispTran, pc%DispTran)

        end do

        ! Apply periodic boundary conditions
        pc%P0(np, :) = pc%P0(np, :) - anint(pc%P0(np, :))

    else

        ! Update number of rotation attempts
        pc%NRotateAttempts = pc%NRotateAttempts + 1
        successCounter => pc%NRotateSuccesses

        ! Save current particle orientation and energy
        q(:) = pc%Q0(np, :)

        ! Generate a trial rotation
        do i = 1, 3

            dq(i) = rnd( -pc%DispRot, pc%DispRot )

        end do

        pc%Q0(np, 1) = q(1) - dq(1) * q(2) - dq(2) * q(3) - dq(3) * q(4)
        pc%Q0(np, 2) = q(2) + dq(1) * q(1) - dq(2) * q(4) + dq(3) * q(3)
        pc%Q0(np, 3) = q(3) + dq(1) * q(4) + dq(2) * q(1) - dq(3) * q(2)
        pc%Q0(np, 4) = q(4) - dq(1) * q(3) + dq(2) * q(2) + dq(3) * q(1)

    end if

    MCOverlapDetected = .FALSE.

    ! Convert molecular coordinates to atom positions
    call Mol2Atom1(pc, np)

#if SPME > 0
    ! Calculate changes in the SPME grid
    if (LongRange .eq. PME) then

        call chargegrid_plus(this, nc, np)

    end if
#endif

    ! Calculate particle energy at trial position
    call EnergyinRC(this, nc, np, EPotNew)

#if MPI_VER > 0
    if ((Equilibration .and. CommonEqui) .or. (mpiMCCommonGroups > 0)) then

        call MPI_Allreduce(EPotOld - EPotNew, EPotDelta, 1, MPI_RK, MPI_SUM, Communicator, ierror)

    else

        EPotDelta = EPotOld - EPotNew

    endif
#else

    EPotDelta = EPotOld - EPotNew

#endif

    if (EnsembleType .eq. EnsembleTypeNVE .and. .not. NVTEquilibration) then

        if ((this%RefHamiltonian*this%NPart - this%Epot+EPotDelta) < 0._RK) then

            NewOmega = 0._RK

        else

            NewOmega = 1._RK

        end if

        accepted = ((((this%RefHamiltonian * this%NPart - this%Epot + EPotDelta) / (this%RefHamiltonian * this%NPart - this%Epot))**((real(this%NDF, RK) - 2._RK) / 2._RK) * NewOmega) .ge. rnd(0._RK, 1._RK))

        if (accepted) then
            ! Accept move
            this%Temperature = 2._RK * (this%RefHamiltonian * this%NPart - this%Epot + EPotDelta) / real(this%NDF, RK)

            this%EPot = this%EPot - EPotDelta

        end if

    else if (EnsembleType .eq. EnsembleTypeNPH .and. .not. NVTEquilibration) then

        accepted = (exp((real(this%NDF, RK) / 2._RK - 1._RK) * log((this%RefEnthalpy * this%NPart - this%Epot + EpotDelta - this%RefPressure * this%Volume0) &
&               / (this%RefEnthalpy * this%NPart - this%Epot - this%RefPressure * this%Volume0))) > rnd(0._RK, 1._RK))

        ! Acceptance criterion
        if (accepted) then

            ! Accept move
            this%Temperature = 2._RK * (this%RefEnthalpy * this%NPart - this%Epot + EpotDelta - this%RefPressure * this%Volume0) / real(this%NDF, RK)

            this%EPot = this%EPot - EPotDelta
            accepted = .True.

        end if

    else if (EnsembleType .eq. EnsembleTypeMUVL .and. .not. NVTEquilibration) then

        StateAlpha = this%RefHill - this%Epot + pc%ChemPot0 * this%NPart
        StateBeta = this%RefHill - this%Epot + EPotDelta + pc%ChemPot0 * this%NPart

        if (StateBeta < 0._RK) then
          NewTheta = 0._RK

        else
          NewTheta = 1._RK

        end if

        accepted = (NewTheta * (StateBeta / StateAlpha)**((real(this%NDF, RK) - 2._RK) / 2._RK)) .ge. rnd(0._RK, 1._RK)

       ! if( .not. accepted ) accepted = exp( EPotDelta / this%Temperature ) > rnd( 0._RK, 1._RK ) .AND. .NOT. MCOverlapDetected
        if (accepted) then

          this%Temperature = 2._RK * StateBeta / real(this%NDF, RK)

          this%EPot = this%EPot - EPotDelta

        end if

    else if (EnsembleType .eq. EnsembleTypeMUPR .and. .not. NVTEquilibration) then

        StateAlpha = this%RefRay - this%Refpressure * this%Volume0 - this%Epot + pc%ChemPot0 * this%NPart
        StateBeta = this%RefRay - this%Refpressure * this%Volume0 - this%Epot + EPotDelta + pc%ChemPot0 * this%NPart

        if (StateBeta < 0._RK) then
          NewTheta = 0._RK

        else
          NewTheta = 1._RK

        end if

        accepted = (NewTheta * (StateBeta / StateAlpha)**((real(this%NDF, RK) - 2._RK) / 2._RK)) .ge. rnd(0._RK, 1._RK)

        if (accepted) then

          this%Temperature = 2._RK * StateBeta / real(this%NDF, RK)

          this%EPot = this%EPot - EPotDelta

        end if

    else

        accepted = EPotDelta > 0._RK
        if (.not. accepted) accepted = exp(EPotDelta / this%Temperature) > rnd(0._RK, 1._RK) .AND. .NOT. MCOverlapDetected

    end if

    if (accepted) then
        successCounter = successCounter + 1

    else

        if (moveParticle) then

            ! Reject move
            if (LongRange .eq. Ewald) then
                this%UFourier = EFourier

                do i = 1, pc%Molecule%NCharge

                    this%rold(i, 1) = pc%Molecule%SiteCharge(i)%RX(np)
                    this%rold(i, 2) = pc%Molecule%SiteCharge(i)%RY(np)
                    this%rold(i, 3) = pc%Molecule%SiteCharge(i)%RZ(np)

                end do

                pc%P0(np, :) = r(:)
                call Mol2Atom1(pc, np)

                call EwaldFourierEnergy(this, nc, np)

#if SPME > 0
            else if (LongRange .eq. PME) then

                this%UFourier = EFourier
                this%EVirial  = EVirial

                call chargegrid_min  (this, nc, np)
                pc%P0(np, :) = r(:)

                call Mol2Atom1( pc, np )
                call chargegrid_plus (this, nc, np)
#endif
            else

                pc%P0(np, :) = r(:)
                call Mol2Atom1(pc, np)

            end if

        else

            ! Reject move
            if (LongRange .eq. Ewald) then
                this%UFourier = EFourier

                do i = 1, pc%Molecule%NCharge

                    this%rold(i, 1) = pc%Molecule%SiteCharge(i)%RX(np)
                    this%rold(i, 2) = pc%Molecule%SiteCharge(i)%RY(np)
                    this%rold(i, 3) = pc%Molecule%SiteCharge(i)%RZ(np)

                end do

                pc%Q0(np, :) = q(:)
                call Mol2Atom1(pc, np)

                call EwaldFourierEnergy(this, nc, np)

#if SPME > 0
            else if (LongRange .eq. PME) then

                this%UFourier = EFourier
                this%EVirial  = EVirial

                call chargegrid_min(this, nc, np)
                pc%Q0(np, :) = q(:)

                call Mol2Atom1(pc, np)
                call chargegrid_plus(this, nc, np)
#endif

            else

                pc%Q0(np, :) = q(:)
                call Mol2Atom1(pc, np)

            end if
        end if

    end if

   end subroutine moveOrRotateParticle


!==============================================================!
!  Subroutine TEnsemble_Rotate                                 !
!==============================================================!

  subroutine TEnsemble_Rotate( this, nc, np )

    implicit none

    ! Include MPI header
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif

    ! Declare arguments03
    type(TEnsemble)     :: this
    integer, intent(in) :: nc, np

    ! Declare local variables
    real(RK)                  :: q(4), dq(3)
    real(RK)                  :: EPotOld, EPotNew
    real(RK)                  :: EFourier, EVirial
    type(TComponent), pointer :: pc
    integer                   :: i
    real(RK)                  :: EPotDelta
    logical                   :: accepted

    ! Assign local variables
    pc => this%Component(nc)

    ! Update number of rotation attempts
    pc%NRotateAttempts = pc%NRotateAttempts + 1

    ! Save current particle orientation and energy
    q(:) = pc%Q0(np, :)
    call EnergyinRC( this, nc, np, EPotOld )

    ! Save the Energies and Virials for a faster MoveRejction
    if (LongRange .eq. Ewald) then
      EFourier = this%UFourier
      DO i=1,pc%Molecule%NCharge
        this%rold(i,1) = pc%Molecule%SiteCharge(i)%RX(np)
        this%rold(i,2) = pc%Molecule%SiteCharge(i)%RY(np)
        this%rold(i,3) = pc%Molecule%SiteCharge(i)%RZ(np)
      END DO

#if SPME > 0
    else if (LongRange .eq. PME) then
      EFourier = this%UFourier
      EVirial  = this%EVirial
      call chargegrid_min  (this, nc, np)
#endif
    end if

    ! Generate a trial rotation
    do i = 1, 3
      dq(i) = rnd( -pc%DispRot, pc%DispRot )
    end do
    pc%Q0(np, 1) = q(1) - dq(1) * q(2) - dq(2) * q(3) - dq(3) * q(4)
    pc%Q0(np, 2) = q(2) + dq(1) * q(1) - dq(2) * q(4) + dq(3) * q(3)
    pc%Q0(np, 3) = q(3) + dq(1) * q(4) + dq(2) * q(1) - dq(3) * q(2)
    pc%Q0(np, 4) = q(4) - dq(1) * q(3) + dq(2) * q(2) + dq(3) * q(1)


    ! Convert molecular coordinates to atom positions
    call Mol2Atom1( pc, np )

#if SPME > 0
    if (LongRange .eq. PME) then
      call chargegrid_plus (this, nc, np)
    end if
#endif

    ! Calculate particle energy with trial orientation
    MCOverlapDetected = .FALSE.
    call EnergyinRC( this, nc, np, EPotNew )

    ! Apply Metropolis acceptance criterion
#if MPI_VER > 0
    if ( (Equilibration .and. CommonEqui) .or. (mpiMCCommonGroups > 0)) then
      call MPI_Allreduce( EPotOld - EPotNew, EPotDelta, 1, MPI_RK, MPI_SUM, Communicator, ierror )
    else
      EPotDelta = EPotOld - EPotNew
    endif

#else
    EPotDelta = EPotOld - EPotNew
#endif

    accepted = EPotDelta > 0._RK
    if( .not. accepted ) accepted = exp( EPotDelta / this%Temperature ) > rnd( 0._RK, 1._RK ) .AND. .NOT. MCOverlapDetected
    if( accepted ) then
      ! Accept rotation
      pc%NRotateSuccesses = pc%NRotateSuccesses + 1

    else

      ! Reject move
      if (LongRange .eq. Ewald) then
        this%UFourier = EFourier
        DO i=1,pc%Molecule%NCharge
          this%rold(i,1) = pc%Molecule%SiteCharge(i)%RX(np)
          this%rold(i,2) = pc%Molecule%SiteCharge(i)%RY(np)
          this%rold(i,3) = pc%Molecule%SiteCharge(i)%RZ(np)
        END DO
        pc%Q0(np, :) = q(:)
        call Mol2Atom1( pc, np )
        call EwaldFourierEnergy(this,nc,np)

#if SPME > 0
      else if (LongRange .eq. PME) then
        this%UFourier = EFourier
        this%EVirial  = EVirial
        call chargegrid_min  (this, nc, np)
        pc%Q0(np, :) = q(:)
        call Mol2Atom1( pc, np )
        call chargegrid_plus (this, nc, np)
#endif

      else
        pc%Q0(np, :) = q(:)
        call Mol2Atom1( pc, np )
      end if

    end if

  end subroutine TEnsemble_Rotate


!==============================================================!
!  Subroutine TEnsemble_MoveBiased                             !
!==============================================================!

  subroutine TEnsemble_MoveBiased( this, nc, np, ncf, npf )

    implicit none

    ! Include MPI header
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif

    ! Declare arguments
    type(TEnsemble)     :: this
    integer, intent(in) :: nc, np, ncf, npf

    ! Declare local variables
    real(RK)                  :: r(3), dr(3), f1, f2
    real(RK)                  :: EPotOld, EPotNew
    real(RK)                  :: EFourier, EVirial
    type(TComponent), pointer :: pc, pcf
    integer                   :: i
    real(RK)                  :: EPotDelta
    logical                   :: accepted

    ! Test for fluctuating particle
    if( nc .eq. ncf .and. np .eq. npf ) return

    ! Assign local variables
    pc => this%Component(nc)
    pcf => this%Component(ncf)

    ! Save current particle position and energy
    r(:) = pc%P0(np, :)
    call EnergyinRC( this, nc, np, EPotOld )

    ! Apply distance criterion
    dr(:) = r(:) - pcf%P0(npf, :)
    dr(:) = ( dr(:) - anint( dr(:) ) ) * this%BoxLength
    f1 = 1._RK / ( dr(1)**2 + dr(2)**2 + dr(3)**2 )**2
    if( rnd(0._RK, 1._RK) < (1._RK - f1) ) return

    ! Update number of move attempts
    pc%NMoveBiasedAttempts = pc%NMoveBiasedAttempts + 1

    ! Save the Energies and Virials for a faster MoveRejction
    if (LongRange .eq. Ewald) then
      EFourier = this%UFourier
      DO i=1,pc%Molecule%NCharge
        this%rold(i,1) = pc%Molecule%SiteCharge(i)%RX(np)
        this%rold(i,2) = pc%Molecule%SiteCharge(i)%RY(np)
        this%rold(i,3) = pc%Molecule%SiteCharge(i)%RZ(np)
      END DO

#if SPME > 0
    else if (LongRange .eq. PME) then
      EFourier = this%UFourier
      EVirial  = this%EVirial
      this%qgrida_old = this%qgrida
      call chargegrid_min  (this, nc, np)
#endif
    end if

    ! Generate a trial displacement
    do i = 1, 3
      pc%P0(np, i) = pc%P0(np, i) + rnd( -pc%DispTran, pc%DispTran )
    end do

    ! Apply periodic boundary conditions
    pc%P0(np, :) = pc%P0(np, :) - anint( pc%P0(np, :) )

    ! Apply direction criterion
    dr(:) = pc%P0(np, :) - pcf%P0(npf, :)
    dr(:) = ( dr(:) - anint( dr(:) ) ) * this%BoxLength
    f2 = 1._RK / ( dr(1)**2 + dr(2)**2 + dr(3)**2 )**2
    if( rnd(0._RK, 1._RK) < (1._RK - f2/f1) ) then
      pc%P0(np, :) = r(:)
      return
    end if

    ! Convert molecular coordinates to atom positions
    call Mol2Atom1( pc, np )

#if SPME > 0
    ! Save Energies, Virials for faster Rejection
    if (LongRange .eq. PME) then
      call chargegrid_plus (this, nc, np)
    end if
#endif

    ! Calculate particle energy at trial position
    call EnergyinRC( this, nc, np, EPotNew )

    ! Apply Metropolis acceptance criterion
#if MPI_VER > 0
    if ( (Equilibration .and. CommonEqui) .or. (mpiMCCommonGroups > 0) ) then
      call MPI_Allreduce( EPotOld - EPotNew, EPotDelta, 1, MPI_RK, MPI_SUM, Communicator, ierror )
    else
          EPotDelta = EPotOld - EPotNew
    endif

#else
    EPotDelta = EPotOld - EPotNew
#endif

    accepted = EPotDelta > 0._RK
    if( .not. accepted ) accepted = exp( EPotDelta / this%Temperature ) > rnd( 0._RK, 1._RK )
    if( accepted ) then

      ! Accept move
      pc%NMoveBiasedSuccesses = pc%NMoveBiasedSuccesses + 1

    else

      ! Reject move
      if (LongRange .eq. Ewald) then
          this%UFourier = EFourier
          DO i=1,pc%Molecule%NCharge
            this%rold(i,1) = pc%Molecule%SiteCharge(i)%RX(np)
            this%rold(i,2) = pc%Molecule%SiteCharge(i)%RY(np)
            this%rold(i,3) = pc%Molecule%SiteCharge(i)%RZ(np)
          END DO
          pc%P0(np, :) = r(:)
          call Mol2Atom1( pc, np )
          call EwaldFourierEnergy(this,nc,np)

#if SPME > 0
      else if (LongRange .eq. PME) then
        this%UFourier = EFourier
        this%EVirial  = EVirial
        this%qgrida   = this%qgrida_old
#endif
      else
        pc%P0(np, :) = r(:)
        call Mol2Atom1( pc, np )
      end if

    end if

  end subroutine TEnsemble_MoveBiased



!==============================================================!
!  Subroutine TEnsemble_RotateBiased                           !
!==============================================================!

  subroutine TEnsemble_RotateBiased( this, nc, np, ncf, npf )

    implicit none

    ! Include MPI header
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif

    ! Declare arguments03
    type(TEnsemble)     :: this
    integer, intent(in) :: nc, np, ncf, npf

    ! Declare local variables
    real(RK)                  :: dr(3), q(4), dq(3), f1
    real(RK)                  :: EPotOld, EPotNew
    real(RK)                  :: EFourier, EVirial
    type(TComponent), pointer :: pc, pcf
    integer                   :: i
    real(RK)                  :: EPotDelta
    logical                   :: accepted

    ! Test for fluctuating particle
    if( nc .eq. ncf .and. np .eq. npf ) return

    ! Assign local variables
    pc => this%Component(nc)
    pcf => this%Component(ncf)

    ! Save current particle orientation and energy
    q(:) = pc%Q0(np, :)
    call EnergyinRC( this, nc, np, EPotOld )

    ! Apply distance criterion
    dr(:) = pc%P0(np, :) - pcf%P0(npf, :)
    dr(:) = ( dr(:) - anint( dr(:) ) ) * this%BoxLength
    f1 = 1._RK / ( dr(1)**2 + dr(2)**2 + dr(3)**2 )**2
    if( rnd(0._RK, 1._RK) < (1._RK - f1) ) return

    ! Update number of rotation attempts
    pc%NRotateBiasedAttempts = pc%NRotateBiasedAttempts + 1

    ! Save the Energies and Virials for a faster MoveRejction
    if (LongRange .eq. Ewald) then
      EFourier = this%UFourier
      DO i=1,pc%Molecule%NCharge
        this%rold(i,1) = pc%Molecule%SiteCharge(i)%RX(np)
        this%rold(i,2) = pc%Molecule%SiteCharge(i)%RY(np)
        this%rold(i,3) = pc%Molecule%SiteCharge(i)%RZ(np)
      END DO

#if SPME > 0
    else if (LongRange .eq. PME) then
      EFourier = this%UFourier
      EVirial  = this%EVirial
      this%qgrida_old = this%qgrida
      call chargegrid_min  (this, nc, np)
#endif
    end if

    ! Generate a trial rotation
    do i = 1, 3
      dq(i) = rnd( -pc%DispRot, pc%DispRot )
    end do
    pc%Q0(np, 1) = q(1) - dq(1) * q(2) - dq(2) * q(3) - dq(3) * q(4)
    pc%Q0(np, 2) = q(2) + dq(1) * q(1) - dq(2) * q(4) + dq(3) * q(3)
    pc%Q0(np, 3) = q(3) + dq(1) * q(4) + dq(2) * q(1) - dq(3) * q(2)
    pc%Q0(np, 4) = q(4) - dq(1) * q(3) + dq(2) * q(2) + dq(3) * q(1)

    ! Convert molecular coordinates to atom positions
    call Mol2Atom1( pc, np )

#if SPME > 0
    ! Save Energies, Virials for faster Rejection
    if (LongRange .eq. PME) then
      call chargegrid_plus (this, nc, np)
    end if
#endif

    ! Calculate particle energy with trial orientation
    call EnergyinRC( this, nc, np, EPotNew )

    ! Apply Metropolis acceptance criterion
#if MPI_VER > 0
    if ( (Equilibration .and. CommonEqui) .or. (mpiMCCommonGroups > 0) ) then
      call MPI_Allreduce( EPotOld - EPotNew, EPotDelta, 1, MPI_RK, MPI_SUM, Communicator, ierror )
    else
      EPotDelta = EPotOld - EPotNew
    endif

#else
    EPotDelta = EPotOld - EPotNew
#endif

    accepted = EPotDelta > 0._RK
    if( .not. accepted ) accepted = exp( EPotDelta / this%Temperature ) > rnd( 0._RK, 1._RK )
    if( accepted ) then
      ! Accept rotation
      pc%NRotateBiasedSuccesses = pc%NRotateBiasedSuccesses + 1

    else

      ! Reject move
      if (LongRange .eq. Ewald) then
        this%UFourier = EFourier
        DO i=1,pc%Molecule%NCharge
          this%rold(i,1) = pc%Molecule%SiteCharge(i)%RX(np)
          this%rold(i,2) = pc%Molecule%SiteCharge(i)%RY(np)
          this%rold(i,3) = pc%Molecule%SiteCharge(i)%RZ(np)
        END DO
        pc%Q0(np, :) = q(:)
        call Mol2Atom1( pc, np )
        call EwaldFourierEnergy(this,nc,np)

#if SPME > 0
      else if (LongRange .eq. PME) then
        this%UFourier = EFourier
        this%EVirial  = EVirial
        this%qgrida   = this%qgrida_old

#endif
      else
        pc%Q0(np, :) = q(:)
        call Mol2Atom1( pc, np )
      end if

    end if

  end subroutine TEnsemble_RotateBiased



!==============================================================!
!  Subroutine TEnsemble_PartnersBiased                         !
!==============================================================!

  subroutine TEnsemble_PartnersBiased ( this, ncf, npf )

    implicit none

    ! Declare arguments
    type(TEnsemble)         :: this
    integer, intent(in)     :: ncf, npf

    real(RK)            :: BoxLength
    real(RK)            :: dxf, dyf, dzf
    real(RK)            :: dx, dy, dz, dr2
    integer             :: NGradIns
    integer             :: counter, counter1
    integer             :: i, j
    type(TComponent),pointer :: pc, pcf

    BoxLength = this%BoxLength
    counter   = 0
    counter1  = 0
    NGradIns  = 0

    pcf => this%Component(ncf)
    dxf = pcf%P0(npf,1)
    dyf = pcf%P0(npf,2)
    dzf = pcf%P0(npf,3)

    do i=1, this%NComponents
      pc => this%Component(i)
      counter1=0
      do j=1,pc%NPart
        if (i .eq. ncf .and. npf .eq. j) cycle
        dx = pc%P0(j,1) - dxf
        dy = pc%P0(j,2) - dyf
        dz = pc%P0(j,3) - dzf

        dx  = (dx-anint(dx))*BoxLength
        dy  = (dy-anint(dy))*BoxLength
        dz  = (dz-anint(dz))*BoxLength
        dr2 = dx**2 + dy**2 + dz**2

        if ( dr2 .le. 25._RK ) then
          counter = counter + 1
          counter1= counter1+ 1
          this%BiasedPartners(counter) = j
        end if
      end do
      pc%BiasedPartners = counter1*pc%Molecule%NDF
      pc%BiasedPartnersNum = counter1
      NGradIns = NGradIns + counter1*pc%Molecule%NDF
    end do

    this%NGradIns = NGradIns

  end subroutine TEnsemble_PartnersBiased


!==============================================================!
!  Subroutine TEnsemble_ChangeFluct                            !
!==============================================================!

  subroutine TEnsemble_ChangeFluct( this, nc, ncf, npf )

    implicit none

    ! Include MPI header
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif

    ! Declare arguments
    type(TEnsemble)        :: this
    integer, intent(in)    :: nc
    integer, intent(inout) :: ncf, npf
    integer                :: i

    ! Declare local variables
    type(TComponent), pointer :: pc, pcf, pcfnew
    integer                   :: oldstate, newstate
    integer                   :: ncfnew, npfnew
    real(RK)                  :: EPotOld, EPotNew
    real(RK)                  :: EPotDeltaAll

    ! Assign local variables
    pc => this%Component(nc)
    pcf => this%Component(ncf)
    oldstate = pc%NFluctState

    if( oldstate .eq. 0 ) then
      if( rnd( 0._RK, 1._RK ) < .5_RK ) then
        npf = rnd( pcf%NPart )
        call Move2End(pcf, npf)
      end if
      newstate = 1
      pc%NFluctUpAttempts( newstate ) = pc%NFluctUpAttempts( newstate ) + 1

    elseif( oldstate .eq. pc%NFluctMax ) then
      newstate = oldstate - 1
      pc%NFluctDownAttempts( oldstate ) = pc%NFluctDownAttempts( oldstate ) + 1

    else

      if( rnd( 0._RK, 1._RK ) < .5_RK ) then
        newstate = oldstate + 1
        pc%NFluctUpAttempts( newstate ) = pc%NFluctUpAttempts( newstate ) + 1
      else
        newstate = oldstate - 1
        pc%NFluctDownAttempts( oldstate ) = pc%NFluctDownAttempts( oldstate ) + 1
      end if

    end if

    ! Get old energy of fluctuating particle
    call EnergyinRC( this, ncf, npf, EPotOld )

    ! Change state of fluctuating particle
    ncfnew = pc%NFluctComp( newstate )
    pcfnew => this%Component( ncfnew )
    if( pcf%Molecule%IsElongated ) then
      call AddParticle( pcfnew, pcf%P0( npf, : ), pcf%Q0( npf, : ) )
    else
      call AddParticle( pcfnew, pcf%P0( npf, : ) )
    end if
    call RemoveParticle( pcf, npf )
    npfnew = pcfnew%NPart

! Save states for the Ewald Summation and/or derivates
    if (LongRange .eq. Ewald) then     ! Ewald Summation
       ! Save the initial state
       EPotOld = EPotOld  + this%USelbstTerm + this%UIntra
!  Sufficient, since no call to Mol2Atom1 yet

       DO i=1,pcf%Molecule%NCharge
         this%rold(i,1) = pcf%Molecule%SiteCharge(i)%RX(npf)
         this%rold(i,2) = pcf%Molecule%SiteCharge(i)%RY(npf)
         this%rold(i,3) = pcf%Molecule%SiteCharge(i)%RZ(npf)
       END DO

       ! Calculate new energies
       call EwaldSelfTerm_Energy(this)

       ! Convert molecular coordinates to atom positions
       call Mol2Atom1( pcfnew, npfnew )

       ! Calculate particle energy at new fluctuating state
       call Energy( this, ncfnew, npfnew, ncf, npf, EPotNew )

       ! Acceptance Criteria
#if MPI_VER > 0
    if ( (Equilibration .and. CommonEqui) .or. (mpiMCCommonGroups > 0) ) then
       call MPI_Allreduce( EPotOld - EPotNew, EPotDeltaAll, 1, MPI_RK, MPI_SUM, Communicator, ierror )
       EPotDeltaAll = EPotDeltaAll + this%Density * ( pcf%EPotTestCorrMIE - pcfnew%EPotTestCorrMIE )
    else
       EPotOld = EPotOld + this%Density * ( pcf%EPotTestCorrMIE - pcfnew%EPotTestCorrMIE )
       EPotDeltaAll = EPotOld - EPotNew
    end if

#else
       EPotOld = EPotOld + this%Density * ( pcf%EPotTestCorrMIE - pcfnew%EPotTestCorrMIE )
       EPotDeltaAll = EPotOld - EPotNew
#endif

       if( rnd( 0._RK, 1._RK ) < pc%WF(newstate) / pc%WF(oldstate) * exp( ( EPotDeltaAll ) / this%Temperature ) ) then
         ! Accept
         pc%NFluctState = newstate
         ncf = ncfnew
         npf = npfnew
         if( newstate > oldstate ) then
           pc%NFluctUpSuccesses( newstate ) = pc%NFluctUpSuccesses( newstate ) + 1
         else
           pc%NFluctDownSuccesses( oldstate ) = pc%NFluctDownSuccesses( oldstate ) + 1
         end if

       else
         ! Reject
         if( pcf%Molecule%IsElongated ) then
           call AddParticle( pcf, pcfnew%P0( npfnew, : ), pcfnew%Q0( npfnew, : ) )
         else
           call AddParticle( pcf, pcfnew%P0( npfnew, : ) )
         end if
         call RemoveParticle( pcfnew, npfnew )
         call EwaldSelfTerm_Energy(this)
         DO i=1,pcfnew%Molecule%NCharge
           this%rold(i,1) = pcfnew%Molecule%SiteCharge(i)%RX(npfnew)
           this%rold(i,2) = pcfnew%Molecule%SiteCharge(i)%RY(npfnew)
           this%rold(i,3) = pcfnew%Molecule%SiteCharge(i)%RZ(npfnew)
         END DO
         call Energy( this, ncf, npf, ncfnew, npfnew, EPotNew )

       end if       ! Acceptance Criteria

#if SPME > 0
! ----------------------------------------------------------------
    else if (LongRange .eq. PME) then ! SPME
      call PMESetup(this)
      write (*,*) 'Gradual Insertion does not yet work with SPME'
      STOP
#endif
! ----------------------------------------------------------------
    else   ! REACTION FIELD
       ! Convert molecular coordinates to atom positions
       call Mol2Atom1( pcfnew, npfnew )

       ! Calculate particle energy at new fluctuating state
       call EnergyinRC( this, ncfnew, npfnew, EPotNew )

    ! Apply acceptance criterion
#if MPI_VER > 0
    if ( (Equilibration .and. CommonEqui) .or. (mpiMCCommonGroups > 0) ) then
       call MPI_Allreduce( EPotOld - EPotNew, EPotDeltaAll, 1, MPI_RK, MPI_SUM, Communicator, ierror )
       EPotDeltaAll = EPotDeltaAll + this%Density * ( pcf%EPotTestCorrMIE - pcfnew%EPotTestCorrMIE ) &
&        + pcf%EPotTestCorrRF - pcfnew%EPotTestCorrRF

    else
       EPotOld = EPotOld + this%Density * ( pcf%EPotTestCorrMIE - pcfnew%EPotTestCorrMIE ) &
&        + pcf%EPotTestCorrRF - pcfnew%EPotTestCorrRF

       EPotDeltaAll = EPotOld - EPotNew
    end if
#else
       EPotOld = EPotOld + this%Density * ( pcf%EPotTestCorrMIE - pcfnew%EPotTestCorrMIE ) &
&        + pcf%EPotTestCorrRF - pcfnew%EPotTestCorrRF

       EPotDeltaAll = EPotOld - EPotNew
#endif
       if( rnd( 0._RK, 1._RK ) < pc%WF(newstate) / pc%WF(oldstate) * exp( ( EPotDeltaAll ) / this%Temperature ) ) then

         ! Accept
         pc%NFluctState = newstate
         ncf = ncfnew
         npf = npfnew

         if( newstate > oldstate ) then
           pc%NFluctUpSuccesses(newstate) = pc%NFluctUpSuccesses(newstate)+1
         else
           pc%NFluctDownSuccesses(oldstate) = pc%NFluctDownSuccesses(oldstate)+1
         end if

        if ( newstate .eq. 0 ) call BiasedPartners ( this, ncf, npf )

       else

         ! Reject
         if( pcf%Molecule%IsElongated ) then
           call AddParticle( pcf, pcfnew%P0( npfnew, : ),pcfnew%Q0( npfnew, : ) )
         else
           call AddParticle( pcf, pcfnew%P0( npfnew, : ) )
         end if
         call RemoveParticle( pcfnew, npfnew )

       end if

    end if      ! LongRange - Correction

  end subroutine TEnsemble_ChangeFluct

!==============================================================!
!  Subroutine TEnsemble_ScaleInteractionThermoInt              !
!==============================================================!

  subroutine TEnsemble_ScaleInteractionThermoInt( this, nt , factor)

   implicit none

    ! Include MPI header
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif

    ! Declare arguments
    type(TEnsemble)        :: this
    integer, intent(in)    :: nt
    real(RK), intent(in)   :: factor

    ! Declare local variables
    integer                 :: i

    do i = 1, this%NComponents
      if( associated(this%Interaction(nt, i)%PotMIEnmMIEnm)) then
        this%Interaction(nt, i)%PotMIEnmMIEnm(:, :)%Epsilon          = this%Interaction(nt, i)%PotMIEnmMIEnm(:, :)%Epsilon * Factor
        this%Interaction(nt, i)%PotMIEnmMIEnm(:, :)%EpsilonMie_a     = this%Interaction(nt, i)%PotMIEnmMIEnm(:, :)%EpsilonMie_a * Factor
        this%Interaction(nt, i)%PotMIEnmMIEnm(:, :)%EpsilonMie_aF    = this%Interaction(nt, i)%PotMIEnmMIEnm(:, :)%EpsilonMie_aF * Factor
        this%Interaction(i, nt)%PotMIEnmMIEnm(:, :)%Epsilon          = this%Interaction(i, nt)%PotMIEnmMIEnm(:, :)%Epsilon * Factor
        this%Interaction(i, nt)%PotMIEnmMIEnm(:, :)%EpsilonMie_a     = this%Interaction(i, nt)%PotMIEnmMIEnm(:, :)%EpsilonMie_a * Factor
        this%Interaction(i, nt)%PotMIEnmMIEnm(:, :)%EpsilonMie_aF    = this%Interaction(i, nt)%PotMIEnmMIEnm(:, :)%EpsilonMie_aF * Factor
      endif
      if( associated(this%Interaction(nt, i)%PotTT68TT68)) then
        this%Interaction(nt, i)%PotTT68TT68(:, :)%TT_A  = this%Interaction(nt, i)%PotTT68TT68(:, :)%TT_A * Factor
        this%Interaction(nt, i)%PotTT68TT68(:, :)%C6    = this%Interaction(nt, i)%PotTT68TT68(:, :)%C6 * Factor
        this%Interaction(nt, i)%PotTT68TT68(:, :)%C8    = this%Interaction(nt, i)%PotTT68TT68(:, :)%C8 * Factor
        this%Interaction(i, nt)%PotTT68TT68(:, :)%TT_A  = this%Interaction(i, nt)%PotTT68TT68(:, :)%TT_A * Factor
        this%Interaction(i, nt)%PotTT68TT68(:, :)%C6    = this%Interaction(i, nt)%PotTT68TT68(:, :)%C6 * Factor
        this%Interaction(i, nt)%PotTT68TT68(:, :)%C8    = this%Interaction(i, nt)%PotTT68TT68(:, :)%C8 * Factor
      endif
      if( associated(this%Interaction(nt, i)%PotChargeCharge)) then
        this%Interaction(nt, i)%PotChargeCharge(:, :)%Epsilon    = this%Interaction(nt, i)%PotChargeCharge(:, :)%Epsilon * Factor
        this%Interaction(i, nt)%PotChargeCharge(:, :)%Epsilon    = this%Interaction(i, nt)%PotChargeCharge(:, :)%Epsilon * Factor

      endif
      if( associated(this%Interaction(nt, i)%PotChargeDipole)) then
        this%Interaction(nt, i)%PotChargeDipole(:, :)%Epsilon    = this%Interaction(nt, i)%PotChargeDipole(:, :)%Epsilon * Factor
        this%Interaction(i, nt)%PotDipoleCharge(:, :)%Epsilon    = this%Interaction(i, nt)%PotDipoleCharge(:, :)%Epsilon * Factor

      endif
      if( associated(this%Interaction(nt, i)%PotChargeQuadrupole)) then
        this%Interaction(nt, i)%PotChargeQuadrupole(:, :)%Epsilon    = this%Interaction(nt, i)%PotChargeQuadrupole(:, :)%Epsilon * Factor
        this%Interaction(i, nt)%PotQuadrupoleCharge(:, :)%Epsilon    = this%Interaction(i, nt)%PotQuadrupoleCharge(:, :)%Epsilon * Factor

      endif
      if( associated(this%Interaction(nt, i)%PotDipoleCharge)) then
        this%Interaction(nt, i)%PotDipoleCharge(:, :)%Epsilon    = this%Interaction(nt, i)%PotDipoleCharge(:, :)%Epsilon * Factor
        this%Interaction(i, nt)%PotChargeDipole(:, :)%Epsilon    = this%Interaction(i, nt)%PotChargeDipole(:, :)%Epsilon * Factor

      endif
      if( associated(this%Interaction(nt, i)%PotDipoleDipole)) then
        this%Interaction(nt, i)%PotDipoleDipole(:, :)%Epsilon    = this%Interaction(nt, i)%PotDipoleDipole(:, :)%Epsilon * Factor
        this%Interaction(i, nt)%PotDipoleDipole(:, :)%Epsilon    = this%Interaction(i, nt)%PotDipoleDipole(:, :)%Epsilon * Factor

      endif
      if( associated(this%Interaction(nt, i)%PotDipoleQuadrupole)) then
        this%Interaction(nt, i)%PotDipoleQuadrupole(:, :)%Epsilon    = this%Interaction(nt, i)%PotDipoleQuadrupole(:, :)%Epsilon * Factor
        this%Interaction(i, nt)%PotQuadrupoleDipole(:, :)%Epsilon    = this%Interaction(i, nt)%PotQuadrupoleDipole(:, :)%Epsilon * Factor

      endif
      if( associated(this%Interaction(nt, i)%PotQuadrupoleCharge)) then
        this%Interaction(nt, i)%PotQuadrupoleCharge(:, :)%Epsilon    = this%Interaction(nt, i)%PotQuadrupoleCharge(:, :)%Epsilon * Factor
        this%Interaction(i, nt)%PotChargeQuadrupole(:, :)%Epsilon    = this%Interaction(i, nt)%PotChargeQuadrupole(:, :)%Epsilon * Factor

      endif
      if( associated(this%Interaction(nt, i)%PotQuadrupoleDipole)) then
        this%Interaction(nt, i)%PotQuadrupoleDipole(:, :)%Epsilon    = this%Interaction(nt, i)%PotQuadrupoleDipole(:, :)%Epsilon * Factor
        this%Interaction(i, nt)%PotDipoleQuadrupole(:, :)%Epsilon    = this%Interaction(i, nt)%PotDipoleQuadrupole(:, :)%Epsilon * Factor

      endif
      if( associated(this%Interaction(nt, i)%PotQuadrupoleQuadrupole)) then
        this%Interaction(nt, i)%PotQuadrupoleQuadrupole(:, :)%Epsilon= this%Interaction(nt, i)%PotQuadrupoleQuadrupole(:, :)%Epsilon * Factor
        this%Interaction(i, nt)%PotQuadrupoleQuadrupole(:, :)%Epsilon= this%Interaction(i, nt)%PotQuadrupoleQuadrupole(:, :)%Epsilon * Factor

      endif
    end do
    if( associated(this%Component(nt)%MueX)) then  ! if MueX then also MueY and Z
      this%Component(nt)%Molecule%Mue(:) = this%Component(nt)%Molecule%Mue(:) * Factor

    endif

  end subroutine TEnsemble_ScaleInteractionThermoInt


!==============================================================!
!  Subroutine TEnsemble_ChangeLambda                           !
!==============================================================!

  subroutine TEnsemble_ChangeLambda( this, nt , nc)

    implicit none

    ! Include MPI header
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif

    ! Declare arguments
    type(TEnsemble)        :: this
    integer, intent(in)    :: nt
    integer, intent(in)    :: nc

    ! Declare local variables
    type(TComponent), pointer  :: pc, pt
    integer                    :: currentbin
    real(RK)                   :: LambdaNew, Factor, ChempotDelta
    real(RK)                   :: EPotOld, EPotNew, EPot
    real(RK)                   :: EPotDeltaAll
    real(RK)                   :: EFourier, EVirial
#if MPI_VER > 0
    real(RK)                   :: auxEPot
#endif

    ! Assign local variables
    pt => this%Component(nt)
    pc => this%Component(nc)

    ! Get old energy of fluctuating particle
    if (SimulationType .ne. MolecularDynamics) then
      if( this%NMIEnmMax > 0 ) then
       EPotOld = (this%Density * pc%EPotTestCorrMIE + pc%EPotTestCorrRF)*pt%Lambda**pc%LambdaExponent
      endif
      if( this%NTT68Max > 0 ) then
       EPotOld = (this%Density * pc%EPotTestCorrTT68 + pc%EPotTestCorrRF)*pt%Lambda**pc%LambdaExponent
      endif
      call EnergyinRC(this, nt, 1, EPot)
#if MPI_VER > 0
      if ( mpiMCCommonGroups > 0 ) then
        call MPI_Allreduce( EPot, auxEPot, 1, MPI_RK, MPI_SUM, Communicator, ierror )
        EPot = auxEPot
      endif
#endif
      EPotOld = EPotOld + EPot
      currentbin=int((pt%Lambda-pc%LaMin)/pc%deltaLa)
      ChempotDelta=-pc%BinsIntdEndLa(currentbin)

      ! Save states for the Ewald Summation and/or derivates
      if (LongRange .eq. Ewald) then     ! Ewald Summation
        ! Save the initial state
        EFourier = this%UFourier
        EPotOld = EPotOld  + this%USelbstTerm + this%UIntra
        EVirial  = this%EVirial

        call EwaldSelfTerm_Energy(this)
      end if

      ! Change state of lambda
      LambdaNew=pt%Lambda+2.0_RK*pc%LaStepMax*(rnd(0.0_RK,1.0_RK)-0.5_RK)!same for every process of the MCCommonGroup, see Randomize

      if (LambdaNew>=pc%LaMin .and. LambdaNew<pc%LaMax) then

        currentbin=int((LambdaNew-pc%LaMin)/pc%deltaLa)
        ChempotDelta=ChempotDelta+pc%BinsIntdEndLa(currentbin)
        ! Calculate energy of fluctuating particle
        Factor = (LambdaNew/pt%Lambda)**pc%LambdaExponent
        EPotNew=Factor*EPotOld

        ! Acceptance Criteria
        EPotDeltaAll = EPotOld - EPotNew

        if( rnd( 0._RK, 1._RK ) < exp( ( EPotDeltaAll + ChempotDelta) / this%Temperature ) ) then
          ! Accept
          ! Apply scaling factors
          call ScaleInteractionThermoInt(this, nt, Factor)
          pt%Lambda=LambdaNew
        else
          ! Reject
          if (LongRange == Ewald) then
            call EwaldSelfTerm_Energy(this)
          end if
        end if       ! Acceptance Criteria

      end if !Lamba change

    else ! MolecularDynamics

      if (RootProc) then
        LambdaNew=pt%Lambda+2.0_RK*pc%LaStepMax*(rnd(0.0_RK,1.0_RK)-0.5_RK)
        ! should be 1/10 of MC-stepwidth for equal distribution (estimation by Gabor and Michael)
        if (LambdaNew<pc%LaMin) then
          LambdaNew = pc%LaMin
        elseif (LambdaNew>=pc%LaMax) then
          LambdaNew = pc%LaMax - Zero
        end if
        Factor = (LambdaNew/pt%Lambda)**pc%LambdaExponent
        pt%Lambda=LambdaNew
      end if
      ! Apply scaling factors
#if MPI_VER > 0
      call MPI_Bcast( Factor, 1, MPI_RK, NRootProc, Communicator, ierror )
      call MPI_Bcast( pt%Lambda, 1, MPI_RK, NRootProc, Communicator, ierror )
#endif
      call ScaleInteractionThermoInt(this, nt, Factor)
      call Mol2Atom( this ) ! only for nt sufficient / call mol2atom( pt, 1 )

    end if

  end subroutine TEnsemble_ChangeLambda


!==============================================================!
!  Subroutine TEnsemble_Insert                                 !
!==============================================================!

  subroutine TEnsemble_Insert( this, nc )

    implicit none

    ! Include MPI header
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif

    ! Declare arguments
    type(TEnsemble)     :: this
    integer, intent(in) :: nc

    ! Declare local variables
    real(RK)                  :: r(3)
    real(RK)                  :: q(4)
    real(RK)                  :: EPotIns, EPotOld
    type(TComponent), pointer :: pc
    integer                   :: i, np
    real(RK)                  :: s
    real(RK)                  :: UIntra, USelbst, EFourier
    real(RK)                  :: ChemPot
#if MPI_VER > 0
    real(RK)                  :: EPotInsAll
#endif

    ! Assign local variables
    pc => this%Component(nc)

    ! Update number of insert attempts
    this%NInsertAttempts = this%NInsertAttempts + 1

    ! Generate a random position and orientation
    do i = 1, 3
      r(i) = rnd( -.5_RK, .5_RK )
    end do
    do
      s = 0._RK
      do i = 1, 4
        q(i) = rnd( -1._RK, 1._RK )
      end do

      s = sum( q**2 )
      if( s <= 1._RK ) exit
    end do
    q = q / sqrt( s )

    call AddParticle( pc, r, q )
    if ( tooManyParticles ) return
    np = pc%NPart
    this%NPart = this%NPart + 1

    ! Convert molecular coordinates to atom positions
    call Mol2Atom1( pc, np )

    if (LongRange .eq. Ewald) then           ! EWALD-SUMMATION
      UIntra   = this%UIntra
      USelbst  = this%USelbstTerm
      EFourier = this%UFourier

      ! Energy
      call EwaldSelfTerm_Energy(this)
      call Energy ( this, nc, np, EPotIns, 1 )

#if MPI_VER > 0
      if ( (Equilibration .and. CommonEqui) .or. (mpiMCCommonGroups > 0) ) then
        ! use MPI_RK (cmp. ms2_global.F90) instead of MPI_RK
        call MPI_Allreduce( EPotIns, EPotInsAll, 1, MPI_RK, MPI_SUM, Communicator, ierror )
        if( this%NMIEnmMax > 0 ) then
          EPotInsAll = EPotInsAll + this%Density * pc%EPotTestCorrMIE + this%UIntra-UIntra + this%USelbstTerm-USelbst-EFourier
        endif
        if( this%NTT68Max > 0 ) then
          EPotInsAll = EPotInsAll + this%Density * pc%EPotTestCorrTT68 + this%UIntra-UIntra + this%USelbstTerm-USelbst-EFourier
        endif

      else
        if( this%NMIEnmMax > 0 ) then
          EPotInsAll = EPotIns + this%Density * pc%EPotTestCorrMIE + this%UIntra-UIntra + this%USelbstTerm-USelbst-EFourier
        endif
        if( this%NTT68Max > 0 ) then
          EPotInsAll = EPotIns + this%Density * pc%EPotTestCorrTT68 + this%UIntra-UIntra + this%USelbstTerm-USelbst-EFourier
        endif
      endif

      if( rnd( 0._RK, 1._RK ) .lt. ( exp( pc%ChemPot - EPotInsAll / this%Temperature ) * this%Volume0 / np )) then
#else
        if( this%NMIEnmMax > 0 ) then
          EPotIns = EPotIns + this%Density * pc%EPotTestCorrMIE + this%UIntra-UIntra + this%USelbstTerm-USelbst-EFourier
        endif
        if( this%NTT68Max > 0 ) then
          EPotIns = EPotIns + this%Density * pc%EPotTestCorrTT68 + this%UIntra-UIntra + this%USelbstTerm-USelbst-EFourier
        endif

      ! Apply acceptance criterion - SINGLE
      if( rnd( 0._RK, 1._RK ) .lt. ( exp( pc%ChemPot - EPotIns / this%Temperature ) * this%Volume0 / np )) then
#endif
        ! Accept Insertion
        this%NInsertSuccesses = this%NInsertSuccesses + 1
        ! Update density
        this%Density = this%NPart / this%Volume0
        ! Update fractions and NDF
        call UpdateFractions( this )
        ! Update long range correction
        call CalculateCorr( this )

      else
        ! Reject Insertion
        call RemoveParticle( pc, np )
        this%NPart = this%NPart - 1
        call EwaldFourierEnergy ( this, nc, np, -1 )
        this%USelbstTerm = USelbst
        this%UIntra  = UIntra
      end if

#if SPME > 0
    else if (LongRange .eq. PME) then           ! SPME-SUMMATION
      this%qgrida_old = this%qgrida
      call chargegrid_plus (this, nc, np)
      call PMESelfTermMC( this )
      write (*,*) 'Insertion and Deletion is not supported for SPME!'
      STOP
#endif

    else                                         ! REACTION FIELD
      ! Calculate particle energy at trial position
      call EnergyinRC( this, nc, np, EPotIns )

    ! Apply acceptance criterion
#if MPI_VER > 0
      if ( (Equilibration .and. CommonEqui) .or. (mpiMCCommonGroups > 0) ) then
        ! use MPI_RK (cmp. ms2_global.F90) instead of MPI_RK
        call MPI_Allreduce( EPotIns, EPotInsAll, 1, MPI_RK, MPI_SUM, Communicator, ierror )
        if( this%NMIEnmMax > 0 ) then
          EPotInsAll = EPotInsAll + this%Density * pc%EPotTestCorrMIE + pc%EPotTestCorrRF
        endif
        if( this%NTT68Max > 0 ) then
          EPotInsAll = EPotInsAll + this%Density * pc%EPotTestCorrTT68 + pc%EPotTestCorrRF
        endif

      else
        if( this%NMIEnmMax > 0 ) then
          EPotInsAll = EPotIns + this%Density * pc%EPotTestCorrMIE + pc%EPotTestCorrRF
        endif
        if( this%NTT68Max > 0 ) then
          EPotInsAll = EPotIns + this%Density * pc%EPotTestCorrTT68 + pc%EPotTestCorrRF
        endif
      endif

      if( rnd( 0._RK, 1._RK ) .lt. ( exp( pc%ChemPot - EPotInsAll / this%Temperature ) * this%Volume0 / np )) then

#else
        if( this%NMIEnmMax > 0 ) then
          EPotIns = EPotIns + this%Density * pc%EPotTestCorrMIE + pc%EPotTestCorrRF
        endif
        if( this%NTT68Max > 0 ) then
          EPotIns = EPotIns + this%Density * pc%EPotTestCorrTT68 + pc%EPotTestCorrRF
        endif
      if( rnd( 0._RK, 1._RK ) .lt. ( exp( pc%ChemPot - EPotIns / this%Temperature ) * this%Volume0 / np )) then
#endif

        ! Accept Insertion
        this%NInsertSuccesses = this%NInsertSuccesses + 1
        ! Update density
        this%Density = this%NPart / this%Volume0
        ! Update fractions and NDF
        call UpdateFractions( this )
        ! Update long range correction
        call CalculateCorr( this )

      else
        ! Reject Insertion
        call RemoveParticle( pc, np )
        this%NPart = this%NPart - 1
      end if

    end if

  end subroutine TEnsemble_Insert



!==============================================================!
!  Subroutine TEnsemble_Insert_MUVL                            !
!==============================================================!

  subroutine TEnsemble_Insert_MUVL( this, nc )

    implicit none

    ! Include MPI header
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif

    ! Declare arguments
    type(TEnsemble)     :: this
    integer, intent(in) :: nc

    ! Declare local variables
    real(RK)                  :: r(3)
    real(RK)                  :: q(4)
    real(RK)                  :: EPotIns, EPot
    type(TComponent), pointer :: pc
    integer                   :: i, np
    real(RK)                  :: s
    real(RK)                  :: ChemPot
    real(RK)                  :: acceptance, StateAlpha, StateBeta
    real(RK)                  :: Gamma, enum, denom, N
#if MPI_VER > 0
    real(RK)                  :: EPotInsAll, EPotOldAll
#endif

    ! Assign local variables
    pc => this%Component(nc)

    ! Update number of insert attempts
    this%NInsertAttempts = this%NInsertAttempts + 1

    ChemPot = pc%ChemPot0 ! log( this%Density/pc%ChemPot )

    ! Generate a random position and orientation
    do i = 1, 3
      r(i) = rnd( -.5_RK, .5_RK )
    end do
    do
      s = 0._RK
      do i = 1, 4
        q(i) = rnd( -1._RK, 1._RK )
      end do

      s = sum( q**2 )
      if( s <= 1._RK ) exit
    end do
    q = q / sqrt( s )

    call AddParticle( pc, r, q )
    if ( tooManyParticles ) return
    np = pc%NPart
    this%NPart = this%NPart + 1

    ! Convert molecular coordinates to atom positions
    call Mol2Atom1( pc, np )

    ! Calculate particle energy at trial position  ! REACTION FIELD only
    call EnergyinRC( this, nc, np, EPot )

#if MPI_VER > 0
    if ( (Equilibration .and. CommonEqui) .or. (mpiMCCommonGroups > 0)) then
      call MPI_Allreduce( EPot, EPotIns, 1, MPI_RK, MPI_SUM, Communicator, ierror )

    else
      EPotIns = EPot
    endif
#else
     EPotIns = EPot
#endif

    if( this%NMIEnmMax > 0 ) then
      EPotIns = EPotIns + this%Density * pc%EPotTestCorrMIE
    endif
    if( this%NTT68Max > 0 ) then
      EPotIns = EPotIns + this%Density * pc%EPotTestCorrTT68
    endif

    ! StateAlpha = ((this%RefHamiltonian-pc%ChemPot0)*this%NPartInitial &
    ! &              - this%Epot + ChemPot*(this%NPart-1) )
    ! StateBeta = ((this%RefHamiltonian-pc%ChemPot0)*this%NPartInitial &
    ! & - this%Epot - EPotIns + ChemPot*this%NPart )

    StateAlpha = this%RefHill - this%Epot + pc%ChemPot0 * (this%NPart-1)
    StateBeta = this%RefHill - this%Epot - EPotIns + pc%ChemPot0 * this%NPart

    ! Gamma-Function
    N = 3._RK*this%Npart/2
    Gamma = sqrt((N)/(N-1.5))
    denom = N + 1/( 12*N - 1/(10*N))
    N = N-1.5
    enum = N + 1/( 12*N - 1/(10*N))
    Gamma = (Gamma * (enum/denom)**N)
    Gamma = Gamma/((exp(-1._RK)*denom)**1.5)
    Gamma = Gamma/(this%Temperature**1.5)

    acceptance =  ((StateBeta)**1.5) * ( StateBeta/StateAlpha )**((3*this%Npart-5)/2._RK)
    if( rnd( 0._RK, 1._RK ) .lt. ( Gamma * acceptance * this%Volume0 / np )) then
      ! Accept Insertion
      this%NInsertSuccesses = this%NInsertSuccesses + 1
      ! Update density
      this%Density = this%NPart / this%Volume0
      ! Update fractions and NDF
      call UpdateFractions( this )
      ! Update long range correction
      call CalculateCorr( this )

    else
      ! Reject Insertion
      call RemoveParticle( pc, np )
      this%NPart = this%NPart - 1
    end if

  end subroutine TEnsemble_Insert_MUVL




!==============================================================!
!  Subroutine TEnsemble_Insert_MUPR                            !
!==============================================================!

  subroutine TEnsemble_Insert_MUPR( this, nc )

    implicit none

    ! Include MPI header
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif

    ! Declare arguments
    type(TEnsemble)     :: this
    integer, intent(in) :: nc

    ! Declare local variables
    real(RK)                  :: r(3)
    real(RK)                  :: q(4)
    real(RK)                  :: EPotIns, EPot
    type(TComponent), pointer :: pc
    integer                   :: i, np
    real(RK)                  :: s
    real(RK)                  :: acceptance, StateAlpha, StateBeta
    real(RK)                  :: Gamma, enum, denom, N
#if MPI_VER > 0
    real(RK)                  :: EPotInsAll, EPotOldAll
#endif

    ! Assign local variables
    pc => this%Component(nc)

    ! Update number of insert attempts
    this%NInsertAttempts = this%NInsertAttempts + 1

    ! Generate a random position and orientation
    do i = 1, 3
      r(i) = rnd( -.5_RK, .5_RK )
    end do
    do
      s = 0._RK
      do i = 1, 4
        q(i) = rnd( -1._RK, 1._RK )
      end do

      s = sum( q**2 )
      if( s <= 1._RK ) exit
    end do
    q = q / sqrt( s )

    call AddParticle( pc, r, q )
    if ( tooManyParticles ) return
    np = pc%NPart
    this%NPart = this%NPart + 1

    ! Convert molecular coordinates to atom positions
    call Mol2Atom1( pc, np )

    ! Calculate particle energy at trial position  ! REACTION FIELD only
    call EnergyinRC( this, nc, np, EPot )

#if MPI_VER > 0
    if ( (Equilibration .and. CommonEqui) .or. (mpiMCCommonGroups > 0)) then
      call MPI_Allreduce( EPot, EPotIns, 1, MPI_RK, MPI_SUM, Communicator, ierror )

    else
      EPotIns = EPot
    endif
#else
     EPotIns = EPot
#endif

    if( this%NMIEnmMax > 0 ) then
      EPotIns = EPotIns + this%Density * pc%EPotTestCorrMIE
    endif
    if( this%NTT68Max > 0 ) then
      EPotIns = EPotIns + this%Density * pc%EPotTestCorrTT68
    endif

    StateAlpha = this%RefRay - this%Refpressure * this%Volume0 - this%Epot + pc%ChemPot0 * (this%NPart-1)
    StateBeta = this%RefRay - this%Refpressure * this%Volume0 - this%Epot - EPotIns + pc%ChemPot0 * this%NPart

    ! Gamma-Function
    N = 3._RK*this%Npart/2
    Gamma = sqrt((N)/(N-1.5))
    denom = N + 1/( 12*N - 1/(10*N))
    N = N-1.5
    enum = N + 1/( 12*N - 1/(10*N))
    Gamma = (Gamma * (enum/denom)**N)
    Gamma = Gamma/((exp(-1._RK)*denom)**1.5)
    Gamma = Gamma/(this%Temperature**1.5)

    acceptance =  ((StateBeta)**1.5) * ( StateBeta/StateAlpha )**((3*this%Npart-5)/2._RK)

    if( rnd( 0._RK, 1._RK ) .lt. ( Gamma * acceptance * this%Volume0 / np )) then
      ! Accept Insertion
      this%NInsertSuccesses = this%NInsertSuccesses + 1
      ! Update density
      this%Density = this%NPart / this%Volume0
      ! Update fractions and NDF
      call UpdateFractions( this )
      ! Update long range correction
      call CalculateCorr( this )

    else
      ! Reject Insertion
      call RemoveParticle( pc, np )
      this%NPart = this%NPart - 1
    end if

  end subroutine TEnsemble_Insert_MUPR



!==============================================================!
!  Subroutine TEnsemble_Delete                                 !
!==============================================================!

  subroutine TEnsemble_Delete( this, nc, np )

    implicit none

    ! Include MPI header
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif

    ! Declare arguments
    type(TEnsemble)     :: this
    integer, intent(in) :: nc, np

    ! Declare local variables
    real(RK)                    :: EPotDel, EPot
    type(TComponent), pointer   :: pc

! Ewald Parameter
    real(RK)                    :: EFourier
    real(RK)                    :: USelf, UIntra

    ! Assign local variables
    pc => this%Component(nc)

    ! Update number of delete attempts
    this%NDeleteAttempts = this%NDeleteAttempts + 1


    if (LongRange .eq. Ewald) then
      EFourier = this%UFourier

      USelf    = this%USelbstTerm
      UIntra   = this%UIntra
      pc%NPart = pc%NPart - 1
      call EwaldSelfTerm_Energy (this)
      call EwaldFourierEnergy(this,nc,np,-1)
      pc%NPart = pc%NPart + 1
      ! Calculate particle energy

#if MPI_VER > 0
    if ( (Equilibration .and. CommonEqui) .or. (mpiMCCommonGroups > 0) ) then
      ! use MPI_RK (cmp. ms2_global.F90) instead of MPI_RK
      call EnergyinRC( this, nc, np, EPot)
      call MPI_Allreduce( EPot, EPotDel, 1,MPI_RK, MPI_SUM, Communicator, ierror )
    else
      call EnergyinRC( this, nc, np, EPotDel)
    endif

#else
      call EnergyinRC( this, nc, np, EPotDel)
#endif
      if( this%NMIEnmMax > 0 ) then
        EPotDel = EPotDel + this%Density * pc%EPotTestCorrMIE + this%UIntra-UIntra + this%USelbstTerm-USelf-EFourier
      endif
      if( this%NTT68Max > 0 ) then
        EPotDel = EPotDel + this%Density * pc%EPotTestCorrTT68 + this%UIntra-UIntra + this%USelbstTerm-USelf-EFourier
      endif

      ! Apply acceptance criterion
      if( rnd( 0._RK, 1._RK ) .lt. ( exp( EPotDel / this%Temperature - pc%ChemPot ) * this%Density * pc%Fraction )) then

        ! Accept Deletion
        this%NDeleteSuccesses = this%NDeleteSuccesses + 1
        call RemoveParticle( pc, np )

        this%NPart = this%NPart - 1

        ! Update density
        this%Density = this%NPart / this%Volume0

        ! Update fractions and NDF
        call UpdateFractions( this )

        ! Update long range correction
        call CalculateCorr( this )
      else        ! Rejection
        call EwaldSelfTerm_Energy (this)
        call EwaldFourierEnergy(this,nc,np,1)
      end if

#if SPME > 0
    else if (LongRange .eq. PME) then
      EFourier = this%UFourier
      USelf    = this%USelbstTerm
      UIntra   = this%UIntra
      this%qgrida_old = this%qgrida
      call chargegrid_min ( this, nc,np )
      this%NPart = this%NPart - 1
      this%Component(nc)%NPart = this%Component(nc)%NPart - 1
      call PMESelfTermMC ( this )
! For further use of the following code
      this%NPart = this%NPart + 1
      this%Component(nc)%NPart = this%Component(nc)%NPart + 1
      write(*,*) 'Molecule Deletion is not supported yet with SPME'
      STOP
#endif


! ReactionField
    else
      ! Calculate particle energy
#if MPI_VER > 0
    if ( SimulationType .ne. MonteCarlo .or. (Equilibration .and. CommonEqui) .or. (mpiMCCommonGroups > 0)) then
      ! use MPI_RK (cmp. ms2_global.F90) instead of MPI_RK
      call EnergyinRC( this, nc, np, EPot)
      call MPI_Allreduce( EPot, EPotDel, 1, MPI_RK, MPI_SUM, Communicator, ierror )
    else
      call EnergyinRC( this, nc, np, EPotDel)
    endif

#else
      call EnergyinRC( this, nc, np, EPotDel)
#endif
      if( this%NMIEnmMax > 0 ) then
        EPotDel = EPotDel + this%Density * pc%EPotTestCorrMIE + pc%EPotTestCorrRF
      endif
      if( this%NTT68Max > 0 ) then
        EPotDel = EPotDel + this%Density * pc%EPotTestCorrTT68 + pc%EPotTestCorrRF
      endif

      ! Apply acceptance criterion
      if( rnd( 0._RK, 1._RK ) .lt. ( exp( EPotDel / this%Temperature - pc%ChemPot ) * this%Density * pc%Fraction )) then

        ! Accept Deletion
        this%NDeleteSuccesses = this%NDeleteSuccesses + 1
        call RemoveParticle( pc, np )

        this%NPart = this%NPart - 1

        ! Update density
        this%Density = this%NPart / this%Volume0

        ! Update fractions and NDF
        call UpdateFractions( this )

        ! Update long range correction
        call CalculateCorr( this )
      end if

     end if

  end subroutine TEnsemble_Delete



!==============================================================!
!  Subroutine TEnsemble_Delete_MUVL                            !
!==============================================================!

  subroutine TEnsemble_Delete_MUVL( this, nc, np )

    implicit none

    ! Include MPI header
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif

    ! Declare arguments
    type(TEnsemble)     :: this
    integer, intent(in) :: nc, np

    ! Declare local variables
    real(RK)                    :: EPotDel, EPot
    type(TComponent), pointer   :: pc
    real(RK)                    :: acceptance, StateAlpha, StateBeta
    real(RK)                    :: Gamma, enum, denom, N
    real(RK)                    :: ChemPot

    ! Assign local variables
    pc => this%Component(nc)

    ! Update number of delete attempts
    this%NDeleteAttempts = this%NDeleteAttempts + 1

    ChemPot = pc%ChemPot0 !log( this%Density/pc%ChemPot )

    ! ReactionField
    ! Calculate particle energy
#if MPI_VER > 0
    if ( SimulationType .ne. MonteCarlo .or. (Equilibration .and. CommonEqui) .or. (mpiMCCommonGroups > 0)) then
      ! use MPI_RK (cmp. ms2_global.F90) instead of MPI_RK
      call EnergyinRC( this, nc, np, EPot)
      call MPI_Allreduce( EPot, EPotDel, 1, MPI_RK, MPI_SUM, Communicator, ierror )
    else
      call EnergyinRC( this, nc, np, EPotDel)
    endif

#else
    call EnergyinRC( this, nc, np, EPotDel)
#endif

    if( this%NMIEnmMax > 0 ) then
      EPotDel = EPotDel + this%Density * pc%EPotTestCorrMIE
    endif
    if( this%NTT68Max > 0 ) then
      EPotDel = EPotDel + this%Density * pc%EPotTestCorrTT68
    endif

    ! StateAlpha = ((this%RefHamiltonian-pc%ChemPot0)*this%NPartInitial &
    ! &              - this%Epot + ChemPot*this%NPart )
    ! StateBeta = ((this%RefHamiltonian-pc%ChemPot0)*this%NPartInitial &
    ! & - this%Epot + EPotDel + ChemPot*(this%NPart-1) )

    StateAlpha = this%RefHill - this%Epot + pc%ChemPot0 * this%NPart
    StateBeta = this%RefHill - this%Epot + EPotDel + pc%ChemPot0 * (this%NPart-1)


    ! Gamma-Function
    N = 3._RK*this%Npart/2
    Gamma = sqrt((N-1.5)/(N))
    enum = N + 1/( 12*N - 1/(10*N))
    N = N-1.5
    denom = N + 1/( 12*N - 1/(10*N))
    Gamma = (Gamma * (enum/denom)**N)
    Gamma = Gamma*((exp(-1._RK)*denom)**1.5)
    Gamma = Gamma*(this%Temperature**1.5)

    acceptance =  ( StateBeta/StateAlpha )**((3*this%Npart-2)/2._RK) / ((StateBeta)**1.5)
    ! Apply acceptance criterion
    if( rnd( 0._RK, 1._RK ) .lt. ( Gamma * acceptance * (this%NPart-1) / this%Volume0 )) then
      ! Accept Deletion
      this%NDeleteSuccesses = this%NDeleteSuccesses + 1
      call RemoveParticle( pc, np )

      this%NPart = this%NPart - 1

      ! Update density
      this%Density = this%NPart / this%Volume0

      ! Update fractions and NDF
      call UpdateFractions( this )

      ! Update long range correction
      call CalculateCorr( this )
    end if


  end subroutine TEnsemble_Delete_MUVL



!==============================================================!
