    StateAlpha =  this%RefRay - this%Refpressure * this%Volume0 - this%Epot + pc%ChemPot0 * this%NPart
    StateBeta =  this%RefRay - this%Refpressure * this%Volume0 - this%Epot + EPotDel + pc%ChemPot0 * (this%NPart-1)

    ! Gamma-Function
    N = 3._RK*this%Npart/2
    Gamma = sqrt((N-1.5)/(N))
    enum = N + 1/( 12*N - 1/(10*N))
    N = N-1.5
    denom = N + 1/( 12*N - 1/(10*N))
    Gamma = (Gamma * (enum/denom)**N)
    Gamma = Gamma*((exp(-1._RK)*denom)**1.5)
    Gamma = Gamma*(this%Temperature**1.5)

    acceptance =  ( StateBeta/StateAlpha )**((3*this%Npart-2)/2._RK) / ((StateBeta)**1.5)

    ! Apply acceptance criterion
    if( rnd( 0._RK, 1._RK ) .lt. ( Gamma * acceptance * (this%NPart-1) / this%Volume0 )) then
      ! Accept Deletion
      this%NDeleteSuccesses = this%NDeleteSuccesses + 1
      call RemoveParticle( pc, np )

      this%NPart = this%NPart - 1

      ! Update density
      this%Density = this%NPart / this%Volume0

      ! Update fractions and NDF
      call UpdateFractions( this )

      ! Update long range correction
      call CalculateCorr( this )
    end if


  end subroutine TEnsemble_Delete_MUPR



!==============================================================!
!  Subroutine TEnsemble_Resize                                 !
!==============================================================!

  subroutine TEnsemble_Resize( this )

    implicit none

    ! Include MPI header
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif

    ! Declare arguments
    type(TEnsemble) :: this

    ! Declare local variables
    real(RK) :: VolumeOld, EPotOld, VirialOld
    real(RK) :: EPotDelta
    real(RK) :: EVirial
    real(RK) :: UFourier
    real(RK) :: UIntra, EVirialintra
    logical  :: accepted
    real(RK) :: EPot, d2EdV2, Virial
    real(RK) :: ChemPot, acceptance, NewTheta, StateAlpha, StateBeta


    ! Update number of resizing attempts
    this%NResizeAttempts = this%NResizeAttempts + 1

    ! Save current simulation box size, volume, energy, virial
    VolumeOld = this%Volume0
    EPotOld = this%EPot
    VirialOld = this%Virial
    if (LongRange .eq. Ewald) then
       UFourier= this%UFourier
       EVirial = this%EVirial

#if SPME > 0
    else if (LongRange .eq. PME) then
       EVirialIntra = this%EVirialIntra
       UFourier= this%UFourier
       EVirial = this%EVirial
#endif
    end if

    ! Generate a trial volume change
    this%Volume0 = this%Volume0 * (1._RK + rnd( -this%DispVol, this%DispVol ))
    call UpdateBoxLength( this )

    ! Convert molecular coordinates to atom positions
    call Mol2Atom( this )

    ! Calculate potential energy and virial at trial position
#if MPI_VER > 0
    ! in MC simulations we only communicate during common equilibration
    if ( SimulationType .ne. MonteCarlo .or. (Equilibration .and. CommonEqui) .or. (mpiMCCommonGroups > 0)) then
        ! use MPI_RK (cmp. ms2_global.F90) instead of MPI_RK
        call Energy( this, EPot, d2EdV2, Virial )
        call MPI_Allreduce( EPot, this%EPot, 1, MPI_RK, MPI_SUM, Communicator, ierror )
        call MPI_Allreduce( Virial, this%Virial, 1, MPI_RK, MPI_SUM, Communicator, ierror )

    else
        call Energy( this, this%EPot, d2EdV2, this%Virial )
    endif
#else
    call Energy( this, this%EPot, d2EdV2, this%Virial )
#endif

    ! Find potential change

    ! NPH
    if( EnsembleType .eq. EnsembleTypeNPH ) then
      if( exp(( real (this%NDF, RK) / 2._RK - 1._RK) * log((this%RefEnthalpy*this%NPart - this%Epot - this%RefPressure * this%Volume0) &
&       / (this%RefEnthalpy*this%NPart - EPotOld - this%RefPressure * VolumeOld)) + (this%NPart-1) * log(this%Volume0 / VolumeOld)) > rnd( 0._RK, 1._RK )) then

        ! Accept volume change
        this%Temperature = 2._RK * (this%RefEnthalpy*this%NPart - this%Epot - this%RefPressure * this%Volume0) / real (this%NDF, RK)
        this%NResizeSuccesses = this%NResizeSuccesses + 1
      else
        ! Reject volume change
        this%Volume0 = VolumeOld
        call UpdateBoxLength( this )
        call Mol2Atom( this )
        this%EPot = EPotOld
        this%Virial = VirialOld
        if (LongRange .eq. Ewald) then
          this%UFourier = UFourier

#if MPI_VER > 0
          if ( SimulationType .ne. MonteCarlo .or. (Equilibration .and. CommonEqui) .or. (mpiMCCommonGroups > 0)) then

            call Energy( this, EPot, d2EdV2, Virial )
            call MPI_Allreduce( EPot, this%EPot, 1 , MPI_RK, MPI_SUM, Communicator, ierror )
            call MPI_Allreduce( Virial, this%Virial, 1 , MPI_RK, MPI_SUM, Communicator, ierror )

          else
            call Energy( this, this%EPot, d2EdV2, this%Virial )
          end if
#else
          call Energy( this, this%EPot, d2EdV2, this%Virial )
#endif

#if SPME > 0
        else if (LongRange .eq. PME) then
          this%UIntra = UIntra
          this%EVirialIntra = EVirialIntra
          this%UFourier = UFourier
          this%EVirial = EVirial
          call charge_grid_MCall ( this )
#endif
        end if
      end if
    !mupR
    else if( EnsembleType .eq. EnsembleTypeMUPR ) then 

      ChemPot = this%Component(1)%ChemPot0
      StateAlpha = this%RefRay - this%Refpressure * VolumeOld - EPotOld + ChemPot * this%NPart
      StateBeta = this%RefRay - this%Refpressure * this%Volume0 - this%Epot + ChemPot * this%NPart

      if( StateBeta < 0._RK ) then
        NewTheta = 0._RK
      else
        NewTheta = 1._RK
      end if

      acceptance = NewTheta * (( StateBeta/StateAlpha )**((real (this%NDF, RK)-2._RK)/2._RK)) * ((this%Volume0 / VolumeOld)**(real (this%NPart-1)))

      if( acceptance .ge. rnd( 0._RK, 1._RK ) ) then
        ! Accept volume change
        this%Temperature = 2._RK * StateBeta / real (this%NDF, RK)
        this%NResizeSuccesses = this%NResizeSuccesses + 1
      else
        ! Reject volume change
        this%Volume0 = VolumeOld
        call UpdateBoxLength( this )
        call Mol2Atom( this )
        this%EPot = EPotOld
        this%Virial = VirialOld
        if (LongRange .eq. Ewald) then
          this%UFourier = UFourier

#if MPI_VER > 0
          if ( SimulationType .ne. MonteCarlo .or. (Equilibration .and. CommonEqui) .or. (mpiMCCommonGroups > 0)) then

            call Energy( this, EPot, d2EdV2, Virial )
            call MPI_Allreduce( EPot, this%EPot, 1 , MPI_RK, MPI_SUM, Communicator, ierror )
            call MPI_Allreduce( Virial, this%Virial, 1 , MPI_RK, MPI_SUM, Communicator, ierror )

          else
            call Energy( this, this%EPot, d2EdV2, this%Virial )
          end if
#else
          call Energy( this, this%EPot, d2EdV2, this%Virial )
#endif

        end if
      end if

    else !NPT of MUPT
      EPotDelta = this%RefPressure * (this%Volume0 - VolumeOld) + this%EPot - EPotOld &
&     + (this%NPart-1) * this%Temperature * log( VolumeOld / this%Volume0 )

      accepted = EPotDelta < 0._RK
      if ( .not. accepted ) accepted = exp( -EPotDelta / this%Temperature ) > rnd( 0._RK, 1._RK )

      if( accepted ) then
        ! Accept volume change
        this%NResizeSuccesses = this%NResizeSuccesses + 1
      else

        ! Reject volume change
        this%Volume0 = VolumeOld
        call UpdateBoxLength( this )
        call Mol2Atom( this )
        this%EPot = EPotOld
        this%Virial = VirialOld
        if (LongRange .eq. Ewald) then
          this%UFourier = UFourier

#if MPI_VER > 0
          if ( SimulationType .ne. MonteCarlo .or. (Equilibration .and. CommonEqui) .or. (mpiMCCommonGroups > 0)) then
            call Energy( this, EPot, d2EdV2, Virial )
            call MPI_Allreduce( EPot, this%EPot, 1 , MPI_RK, MPI_SUM, Communicator, ierror )
            call MPI_Allreduce( Virial, this%Virial, 1 , MPI_RK, MPI_SUM, Communicator, ierror )

          else
            call Energy( this, this%EPot, d2EdV2, this%Virial )
          end if
#else
          call Energy( this, this%EPot, d2EdV2, this%Virial )
#endif

#if SPME > 0
        else if (LongRange .eq. PME) then
          this%UIntra = UIntra
          this%EVirialIntra = EVirialIntra
          this%UFourier = UFourier
          this%EVirial = EVirial
          call charge_grid_MCall ( this )
#endif
        end if
      end if
    end if

  end subroutine TEnsemble_Resize



!==============================================================!
!  Subroutine TEnsemble_Resize_LiquidPhase                     !
!==============================================================!

  subroutine TEnsemble_Resize_liq( this,dv,EPotDelta )

    implicit none

    ! Include MPI header
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif

    ! Declare arguments
    type(TEnsemble) :: this

    ! Declare local variables
    real(RK), intent(in out) :: dv
    real(RK), intent(in out) :: EPotDelta
    real(RK) :: VolumeOld, EPotOld
    real(RK) :: EPot, d2EdV2, Virial

    ! Update number of resizing attempts
    this%NResizeAttempts = this%NResizeAttempts + 1

    ! Save current simulation energy
    EPotOld = this%EPot
    VolumeOld = this%Volume0

    ! Generate a trial volume change
    dv = this%Volume0 * rnd( -this%DispVol, this%DispVol )
    this%Volume0 = this%Volume0 + dv
    call UpdateBoxLength( this )

    ! Convert molecular coordinates to atom positions
    call Mol2Atom( this )

    ! Calculate potential energy and virial at trial position
#if MPI_VER > 0
    call Energy( this, EPot, d2EdV2, Virial )
    call MPI_Allreduce( EPot, this%EPot, 1, MPI_RK, MPI_SUM, Communicator, ierror )
#else
    call Energy( this, this%EPot, d2EdV2, Virial )
#endif

    ! Find potential change
    EPotDelta = this%EPot - EPotOld + this%NPart * this%Temperature * log( VolumeOld / this%Volume0 )

  end subroutine TEnsemble_Resize_liq



!==============================================================!
!  Subroutine TEnsemble_Resize_LiquidPhaseUpdate               !
!==============================================================!

  subroutine TEnsemble_ResizeLiquid_Update(this,accept,EPotOldliq,VolumeOld)

    implicit none

    ! Include MPI header
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif

    ! Declare arguments
    type(TEnsemble) :: this
    real(RK),intent(in) :: EPotOldliq,VolumeOld
    logical  :: accept
    real(RK) :: EPot, d2EdV2, Virial

    if ( accept ) then
      ! Accept volume change
      this%NResizeSuccesses = this%NResizeSuccesses + 1


#if MPI_VER > 0
      call Energy( this, EPot, d2EdV2, Virial )
      call MPI_Allreduce( Virial, this%Virial, 1, MPI_RK, MPI_SUM, Communicator, ierror )
#else
      call Energy( this, EPot, d2EdV2, Virial )
      this%Virial = Virial
#endif

    else
      ! Reject volume change
      this%Volume0 = VolumeOld
      call UpdateBoxLength( this )
      call Mol2Atom( this )
      this%EPot = EPotOldliq
      if (LongRange .eq. Ewald) then

#if MPI_VER > 0
         call Energy( this, EPot, d2EdV2, Virial )
         call MPI_Allreduce( EPot, this%EPot, 1 , MPI_RK, MPI_SUM, Communicator, ierror )
         call MPI_Allreduce( Virial, this%Virial, 1 , MPI_RK, MPI_SUM, Communicator, ierror )
#else
         call Energy( this, this%EPot, d2EdV2, this%Virial )
#endif

#if SPME > 0
      else if (LongRange .eq. PME) then
        call charge_grid_MCall ( this )
#endif
      end if
    end if

  end subroutine TEnsemble_ResizeLiquid_Update


!==============================================================!
!  Subroutine TEnsemble_Resize_VaporPhase                      !
!==============================================================!

  subroutine TEnsemble_Resize_vap( this,dv,EPotDelta,accept )

    implicit none

    ! Include MPI header
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif

    ! Declare arguments
    type(TEnsemble) :: this

    ! Declare local variables
    real(RK), intent(in) :: dv
    real(RK), intent(in out) :: EPotDelta
    real(RK) :: VolumeOld, EPotOld
    real(RK) :: EVirial
    real(RK) :: UFourier
    real(RK) :: UIntra, EVirialintra
    real(RK) :: EPot, d2EdV2, Virial
#if MPI_VER > 0
    real(RK) :: EPotNew
#endif
    logical  :: accept

    ! Save current simulation box size, volume, energy, virial
    VolumeOld = this%Volume0
    EPotOld = this%EPot
    if (LongRange .eq. Ewald) then
       UFourier= this%UFourier
       EVirial = this%EVirial

#if SPME > 0
    else if (LongRange .eq. PME) then
       EVirialIntra = this%EVirialIntra
       UFourier= this%UFourier
       EVirial = this%EVirial
#endif
    end if

    ! Generate a trial volume change
    this%Volume0 = this%Volume0 - dv
    call UpdateBoxLength( this )

    ! Convert molecular coordinates to atom positions
    call Mol2Atom( this )

    ! Calculate potential energy and virial at trial position

#if MPI_VER > 0
    call Energy( this, EPotNew, d2EdV2, Virial )
    call MPI_Allreduce( EPotNew, this%EPot, 1, MPI_RK, MPI_SUM, Communicator, ierror )
#else
    call Energy( this, this%EPot, d2EdV2, Virial )
#endif

    ! Find potential change
    EPotDelta = EPotDelta + this%EPot - EPotOld + this%NPart * this%Temperature * log( VolumeOld / this%Volume0 )

    ! Acceptance criteria
    if( exp( -EPotDelta / this%Temperature ) .gt. rnd( 0._RK, 1._RK ) ) then

      accept = .true.

#if MPI_VER > 0
      call MPI_Allreduce( Virial, this%Virial, 1, MPI_RK, MPI_SUM, Communicator, ierror )
#else
      this%Virial = Virial
#endif

    else
      ! Reject volume change
      this%Volume0 = VolumeOld
      call UpdateBoxLength( this )
      call Mol2Atom( this )
      this%EPot = EPotOld
      if (LongRange .eq. Ewald) then
         this%UFourier = UFourier
         call Energy( this, EPot, d2EdV2, Virial )

#if MPI_VER > 0
         call MPI_Allreduce( EPot, this%EPot, 1 , MPI_RK, MPI_SUM, Communicator, ierror )
         call MPI_Allreduce( Virial, this%Virial, 1 , MPI_RK, MPI_SUM, Communicator, ierror )
#else
         this%EPot = EPot
         this%Virial = Virial
#endif

#if SPME > 0
      else if (LongRange .eq. PME) then
         this%UIntra = UIntra
         this%EVirialIntra = EVirialIntra
         this%UFourier = UFourier
         this%EVirial = EVirial
         call charge_grid_MCall ( this )
#endif
      end if

    end if

  end subroutine TEnsemble_Resize_vap



!==============================================================!
!  Subroutine TEnsemble_GibbsRemoveParticle                    !
!==============================================================!

  subroutine TEnsemble_GibbsRemove( this, nc, np, EPotDelta )

    implicit none

    ! Declare arguments
    type(TEnsemble)         :: this

    real(RK)                :: rx,sx
    real(RK),intent(in out) :: EPotDelta
    integer,intent(in out)  :: nc,np

    real(RK) :: charge

     charge = 1._RK

     ! Chose component - exclude charged components
     do while  ( Charge > 0.1_RK )
       sx = 0._RK
       rx = rnd( 0._RK, 1._RK )
       do nc = 1, this%NComponents
          sx = sx + this%Component(nc)%Fraction
          if( rx <= sx ) exit
       end do
       Charge = this%Component(nc)%Molecule%Charge
     end do

     np = rnd( this%Component(nc)%NPart )

     call Gibbs_Delete( this, nc, np, EPotDelta )

   end subroutine TEnsemble_GibbsRemove


!==============================================================!
!  Subroutine TEnsemble_GibbsDelete                            !
!==============================================================!

  subroutine TEnsemble_GibbsDelete( this, nc, np, EPotDel )

    implicit none

    ! Include MPI header
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif

    ! Declare arguments
    type(TEnsemble)     :: this
    integer, intent(in) :: nc, np
    real(RK),intent(in out) :: EPotDel

    ! Declare local variables
    type(TComponent), pointer   :: pc

! Ewald Parameter
    real(RK)                    :: EFourier, EPot
    real(RK)                    :: EVirial, EVirialIntra
    real(RK)                    :: USelf, UIntra

    ! Assign local variables
    pc => this%Component(nc)
    EPotDel = 0._RK

    ! Update number of delete attempts
    this%NDeleteAttempts = this%NDeleteAttempts + 1


    if (LongRange .eq. Ewald) then
      EFourier = this%UFourier
      EVirial  = this%EVirial
      USelf    = this%USelbstTerm
      UIntra   = this%UIntra
      pc%NPart = pc%NPart - 1
      call EwaldSelfTerm_Energy (this)
      call EwaldFourierEnergy(this,nc,np,-1)
      pc%NPart = pc%NPart + 1
      ! Calculate particle energy

#if MPI_VER > 0
      call EnergyinRC( this, nc, np, EPot)
      call MPI_Allreduce( EPot, EPotDel, 1, MPI_RK, MPI_SUM, Communicator, ierror )
#else
      call EnergyinRC( this, nc, np, EPotDel)
#endif

      if( this%NMIEnmMax > 0 ) then
        EPotDel = EPotDel + this%Density * pc%EPotTestCorrMIE + NProcs*(this%UIntra-UIntra + this%USelbstTerm-USelf-EFourier) - &
&                  this%Temperature*log(this%Volume0/(this%NPart) )
      end if
      if( this%NTT68Max > 0 ) then
        EPotDel = EPotDel + this%Density * pc%EPotTestCorrTT68 + NProcs*(this%UIntra-UIntra + this%USelbstTerm-USelf-EFourier) - &
&                  this%Temperature*log(this%Volume0/(this%NPart) )
      end if

#if SPME > 0
    else if (LongRange .eq. PME) then
      EFourier = this%UFourier
      EVirial  = this%EVirial
      EVirialIntra = this%EVirialIntra
      USelf    = this%USelbstTerm
      UIntra   = this%UIntra
      this%qgrida_old = this%qgrida
      call chargegrid_min ( this, nc,np )
      this%NPart = this%NPart - 1
      this%Component(nc)%NPart = this%Component(nc)%NPart - 1
      call PMESelfTermMC ( this )
! For further use of the following code
      this%NPart = this%NPart + 1
      this%Component(nc)%NPart = this%Component(nc)%NPart + 1
      write(*,*) 'Molecule Deletion is not supported yet with SPME'
      STOP
#endif


! ReactionField
    else
      ! Calculate particle energy
#if MPI_VER > 0
      call EnergyinRC( this, nc, np, EPot)
      call MPI_Allreduce( EPot, EPotDel, 1, MPI_RK, MPI_SUM, Communicator, ierror )
#else
      call EnergyinRC( this, nc, np, EPotDel)
#endif
      if( this%NMIEnmMax > 0 ) then
        EPotDel = EPotDel + this%Density * pc%EPotTestCorrMIE + pc%EPotTestCorrRF - this%Temperature*log(this%Volume0/(this%NPart) )
      end if
      if( this%NTT68Max > 0 ) then
        EPotDel = EPotDel + this%Density * pc%EPotTestCorrTT68 + pc%EPotTestCorrRF - this%Temperature*log(this%Volume0/(this%NPart) )
      end if

    end if

  end subroutine TEnsemble_GibbsDelete


!==============================================================!
!  Subroutine TEnsemble_GibbsInsertParticle                    !
!==============================================================!

  subroutine TEnsemble_GibbsInsert( this, nc, EPotDelta,accept )

    implicit none

    ! Include MPI header
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif

    ! Declare arguments
    type(TEnsemble)     :: this
    integer, intent(in) :: nc
    real(RK),intent(in out)   :: EPotDelta
    logical             :: accept

    ! Declare local variables
    real(RK)                  :: r(3)
    real(RK)                  :: q(4)
    type(TComponent), pointer :: pc
    integer                   :: i, np
    real(RK)                  :: s
    real(RK)                  :: EPotIns
    real(RK)                  :: UIntra, USelbst, EFourier, EVirial
#if MPI_VER > 0
    real(RK)                  :: EPotInsAll
#endif

    ! Assign local variables
    pc => this%Component(nc)

    ! Generate a random position and orientation
    do i = 1, 3
      r(i) = rnd( -.5_RK, .5_RK )
    end do
    do
      s = 0._RK
      do i = 1, 4
        q(i) = rnd( -1._RK, 1._RK )
      end do
      s = sum( q**2 )
      if( s <= 1._RK ) exit
    end do
    q = q / sqrt( s )

    call AddParticle( pc, r, q )
    np = pc%NPart
    this%NPart = this%NPart + 1

    ! Convert molecular coordinates to atom positions
    call Mol2Atom1( pc, np )

    if (LongRange .eq. Ewald) then           ! EWALD-SUMMATION
      UIntra   = this%UIntra
      USelbst  = this%USelbstTerm
      EFourier = this%UFourier
      EVirial  = this%EVirial
      ! Energy
      call EwaldSelfTerm_Energy(this)
      call Energy ( this, nc, np, EPotIns, 1 )
#if MPI_VER > 0
      call MPI_Allreduce( EPotIns, EPotInsAll, 1, MPI_RK, MPI_SUM, Communicator, ierror )
      if( this%NMIEnmMax > 0 ) then
        EPotDelta = EpotDelta - EPotInsAll - this%Density * pc%EPotTestCorrMIE - this%Temperature * log((this%NPart)/this%Volume0 ) - &
&            NProcs * this%UIntra + NProcs * UIntra - NProcs * this%USelbstTerm + NProcs * USelbst + NProcs * EFourier
      end if
      if( this%NTT68Max > 0 ) then
        EPotDelta = EpotDelta - EPotInsAll - this%Density * pc%EPotTestCorrTT68 - this%Temperature * log((this%NPart)/this%Volume0 ) - &
&            NProcs * this%UIntra + NProcs * UIntra - NProcs * this%USelbstTerm + NProcs * USelbst + NProcs * EFourier
      end if

      if( rnd( 0._RK, 1._RK ) .lt. ( exp( EPotDelta / this%Temperature ) )) then
#else
      if( this%NMIEnmMax > 0 ) then
        EPotDelta = EPotDelta - EPotIns - this%Density * pc%EPotTestCorrMIE  - this%Temperature * log((this%NPart)/this%Volume0 ) - &
&            this%UIntra + UIntra - this%USelbstTerm + USelbst + EFourier
      end if
      if( this%NTT68Max > 0 ) then
        EPotDelta = EPotDelta - EPotIns - this%Density * pc%EPotTestCorrTT68  - this%Temperature * log((this%NPart)/this%Volume0 ) - &
&            this%UIntra + UIntra - this%USelbstTerm + USelbst + EFourier
      end if

      if( rnd( 0._RK, 1._RK ) .lt. ( exp( EPotDelta / this%Temperature ) )) then
#endif
        ! Accept Insertion
        accept = .true.
        this%NInsertSuccesses = this%NInsertSuccesses + 1
        ! Update density
        this%Density = this%NPart / this%Volume0
        ! Update fractions and NDF
        call UpdateFractions( this )
        ! Update long range correction
        call CalculateCorr( this )

      else
        ! Reject Insertion
        call RemoveParticle( pc, np )
        this%NPart = this%NPart - 1
        call EwaldFourierEnergy ( this, nc, np, -1 )
        this%USelbstTerm = USelbst
        this%UIntra  = UIntra
      end if

    else                                         ! REACTION FIELD
      ! Calculate particle energy at trial position
      call EnergyinRC( this, nc, np, EPotIns )
    ! Apply acceptance criterion
#if MPI_VER > 0
      call MPI_Allreduce( EPotIns, EPotInsAll, 1, MPI_RK, MPI_SUM, Communicator, ierror )

      if( this%NMIEnmMax > 0 ) then
        EPotDelta = EpotDelta - EPotInsAll - this%Density * pc%EPotTestCorrMIE &
&        - pc%EPotTestCorrRF - this%Temperature*log((this%NPart)/this%Volume0 )
      end if
      if( this%NTT68Max > 0 ) then
        EPotDelta = EpotDelta - EPotInsAll - this%Density * pc%EPotTestCorrTT68 &
&        - pc%EPotTestCorrRF - this%Temperature*log((this%NPart)/this%Volume0 )
      end if

      if( rnd( 0._RK, 1._RK ) .lt. ( exp( EPotDelta / this%Temperature ) )) then
#else
      if( this%NMIEnmMax > 0 ) then
        EPotDelta = EPotDelta - EPotIns - this%Density * pc%EPotTestCorrMIE &
&         - pc%EPotTestCorrRF - this%Temperature*log((this%NPart)/this%Volume0 )
      end if
      if( this%NTT68Max > 0 ) then
        EPotDelta = EPotDelta - EPotIns - this%Density * pc%EPotTestCorrTT68 &
&         - pc%EPotTestCorrRF - this%Temperature*log((this%NPart)/this%Volume0 )
      end if

      if( rnd( 0._RK, 1._RK ) .lt. ( exp( EPotDelta / this%Temperature ) )) then
#endif

        accept = .true.
        ! Update density
        this%Density = this%NPart / this%Volume0
        ! Update fractions and NDF
        call UpdateFractions( this )
        ! Update long range correction
        call CalculateCorr( this )

      else
        ! Reject Insertion
        call RemoveParticle( pc, np )
        this%NPart = this%NPart - 1
      end if

    end if

   end subroutine TEnsemble_GibbsInsert



!==============================================================!
!  Subroutine TEnsemble_PartChangeUpdate                       !
!==============================================================!

  subroutine TEnsemble_PartChangeUpdate(this,nc,np,TransferRate,accept)

    implicit none

    ! Include MPI header
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif

    ! Declare arguments
    type(TEnsemble)       :: this
    integer, intent(in)   :: nc,np
    integer,intent(in out):: TransferRate
    logical               :: accept

    ! Declare variables
    type(TComponent)  ,pointer :: pc
    type(TInteraction),pointer :: pi

    real(RK) :: AccRateTransfer

    pc => this%Component(nc)
    this%NTransferAttempts = this%NTransferAttempts + 1
    if ( accept ) then
      this%NTransferSuccesses = this%NTransferSuccesses + 1
      call RemoveParticle( pc, np )

        this%NPart = this%NPart - 1

        ! Update density
        this%Density = this%NPart / this%Volume0

        ! Update fractions and NDF
        call UpdateFractions( this )

        ! Update long range correction
        call CalculateCorr( this )
    else
      if (LongRange .eq. Ewald) then
        call EwaldSelfTerm_Energy (this)
        call EwaldFourierEnergy(this,nc,np,1)
      end if
    endif

! Adjusting the amount of transfer moves
    AccRateTransfer = real(this%NTransferSuccesses) / real(this%NTransferAttempts)

      ! Update transfer rate
      if(( AccRateTransfer .gt. AccUpperLimit ) .and. ( TransferRate .lt. TransferRateLimit )) then
           TransferRate = int(TransferRate * 1.05_RK)

      else if( AccRateTransfer .lt. AccLowerLimit ) then
           TransferRate = int(TransferRate * 0.95_RK)
      end if



  end subroutine TEnsemble_PartChangeUpdate


!==============================================================!
!  Subroutine TEnsemble_ZeroNAttempts                          !
!==============================================================!

  subroutine TEnsemble_ZeroNAttempts( this )

    implicit none

    ! Declare arguments
    type(TEnsemble) :: this

    ! Declare local variables
    integer :: i

    ! Zero number of MC attempts and successes
    do i = 1, this%NComponents
      call ZeroNAttempts( this%Component(i) )
    end do

    this%NResizeAttempts  = 0
    this%NResizeSuccesses = 0
    this%NInsertAttempts  = 0
    this%NInsertSuccesses = 0
    this%NDeleteAttempts  = 0
    this%NDeleteSuccesses = 0
    this%NTransferAttempts  = 0
    this%NTransferSuccesses = 0

  end subroutine TEnsemble_ZeroNAttempts



!==============================================================!
!  Subroutine TEnsemble_UpdateDisplacements                    !
!==============================================================!

  subroutine TEnsemble_UpdateDisplacements( this )

    implicit none

    ! Declare arguments
    type(TEnsemble) :: this

    ! Declare local variables
    type(TComponent), pointer :: pc
    integer                   :: i
    real(RK) :: AccRateTran, AccRateRot, AccRateVol

    ! Calculate acceptance rates
    do i = 1, this%NRealComponents
      pc => this%Component(i)
      AccRateTran = real(pc%NMoveSuccesses) / real(pc%NMoveAttempts)
      AccRateRot = real(pc%NRotateSuccesses) / real(pc%NRotateAttempts)

      ! Update translational displacement
      if(( AccRateTran .gt. AccUpperLimit) .and. ( pc%DispTran .lt. DispTranLimit )) then
        pc%DispTran = pc%DispTran * 1.05_RK

      else if( AccRateTran .lt. AccLowerLimit ) then
        pc%DispTran = pc%DispTran * .95_RK
      end if

      ! Update rotational displacement
      if(( AccRateRot .gt. AccUpperLimit ) .and. ( pc%DispRot .lt. DispRotLimit )) then
        pc%DispRot = pc%DispRot * 1.05_RK

      else if( AccRateRot .lt. AccLowerLimit ) then
        pc%DispRot = pc%DispRot * 0.95_RK
      end if
    end do

    if( ConstantPressure .and. .not. NVTEquilibration ) then
      AccRateVol = real(this%NResizeSuccesses) / real(this%NResizeAttempts)

      ! Update volume displacement
      if(( AccRateVol .gt. AccUpperLimit ) .and. ( this%DispVol .lt. DispVolLimit )) then
        this%DispVol = this%DispVol * 1.05_RK

      else if( AccRateVol .lt. AccLowerLimit ) then
        this%DispVol = this%DispVol * 0.95_RK
      end if
    end if

    ! Zero attempts
    call ZeroNAttempts( this )

  end subroutine TEnsemble_UpdateDisplacements




!==============================================================!
!  Subroutine TEnsemble_ResidenceTime                          !
!==============================================================!

  subroutine TEnsemble_Residence( this )

    implicit none

    ! Declare arguments
    type(TEnsemble)    :: this

    ! Declare local variables
    real(RK) :: R1x, R1y, R1z
    real(RK) :: R2x, R2y, R2z
    real(RK) :: drx, dry, drz
    real(RK) :: CriticalLength
    integer  :: i
    integer  :: Numb1, Numb2
    integer  :: counter

!     CriticalLength = (this%ResidLength * this%BoxLength)**2
    CriticalLength = (this%ResidLength)**2
    counter = 0
    do i = 1, this%ResidPairs
      Numb1 = this%CompPair(i,1)
      Numb2 = this%CompPair(i,2)

      ! Do not evaluate the pair, since it seperated earlier
      if ( (Numb1 == 0) .or. (Numb2 == 0) ) then
        counter = counter + 1
        cycle
      end if

      ! Calculate distance
      if( this%NMIEnmMax > 0 ) then
        R1x = this%Component(this%ResidComp1)%Molecule%SiteMIEnm(this%ResidSite1)%RX(Numb1)
        R1y = this%Component(this%ResidComp1)%Molecule%SiteMIEnm(this%ResidSite1)%RY(Numb1)
        R1z = this%Component(this%ResidComp1)%Molecule%SiteMIEnm(this%ResidSite1)%RZ(Numb1)
        R2x = this%Component(this%ResidComp2)%Molecule%SiteMIEnm(this%ResidSite2)%RX(Numb2)
        R2y = this%Component(this%ResidComp2)%Molecule%SiteMIEnm(this%ResidSite2)%RY(Numb2)
        R2z = this%Component(this%ResidComp2)%Molecule%SiteMIEnm(this%ResidSite2)%RZ(Numb2)
      end if
      if( this%NTT68Max > 0 ) then
        R1x = this%Component(this%ResidComp1)%Molecule%SiteTT68(this%ResidSite1)%RX(Numb1)
        R1y = this%Component(this%ResidComp1)%Molecule%SiteTT68(this%ResidSite1)%RY(Numb1)
        R1z = this%Component(this%ResidComp1)%Molecule%SiteTT68(this%ResidSite1)%RZ(Numb1)
        R2x = this%Component(this%ResidComp2)%Molecule%SiteTT68(this%ResidSite2)%RX(Numb2)
        R2y = this%Component(this%ResidComp2)%Molecule%SiteTT68(this%ResidSite2)%RY(Numb2)
        R2z = this%Component(this%ResidComp2)%Molecule%SiteTT68(this%ResidSite2)%RZ(Numb2)
      end if

      drx = (R1x - R2x)
      drx = ( (drx -anint(drx))*this%BoxLength )**2
      dry = (R1y - R2y)
      dry = ( (dry -anint(dry))*this%BoxLength )**2
      drz = (R1z - R2z)
      drz = ( (drz -anint(drz))*this%BoxLength )**2

      if ( drx+dry+drz .gt. CriticalLength ) then
        this%ResidCem = this%ResidCem + 1
        this%ResidPairsCem(this%ResidCem,1) = this%CompPair(i,1)
        this%ResidPairsCem(this%ResidCem,2) = this%CompPair(i,2)
        this%ResidPairsCem(this%ResidCem,3) = this%ResidTimesStart(i)
        this%ResidPairsCem(this%ResidCem,4) = Step
        this%CompPair(i,1) = 0
        this%CompPair(i,2) = 0
        this%ResidTimesStart(i) = 0._RK
      end if
    end do

    ! Update list, if time is ready
    if (mod(Step,this%ResidPeriod) == 0) then
      call ResidencePartners ( this )
    end if
    ! Count number of pairs per time step
    call Update( this%SumResidencePairs, 1._RK*this%ResidPairs - 1._RK*counter )

   end subroutine TEnsemble_Residence


!==============================================================!
!  Subroutine TEnsemble_ResidencePartners                      !
!==============================================================!

  subroutine TEnsemble_ResidencePartners( this )

    implicit none

    ! Declare arguments
    type(TEnsemble) :: this

    ! Declare local variables
    integer :: i, j
    integer :: ResidPairs
    integer :: counter
    type(TComponent),pointer :: pc1, pc2
    real(RK) :: R1x, R1y, R1z
    real(RK) :: R2x, R2y, R2z
    real(RK) :: drx, dry, drz
    real(RK) :: CriticalLength

    pc1 => this%Component(this%ResidComp1)
    pc2 => this%Component(this%ResidComp2)
    CriticalLength = (this%ResidLength)**2
    ResidPairs = 0
    this%ResidTimesStart_Old = this%ResidTimesStart
    this%CompPair_Old = this%CompPair

    do i=1, pc1%NPart
      do j=1, pc2%NPart

        ! Calculate distance
        if( this%NMIEnmMax > 0 ) then
          R1x = pc1%Molecule%SiteMIEnm(this%ResidSite1)%RX(i)
          R1y = pc1%Molecule%SiteMIEnm(this%ResidSite1)%RY(i)
          R1z = pc1%Molecule%SiteMIEnm(this%ResidSite1)%RZ(i)
          R2x = pc2%Molecule%SiteMIEnm(this%ResidSite2)%RX(j)
          R2y = pc2%Molecule%SiteMIEnm(this%ResidSite2)%RY(j)
          R2z = pc2%Molecule%SiteMIEnm(this%ResidSite2)%RZ(j)
        end if
        if( this%NTT68Max > 0 ) then
          R1x = pc1%Molecule%SiteTT68(this%ResidSite1)%RX(i)
          R1y = pc1%Molecule%SiteTT68(this%ResidSite1)%RY(i)
          R1z = pc1%Molecule%SiteTT68(this%ResidSite1)%RZ(i)
          R2x = pc2%Molecule%SiteTT68(this%ResidSite2)%RX(j)
          R2y = pc2%Molecule%SiteTT68(this%ResidSite2)%RY(j)
          R2z = pc2%Molecule%SiteTT68(this%ResidSite2)%RZ(j)
        end if

        drx = (R1x - R2x)
        drx = ( (drx -anint(drx))*this%BoxLength )**2
        dry = (R1y - R2y)
        dry = ( (dry -anint(dry))*this%BoxLength )**2
        drz = (R1z - R2z)
        drz = ( (drz -anint(drz))*this%BoxLength )**2
        if ( drx+dry+drz .le. CriticalLength ) then
          ResidPairs = ResidPairs + 1
          this%CompPair(ResidPairs,1) = i
          this%CompPair(ResidPairs,2) = j
          this%ResidTimesStart(ResidPairs) = Step
        end if
      end do
    end do

! Update pairs, that are still grouped
    do i=1,ResidPairs
      do j=1, this%ResidPairs
        if ( (this%CompPair(i,1) .eq. this%CompPair_Old(j,1)) .and. (this%CompPair(i,2) .eq. this%CompPair_Old(j,2)) ) then
          this%ResidTimesStart(i) = this%ResidTimesStart_Old(j)
        end if
      end do
    end do

! Update pairs, that were grouped but were separated for less time than allowed (ResidBreak)
    counter = 0
    do i=1,ResidPairs
      do j=1, this%ResidCem
        if ( (this%CompPair(i,1) .eq. this%ResidPairsCem(j,1)) .and. (this%CompPair(i,2) .eq. this%ResidPairsCem(j,2)) ) then
          this%ResidTimesStart(i) = this%ResidPairsCem(j,3)
          this%ResidPairsCem(this%ResidCem,1:4) = this%ResidPairsCem(j,1:4)
          counter = counter + 1
        end if
      end do
    end do
    this%ResidCem = this%ResidCem - counter

! Update Residence Time
    counter = 0
    do i=1, this%ResidCem
      if ( (Step - this%ResidPairsCem(i,4)) .gt. this%ResidBreak ) then
         call Update( this%SumResidenceDuration, ( this%ResidPairsCem(i,4)-this%ResidPairsCem(i,3) )*TimeStep )
          this%ResidPairsCem(this%ResidCem,1:4) = this%ResidPairsCem(i,1:4)
          counter = counter + 1
      end if
    end do
    this%ResidCem = this%ResidCem - counter

! Update Number of pairs in the system (really grouped!)
    this%ResidPairs = ResidPairs

   end subroutine TEnsemble_ResidencePartners



!==============================================================!
!  Subroutine TEnsemble_SaveState                              !
!==============================================================!

  subroutine TEnsemble_SaveState( this )

    implicit none

    ! Declare arguments
    type(TEnsemble) :: this

    ! Declare local variables
    integer :: i

    ! Save current state
    do i = 1, this%NRealComponents
      call SaveState( this%Component(i) )
    end do

  end subroutine TEnsemble_SaveState



!==============================================================!
!  Subroutine TEnsemble_RestoreState                           !
!==============================================================!

  subroutine TEnsemble_RestoreState( this )

    implicit none

    ! Declare arguments
    type(TEnsemble) :: this

    ! Declare local variables
    integer :: i
    real(RK):: EPot, d2EdV2, Virial

    ! Restore current state
    do i = 1, this%NRealComponents
      call RestoreState( this%Component(i) )
    end do

    call Energy( this, this%EPot, d2EdV2, Virial )

  end subroutine TEnsemble_RestoreState



!==============================================================!
!  Subroutine TEnsemble_ResultOpen                             !
!==============================================================!

  subroutine TEnsemble_ResultOpen( this )

    implicit none

    ! Declare arguments
    type(TEnsemble) :: this

    if( Restart ) then
#if MPI_VER > 0
      if (SimulationType .eq. MonteCarlo) then
        write( IOBuffer, '(I16)' ) this%EnsembleNumber
        call FileAppend_parallel(this%resultFile, trim( OutputNameTag )//'_'//trim( adjustl( IOBuffer ) )//ResultFileExtension )

        if( .not. SimulationType .eq. SecondVirialCoeff ) then

          ! Open running average result file
          write( IOBuffer, '(I16)' ) this%EnsembleNumber
          call FileAppend_parallel( this%runaveFile, trim( OutputNameTag )//'_'//trim( adjustl( IOBuffer ) )//RunAveFileExtension )
        end if
      else
        write( IOBuffer, '(I16)' ) this%EnsembleNumber
        call FileAppend(this%resultFile, trim( OutputNameTag )//'_'//trim( adjustl( IOBuffer ) )//ResultFileExtension )

        if( .not. SimulationType .eq. SecondVirialCoeff ) then

          ! Open running average result file
          write( IOBuffer, '(I16)' ) this%EnsembleNumber
          call FileAppend(this%runaveFile, trim( OutputNameTag )//'_'//trim( adjustl( IOBuffer ) )//RunAveFileExtension )
        end if
      endif
#else
      ! Open result file
      write( IOBuffer, '(I16)' ) this%EnsembleNumber
      call FileAppend(this%resultFile ,trim( OutputNameTag )//'_'//trim( adjustl( IOBuffer ) )//ResultFileExtension )

      if( .not. SimulationType .eq. SecondVirialCoeff ) then

        ! Open running average result file
        write( IOBuffer, '(I16)' ) this%EnsembleNumber
        call FileAppend(this%runaveFile, trim( OutputNameTag )//'_'//trim( adjustl( IOBuffer ) )//RunAveFileExtension )
      end if
#endif

#if TRANS ==1
      write( IOBuffer, '(I16)' ) this%EnsembleNumber
      call FileAppend(this%rescfFile, trim( OutputNameTag )//'_'//trim( adjustl( IOBuffer ) )//ResultTransportExtension )
#endif

    else
#if MPI_VER > 0
      if (SimulationType .eq. MonteCarlo) then
        ! Open result file
        write( IOBuffer, '(I16)' ) this%EnsembleNumber
        call FileRewrite_parallel(this%resultFile, trim( OutputNameTag )//'_'//trim( adjustl( IOBuffer ) )//ResultFileExtension )
        if( .not. SimulationType .eq. SecondVirialCoeff ) then

          ! Open running average result file
          write( IOBuffer, '(I16)' ) this%EnsembleNumber
          call FileRewrite_parallel(this%runaveFile, trim( OutputNameTag )//'_'//trim( adjustl( IOBuffer ) )//RunAveFileExtension )
        end if
      else
        ! Open result file
        write( IOBuffer, '(I16)' ) this%EnsembleNumber
        call FileRewrite(this%resultFile, trim( OutputNameTag )//'_'//trim( adjustl( IOBuffer ) )//ResultFileExtension )

        if( .not. SimulationType .eq. SecondVirialCoeff ) then

          ! Open running average result file
          write( IOBuffer, '(I16)' ) this%EnsembleNumber
          call FileRewrite(this%runaveFile, trim( OutputNameTag )//'_'//trim( adjustl( IOBuffer ) )//RunAveFileExtension )
        end if
      endif
#else

      ! Open result file
      write( IOBuffer, '(I16)' ) this%EnsembleNumber
      call FileRewrite(this%resultFile, trim( OutputNameTag )//'_'//trim( adjustl( IOBuffer ) )//ResultFileExtension )

      if( .not. SimulationType .eq. SecondVirialCoeff ) then

        ! Open running average result file
        write( IOBuffer, '(I16)' ) this%EnsembleNumber
        call FileRewrite(this%runaveFile, trim( OutputNameTag )//'_'//trim( adjustl( IOBuffer ) )//RunAveFileExtension )
      end if
#endif
#if  TRANS == 1
      ! Open result file for correlation function
      write( IOBuffer, '(I16)' ) this%EnsembleNumber
      call FileRewrite(this%rescfFile, trim( OutputNameTag )//'_'//trim( adjustl( IOBuffer ) )//ResultTransportExtension )
      !if( (TransMethod .eq. Einstein) .or. (TransMethod .eq. GKEinstein)) then
      !    write( IOBuffer, '(I16)' ) this%EnsembleNumber
      !    call FileRewrite( this%ecoefFile%iounit, trim( OutputNameTag )//'_'//trim( adjustl( IOBuffer ) )//EinsteinCoefFileExtension )
      !end if
#endif

    end if

  end subroutine TEnsemble_ResultOpen


  subroutine writeIOBufferToRUNandRAV(resultFile, runaveFile)

    implicit none

    type(TFile), intent(in) :: resultFile, runaveFile

#if MPI_VER > 0

    ! parallel MC
    if (SimulationType .eq. MonteCarlo) then

        call FileWriteNoAdvance_parallel(resultFile)
        call FileWriteNoAdvance_parallel(runaveFile)

    else
#endif
        ! not parallel MC
        call FileWriteNoAdvance(resultFile)
        call FileWriteNoAdvance(runaveFile)

#if MPI_VER > 0
    endif
#endif

  end subroutine writeIOBufferToRUNandRAV


  subroutine writeRunRavHeader(this)

    implicit none

    type(TEnsemble) :: this
    integer :: i, j
    character(11) :: columnWidth

#if HBOND > 0
    integer                   :: k, l, m
#endif

    ! Number of steps
    write( IOBuffer, '("       NR")' )

#if MPI_VER > 0
    if (SimulationType .eq. MonteCarlo) then ! parallel MC differs w.r.t. this column width

        write( IOBuffer, '(A)' )new_line('a')
        call writeIOBufferToRUNandRAV(this%resultFile, this%runaveFile)

        ! PROC
        write( IOBuffer, '("       PROC")' )
        call writeIOBufferToRUNandRAV(this%resultFile, this%runaveFile)

        write( IOBuffer, '("         NR")' )
    else
#endif

        call FileWriteBlank(this%resultFile)
        call FileWriteBlank(this%runaveFile)

#if MPI_VER > 0
    end if
#endif

    call writeIOBufferToRUNandRAV(this%resultFile, this%runaveFile)

    if (SimulationType .ne. MonteCarlo) then

        ! Displacement
        write( IOBuffer, '("     DISP")' )
        call FileWriteNoAdvance(this%runaveFile)

    end if

    ! Pressure
    write( IOBuffer, '("      PRESS")' )
    call writeIOBufferToRUNandRAV(this%resultFile, this%runaveFile)

    ! Density
    write( IOBuffer, '("    DENSITY")' )
    call writeIOBufferToRUNandRAV(this%resultFile, this%runaveFile)

    ! Temperature
    write( IOBuffer, '("       TEMP")' )
    call writeIOBufferToRUNandRAV(this%resultFile, this%runaveFile)

#if OSMOP > 0
    ! OsmoticPressure
    write( IOBuffer, '("      OSPR")' )
    call writeIOBufferToRUNandRAV(this%resultFile, this%runaveFile)
#endif

    ! Potential energy
    write( IOBuffer, '("       EPOT")' )
    call writeIOBufferToRUNandRAV(this%resultFile, this%runaveFile)

    ! Enthalpy
    write( IOBuffer, '("      ENTLP")' )
    call writeIOBufferToRUNandRAV(this%resultFile, this%runaveFile)

    ! Dielectric Constant
    if( (this%NChargeMax > 0).or.(this%NDipoleMax > 0) ) then

        write( IOBuffer, '("    EPSILON")' )
        call writeIOBufferToRUNandRAV(this%resultFile, this%runaveFile)

        ! Dielectric Constant
        write( IOBuffer, '("        <M>")' )
        call writeIOBufferToRUNandRAV(this%resultFile, this%runaveFile)

        ! Dielectric Constant
        write( IOBuffer, '("      <M^2>")' )
        call writeIOBufferToRUNandRAV(this%resultFile, this%runaveFile)

    endif

    ! Chemical potential
    do i = 1, this%NRealComponents

        if( (this%Component(i)%ChemPotMethod .ne. ChemPotMethodNone) .or. (EnsembleType .eq. EnsembleTypeGE) ) then

            write( columnWidth, '(A, I0.1)') "MUE_", i  ! create string
            write( IOBuffer, '(A)' ) adjustr(columnWidth)! fill string up to length 'width' with leading spaces for right alignment

            call writeIOBufferToRUNandRAV(this%resultFile, this%runaveFile)

        end if

    end do

    ! Partial molar volume
    do i = 1, this%NRealComponents

        if( this%Component(i)%ChemPotMethod .ne. ChemPotMethodNone .and. ( (EnsembleType .eq. EnsembleTypeNPT) .or. (EnsembleType .eq. EnsembleTypeNPTSVC) ) ) then

            write( columnWidth, '(A, I0.1)') "VW_", i
            write( IOBuffer, '(A)' ) adjustr(columnWidth)

            call writeIOBufferToRUNandRAV(this%resultFile, this%runaveFile)

        end if

    end do

    ! Partial molar enthalpy
    do i = 1, this%NRealComponents

        if( this%Component(i)%ChemPotMethod .ne. ChemPotMethodNone .and. ( (EnsembleType .eq. EnsembleTypeNPT) .or. (EnsembleType .eq. EnsembleTypeNPTSVC) ) ) then

            write( columnWidth, '(A, I0.1)') "HM_", i
            write( IOBuffer, '(A)' ) adjustr(columnWidth)

            call writeIOBufferToRUNandRAV(this%resultFile, this%runaveFile)

        end if

    end do

    if (SimulationType .ne. MonteCarlo) then

#if HBOND > 0
        do i = 1, this%NComponents
          write( IOBuffer, '("  HB0_(", I1, ")")' ) i
          call writeIOBufferToRUNandRAV(this%resultFile, this%runaveFile)
        end do

        do i = 1, this%NComponents
          do  j = 1, this%NComponents
            write( IOBuffer, '("  HB1_(", I1, ",", I1, ")")' ) i, j
            call writeIOBufferToRUNandRAV(this%resultFile, this%runaveFile)
          end do
        end do

        do i = 1, this%NComponents
          do  j = 1, this%NComponents
            do k = j, this%NComponents
              write( IOBuffer, '("  HB2_(", I1, ",", I1, ",", I1, ")")' ) i, j, k
              call writeIOBufferToRUNandRAV(this%resultFile, this%runaveFile)
            end do
          end do
        end do

        do i = 1, this%NComponents
          do  j = 1, this%NComponents
            do k = j, this%NComponents
              do  l = k, this%NComponents
                write( IOBuffer, '("  HB3_(", I1, ",", I1, ",", I1, ",", I1, ")")' ) i, j, k, l
                call writeIOBufferToRUNandRAV(this%resultFile, this%runaveFile)
              end do
            end do
          end do
        end do

        do i = 1, this%NComponents
          do  j = 1, this%NComponents
            do k = j, this%NComponents
              do l = k, this%NComponents
                do m = l, this%NComponents
                  write( IOBuffer, '("  HB4_(", I1, ",", I1, ",", I1, ",", I1,",", I1, ")")' ) i, j, k, l, m
                  call writeIOBufferToRUNandRAV(this%resultFile, this%runaveFile)
                end do
              end do
            end do
          end do
        end do

        do i = 1, this%NComponents
          write( IOBuffer, '("  HB4+_(", I1, ")")' ) i
          call writeIOBufferToRUNandRAV(this%resultFile, this%runaveFile)
        end do
#endif

#if OSMOP > 0
        !Density Profile
        do i = 1, this%NComponents
          do j = 1, NBinsDen
            if (j .le. 9) then
              write( IOBuffer, '("   DP", I1, "B00", I1)' ) i, j
            elseif (j .le. 99) then
              write( IOBuffer, '("    DP", I1, "B0", I2)' ) i, j
            else
              write( IOBuffer, '("     DP", I1, "B", I3)' ) i, j
            endif
            call writeIOBufferToRUNandRAV(this%resultFile, this%runaveFile)
          end do
        end do

#if OSMOP == 2
        !Pressure Profile
        do j = 1, NBinsDen
          if (j .le. 9) then
            write( IOBuffer, '(" PPB00", I1)' ) j
          elseif (j .le. 99) then
            write( IOBuffer, '(" PPB0", I2)' ) j
          else
            write( IOBuffer, '(" PPB", I3)' ) j
          endif
          call writeIOBufferToRUNandRAV(this%resultFile, this%runaveFile)
        end do

        !Chemical Potential Profile
        do i = 1, this%NRealComponents
          if( this%Component(i)%ChemPotMethod .eq. ChemPotMethodWidom ) then
            do j = 1, NBinsDen
              if (j .le. 9) then
                write( IOBuffer, '("     CP", I1, "B00", I1)' ) i, j
              elseif (j .le. 99) then
                write( IOBuffer, '("     CP", I1, "B0", I2)' ) i, j
              else
                write( IOBuffer, '("     CP", I1, "B", I3)' ) i, j
              endif
              call writeIOBufferToRUNandRAV(this%resultFile, this%runaveFile)
            end do
          end if
        end do
#endif
#endif
    end if

    ! Number of particles in ensemble
    if( OpenSystem .or. EnsembleType .eq. EnsembleTypeHA .or. SimulationType .eq. Gibbs) then

        write( IOBuffer, '("      NPART")' )
        call writeIOBufferToRUNandRAV(this%resultFile, this%runaveFile)

        ! Mole fraction of each component
        do i = 1, this%NComponents

            write( columnWidth, '(A, I0.1)') "FRACT_", i
            write( IOBuffer, '(A)' ) adjustr(columnWidth)

            call writeIOBufferToRUNandRAV(this%resultFile, this%runaveFile)

        end do

    end if

#if MPI_VER > 0
    if (SimulationType .eq. MonteCarlo) then ! parallel MC

        write( IOBuffer, '(A)' )new_line('a')
        call writeIOBufferToRUNandRAV(this%resultFile, this%runaveFile)

    else
#endif

        call FileWriteBlank(this%resultFile)
        call FileWriteBlank(this%runaveFile)

#if MPI_VER > 0
    end if
#endif

  end subroutine writeRunRavHeader


!==============================================================!
!  Subroutine TEnsemble_ResultUpdate                           !
!==============================================================!

  subroutine TEnsemble_ResultUpdate( this )

    implicit none

#if MPI_VER > 0
#if !defined(MPI_USE_MODULE)
  include 'mpif.h'
#endif
    integer         :: fields = 0
    integer         :: accumulate_step = 0
    integer         :: headers = 0
    integer(kind=MPI_OFFSET_KIND) :: offset = 0
    integer                       :: ierr
#endif

    ! Declare arguments
    type(TEnsemble) :: this

    ! Declare local variables
    type(TComponent), pointer :: pc
    integer                   :: i,j,t,err,currentbin
    real(RK)                  :: value, factor
    real(RK)                  :: currentBinsEn, EPot
    real(RK)                  :: currentdEpotdV,currentd2EpotdV2
    real(RK)                  :: A10res, A01res, A20res, A11res, A02res, A30res, A21res, A12res
    real(RK)                  :: Psi001res, Psi002res, Psi100res, Psi200res, Psi020res, Psi101res, Psi010res, Psi110res, Psi011res
    real(RK)                  :: CV, BetaT, GammaV, Totalmu, CP, AlphaP
    real(RK)                  :: Z01, Z10, Z11, Z02, Z20, V, V2, H, H2, HV
    real(RK)                  :: specv, specv2, Beta, Beta2, Beta3, InvBeta, InvBeta2, Numb, Numb2, Numb3, NU, N2U, NU2, NdUdV, U, U2, U3, dUdV, UdUdV, dUdV2, U2dUdV, UdUdV2, d2UdV2, Ud2UdV2, InvVol
    real(RK)                  :: currentHmU, currentHmUm1, currentH
    real(RK)                  :: O10, O01, O20, O11, O02, O30, O21, O12, O40, O31, O22, O00
    real(RK)                  :: S10, S01, S20, S11, S02, S30, S21, S12
    real(RK)                  :: O00m1, O00m2, O00m3, O012, O20m1, S20m1, S20m2, S20m3
    real(RK)                  :: HmUmpV, HmUmpVInv, HmUmpVInvV, HmUmpVInvV2
    real(RK)                  :: F, invF, funcF, rho, rho2, HmU, HmUm1, HmUm2, HmUm3, HmUm1dUdV, HmUm1dUdV2, HmUm1d2UdV2, HmUm2dUdV, HmUm2dUdV2, HmUm2d2UdV2, HmUm3dUdV, HmUm3dUdV2
    real(RK)                  :: LmUpmuN, RmUmpVpmuN, O000, O200, O010, O020, O001, O002, O101, O110, O011
    real(RK)                  :: dTdL, dTdV, dTdmu, dpdL, dpdV, dpdmu, dNdL, dNdV, dNdmu
    real(RK)                  :: dTdR, dTdp, dVdR, dVdp, dVdmu, dNdR, dNdp
    real(RK)                  :: Zero, Xi100, Xi200, Xi010, Xi020, Xi001, Xi002, Xi110, Xi101, Xi011

    real(RK)                  :: a1, a2 ! dummy arguments
#if MPI_VER > 0
    real(RK)                  :: auxEPot !ThermoInt with mpiMCCommonGroups
#endif
    ! Sampling of Dielectric Constant
    real(RK)                  :: MX, MY, MZ
    integer                   :: kIndex, lIndex
    type(TMolecule), pointer  :: pm
    type(TSiteCharge), pointer:: pCharge
    real(RK)                  :: varmu( this%NComponents )

#if HBOND > 0
    integer                   :: k, l, m
#endif

    !DC NOTE this prevent update of data on stopped simulations
    if (this%isStopSimulation .eqv. .true.) then
      return
    endif

#if MPI_VER > 0
    if (SimulationType .eq. MonteCarlo .and. fields .eq. 0) then
       headers = headers + 1
       fields = fields + 7
       ! Sampling of Dielectric Constant
       if( (this%NChargeMax > 0).or.(this%NDipoleMax > 0) ) then
       fields = fields + 3
       end if
       do i = 1, this%NRealComponents
         if( this%Component(i)%ChemPotMethod .ne. ChemPotMethodNone ) then
           fields = fields + 1
           if( (EnsembleType .eq. EnsembleTypeNPT) .or. (EnsembleType .eq. EnsembleTypeNPTSVC) ) then
             fields = fields + 1
             if( this%Component(i)%ChemPotMethod .ne. ChemPotMethodNone ) fields = fields + 1
           end if
         end if
         if( EnsembleType .eq. EnsembleTypeGE ) then
           fields = fields + 1
         endif
       enddo
       if( OpenSystem .or. EnsembleType .eq. EnsembleTypeHA .or. SimulationType .eq. Gibbs) then
          fields = fields + this%NComponents + 1
       end if
    end if
#endif

    !
    if( Step == 1 ) then
      ! Reset accumulators
      ! 1.) Basic sums
      call Reset( this%SumPressure )
      call Reset( this%SumDensity )
      call Reset( this%SumTemperature )
      call Reset( this%SumEPot )
      call Reset( this%SumEPotDeltaSquared )
      call Reset( this%SumEnthalpy )
      call Reset( this%SumConfEnthalpy )
      call Reset( this%SumVolume )
      call Reset( this%SumVirial )
      call Reset( this%SumVirialDeltaSquared )
      call Reset( this%SumdEpotdV )
      call Reset( this%Sumd2EpotdV2 )
#if OSMOP > 0
      call Reset( this%SumOsmoticPressure )
      do i = 1, this%NComponents
        do j = 1, NBinsDen
          call Reset( this%Component(i)%SumDenProfile(j) )
#if OSMOP == 2
          if( this%Component(i)%ChemPotMethod .eq. ChemPotMethodWidom ) then
            call Reset( this%Component(i)%SumChemPotProfile(j) )
          end if
#endif
        end do
      end do
#if OSMOP == 2
      do j = 1, NBinsDen
        call Reset( this%SumPressureProfile(j) )
      end do
#endif
#endif

#if HBOND > 0
      do i = 1, this%NComponents
        call Reset( this%SumHBond0(i) )
        do j = 1, this%NComponents
          call Reset( this%SumHBond1(i,j) )
          do k = j, this%NComponents
            call Reset( this%SumHBond2(i,j,k) )
            do l = k, this%NComponents
              call Reset( this%SumHBond3(i,j,k,l) )
              do m = l, this%NComponents
                call Reset( this%SumHBond4(i,j,k,l,m) )
              end do
            end do
          end do
        end do
        call Reset( this%SumHBondN(i) )
      end do
#endif

      if( OpenSystem .or. EnsembleType .eq. EnsembleTypeHA .or. SimulationType .eq. Gibbs) then
        call Reset( this%SumNPart )
        call Reset( this%SumP100 )
        call Reset( this%SumP200 )
        call Reset( this%SumP020 )
        call Reset( this%SumP001 )
        call Reset( this%SumP002 )
        call Reset( this%SumP101 )
        call Reset( this%SumP010 )
        call Reset( this%SumP110 )
        call Reset( this%SumP011 )
        if( EnsembleType .eq. EnsembleTypeGE .or. EnsembleType .eq. EnsembleTypeMUVT ) then
          call Reset( this%SumNPart2 )
          call Reset( this%SumNPart3 )
          call Reset( this%SumEPotTot )
          call Reset( this%SumdEPotdVTot )
          call Reset( this%SumdEPotdV2Tot )
          call Reset( this%SumUdEPotdVTot )
          call Reset( this%Sumd2EPotdV2Tot )
          call Reset( this%SumEPot2Tot )
          call Reset( this%SumNPartEPot )
          call Reset( this%SumNPartEPot2 )
          call Reset( this%SumNPart2EPot )
          call Reset( this%SumNPartdEpotdV )
          call Reset( this%SumCVsm )
          call Reset( this%SumCPsm )
          call Reset( this%SumGammaVsm )
          call Reset( this%SumBetaTsm )
          call Reset( this%SumAlphaPsm )
        else if( EnsembleType .eq. EnsembleTypeMUVL ) then
          call Reset( this%SumOmega000 )
          call Reset( this%SumOmega200 )
          call Reset( this%SumOmega010 )
          call Reset( this%SumdEPotdVTot )
          call Reset( this%SumOmega0201 )
          call Reset( this%Sumd2EPotdV2Tot )
          call Reset( this%SumOmega0202 )
          call Reset( this%Sum2NVdUdV )
          call Reset( this%SumOmega002 )
          call Reset( this%SumOmega101 )
          call Reset( this%SumOmega110 )
          call Reset( this%SumOmega011 )
          call Reset( this%SumNPartV )
          call Reset( this%SumNPart2V )
          call Reset( this%SumCVsm )
          call Reset( this%SumCPsm )
          call Reset( this%SumGammaVsm )
          call Reset( this%SumBetaTsm )
          call Reset( this%SumAlphaPsm )
        else if( EnsembleType .eq. EnsembleTypeMUPR ) then
          call Reset( this%SumOmega000 )
          call Reset( this%SumOmega200 )
          call Reset( this%SumOmega010 )
          call Reset( this%SumOmega020 )
          call Reset( this%SumOmega002 )
          call Reset( this%SumOmega101 )
          call Reset( this%SumOmega110 )
          call Reset( this%SumOmega011 )
          call Reset( this%SumCVsm )
          call Reset( this%SumCPsm )
          call Reset( this%SumGammaVsm )
          call Reset( this%SumBetaTsm )
          call Reset( this%SumAlphaPsm )
        else if( EnsembleType .eq. EnsembleTypeMUPT ) then
          call Reset( this%SumNPart2 )
          call Reset( this%SumZero )
          call Reset( this%SumZeroN )
          call Reset( this%SumZeroV )
          call Reset( this%SumZero2 )
          call Reset( this%SumVext )
          call Reset( this%SumVext2 )
          call Reset( this%SumN2pN )
          call Reset( this%SumNVmV )
          call Reset( this%SumNmN2 )
          call Reset( this%SumNV )
          call Reset( this%SumCVsm )
          call Reset( this%SumCPsm )
          call Reset( this%SumGammaVsm )
          call Reset( this%SumBetaTsm )
          call Reset( this%SumAlphaPsm )
        end if
        do i = 1, this%NComponents
          call Reset( this%Component(i)%SumFraction )
        end do
      end if

      ! Calculation of residence times
      if ( this%ResidenceTime ) then
        call Reset( this%SumResidenceDuration )
        call Reset( this%SumResidencePairs )
      end if

      ! 2.) Combined sums
      call Reset( this%SumEPotSquared )
      call Reset( this%SumEPotV )
      call Reset( this%SumEPotVirial )
      call Reset( this%SumEPotDeltaVirialDelta )
      call Reset( this%SumEnthalpySquared )
      call Reset( this%SumEnthalpyV )
      call Reset( this%SumVolumeSquared )
      call Reset( this%SumEPotCubic )
      call Reset( this%SumdEpotdVSquared )
      call Reset( this%SumEPotdEpotdV )
      call Reset( this%SumEPotSquareddEpotdV )
      call Reset( this%SumEPotdEpotdVSquared )
      call Reset( this%SumEPotd2EpotdV2 )
      if( EnsembleType .eq. EnsembleTypeNVE .and. LongRange .eq. Rfield) then
        call Reset( this%SumHmU )
        call Reset( this%SumHmUm1)
        call Reset( this%SumHmUm2 )
        call Reset( this%SumHmUm3 )
        call Reset( this%SumHmUm1dUdV )
        call Reset( this%SumHmUm1dUdV2 )
        call Reset( this%SumHmUm1d2UdV2 )
        call Reset( this%SumHmUm2dUdV )
        call Reset( this%SumHmUm2dUdV2 )
        call Reset( this%SumHmUm2d2UdV2 )
        call Reset( this%SumHmUm3dUdV )
        call Reset( this%SumHmUm3dUdV2 )
      end if

      ! 3.) Derived sums
      if( ConstantPressure ) then
        call Reset( this%SumBetaT )
        call Reset( this%SumdHdP )
        call Reset( this%SumCP )
        call Reset( this%SumAlphaP )
      else
        call Reset( this%SumdUdV )
        call Reset( this%SumCV )
        call Reset( this%SumCorCoefR )
      endif
      if( LongRange .eq. Rfield) then
        call Reset( this%SumCVsm )
        call Reset( this%SumCPsm )
        call Reset( this%SumGammaVsm )
        call Reset( this%SumBetaTsm )
        call Reset( this%SumAlphaPsm )
        if ( EnsembleType .eq. EnsembleTypeNVT ) then
          call Reset( this%SumA10resI )
          call Reset( this%SumA01resI )
          call Reset( this%SumA20resI )
          call Reset( this%SumA11resI )
          call Reset( this%SumA02resI )
          call Reset( this%SumA30resI )
          call Reset( this%SumA21resI )
          call Reset( this%SumA12resI )
        elseif ( EnsembleType .eq. EnsembleTypeNVE ) then
          call Reset( this%SumA10resI )
          call Reset( this%SumA01resI )
          call Reset( this%SumA20resI )
          call Reset( this%SumA11resI )
          call Reset( this%SumA02resI )
          call Reset( this%SumA30resI )
          call Reset( this%SumA21resI )
          call Reset( this%SumA12resI )
          call Reset( this%SumA10resII )
          call Reset( this%SumA01resII )
          call Reset( this%SumA20resII )
          call Reset( this%SumA11resII )
          call Reset( this%SumA02resII )
          call Reset( this%SumA30resII )
          call Reset( this%SumA21resII )
          call Reset( this%SumA12resII )
        elseif ( EnsembleType .eq. EnsembleTypeNPT ) then
          call Reset( this%SumConfEnthalpyTot )
          call Reset( this%SumConfEnthalpy2 )
          call Reset( this%SumConfEnthalpyV )
          call Reset( this%SumG10 )
          call Reset( this%SumG01 )
          call Reset( this%SumG11 )
          call Reset( this%SumG02 )
          call Reset( this%SumG20 )
        elseif ( EnsembleType .eq. EnsembleTypeNPH ) then
          call Reset( this%SumHmUmpV )
          call Reset( this%SumHmUmpVInv )
          call Reset( this%SumHmUmpVInvV )
          call Reset( this%SumHmUmpVInvV2 )
          call Reset( this%SumS10 )
          call Reset( this%SumS01 )
          call Reset( this%SumS11 )
          call Reset( this%SumS02 )
          call Reset( this%SumS20 )
        end if
      end if

      ! 4.) Chemical potential and partial molar volumes
      do i = 1, this%NRealComponents
        select case( this%Component(i)%ChemPotMethod )
        case( ChemPotMethodGradIns )
          call Reset( this%Component(i)%SumInvChemPotRho )
          call Reset( this%Component(i)%SumInvChemPot )
        case( ChemPotMethodWidom )
          call Reset( this%Component(i)%SumChemPotV )
          call Reset( this%Component(i)%SumChemPotVV )
          call Reset( this%Component(i)%SumHW_counter )
          call Reset( this%Component(i)%SumHW_denom )
        case( ChemPotMethodThermoInt )
          call Reset( this%Component(i)%SumChemPotV )
          call Reset( this%Component(i)%SumChemPotVV )
          call Reset( this%Component(i)%SumChemPotThermoIntWidom )
          call Reset( this%Component(i)%SumChemPotThermoIntWidomV )
          call Reset( this%Component(i)%SumHW_counter )
          call Reset( this%Component(i)%SumHW_denom )
        end select
        if (EnsembleType .eq. EnsembleTypeGE) then
          call Reset( this%Component(i)%SumChemPotGE )
        endif
      end do

      ! 5.) Sampling of Dielectric Constant
        call Reset( this%SumTotalDipoleMoment )
        call Reset( this%SumTotalDipoleMomentSquared )
        call Reset( this%SumDielectricConstant )

        do i = 1, this%NRealComponents
          if( this%Component(i)%ChemPotMethod .ne. ChemPotMethodNone ) then
            call Reset( this%Component(i)%SumVW )
            call Reset( this%Component(i)%SumHM )
          end if
        end do

      ! Update result header
#if MPI_VER > 0
      if (SimulationType .eq. MonteCarlo) then ! parallel MC
         ! wait for RootProc_W to write header, in MC Communicator=MPI_COMM_WORLD for standard MC and MC with CommonEqui
         ! so RootProc=RootProc_W, but in MC with mpiMCCommonGroups>0, Communicator is split into mpiMCCommonGroups with each
         ! group has its own RootProc, so only RootProc_W writes header, thus MPI_Barrier is done for MPI_COMM_WORLD to wait for
         ! all processes
         ! RootProc_W is writing header
         call MPI_Barrier(MPI_COMM_WORLD, ierror)
         call MPI_File_seek(this%resultFile%MPIhandle, offset, MPI_SEEK_END, ierr)
         call MPI_File_seek(this%runaveFile%MPIhandle, offset, MPI_SEEK_END, ierr)
         if (RootProc_W) then

           call writeRunRavHeader(this)

         endif
         ! wait for RootProc_W to write header
         call MPI_Barrier(MPI_COMM_WORLD, ierror)

      else ! not parallel MC
#endif

         call writeRunRavHeader(this)

#if MPI_VER > 0
      end if
#endif

    endif
!!!!!!!!!!!!!!!!!!!!!!!!!!!
! END IF of step ==1
!!!!!!!!!!!!!!!!!!!!!!!!!!!

    ! Update accumulators
    ! 1.) Basic sums
    call Update( this%SumPressure, this%Pressure )
    call Update( this%SumDensity, this%Density )
    call Update( this%SumTemperature, this%Temperature )
    call Update( this%SumEPot, this%EPot / real( this%NPart, RK ) )
    if( ConstantPressure ) then
      call Update( this%SumEnthalpy, this%EPot / real( this%NPart, RK ) + this%RefPressure / this%Density - this%RefTemperature )
      call Update( this%SumConfEnthalpy, this%EPot / real( this%NPart, RK ) + this%RefPressure / this%Density )
    else
      call Update( this%SumEnthalpy, this%EPot / real( this%NPart, RK ) + this%Pressure / this%Density - this%RefTemperature )
      call Update( this%SumConfEnthalpy, this%EPot / real( this%NPart, RK ) + this%Pressure / this%Density )
    end if

    call Update( this%SumVolume, 1._RK / this%Density )
    call Update( this%SumVirial, -3._RK * this%Virial )
    call Update( this%SumEPotDeltaVirialDelta, (this%EPot/real( this%NPart, RK ) - this%SumEPot%Average)*((-3_RK*this%Virial) - this%SumVirial%Average) )
    call Update( this%SumEPotDeltaSquared, (this%EPot/real( this%NPart, RK ) - this%SumEPot%Average)**2 )
    call Update( this%SumVirialDeltaSquared, ((-3_RK*this%Virial) - this%SumVirial%Average)**2 )
#if OSMOP > 0
    call Update( this%SumOsmoticPressure, this%OsmoticPressure )
    do i = 1, this%NComponents
      do j = 1, NBinsDen
        call Update( this%Component(i)%SumDenProfile(j), real(this%Component(i)%DensityProfileN(j),RK)*NBinsDen/this%Volume0)
#if OSMOP == 2
        if( this%Component(i)%ChemPotMethod .eq. ChemPotMethodWidom ) then
          call Update( this%Component(i)%SumChemPotProfile(j), this%Component(i)%ChemPotProfile(j))
        end if
#endif
      end do
    end do
#if OSMOP == 2
    do j = 1, NBinsDen
      call Update( this%SumPressureProfile(j), this%PressureProfile(j))
    end do
#endif
#endif

#if HBOND > 0
    do i = 1, this%NComponents
      call Update( this%SumHBond0(i), real(this%NHBond0(i),RK) )
      do j = 1, this%NComponents
        call Update( this%SumHBond1(i,j), real(this%NHBond1(i,j),RK) )
        do k = j, this%NComponents
          call Update( this%SumHBond2(i,j,k), real(this%NHBond2(i,j,k),RK) )
          do l = k, this%NComponents
            call Update( this%SumHBond3(i,j,k,l), real(this%NHBond3(i,j,k,l),RK) )
            do m = l, this%NComponents
              call Update( this%SumHBond4(i,j,k,l,m), real(this%NHBond4(i,j,k,l,m),RK) )
            end do
          end do
        end do
      end do
      call Update( this%SumHBondN(i), real(this%NHBondN(i),RK) )
    end do
#endif

    currentdEpotdV   = -this%Density*this%Virial/real( this%NPart, RK )
    currentd2EpotdV2 =  this%Density**2*(2._RK*this%Virial/3._RK + this%d2EpotdV2) / (real( this%NPart, RK ))**2
    call Update( this%SumdEpotdV,   currentdEpotdV)
    call Update( this%Sumd2EpotdV2, currentd2EpotdV2)

        ! 2.) Combined sums
    call Update( this%SumEPotSquared,      ( this%EPot / real( this%NPart, RK ) )**2 )
    call Update( this%SumEPotCubic,          this%EPot**3 )
    call Update( this%SumdEpotdVSquared,                    currentdEpotdV**2 )
    call Update( this%SumEPotdEpotdV,        this%EPot    * currentdEpotdV    )
    call Update( this%SumEPotSquareddEpotdV, this%EPot**2 * currentdEpotdV    )
    call Update( this%SumEPotdEpotdVSquared, this%EPot    * currentdEpotdV**2 )
    call Update( this%SumEPotd2EpotdV2,      this%EPot    * currentd2EpotdV2  )

    if( OpenSystem .or. EnsembleType .eq. EnsembleTypeHA .or. SimulationType .eq. Gibbs) then
      call Update( this%SumNPart, real( this%NPart, RK ) )
      if( EnsembleType .eq. EnsembleTypeGE .or. EnsembleType .eq. EnsembleTypeMUVT ) then
        Totalmu = 0
        do i = 1, this%NComponents
          Totalmu = Totalmu + this%Component(i)%Chempot0*this%Component(i)%Fraction
        end do
        call Update( this%SumNPart2, real( this%NPart, RK )**2 )
        call Update( this%SumNPart3, real( this%NPart, RK )**3 )
        call Update( this%SumNPartEPot, real( this%NPart, RK )*this%EPot )
        call Update( this%SumNPart2EPot, (real( this%NPart, RK )**2)*this%EPot )
        call Update( this%SumNPartEPot2, real( this%NPart, RK )*(this%EPot**2) )
        call Update( this%SumNPartdEpotdV, (real( this%NPart, RK )**2)*currentdEpotdV )
        call Update( this%SumEPotTot, this%EPot )
        call Update( this%SumEPot2Tot, this%EPot**2 )
        call Update( this%SumdEPotdVTot, -this%Density*this%Virial )
        call Update( this%SumdEPotdV2Tot, (this%Density*this%Virial)**2 )
        call Update( this%SumUdEPotdVTot, -this%EPot*this%Density*this%Virial )
        call Update( this%Sumd2EpotdV2Tot, currentd2EpotdV2*real( this%NPart, RK )**2 )

        Beta    = 1._RK/this%RefTemperature
        Beta2   = Beta*Beta
        Beta3   = Beta*Beta2
        InvBeta = this%RefTemperature
        InvBeta2 = InvBeta*InvBeta
        specv   = 1._RK/this%RefDensity
        InvVol  = this%RefDensity
        Numb    = real( this%SumNPart%Average, RK )
        Numb2   = real( this%SumNPart2%Average, RK )
        Numb3   = real( this%SumNPart3%Average, RK )
        NU      = this%SumNPartEPot%Average
        N2U     = this%SumNPart2EPot%Average
        NU2     = this%SumNPartEPot2%Average
        NdUdV   = this%SumNPartdEpotdV%Average
        U       = this%SumEpotTot%Average
        U2      = this%SumEpot2Tot%Average
        dUdV    = this%SumdEpotdVTot%Average
        dUdV2   = this%SumdEpotdV2Tot%Average
        UdUdV   = this%SumUdEpotdVTot%Average
        d2UdV2  = this%Sumd2EpotdV2Tot%Average

        factor    = Totalmu-1.5*InvBeta
        Psi100res = factor*Numb-U
        Psi200res = factor*factor*Numb2+1.5*InvBeta2*Numb+(3*InvBeta-2*Totalmu)*NU+U2
        Psi001res = Numb*Beta
        Psi002res = Beta2*Numb2
        Psi101res = (Totalmu*beta-1.5)*Numb2+Numb-Beta*NU
        Psi010res = Numb*InvVol-beta*dUdV
        Psi020res = InvVol*( InvVol*( Numb2-Numb )-2*Beta*NdUdV )-Beta*d2UdV2+Beta2*dUdV2
        Psi011res = beta*InvVol*Numb2-Beta2*NdUdV
        Psi110res = factor*InvVol*Numb2-Beta*factor*NdUdV-InvVol*NU-dUdV+Beta*UdUdV

        call Update( this%SumP100, Psi100res )
        call Update( this%SumP010, Psi010res )
        call Update( this%SumP001, Psi001res )
        call Update( this%SumP200, Psi200res-Psi100res**2 )
        call Update( this%SumP020, Psi020res-Psi010res**2 )
        call Update( this%SumP002, Psi002res-Psi001res**2 )
        call Update( this%SumP110, Psi110res-Psi100res*Psi010res )
        call Update( this%SumP101, Psi101res-Psi100res*Psi001res )
        call Update( this%SumP011, Psi011res-Psi010res*Psi001res )

        CV = ( Beta2*this%SumP200%Average - ( (this%SumP001%Average - Beta*this%SumP101%Average)**2 )&
        &           /this%SumP002%Average )/real( this%SumNPart%Average, RK )

        GammaV = ( this%SumP010%Average-Beta*this%SumP110%Average - this%SumP011%Average &
        &              * ( this%SumP001%Average - Beta*this%SumP101%Average )/this%SumP002%Average ) &
        &              / real( this%SumNPart%Average, RK )

        BetaT = -Beta*InvVol*real( this%SumNPart%Average, RK )/( this%SumP020%Average- &
        &                (this%SumP011%Average**2) / this%SumP002%Average )

        CP = CV + specv*InvBeta*BetaT*(GammaV**2)

        call Update( this%SumCVsm, CV )
        call Update( this%SumGammaVsm, GammaV )
        call Update( this%SumBetaTsm, BetaT )
        call Update( this%SumAlphaPsm, BetaT*GammaV )
        call Update( this%SumCPsm, CP )

      else if( EnsembleType .eq. EnsembleTypeMUVL ) then

        Totalmu = 0
        do i = 1, this%NComponents
          Totalmu = Totalmu + this%Component(i)%Chempot0*this%Component(i)%Fraction
        end do

        LmUpmuN = this%RefHill - this%Epot + Totalmu * this%NPart
        InvVol  = this%RefDensity
        dUdV = -this%Density*this%Virial
        specv   = 1._RK/this%RefDensity
        InvBeta = this%RefTemperature

        call Update( this%SumOmega000, 2*LmUpmuN/(3*this%NPart) )
        call Update( this%SumOmega200, (1.5*this%NPart-1)/LmUpmuN )

        call Update( this%SumOmega010, LmUpmuN )
        call Update( this%SumdEPotdVTot, dUdV )
        call Update( this%SumOmega0201, 2*(this%NPart-1)*(InvVol**2)*LmUpmuN/3 )
        call Update( this%Sum2NVdUdV, 2*this%NPart*InvVol*dUdV )
        call Update( this%SumOmega0202, (1.5*this%NPart-1)*(dUdV**2)/LmUpmuN )
        call Update( this%Sumd2EpotdV2Tot, currentd2EpotdV2*real( this%NPart, RK )**2 )

        call Update( this%SumOmega002, (this%NPart**2)*(1.5*this%NPart-1)/LmUpmuN )
        call Update( this%SumOmega101, this%NPart*(1.5*this%NPart-1)/LmUpmuN )
        call Update( this%SumOmega110, (1.5*this%NPart-1)*dUdV/LmUpmuN )
        call Update( this%SumNpartV, this%NPart*InvVol )
        call Update( this%SumOmega011, (1.5*this%NPart-1)*dUdV*this%NPart/LmUpmuN )
        call Update( this%SumNpart2V, (this%NPart**2)*InvVol )


        O000 = this%SumOmega000%Average
        O200 = this%SumOmega200%Average
        O010 = 2*InvVol*this%SumOmega010%Average/3 - this%SumdEPotdVTot%Average
        O020 = this%SumOmega0201%Average - this%Sum2NVdUdV%Average + this%SumOmega0202%Average - this%Sumd2EpotdV2Tot%Average
        O001 = real( this%SumNPart%Average, RK )
        O002 = this%SumOmega002%Average
        O101 = this%SumOmega101%Average
        O110 = this%SumNpartV%Average - this%SumOmega110%Average
        O011 = this%SumNpart2V%Average - this%SumOmega011%Average

        call Update( this%SumP100, 1/O000 )
        call Update( this%SumP200, (O200-1/O000)/O000 )
        call Update( this%SumP010, O010/O000 )
        call Update( this%SumP020, (O020-O010*O010/O000)/O000 )
        call Update( this%SumP001, O001/O000 )
        call Update( this%SumP002, (O002-O001*O001/O000)/O000 )
        call Update( this%SumP110, (O110-O010/O000)/O000 )
        call Update( this%SumP101, (O101-O001/O000)/O000 )
        call Update( this%SumP011, (O011-O010*O001/O000)/O000 ) 
 
        dTdL = 1 - O000*O200
        dTdV = O010 - O000*O110
        dTdmu = O001 - O000*O101
        dpdL = O110 - O010*O200
        dpdV = O020 - O010*O110
        dpdmu = O011 - O010*O101
        dNdL = O101 - O001*O200
        dNdV = O011 - O001*O110
        dNdmu = O002 - O001*O101


        ! CV = (O002-2*O001*O101+O001*O001*O200) / ( O001*((1-O000*O200)*(O002-O001*O101)-(O101-O001*O200)*(O001-O000*O101)) )

        CV = (dNdmu-this%SumNPart%Average*dNdL ) / ( this%SumNPart%Average*( dTdL*dNdmu - dNdL*dTdmu))

        GammaV = ( dpdL*dNdmu - dpdmu*dNdL ) / ( this%SumNPart%Average*( dTdL*dNdmu-dTdmu*dNdL ) )

        BetaT = -this%SumNPart%Average*InvVol / ( dpdV &
&               -dpdL*( dTdV*dNdmu-dTdmu*dNdV ) / ( dTdL*dNdmu-dTdmu*dNdL ) &
&               +dpdmu*( dTdV*dNdL-dTdL*dNdV ) / ( dTdL*dNdmu-dTdmu*dNdL ) )

        CP = CV + specv*InvBeta*BetaT*(GammaV**2)

        call Update( this%SumCVsm, CV )
        call Update( this%SumGammaVsm, GammaV )
        call Update( this%SumBetaTsm, BetaT )
        call Update( this%SumAlphaPsm, BetaT*GammaV )
        call Update( this%SumCPsm, CP )

      else if( EnsembleType .eq. EnsembleTypeMUPR ) then

        Totalmu = 0
        do i = 1, this%NComponents
          Totalmu = Totalmu + this%Component(i)%Chempot0*this%Component(i)%Fraction
        end do

        RmUmpVpmuN = this%RefRay - this%Epot - this%Refpressure * this%Volume0 + Totalmu * this%NPart
        specv   = 1._RK/this%RefDensity

        call Update( this%SumOmega000, 2*RmUmpVpmuN/(3*this%NPart) )
        call Update( this%SumOmega200, (1.5*this%NPart-1)/RmUmpVpmuN )

        call Update( this%SumOmega010, this%Volume0 )
        call Update( this%SumOmega020, (1.5*this%NPart-1)*(this%Volume0**2)/RmUmpVpmuN )

        call Update( this%SumOmega002, (this%NPart**2)*(1.5*this%NPart-1)/RmUmpVpmuN )

        call Update( this%SumOmega101, this%NPart*(1.5*this%NPart-1)/RmUmpVpmuN )
        call Update( this%SumOmega110, (1.5*this%NPart-1)*this%Volume0/RmUmpVpmuN )
        call Update( this%SumOmega011, (1.5*this%NPart-1)*this%Volume0*this%NPart/RmUmpVpmuN )

        O000 = this%SumOmega000%Average
        O200 = this%SumOmega200%Average
        O010 = -this%SumOmega010%Average
        O020 = this%SumOmega020%Average
        O001 = real( this%SumNPart%Average, RK )
        O002 = this%SumOmega002%Average
        O101 = this%SumOmega101%Average
        O110 = -this%SumOmega110%Average
        O011 = -this%SumOmega011%Average

        call Update( this%SumP100, 1/O000 )
        call Update( this%SumP200, (O200-1/O000)/O000 )
        call Update( this%SumP010, O010/O000 )
        call Update( this%SumP020, (O020-O010*O010/O000)/O000 )
        call Update( this%SumP001, O001/O000 )
        call Update( this%SumP002, (O002-O001*O001/O000)/O000 )
        call Update( this%SumP110, (O110-O010/O000)/O000 )
        call Update( this%SumP101, (O101-O001/O000)/O000 )
        call Update( this%SumP011, (O011-O010*O001/O000)/O000 ) 

        dTdR = 1 - O000*O200
        dTdp = O010 - O000*O110
        dTdmu = O001 - O000*O101
        dVdR = O110 - O010*O200
        dVdp = O020 - O010*O110
        dVdmu = O011 - O010*O101
        dNdR = O101 - O001*O200
        dNdp = O011 - O001*O110
        dNdmu = O002 - O001*O101

        CP = (dNdmu - this%SumNPart%Average*dNdR ) / ( this%SumNPart%Average*( dTdR*dNdmu-dTdmu*dNdR) )

        AlphaP = ( dVdR*dNdmu-dVdmu*dNdR ) / ( O010*( dTdR*dNdmu-dTdmu*dNdR ) )

        BetaT = -( dVdp - ( dVdR*(dTdp*dNdmu-dTdmu*dNdp)+dVdmu*(dTdR*dNdp-dTdp*dNdR) ) &
        &         / (dTdR*dNdmu-dTdmu*dNdR) ) / O010

        CV = CP - specv*this%RefTemperature*BetaT*(AlphaP/BetaT)**2

        call Update( this%SumCVsm, CV )
        call Update( this%SumGammaVsm, AlphaP/BetaT )
        call Update( this%SumBetaTsm, BetaT )
        call Update( this%SumAlphaPsm, AlphaP )
        call Update( this%SumCPsm, CP )

      else if( EnsembleType .eq. EnsembleTypeMUPT ) then

        Totalmu = 0
        do i = 1, this%NComponents
          Totalmu = Totalmu + this%Component(i)%Chempot0*this%Component(i)%Fraction
        end do

        Zero = this%Epot + this%Refpressure * this%Volume0 - Totalmu * this%NPart
        Beta    = 1._RK/this%RefTemperature
        Beta2   = Beta*Beta
        InvBeta = this%RefTemperature
        InvBeta2 = InvBeta*InvBeta
        specv   = 1._RK/this%RefDensity

        call Update( this%SumNPart2, real( this%NPart, RK )**2 )
        call Update( this%SumZero, Zero )
        call Update( this%SumZeroN, Zero*this%NPart )
        call Update( this%SumZeroV, Zero*this%Volume0 )
        call Update( this%SumZero2, Zero**2 )
        call Update( this%SumVext, this%Volume0 )
        call Update( this%SumVext2, this%Volume0**2 )
        call Update( this%SumN2pN, real( 1.5*this%NPart*(1.5*this%NPart+1), RK) )
        call Update( this%SumNVmV, (1.5*this%NPart-1)*this%Volume0 )
        call Update( this%SumNmN2, real((1-1.5*this%NPart)*this%NPart, RK) )
        call Update( this%SumNV, this%NPart*this%Volume0 )

        Xi100 = -1.5*InvBeta*this%SumNPart%Average - this%SumZero%Average
        Xi200 = InvBeta2*this%SumN2pN%Average + 3*InvBeta*this%SumZeroN%Average + this%SumZero2%Average
        Xi010 = -Beta*this%SumVext%Average
        Xi020 = Beta2*this%SumVext2%Average
        Xi001 = Beta*this%SumNPart%Average
        Xi002 = Beta2*this%SumNPart2%Average
        Xi110 = this%SumNVmV%Average + Beta*this%SumZeroV%Average
        Xi101 = this%SumNmN2%Average - Beta*this%SumZeroN%Average
        Xi011 = -Beta2*this%SumNV%Average

        call Update( this%SumP100, Xi100 )
        call Update( this%SumP200, Xi200-Xi100*Xi100 )
        call Update( this%SumP010, Xi010 )
        call Update( this%SumP020, Xi020-Xi010*Xi010 )
        call Update( this%SumP001, Xi001 )
        call Update( this%SumP002, Xi002-Xi001*Xi001 )
        call Update( this%SumP110, Xi110-Xi100*Xi010 )
        call Update( this%SumP101, Xi101-Xi100*Xi001 )
        call Update( this%SumP011, Xi011-Xi001*Xi010 ) 

        CP = (Beta2*(Xi200-Xi100**2) - ((Xi001-Beta*(Xi101-Xi100*Xi001))**2) / (Xi002-Xi001**2)) / this%SumNPart%Average

        AlphaP = Beta/Xi010 * ( Xi010-Beta*(Xi110-Xi100*Xi010) - (Xi011-Xi010*Xi001) * (Xi001-Beta*(Xi101-Xi100*Xi001)) / (Xi002-Xi001**2) )

        BetaT = -( Xi020-Xi010**2 - ( (Xi011-Xi010*Xi001)**2 ) / (Xi002-Xi001**2) ) / Xi010

        CV = CP - specv*this%RefTemperature*BetaT*(AlphaP/BetaT)**2

        call Update( this%SumCVsm, CV )
        call Update( this%SumGammaVsm, AlphaP/BetaT )
        call Update( this%SumBetaTsm, BetaT )
        call Update( this%SumAlphaPsm, AlphaP )
        call Update( this%SumCPsm, CP )

      end if

      do i = 1, this%NComponents
        pc => this%Component(i)
        call Update( pc%SumFraction, pc%Fraction )
      end do
    end if

    ! ! 2.) Combined sums
    ! call Update( this%SumEPotSquared,      ( this%EPot / real( this%NPart, RK ) )**2 )
    ! call Update( this%SumEPotCubic,          this%EPot**3 )
    ! call Update( this%SumdEpotdVSquared,                    currentdEpotdV**2 )
    ! call Update( this%SumEPotdEpotdV,        this%EPot    * currentdEpotdV    )
    ! call Update( this%SumEPotSquareddEpotdV, this%EPot**2 * currentdEpotdV    )
    ! call Update( this%SumEPotdEpotdVSquared, this%EPot    * currentdEpotdV**2 )
    ! call Update( this%SumEPotd2EpotdV2,      this%EPot    * currentd2EpotdV2  )

    if( EnsembleType .eq. EnsembleTypeNVE .and. LongRange .eq. Rfield ) then
      !Following part differs from J.Chem.Phys.100(4)1994 for NVEMom MD,
      !the results are identical with and without complete implementation

      currentHmU = (this%RefHamiltonian*real( this%NPart, RK ) - this%EPot)

      currentHmUm1 = 1._RK/currentHmU
      call Update( this%SumHmU,            currentHmU )
      call Update( this%SumHmUm1,          currentHmUm1 )
      call Update( this%SumHmUm2,          currentHmUm1**2 )
      call Update( this%SumHmUm3,          currentHmUm1**3 )
      call Update( this%SumHmUm1dUdV,      currentHmUm1     * currentdEpotdV    )
      call Update( this%SumHmUm1dUdV2,     currentHmUm1     * currentdEpotdV**2 )
      call Update( this%SumHmUm1d2UdV2,    currentHmUm1     * currentd2EpotdV2  )
      call Update( this%SumHmUm2dUdV,      currentHmUm1**2  * currentdEpotdV    )
      call Update( this%SumHmUm2dUdV2,     currentHmUm1**2  * currentdEpotdV**2 )
      call Update( this%SumHmUm2d2UdV2,    currentHmUm1**2  * currentd2EpotdV2  )
      call Update( this%SumHmUm3dUdV,      currentHmUm1**3  * currentdEpotdV    )
      call Update( this%SumHmUm3dUdV2,     currentHmUm1**3  * currentdEpotdV**2 )
    endif

    call Update( this%SumEPotV, this%EPot / ( real( this%NPart, RK ) * this%Density ) )

    call Update( this%SumEPotVirial, -3. * this%Virial * this%EPot / real( this%NPart, RK ) )
    if( ConstantPressure ) then
       call Update( this%SumEnthalpySquared, ( this%EPot / real( this%NPart, RK ) + &
&                this%RefPressure / this%Density - this%RefTemperature )**2 )

       call Update( this%SumEnthalpyV, ( this%EPot / real( this%NPart, RK ) + &
&                this%RefPressure / this%Density - this%RefTemperature ) / this%Density )
    else
       call Update( this%SumEnthalpySquared, ( this%EPot / real( this%NPart, RK ) + &
&                this%Pressure / this%Density - this%RefTemperature )**2 )

       call Update( this%SumEnthalpyV, ( this%EPot / real( this%NPart, RK ) + &
&                this%Pressure / this%Density - this%RefTemperature ) / this%Density )
    end if
    call Update( this%SumVolumeSquared, 1._RK / this%Density**2 )

    ! 3.) Derived sums
    if( .not. OpenSystem ) then

      if( ConstantPressure ) then

        call Update( this%SumBetaT, real( this%NPart, RK ) / this%RefTemperature &
  &                * ( this%SumVolumeSquared%Average / this%SumVolume%Average - this%SumVolume%Average ) )

        call Update( this%SumdHdP, this%SumVolume%Average - real( this%NPart, RK ) / this%RefTemperature &
  &                * ( this%SumEPotV%Average - this%SumEPot%Average * this%SumVolume%Average + this%RefPressure &
  &                * ( this%SumVolumeSquared%Average - this%SumVolume%Average**2 ) ) )

        call Update( this%SumCP, real( this%NPart, RK ) / this%RefTemperature**2 &
  &                * ( this%SumEnthalpySquared%Average - this%SumEnthalpy%Average**2 ) )

        call Update( this%SumAlphaP, real( this%NPart, RK ) / this%RefTemperature**2 &
  &                * this%SumDensity%Average * ( this%SumEnthalpyV%Average &
  &                - this%SumEnthalpy%Average * this%SumVolume%Average ) )

      else

        call Update( this%SumdUdV, this%Density / ( 3. * real( this%NPart, RK )) * (this%NPart / this%RefTemperature &
  &                * ( this%SumVirial%Average * this%SumEPot%Average - this%SumEPotVirial%Average )&
  &                + this%SumVirial%Average ) )

        call Update( this%SumCV, real( this%NPart, RK ) / this%RefTemperature**2 &
  &                * ( this%SumEPotSquared%Average - this%SumEPot%Average**2 ) )
        call Update( this%SumCorCoefR, (-1_RK)*this%SumEPotDeltaVirialDelta%Average/sqrt(this%SumVirialDeltaSquared%Average*this%SumEPotDeltaSquared%Average) )
      endif
    endif

    if( EnsembleType .eq. EnsembleTypeNVT .and. LongRange .eq. Rfield ) then
      Beta    = 1._RK/this%RefTemperature
      Beta2   = Beta*Beta
      Beta3   = Beta*Beta2
      specv   = 1._RK/this%Density
      specv2  = specv*specv
      Numb    = real( this%NPart, RK )
      U       = this%SumEpot%Average*real( this%NPart, RK )
      U2      = this%SumEpotSquared%Average*real( this%NPart, RK )**2
      U3      = this%SumEpotCubic%Average
      dUdV    = this%SumdEpotdV%Average
      dUdV2   = this%SumdEpotdVSquared%Average
      UdUdV   = this%SumEpotdEpotdV%Average
      U2dUdV  = this%SumEPotSquareddEpotdV%Average
      UdUdV2  = this%SumEPotdEpotdVSquared%Average
      d2UdV2  = this%Sumd2EpotdV2%Average
      Ud2UdV2 = this%SumEPotd2EpotdV2%Average

      A10res =  Beta*U/Numb
      A01res = -Beta*specv*dUdV
      A20res =  Beta2*(U*U-U2)/Numb
      A11res =  specv*(-Beta*dUdV + Beta2*UdUdV - Beta2*U*dUdV)
      A02res =  Numb*specv2*(Beta*d2UdV2 - Beta2*dUdV2 + Beta2*dUdV**2) + 2._RK*specv*Beta*dUdV
      A30res =  Beta3*(U3 -3._RK*U*U2 + 2._RK*U**3)/Numb
      A21res =  specv*( Beta2*( 2._RK*UdUdV - 2._RK*U*dUdV) + Beta3*(U2*dUdV - U2dUdV + 2._RK*U*UdUdV - 2._RK*U**2*dUdV) )
      A12res =  Numb*specv2*Beta3*( UdUdV2 + 2._RK*U*dUdV**2 - U*dUdV2 - 2._RK*UdUdV*dUdV)+&
&               Numb*specv2*Beta2*( 2._RK*dUdV**2 + U*d2UdV2 - 2._RK*dUdV2 - Ud2UdV2)+&
&               Numb*specv2*Beta*d2UdV2+&
&               specv*Beta2*(2._RK*U*dUdV - 2._RK*UdUdV)+&
&               specv*Beta*2._RK*dUdV

      call Update( this%SumA10resI, A10res )
      call Update( this%SumA01resI, A01res )
      call Update( this%SumA20resI, A20res )
      call Update( this%SumA11resI, A11res )
      call Update( this%SumA02resI, A02res )
      call Update( this%SumA30resI, A30res )
      call Update( this%SumA21resI, A21res )
      call Update( this%SumA12resI, A12res )

      CV = -A20res

      CP = - 1._RK - A20res + ((1._RK+A01res-A11res)**2)/ &
&             (1._RK+2._RK*A01res+A02res)

      GammaV = this%Density * (1._RK+A01res-A11res)

      BetaT = 1._RK/(this%Density*this%RefTemperature * (1._RK+2._RK*A01res+A02res))

      call Update( this%SumCVsm, CV + 1.5 )
      call Update( this%SumGammaVsm, GammaV )
      call Update( this%SumBetaTsm, BetaT )
      call Update( this%SumAlphaPsm, BetaT*GammaV )
      call Update( this%SumCPsm, CP + 2.5 )

    end if

    if( EnsembleType .eq. EnsembleTypeNVE .and. LongRange .eq. Rfield) then
      specv       = 1._RK/this%Density
      specv2      = specv*specv
      Numb        = real( this%NPart, RK )
      rho         = this%Density
      rho2        = rho*rho
      !Following was part was commented, even if J.Chem.Phys.100(4)1994 prescribes it for NVEMom MD, because it deteriorates the results considerably.
      !if( SimulationType .eq. MolecularDynamics ) then
      ! F = (real(this%NDF, RK)- 3._RK)/2._RK
      !else
       F = real(this%NDF, RK)/2._RK
      !endif
      invF        = 2._RK/real(this%NDF, RK)
      dUdV        = this%SumdEpotdV%Average
      dUdV2       = this%SumdEpotdVSquared%Average
      d2UdV2      = this%Sumd2EpotdV2%Average
      HmU         =this%SumHmU%Average
      HmUm1       =this%SumHmUm1%Average
      HmUm2       =this%SumHmUm2%Average
      HmUm3       =this%SumHmUm3%Average
      HmUm1dUdV   =this%SumHmUm1dUdV%Average
      HmUm1dUdV2  =this%SumHmUm1dUdV2%Average
      HmUm1d2UdV2 =this%SumHmUm1d2UdV2%Average
      HmUm2dUdV   =this%SumHmUm2dUdV%Average
      HmUm2dUdV2  =this%SumHmUm2dUdV2%Average
      HmUm2d2UdV2 =this%SumHmUm2d2UdV2%Average
      HmUm3dUdV   =this%SumHmUm3dUdV%Average
      HmUm3dUdV2  =this%SumHmUm3dUdV2%Average

      O00 = HmU*invF
      O10 = 1._RK
      O01 = rho*HmU*invF - dUdV
      O20 = (F-1._RK)*HmUm1
      O11 = rho + (1._RK-F)*HmUm1dUdV
      O02 = rho*rho*(1._RK-1._RK/Numb)*HmU*invF - 2._RK*rho*dUdV - d2UdV2 + (F-1._RK)*HmUm1dUdV2
      O30 = (F*F-3._RK*F+2._RK)*HmUm2
      O21 = rho*(F-1._RK)*HmUm1+(3._RK*F-F*F-2._RK)*HmUm2dUdV
      O12 = rho*(rho*(1._RK-1._RK/Numb) + 2._RK*HmUm1dUdV*(1._RK-F)) + (1._RK-F)*HmUm1d2UdV2 + (2._RK-3._RK*F+F*F)*HmUm2dUdV2
      O40 = (F*F*F-6._RK*F*F+11._RK*F-6._RK)*HmUm3
      O31 = rho*(F*F-3._RK*F+2._RK)*HmUm2 + (6._RK-11._RK*F+6._RK*F*F-F*F*F)*HmUm3dUdV
      O22 = rho*rho*(F-1._RK-F/Numb+1._RK/Numb)*HmUm1 + rho*(6._RK*F-2._RK*F*F-4._RK)*HmUm2dUdV + (3._RK*F-F*F-2._RK)*HmUm2d2UdV2 + (F*F*F-6._RK*F*F+11._RK*F-6._RK)*HmUm3dUdV2

      O00m1 = 1._RK/O00
      O00m2 = O00m1*O00m1
      O00m3 = O00m2*O00m1
      O012  = O01*O01

      !Entropy definition I

      S01 =  O00m1*O01
      S10 =  O00m1
      S02 = -O00m2*O012+O00m1*O02
      S11 = -O00m2*O01 +O00m1*O11
      S20 = -O00m2     +O00m1*O20
      S12 = 2._RK*O00m3*O012-2._RK*O00m2*O01*O11      -O00m2*O02+O00m1*O12
      S21 = 2._RK*O00m3*O01       -O00m2*O01*O20-2._RK*O00m2*O11+O00m1*O21
      S30 = 2._RK*O00m3     -3._RK*O00m2*O20          +O00m1*O30

      S20m1 = 1._RK/S20
      S20m2 = S20m1*S20m1
      S20m3 = S20m2*S20m1

      A01res =  S01
      A10res = -this%RefHamiltonian*Numb
      A02res =  S02-S11*S11*S20m1
      A11res =  S11*S20m1
      A20res = -S20m1
      A12res =  S20m1*(S11*S20m1*(S11*S20m1*S30-2._RK*S21)+S12)
      A21res = -S20m2*(S11*S20m1*S30-S21)
      A30res =  S20m3*S30

      ! Substraction of the ideal part

      Beta    = O00m1
      Beta2   = Beta*Beta
      Beta3   = Beta*Beta2

      A10res =  A10res-(      -F*O00   ) !Beta=O00m1
      A20res =  A20res-(       F*O00**2)
      A30res =  A30res-(-2._RK*F*O00**3)
      A01res =  A01res-  rho
      A02res =  A02res-(-rho2/Numb)

      ! Final conversion

      call Update( this%SumA10resI, -A10res*Beta/Numb )
      call Update( this%SumA01resI,  A01res*specv ) !=-(-V*A01res)/Numb
      call Update( this%SumA20resI, -A20res*Beta2/Numb )
      call Update( this%SumA11resI,  A11res*Beta*specv ) !=-(-V*Beta*A11res)/Numb
      call Update( this%SumA02resI, -(specv2*A02res*Numb + 2._RK*specv*A01res) ) !=-(V^2*A02res+2V*A01res)/Numb
      call Update( this%SumA30resI, -A30res*Beta3/Numb )
      call Update( this%SumA21resI,  A21res*specv*Beta2 ) !=-(-V*Beta2*A21res)/Numb
      call Update( this%SumA12resI, -Beta*(specv2*A12res*Numb + 2._RK*specv*A11res) ) !=-Beta*(V^2*A12res+2V*A11res)/Numb

      CV = -this%SumA20resI%Average

      CP = - 1._RK - this%SumA20resI%Average + ((1._RK+this%SumA01resI%Average-this%SumA11resI%Average)**2)/ &
&             (1._RK+2._RK*this%SumA01resI%Average+this%SumA02resI%Average)

      GammaV = this%Density * (1._RK+this%SumA01resI%Average-this%SumA11resI%Average)

      BetaT = 1._RK/(this%Density*this%RefTemperature * (1._RK+2._RK*this%SumA01resI%Average+this%SumA02resI%Average))

      call Update( this%SumCVsm, CV + 1.5 )
      call Update( this%SumGammaVsm, GammaV )
      call Update( this%SumBetaTsm, BetaT )
      call Update( this%SumAlphaPsm, BetaT*GammaV )
      call Update( this%SumCPsm, CP + 2.5 )

      !Entropy definition II

      S01 =  O11
      S10 =  O20
      S02 = -O11*O11+O12
      S11 = -O11*O20+O21
      S20 = -O20*O20+O30
      S12 = 2._RK*O11*O11*O20-2._RK*O11*O21      -O12*O20+O22
      S21 = 2._RK*O11*O20*O20      -O11*O30-2._RK*O20*O21+O31
      S30 = 2._RK*O20*O20*O20-3._RK*O20*O30      +O40

      S20m1 = 1._RK/S20
      S20m2 = S20m1*S20m1
      S20m3 = S20m2*S20m1

      A01res =  S01
      A10res = -this%RefHamiltonian*Numb
      A02res =  S02-S11*S11*S20m1
      A11res =  S11*S20m1
      A20res = -S20m1
      A12res =  S20m1*(S11*S20m1*(S11*S20m1*S30-2._RK*S21)+S12)
      A21res = -S20m2*(S11*S20m1*S30-S21)
      A30res =  S20m3*S30

      ! Substraction of the ideal part

      O20m1   = 1._RK/O20
      Beta    = O20
      Beta2   = Beta*Beta
      Beta3   = Beta*Beta2

      funcF=(1._RK-invF)

      A10res =  A10res-(      -F* funcF*O20m1    )       !Beta=O20
      A20res =  A20res-(       F*(funcF*O20m1)**2)/funcF
      A30res =  A30res-(-2._RK*F*(funcF*O20m1)**3)/funcF**2
      A01res =  A01res-rho
      A02res =  A02res-(-rho2/Numb)

      ! Final conversion

      call Update( this%SumA10resII, -A10res*Beta/Numb )
      call Update( this%SumA01resII,  A01res*specv ) !=-(-V*A01res)/Numb
      call Update( this%SumA20resII, -A20res*Beta2/Numb )
      call Update( this%SumA11resII,  A11res*Beta*specv ) !=-(-V*Beta*A11res)/Numb
      call Update( this%SumA02resII, -(specv2*A02res*Numb + 2._RK*specv*A01res) ) !=-(V^2*A02res+2V*A01res)/Numb
      call Update( this%SumA30resII, -A30res*Beta3/Numb )
      call Update( this%SumA21resII,  A21res*specv*Beta2 ) !=-(-V*Beta2*A21res)/Numb
      call Update( this%SumA12resII, -Beta*(specv2*A12res*Numb + 2._RK*specv*A11res) ) !=-Beta*(V^2*A12res+2V*A11res)/Numb
    end if

    if( EnsembleType .eq. EnsembleTypeNpT .and. LongRange .eq. Rfield) then

      call Update( this%SumConfEnthalpyTot, ( this%EPot +  real( this%NPart, RK )*this%RefPressure / this%Density) )
      call Update( this%SumConfEnthalpy2, ( this%EPot +  real( this%NPart, RK )*this%RefPressure / this%Density)**2 )
      call Update( this%SumConfEnthalpyV, ( this%EPot +  real( this%NPart, RK )*this%RefPressure / this%Density) / this%Density )

      Beta     = 1._RK/this%RefTemperature
      Beta2    = Beta*Beta
      InvBeta  = this%RefTemperature
      InvBeta2 = InvBeta*InvBeta
      Numb     = real( this%NPart, RK )
      V        = this%SumVolume%Average
      V2       = this%SumVolumeSquared%Average*Numb
      H        = this%SumConfEnthalpyTot%Average
      H2       = this%SumConfEnthalpy2%Average
      HV       = this%SumConfEnthalpyV%Average

      Z01 = -Beta*V
      Z10 = -1.5*InvBeta - H/Numb
      Z11 = (1.5*Numb-1._RK)*V + Beta*HV
      Z02 = Beta2*V2
      Z20 = 1.5*(1.5*Numb+1)*InvBeta2 + 3*InvBeta*H + H2/Numb

      call Update( this%SumG10, Z10 )
      call Update( this%SumG01, Z01 )
      call Update( this%SumG11, Z11 - Z10*Z01*Numb )
      call Update( this%SumG02, Z02 - Z01*Z01*Numb )
      call Update( this%SumG20, Z20 - Z10*Z10*Numb )

      CV =  ( Beta2*this%SumG20%Average - ( (this%SumG01%Average - Beta*this%SumG11%Average)**2 )&
      &           /this%SumG02%Average )

      GammaV = -( Beta*( this%SumG01%Average - Beta*this%SumG11%Average )/this%SumG02%Average )

      CP = Beta2*this%SumG20%Average

      BetaT = -this%SumG02%Average / this%SumG01%Average

      AlphaP = Beta*( this%SumG01%Average - Beta*this%SumG11%Average) / this%SumG01%Average

      call Update( this%SumCVsm, CV )
      call Update( this%SumGammaVsm, GammaV )
      call Update( this%SumBetaTsm, BetaT )
      call Update( this%SumAlphaPsm, AlphaP )
      call Update( this%SumCPsm, CP )

    end if

    if( EnsembleType .eq. EnsembleTypeNPH .and. LongRange .eq. Rfield) then

      HmUmpV =  this%RefEnthalpy*real( this%NPart, RK ) - this%EPot - real( this%NPart, RK )*this%RefPressure / this%Density
      HmUmpVInv =  1._RK / HmUmpV

      call Update( this%SumHmUmpV, HmUmpV )
      call Update( this%SumHmUmpVInv, HmUmpVInv )
      call Update( this%SumHmUmpVInvV, HmUmpVInv / this%Density )
      call Update( this%SumHmUmpVInvV2, HmUmpVInv / (this%Density**2) )

      Beta       = 1._RK/this%RefTemperature
      Beta2      = Beta*Beta
      InvBeta    = this%RefTemperature
      InvBeta2   = InvBeta*InvBeta
      Numb       = real( this%NPart, RK )
      rho        = this%Density
      rho2       = rho*rho
      specv      = 1._RK / this%Density
      F = real(this%NDF, RK)/2._RK
      HmUmpV     = this%SumHmUmpV%Average
      HmUmpVInv  = this%SumHmUmpVInv%Average
      HmUmpVInvV = this%SumHmUmpVInvV%Average*Numb
      HmUmpVInvV2= this%SumHmUmpVInvV2%Average*Numb*Numb
      V          = this%SumVolume%Average*Numb

      O00 = HmUmpV / (1.5_RK*Numb)
      O10 = 1._RK
      O01 = -V
      O20 = (1.5_RK*Numb - 1._RK) * HmUmpVInv
      O02 = (1.5_RK*Numb - 1._RK) * HmUmpVInvV2
      O11 = -(1.5_RK*Numb - 1._RK) * HmUmpVInvV

      O00m1 = 1._RK/O00
      O00m2 = O00m1*O00m1
      O00m3 = O00m2*O00m1
      O012  = O01*O01

      !Entropy definition I
      S10 =  O00m1
      S01 =  O00m1*O01
      S20 = -O00m2     +O00m1*O20
      S02 = -O00m2*O012+O00m1*O02
      S11 = -O00m2*O01 +O00m1*O11

      S20m1 = 1._RK/S20
      S20m2 = S20m1*S20m1

      call Update( this%SumS10, S10 )
      call Update( this%SumS01, S01 )
      call Update( this%SumS11, S11 )
      call Update( this%SumS02, S02 )
      call Update( this%SumS20, S20 )

      CV = ( 1._RK + ( O00*(O11-O20*O01)**2 ) / &
      &    ( (1-O00*O20)*(O11*O01-O02) - (O01-O00*O11)*(O20*O01-O11) ) ) / &
      &    ((1 - O00*O20) * Numb)

      BetaT = O11 - O02/O01 - (O20-O11/O01)*(O01-O00*O11)/(1-O00*O20)

      CP = 1._RK / ((1 - O00*O20) * Numb)

      GammaV = (O11-O20*O01) / ( (1-O00*O20)*(O11*O01-O02) - (O01-O00*O11)*(O20*O01-O11) )

      AlphaP = (O11-O20*O01) / (O01*(1-O00*O20))

      call Update( this%SumCVsm, CV )
      call Update( this%SumGammaVsm, GammaV )
      call Update( this%SumBetaTsm, BetaT )
      call Update( this%SumAlphaPsm, AlphaP )
      call Update( this%SumCPsm, CP )

    end if

#if  TRANS == 1
    ! Tranport properties
    if( mod(Step-1,this%NStepCorr) .eq. 0 ) then

      if( mod( (Step-1)/this%NStepCorr-this%NCorr+1, BlockSizeCF*this%NSpanCF ) == 0 .and. (this%Mmess > 0) ) then
        if ( (TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
          do i = 1, this%NComponents
            call Update( this%Sumself_i(i), this%selfd_i(i), this%Mmess )
          end do
          call Update( this%SumVisco_s, this%visco_s, this%Mmess )
        end if

        if(this%NComponents .gt. 1) then
          do i = 1, this%NComponents
           call Update( this%SumSoret(i), this%soret(i), this%Mmess )
          end do
          if ( (TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
            do i = 1, this%NComponents
              do j = 1, this%NComponents
                call Update( this%SumOnsager(i,j),this%Onsager(i,j), this%Mmess )
              end do
            end do
          end if
        end if

        call Update( this%SumVisco_b, this%visco_b, this%Mmess )
        call Update( this%SumConduct, this%conduct, this%Mmess )
        call Update( this%SumEConduct, this%econduct, this%Mmess )
      end if
    end if
#endif

    t = this%NRealComponents+1  ! pseudo component identifier for ThermoInt (ThermoInt does not function together with GradIns)

    ! 4.) Chemical potential and partial molar volumes
    do i = 1, this%NRealComponents
      pc => this%Component(i)
      if( pc%CalcChemPot ) then
        select case( pc%ChemPotMethod )
        case( ChemPotMethodGradins )
#if MPI_VER > 0
          ! Per Process we calculate GI only for one component
          if (mod(NProc,this%NGradInsComp)/=pc%NGradThis) cycle
!           if (mod(NProc,this%NRealComponents)/=i-1) cycle
#endif
          call Update( pc%SumInvChemPotRho, 1._RK / pc%ChemPot )
          call Update( pc%SumInvChemPot, 1._RK / pc%ChemPot1 )
        case( ChemPotMethodWidom )
          call Update( pc%SumChemPotV, pc%ChemPot / this%Density )
          call Update( pc%SumChemPotVV, pc%ChemPot / this%Density**2 )
          call Update(pc%SumHW_counter, pc%HW_counter)
          call Update(pc%SumHW_denom, pc%HW_denom)
        case( ChemPotMethodThermoInt )
          if( .not. Equilibration ) then
            currentbin=int((this%Component(t)%Lambda-pc%LaMin)/pc%deltaLa)
            pc%BinsVisit(currentbin)=pc%BinsVisit(currentbin)+1

            if( this%NMIEnmMax > 0 ) then
              currentBinsEn = (this%Density * pc%EPotTestCorrMIE + pc%EPotTestCorrRF)*this%Component(t)%Lambda**pc%LambdaExponent
            end if
            if( this%NTT68Max > 0 ) then
              currentBinsEn = (this%Density * pc%EPotTestCorrTT68 + pc%EPotTestCorrRF)*this%Component(t)%Lambda**pc%LambdaExponent
            end if

            if (SimulationType .ne. MolecularDynamics ) then
              call EnergyinRC( this, t, 1, EPot)
#if MPI_VER > 0
              if ( mpiMCCommonGroups > 0 ) then
                call MPI_Allreduce( EPot, auxEPot, 1, MPI_RK, MPI_SUM, Communicator, ierror )
                EPot = auxEPot
              endif
#endif
              currentBinsEn = currentBinsEn + EPot
            else
              do j = 1, this%NRealComponents
                call Force( this%Interaction( t, j ), currentBinsEn, a1, a2, this%BoxLength )
              end do
            end if
            currentH=this%EPot + this%RefPressure * real( this%NPart, RK ) / this%Density
            pc%BinsEn(currentbin)     =  (                  currentBinsEn                                       + (pc%BinsVisit(currentbin)-1)*pc%BinsEn(currentbin)    )/pc%BinsVisit(currentbin)
            pc%BinsdEndLa(currentbin) =  (pc%LambdaExponent*currentBinsEn/this%Component(t)%Lambda              + (pc%BinsVisit(currentbin)-1)*pc%BinsdEndLa(currentbin))/pc%BinsVisit(currentbin)
            pc%BinsdEndLaV(currentbin) = (pc%LambdaExponent*currentBinsEn/this%Component(t)%Lambda/this%Density + (pc%BinsVisit(currentbin)-1)*pc%BinsdEndLaV(currentbin))/pc%BinsVisit(currentbin)
            pc%BinsdEndLaH(currentbin)=(pc%LambdaExponent*currentBinsEn/this%Component(t)%Lambda*currentH     + (pc%BinsVisit(currentbin)-1)*pc%BinsdEndLaH(currentbin))/pc%BinsVisit(currentbin)

            pc%BinsIntdEndLa(0)=pc%BinsdEndLa(0)*pc%deltaLa
            pc%BinsIntVW(0)=(pc%BinsdEndLaV(0)-pc%BinsdEndLa(0)*this%SumVolume%Average)*pc%deltaLa
            pc%BinsIntHW(0)=(pc%BinsdEndLaH(0)-pc%BinsdEndLa(0)*this%SumConfEnthalpy%Average+pc%BinsdEndLa(0)/this%RefTemperature)*pc%deltaLa
            do j = 1, pc%NBins-1
              pc%BinsIntdEndLa(j)=pc%BinsIntdEndLa(j-1)+pc%BinsdEndLa(j)*pc%deltaLa
              pc%BinsIntVW(j)=pc%BinsIntVW(j-1)+(pc%BinsdEndLaV(j)-pc%BinsdEndLa(j)*this%SumVolume%Average)*pc%deltaLa
              pc%BinsIntHW(j)=pc%BinsIntHW(j-1)+(pc%BinsdEndLaH(j)-pc%BinsdEndLa(j)*this%SumConfEnthalpy%Average+pc%BinsdEndLa(j)/this%RefTemperature)*pc%deltaLa
            end do
            call Update( pc%SumChemPotThermoIntWidom,  pc%ExpMinusBetaEnLaMin/this%Density)
            call Update( pc%SumChemPotThermoIntWidomV, pc%ExpMinusBetaEnLaMin/this%Density/this%Density)
            call Update( pc%SumChemPotV, pc%BinsIntdEndLa(pc%NBins-1)/this%Temperature-log(pc%SumChemPotThermoIntWidom%Average/(pc%Fraction+1._RK/real( this%NPart, RK ))))
            call Update(pc%SumHW_counter, pc%HW_counter)
            call Update(pc%SumHW_denom, pc%HW_denom)
            t=t+1
          end if
        end select
      end if
      if (EnsembleType .eq. EnsembleTypeGE) then
          call Update( pc%SumChemPotGE, pc%ChemPot )
      endif
    end do

      do i = 1, this%NRealComponents
        pc => this%Component(i)
        if( pc%CalcChemPot ) then
          select case( pc%ChemPotMethod )
          case( ChemPotMethodGradIns )

#if MPI_VER > 0
          ! Per Process we calculate GI only for one component
          if (mod(NProc,this%NGradInsComp)/=pc%NGradThis) cycle
#endif
          call Update( pc%SumVW, this%NPart * ( this%SumVolume%Average &
&                    - pc%SumInvChemPot%Average / pc%SumInvChemPotRho%Average ) )

          case( ChemPotMethodWidom )
            call Update( pc%SumVW, this%NPart * ( pc%SumChemPotVV%Average / pc%SumChemPotV%Average &
&                      - this%SumVolume%Average ) )
          ! partial molar enthalpy
            call Update( pc%SumHM, pc%SumHW_counter%Average / pc%SumHW_denom%Average &
&                      - this%SumConfEnthalpy%Average*this%NPart  - this%RefTemperature)

          case( ChemPotMethodThermoInt )
            call Update( pc%SumVW, this%NPart * ( pc%SumChemPotThermoIntWidomV%Average / pc%SumChemPotThermoIntWidom%Average &
&                      - this%SumVolume%Average - pc%BinsIntVW(pc%NBins-1)/this%RefTemperature) )
          ! partial molar enthalpy
            call Update( pc%SumHM, pc%BinsIntHW(pc%NBins-1)/this%RefTemperature + pc%SumHW_counter%Average / pc%SumHW_denom%Average &
&                      - this%SumConfEnthalpy%Average*this%NPart  - this%RefTemperature)

          end select
        end if
      end do

    ! 5.) Sampling of Dielectric Constant
    if( (this%NChargeMax > 0).or.(this%NDipoleMax > 0) ) then
        MX = 0._RK
        MY = 0._RK
        MZ = 0._RK
        if( LongRange .eq. Rfield ) then
          do i = 1, this%NComponents
            pc => this%Component(i)
            if (pc%Molecule%NDipole > 0 .and. associated(pc%MueX)) then
              do kIndex = 1, pc%NPart
                  MX=MX+pc%MueX(kIndex)
                  MY=MY+pc%MueY(kIndex)
                  MZ=MZ+pc%MueZ(kIndex)
              end do
            endif
          end do
        else ! Ewald
          do i = 1, this%NComponents
          pc => this%Component(i)
        do kIndex = 1, pc%NPart
        pm => pc%Molecule
          do lIndex = 1, pm%NCharge
            pCharge => pm%SiteCharge(lIndex)
            MX=MX+pCharge%e*(pCharge%RX(kIndex)-pc%P0(kIndex,1))*this%BoxLength
            MY=MY+pCharge%e*(pCharge%RY(kIndex)-pc%P0(kIndex,2))*this%BoxLength
            MZ=MZ+pCharge%e*(pCharge%RZ(kIndex)-pc%P0(kIndex,3))*this%BoxLength
          end do
        end do
          end do
        endif

        this%TotalDipoleMomentSquared=MX**2+MY**2+MZ**2
        this%TotalDipoleMoment=sqrt(this%TotalDipoleMomentSquared)

        call Update( this%SumTotalDipoleMoment, this%TotalDipoleMoment )
        call Update( this%SumTotalDipoleMomentSquared, this%TotalDipoleMomentSquared )

        this%DielectricConstant=(4._RK*Pi*this%TotalDipoleMomentSquared)/(3._RK*this%NPart/this%Density*this%Temperature)+1._RK
        call Update( this%SumDielectricConstant, this%DielectricConstant)
    endif

    ! Update result files
    if( mod( Step, BlockSize ) == 0 ) then
      if(SimulationType .eq. MonteCarlo) then
#if MPI_VER > 0
        call MPI_Barrier(MPI_COMM_WORLD, ierror) ! wait for RootProc_W to write header
        offset=0
        call MPI_File_seek(this%resultFile%MPIhandle, offset, MPI_SEEK_END, ierr)
        call MPI_File_seek(this%runaveFile%MPIhandle, offset, MPI_SEEK_END, ierr)
        call MPI_Barrier(MPI_COMM_WORLD, ierror) ! wait for seeks before writing (and maybe moving END)

        if (Equilibration) then
          if(CommonEqui .or. (mpiMCCommonGroups > 0)) then
            !in case of mpiMCCommonGroups>0, then RootProc is every head of each mpiMCCommonGroup,
            ! in the other cases RootProc=RootProc_W
            if (RootProc) then
              if (mpiMCCommonGroups > 0) then
                offset = (NProc_W/NProcs) * (11 * fields + 1) !offset for each head of each mpiMCCommonGroup
                call MPI_File_Seek((this%resultFile%MPIhandle), offset, MPI_SEEK_CUR, ierr)
                call MPI_File_Seek((this%runaveFile%MPIhandle), offset, MPI_SEEK_CUR, ierr)

                ! PROC
                write( IOBuffer, '(I11)' ) NProc_W
                call FileWriteNoAdvance_parallel(this%resultFile)
                call FileWriteNoAdvance_parallel(this%runaveFile)

                ! Number of steps
                write( IOBuffer, '(I11)' ) ((Step/BlockSize) - 1) &
&                  * (BlockSize * mpiMCCommonGroups) + (NProc_W/NProcs + 1) * BlockSize
                call FileWriteNoAdvance_parallel(this%resultFile)
                call FileWriteNoAdvance_parallel(this%runaveFile)
              else
                ! PROC
                write( IOBuffer, '(I11)' ) NProc
                call FileWriteNoAdvance_parallel(this%resultFile)
                call FileWriteNoAdvance_parallel(this%runaveFile)

                ! Number of steps
                write( IOBuffer, '(I11)' ) Step
                call FileWriteNoAdvance_parallel(this%resultFile)
                call FileWriteNoAdvance_parallel(this%runaveFile)
              endif

              call writeAverages(this%SumPressure, this%resultFile, this%runaveFile, parallelMC=.true.)

              call writeAverages(this%SumDensity, this%resultFile, this%runaveFile, parallelMC=.true.)

              call writeAverages(this%SumTemperature, this%resultFile, this%runaveFile, parallelMC=.true.)

              call writeAverages(this%SumEPot, this%resultFile, this%runaveFile, parallelMC=.true.)

              call writeAverages(this%SumEnthalpy, this%resultFile, this%runaveFile, parallelMC=.true.)

              ! Dielectric Constant
              if( (this%NChargeMax > 0).or.(this%NDipoleMax > 0) ) then

                  call writeAverages(this%SumDielectricConstant, this%resultFile, this%runaveFile, parallelMC=.true.)

                  call writeAverages(this%SumTotalDipoleMoment, this%resultFile, this%runaveFile, parallelMC=.true.)

                  call writeAverages(this%SumTotalDipoleMomentSquared, this%resultFile, this%runaveFile, parallelMC=.true.)

              endif

              ! Chemical potential
              do i = 1, this%NRealComponents
                pc => this%Component(i)
                if( pc%ChemPotMethod .ne. ChemPotMethodNone ) then
                    write( IOBuffer, '(" ",F10.5)' ) 0._RK
                    call FileWriteNoAdvance_parallel(this%resultFile)
                    call FileWriteNoAdvance_parallel(this%runaveFile)
                end if
                if (EnsembleType .eq. EnsembleTypeGE) then
                  write( IOBuffer, '(" ",F10.5)' ) pc%SumChemPotGE%BlockAverage
                  call FileWriteNoAdvance_parallel(this%resultFile)
                  write( IOBuffer, '(" ",F10.5)' ) pc%SumChemPotGE%Average
                  call FileWriteNoAdvance_parallel(this%runaveFile)
                endif
              end do

              ! Partial molar volume
              do i = 1, this%NRealComponents
                pc => this%Component(i)
                if( pc%ChemPotMethod .ne. ChemPotMethodNone .and. ( (EnsembleType .eq. EnsembleTypeNPT) .or. (EnsembleType .eq. EnsembleTypeNPTSVC) )) then
                    write( IOBuffer, '(" ",F10.4)' ) 0._RK
                    call FileWriteNoAdvance_parallel(this%resultFile)
                    call FileWriteNoAdvance_parallel(this%runaveFile)

                end if
              end do

              ! Partial molar enthalphy
              do i = 1, this%NRealComponents
                pc => this%Component(i)
                if( pc%ChemPotMethod .ne. ChemPotMethodNone .and. ( (EnsembleType .eq. EnsembleTypeNPT) .or. (EnsembleType .eq. EnsembleTypeNPTSVC) )) then
                    write( IOBuffer, '(" ",F10.4)' ) 0._RK
                    call FileWriteNoAdvance_parallel(this%resultFile)
                    call FileWriteNoAdvance_parallel(this%runaveFile)
                end if
              end do

              ! Number of particles in ensemble
              if( OpenSystem .or. EnsembleType .eq. EnsembleTypeHA .or. SimulationType .eq. Gibbs) then
                write( IOBuffer, '(" ",F10.2)' ) this%SumNPart%BlockAverage
                call FileWriteNoAdvance_parallel(this%resultFile)
                write( IOBuffer, '(" ",F10.2)' ) this%SumNPart%Average
                call FileWriteNoAdvance_parallel(this%runaveFile)

                ! Mole fraction of each component
                do i = 1, this%NComponents
                  pc => this%Component(i)
                  write( IOBuffer, '(" ",F10.5)' ) pc%SumFraction%BlockAverage
                  call FileWriteNoAdvance_parallel(this%resultFile)
                  write( IOBuffer, '(" ",F10.5)' ) pc%SumFraction%Average
                  call FileWriteNoAdvance_parallel(this%runaveFile)
                end do
              end if

               write( IOBuffer, '(A)' )new_line('a')
               call FileWriteNoAdvance_parallel(this%resultFile)
               call FileWriteNoAdvance_parallel(this%runaveFile)
            endif !RootProc
          else ! No CommonEqui

            offset = NProc * (11 * fields + 1)
            call MPI_File_Seek((this%resultFile%MPIhandle), offset, MPI_SEEK_CUR, ierr)
            call MPI_File_Seek((this%runaveFile%MPIhandle), offset, MPI_SEEK_CUR, ierr)

            ! PROC
            write( IOBuffer, '(I11)' ) NProc
            call FileWriteNoAdvance_parallel(this%resultFile)
            call FileWriteNoAdvance_parallel(this%runaveFile)

            ! Number of steps
            write( IOBuffer, '(I11)' ) ((Step/BlockSize) - 1) * (BlockSize * NProcs)  + (NProc + 1) * BlockSize
            call FileWriteNoAdvance_parallel(this%resultFile)
            call FileWriteNoAdvance_parallel(this%runaveFile)

            call writeAverages(this%SumPressure, this%resultFile, this%runaveFile, parallelMC=.true.)

            call writeAverages(this%SumDensity, this%resultFile, this%runaveFile, parallelMC=.true.)

            call writeAverages(this%SumTemperature, this%resultFile, this%runaveFile, parallelMC=.true.)

            call writeAverages(this%SumEPot, this%resultFile, this%runaveFile, parallelMC=.true.)

            call writeAverages(this%SumEnthalpy, this%resultFile, this%runaveFile, parallelMC=.true.)

            ! Dielectric Constant
            if( (this%NChargeMax > 0).or.(this%NDipoleMax > 0) ) then

                call writeAverages(this%SumDielectricConstant, this%resultFile, this%runaveFile, parallelMC=.true.)

                call writeAverages(this%SumTotalDipoleMoment, this%resultFile, this%runaveFile, parallelMC=.true.)

                call writeAverages(this%SumTotalDipoleMomentSquared, this%resultFile, this%runaveFile, parallelMC=.true.)

            endif

            ! Chemical potential
            do i = 1, this%NRealComponents
              pc => this%Component(i)
              if( pc%ChemPotMethod .ne. ChemPotMethodNone ) then
                  write( IOBuffer, '(" ",F10.5)' ) 0._RK
                  call FileWriteNoAdvance_parallel(this%resultFile)
                  call FileWriteNoAdvance_parallel(this%runaveFile)
              end if
              if (EnsembleType .eq. EnsembleTypeGE) then
                  write( IOBuffer, '(" ",F10.5)' ) pc%SumChemPotGE%BlockAverage
                  call FileWriteNoAdvance_parallel(this%resultFile)
                  write( IOBuffer, '(" ",F10.5)' ) pc%SumChemPotGE%Average
                  call FileWriteNoAdvance_parallel(this%runaveFile)
              endif
            end do

            ! Partial molar volume
            do i = 1, this%NRealComponents
              pc => this%Component(i)
              if( pc%ChemPotMethod .ne. ChemPotMethodNone .and.  ( (EnsembleType .eq. EnsembleTypeNPT) .or. (EnsembleType .eq. EnsembleTypeNPTSVC) ) ) then
                  write( IOBuffer, '(" ",F10.4)' ) 0._RK
                  call FileWriteNoAdvance_parallel(this%resultFile)
                  call FileWriteNoAdvance_parallel(this%runaveFile)
              end if
            end do

            ! Partial molar enthalphy
            do i = 1, this%NRealComponents
              pc => this%Component(i)
              if( pc%ChemPotMethod .ne. ChemPotMethodNone .and. ( (EnsembleType .eq. EnsembleTypeNPT) .or. (EnsembleType .eq. EnsembleTypeNPTSVC) ) ) then
                  write( IOBuffer, '(" ",F10.4)' ) 0._RK
                  call FileWriteNoAdvance_parallel(this%resultFile)
                  call FileWriteNoAdvance_parallel(this%runaveFile)
              end if
            end do

            ! Number of particles in ensemble
            if( OpenSystem .or. EnsembleType .eq. EnsembleTypeHA .or. SimulationType .eq. Gibbs) then
              write( IOBuffer, '(" ",F10.2)' ) this%SumNPart%BlockAverage
              call FileWriteNoAdvance_parallel(this%resultFile)
              write( IOBuffer, '(" ",F10.2)' ) this%SumNPart%Average
              call FileWriteNoAdvance_parallel(this%runaveFile)

              ! Mole fraction of each component
              do i = 1, this%NComponents

                pc => this%Component(i)
                call writeAverages(pc%SumFraction, this%resultFile, this%runaveFile, parallelMC=.true.)

              end do
            end if

            write( IOBuffer, '(A)' )new_line('a')
            call FileWriteNoAdvance_parallel(this%resultFile)
            call FileWriteNoAdvance_parallel(this%runaveFile)
            accumulate_step = accumulate_step + BlockSize

          endif !(CommonEqui or mpiMCCommonGroups>0) else No CommonEqui

        else !production starts

          if (mpiMCCommonGroups > 0) then
            !in case of mpiMCCommonGroups>0, then RootProc is every head of each mpiMCCommonGroup
            if (.not. RootProc) return

            offset = (NProc_W/NProcs) * (11 * fields + 1) !offset for each head of each mpiMCCommonGroup
            call MPI_File_Seek((this%resultFile%MPIhandle), offset, MPI_SEEK_CUR, ierr)
            call MPI_File_Seek((this%runaveFile%MPIhandle), offset, MPI_SEEK_CUR, ierr)

            ! PROC
            write( IOBuffer, '(I11)' ) NProc_W
            call FileWriteNoAdvance_parallel(this%resultFile)
            call FileWriteNoAdvance_parallel(this%runaveFile)

            ! Number of steps
            write( IOBuffer, '(I11)' ) ((Step/BlockSize) - 1) &
&                  * (BlockSize * mpiMCCommonGroups) + (NProc_W/NProcs + 1) * BlockSize
            call FileWriteNoAdvance_parallel(this%resultFile)
            call FileWriteNoAdvance_parallel(this%runaveFile)
          else
            offset = NProc * (11 * fields + 1)
            call MPI_File_Seek((this%resultFile%MPIhandle), offset, MPI_SEEK_CUR, ierr)
            call MPI_File_Seek((this%runaveFile%MPIhandle), offset, MPI_SEEK_CUR, ierr)

            ! PROC
            write( IOBuffer, '(I11)' ) NProc
            call FileWriteNoAdvance_parallel(this%resultFile)
            call FileWriteNoAdvance_parallel(this%runaveFile)

            ! Number of steps
            write( IOBuffer, '(I11)' ) ((Step/BlockSize) - 1) * (BlockSize * NProcs)  + (NProc + 1) * BlockSize
            call FileWriteNoAdvance_parallel(this%resultFile)
            call FileWriteNoAdvance_parallel(this%runaveFile)
          endif

          call writeAverages(this%SumPressure, this%resultFile, this%runaveFile, parallelMC=.true.)

          call writeAverages(this%SumDensity, this%resultFile, this%runaveFile, parallelMC=.true.)

          call writeAverages(this%SumTemperature, this%resultFile, this%runaveFile, parallelMC=.true.)

          call writeAverages(this%SumEPot, this%resultFile, this%runaveFile, parallelMC=.true.)

          call writeAverages(this%SumEnthalpy, this%resultFile, this%runaveFile, parallelMC=.true.)

          ! Dielectric Constant
          if( (this%NChargeMax > 0).or.(this%NDipoleMax > 0) ) then

              call writeAverages(this%SumDielectricConstant, this%resultFile, this%runaveFile, parallelMC=.true.)

              call writeAverages(this%SumTotalDipoleMoment, this%resultFile, this%runaveFile, parallelMC=.true.)

              call writeAverages(this%SumTotalDipoleMomentSquared, this%resultFile, this%runaveFile, parallelMC=.true.)

          endif

          ! Chemical potential
          do i = 1, this%NRealComponents
            pc => this%Component(i)
            if( pc%ChemPotMethod .ne. ChemPotMethodNone ) then
                if( pc%NPart > 1 ) then
                  select case( pc%ChemPotMethod )

                  case( ChemPotMethodGradIns )
                    if (mod(NProc,this%NGradInsComp)/=pc%NGradThis) then
                      write( IOBuffer, '(" ",A10)' ) '----------'
                      call FileWriteNoAdvance_parallel(this%resultFile)
                      write( IOBuffer, '(" ",A10)' ) '----------'
                      call FileWriteNoAdvance_parallel(this%runaveFile)
                    else
                      write( IOBuffer, '(" ",F10.5)' ) log( pc%Fraction * pc%SumInvChemPotRho%BlockAverage )
                      call FileWriteNoAdvance_parallel(this%resultFile)
                      write( IOBuffer, '(" ",F10.5)' ) log( pc%Fraction * pc%SumInvChemPotRho%Average )
                      call FileWriteNoAdvance_parallel(this%runaveFile)
                    endif

                  case( ChemPotMethodWidom )
                    write( IOBuffer, '(" ",F10.5)' ) log( pc%Fraction / pc%SumChemPotV%BlockAverage )
                    call FileWriteNoAdvance_parallel(this%resultFile)
                    write( IOBuffer, '(" ",F10.5)' ) log( pc%Fraction / pc%SumChemPotV%Average )
                    call FileWriteNoAdvance_parallel(this%runaveFile)

                  case( ChemPotMethodThermoInt )

                    call writeAverages(pc%SumChemPotV, this%resultFile, this%runaveFile, parallelMC=.true.)

                  end select

                else
                  select case( pc%ChemPotMethod )

                  case( ChemPotMethodGradIns )
                    if (mod(NProc,this%NGradInsComp)/=pc%NGradThis) then
                      write( IOBuffer, '(" ",A10)' ) '----------'
                      call FileWriteNoAdvance_parallel(this%resultFile)
                      write( IOBuffer, '(" ",A10)' ) '----------'
                      call FileWriteNoAdvance_parallel(this%runaveFile)
                    else
                      write( IOBuffer, '(" ",F10.5)' ) log( pc%SumInvChemPotRho%BlockAverage )
                      call FileWriteNoAdvance_parallel(this%resultFile)
                      write( IOBuffer, '(" ",F10.5)' ) log( pc%SumInvChemPotRho%Average )
                      call FileWriteNoAdvance_parallel(this%runaveFile)
                    endif

                  case( ChemPotMethodWidom )
                    write( IOBuffer, '(" ",F10.5)' ) -log( pc%SumChemPotV%BlockAverage )
                    call FileWriteNoAdvance_parallel(this%resultFile)
                    write( IOBuffer, '(" ",F10.5)' ) -log( pc%SumChemPotV%Average )
                    call FileWriteNoAdvance_parallel(this%runaveFile)

                  case( ChemPotMethodThermoInt )

                    call writeAverages(pc%SumChemPotV, this%resultFile, this%runaveFile, parallelMC=.true.)

                  end select
                end if
            end if
            if (EnsembleType .eq. EnsembleTypeGE) then
              write( IOBuffer, '(" ",F10.5)' ) pc%SumChemPotGE%BlockAverage
              call FileWriteNoAdvance_parallel(this%resultFile)
              write( IOBuffer, '(" ",F10.5)' ) pc%SumChemPotGE%Average
              call FileWriteNoAdvance_parallel(this%runaveFile)
            endif
          end do

        ! Partial molar volume
          do i = 1, this%NRealComponents
            pc => this%Component(i)
            if( pc%ChemPotMethod .ne. ChemPotMethodNone .and. ( (EnsembleType .eq. EnsembleTypeNPT) .or. (EnsembleType .eq. EnsembleTypeNPTSVC) ) ) then

                call writeAverages(pc%SumVW, this%resultFile, this%runaveFile, '(" ",F10.4)', parallelMC=.true.)

            end if
          end do

          ! Partial molar enthalphy
          do i = 1, this%NRealComponents
            pc => this%Component(i)
            if( pc%ChemPotMethod .ne. ChemPotMethodNone .and. ( (EnsembleType .eq. EnsembleTypeNPT) .or. (EnsembleType .eq. EnsembleTypeNPTSVC) ) ) then

                call writeAverages(pc%SumHM, this%resultFile, this%runaveFile, '(" ",F10.4)', parallelMC=.true.)

            end if
          end do

        ! Number of particles in ensemble
          if( OpenSystem .or. EnsembleType .eq. EnsembleTypeHA .or. SimulationType .eq. Gibbs) then

            call writeAverages(this%SumNPart, this%resultFile, this%runaveFile, '(" ",F10.2)', parallelMC=.true.)

            ! Mole fraction of each component
            do i = 1, this%NComponents

              pc => this%Component(i)
              call writeAverages(pc%SumFraction, this%resultFile, this%runaveFile, parallelMC=.true.)

            end do

          end if

          write( IOBuffer, '(A)' )new_line('a')
          call FileWriteNoAdvance_parallel(this%resultFile)
          call FileWriteNoAdvance_parallel(this%runaveFile)
        endif
#else
!MPI=0
        ! Number of steps
        write( IOBuffer, '(I9)' ) Step
        call FileWriteNoAdvance(this%resultFile)
        call FileWriteNoAdvance(this%runaveFile)

        call writeAverages(this%SumPressure, this%resultFile, this%runaveFile, parallelMC=.false.)

        call writeAverages(this%SumDensity, this%resultFile, this%runaveFile, parallelMC=.false.)

        call writeAverages(this%SumTemperature, this%resultFile, this%runaveFile, parallelMC=.false.)

        call writeAverages(this%SumEPot, this%resultFile, this%runaveFile, parallelMC=.false.)

        call writeAverages(this%SumEnthalpy, this%resultFile, this%runaveFile, parallelMC=.false.)

        ! Dielectric Constant
        if( (this%NChargeMax > 0).or.(this%NDipoleMax > 0) ) then

            call writeAverages(this%SumDielectricConstant, this%resultFile, this%runaveFile, parallelMC=.false.)

            call writeAverages(this%SumTotalDipoleMoment, this%resultFile, this%runaveFile, parallelMC=.false.)

            call writeAverages(this%SumTotalDipoleMomentSquared, this%resultFile, this%runaveFile, parallelMC=.false.)

        endif

        ! Chemical potential
        do i = 1, this%NRealComponents
          pc => this%Component(i)
          if( pc%ChemPotMethod .ne. ChemPotMethodNone ) then
              if( pc%NPart > 1 ) then
                select case( pc%ChemPotMethod )

                case( ChemPotMethodGradIns )
                  write( IOBuffer, '(" ",F10.5)' ) log( pc%Fraction * pc%SumInvChemPotRho%BlockAverage )
                  call FileWriteNoAdvance(this%resultFile)
                  write( IOBuffer, '(" ",F10.5)' ) log( pc%Fraction * pc%SumInvChemPotRho%Average )
                  call FileWriteNoAdvance(this%runaveFile)

                case( ChemPotMethodWidom )
                  write( IOBuffer, '(" ",F10.5)' ) log( pc%Fraction / pc%SumChemPotV%BlockAverage )
                  call FileWriteNoAdvance(this%resultFile)
                  write( IOBuffer, '(" ",F10.5)' ) log( pc%Fraction / pc%SumChemPotV%Average )
                  call FileWriteNoAdvance(this%runaveFile)

                case( ChemPotMethodThermoInt )

                  call writeAverages(pc%SumChemPotV, this%resultFile, this%runaveFile, parallelMC=.false.)

                end select

              else
                select case( pc%ChemPotMethod )

                case( ChemPotMethodGradIns )
                  write( IOBuffer, '(" ",F10.5)' ) log( pc%SumInvChemPotRho%BlockAverage )
                  call FileWriteNoAdvance(this%resultFile)
                  write( IOBuffer, '(" ",F10.5)' ) log( pc%SumInvChemPotRho%Average )
                  call FileWriteNoAdvance(this%runaveFile)

                case( ChemPotMethodWidom )
                  write( IOBuffer, '(" ",F10.5)' ) -log( pc%SumChemPotV%BlockAverage )
                  call FileWriteNoAdvance(this%resultFile)
                  write( IOBuffer, '(" ",F10.5)' ) -log( pc%SumChemPotV%Average )
                  call FileWriteNoAdvance(this%runaveFile)

                case( ChemPotMethodThermoInt )

                  call writeAverages(pc%SumChemPotV, this%resultFile, this%runaveFile, parallelMC=.false.)

                end select
              end if
          end if
          if (EnsembleType .eq. EnsembleTypeGE) then

            call writeAverages(pc%SumChemPotGE, this%resultFile, this%runaveFile, parallelMC=.false.)

          endif
        end do

      ! Partial molar volume
        do i = 1, this%NRealComponents
          pc => this%Component(i)
          if( pc%ChemPotMethod .ne. ChemPotMethodNone .and. ( (EnsembleType .eq. EnsembleTypeNPT) .or. (EnsembleType .eq. EnsembleTypeNPTSVC) ) ) then

            call writeAverages(pc%SumVW, this%resultFile, this%runaveFile, '(" ",F10.4)', parallelMC=.false.)

          end if
        end do

        ! Partial molar enthalphy
        do i = 1, this%NRealComponents
          pc => this%Component(i)
          if( pc%ChemPotMethod .ne. ChemPotMethodNone .and. ( (EnsembleType .eq. EnsembleTypeNPT) .or. (EnsembleType .eq. EnsembleTypeNPTSVC) ) ) then

            call writeAverages(pc%SumHM, this%resultFile, this%runaveFile, '(" ",F10.4)', parallelMC=.false.)

          end if
        end do

      ! Number of particles in ensemble
        if( OpenSystem .or. EnsembleType .eq. EnsembleTypeHA .or. SimulationType .eq. Gibbs) then

          call writeAverages(this%SumNPart, this%resultFile, this%runaveFile, '(" ",F10.2)', parallelMC=.false.)

          ! Mole fraction of each component
          do i = 1, this%NComponents
            pc => this%Component(i)

            call writeAverages(pc%SumFraction, this%resultFile, this%runaveFile, parallelMC=.false.)

          end do
        end if

        call FileWriteBlank(this%resultFile)
        call FileWriteBlank(this%runaveFile)

#if ARCH == 2 && ! MPI_VER > 0
        call flush( this%resultFile%iounit )
        call flush( this%runaveFile%iounit )
#endif
#endif
      else !MD
        ! Number of steps
        write( IOBuffer, '(I9)' ) Step
        call FileWriteNoAdvance(this%resultFile)
        call FileWriteNoAdvance(this%runaveFile)

        ! Displacement
        value = 0._RK
        do i = 1, this%NComponents
          value = value + sum( this%Component(i)%Disp(:, :)**2 )
        end do
        value = value * this%BoxLength**2 / ( 6._RK * this%NPart * TimeStep * Step )
        write( IOBuffer, '(" ",F8.3)' ) value
        call FileWriteNoAdvance(this%runaveFile)

        call writeAverages(this%SumPressure, this%resultFile, this%runaveFile, parallelMC=.false.)

        call writeAverages(this%SumDensity, this%resultFile, this%runaveFile, parallelMC=.false.)

        call writeAverages(this%SumTemperature, this%resultFile, this%runaveFile, parallelMC=.false.)

#if OSMOP > 0
        call writeAverages(this%SumOsmoticPressure, this%resultFile, this%runaveFile, '(F10.5)', parallelMC=.false.)
#endif

        call writeAverages(this%SumEPot, this%resultFile, this%runaveFile, parallelMC=.false.)

        call writeAverages(this%SumEnthalpy, this%resultFile, this%runaveFile, parallelMC=.false.)

        if( (this%NChargeMax > 0).or.(this%NDipoleMax > 0) ) then

            call writeAverages(this%SumDielectricConstant, this%resultFile, this%runaveFile, parallelMC=.false.)

            call writeAverages(this%SumTotalDipoleMoment, this%resultFile, this%runaveFile, parallelMC=.false.)

            call writeAverages(this%SumTotalDipoleMomentSquared, this%resultFile, this%runaveFile, parallelMC=.false.)

        endif

        ! Chemical potential
        do i = 1, this%NRealComponents
          pc => this%Component(i)
          if( pc%ChemPotMethod .ne. ChemPotMethodNone ) then
            if( Equilibration ) then
              write( IOBuffer, '(" ",F10.5)' ) 0._RK
              call FileWriteNoAdvance(this%resultFile)
              call FileWriteNoAdvance(this%runaveFile)
            else
              if( pc%NPart > 1 ) then
                select case( pc%ChemPotMethod )

                case( ChemPotMethodGradIns )
                  write( IOBuffer, '(" ",F10.5)' ) log( pc%Fraction * pc%SumInvChemPotRho%BlockAverage )
                  call FileWriteNoAdvance(this%resultFile)
                  write( IOBuffer, '(" ",F10.5)' ) log( pc%Fraction * pc%SumInvChemPotRho%Average )
                  call FileWriteNoAdvance(this%runaveFile)

                case( ChemPotMethodWidom )
                  write( IOBuffer, '(" ",F10.5)' ) log( pc%Fraction / pc%SumChemPotV%BlockAverage )
                  call FileWriteNoAdvance(this%resultFile)
                  write( IOBuffer, '(" ",F10.5)' ) log( pc%Fraction / pc%SumChemPotV%Average )
                  call FileWriteNoAdvance(this%runaveFile)

                case( ChemPotMethodThermoInt )
                  write( IOBuffer, '(" ",F10.5)' ) pc%SumChemPotV%BlockAverage
                  call FileWriteNoAdvance(this%resultFile)
                  write( IOBuffer, '(" ",F10.5)' ) pc%SumChemPotV%Average
                  call FileWriteNoAdvance(this%runaveFile)
                end select

              else
                select case( pc%ChemPotMethod )

                case( ChemPotMethodGradIns )
                  write( IOBuffer, '(" ",F10.5)' ) log( pc%SumInvChemPotRho%BlockAverage )
                  call FileWriteNoAdvance(this%resultFile)
                  write( IOBuffer, '(" ",F10.5)' ) log( pc%SumInvChemPotRho%Average )
                  call FileWriteNoAdvance(this%runaveFile)

                case( ChemPotMethodWidom )
                  write( IOBuffer, '(" ",F10.5)' ) -log( pc%SumChemPotV%BlockAverage )
                  call FileWriteNoAdvance(this%resultFile)
                  write( IOBuffer, '(" ",F10.5)' ) -log( pc%SumChemPotV%Average )
                  call FileWriteNoAdvance(this%runaveFile)

                case( ChemPotMethodThermoInt )
                  write( IOBuffer, '(" ",F10.5)' ) pc%SumChemPotV%BlockAverage
                  call FileWriteNoAdvance(this%resultFile)
                  write( IOBuffer, '(" ",F10.5)' ) pc%SumChemPotV%Average
                  call FileWriteNoAdvance(this%runaveFile)
                end select
              end if
            end if
          end if
        end do

      ! Partial molar volume
        do i = 1, this%NRealComponents
          pc => this%Component(i)
        if( pc%ChemPotMethod .ne. ChemPotMethodNone .and. ( (EnsembleType .eq. EnsembleTypeNPT) .or. (EnsembleType .eq. EnsembleTypeNPTSVC) ) ) then
            if( Equilibration ) then
              write( IOBuffer, '(" ",F10.4)' ) 0._RK
              call FileWriteNoAdvance(this%resultFile)
              call FileWriteNoAdvance(this%runaveFile)

            else

               call writeAverages(pc%SumVW, this%resultFile, this%runaveFile, '(" ",F10.4)', parallelMC=.false.)

            end if
          end if
        end do

        ! Partial molar enthalphy
        do i = 1, this%NRealComponents
          pc => this%Component(i)
         if( pc%ChemPotMethod .ne. ChemPotMethodNone .and. ( (EnsembleType .eq. EnsembleTypeNPT) .or. (EnsembleType .eq. EnsembleTypeNPTSVC) ) ) then
            if( Equilibration ) then
              write( IOBuffer, '(" ",F10.4)' ) 0._RK
              call FileWriteNoAdvance(this%resultFile)
              call FileWriteNoAdvance(this%runaveFile)
            else

              call writeAverages(pc%SumHM, this%resultFile, this%runaveFile, '(" ",F10.4)', parallelMC=.false.)

            end if
          end if
        end do

#if HBOND > 0
        do i = 1, this%NComponents

          call writeAverages(this%SumHBond0(i), this%resultFile, this%runaveFile, '(" ",F10.4)', parallelMC=.false.)

        end do

        do i = 1, this%NComponents
          do  j = 1, this%NComponents

            call writeAverages(this%SumHBond1(i,j), this%resultFile, this%runaveFile, '("   ", F10.4)', parallelMC=.false.)

          end do
        end do

        do i = 1, this%NComponents
          do  j = 1, this%NComponents
            do k = j, this%NComponents

              call writeAverages(this%SumHBond2(i,j,k), this%resultFile, this%runaveFile, '("      ", F10.4)', parallelMC=.false.)

            end do
          end do
        end do

        do i = 1, this%NComponents
          do  j = 1, this%NComponents
            do k = j, this%NComponents
              do  l = k, this%NComponents

                call writeAverages(this%SumHBond3(i,j,k,l), this%resultFile, this%runaveFile, '("         ", F10.4)', parallelMC=.false.)

              end do
            end do
          end do
        end do

        do i = 1, this%NComponents
          do  j = 1, this%NComponents
            do k = j, this%NComponents
              do l = k, this%NComponents
                do m = l, this%NComponents

                  call writeAverages(this%SumHBond4(i,j,k,l,m), this%resultFile, this%runaveFile, '("         ", F10.4)', parallelMC=.false.)

                end do
              end do
            end do
          end do
        end do

        do i = 1, this%NComponents

          call writeAverages(this%SumHBondN(i), this%resultFile, this%runaveFile, '(" ", F10.4)', parallelMC=.false.)

        end do
#endif

#if OSMOP > 0
        !Density Profile
        do i = 1, this%NComponents
          pc => this%Component(i)
          do j = 1, NBinsDen

            call writeAverages(pc%SumDenProfile(j), this%resultFile, this%runaveFile, '(F10.4)', parallelMC=.false.)

          end do
        end do

#if OSMOP == 2
        !Pressure Profile
        do j = 1, NBinsDen

            call writeAverages(this%SumPressureProfile(j), this%resultFile, this%runaveFile, '(F10.4)', parallelMC=.false.)

        end do

        !Chemical Potential Profile
        do i = 1, this%NRealComponents
          pc => this%Component(i)
          if( pc%ChemPotMethod .eq. ChemPotMethodWidom ) then
            if( Equilibration ) then
              do j = 1, NBinsDen
                write( IOBuffer, '(F10.5)' ) 0._RK
                call FileWriteNoAdvance(this%resultFile)
                call FileWriteNoAdvance(this%runaveFile)
              end do
            else
              do j = 1, NBinsDen
                write( IOBuffer, '(F10.5)' ) &
&                      log( pc%SumDenProfile(j)%Average / pc%SumChemPotProfile(j)%BlockAverage )
                call FileWriteNoAdvance(this%resultFile)
                write( IOBuffer, '(F10.5)' ) &
&                      log( pc%SumDenProfile(j)%Average / pc%SumChemPotProfile(j)%Average )
                call FileWriteNoAdvance(this%runaveFile)
              end do
            end if
          end if
        end do
#endif
#endif

      ! Number of particles in ensemble
        if( OpenSystem .or. EnsembleType .eq. EnsembleTypeHA .or. SimulationType .eq. Gibbs ) then
          write( IOBuffer, '(" ",F10.2)' ) this%SumNPart%BlockAverage
          call FileWriteNoAdvance(this%resultFile)
          write( IOBuffer, '(" ",F10.2)' ) this%SumNPart%Average
          call FileWriteNoAdvance(this%runaveFile)

          ! Mole fraction of each component
          do i = 1, this%NComponents
            pc => this%Component(i)
            write( IOBuffer, '(" ",F10.5)' ) pc%SumFraction%BlockAverage
            call FileWriteNoAdvance(this%resultFile)
            write( IOBuffer, '(" ",F10.5)' ) pc%SumFraction%Average
            call FileWriteNoAdvance(this%runaveFile)
          end do
        end if

        call FileWriteBlank(this%resultFile)
        call FileWriteBlank(this%runaveFile)

#if ARCH == 2
        call flush( this%resultFile%iounit )
        call flush( this%runaveFile%iounit )
#endif

      end if
    end if

#if  TRANS == 1
    ! Transport properties
    if( ( this%Mmess > 0 ) .and. ( mod(this%Mmess, this%Nviewcf) == 0 )&
&       .and. (mod((Step + this%NStepCorr -1), (this%NSpanCF*this%NStepCorr)) == 0) ) then

      rewind( this%rescfFile%iounit )
      write( IOBuffer, '("  TIME[ps]")' )
      call FileWriteNoAdvance(this%rescfFile)

      if ( (TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
        if(this%Ncomponents>1)then
          do i=1,this%NComponents*this%NComponents
            write( IOBuffer, '(T10, "L_ij", I1)') i
            call FileWriteNoAdvance(this%rescfFile)
          end do
        end if

        do i = 1, this%NComponents
          write( IOBuffer, '(T10,"D_i",I2)' ) i
          call FileWriteNoAdvance(this%rescfFile)
        end do

        write( IOBuffer, '(T13,"Shr. Vis.")' )
        call FileWriteNoAdvance(this%rescfFile)
      end if

      if (this%Bulkviscosity) then
        write( IOBuffer, '(T13,"Bulk Vis.")' )
        call FileWriteNoAdvance(this%rescfFile)
      end if

!      if (this%Conductivity) then
      write( IOBuffer, '(T13,"Th. Cond.")' )
      call FileWriteNoAdvance(this%rescfFile)

      if(this%Ncomponents .gt.  1)then
        do i = 1, this%NComponents
          write( IOBuffer, '(T10,"L_iQ", I1)' )i
          call FileWriteNoAdvance(this%rescfFile)
        end do
      end if
!      end if

      if (this%EConductivity) then
        write( IOBuffer, '(T13,"El. Cond.")' )
        call FileWriteNoAdvance(this%rescfFile)
      end if

      if ( (TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
        if( this%Ncomponents > 1 ) then
          do i=1,this%NComponents*this%NComponents
             write( IOBuffer, '(T9,"Int_Lij",I1)')i
             call FileWriteNoAdvance(this%rescfFile)
         end do
        end if

        do i = 1, this%NComponents
           write( IOBuffer, '(T9,"IntD_i",I2)' ) i
           call FileWriteNoAdvance(this%rescfFile)
        end do

        write( IOBuffer, '(T9,"Int Sh. Vis.")' )
        call FileWriteNoAdvance(this%rescfFile)
      end if

      if (this%Bulkviscosity) then
        write( IOBuffer, '(T10,"Int Bulk Vis.")' )
        call FileWriteNoAdvance(this%rescfFile)
      end if

 !     if (this%Conductivity) then
        write( IOBuffer, '(T10,"Int Th. Cond.")' )
        call FileWriteNoAdvance(this%rescfFile)
        if (this%NComponents .gt. 1 ) then
          do i = 1, this%NComponents
            write( IOBuffer, '(T10,"Int L_iQ", I1)')i
            call FileWriteNoAdvance(this%rescfFile)
          end do
        end if
 !     end if

      if (this%EConductivity) then
        write( IOBuffer, '(T9,"Int El. Cond.")' )
        call FileWriteNoAdvance(this%rescfFile)
      end if

      call FileWriteBlank(this%rescfFile)

      ! integration time
      do i  = 1, this%NCorr
        value = this%TimeStepCorr*UnitTime/1E-12_RK
        write( IOBuffer, '(F10.5)' ) (i-1)*value
        call FileWriteNoAdvance(this%rescfFile)

!         ! Onsager Diffusion coefficients
        if ( (TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
          if(this%Ncomponents>1)then
            do j=1,this%NComponents*this%NComponents
               write( IOBuffer, '(T5, F10.5)' )  this%average_lamda(j, i)/this%average_lamda(j,1)
               call FileWriteNoAdvance(this%rescfFile)
            end do
          end if

          ! Self-diffusion coefficients
          do j = 1, this%NComponents
            write( IOBuffer, '(T5, F10.5)' ) this%average_cf_d(j,i)/this%average_cf_d(j,1)
            call FileWriteNoAdvance(this%rescfFile)
          end do

          ! Shear viscosity
          write( IOBuffer, '(T5, F10.5)' ) this%average_cf_vs(i)/this%average_cf_vs(1)
          call FileWriteNoAdvance(this%rescfFile)
        end if

        ! Bulk viscosity
        if (this%Bulkviscosity) then
          write( IOBuffer, '(T5, F10.5)' ) this%average_cf_vb(i)/this%average_cf_vb(1)
          call FileWriteNoAdvance(this%rescfFile)
        end if

        ! Thermal conductivity and thermal diffusion
          write( IOBuffer, '(T5, F10.5)' )  this%average_cf_c(i)/this%average_cf_c(1)
          call FileWriteNoAdvance(this%rescfFile)
          if (this%NComponents .gt. 1) then
            do j=1,this%NComponents
              value = this%density*this%density*this%Component(j)%Molecule%Mass/(6._RK*this%NPart)
              write( IOBuffer, '(T5,F14.4)' ) this%average_cf_soret(j,i)*value/this%Mmess
              call FileWriteNoAdvance(this%rescfFile)
            end do
          end if

        ! Electric Conductivity
        if (this%EConductivity) then
          write( IOBuffer, '(T5, F10.5)' )  this%average_cf_ec(i)/this%average_cf_ec(1)
          call FileWriteNoAdvance(this%rescfFile)
        end if

        ! integral ======================================================!
        value = dsqrt(UnitEnergy/UnitMass)*UnitLength/1E-10_RK

        ! Onsager Diffusion coefficients
        if ( (TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
          if( this%Ncomponents > 1) then
            do j = 1, this%NComponents*this%NComponents
               write( IOBuffer, '(T5, F10.4)' )  this%average_sinte_lamda(j,i)*value !this%sinte_lamda(j,i) / this%sinte_lamda(j,this%Ncorr)* value
               call FileWriteNoAdvance(this%rescfFile)
            end do
          end if

          ! Self-diffusion coefficient
          do j = 1, this%NComponents
            write( IOBuffer, '(T5, F10.4)' ) this%average_sinte_i(j,i)* value !this%sinte_i(j,i) / this%sinte_i(j,this%NCorr) * this%selfd_i(j) * value
            call FileWriteNoAdvance(this%rescfFile)
          end do

          !shear viscosity
          value = dsqrt(UnitEnergy*UnitMass)/UnitLength**2/1E-4_RK
          write( IOBuffer, '(T5, F10.5)' )  this%average_sinte_vs(i)* value !this%sinte_vs(i) / this%sinte_vs(this%NCorr) * this%visco_s * value
          call FileWriteNoAdvance(this%rescfFile)
        end if

       ! bulk viscosity
        if (this%Bulkviscosity) then
          value = dsqrt(UnitEnergy*UnitMass)/UnitLength**2/1E-4_RK
          write( IOBuffer, '(T5, F10.5)' ) this%average_sinte_vb(i)*value !this%sinte_vb(i) / this%sinte_vb(this%NCorr) * this%visco_b * value
          call FileWriteNoAdvance(this%rescfFile)
        end if

       ! thermal conductivity
  !      if (this%Conductivity) then
          value = dsqrt(UnitEnergy/UnitMass)*kBoltzmann/UnitLength**2
          write( IOBuffer, '(T5, F10.5)' ) this%average_sinte_c(i)*value !this%sinte_c(i) / this%sinte_c(this%NCorr) * this%conduct * value
          call FileWriteNoAdvance(this%rescfFile)
          if ( this%NComponents .gt. 1) then
            value = dsqrt(UnitEnergy/UnitMass)*UnitMass*UnitTemperature/(1E-6_RK*UnitLength**2)
            do j = 1, this%NComponents
              write( IOBuffer, '(T5, F10.4)' ) this%average_sinte_soret(j,i)*value !/ this%average_sinte_soret(this%NCorr) * this%soret * value
              call FileWriteNoAdvance(this%rescfFile)
            end do
          end if
   !     end if

        ! electric conductivity
        if (this%EConductivity) then
           value = ElementaryCharge**2 /(dsqrt(UnitEnergy*UnitMass) * UnitLength**2)
           write( IOBuffer, '(T5, F10.5)' ) this%sinte_ec(i) / this%sinte_ec(this%NCorr) * this%econduct * value
           call FileWriteNoAdvance(this%rescfFile)
        end if

        call FileWriteBlank(this%rescfFile)
      end do

#if ARCH == 2
      call flush( this%rescfFile%iounit )
#endif
    end if
#endif


! Exit, if specific file is in the folder!
    open( 99, file = 'stop.txt', action = 'READ', status = 'OLD', iostat = err )

#if MPI_VER > 0
! MPI Abortion
#ifdef __INTEL_COMPILER
    if( err .eq. 0 ) then
      call MPI_Bcast(err,1,MPI_INTEGER,NRootProc,Communicator,ierror)
      err = SetTerminateProgram( 1 )
    end if

#else
    if( err .eq. 0 ) then
      call MPI_Bcast(err,1,MPI_INTEGER,NRootProc,Communicator,ierror)
      call SetTerminateProgram
    end if
#endif

#else
! Single Abortion
#ifdef __INTEL_COMPILER
    if( err .eq. 0 ) err = SetTerminateProgram( 1 )
#else
    if( err .eq. 0 ) call SetTerminateProgram
#endif

#endif

#if MPI_VER > 0
! Abortion of simulation run in Karlsruhe
    call time_left(time_limit)
#endif

  end subroutine TEnsemble_ResultUpdate



!==============================================================!
!  Subroutine TEnsemble_ResultClose                            !
!==============================================================!

  subroutine TEnsemble_ResultClose( this )

    implicit none

    ! Declare arguments
    type(TEnsemble) :: this

#if MPI_VER > 0
    if (SimulationType .eq. MonteCarlo) then
      ! Close running average result file
      if( .not. SimulationType .eq. SecondVirialCoeff ) call FileClose_parallel(this%runaveFile)

      ! Close result file
      call FileClose_parallel(this%resultFile)
    else
      if( .not. SimulationType .eq. SecondVirialCoeff ) call FileClose(this%runaveFile)

      ! Close result file
      call FileClose(this%resultFile)
    endif
#else
    if( .not. SimulationType .eq. SecondVirialCoeff ) call FileClose(this%runaveFile)

    ! Close result file
    call FileClose(this%resultFile)
#endif
  end subroutine TEnsemble_ResultClose


  subroutine writeStatisticalAnalogues(this)

    type(TEnsemble) :: this
    type(TComponent), pointer :: pc

    real(RK) :: Average, Variance, dimensionFactor
    real(RK) :: molmass, cpid

    ! Cv

    Average = this%SumCVsm%Average - 1.5_RK
    Variance = this%SumCVsm%Variance

    dimensionFactor = kBoltzmann * NAvogadro

    call writeValue("Isochoric heat capacity", Average, Variance, dimensionFactor, "J/(mol K)", this%errorsFile)

    ! GammaV

    Average = this%SumGammaVsm%Average
    Variance = this%SumGammaVsm%Variance

    dimensionFactor = (UnitPressure * 1E-6_RK) / UnitTemperature

    call writeValue("Thermal pressure coefficient", Average, Variance, dimensionFactor, "MPa/ K", this%errorsFile)

    ! BetaT

    Average = this%SumBetaTsm%Average
    Variance = this%SumBetaTsm%Variance

    dimensionFactor = 1 / ( UnitPressure * 1E-6_RK )

    call writeValue("Isothermal compressibility", Average, Variance, dimensionFactor, "1/MPa", this%errorsFile)

    ! ALphaP

    Average = this%SumAlphaPsm%Average
    Variance = SQRT( ( this%SumBetaTsm%Average * this%SumGammaVsm%Variance )**2 + &
                     ( this%SumBetaTsm%Variance * this%SumGammaVsm%Average )**2 )

    dimensionFactor = 1 / UnitTemperature

    call writeValue("Thermal expansion coefficient", Average, Variance, dimensionFactor, "1/ K", this%errorsFile)

    ! CP

    Average = this%SumCPsm%Average - 2.5_RK
    Variance = this%SumCPsm%Variance

    dimensionFactor = kBoltzmann * NAvogadro

    call writeValue("Isobaric heat capacity", Average, Variance, dimensionFactor, "J/(mol K)", this%errorsFile)

    ! Speed of Sound

    molmass = 0._RK
    cpid = 0._RK

    do i = 1, this%NRealComponents
        pc => this%Component(i)
        molmass = molmass + pc%Fraction * pc%Molecule%Mass
        cpid = cpid + .5_RK * pc%Fraction * pc%Molecule%NDF
    end do

    Average = SQRT( this%SumCPsm%Average / ( molmass*this%SumBetaTsm%Average &
                    *this%SumCVsm%Average*this%RefDensity ) )

    Variance = .5_RK * SQRT(( Average*this%SumCPsm%Variance/this%SumCpsm%Average )**2 + &
                            ( Average*this%SumBetaTsm%Variance/this%SumBetaTsm%Average )**2 + &
                            ( Average*this%SumCVsm%Variance/this%SumCVsm%Average )**2 ) / Average

    dimensionFactor = UnitLength / UnitTime

    call writeValue("Speed of sound", Average, Variance, dimensionFactor, "m/s", this%errorsFile)

    ! Joule Thomson

    Average = 1._RK/(this%RefDensity*this%SumCPsm%Average) * (this%RefTemperature*this%SumAlphaPsm%Average-1)

    Variance = SQRT(( this%SumCPsm%Variance/(this%RefDensity*this%SumCPsm%Average*this%SumCPsm%Average) * &
                    (this%RefTemperature*this%SumAlphaPsm%Average-1) )**2 + &
                    (this%RefTemperature*this%SumAlphaPsm%Variance / &
                    (this%RefDensity*this%SumCPsm%Average) )**2 )

    dimensionFactor = UnitTemperature / ( UnitPressure * 1E-6_RK )

    call writeValue("Joule Thomson coefficient", Average, Variance, dimensionFactor, "K/MPa", this%errorsFile)

  end subroutine writeStatisticalAnalogues


  subroutine writeValue(quantityName, Average, Variance, dimensionFactor, unitString, errorsFile)
    ! Output with : as 29th character should be:
    !<quantityName>             red.:        12.314568478         0.314568478
    !                in <unitString>:         5.001409733         0.000352543

    type(TFile) :: errorsFile
    real(RK) :: Average, Variance, dimensionFactor
    character(*) :: quantityName, unitString
    character(len=:), allocatable :: formatString
    integer :: nSpaces

    ! order of ifs is important!
    if (len(quantityName) <= (36 - 7 - 2)) then ! line width - len("reduced") - space - len(":")

        formatString = '(A, A, "reduced:", 2F20.9)'
        nSpaces = 36 - len(quantityName) - 7 - 1

    else if (len(quantityName) <= (36 - 4 - 2)) then ! line width - len("red.") - space - len(":")

        formatString = '(A, A, "red.:", 2F20.9)'
        nSpaces = 36 - len(quantityName) - 4 - 1

    else

        write( ErrorBuffer, '(A, A, A)' ) "Variable name '", quantityName, &
                                          "' in writeValue does not fit coulmn width."
        call Error

    end if

    write(IOBuffer, formatString) quantityName, repeat(" ", NSpaces), Average, Variance
    call FileWrite(errorsFile)

    nSpaces = 36 - len(unitString) - 4
    write(IOBuffer, '(A, A, A, A, 2F20.9)') repeat(" ", nSpaces), "in ", unitString, ":", Average * dimensionFactor , Variance  * dimensionFactor

    call FileWrite(errorsFile)
    call FileWriteBlank(errorsFile)

  end subroutine writeValue


  subroutine writeSeparator(errorsFile, noHline, errorColumn)

    type(Tfile) :: errorsFile
    logical :: noHline, errorColumn

    if (.not. noHline) then
        write( IOBuffer, '(76("="))' )
    end if

    call FileWrite(errorsFile)
    call FileWriteBlank(errorsFile)

    if (errorColumn) then

        write( IOBuffer, '("VALUE", T31, "UNITS", T46, "AVERAGE", T66, "ERROR")' )
        call FileWrite(errorsFile)
        write( IOBuffer, '("-----", T31, "-----", T46, "-------", T66, "-----")' )

    else

        write( IOBuffer, '("VALUE", T31, "UNITS", T46, "AVERAGE")')
        call FileWrite(errorsFile)
        write( IOBuffer, '("-----", T31, "-----", T46, "-------")')

    end if

    call FileWrite(errorsFile)
    call FileWriteBlank(errorsFile)

  end subroutine writeSeparator


!==============================================================!
!  Subroutine TEnsemble_ErrorsUpdate                           !
!==============================================================!

  subroutine TEnsemble_ErrorsUpdate( this )

    implicit none

    ! Include MPI header
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif

    ! Declare arguments
    type(TEnsemble) :: this

    ! Declare local variables
    real(RK)                  :: Average, Variance
    real(RK)                  :: Beta, Beta2
    type(TComponent), pointer :: pc
    integer                   :: i, j, t, iKBImethod, iComponent
    real(RK)                  :: dimensionFactor, value
    character(:), allocatable :: formatString
    character(len=16), dimension(3) :: methodStringKBI
#if  TRANS == 1
    integer                   :: k, m
    real(RK)                  :: mw,w1,w2,nc,factor
    real(RK)                  :: det, inv_det
    real(RK)                  :: x(this%NComponents)
    real(RK)                  :: Inv_x(this%NComponents)
    real(RK)                  :: L(this%NComponents, this%NComponents)
    real(RK)                  :: delta(this%NComponents-1, this%NComponents-1)
    real(RK)                  :: err_delta(this%NComponents-1, this%NComponents-1)
    real(RK)                  :: B(this%NComponents-1, this%NComponents-1)
    real(RK)                  :: err_B(this%NComponents-1, this%NComponents-1)
    real(RK)                  :: D_12, D_13, D_14, D_23, D_24, D_34
    real(RK)                  :: err_D12, err_D13, err_D14, err_D23, err_D24, err_D34
#endif
#if HBOND > 0
    integer                   :: k, l, m
#endif

    ! Declare local variables for velocity of sound
    real(RK) :: molmass, cpid

    ! Declare local variables for phase equilibrium results
    real(RK) :: NN, yvi
    real(RK) :: dpdmu( this%NComponents ), dpdv( this%NComponents )
    real(RK) :: dydmu( this%NComponents, this%NComponents ), dydv( this%NComponents, this%NComponents )
    real(RK) :: varmu( this%NComponents ), varv( this%NComponents )
    real(RK) :: vary( this%NComponents - 1 )
    real(RK) :: VarPressure, DeltaHv, VarDeltaHv

! Declare local variables for VLE Calculation with the SVC (Denis) delete the ones not needed
    real(RK) ::  x_vlesvc ( this%NComponents), y_vlesvc (this%NComponents)
    real(RK) :: f (this%NComponents), Jacobian( this%NComponents, this%NComponents )
    real(RK) :: VapPressSVC, VapPressSVCErr, VapDensSVC, VapDensSVCErr, dRhoVapdp, VapPressLimSVC
    real(RK) :: z_calc, z_lim
    logical  :: flag ! infinity or nan

    !for the last vapor.mole fraction
     real(RK) :: t_sub

     logical  :: conv
     !integer  ::  l, errcode, fehler, s, n, k
     integer  ::  fehler, n

#if MPI_VER > 0
    integer :: tempVal, tempVal2, color
    integer :: tempVec1(this%NFluctMax), tempVec2(this%NFluctMax)
    integer :: tempVec3(this%NFluctMax), tempVec4(this%NFluctMax)
    real(RK):: tempReal

    if ( SimulationType .eq. MonteCarlo) then
      if ( mpiMCCommonGroups > 0 ) then
        NBlockSizes = int( sqrt( real( Step*mpiMCCommonGroups / BlockSize, RK ) ) )
        tempVal = NBlocks
        NBlocks = tempVal*mpiMCCommonGroups
      else
        NBlockSizes = int( sqrt( real( Step*NProcs / BlockSize, RK ) ) )
        tempVal = NBlocks
        NBlocks = tempVal*NProcs
      endif
    endif
#endif

    !DC NOTE this prevent update of data on stopped simulations
    if (this%isStopSimulation .eqv. .true.) then
      return
    endif
    ! Calculate averages and errors
    call Error( this%SumPressure )
    call Error( this%SumDensity )
    call Error( this%SumTemperature )
    call Error( this%SumEPot )
    call Error( this%SumEnthalpy )
    call Error( this%SumConfEnthalpy )
    call Error( this%SumVolume )
#if OSMOP > 0
    call Error( this%SumOsmoticPressure )
    do i = 1, this%NComponents
      do j = 1, NBinsDen
        call Error( this%Component(i)%SumDenProfile(j) )
#if OSMOP == 2
        if( this%Component(i)%ChemPotMethod .eq. ChemPotMethodWidom ) then
          call Error( this%Component(i)%SumChemPotProfile(j) )
        end if
#endif
      end do
    end do
#if OSMOP == 2
    do j = 1, NBinsDen
       call Error( this%SumPressureProfile(j) )
    end do
#endif
#endif

#if HBOND > 0
    do i = 1, this%NComponents
      call Error( this%SumHBond0(i) )
      do j = 1, this%NComponents
        call Error( this%SumHBond1(i,j) )
        do k = j, this%NComponents
          call Error( this%SumHBond2(i,j,k) )
          do l = k, this%NComponents
            call Error( this%SumHBond3(i,j,k,l) )
            do m = l, this%NComponents
              call Error( this%SumHBond4(i,j,k,l,m) )
            end do
          end do
        end do
      end do
      call Error( this%SumHBondN(i) )
    end do
#endif

    call Error( this%SumdEpotdV )
    call Error( this%Sumd2EpotdV2 )

    call Error( this%SumEPotSquared)
    call Error( this%SumEPotCubic)
    call Error( this%SumdEpotdVSquared)
    call Error( this%SumEPotdEpotdV)
    call Error( this%SumEPotSquareddEpotdV)
    call Error( this%SumEPotdEpotdVSquared)
    call Error( this%SumEPotd2EpotdV2)

    if ( LongRange .eq. Rfield ) then
      call Error( this%SumCVsm )
      call Error( this%SumGammaVsm )
      call Error( this%SumBetaTsm )
      call Error( this%SumAlphaPsm )
      call Error( this%SumCPsm )
      if( EnsembleType .eq. EnsembleTypeNVE ) then
        call Error( this%SumHmU )
        call Error( this%SumHmUm1)
        call Error( this%SumHmUm2 )
        call Error( this%SumHmUm3 )
        call Error( this%SumHmUm1dUdV )
        call Error( this%SumHmUm1dUdV2 )
        call Error( this%SumHmUm1d2UdV2 )
        call Error( this%SumHmUm2dUdV )
        call Error( this%SumHmUm2dUdV2 )
        call Error( this%SumHmUm2d2UdV2 )
        call Error( this%SumHmUm3dUdV )
        call Error( this%SumHmUm3dUdV2 )

        call Error( this%SumA10resI )
        call Error( this%SumA01resI )
        call Error( this%SumA20resI )
        call Error( this%SumA11resI )
        call Error( this%SumA02resI )
        call Error( this%SumA30resI )
        call Error( this%SumA21resI )
        call Error( this%SumA12resI )
        call Error( this%SumA10resII )
        call Error( this%SumA01resII )
        call Error( this%SumA20resII )
        call Error( this%SumA11resII )
        call Error( this%SumA02resII )
        call Error( this%SumA30resII )
        call Error( this%SumA21resII )
        call Error( this%SumA12resII )
      elseif ( EnsembleType .eq. EnsembleTypeNVT ) then
        call Error( this%SumA10resI )
        call Error( this%SumA01resI )
        call Error( this%SumA20resI )
        call Error( this%SumA11resI )
        call Error( this%SumA02resI )
        call Error( this%SumA30resI )
        call Error( this%SumA21resI )
        call Error( this%SumA12resI )
      elseif( EnsembleType .eq. EnsembleTypeNPT ) then
        call Error( this%SumConfEnthalpyTot )
        call Error( this%SumConfEnthalpy2 )
        call Error( this%SumConfEnthalpyV )
        call Error( this%SumG10 )
        call Error( this%SumG01 )
        call Error( this%SumG11 )
        call Error( this%SumG02 )
        call Error( this%SumG20 )
      elseif( EnsembleType .eq. EnsembleTypeNPH ) then
        call Error( this%SumHmUmpV )
        call Error( this%SumHmUmpVInv )
        call Error( this%SumHmUmpVInvV )
        call Error( this%SumHmUmpVInvV2 )
        call Error( this%SumS10 )
        call Error( this%SumS01 )
        call Error( this%SumS11 )
        call Error( this%SumS02 )
        call Error( this%SumS20 )
      end if
    end if

    if( OpenSystem .or. EnsembleType .eq. EnsembleTypeHA .or. SimulationType .eq. Gibbs) then
      do i = 1, this%NComponents
        pc => this%Component(i)
        call Error( pc%SumFraction )
      end do

      if( EnsembleType .eq. EnsembleTypeGE .or. EnsembleType .eq. EnsembleTypeMUVT ) then
        call Error( this%SumP001 )
        call Error( this%SumP002 )
        call Error( this%SumP100 )
        call Error( this%SumP200 )
        call Error( this%SumP020 )
        call Error( this%SumP101 )
        call Error( this%SumP010 )
        call Error( this%SumP110 )
        call Error( this%SumP011 )
        call Error( this%SumCVsm )
        call Error( this%SumGammaVsm )
        call Error( this%SumBetaTsm )
        call Error( this%SumAlphaPsm )
        call Error( this%SumCPsm )
      else if( EnsembleType .eq. EnsembleTypeMUVL .or. EnsembleType .eq. EnsembleTypeMUPR ) then
        call Error( this%SumP001 )
        call Error( this%SumP002 )
        call Error( this%SumP100 )
        call Error( this%SumP200 )
        call Error( this%SumP020 )
        call Error( this%SumP101 )
        call Error( this%SumP010 )
        call Error( this%SumP110 )
        call Error( this%SumP011 )
      else if( EnsembleType .eq. EnsembleTypeMUPT ) then
        call Error( this%SumP001 )
        call Error( this%SumP002 )
        call Error( this%SumP100 )
        call Error( this%SumP200 )
        call Error( this%SumP020 )
        call Error( this%SumP101 )
        call Error( this%SumP010 )
        call Error( this%SumP110 )
        call Error( this%SumP011 )
      end if

    else
      if( ConstantPressure ) then
        call Error( this%SumBetaT )
        call Error( this%SumdHdP )
        call Error( this%SumCP )
        call Error( this%SumAlphaP )
      else
        call Error( this%SumdUdV )
        call Error( this%SumCV )
        call Error( this%SumCorCoefR )
      end if

      do i = 1, this%NRealComponents
        pc => this%Component(i)
        select case( pc%ChemPotMethod )
        case( ChemPotMethodGradIns )

#if MPI_VER > 0
           if (mod(NProc,this%NGradInsComp)==pc%NGradThis) then
            color = i
          else
            color = 100000
          endif

          NProc_W = NProc
          RootProc_W = Rootproc
          call MPI_COMM_SPLIT(Communicator,color,NProc,Communicator,ierror)
           ! Careful, Nproc and NProcs are now specific for Communicator
          call SetCommunicator( Communicator )
          NBlockSizes = int( sqrt( real( Step*NProcs / BlockSize, RK ) ) )
          NBlocks = tempVal*NProcs
          RootProc = NProc_W==(pc%NGradThis)
          NRootProc_W = (pc%NGradThis)

#endif

          call ErrorGI( pc%SumInvChemPotRho )
          call ErrorGI( pc%SumVW )

#if MPI_VER > 0
          call SetCommunicator(MPI_COMM_WORLD)
          RootProc = Rootproc_W
#endif

        case( ChemPotMethodWidom )
          call Error( pc%SumChemPotV )
          call Error( pc%SumHW_counter )
          call Error( pc%SumHW_denom )
          call Error( pc%SumVW )
          call Error( pc%SumHM )
        case( ChemPotMethodThermoInt )
          call Error( pc%SumChemPotV )
          call Error( pc%SumChemPotThermoIntWidom )
          call Error( pc%SumChemPotThermoIntWidomV )
          call Error( pc%SumHW_counter )
          call Error( pc%SumHW_denom )
          call Error( pc%SumVW )
          call Error( pc%SumHM )
        case default
          ! DO NOTHING
        end select
      end do
    end if
    if (EnsembleType .eq. EnsembleTypeGE) then
      do i = 1, this%NRealComponents
        pc => this%Component(i)
        call Error( pc%SumChemPotGE )
      enddo
    endif

    ! Sampling of Dielectric Constant
    if( (this%NChargeMax > 0).or.(this%NDipoleMax > 0) ) then
        call Error( this%SumTotalDipoleMoment )
        call Error( this%SumTotalDipoleMomentSquared )
        call Error( this%SumDielectricConstant )
    endif

#if MPI_VER >0
    if ( SimulationType .eq. MonteCarlo) then
      NBlockSizes = int( sqrt( real( Step / BlockSize, RK ) ) )
      NBlocks = tempVal
    end if
#endif


#if MPI_VER > 0
    if ( mpiMCCommonGroups > 0 ) then
       if ( RootProc_MCCom ) then !=RootProc_W
         ! Open final result file
         write( IOBuffer, '(I16)' ) this%EnsembleNumber
         call FileRewrite( this%errorsFile, trim( OutputNameTag )//'_'//trim( adjustl( IOBuffer ) )//ErrorsFileExtension )
       endif
    else
       ! Open final result file
       write( IOBuffer, '(I16)' ) this%EnsembleNumber
       call FileRewrite( this%errorsFile, trim( OutputNameTag )//'_'//trim( adjustl( IOBuffer ) )//ErrorsFileExtension )
    endif
#else    ! Open final result file
    write( IOBuffer, '(I16)' ) this%EnsembleNumber
    call FileRewrite( this%errorsFile, trim( OutputNameTag )//'_'//trim( adjustl( IOBuffer ) )//ErrorsFileExtension )
#endif

    call writeCitationHeader(this%errorsFile)

    ! Separator
    write( IOBuffer, '(76("="))' )
    call FileWrite(this%errorsFile)
    call FileWriteBlank(this%errorsFile)
    write( IOBuffer, '(T24, "SIMULATION RESULT FILE")' )
    call FileWrite(this%errorsFile)
    write( IOBuffer, '(T24, "----------------------")' )
    call FileWrite(this%errorsFile)
    call FileWriteBlank(this%errorsFile)

    ! Simulation type
    write( IOBuffer, '("Simulation type", T36, ":", 9X, A)' ) trim( SimulationTypeString )
    call FileWrite(this%errorsFile)
    write( IOBuffer, '("Ensemble type", T36, ":", 9X, A)' ) trim( EnsembleTypeString )
    call FileWrite(this%errorsFile)
    if( SimulationType .eq. MolecularDynamics ) then
      write( IOBuffer, '("Integrator type", T36, ":", 9X, A)' ) trim( IntegratorTypeString )
      call FileWrite(this%errorsFile)
    end if
    call FileWriteBlank(this%errorsFile)

    ! Number of steps
    write( IOBuffer, '("Number of NVT equilibration steps", T36, ":", I10)' ) NStepsV
    call FileWrite(this%errorsFile)
    write( IOBuffer, '("Number of NVE equilibration steps", T36, ":", I10)' ) NStepsE
    call FileWrite(this%errorsFile)
    if( EnsembleType .eq. EnsembleTypeHA ) then
      write( IOBuffer, '("Number of HA equilibration steps", T36, ":", I10)' ) NStepsP
    elseif( EnsembleType .eq. EnsembleTypeGE ) then
      write( IOBuffer, '("Number of GE equilibration steps", T36, ":", I10)' ) NStepsP
    elseif( EnsembleType .eq. EnsembleTypeMUVT ) then
      write( IOBuffer, '("Number of MUVT equilibration steps", T36, ":", I10)' ) NStepsP
    elseif( EnsembleType .eq. EnsembleTypeMUVL ) then
      write( IOBuffer, '("Number of MUVL equilibration steps", T36, ":", I10)' ) NStepsP
    elseif( EnsembleType .eq. EnsembleTypeMUPR ) then
      write( IOBuffer, '("Number of MUPR equilibration steps", T36, ":", I10)' ) NStepsP
    elseif( EnsembleType .eq. EnsembleTypeMUPT ) then
      write( IOBuffer, '("Number of MUPT equilibration steps", T36, ":", I10)' ) NStepsP
    else
      write( IOBuffer, '("Number of NPT equilibration steps", T36, ":", I10)' ) NStepsP
    endif
    call FileWrite(this%errorsFile)
    write( IOBuffer, '("Number of NPH equilibration steps", T36, ":", I10)' ) NStepsH
    call FileWrite(this%errorsFile)


    if ( SimulationType .eq. MonteCarlo .and. (Nproc == NRootProc)) then
      ! The RootProc receives data from all processes and therefore the # of
      ! Step is increased accordingly
#if MPI_VER > 0
      if ( mpiMCCommonGroups > 0 ) then
        write( IOBuffer, '("Number of production steps", T34, ":", I12)' ) Step*mpiMCCommonGroups
      else
        write( IOBuffer, '("Number of production steps", T34, ":", I12)' ) Step*NProcs
      endif
#else
      write( IOBuffer, '("Number of production steps", T34, ":", I12)' ) Step*NProcs
#endif
    else
      write( IOBuffer, '("Number of production steps", T36, ":", I10)' ) Step
    end if
    call FileWrite(this%errorsFile)
    call FileWriteBlank(this%errorsFile)

    ! Time step
    if( SimulationType .eq. MolecularDynamics ) then
      write( IOBuffer, '("Time step", T29, "reduced:", F20.9)' ) TimeStep
      call FileWrite(this%errorsFile)
      write( IOBuffer, '(T31, "in fs:", F20.9)' ) TimeStep * UnitTime * 1E15_RK
      call FileWrite(this%errorsFile)
      call FileWriteBlank(this%errorsFile)
    end if

    ! Acceptance rate
    if( (SimulationType .eq. MonteCarlo) .or. (SimulationType .eq. Gibbs)  ) then
      write( IOBuffer, '("Acceptance rate", T34, ":", F20.9)' ) Acceptance
      call FileWrite(this%errorsFile)
      call FileWriteBlank(this%errorsFile)
    end if

    ! Mass of piston
    if( SimulationType .eq. MolecularDynamics .and. ConstantPressure ) then
      write( IOBuffer, '("Mass of piston (reduced)", T36, ":", F20.9)' ) this%PistonMass
      call FileWrite(this%errorsFile)
      write( IOBuffer, '("Mass of piston", T36, ":", F20.9," kg/m^4")' ) this%PistonMass * UnitMass / UnitLength**4
      call FileWrite(this%errorsFile)
      call FileWriteBlank(this%errorsFile)
    end if

    ! Number of particles
    write( IOBuffer, '("Number of particles", T36, ":", I10)' ) this%NPart
    call FileWrite(this%errorsFile)
    call FileWriteBlank(this%errorsFile)

    ! Potential models
    if( OpenSystem .or. EnsembleType .ne. EnsembleTypeHA .or. SimulationType .eq. Gibbs) then
      do i = 1, this%NRealComponents
        write( IOBuffer, '("Mole fraction of ", A, T36, ":", F20.9)' )&
&              trim( this%Component(i)%Molecule%PotModFileName ), &
&              this%Component(i)%Fraction

        call FileWrite(this%errorsFile)
        select case( this%Component(i)%ChemPotMethod )
        case( ChemPotMethodGradIns )
          write( IOBuffer, '("Chemical potential calculated by gradual insertion")' )
          call FileWrite(this%errorsFile)
        case( ChemPotMethodWidom )
          if (SimulationType .eq. MolecularDynamics) then
            write( IOBuffer, '("Number of test particles", T36, ":", I10)' ) this%Component(i)%NTestAll
          else
            write( IOBuffer, '("Number of test particles", T36, ":", I10)' ) this%Component(i)%NTest
          end if
          call FileWrite(this%errorsFile)
        end select
      end do
      call FileWriteBlank(this%errorsFile)
    end if

    ! Initial pressure
    if( ConstantPressure ) then
      write( IOBuffer, '("Initial pressure", T29, "reduced:", F20.9)' ) this%RefPressure
          StartPressure = this%RefPressure  ! global variable for NPTSVC
      call FileWrite(this%errorsFile)
      write( IOBuffer, '(T30, "in MPa:", F20.9)' ) this%RefPressure * UnitPressure * 1E-6_RK
      call FileWrite(this%errorsFile)
      call FileWriteBlank(this%errorsFile)
    end if

    ! Initial density
    write( IOBuffer, '("Initial density", T29, "reduced:", F20.9)' ) this%RefDensity
    call FileWrite(this%errorsFile)
    write( IOBuffer, '(T28, "in mol/l:", F20.9)' ) this%RefDensity * UnitDensity
    call FileWrite(this%errorsFile)
    call FileWriteBlank(this%errorsFile)

    ! Initial temperature
    write( IOBuffer, '("Initial temperature", T29, "reduced:", F20.9)' ) this%RefTemperature
    StartTemperature = this%RefTemperature
    call FileWrite(this%errorsFile)
    write( IOBuffer, '(T32, "in K:", F20.9)' ) this%RefTemperature * UnitTemperature
    call FileWrite(this%errorsFile)
    call FileWriteBlank(this%errorsFile)


    ! System of units
    write( IOBuffer, '("Unit of length", T36, ":", F20.9, " A")' ) UnitLength / Angstroem
    call FileWrite(this%errorsFile)
    write( IOBuffer, '("Unit of energy", T36, ":", F20.9, " K")' ) UnitEnergy / kBoltzmann
    call FileWrite(this%errorsFile)
    write( IOBuffer, '("Unit of mass", T36, ":", F20.9, " g/mol")' ) UnitMass * NAvogadro * 1000._RK
    call FileWrite(this%errorsFile)
    call FileWriteBlank(this%errorsFile)

    ! Cutoff radii
    if( this%NMIEnmMax > 0 ) then
      write( IOBuffer, '(A, " cutoff radius", T36, ":", F20.9, " A")' ) &
&            trim(LJorMIE), this%RCutoffMIEnmMIEnm * UnitLength / Angstroem
      call FileWrite(this%errorsFile)
    end if

    if( this%NTT68Max > 0 ) then
      write( IOBuffer, '("TT68-TT68 cutoff radius", T36, ":", F20.9, " A")' ) &
&             this%RCutoffTT68TT68 * UnitLength / Angstroem
      call FileWrite(this%errorsFile)
    end if

    if( this%NDipoleMax > 0 ) then
      write( IOBuffer, '("Dipole-dipole cutoff radius", T36, ":", F20.9, " A")' ) &
&            this%RCutoffDipoleDipole * UnitLength / Angstroem
      call FileWrite(this%errorsFile)

      if( this%NQuadrupoleMax > 0 ) then
        write( IOBuffer, '("Dipole-quadrupole cutoff radius", T36, ":", F20.9, " A")' ) &
&              this%RCutoffDipoleQuadrupole * UnitLength / Angstroem
        call FileWrite(this%errorsFile)
      end if

    end if

    if( this%NQuadrupoleMax > 0 ) then
      write( IOBuffer, '("Quadrupole-quadrupole cutoff radius", T36, ":", F20.9, " A")' ) &
&            this%RCutoffQuadrupoleQuadrupole * UnitLength / Angstroem
      call FileWrite(this%errorsFile)
    end if

    call FileWriteBlank(this%errorsFile)

    ! Dielectric constant
    if( this%NDipoleMax > 0 ) then
      write( IOBuffer, '("Dielectric constant:", F36.9)' ) this%RFEpsilon
      call FileWrite(this%errorsFile)
    end if
    call FileWriteBlank(this%errorsFile)

    ! Separator
    call writeSeparator(this%errorsFile, noHline = .false., errorColumn = .true.)

    ! Pressure
    Average = this%SumPressure%Average
    Variance = this%SumPressure%Variance

    dimensionFactor = UnitPressure * 1E-6_RK

    call writeValue("Pressure", Average, Variance, dimensionFactor, "MPa", this%errorsFile)

    ! Density
    Average = this%SumDensity%Average
    Variance = this%SumDensity%Variance

    dimensionFactor = UnitDensity

    call writeValue("Density", Average, Variance, dimensionFactor, "mol/l", this%errorsFile)

    ! Temperature
    Average = this%SumTemperature%Average
    Variance = this%SumTemperature%Variance

    dimensionFactor = UnitTemperature

    call writeValue("Temperature", Average, Variance, dimensionFactor, "K", this%errorsFile)

#if OSMOP > 0
    if (SimulationType .eq. MolecularDynamics) then
        ! OsmoticPressure
        Average = this%SumOsmoticPressure%Average
        Variance = this%SumOsmoticPressure%Variance

        dimensionFactor = UnitPressure * 1E-6_RK

        call writeValue("OsmoticPressure", Average, Variance, dimensionFactor, "MPa", this%errorsFile)

    end if
#endif

    ! Potential energy
    Average = this%SumEPot%Average
    Variance = this%SumEPot%Variance

    dimensionFactor = UnitEnergy * NAvogadro

    call writeValue("Potential energy", Average, Variance, dimensionFactor, "J/mol", this%errorsFile)

    ! Enthalpy
    Average = this%SumEnthalpy%Average
    Variance = this%SumEnthalpy%Variance

    dimensionFactor = UnitEnergy * NAvogadro

    call writeValue("Enthalpy", Average, Variance, dimensionFactor, "J/mol", this%errorsFile)

    ! Sampling of Dielectric Constant
    if( (this%NChargeMax > 0).or.(this%NDipoleMax > 0) ) then
        Average = this%SumDielectricConstant%Average
        Variance = this%SumDielectricConstant%Variance
        write( IOBuffer, '("Dielectric Constant", T29, "SI:", 2F20.9)' ) Average, Variance
        call FileWrite(this%errorsFile)
        call FileWriteBlank(this%errorsFile)

        ! Sampling of Dielectric Constant
        Average = this%SumTotalDipoleMoment%Average
        Variance = this%SumTotalDipoleMoment%Variance
        write( IOBuffer, '("<M>", T29, "red:", 2F20.9)' ) Average, Variance
        call FileWrite(this%errorsFile)
        call FileWriteBlank(this%errorsFile)

        ! Sampling of Dielectric Constant
        Average = this%SumTotalDipoleMomentSquared%Average
        Variance = this%SumTotalDipoleMomentSquared%Variance
        write( IOBuffer, '("<M^2>", T29, "red:", 2F20.9)' ) Average, Variance
        call FileWrite(this%errorsFile)
        call FileWriteBlank(this%errorsFile)
    endif

    if( OpenSystem .or. EnsembleType .eq. EnsembleTypeHA .or. SimulationType .eq. Gibbs) then
      ! Mole fraction
      do i = 1, this%NComponents
        pc => this%Component(i)
        Average = pc%SumFraction%Average
        Variance = pc%SumFraction%Variance
        write( IOBuffer, '("Mole fraction of ", A, T36, ":", 2F20.9)' ) &
&              trim( this%Component(i)%Molecule%PotModFileName ), Average, Variance
        call FileWrite(this%errorsFile)
      end do
      call FileWriteBlank(this%errorsFile)

      if (EnsembleType .eq. EnsembleTypeGE) then
        ! Chemical potential
        do i = 1, this%NRealComponents
          pc => this%Component(i)
          Average = pc%SumChemPotGE%Average
          Variance = pc%SumChemPotGE%Variance
          write( IOBuffer, '("Chemical potential of ", A, T33, "r`d:", 2F20.9)' ) &
&                  trim( this%Component(i)%Molecule%PotModFileName ), Average, Variance
          call FileWrite(this%errorsFile)
        enddo
        call FileWriteBlank(this%errorsFile)
      endif

    else
      ! Chemical potential
      do i = 1, this%NRealComponents
        pc => this%Component(i)
        select case( pc%ChemPotMethod )

        case( ChemPotMethodGradIns )
          if( pc%NPart > 1 ) then
            Variance = pc%SumInvChemPotRho%Variance / pc%SumInvChemPotRho%Average
            Average = log( pc%Fraction * pc%SumInvChemPotRho%Average )
            write( IOBuffer, '("Chemical potential of ", A, T33, "r`d:", 2F20.9)' ) &
&                  trim( this%Component(i)%Molecule%PotModFileName ), Average, Variance
          else
            Variance = pc%SumInvChemPotRho%Variance / pc%SumInvChemPotRho%Average
            Average = -log( 1/pc%SumInvChemPotRho%Average )
            write( IOBuffer, '("Chem. pot. at inf. dilution of ", A, T33, "r`d:", 2F20.9)' ) &
&                  trim( this%Component(i)%Molecule%PotModFileName ), Average, Variance
            call FileWrite(this%errorsFile)
            Average = this%Temperature*pc%SumInvChemPotRho%Average
            Variance = this%Temperature*pc%SumInvChemPotRho%Variance
            write( IOBuffer, '("Henrys law constant of ", A, T33, "r`d:", 2F20.9)' ) &
&                  trim( pc%Molecule%PotModFileName ), Average, Variance
            call FileWrite(this%errorsFile)
            write( IOBuffer, '(T30, "in MPa:", 2F20.9)' ) &
&                  Average * UnitPressure * 1E-6_RK, Variance * UnitPressure * 1E-6_RK
          end if
          call FileWrite(this%errorsFile)

        case( ChemPotMethodWidom )
          Variance = pc%SumChemPotV%Variance / pc%SumChemPotV%Average
          if( pc%Fraction > 0.0_RK ) then
            Average = log( pc%Fraction / pc%SumChemPotV%Average )
            if (EnsembleType .eq. EnsembleTypeNPTSVC) then
             ArrChemPot(i)= Average
            end if
            write( IOBuffer, '("Chemical potential of ", A, T33, "r`d:", 2F20.9)' ) &
&                  trim( this%Component(i)%Molecule%PotModFileName ), Average, Variance

          else
            Average = this%Temperature / pc%SumChemPotV%Average
            Variance = this%Temperature * ( pc%SumChemPotV%Variance / (pc%SumChemPotV%Average * pc%SumChemPotV%Average))
            write( IOBuffer, '("Henrys law constant of ", A, T33, "r`d:", 2F20.9)' ) &
&                  trim( pc%Molecule%PotModFileName ), Average, Variance
            call FileWrite(this%errorsFile)
            write( IOBuffer, '(T30, "in MPa:", 2F20.9)' ) &
&                  Average * UnitPressure * 1E-6_RK, Variance * UnitPressure * 1E-6_RK
          end if
          call FileWrite(this%errorsFile)

        case( ChemPotMethodThermoInt )
          Average  = log( (pc%Fraction+1._RK/real( this%NPart, RK )) / pc%SumChemPotThermoIntWidom%Average )
          Variance =  pc%SumChemPotThermoIntWidom%Variance / pc%SumChemPotThermoIntWidom%Average
          write( IOBuffer, '("Chem. pot. at LambdaMin", A, T33, "r`d:", 2F20.9)' ) &
&                trim( this%Component(i)%Molecule%PotModFileName ), Average , Variance
          call FileWrite(this%errorsFile)
          Average  = pc%SumChemPotV%Average
          Variance = pc%SumChemPotV%Variance
          write( IOBuffer, '("Chemical potential of ", A, T33, "r`d:", 2F20.9)' ) &
&                trim( this%Component(i)%Molecule%PotModFileName ), Average, Variance
          call FileWrite(this%errorsFile)

          if( pc%Npart .eq. 0 ) then
            ! Actually: Average  = this%Temperature * exp(pc%SumChemPotV%Average)/(pc%Fraction+1._RK/real( this%NPart, RK )), but pc%Fraction=0.0
            Average  = this%Temperature * exp(pc%SumChemPotV%Average)*this%NPart
            Variance = Average * pc%SumChemPotV%Variance
            write( IOBuffer, '("Henrys law constant of ", A, T33, "r`d:", 2F20.9)' ) &
&                  trim( pc%Molecule%PotModFileName ), Average, Variance
            call FileWrite(this%errorsFile)
            write( IOBuffer, '(T30, "in MPa:", 2F20.9)' ) &
&                  Average * UnitPressure * 1E-6_RK, Variance * UnitPressure * 1E-6_RK
            call FileWrite(this%errorsFile)
          end if

        end select
      end do

      if( any(this%Component(:)%ChemPotMethod .ne. ChemPotMethodNone)) call FileWriteBlank(this%errorsFile)

      ! Partial molar volume
      do i = 1, this%NRealComponents
        pc => this%Component(i)
        if( pc%ChemPotMethod .ne. ChemPotMethodNone .and. ( (EnsembleType .eq. EnsembleTypeNPT) .or. (EnsembleType .eq. EnsembleTypeNPTSVC) ) ) then
          Average = pc%SumVW%Average
          Variance = pc%SumVW%Variance
          if (EnsembleType .eq. EnsembleTypeNPTSVC) then
             ArrPartMolVol(i) = Average
                if ( this%NComponents .eq. 1 ) then
                    ArrPartMolVol(1) = 1/this%SumDensity%Average
                    end if
            end if
          write( IOBuffer, '("Partial molar volume of ", A, T33, "r`d:", 2F20.9)' ) &
&                trim( this%Component(i)%Molecule%PotModFileName ), Average, Variance
          call FileWrite(this%errorsFile)
          write( IOBuffer, '(T28, "in l/mol:", 2F20.9)' ) Average / UnitDensity, Variance / UnitDensity
          call FileWrite(this%errorsFile)
        end if

          ! Partial molar enthalpy
         if( pc%ChemPotMethod .ne. ChemPotMethodNone .and. ( (EnsembleType .eq. EnsembleTypeNPT) .or. (EnsembleType .eq. EnsembleTypeNPTSVC) ) )  then
          Average = pc%SumHM%Average
          Variance = pc%SumHM%Variance
          write( IOBuffer, '("Partial molar enthalpy of ", A, T33, "r`d:", 2F20.9)' ) &
&                trim( this%Component(i)%Molecule%PotModFileName ), Average, Variance
          call FileWrite(this%errorsFile)
          write( IOBuffer, '(T28, "in J/mol:", 2F20.9)' ) Average * UnitEnergy * NAvogadro, &
&                Variance * UnitEnergy * NAvogadro
          call FileWrite(this%errorsFile)
        end if
      end do

      if( any(this%Component(:)%ChemPotMethod .ne. ChemPotMethodNone)) call FileWriteBlank(this%errorsFile)

      if( ConstantPressure ) then
        ! Isothermal compressibility
        Average = this%SumBetaT%Average
        Variance = this%SumBetaT%Variance

        dimensionFactor = 1 / (UnitPressure * 1E-6_RK)

        call writeValue("Isothermal compressibility", Average, Variance, dimensionFactor, "1/MPa", this%errorsFile)

        ! dH/dP
        Average = this%SumdHdP%Average
        Variance = this%SumdHdP%Variance

        dimensionFactor = 1 / UnitDensity

        call writeValue("dH/dP", Average, Variance, dimensionFactor, "l/mol", this%errorsFile)

        ! CP - subtract ideal gas contribution of the pressure
        Average = this%SumCP%Average - 1._RK
        Variance = this%SumCP%Variance

        dimensionFactor = kBoltzmann * NAvogadro

        call writeValue("Isobaric heat capacity", Average, Variance, dimensionFactor, "J/(mol K)", this%errorsFile)

        ! AlphaP
        Average = this%SumAlphaP%Average
        Variance = this%SumAlphaP%Variance

        dimensionFactor = 1 / UnitTemperature

        call writeValue("Volume expansivity", Average, Variance, dimensionFactor, "1/K", this%errorsFile)

        ! Speed of sound
        molmass = 0._RK
        cpid = 0._RK

        do i = 1, this%NRealComponents
          pc => this%Component(i)
          molmass = molmass + pc%Fraction * pc%Molecule%Mass
          cpid = cpid + .5_RK * pc%Fraction * pc%Molecule%NDF
        end do

        Average = 1._RK / sqrt( molmass * ( this%SumBetaT%Average * this%SumDensity%Average - this%RefTemperature * &
&                 this%SumAlphaP%Average**2 / ( this%SumCP%Average + cpid ) ) )

        Variance = .25_RK / molmass / ( this%SumBetaT%Average * this%SumDensity%Average - this%RefTemperature * &
&                  this%SumAlphaP%Average**2 / ( this%SumCP%Average + cpid ) )**3 * ( this%SumDensity%Average**2 *&
&                  this%SumBetaT%Variance**2 + this%SumBetaT%Average**2 * this%SumDensity%Variance**2 +&
&                  this%RefTemperature**2 * this%SumAlphaP%Average**2 / ( this%SumCP%Average + cpid )**2 *&
&                  ( 4._RK * this%SumAlphaP%Variance**2 + this%SumAlphaP%Average**2 / ( this%SumCP%Average + cpid )**2 * &
&                  this%SumCP%Variance**2 ) )

        dimensionFactor = UnitLength / UnitTime

        call writeValue("Speed of sound", Average, Variance, dimensionFactor, "m/s", this%errorsFile)

      else
        ! dU/dV
        Average = this%SumdUdV%Average
        Variance = this%SumdUdV%Variance

        dimensionFactor = UnitPressure * 1E-6_RK

        call writeValue("dU/dV", Average, Variance, dimensionFactor, "MPa", this%errorsFile)

        ! Cv
        Average = this%SumCV%Average
        Variance = this%SumCV%Variance

        dimensionFactor = kBoltzmann * NAvogadro

        call writeValue("Isochoric heat capacity", Average, Variance, dimensionFactor, "J/(mol K)", this%errorsFile)

        ! Correlation coefficient R
        Average = this%SumCorCoefR%Average
        Variance = this%SumCorCoefR%Variance
        write( IOBuffer, '("Correlation coefficient R", T29, "reduced:", 2F20.9)' ) Average, Variance
        call FileWrite(this%errorsFile)
        call FileWriteBlank(this%errorsFile)
      endif

    end if

    if (any((/EnsembleTypeNVT, EnsembleTypeNVE/) .eq. EnsembleType) .and. LongRange .eq. Rfield) then
      ! Separator
      write( IOBuffer, '(76("="))' )
      call FileWrite(this%errorsFile)
      call FileWriteBlank(this%errorsFile)

      call writeStatisticalAnalogues(this)

      ! A00
      if( all(this%Component(1:this%NRealComponents)%CalcChemPot) .eqv. .true.) then
        Average  = 0_RK
        Variance = 0_RK
        do i = 1, this%NRealComponents
          pc => this%Component(i)
          select case( pc%ChemPotMethod )
          case( ChemPotMethodWidom )
            Average  = Average  + pc%Fraction * ( -log(pc%SumChemPotV%Average) )
            Variance = Variance + ( pc%SumChemPotV%Variance/pc%SumChemPotV%Average )**2
          case( ChemPotMethodThermoInt )
            Average  = Average  + (pc%Fraction+1._RK/real( this%NPart, RK ))&
&                               * ( pc%SumChemPotV%Average - log(pc%Fraction+1._RK/real( this%NPart, RK )) )
            Variance = Variance + pc%SumChemPotV%Variance**2
          end select
        end do
        Average  = Average - this%SumA01resI%Average - log(this%Density)
        Variance = sqrt(Variance + this%SumA01resI%Variance**2)
        write( IOBuffer, '("A00", T29, "Dimensionless, residual:", 2F20.9)' ) Average, Variance
        call FileWrite(this%errorsFile)
        call FileWriteBlank(this%errorsFile)
      end if

      call writeAverageAndVariance(this%SumA10resI, 'A10', this%errorsFile)

      call writeAverageAndVariance(this%SumA01resI, 'A01', this%errorsFile)

      call writeAverageAndVariance(this%SumA20resI, 'A20', this%errorsFile)

      call writeAverageAndVariance(this%SumA11resI, 'A11', this%errorsFile)

      call writeAverageAndVariance(this%SumA02resI, 'A02', this%errorsFile)

      call writeAverageAndVariance(this%SumA30resI, 'A30', this%errorsFile)

      call writeAverageAndVariance(this%SumA21resI, 'A21', this%errorsFile)

      call writeAverageAndVariance(this%SumA12resI, 'A12', this%errorsFile)

      if (EnsembleType .eq. EnsembleTypeNVE) then

          call writeAverageAndVariance(this%SumA10resII, 'A10', this%errorsFile)

          call writeAverageAndVariance(this%SumA01resII, 'A01', this%errorsFile)

          call writeAverageAndVariance(this%SumA20resII, 'A20', this%errorsFile)

          call writeAverageAndVariance(this%SumA11resII, 'A11', this%errorsFile)

          call writeAverageAndVariance(this%SumA02resII, 'A02', this%errorsFile)

          call writeAverageAndVariance(this%SumA30resII, 'A30', this%errorsFile)

          call writeAverageAndVariance(this%SumA21resII, 'A21', this%errorsFile)

          call writeAverageAndVariance(this%SumA12resII, 'A12', this%errorsFile)

      end if

    end if

    if( EnsembleType .eq. EnsembleTypeNPT .and. LongRange .eq. Rfield ) then
      ! Separator
      write( IOBuffer, '(76("="))' )
      call FileWrite(this%errorsFile)
      call FileWriteBlank(this%errorsFile)

      call writeStatisticalAnalogues(this)

      ! G00
      if( all(this%Component(1:this%NRealComponents)%CalcChemPot) .eqv. .true.) then
        Average  = 0_RK
        Variance = 0_RK
        do i = 1, this%NRealComponents
          pc => this%Component(i)
          select case( pc%ChemPotMethod )
          case( ChemPotMethodWidom )
            Average  = Average  + pc%Fraction * ( -log(pc%SumChemPotV%Average) )
            Variance = Variance + ( pc%SumChemPotV%Variance/pc%SumChemPotV%Average )**2
          case( ChemPotMethodThermoInt )
            Average  = Average  + (pc%Fraction+1._RK/real( this%NPart, RK ))&
&                               * ( pc%SumChemPotV%Average - log(pc%Fraction+1._RK/real( this%NPart, RK )) )
            Variance = Variance + pc%SumChemPotV%Variance**2
          end select
        end do

        Average  = Average - log(this%RefPressure/this%RefTemperature)
        Variance = sqrt(Variance)

        call writeDimlessValueWithError(this%errorsFile, "G00", Average, Variance)

        ! write( IOBuffer, '("G00", T29, "Dimensionless, residual:", 2F20.9)' ) Average, Variance
        ! call FileWrite(this%errorsFile)
        ! call FileWriteBlank(this%errorsFile)
      end if

      ! G10
      Average = - this%SumG10%Average - 2.5_RK*this%RefTemperature
      Variance = this%SumG10%Variance

      call writeDimlessValueWithError(this%errorsFile, "G10", Average, Variance)

      ! G01
      Average = - this%SumG01%Average - 1._RK/this%RefPressure
      Variance = this%SumG01%Variance

      call writeDimlessValueWithError(this%errorsFile, "G01", Average, Variance)

      ! G20
      Average = - this%SumG20%Average + 2.5_RK*this%RefTemperature*this%RefTemperature
      Variance = this%SumG20%Variance

      call writeDimlessValueWithError(this%errorsFile, "G20", Average, Variance)

      ! G02
      Average = - this%SumG02%Average + (1._RK/this%RefPressure)**2
      Variance = this%SumG02%Variance

      call writeDimlessValueWithError(this%errorsFile, "G02", Average, Variance)

      ! G11
      Average = - this%SumG11%Average
      Variance = this%SumG11%Variance

      call writeDimlessValueWithError(this%errorsFile, "G11", Average, Variance)

    end if

    if( EnsembleType .eq. EnsembleTypeNPH .and. LongRange .eq. Rfield ) then
      ! Separator
      write( IOBuffer, '(76("="))' )
      call FileWrite(this%errorsFile)
      call FileWriteBlank(this%errorsFile)

      call writeStatisticalAnalogues(this)

      call writeAverageAndVariance(this%SumS10, "S10", this%errorsFile)

      call writeAverageAndVariance(this%SumS01, "S01", this%errorsFile)

      call writeAverageAndVariance(this%SumS20, "S20", this%errorsFile)

      call writeAverageAndVariance(this%SumS02, "S02", this%errorsFile)

      call writeAverageAndVariance(this%SumS11, "S11", this%errorsFile)

    end if

    methodStringKBI = [character(len=16) :: "RDF", "RDF vdV cor.", "RDF vdV+shf cor."]

    ! thermodynamic factors with KBI
    if( KBIUpdateFrequency > 0 .and. Step >= BlockSizeKBI ) then

        dimensionFactor =  1E-6_RK / (NAvogadro * (UnitLength**3))

        if (this%NRealComponents == 2) then

            ! Thermodynamic factor through KBI

            do iKBImethod = 1, 3

                write(IOBuffer, '("GAMMA11 (", A, ")" , T29, "Dimensionless:", 2F20.9)') &
                    trim(methodStringKBI(iKBImethod)), this%TDF(iKBImethod, 1), this%dTDF(iKBImethod, 1)

                call FileWrite(this%errorsFile)

                write(IOBuffer, '("GAMMA11,0 (", A, ")", T29, "Dimensionless:", 1F20.9)') &
                    trim(methodStringKBI(iKBImethod)), this%TDF0(iKBImethod, 1)

                call FileWrite(this%errorsFile)
                call FileWriteBlank(this%errorsFile)

            end do

            do iKBImethod = 1, 3

                do iComponent = 1, this%NRealComponents

                    write(IOBuffer, '("partial molar volume ", I1, " (", A, ")", T45, "reduced:", 2F20.9)') iComponent, trim(methodStringKBI(iKBImethod)), &
                                                                                this%partialmolV(iKBImethod, iComponent) * dimensionFactor, &
                                                                                this%dpartialmolV(iKBImethod, iComponent) * dimensionFactor
                    call FileWrite(this%errorsFile)

                    write(IOBuffer, '(T44, "in l/mol:", 2F20.9)') 0.001_RK * this%partialmolV(iKBImethod, iComponent), &
                                                                  0.001_RK * this%dpartialmolV(iKBImethod, iComponent)
                    call FileWrite(this%errorsFile)

                    write(IOBuffer, '("partial molar volume ", I1, ",0 (", A, ")", T45, "reduced:", 2F20.9)') iComponent, trim(methodStringKBI(iKBImethod)), &
                                                                                this%partialmolV0(iKBImethod, iComponent) * dimensionFactor, &
                                                                                this%dpartialmolV(iKBImethod, iComponent) * dimensionFactor
                    call FileWrite(this%errorsFile)

                    write(IOBuffer, '(T44, "in l/mol:", 2F20.9)') 0.001_RK * this%partialmolV0(iKBImethod, iComponent), &
                                                                  0.001_RK * this%dpartialmolV(iKBImethod, iComponent)
                    call FileWrite(this%errorsFile)

                end do

            end do

            call FileWriteBlank(this%errorsFile)

        else if (this%NRealComponents == 3) then

            formatString = '(T20, 2F20.9, A, 19X, 2F20.9)'

            ! Thermodynamic factor through KBI
            do iKBImethod = 1, 3

                write(IOBuffer, '("GAMMA_ij (", A, ")", T29, "Dimensionless:")') trim(methodStringKBI(iKBImethod))
                call FileWrite(this%errorsFile)

                write(IOBuffer, formatString) this%TDF(iKBImethod, 1:2), NEW_LINE('A'), this%TDF(iKBImethod, 3:4)
                call FileWrite(this%errorsFile)

                write(IOBuffer, '("dGAMMA_ij (", A, ")", T29, "Dimensionless:")') trim(methodStringKBI(iKBImethod))
                call FileWrite(this%errorsFile)

                write(IOBuffer, formatString) this%dTDF(iKBImethod, 1:2), NEW_LINE('A'), this%dTDF(iKBImethod, 3:4)
                call FileWrite(this%errorsFile)

                write(IOBuffer, '("GAMMA0_ij (", A, ")", T29, "Dimensionless:")') trim(methodStringKBI(iKBImethod))
                call FileWrite(this%errorsFile)

                write(IOBuffer, formatString) this%TDF0(iKBImethod, 1:2), NEW_LINE('A'), this%TDF0(iKBImethod, 3:4)
                call FileWrite(this%errorsFile)

                call FileWriteBlank(this%errorsFile)

            end do

            formatString = '(T44, "in l/mol:", 2F20.9)'

            ! Partial molar volumes through KBI
            do iKBImethod = 1, 3

                do iComponent = 1, this%NRealComponents

                    write(IOBuffer, '("partial molar volume ", I1, " (", A, ")", T45, "reduced:", 2F20.9)') iComponent, trim(methodStringKBI(iKBImethod)), &
                                                                                this%partialmolV(iKBImethod, iComponent) * dimensionFactor, &
                                                                                this%dpartialmolV(iKBImethod, iComponent) * dimensionFactor
                    call FileWrite(this%errorsFile)

                    write(IOBuffer, formatString) 0.001_RK * this%partialmolV(iKBImethod, iComponent), &
                                                  0.001_RK * this%dpartialmolV(iKBImethod, iComponent)
                    call FileWrite(this%errorsFile)

                    write(IOBuffer, '("partial molar volume ", I1, ",0 (", A, ")", T45, "reduced:", 2F20.9)') iComponent, trim(methodStringKBI(iKBImethod)), &
                                                                                this%partialmolV0(iKBImethod, iComponent) * dimensionFactor, &
                                                                                this%dpartialmolV(iKBImethod, iComponent) * dimensionFactor
                    call FileWrite(this%errorsFile)

                    write(IOBuffer, formatString) 0.001_RK * this%partialmolV0(iKBImethod, iComponent), &
                                                  0.001_RK * this%dpartialmolV(iKBImethod, iComponent)
                    call FileWrite(this%errorsFile)

                end do

            end do

            call FileWriteBlank(this%errorsFile)

        else if (this%NRealComponents == 4) then

            formatString = '(T20, 3F20.9, A, 19X, 3F20.9, A, 19X, 3F20.9)'

            do iKBImethod = 1, 3

                write(IOBuffer, '("GAMMA_ij (", A, ")", T29, "Dimensionless:")') trim(methodStringKBI(iKBImethod))
                call FileWrite(this%errorsFile)

                write(IOBuffer, formatString) this%TDF(iKBImethod, 1:3), NEW_LINE('A'), &
                                              this%TDF(iKBImethod, 4:6), NEW_LINE('A'), &
                                              this%TDF(iKBImethod, 7:9)
                call FileWrite(this%errorsFile)

                write(IOBuffer, '("dGAMMA_ij (", A, ")", T29, "Dimensionless:")') trim(methodStringKBI(iKBImethod))
                call FileWrite(this%errorsFile)

                write(IOBuffer, formatString) this%dTDF(iKBImethod, 1:3), NEW_LINE('A'), &
                                              this%dTDF(iKBImethod, 4:6), NEW_LINE('A'), &
                                              this%dTDF(iKBImethod, 7:9)
                call FileWrite(this%errorsFile)

                write(IOBuffer, '("GAMMA0_ij (", A, ")", T29, "Dimensionless:")') trim(methodStringKBI(iKBImethod))
                call FileWrite(this%errorsFile)

                write(IOBuffer, formatString) this%TDF0(iKBImethod, 1:3), NEW_LINE('A'), &
                                              this%TDF0(iKBImethod, 4:6), NEW_LINE('A'), &
                                              this%TDF0(iKBImethod, 7:9)
                call FileWrite(this%errorsFile)

                call FileWriteBlank(this%errorsFile)

            end do

        end if
    end if


    ! Separator
    write( IOBuffer, '(76("="))' )
    call FileWrite(this%errorsFile)
    call FileWriteBlank(this%errorsFile)
! FLAG - FÜR DEN 2VK
    if (EnsembleType .eq. EnsembleTypeNPTSVC) then
    ! Denis (  Flag - kein VLESVC!? EnsembleTypeNPTSVC)

    ! Simulation type
    write( IOBuffer, '("Simulation type", T36, ":", 9X, "Second Virial Coefficient")' )
    call FileWrite(this%errorsFile)

    ! Simulation type
    write( IOBuffer, '("Simulation type", T36, ":", 9X, "Second Virial Coefficient")' )
    call FileWrite(this%errorsFile)
    ! Number of orientations
    write( IOBuffer, '("Number of orientations", T36, ":", I10)' ) NOrient
        call FileWrite(this%errorsFile)
        write( IOBuffer, '("Number of radial steps", T36, ":", I10)' ) NStepsSVC
        call FileWrite(this%errorsFile)
        write( IOBuffer, '("Minimum radius", T29, "reduced:", F20.9)' ) MinRadius
        call FileWrite(this%errorsFile)
        write( IOBuffer, '(T32, "in A:", F20.9)' ) MinRadius * UnitLength / Angstroem
        call FileWrite(this%errorsFile)
        write( IOBuffer, '("Maximum radius", T29, "reduced:", F20.9)' ) MaxRadius
        call FileWrite(this%errorsFile)
        write( IOBuffer, '(T32, "in A:", F20.9)' ) MaxRadius * UnitLength / Angstroem
        call FileWrite(this%errorsFile)
        call FileWriteBlank(this%errorsFile)

        ! Separator
        call writeSeparator(this%errorsFile, noHline = .false., errorColumn = .false.)

        ! Second virial coefficient
        do i = 1, this%NComponents
            do j = i, this%NComponents
                write( IOBuffer, '("2. VC of ", A, "-", A, T29, "reduced:", F20.9)' ) &
&                   trim( this%Component(i)%Molecule%PotModFileName ), &
&                   trim( this%Component(j)%Molecule%PotModFileName ), ArrSVC(i*2-1, j*2, this%EnsembleNumber)
                call FileWrite(this%errorsFile)
                write( IOBuffer, '(T28, "in l/mol:", F20.9)' ) ArrSVC(i*2-1, j*2, this%EnsembleNumber) / UnitDensity
                call FileWrite(this%errorsFile)
            end do

        end do
        call FileWriteBlank(this%errorsFile)

        ! Temperature deviation of second virial coefficient
        do i = 1, this%NComponents
            do j = i, this%NComponents
                write( IOBuffer, '("dB/dT of ", A, "-", A, T29, "reduced:", F20.9)' ) &
&                   trim( this%Component(i)%Molecule%PotModFileName ), &
&                   trim( this%Component(j)%Molecule%PotModFileName ), ArrdBdT(i*2-1, j*2, this%EnsembleNumber)
                call FileWrite(this%errorsFile)
                write( IOBuffer, '(T24, "in l/(mol K):", F20.9)' ) ArrdBdT(i*2-1, j*2, this%EnsembleNumber) / ( UnitDensity * UnitTemperature )
                call FileWrite(this%errorsFile)
            end do
        end do
        call FileWriteBlank(this%errorsFile)

        ! Separator
        write( IOBuffer, '(76("="))' )
        call FileWrite(this%errorsFile)
        call FileWriteBlank(this%errorsFile)

        ! NpT + SVC method.

        ! Creating the initial guess vector for the nonlinear algorithm later
        x_vlesvc(:) = 0.0
        if (this%NComponents == 1) then !initial guess vector for pure fluids x = [0.5]^T.
        x_vlesvc(:) = 0.5
        else
        x_vlesvc(:) = 1/real(this%NComponents)
        end if
        call TEnsemble_vlecalcsvc(x_vlesvc, f, conv, this) ! Call the solver.

       ! Reading the solver results vector, e.g. in a binary mixtures x = [t_sub, y_1]^T
       t_sub = x_vlesvc(1)
       y_vlesvc(:) = 0.0
       do i = 1, this%NComponents-1
       y_vlesvc(i) = x_vlesvc(i+1)
       end do
       y_vlesvc(this%NComponents) = 1-sum(y_vlesvc) !f.e. y_2 = 1-y_1




        ! Calculation of the vapor pressure with NpT + SVC
        VapPressSVC = (this%RefTemperature*(t_sub-1)) / (4*BmixSVCtemp)
        x_vlesvc(1) = VapPressSVC ! returning back for calculation of error
        fehler = 1 !For calculating the error
        call TEnsemble_jacobi (x_vlesvc, f, Jacobian, fehler) !

        ! Reference for the formulas used [Vrabec, Testparticle Method]

        VapPressSVC = x_vlesvc(1) ! Results of the vapor pressure
        VapDensSVC = (SQRT((4*BmixSVCtemp*VapPressSVC/this%RefTemperature)+1) - 1) / (2*BmixSVCtemp) ! Vapor density
        dRhoVapdp = 1 /(this%RefTemperature &
        & *((4*BmixSVCtemp*VapPressSVC)/this%RefTemperature + 1)**(1/2)) ! dRho_vap/dP derivation


       ! Error calculation for the vapor pressure and the vapor mole fraction

       NN = 0._RK
      do i = 1, this%NComponents
         if ( this%NComponents .eq. 1 ) then
           NN = NN + y_vlesvc(i) * 1/this%SumDensity%Average
else
                 NN = NN + y_vlesvc(i) * pc%SumVW%Average
           end if
      end do
      NN = NN - this%RefTemperature / VapPressSVC
      do i = 1, this%NComponents
        pc => this%Component(i)
        dpdmu(i) = -this%RefTemperature * y_vlesvc(i) / NN
        dpdv(i) = -y_vlesvc(i) * (VapPressSVC-this%RefPressure) / NN
        varmu(i) = pc%SumChemPotV%Variance / pc%SumChemPotV%Average
        if ( this%NComponents .eq. 1) then
        varv(i) = (this%SumDensity%Variance*this%SumDensity%Average**2)
        else
        varv(i) = pc%SumVW%Variance
        end if
        end do

      VapPressSVCErr = sqrt( sum( (dpdmu * varmu)**2 ) + sum( (dpdv * varv)**2 ) )
      VapDensSVCErr = sqrt( (VapPressSVCErr*dRhoVapdp)**2)


      do i = 1, this%NComponents
        pc => this%Component(i)
        yvi = y_vlesvc(i) * ( pc%SumVW%Average / this%RefTemperature - 1 / VapPressSVC )
        do j = 1, this%NComponents
          dydmu(i, j) = yvi * dpdmu(j)
          dydv(i, j) = yvi * dpdv(j)
        end do
        dydmu(i, i) = dydmu(i, i) + y_vlesvc(i)
        dydv(i, i) = dydv(i, i) + y_vlesvc(i) * 1 / this%RefTemperature * ( VapPressSVC - this%RefPressure )
      end do

    call TEnsemble_infnan(VapPressSVC, flag) !NaN or Infinity? If yes, no results are possible with NpT + SVC.
    if (flag) then

     write( IOBuffer, '("VLE calculated with the NpT + SVC method")' )
       call FileWrite(this%errorsFile)
       call FileWriteBlank(this%errorsFile)
       call writeSeparator(this%errorsFile, noHline = .false., errorColumn = .true.)

      ! Simulation temperature
      write( IOBuffer, '("Simulation temperature", T29, "reduced:", F20.9)' ) this%RefTemperature
      call FileWrite(this%errorsFile)
      write( IOBuffer, '(T32, "in K:", F20.9)' ) this%Temperature * UnitTemperature
      call FileWrite(this%errorsFile)
      call FileWriteBlank(this%errorsFile)

       ! Mole fractions of liquid phase
     if (this%NComponents .ge. 2) then
      do i = 1, this%NComponents
        pc => this%Component(i)
        write( IOBuffer, '("Liquid mole fraction of ", A, T36, ":", F20.9)' ) &
&              trim( pc%Molecule%PotModFileName ), pc%Fraction
        call FileWrite(this%errorsFile)
      end do
      call FileWriteBlank(this%errorsFile)
      end if


       ! Simulation pressure of liquid phase
      write( IOBuffer, '("Liquid simulation pressure", T29, "reduced:", F20.9)' ) this%RefPressure
      call FileWrite(this%errorsFile)
      write( IOBuffer, '(T30, "in MPa:", F20.9)' ) this%RefPressure * UnitPressure * 1e-6_RK
      call FileWrite(this%errorsFile)
      call FileWriteBlank(this%errorsFile)

      ! Liquid density.

      Average = this%SumDensity%Average + this%SumDensity%Average * this%SumBetaT%Average * ( VapPressSVC - this%RefPressure)
      Variance = sqrt( this%SumDensity%Variance**2 + ( this%SumBetaT%Variance * ( VapPressSVC - this%RefPressure )&
&                + VapPressSVCErr * this%SumBetaT%Average )**2 )

      dimensionFactor = UnitDensity

      call writeValue("Liquid density", Average, Variance, dimensionFactor, "mol/l", this%errorsFile)

       ! Vapor pressure

       dimensionFactor = UnitPressure * 1E-6_RK

       call writeValue("Vapor pressure", VapPressSVC, VapPressSVCErr, dimensionFactor, "MPa", this%errorsFile)

       ! Vapor mole fraction

       if (this%NComponents .ge. 2) then

        do i = 1, (this%NComponents - 1)
        pc => this%Component(i)
        vary(i) = sqrt( sum( (dydmu(i, :) * varmu)**2 ) + sum( (dydv(i, :) * varv)**2 ) )
        write( IOBuffer, '("Vapor mole fraction of ", A, T36, ":", 2F20.9)' ) &
&              trim( pc%Molecule%PotModFileName ), y_vlesvc(i), vary(i)
        call FileWrite(this%errorsFile)
      end do

      pc => this%Component( this%NComponents )
      Variance = sqrt( sum( vary(1:(this%NComponents - 1))**2 ) )
      write( IOBuffer, '("Vapor mole fraction of ", A, T36, ":", 2F20.9)' ) &
&            trim( pc%Molecule%PotModFileName ), y_vlesvc(i), Variance
      call FileWrite(this%errorsFile)
      call FileWriteBlank(this%errorsFile)
 end if
        ! Vapor density.

       dimensionFactor = UnitDensity

       call writeValue("Vapor density", VapDensSVC, VapDensSVCErr, dimensionFactor, "mol/l", this%errorsFile)


    ! Saturated liquid enthalpy.
      Average = this%SumEnthalpy%Average + this%SumdHdP%Average * ( VapPressSVC - this%RefPressure )

      Variance = sqrt( this%SumEnthalpy%Variance**2 + ( this%SumdHdP%Variance * &
&                ( VapPressSVC - this%RefPressure ) + VapPressSVCErr * this%SumdHdP%Average )**2 )

      dimensionFactor = UnitEnergy * NAvogadro

      call writeValue("Liquid enthalpy", Average, Variance, dimensionFactor, "J/mol", this%errorsFile)

      DeltaHv = Average
      VarDeltaHv = Variance

      ! Saturated vapor enthalpy
      Average = (this%RefTemperature* VapDensSVC* BmixSVCtemp) - &
&     (this%RefTemperature* this%RefTemperature * VapDensSVC*dBdTmixtemp)
      Variance = sqrt( ( (BmixSVCtemp*this%RefTemperature -  &
&     dBdTmixtemp*this%RefTemperature*this%RefTemperature)* VapDensSVCErr )**2 )

      dimensionFactor = UnitEnergy * NAvogadro

      call writeValue("Vapor enthalpy", Average, Variance, dimensionFactor, "J/mol", this%errorsFile)

      DeltaHv = Average - DeltaHv
      VarDeltaHv = Variance + VarDeltaHv

      ! Evaporation enthalpy

      dimensionFactor = UnitEnergy * NAvogadro

      call writeValue("Enthalpy of vaporization", DeltaHv, VarDeltaHv, dimensionFactor, "J/mol", this%errorsFile)

      ! Ratio of compressibility factors
      z_calc = VapPressSVC / (VapDensSVC * this%RefTemperature)
      z_lim = -1 / ( 4 * BMixSVCtemp * VapDensSVC)
      write( IOBuffer, '("Compressibility factor ratio", T36, ":", F20.9)' ) z_calc / z_lim
      call FileWrite(this%errorsFile)
      call FileWriteBlank(this%errorsFile)


    ! Mixture second virial coefficient at equilibrium
        if (this%NComponents .ge. 2 ) then

        write( IOBuffer, '("2. VC of mixture", T29, "reduced:", F20.9)' ) BmixSVCtemp
       call FileWrite(this%errorsFile)
       write( IOBuffer, '(T28, "in l/mol:", F20.9)' ) BmixSVCtemp / UnitDensity
             call FileWrite(this%errorsFile)
       call FileWriteBlank(this%errorsFile)

            write( IOBuffer, '("dB/dT of mixture", T29, "reduced:", F20.9)' ) dBdTmixtemp
       call FileWrite(this%errorsFile)
       write( IOBuffer, '(T28, "in l/mol:", F20.9)' ) dBdTmixtemp / (UnitDensity * UnitTemperature)
             call FileWrite(this%errorsFile)
       call FileWriteBlank(this%errorsFile)

        end if


  ! Separator
       call FileWriteBlank(this%errorsFile)
       write( IOBuffer, '(76("="))' )
       call FileWrite(this%errorsFile)
       call FileWriteBlank(this%errorsFile)
    endif

end if

#if HBOND > 0
    do i = 1, this%NComponents
      Average = this%SumHBond0(i)%Average
      Variance = this%SumHBond0(i)%Variance
      write( IOBuffer, '("HBond0 of [", I2, "]", T36, ":", 2F20.9)' ) i, Average, Variance
      call FileWrite(this%errorsFile)
    end do

    do i = 1, this%NComponents
      do  j = 1, this%NComponents
        Average = this%SumHBond1(i,j)%Average
        Variance = this%SumHBond1(i,j)%Variance
        write( IOBuffer, '("HBond1 of [", I2, "] with (", I2, ")", T36, ":", 2F20.9)' ) i, j, Average, Variance
        call FileWrite(this%errorsFile)
      end do
    end do

    do i = 1, this%NComponents
      do  j = 1, this%NComponents
        do k = j, this%NComponents
          Average = this%SumHBond2(i,j,k)%Average
          Variance = this%SumHBond2(i,j,k)%Variance
          write( IOBuffer, '("HBond2 of [", I2, "] with (", I2, ",", I2, ")", T36, ":", 2F20.9)' ) i, j, k, Average, Variance
          call FileWrite(this%errorsFile)
        end do
      end do
    end do

    do i = 1, this%NComponents
      do  j = 1, this%NComponents
        do k = j, this%NComponents
          do  l = k, this%NComponents
            Average = this%SumHBond3(i,j,k,l)%Average
            Variance = this%SumHBond3(i,j,k,l)%Variance
            write( IOBuffer, '("HBond3 of [", I2, "] with (", I2, ",", I2, ",", I2, ")", T36, ":", 2F20.9)' ) i, j, k, l, Average, Variance
            call FileWrite(this%errorsFile)
          end do
        end do
      end do
    end do

    do i = 1, this%NComponents
      do  j = 1, this%NComponents
        do k = j, this%NComponents
          do l = k, this%NComponents
            do m = l, this%NComponents
              Average = this%SumHBond4(i,j,k,l,m)%Average
              Variance = this%SumHBond4(i,j,k,l,m)%Variance
              write( IOBuffer, '("HBond4 of [", I2, "] with (", I2, ",", I2, ",", I2, ",", I2, ")", T36, ":", 2F20.9)' ) i, j, k, l, m, Average, Variance
              call FileWrite(this%errorsFile)
            end do
          end do
        end do
      end do
    end do

    do i = 1, this%NComponents
      Average = this%SumHBondN(i)%Average
      Variance = this%SumHBondN(i)%Variance
      write( IOBuffer, '("HBond5+ of [", I2, "]", T36, ":", 2F20.9)' ) i, Average, Variance
      call FileWrite(this%errorsFile)
    end do
    call FileWriteBlank(this%errorsFile)

    ! Separator
    write( IOBuffer, '(76("="))' )
    call FileWrite(this%errorsFile)
    call FileWriteBlank(this%errorsFile)
#endif

#if  TRANS == 1
    ! Transport properties
    if ( this%CorrfunMode ) Then

      write( IOBuffer, '(T24, "TRANSPORT PROPERTIES")' )

      call writeSeparator(this%errorsFile, noHline = .true., errorColumn = .true.)

      write( IOBuffer, '("Number of Corr. Funct.", T36, ":",T45, I8 )' ) this%Mmess
      call FileWrite(this%errorsFile)
      call FileWriteBlank(this%errorsFile)

      value = this%NCorr*this%TimeStepCorr
      write( IOBuffer, '("Length of Corr. Funct.", T29, "reduced:", F20.9)' ) value
      call FileWrite(this%errorsFile)

      write( IOBuffer, '(T31, "in ps:", F20.9)' )  value*UnitTime/1E-12_RK
      call FileWrite(this%errorsFile)
      call FileWriteBlank(this%errorsFile)

      value = this%NSpanCF*this%TimeStepCorr
      write( IOBuffer, '("Time span between CF ", T29, "reduced:", F20.9)' ) value
      call FileWrite(this%errorsFile)

      write( IOBuffer, '(T31, "in ps:", F20.9)' )  value*UnitTime/1E-12_RK
      call FileWrite(this%errorsFile)
      call FileWriteBlank(this%errorsFile)


      if ( this%Mmess > 0 ) then

        ! Error update for transport properties
        if( mod( ((Step-1)/this%NStepCorr) - this%NCorr + 1, BlockSizeCF * this%NSpanCF ) == 0 .and. NBlockSizesCF >= 2) then

          if ( this%NComponents > 1 ) then
            if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
              do i = 1, this%NComponents
                do j = 1, this%NComponents
                  call Error(this%SumOnsager(i,j), .true.)
                end do
              end do
            end if
            do i = 1, this%NComponents
              call Error(this%SumSoret(i), .true.)
            end do
          end if !this%NComponents > 1

          if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
            do i = 1, this%NComponents
              call Error(this%Sumself_i(i), .true.)
            end do
            call Error(this%SumVisco_s, .true.)
          end if

          call Error(this%SumVisco_b, .true.)
          call Error(this%SumConduct, .true.)
          call Error(this%SumEConduct,.true.)

        end if

        do i = 1, this%NComponents
           x(i) = this%Component(i)%Fraction
           Inv_x(i) = 1._RK/x(i)
        end do

        ! Onsager coefficients
        if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
          if ( this%NComponents > 1 ) then
            do i = 1, this%NComponents
              do j = 1, this%NComponents
                Average  = this%SumOnsager(i,j)%Average
                Variance = this%SumOnsager(i,j)%Variance
                value = dsqrt(UnitEnergy/UnitMass)*UnitLength/1E-10_RK
                write( IOBuffer, '("Onsager-diff. coeff.",2I2,T29, "reduced:", 2F20.9)' ) i,j,Average, Variance
                call FileWrite(this%errorsFile)
                write( IOBuffer, '(T22, "in 1E-10 m^2/s:", 2F20.9)' ) Average*value, Variance*value
                call FileWrite(this%errorsFile)
              end do
            end do
            call FileWriteBlank(this%errorsFile)

            do i = 1, this%NComponents
              do  j = 1, this%NComponents
                 if (i ==j) then
                  L(i,j) = this%SumOnsager(i,j)%Average
                 else
                  L(i,j) = (this%SumOnsager(i,j)%Average + this%SumOnsager(j,i)%Average)/2._RK
                 end if
              end do
            end do
          end if !this%NComponents
        end if


        !binary diffusion and thermal diffusion
        if( this%NComponents == 2  ) then
          value = dsqrt(UnitEnergy/UnitMass)*UnitLength/1E-10_RK

          if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
            D_12 = L(1,1) * x(2)*Inv_x(1) + L(2,2) * x(1)*Inv_x(2) - L(1,2) - L(2,1)
            err_D12 = this%SumOnsager(1,1)%Variance * x(2)*Inv_x(1) + &
&                     this%SumOnsager(2,2)%Variance * x(1)* Inv_x(2) + &
&                     this%SumOnsager(1,2)%Variance + this%SumOnsager(2,1)%Variance

            call writeValue("Binary diff. coeff.", D_12, err_D12, value, "1E-10 m^2/s", this%errorsFile)

          end if

          if (this%MolarEnthConduct) then

            mw = this%Component(1)%Molecule%Mass*this%Component(1)%Fraction + this%Component(2)%Molecule%Mass*this%Component(2)%Fraction
            w1 = this%Component(1)%Molecule%Mass*this%Component(1)%Fraction/mw
            w2 = this%Component(2)%Molecule%Mass*this%Component(2)%Fraction/mw
            nc = this%density*mw

            Average  = this%SumSoret(1)%Average
            Variance = this%SumSoret(1)%Variance
            factor = 1._RK/(this%temperature*this%temperature*w1*w2*nc)
            value = dsqrt(UnitEnergy/UnitMass)*UnitLength/(UnitTemperature*1E-12_RK)
            write( IOBuffer, '("Thermal diff. coeff",A, T29, "reduced:", 2F20.9)' ) trim(this%Component(1)%Molecule%PotModFileName), Average*factor, Variance*factor
            call FileWrite(this%errorsFile)
            write( IOBuffer, '(T17, "in 10E-12 m^2/(K s):", 2F20.9)' ) Average*value*factor, Variance*value*factor
            call FileWrite(this%errorsFile)
            call FileWriteBlank(this%errorsFile)
          else
            write( IOBuffer, '("Thermal diffusivity requires the partial molar enthalpies of all components")' )
            call FileWrite(this%errorsFile)
            call FileWriteBlank(this%errorsFile)
          end if  !this%MolarEnthConduct

        end if !this components = 2


        ! Ternary and Quaternary diffusion
        if(( this%NComponents == 3 ) .or. ( this%NComponents == 4 )) then
           if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then

             !obtain matrix [delta] Equations 48 to 55 from Supplementary material
             !Krishna and van Baten, Ind. Eng. Chem. Res., 2005, 44 (17), pp 6939

             delta(:,:) = 0._RK
             do i=1, (this%NComponents-1)
               do j =1, (this%NComponents-1)
                 delta(i,j) = (1._RK-x(i))*(L(i,j)*Inv_x(j)-L(i,this%NComponents)*Inv_x(this%NComponents))
                 do k = 1, this%NComponents
                   if (k /= i) then
                     delta(i,j) = delta(i,j) - x(i)* (L(k,j)*Inv_x(j)-L(k,this%NComponents)*Inv_x(this%NComponents))
                   end if
                 end do
               end do
             end do

             !calculate variance by error propagation
             err_delta(:,:) = 0._RK
             do i=1, (this%NComponents-1)
               do j =1, (this%NComponents-1)
                 err_delta(i,j) = (1._RK-x(i))*Inv_x(j)*this%SumOnsager(i,j)%Variance + (1._RK-x(i))*Inv_x(this%NComponents)*this%SumOnsager(i,this%NComponents)%Variance
                 do k = 1, this%NComponents
                   if (k /= i) then
                     err_delta(i,j) = err_delta(i,j) + x(i)*Inv_x(j)*this%SumOnsager(k,j)%Variance + x(i)*Inv_x(this%NComponents)*this%SumOnsager(k,this%NComponents)%Variance
                   end if
                 end do
               end do
             end do
!        end if

           !Ternary diffusion
             if( this%NComponents == 3 ) then
               value = dsqrt(UnitEnergy/UnitMass)*UnitLength/1E-10_RK

               ! determinat of matrix [delta]
               det = (delta(1,1)*delta(2,2))-(delta(1,2)*delta(2,1))
               inv_det = 1._RK/det

               !obtain matrix [B] so that [B]=[D]-1
               B(1,1) =  inv_det* delta(2,2) !B1
               B(1,2) =  inv_det*(-delta(1,2)) !B2
               B(2,1) =  inv_det*(-delta(2,1)) !B3
               B(2,2) =  inv_det* delta(1,1) !B4

               !Obtain Error matrix B (from Propagation of Errors for Matrix Inversion,
               !Lefebvre et al.Nucl.Instrm.Meth. A451 (2000) 520-528)

               err_B(:,:) = 0._RK

               do k = 1, (this%NComponents-1)
                 do m = 1, (this%NComponents-1)
                   do i = 1, (this%NComponents-1)
                     do  j = 1, (this%NComponents-1)
                       err_B(k,m) = err_B(k,m) + ABS(B(k,i)*B(j,m))*err_delta(i,j)
                     end do
                   end do
                 end do
               end do

               !Calculate diffusion coefficients
               D_13 =  1._RK  / ( (B(1,1)) + ( x(2)* B(1,2) * Inv_x(1)) )
               D_12 =  1._RK  / ( (B(1,1)) - ( (x(1) + x(3)) * B(1,2) *Inv_x(1)))
               D_23 =  1._RK  / ( (B(2,2)) + ( x(1)* B(2,1) * Inv_x(2)))

               !Obtain error of Diffusion coefficients
               err_D13 = ABS(1._RK/((x(2)*Inv_x(1)*B(1,2)+B(1,1))**2))*err_B(1,1) + &
&                        ABS(x(2)*Inv_x(1)/((B(1,1)+x(2)*Inv_x(1)*B(1,2))**2))*err_B(1,2)
               err_D12 = ABS(1._RK/((B(1,1)-((x(1)+x(3))*Inv_x(1)*B(1,2)))**2))*err_B(1,1) + &
&                        ABS(((x(1)+x(3))*Inv_x(1))/((B(1,1)-((x(1)+x(3))*Inv_x(1)*B(1,2)))**2))*err_B(1,2)
               err_D23 = ABS(1._RK/((x(1)*Inv_x(2)*B(2,1)+B(2,2))**2))*err_B(2,2) + &
&                        ABS(x(1)*Inv_x(2)/((B(2,2)+x(1)*Inv_x(2)*B(2,1))**2))*err_B(2,1)

               call writeValue("Ternary diff. coeff. 1 2", D_12, err_D12, value, "1E-10 m^2/s", this%errorsFile)

               call writeValue("Ternary diff. coeff. 1 3", D_13, err_D13, value, "1E-10 m^2/s", this%errorsFile)

               call writeValue("Ternary diff. coeff. 2 3", D_23, err_D23, value, "1E-10 m^2/s", this%errorsFile)

             end if !this%NComponents == 3


             if ( this%NComponents == 4 ) then

               value = dsqrt(UnitEnergy/UnitMass)*UnitLength/1E-10_RK

               ! determinat of matrix [delta]
               det = (delta(1,1)*delta(2,2)*delta(3,3))+(delta(2,1)*delta(3,2)*delta(1,3))+(delta(3,1)*delta(1,2)*delta(2,3))-&
&                    (delta(1,1)*delta(3,2)*delta(2,3))-(delta(3,1)*delta(2,2)*delta(1,3))-(delta(2,1)*delta(1,2)*delta(3,3))

               inv_det = 1._RK/det

               !obtain matrix [B] so that [B]=[D]-1
               B(1,1) =  inv_det* (delta(2,2)*delta(3,3)-delta(2,3)*delta(3,2)) !B1
               B(1,2) =  inv_det* (delta(1,3)*delta(3,2)-delta(1,2)*delta(3,3)) !B2
               B(1,3) =  inv_det* (delta(1,2)*delta(2,3)-delta(1,3)*delta(2,2))
               B(2,1) =  inv_det* (delta(2,3)*delta(3,1)-delta(2,1)*delta(3,3))
               B(2,2) =  inv_det* (delta(1,1)*delta(3,3)-delta(1,3)*delta(3,1))
               B(2,3) =  inv_det* (delta(1,3)*delta(2,1)-delta(1,1)*delta(2,3))
               B(3,1) =  inv_det* (delta(2,1)*delta(3,2)-delta(2,2)*delta(3,1))
               B(3,2) =  inv_det* (delta(1,2)*delta(3,1)-delta(1,1)*delta(3,2))
               B(3,3) =  inv_det* (delta(1,1)*delta(2,2)-delta(1,2)*delta(2,1))

              !Obtain Error matrix B (from Propagation of Errors for Matrix Inversion,
              !Lefebvre et al.Nucl.Instrm.Meth. A451 (2000) 520-528)

               err_B(:,:) = 0._RK

               do k = 1, (this%NComponents-1)
                 do m = 1, (this%NComponents-1)
                   do i = 1, (this%NComponents-1)
                     do  j = 1, (this%NComponents-1)
                       err_B(k,m) = err_B(k,m) + ABS(B(k,i)*B(j,m))*err_delta(i,j)
                     end do
                   end do
                 end do
               end do

               !Calculate diffusion coefficients
               D_14 =  1._RK  / ( (B(1,1)) + ( x(2)* B(1,2) * Inv_x(1)) + (x(3) * B(1,3)* Inv_x(1)) )
               D_24 =  1._RK  / ( (B(2,2)) + ( x(1)* B(2,1) * Inv_x(2)) + (x(3) * B(2,3)* Inv_x(2)) )
               D_34 =  1._RK  / ( (B(3,3)) + ( x(1)* B(3,1) * Inv_x(3)) + (x(2) * B(3,2)* Inv_x(3)) )
               D_12 =  1._RK  / ( (1._RK/D_24) - (B(2,1)*Inv_x(2)))
               D_13 =  1._RK  / ( (1._RK/D_14) - (B(1,3)*Inv_x(1)))
               D_23 =  1._RK  / ( (1._RK/D_24) - (B(2,3)*Inv_x(2)))


               !Obtain error of Diffusion coefficients
               err_D14 = ABS(1._RK/(((B(1,1)) + ( x(2)* B(1,2) * Inv_x(1)) + (x(3) * B(1,3)* Inv_x(1)) )**2))*err_B(1,1) + &
                         ABS(x(2)*Inv_x(1)/(((B(1,1)) + ( x(2)* B(1,2) * Inv_x(1)) + (x(3) * B(1,3)* Inv_x(1)) )**2))*err_B(1,2) + &
                         ABS(x(3)*Inv_x(1)/(((B(1,1)) + ( x(2)* B(1,2) * Inv_x(1)) + (x(3) * B(1,3)* Inv_x(1)) )**2))*err_B(1,3)

               err_D24 = ABS(1._RK/(((B(2,2)) + ( x(1)* B(2,1) * Inv_x(2)) + (x(3) * B(2,3)* Inv_x(2)) )**2))*err_B(2,2) + &
                         ABS(x(1)*Inv_x(2)/(((B(2,2)) + ( x(1)* B(2,1) * Inv_x(2)) + (x(3) * B(2,3)* Inv_x(2)) )**2))*err_B(2,1) + &
                         ABS(x(3)*Inv_x(2)/(((B(2,2)) + ( x(1)* B(2,1) * Inv_x(2)) + (x(3) * B(2,3)* Inv_x(2)) )**2))*err_B(2,3)

               err_D34 = ABS(1._RK/(((B(3,3)) + ( x(1)* B(3,1) * Inv_x(3)) + (x(2) * B(3,2)* Inv_x(3)) )**2))*err_B(3,3) + &
                         ABS(x(1)*Inv_x(3)/(((B(3,3)) + ( x(1)* B(3,1) * Inv_x(3)) + (x(2) * B(3,2)* Inv_x(3)) )**2))*err_B(3,1) + &
                         ABS(x(2)*Inv_x(3)/(((B(3,3)) + ( x(1)* B(3,1) * Inv_x(3)) + (x(2) * B(3,2)* Inv_x(3)) )**2))*err_B(3,2)

               err_D12 = ABS(1._RK/(((B(2,2)) + ( (x(1)-1._RK)* B(2,1) * Inv_x(2)) + (x(3) * B(2,3)* Inv_x(2)) )**2))*err_B(2,2) + &
                         ABS((x(1)-1._RK)*Inv_x(2)/(((B(2,2)) + ( (x(1)-1._RK)* B(2,1) * Inv_x(2)) + (x(3) * B(2,3)* Inv_x(2)) )**2))*err_B(2,1) + &
                         ABS(x(3)*Inv_x(2)/(((B(2,2)) + ( (x(1)-1._RK)* B(2,1) * Inv_x(2)) + (x(3) * B(2,3)* Inv_x(2)) )**2))*err_B(2,3)

               err_D13 = ABS(1._RK/(((B(1,1)) + ( x(2)* B(1,2) * Inv_x(1)) + ((x(3)-1._RK) * B(1,3)* Inv_x(3)) )**2))*err_B(1,1) + &
                         ABS(x(2)*Inv_x(1)/(((B(1,1)) + ( x(2)* B(1,2) * Inv_x(1)) + ((x(3)-1._RK) * B(1,3)* Inv_x(3)) )**2))*err_B(1,2) + &
                         ABS((x(3)-1._RK)*Inv_x(1)/(((B(1,1)) + ( x(2)* B(1,2) * Inv_x(1)) + ((x(3)-1._RK) * B(1,3)* Inv_x(3)) )**2))*err_B(1,3)

               err_D23 = ABS(1._RK/(((B(2,2)) + ( x(1)* B(2,1) * Inv_x(2)) + ((x(3)-1._RK) * B(2,3)* Inv_x(2)) )**2))*err_B(2,2) + &
                         ABS(x(1)*Inv_x(2)/(((B(2,2)) + ( x(1)* B(2,1) * Inv_x(2)) + ((x(3)-1._RK) * B(2,3)* Inv_x(2)) )**2))*err_B(2,1) + &
                         ABS((x(3)-1._RK)*Inv_x(2)/(((B(2,2)) + ( x(1)* B(2,1) * Inv_x(2)) + ((x(3)-1._RK) * B(2,3)* Inv_x(2)) )**2))*err_B(2,3)

               call writeValue("Quat. diff. coeff. 1 2", D_12, err_D12, value, "1E-10 m^2/s", this%errorsFile)

               call writeValue("Quat. diff. coeff. 1 3", D_13, err_D13, value, "1E-10 m^2/s", this%errorsFile)

               call writeValue("Quat. diff. coeff. 1 4", D_14, err_D14, value, "1E-10 m^2/s", this%errorsFile)

               call writeValue("Quat. diff. coeff. 2 3", D_23, err_D23, value, "1E-10 m^2/s", this%errorsFile)

               call writeValue("Quat. diff. coeff. 2 4", D_24, err_D24, value, "1E-10 m^2/s", this%errorsFile)

               call writeValue("Quat. diff. coeff. 3 4", D_34, err_D34, value, "1E-10 m^2/s", this%errorsFile)

             end if !this%NComponents == 4
           end if !TransMethod GreenKubo
        end if !NComponents = 3 or 4

        !self-diffusion coefficient
        if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
          do i = 1, this%NComponents
            Average  = this%Sumself_i(i)%Average
            Variance = this%Sumself_i(i)%Variance
            value = dsqrt(UnitEnergy/UnitMass)*UnitLength/1E-10_RK
            write( IOBuffer, '("Self-diff. coeff. ",A ,T29, "reduced:", 2F20.9)' )  &
&                trim( this%Component(i)%Molecule%PotModFileName ), Average, Variance
            call FileWrite(this%errorsFile)
            write( IOBuffer, '(T22, "in 1E-10 m^2/s:", 2F20.9)' ) Average*value, Variance*value
            call FileWrite(this%errorsFile)
          end do
          call FileWriteBlank(this%errorsFile)

          !shear viscosity
          Average  = this%SumVisco_s%Average
          Variance = this%SumVisco_s%Variance
          value = dsqrt(UnitEnergy*UnitMass)/UnitLength**2/1E-4_RK

          call writeValue("Shear viscosity    ", Average, Variance, value, "1E-4 Pa s", this%errorsFile)

         end if

        !bulk viscosity
        if (this%Bulkviscosity ) then
          Average  = this%SumVisco_b%Average
          Variance = this%SumVisco_b%Variance
          write( IOBuffer, '("Bulk viscosity    ", T29, "reduced:", 2F20.9)' ) Average, Variance
          call FileWrite(this%errorsFile)
          write( IOBuffer, '(T24, "in 1E-4 Pa s:", 2F20.9)' ) Average*value, Variance*value
          call FileWrite(this%errorsFile)
          call FileWriteBlank(this%errorsFile)
        else
          write( IOBuffer, '("Bulk viscosity only defined for the NVE ensemble")' )
          call FileWrite(this%errorsFile)
          call FileWriteBlank(this%errorsFile)
        end if

        !Thermal conductivity

        if (LongRange .eq. Rfield)then
          Average  = this%SumConduct%Average
          Variance = this%SumConduct%Variance
          factor   = 1._RK/(this%Temperature*this%Temperature)
          value    = dsqrt(UnitEnergy/UnitMass)*kBoltzmann/UnitLength**2

          write( IOBuffer, '("Thermal conductivity ", T29, "reduced:", 2F20.9)' ) Average*factor, Variance*factor
          call FileWrite(this%errorsFile)
          write( IOBuffer, '(T23, "in W / (m K) :", 2F20.9)' ) Average*value*factor, Variance*value*factor
          call FileWrite(this%errorsFile)
!          call FileWriteBlank(this%errorsFile)
          if (this%NComponents > 1 ) then
            if (this%MolarEnthConduct) then
              write( IOBuffer, '("Note: Thermal conductivity includes the enthalpic contribution")')
              call FileWrite(this%errorsFile)
            else
              write( IOBuffer, '("Note: Thermal conductivity was calculated without the enthalpic contribution")' )
              call FileWrite(this%errorsFile)
            end if
          end if
        else
          write( IOBuffer, '("Thermal conductivity only implemented for Reaction field")' )
          call FileWrite(this%errorsFile)
        end if
        call FileWriteBlank(this%errorsFile)

        !Electric conductivity
        Average  = this%SumEConduct%Average
        Variance = this%SumEConduct%Variance
        value = ElementaryCharge**2 / (dsqrt(UnitEnergy*UnitMass) * UnitLength**2)
        if (this%EConductivity) then
          write( IOBuffer, '("Electric conductivity ", T29, "reduced:", 2F20.9)' ) Average, Variance
          call FileWrite(this%errorsFile)
          write( IOBuffer, '(T23, "in 1 / (Ohm m):", 2F20.9)' ) Average*value, Variance*value
        else
          write( IOBuffer, '("Electric conductivity only defined for charged particles")' )
        end if
        call FileWrite(this%errorsFile)
        call FileWriteBlank(this%errorsFile)

         ! Onsager coefficients
        if ( this%NComponents > 1 ) then
          if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
            do i = 1, this%NComponents
              Average  = this%SumOnsager(i,i)%Average
              Variance = this%SumOnsager(i,i)%Variance
              factor = this%density*this%Component(i)%Molecule%Mass* this%Component(i)%Molecule%Mass
              value = UnitTemperature*UnitMass*UnitTime/(1E-10_RK*UnitLength**3)
              write( IOBuffer, '("Mass coefficient Lii",2I2,T29, "reduced:", 2F20.9)' ) i,i,Average*factor, Variance*factor
              call FileWrite(this%errorsFile)
              write( IOBuffer, '(T16, "in 10E-10 Kg K s/m^3:", 2F20.9)' ) Average*factor*value, Variance*factor*value
              call FileWrite(this%errorsFile)
            end do
            call FileWriteBlank(this%errorsFile)
          end if

          Average  = this%SumConduct%Average
          Variance = this%SumConduct%Variance
          value = dsqrt(UnitEnergy/UnitMass)*kBoltzmann*UnitTemperature*UnitTemperature/UnitLength**2
          if (this%MolarEnthConduct) then
             write( IOBuffer, '("Energy coefficient LQQ ", T29, "reduced:", 2F20.9)' ) Average, Variance
             call FileWrite(this%errorsFile)
             write( IOBuffer, '(T26, "in W K/ m :", 2F20.9)' ) Average*value, Variance*value
             call FileWrite(this%errorsFile)
             call FileWriteBlank(this%errorsFile)
             do i = 1, this%NComponents
               Average  = this%SumSoret(i)%Average
               Variance = this%SumSoret(i)%Variance
               value = dsqrt(UnitEnergy/UnitMass)*UnitMass*UnitTemperature/(1E-6_RK*UnitLength**2)
               write( IOBuffer, '("Cross coefficient LiQ",I2, T29, "reduced:", 2F20.9)' )i,Average, Variance
               call FileWrite(this%errorsFile)
               write( IOBuffer, '(T16, "in 10E-6 Kg K/(m s) :", 2F20.9)' ) Average*value, Variance*value
               call FileWrite(this%errorsFile)
               call FileWriteBlank(this%errorsFile)
             end do
          else

             call writeValue("Energy coefficient LEE ", Average, Variance, value, "W K/ m ", this%errorsFile)

             do i = 1, this%NComponents
               Average  = this%SumSoret(i)%Average
               Variance = this%SumSoret(i)%Variance
               value = dsqrt(UnitEnergy/UnitMass)*UnitMass*UnitTemperature/(1E-6_RK*UnitLength**2)
               write( IOBuffer, '("Cross coefficient LiE", I2, T29, "reduced:", 2F20.9)' ) i, Average, Variance
               call FileWrite(this%errorsFile)
               write( IOBuffer, '(T16, "in 10E-6 Kg K/(m s) :", 2F20.9)' ) Average*value, Variance*value
               call FileWrite(this%errorsFile)
               call FileWriteBlank(this%errorsFile)
             end do
             write( IOBuffer, '("Note: LEE and LiE do not include the enthalpic contribution")' )
             call FileWrite(this%errorsFile)
             call FileWriteBlank(this%errorsFile)
          end if  !this%MolarEnthConduct

        end if !this%NComponents > 1


      else    ! ( this%Mmess > 0 )

         !Onsager coefficients
        if ( this%NComponents > 1 ) then
           if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
             do i = 1, this%NComponents
               do j = 1, this%NComponents
                 write( IOBuffer, '("Onsager-diff. coeff.",2I2,T29, "reduced:", 2F20.9)' ) i,j,0._RK
                 call FileWrite(this%errorsFile)
                 write( IOBuffer, '(T22, "in 1E-10 m^2/s:", 2F20.9)' ) 0._RK
                 call FileWrite(this%errorsFile)
               end do
             end do
             call FileWriteBlank(this%errorsFile)

             if ( this%NComponents==2 ) then
               write( IOBuffer, '("Binary diff. coeff.", T29, "reduced:", F20.9)' ) 0._RK
               call FileWrite(this%errorsFile)
               write( IOBuffer, '(T22, "in 1E-10 m^2/s:", F20.9)' )  0._RK
               call FileWrite(this%errorsFile)
               call FileWriteBlank(this%errorsFile)
             end if  !Ncomponents ==2
           end if !TransMethod

           !Thermal diff. coeff.
           if ( this%NComponents==2 ) then
             if (this%MolarEnthConduct) then
               write( IOBuffer, '("Thermal diff. coeff.", A, T29, "reduced:", F20.9)' ) trim(this%Component(1)%Molecule%PotModFileName), 0._RK
               call FileWrite(this%errorsFile)
               write( IOBuffer, '(T18, "in 1E-12 m^2/(K s):", F20.9)' ) 0._RK
               call FileWrite(this%errorsFile)
               call FileWriteBlank(this%errorsFile)
             else
               write( IOBuffer, '("Thermal diffusivity requires the partial molar enthalpies of all components")' )
               call FileWrite(this%errorsFile)
               call FileWriteBlank(this%errorsFile)
             end if
           end if !this%NComponents==2

           !ternary diffusion coefficient
           if( this%NComponents == 3 ) then
             if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
               write( IOBuffer, '("Ternary diff. coeff. 1 3", T29, "reduced:", 2F20.9)') 0._RK
               call FileWrite(this%errorsFile)
               write( IOBuffer, '(T22, "in 1E-10 m^2/s:", 2F20.9)' ) 0._RK
               call FileWrite(this%errorsFile)
               call FileWriteBlank(this%errorsFile)
               write( IOBuffer, '("Ternary diff. coeff. 1 2", T29, "reduced:", 2F20.9)' ) 0._RK
               call FileWrite(this%errorsFile)
               write( IOBuffer, '(T22, "in 1E-10 m^2/s:", 2F20.9)' ) 0._RK
               call FileWrite(this%errorsFile)
               call FileWriteBlank(this%errorsFile)
               write( IOBuffer, '("Ternary diff. coeff. 2 3", T29, "reduced:", 2F20.9)' ) 0._RK
               call FileWrite(this%errorsFile)
               write( IOBuffer, '(T22, "in 1E-10 m^2/s:", 2F20.9)' ) 0._RK
               call FileWrite(this%errorsFile)
               call FileWriteBlank(this%errorsFile)
             end if  !TransMethod
           end if !Ncomponents ==3
        end if !Ncomponents >1


        do i = 1, this%NComponents
          write( IOBuffer, '("Self-diff. coeff. ",A ,T29, "reduced:", F20.9)' ) trim( this%Component(i)%Molecule%PotModFileName ), 0._RK
          call FileWrite(this%errorsFile)
          write( IOBuffer, '(T22, "in 1E-10 m^2/s:", F20.9)' )  0._RK
          call FileWrite(this%errorsFile)
        end do
        call FileWriteBlank(this%errorsFile)

        if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
          write( IOBuffer, '("Shear viscosity    ", T29, "reduced:", F20.9)' )  0._RK
          call FileWrite(this%errorsFile)
          write( IOBuffer, '(T23, "in 1E-4 Pa s:", F20.9)' ) 0._RK
          call FileWrite(this%errorsFile)
          call FileWriteBlank(this%errorsFile)
        end if

        if (this%Bulkviscosity ) then
          write( IOBuffer, '("Bulk viscosity     ", T29, "reduced:", F20.9)' )  0._RK
          call FileWrite(this%errorsFile)
          write( IOBuffer, '(T23, "in 1E-4 Pa s:", F20.9)' ) 0._RK
        else
          write( IOBuffer, '("Bulk viscosity only defined for the NVE ensemble")' )
        end if
        call FileWrite(this%errorsFile)
        call FileWriteBlank(this%errorsFile)

        if (LongRange .eq. Ewald) then
          write( IOBuffer, '("Thermal conductivity not implemented for Ewald")' )
        end if

        if ( LongRange .eq. Rfield) then
           write( IOBuffer, '("Thermal conductivity ", T29, "reduced:", 2F20.9)' ) 0._RK
           call FileWrite(this%errorsFile)
           write( IOBuffer, '(T23, "in W / (m K) :", 2F20.9)' ) 0._RK
           call FileWrite(this%errorsFile)
           if ( this%NComponents > 1 ) then
             if (this%MolarEnthConduct) then
               write( IOBuffer, '("Thermal conductivity includes the  enthalpic contribution")' )
               call FileWrite(this%errorsFile)
             else
               write( IOBuffer, '("Thermal conductivity was calculated without the enthalpic contribution")' )
               call FileWrite(this%errorsFile)
             end if
           end if
        else
           write( IOBuffer, '("Thermal conductivity only implemented for Reaction Field")' )
           call FileWrite(this%errorsFile)
        end if
        call FileWriteBlank(this%errorsFile)


        if (this%EConductivity) then
          write( IOBuffer, '("Electric conductivity ", T29, "reduced:", F20.9)' )  0._RK
          call FileWrite(this%errorsFile)
          write( IOBuffer, '(T23, "in 1 / (Ohm m):", F20.9)' ) 0._RK
        else
          write( IOBuffer, '("Electric conductivity only defined for pure charged particles")' )
        end if
        call FileWrite(this%errorsFile)
        call FileWriteBlank(this%errorsFile)


        if ( this%NComponents > 1 ) then
          if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
            do i = 1, this%NComponents
              write( IOBuffer, '("Mass coefficient Lii",2I2,T29, "reduced:", 2F20.9)' ) i,i, 0._RK
              call FileWrite(this%errorsFile)
              write( IOBuffer, '(T21, "in 10E-10 Kg K s/m^3:", 2F20.9)' ) 0._RK
              call FileWrite(this%errorsFile)
              call FileWriteBlank(this%errorsFile)
            end do
          end if

          if (this%MolarEnthConduct) then
            write( IOBuffer, '("Energy coefficient LQQ ", T29, "reduced:", 2F20.9)' ) 0._RK
            call FileWrite(this%errorsFile)
            write( IOBuffer, '(T25, "in W K/ m:", 2F20.9)' ) 0._RK
            call FileWrite(this%errorsFile)
            call FileWriteBlank(this%errorsFile)
            do i = 1, this%NComponents-1
              write( IOBuffer, '("Cross coefficient LiQ",I2, T29, "reduced:", 2F20.9)' )i, 0._RK
              call FileWrite(this%errorsFile)
              write( IOBuffer, '(T18, "in 10E-6 Kg K/(m s):", 2F20.9)' ) 0._RK
              call FileWrite(this%errorsFile)
              call FileWriteBlank(this%errorsFile)
            end do
          else
            write( IOBuffer, '("Energy coefficient LEE ", T29, "reduced:", 2F20.9)' ) 0._RK
            call FileWrite(this%errorsFile)
            write( IOBuffer, '(T23, "in W K/ m:", 2F20.9)' ) 0._RK
            call FileWrite(this%errorsFile)
            call FileWriteBlank(this%errorsFile)
            do i = 1, this%NComponents
              write( IOBuffer, '("Cross coefficient LiE",I2, T29, "reduced:", 2F20.9)' )i, 0._RK
              call FileWrite(this%errorsFile)
              write( IOBuffer, '(T18, "in 10E-6 Kg K/(m s):", 2F20.9)' ) 0._RK
              call FileWrite(this%errorsFile)
            end do
              write( IOBuffer, '("LEE and L1E do not include the enthalpic term")' )
              call FileWrite(this%errorsFile)
              call FileWriteBlank(this%errorsFile)
          end if  !this%MolarEnthConduct
        end if !This component > 1

      end if

!EinsteinCoef errorsFile%iounit

      if ((TransMethod .eq. Einstein) .or. (TransMethod .eq. GKEinstein)) then
        if (this%EinsteinCoefAveCount > 0) then

          if ( this%NComponents > 1 ) then
            do i = 1, this%NComponents
              do j = 1, this%NComponents
                call Error(this%EinsteinOnsagerAcc(i,j), .true.)
              end do
            end do
          end if

        do i = 1, this%NComponents
            call Error(this%EinsteinDSelfAcc(i), .true.)
        end do

        call Error(this%EinsteinShearAcc, .true.)

        write( IOBuffer, '(T24, "Einstein coefficient theory")' )
        call FileWrite(this%errorsFile)
        call FileWriteBlank(this%errorsFile)

        value = (dsqrt(UnitEnergy/UnitMass)*UnitLength*1E10_RK)

       ! Onsager coefficients
        if ( this%NComponents > 1 ) then
          do i = 1, this%NComponents
            do j = 1, this%NComponents
              Average  = this%EinsteinOnsagerAcc(i,j)%Average
              Variance = this%EinsteinOnsagerAcc(i,j)%Variance
              write( IOBuffer, '("Onsager-diff. coeff.",2I2,T29, "reduced:", 2F20.9)' ) i,j,Average, Variance
              call FileWrite(this%errorsFile)
              write( IOBuffer, '(T22, "in 1E-10 m^2/s:", 2F20.9)' ) Average*value, Variance*value
              call FileWrite(this%errorsFile)
            end do
          end do
          call FileWriteBlank(this%errorsFile)
        end if !this%NComponents

        !for multicomponent mixtures

        if( this%NComponents >= 2  ) then

           do i = 1, this%NComponents
              x(i) = this%Component(i)%Fraction
              Inv_x(i) = 1._RK/x(i)
           end do

           do i = 1, this%NComponents
              do  j = 1, this%NComponents
                 if (i ==j) then
                   L(i,j) = this%EinsteinOnsagerAcc(i,j)%Average
                 else
                   L(i,j) = (this%EinsteinOnsagerAcc(i,j)%Average + this%EinsteinOnsagerAcc(j,i)%Average)/2._RK
                 end if
              end do
           end do
        end if

        !binary diffusion and thermal diffusion
        if( this%NComponents == 2  ) then
          D_12 = L(1,1) * x(2)*Inv_x(1) + L(2,2) * x(1)*Inv_x(2) - L(1,2) - L(2,1)
          err_D12 = this%EinsteinOnsagerAcc(1,1)%Variance * x(2)*Inv_x(1) + &
&                   this%EinsteinOnsagerAcc(2,2)%Variance * x(1)* Inv_x(2) + &
&                   this%EinsteinOnsagerAcc(1,2)%Variance + this%EinsteinOnsagerAcc(2,1)%Variance

          write( IOBuffer, '("Binary diff. coeff.", T29, "reduced:", 2F20.9)' ) D_12, err_D12
          call FileWrite(this%errorsFile)
          write( IOBuffer, '(T22, "in 1E-10 m^2/s:", 2F20.9)' ) D_12*value, err_D12*value
          call FileWrite(this%errorsFile)
          call FileWriteBlank(this%errorsFile)
        end if !this components = 2

       ! Ternary and Quaternary diffusion
        if(( this%NComponents == 3 ) .or. ( this%NComponents == 4 )) then

          !obtain matrix [delta] Equations 48 to 55 from Supplementary material
          !Krishna and van Baten, Ind. Eng. Chem. Res., 2005, 44 (17), pp 6939

          delta(:,:) = 0._RK
          do i=1, (this%NComponents-1)
             do j =1, (this%NComponents-1)
                delta(i,j) = (1._RK-x(i))*(L(i,j)*Inv_x(j)-L(i,this%NComponents)*Inv_x(this%NComponents))
                do k = 1, this%NComponents
                   if (k /= i) then
                    delta(i,j) = delta(i,j) - x(i)* (L(k,j)*Inv_x(j)-L(k,this%NComponents)*Inv_x(this%NComponents))
                   end if
                end do
             end do
          end do

          !calculate variance by error propagation
          err_delta(:,:) = 0._RK
          do i=1, (this%NComponents-1)
            do j =1, (this%NComponents-1)
               err_delta(i,j) = (1._RK-x(i))*Inv_x(j)*this%EinsteinOnsagerAcc(i,j)%Variance + (1._RK-x(i))*Inv_x(this%NComponents)*this%EinsteinOnsagerAcc(i,this%NComponents)%Variance
               do k = 1, this%NComponents
                  if (k /= i) then
                    err_delta(i,j) = err_delta(i,j) + x(i)*Inv_x(j)*this%EinsteinOnsagerAcc(k,j)%Variance + x(i)*Inv_x(this%NComponents)*this%EinsteinOnsagerAcc(k,this%NComponents)%Variance
                  end if
               end do
            end do
          end do
        end if !Components 3 or 4


        !Ternary diffusion
        if( this%NComponents == 3 ) then

          ! determinat of matrix [delta]
          det = (delta(1,1)*delta(2,2))-(delta(1,2)*delta(2,1))
          inv_det = 1._RK/det

          !obtain matrix [B] so that [B]=[D]-1
          B(1,1) =  inv_det* delta(2,2) !B1
          B(1,2) =  inv_det*(-delta(1,2)) !B2
          B(2,1) =  inv_det*(-delta(2,1)) !B3
          B(2,2) =  inv_det* delta(1,1) !B4

          !Obtain Error matrix B (from Propagation of Errors for Matrix Inversion,
          !Lefebvre et al.Nucl.Instrm.Meth. A451 (2000) 520-528)

           err_B(:,:) = 0._RK

           do k = 1, (this%NComponents-1)
              do m = 1, (this%NComponents-1)
                 do i = 1, (this%NComponents-1)
                    do  j = 1, (this%NComponents-1)
                       err_B(k,m) = err_B(k,m) + ABS(B(k,i)*B(j,m))*err_delta(i,j)
                    end do
                 end do
               end do
           end do

          !Calculate diffusion coefficients
          D_13 =  1._RK  / ( (B(1,1)) + ( x(2)* B(1,2) * Inv_x(1)) )
          D_12 =  1._RK  / ( (B(1,1)) - ( (x(1) + x(3)) * B(1,2) *Inv_x(1)))
          D_23 =  1._RK  / ( (B(2,2)) + ( x(1)* B(2,1) * Inv_x(2)))

          !Obtain error of Diffusion coefficients
          err_D13 = ABS(1._RK/((x(2)*Inv_x(1)*B(1,2)+B(1,1))**2))*err_B(1,1) + &
&                   ABS(x(2)*Inv_x(1)/((B(1,1)+x(2)*Inv_x(1)*B(1,2))**2))*err_B(1,2)
          err_D12 = ABS(1._RK/((B(1,1)-((x(1)+x(3))*Inv_x(1)*B(1,2)))**2))*err_B(1,1) + &
&                   ABS(((x(1)+x(3))*Inv_x(1))/((B(1,1)-((x(1)+x(3))*Inv_x(1)*B(1,2)))**2))*err_B(1,2)
          err_D23 = ABS(1._RK/((x(1)*Inv_x(2)*B(2,1)+B(2,2))**2))*err_B(2,2) + &
&                   ABS(x(1)*Inv_x(2)/((B(2,2)+x(1)*Inv_x(2)*B(2,1))**2))*err_B(2,1)

          call writeValue("Ternary diff. coeff. 1 2", D_12, err_D12, value, "1E-10 m^2/s", this%errorsFile)

          call writeValue("Ternary diff. coeff. 1 3", D_13, err_D13, value, "1E-10 m^2/s", this%errorsFile)

          call writeValue("Ternary diff. coeff. 2 3", D_23, err_D23, value, "1E-10 m^2/s", this%errorsFile)

        end if !this%NComponents == 3


        if ( this%NComponents == 4 ) then
          ! determinat of matrix [delta]
          det = (delta(1,1)*delta(2,2)*delta(3,3))+(delta(2,1)*delta(3,2)*delta(1,3))+(delta(3,1)*delta(1,2)*delta(2,3))-&
&               (delta(1,1)*delta(3,2)*delta(2,3))-(delta(3,1)*delta(2,2)*delta(1,3))-(delta(2,1)*delta(1,2)*delta(3,3))

          inv_det = 1._RK/det

          !obtain matrix [B] so that [B]=[D]-1
          B(1,1) =  inv_det* (delta(2,2)*delta(3,3)-delta(2,3)*delta(3,2)) !B1
          B(1,2) =  inv_det* (delta(1,3)*delta(3,2)-delta(1,2)*delta(3,3)) !B2
          B(1,3) =  inv_det* (delta(1,2)*delta(2,3)-delta(1,3)*delta(2,2))
          B(2,1) =  inv_det* (delta(2,3)*delta(3,1)-delta(2,1)*delta(3,3))
          B(2,2) =  inv_det* (delta(1,1)*delta(3,3)-delta(1,3)*delta(3,1))
          B(2,3) =  inv_det* (delta(1,3)*delta(2,1)-delta(1,1)*delta(2,3))
          B(3,1) =  inv_det* (delta(2,1)*delta(3,2)-delta(2,2)*delta(3,1))
          B(3,2) =  inv_det* (delta(1,2)*delta(3,1)-delta(1,1)*delta(3,2))
          B(3,3) =  inv_det* (delta(1,1)*delta(2,2)-delta(1,2)*delta(2,1))

          !Obtain Error matrix B (from Propagation of Errors for Matrix Inversion,
          !Lefebvre et al.Nucl.Instrm.Meth. A451 (2000) 520-528)

          err_B(:,:) = 0._RK

           do k = 1, (this%NComponents-1)
              do m = 1, (this%NComponents-1)
                 do i = 1, (this%NComponents-1)
                    do  j = 1, (this%NComponents-1)
                       err_B(k,m) = err_B(k,m) + ABS(B(k,i)*B(j,m))*err_delta(i,j)
                    end do
                 end do
               end do
           end do


          !Calculate diffusion coefficients
          D_14 =  1._RK  / ( (B(1,1)) + ( x(2)* B(1,2) * Inv_x(1)) + (x(3) * B(1,3)* Inv_x(1)) )
          D_24 =  1._RK  / ( (B(2,2)) + ( x(1)* B(2,1) * Inv_x(2)) + (x(3) * B(2,3)* Inv_x(2)) )
          D_34 =  1._RK  / ( (B(3,3)) + ( x(1)* B(3,1) * Inv_x(3)) + (x(2) * B(3,2)* Inv_x(3)) )
          D_12 =  1._RK  / ( (1._RK/D_24) - (B(2,1)*Inv_x(2)))
          D_13 =  1._RK  / ( (1._RK/D_14) - (B(1,3)*Inv_x(1)))
          D_23 =  1._RK  / ( (1._RK/D_24) - (B(2,3)*Inv_x(2)))


          !Obtain error of Diffusion coefficients
          err_D14 = ABS(1._RK/(((B(1,1)) + ( x(2)* B(1,2) * Inv_x(1)) + (x(3) * B(1,3)* Inv_x(1)) )**2))*err_B(1,1) + &
                    ABS(x(2)*Inv_x(1)/(((B(1,1)) + ( x(2)* B(1,2) * Inv_x(1)) + (x(3) * B(1,3)* Inv_x(1)) )**2))*err_B(1,2) + &
                    ABS(x(3)*Inv_x(1)/(((B(1,1)) + ( x(2)* B(1,2) * Inv_x(1)) + (x(3) * B(1,3)* Inv_x(1)) )**2))*err_B(1,3)

          err_D24 = ABS(1._RK/(((B(2,2)) + ( x(1)* B(2,1) * Inv_x(2)) + (x(3) * B(2,3)* Inv_x(2)) )**2))*err_B(2,2) + &
                    ABS(x(1)*Inv_x(2)/(((B(2,2)) + ( x(1)* B(2,1) * Inv_x(2)) + (x(3) * B(2,3)* Inv_x(2)) )**2))*err_B(2,1) + &
                    ABS(x(3)*Inv_x(2)/(((B(2,2)) + ( x(1)* B(2,1) * Inv_x(2)) + (x(3) * B(2,3)* Inv_x(2)) )**2))*err_B(2,3)

          err_D34 = ABS(1._RK/(((B(3,3)) + ( x(1)* B(3,1) * Inv_x(3)) + (x(2) * B(3,2)* Inv_x(3)) )**2))*err_B(3,3) + &
                    ABS(x(1)*Inv_x(3)/(((B(3,3)) + ( x(1)* B(3,1) * Inv_x(3)) + (x(2) * B(3,2)* Inv_x(3)) )**2))*err_B(3,1) + &
                    ABS(x(2)*Inv_x(3)/(((B(3,3)) + ( x(1)* B(3,1) * Inv_x(3)) + (x(2) * B(3,2)* Inv_x(3)) )**2))*err_B(3,2)

          err_D12 = ABS(1._RK/(((B(2,2)) + ( (x(1)-1._RK)* B(2,1) * Inv_x(2)) + (x(3) * B(2,3)* Inv_x(2)) )**2))*err_B(2,2) + &
                    ABS((x(1)-1._RK)*Inv_x(2)/(((B(2,2)) + ( (x(1)-1._RK)* B(2,1) * Inv_x(2)) + (x(3) * B(2,3)* Inv_x(2)) )**2))*err_B(2,1) + &
                    ABS(x(3)*Inv_x(2)/(((B(2,2)) + ( (x(1)-1._RK)* B(2,1) * Inv_x(2)) + (x(3) * B(2,3)* Inv_x(2)) )**2))*err_B(2,3)

          err_D13 = ABS(1._RK/(((B(1,1)) + ( x(2)* B(1,2) * Inv_x(1)) + ((x(3)-1._RK) * B(1,3)* Inv_x(3)) )**2))*err_B(1,1) + &
                    ABS(x(2)*Inv_x(1)/(((B(1,1)) + ( x(2)* B(1,2) * Inv_x(1)) + ((x(3)-1._RK) * B(1,3)* Inv_x(3)) )**2))*err_B(1,2) + &
                    ABS((x(3)-1._RK)*Inv_x(1)/(((B(1,1)) + ( x(2)* B(1,2) * Inv_x(1)) + ((x(3)-1._RK) * B(1,3)* Inv_x(3)) )**2))*err_B(1,3)

          err_D23 = ABS(1._RK/(((B(2,2)) + ( x(1)* B(2,1) * Inv_x(2)) + ((x(3)-1._RK) * B(2,3)* Inv_x(2)) )**2))*err_B(2,2) + &
                    ABS(x(1)*Inv_x(2)/(((B(2,2)) + ( x(1)* B(2,1) * Inv_x(2)) + ((x(3)-1._RK) * B(2,3)* Inv_x(2)) )**2))*err_B(2,1) + &
                    ABS((x(3)-1._RK)*Inv_x(2)/(((B(2,2)) + ( x(1)* B(2,1) * Inv_x(2)) + ((x(3)-1._RK) * B(2,3)* Inv_x(2)) )**2))*err_B(2,3)

          call writeValue("Quat. diff. coeff. 1 2", D_12, err_D12, value, "1E-10 m^2/s", this%errorsFile)

          call writeValue("Quat. diff. coeff. 1 3", D_13, err_D13, value, "1E-10 m^2/s", this%errorsFile)

          call writeValue("Quat. diff. coeff. 1 4", D_14, err_D14, value, "1E-10 m^2/s", this%errorsFile)

          call writeValue("Quat. diff. coeff. 2 3", D_23, err_D23, value, "1E-10 m^2/s", this%errorsFile)

          call writeValue("Quat. diff. coeff. 2 4", D_24, err_D24, value, "1E-10 m^2/s", this%errorsFile)

          call writeValue("Quat. diff. coeff. 3 4", D_34, err_D34, value, "1E-10 m^2/s", this%errorsFile)

        end if !this%NComponents == 4


        !self-diffusion coefficient
        do i = 1, this%NComponents
          Average  = this%EinsteinDSelfAcc(i)%Average
          Variance = this%EinsteinDSelfAcc(i)%Variance
          write( IOBuffer, '("Self-diff. coeff. ",A ,T29, "reduced:", 2F20.9)' )  &
&                trim( this%Component(i)%Molecule%PotModFileName ), Average, Variance
          call FileWrite(this%errorsFile)
          write( IOBuffer, '(T22, "in 1E-10 m^2/s:", 2F20.9)' ) Average*value, Variance*value
          call FileWrite(this%errorsFile)
        end do
        call FileWriteBlank(this%errorsFile)

        Average  =  this%EinsteinShearAcc%Average
        Variance =  this%EinsteinShearAcc%Variance
        value = dsqrt(UnitEnergy*UnitMass)/UnitLength**2/1E-4_RK

        call writeValue("Shear viscosity    ", Average, Variance, value, "1E-4 Pa s", this%errorsFile)

        if ( this%NComponents > 1 ) then
           do i = 1, this%NComponents
             Average  = this%EinsteinOnsagerAcc(i,i)%Average
             Variance = this%EinsteinOnsagerAcc(i,i)%Variance
             factor = this%density*this%Component(i)%Molecule%Mass* this%Component(i)%Molecule%Mass
             value = UnitTemperature*UnitMass*UnitTime/(1E-10_RK*UnitLength**3)
             write( IOBuffer, '("Mass coefficient Lii",2I2,T29, "reduced:", 2F20.9)' ) i,i,Average*factor, Variance*factor
             call FileWrite(this%errorsFile)
             write( IOBuffer, '(T16, "in 10E-10 Kg K s/m^3:", 2F20.9)' ) Average*factor*value, Variance*factor*value
             call FileWrite(this%errorsFile)
           end do
           call FileWriteBlank(this%errorsFile)
        end if

      end if !EinsteinAverageCount
    end if   !TransMethodEinstein

      ! Separator
      write( IOBuffer, '(76("="))' )
      call FileWrite(this%errorsFile)
      call FileWriteBlank(this%errorsFile)

    end if   ! (this%CorrfunMode)
#endif

    ! Too large cutoff radius
    write( IOBuffer, '("Cutoff radius is", I10, " times (", F6.2, "%) too large")' ) &
&          this%NRCutoffMax, ( 100._RK * this%NRCutoffMax ) / Step
    call FileWrite(this%errorsFile)
    call FileWriteBlank(this%errorsFile)

    ! Separator
    write( IOBuffer, '(76("="))' )
    call FileWrite(this%errorsFile)
    call FileWriteBlank(this%errorsFile)

    ! Phase equilibria data for GE-ensemble
    if( EnsembleType .eq. EnsembleTypeGE .or. EnsembleType .eq. EnsembleTypeMUVT ) then  
      if( EnsembleType .eq. EnsembleTypeGE ) then
        write( IOBuffer, '("PHASE EQUILIBRIUM DATA")' )
        call FileWrite(this%errorsFile)
        write( IOBuffer, '("---------------------")' )
        call FileWrite(this%errorsFile)
        call FileWriteBlank(this%errorsFile)

        ! Simulation temperature
        write( IOBuffer, '("Simulation temperature", T29, "reduced:", F20.9)' ) this%RefTemperature
        call FileWrite(this%errorsFile)
        write( IOBuffer, '(T32, "in K:", F20.9)' ) this%Temperature * UnitTemperature
        call FileWrite(this%errorsFile)
        call FileWriteBlank(this%errorsFile)

        ! Mole fractions of liquid phase
        do i = 1, this%NComponents
          pc => this%Component(i)
          write( IOBuffer, '("Liquid mole fraction of ", A, T36, ":", F20.9)' ) &
&              trim( pc%Molecule%PotModFileName ), pc%LiqFraction
          call FileWrite(this%errorsFile)
        end do
        call FileWriteBlank(this%errorsFile)

        ! Simulation pressure of liquid phase
        write( IOBuffer, '("Liquid simulation pressure", T29, "reduced:", F20.9)' ) this%RefPressure
        call FileWrite(this%errorsFile)
        write( IOBuffer, '(T30, "in MPa:", F20.9)' ) this%RefPressure * UnitPressure * 1e-6_RK
        call FileWrite(this%errorsFile)
        call FileWriteBlank(this%errorsFile)

        ! Vapor pressure
        Average = this%SumPressure%Average
        Variance = this%SumPressure%Variance
        NN = 0._RK
        do i = 1, this%NComponents
          NN = NN + this%Component(i)%SumFraction%Average * this%Component(i)%PartialMolarVolume
        end do
        NN = NN - this%Temperature / Average
        do i = 1, this%NComponents
          pc => this%Component(i)
          dpdmu(i) = -this%Temperature * pc%SumFraction%Average / NN
          dpdv(i) = -pc%SumFraction%Average * (Average-this%RefPressure) / NN
          varmu(i) = pc%VarChemPot
          varv(i) = pc%VarPartialMolarVolume
        end do

        VarPressure = sqrt( Variance**2 + sum( (dpdmu * varmu)**2 ) + sum( (dpdv * varv)**2 ) )

        dimensionFactor = UnitPressure * 1E-6_RK

        call writeValue("Vapor pressure", Average, VarPressure, dimensionFactor, "MPa", this%errorsFile)

        ! Mole fractions of vapor phase
        do i = 1, this%NComponents
          pc => this%Component(i)
          yvi = pc%SumFraction%Average * ( pc%PartialMolarVolume / this%Temperature - 1 / this%SumPressure%Average )
          do j = 1, this%NComponents
            dydmu(i, j) = yvi * dpdmu(j)
            dydv(i, j) = yvi * dpdv(j)
          end do
          dydmu(i, i) = dydmu(i, i) + pc%SumFraction%Average
          dydv(i, i) = dydv(i, i) + pc%SumFraction%Average * 1 / this%Temperature * ( this%SumPressure%Average - this%RefPressure )
        end do

        do i = 1, (this%NComponents - 1)
          pc => this%Component(i)
          Average = pc%SumFraction%Average
          vary(i) = sqrt( pc%SumFraction%Variance**2 + sum( (dydmu(i, :) * varmu)**2 ) + sum( (dydv(i, :) * varv)**2 ) )
          write( IOBuffer, '("Vapor mole fraction of ", A, T36, ":", 2F20.9)' ) &
  &              trim( pc%Molecule%PotModFileName ), Average, vary(i)
          call FileWrite(this%errorsFile)
        end do

        pc => this%Component( this%NComponents )
        Average = pc%SumFraction%Average
        Variance = sqrt( sum( vary(1:(this%NComponents - 1))**2 ) )
        write( IOBuffer, '("Vapor mole fraction of ", A, T36, ":", 2F20.9)' ) &
  &            trim( pc%Molecule%PotModFileName ), Average, Variance
        call FileWrite(this%errorsFile)
        call FileWriteBlank(this%errorsFile)

        ! Saturated liquid density
        Average = this%LiqDensity + this%LiqDensity * this%LiqBetaT * ( this%SumPressure%Average - this%RefPressure)

        Variance = sqrt( this%VarLiqDensity**2 + ( this%VarLiqBetaT * ( this%SumPressure%Average - this%RefPressure )&
  &               + VarPressure * this%LiqBetaT )**2 )

        dimensionFactor = UnitDensity

        call writeValue("Liquid density", Average, Variance, dimensionFactor, "mol/l", this%errorsFile)

        ! Saturated vapor density
        Average = this%SumDensity%Average

        dimensionFactor = UnitDensity

        call writeValue("Vapor density", Average, Average * VarPressure / this%SumPressure%Average, dimensionFactor, "mol/l", this%errorsFile)


        ! Saturated liquid enthalpy
        Average = this%LiqEnthalpy + this%LiqdHdP * ( this%SumPressure%Average - this%RefPressure )

        Variance = sqrt( this%VarLiqEnthalpy**2 + ( this%VarLiqdHdP * &
  &                ( this%SumPressure%Average - this%RefPressure ) + VarPressure * this%LiqdHdP )**2 )

        dimensionFactor = UnitEnergy * NAvogadro

        call writeValue("Liquid enthalpy", Average, Variance, dimensionFactor, "J/mol", this%errorsFile)

        DeltaHv = Average
        VarDeltaHv = Variance

        ! Saturated vapor enthalpy
        Average = this%SumEnthalpy%Average
        Variance = this%SumEnthalpy%Variance

        dimensionFactor = UnitEnergy * NAvogadro

        call writeValue("Vapor enthalpy", Average, Variance, dimensionFactor, "J/mol", this%errorsFile)

      DeltaHv = Average - DeltaHv
      VarDeltaHv = Variance + VarDeltaHv

        ! Evaporation enthalpy

        dimensionFactor = UnitEnergy * NAvogadro

        call writeValue("Enthalpy of vaporization", DeltaHv, VarDeltaHv, dimensionFactor, "J/mol", this%errorsFile)

        ! Separator
        write( IOBuffer, '(76("="))' )
        call FileWrite(this%errorsFile)
        call FileWriteBlank(this%errorsFile)
      end if

      ! Statistical analogues

      call writeStatisticalAnalogues(this)

      ! J000
      Average = - this%SumPressure%Average / (this%RefTemperature*this%RefDensity)
      Variance = - this%SumPressure%Variance / (this%RefTemperature*this%RefDensity)
      write( IOBuffer, '("J000", T29, "Dimensionless: ", 2F20.9)' ) Average, Variance
      call FileWrite(this%errorsFile)
      call FileWriteBlank(this%errorsFile)

      call writeAverageAndVariance(this%SumP100, "J100", this%errorsFile, .true.)

      call writeAverageAndVariance(this%SumP010, "J010", this%errorsFile, .true.)

      call writeAverageAndVariance(this%SumP001, "J001", this%errorsFile, .true.)

      call writeAverageAndVariance(this%SumP200, "J200", this%errorsFile, .true.)

      call writeAverageAndVariance(this%SumP020, "J020", this%errorsFile, .true.)

      call writeAverageAndVariance(this%SumP002, "J002", this%errorsFile, .true.)

      call writeAverageAndVariance(this%SumP110, "J110", this%errorsFile, .true.)

      call writeAverageAndVariance(this%SumP101, "J101", this%errorsFile, .true.)

      call writeAverageAndVariance(this%SumP011, "J011", this%errorsFile, .true.)

    else if( EnsembleType .eq. EnsembleTypeMUVL .or. EnsembleType .eq. EnsembleTypeMUPR ) then

      call writeStatisticalAnalogues(this)

      call writeAverageAndVariance(this%SumP100, "S100", this%errorsFile, .true.)

      call writeAverageAndVariance(this%SumP010, "S010", this%errorsFile, .true.)

      call writeAverageAndVariance(this%SumP001, "S001", this%errorsFile, .true.)

      call writeAverageAndVariance(this%SumP200, "S200", this%errorsFile, .true.)

      call writeAverageAndVariance(this%SumP020, "S020", this%errorsFile, .true.)

      call writeAverageAndVariance(this%SumP002, "S002", this%errorsFile, .true.)

      call writeAverageAndVariance(this%SumP110, "S110", this%errorsFile, .true.)

      call writeAverageAndVariance(this%SumP101, "S101", this%errorsFile, .true.)

      call writeAverageAndVariance(this%SumP011, "S011", this%errorsFile, .true.)

    else if( EnsembleType .eq. EnsembleTypeMUPT ) then

      call writeStatisticalAnalogues(this)

      call writeAverageAndVariance(this%SumP100, "Z100", this%errorsFile, .true.)

      call writeAverageAndVariance(this%SumP010, "Z010", this%errorsFile, .true.)

      call writeAverageAndVariance(this%SumP001, "Z001", this%errorsFile, .true.)

      call writeAverageAndVariance(this%SumP200, "Z200", this%errorsFile, .true.)

      call writeAverageAndVariance(this%SumP020, "Z020", this%errorsFile, .true.)

      call writeAverageAndVariance(this%SumP002, "Z002", this%errorsFile, .true.)

      call writeAverageAndVariance(this%SumP110, "Z110", this%errorsFile, .true.)

      call writeAverageAndVariance(this%SumP101, "Z101", this%errorsFile, .true.)

      call writeAverageAndVariance(this%SumP011, "Z011", this%errorsFile, .true.)

    end if

    if( (SimulationType .eq. MonteCarlo) .or. (SimulationType .eq. Gibbs) ) then
      ! Statistics section
      write( IOBuffer, '("Statistics")' )
      call FileWrite(this%errorsFile)
      write( IOBuffer, '("----------")' )
      call FileWrite(this%errorsFile)
      call FileWriteBlank(this%errorsFile)

      ! Volume change acceptance rate and maximum displacement
      if( ConstantPressure ) then
#if MPI_VER > 0
        if ( mpiMCCommonGroups > 0 ) then
          call MPI_Reduce( this%NResizeSuccesses,tempVal, 1, MPI_INTEGER, MPI_SUM, NRootProc_W, MPI_COMM_WORLD, ierror )
          call MPI_Reduce( this%NResizeAttempts,tempVal2, 1, MPI_INTEGER, MPI_SUM, NRootProc_W, MPI_COMM_WORLD, ierror )
        else
          call MPI_Reduce( this%NResizeSuccesses,tempVal, 1, MPI_INTEGER, MPI_SUM, NRootProc, Communicator, ierror )
          call MPI_Reduce( this%NResizeAttempts,tempVal2, 1, MPI_INTEGER, MPI_SUM, NRootProc, Communicator, ierror )
        endif
        if ( Nproc == NRootProc) then
          write( IOBuffer, '("Acceptance rate volume changes", T32, "in %:", F20.9)' ) &
&                100._RK * real(tempVal, RK ) / real (tempVal2, RK )
        endif
#else
        write( IOBuffer, '("Acceptance rate volume changes", T32, "in %:", F20.9)' ) &
&              100._RK * real( this%NResizeSuccesses, RK ) / real ( this%NResizeAttempts, RK )
#endif
        call FileWrite(this%errorsFile)
#if MPI_VER > 0
        if ( mpiMCCommonGroups > 0 ) then
           call MPI_Reduce( this%DispVol,tempReal, 1, MPI_RK, MPI_SUM, NRootProc_W, MPI_COMM_WORLD, ierror )
           tempReal = tempReal / mpiMCCommonGroups
        else
          call MPI_Reduce( this%DispVol,tempReal, 1, MPI_RK, MPI_SUM, NRootProc, Communicator, ierror )
        endif
        if ( Nproc == NRootProc) then
          write( IOBuffer, '("Maximum displacement volume", T33, "r`d:", F20.9)' ) tempReal
        endif
#else
        write( IOBuffer, '("Maximum displacement volume", T33, "r`d:", F20.9)' ) this%DispVol
#endif
        call FileWrite(this%errorsFile)
        call FileWriteBlank(this%errorsFile)
      end if

      do i = 1, this%NRealComponents
        pc => this%Component(i)

        ! Move and rotate acceptance rates
        write( IOBuffer, '("Component ", A)' ) pc%PotModFileName
        call FileWrite(this%errorsFile)
#if MPI_VER > 0
        if ( mpiMCCommonGroups > 0 ) then
          call MPI_Reduce( pc%NMoveSuccesses,tempVal, 1, MPI_INTEGER, MPI_SUM, NRootProc_W, MPI_COMM_WORLD, ierror )
          call MPI_Reduce( pc%NMoveAttempts,tempVal2, 1, MPI_INTEGER, MPI_SUM, NRootProc_W, MPI_COMM_WORLD, ierror )
        else
          call MPI_Reduce( pc%NMoveSuccesses,tempVal, 1, MPI_INTEGER, MPI_SUM, NRootProc, Communicator, ierror )
          call MPI_Reduce( pc%NMoveAttempts,tempVal2, 1, MPI_INTEGER, MPI_SUM, NRootProc, Communicator, ierror )
        endif
        if (Nproc == NRootProc) then
          write( IOBuffer, '("Acceptance rate trans.", T32, "in %:", F20.9)' ) &
&                100._RK * real( tempVal, RK ) / real ( tempVal2, RK )
        endif
#else
        write( IOBuffer, '("Acceptance rate trans.", T32, "in %:", F20.9)' ) &
&              100._RK * real( pc%NMoveSuccesses, RK ) / real ( pc%NMoveAttempts, RK )
#endif
        call FileWrite(this%errorsFile)

        if( pc%Molecule%IsElongated ) then
#if MPI_VER > 0
          if ( mpiMCCommonGroups > 0 ) then
            call MPI_Reduce( pc%NRotateSuccesses,tempVal, 1, MPI_INTEGER, MPI_SUM, NRootProc_W, MPI_COMM_WORLD, ierror )
            call MPI_Reduce( pc%NRotateAttempts,tempVal2, 1, MPI_INTEGER, MPI_SUM, NRootProc_W, MPI_COMM_WORLD, ierror )
          else
            call MPI_Reduce( pc%NRotateSuccesses,tempVal, 1, MPI_INTEGER, MPI_SUM, NRootProc, Communicator, ierror )
            call MPI_Reduce( pc%NRotateAttempts,tempVal2, 1, MPI_INTEGER, MPI_SUM, NRootProc, Communicator, ierror )
          endif
          if (Nproc == NRootProc) then
            write( IOBuffer, '(T17, "rotates", T32, "in %:", F20.9)' ) 100._RK &
&                  * real( tempVal, RK ) / real (tempVal2, RK )
          endif
#else
          write( IOBuffer, '(T17, "rotates", T32, "in %:", F20.9)' ) 100._RK &
&                * real( pc%NRotateSuccesses, RK ) / real ( pc%NRotateAttempts, RK )
#endif
          call FileWrite(this%errorsFile)
        end if

        if( pc%ChemPotMethod .eq. ChemPotMethodGradIns ) then
          ! Biased move and rotate acceptance rates
#if MPI_VER > 0
          call MPI_Reduce( pc%NMoveBiasedSuccesses,tempVal, 1, MPI_INTEGER, MPI_SUM, NRootProc, Communicator, ierror )
          call MPI_Reduce( pc%NMoveBiasedAttempts,tempVal2, 1, MPI_INTEGER, MPI_SUM, NRootProc, Communicator, ierror )
          if (Nproc == NRootProc) then
            write( IOBuffer, '(T17, "biased trans.", T32, "in %:", F20.9)' ) 100._RK * real(tempVal, RK ) / &
&                  real ( tempVal2, RK )
          endif
#else
          write( IOBuffer, '(T17, "biased trans.", T32, "in %:", F20.9)' ) &
&                100._RK * real( pc%NMoveBiasedSuccesses, RK ) / real ( pc%NMoveBiasedAttempts, RK )
#endif
          call FileWrite(this%errorsFile)

          if( pc%Molecule%IsElongated ) then
#if MPI_VER > 0
            call MPI_Reduce( pc%NRotateBiasedSuccesses,tempVal, 1, MPI_INTEGER, MPI_SUM, NRootProc, Communicator, ierror )
            call MPI_Reduce( pc%NRotateBiasedAttempts,tempVal2, 1, MPI_INTEGER, MPI_SUM, NRootProc, Communicator, ierror )
            if (Nproc == NRootProc) then
              write( IOBuffer, '(T17, "biased rotates", T32, "in %:", F20.9)' ) &
&                    100._RK * real(tempVal, RK ) / real (tempVal2, RK )
            endif
#else
            write( IOBuffer, '(T17, "biased rotates", T32, "in %:", F20.9)' ) &
&                  100._RK * real( pc%NRotateBiasedSuccesses, RK ) / real ( pc%NRotateBiasedAttempts, RK )
#endif

            call FileWrite(this%errorsFile)
          end if
        end if

        ! Maximum translational and rotational displacements
#if MPI_VER > 0
        if ( mpiMCCommonGroups > 0 ) then
          call MPI_Reduce( pc%DispTran,tempReal, 1, MPI_RK, MPI_MAX, NRootProc_W, MPI_COMM_WORLD, ierror )
        else
          call MPI_Reduce( pc%DispTran,tempReal, 1, MPI_RK, MPI_MAX, NRootProc, Communicator, ierror )
        endif
        if (Nproc == NRootProc) then
          write( IOBuffer, '("Maximum displacement trans.", T33, "r`d:", F20.9)' ) tempReal
        endif
#else
        write( IOBuffer, '("Maximum displacement trans.", T33, "r`d:", F20.9)' ) pc%DispTran
#endif
        call FileWrite(this%errorsFile)

        if( pc%Molecule%IsElongated ) then
#if MPI_VER > 0
          if ( mpiMCCommonGroups > 0 ) then
            call MPI_Reduce( pc%DispRot,tempReal, 1, MPI_RK, MPI_MAX, NRootProc_W, MPI_COMM_WORLD, ierror )
          else
            call MPI_Reduce( pc%DispRot,tempReal, 1, MPI_RK, MPI_MAX, NRootProc, Communicator, ierror )
          endif
          if (Nproc == NRootProc) then
            write( IOBuffer, '(T22, "rotational", T33, "r`d:", F20.9)' ) tempReal
          endif
#else
          write( IOBuffer, '(T22, "rotational", T33, "r`d:", F20.9)' ) pc%DispRot
#endif
          call FileWrite(this%errorsFile)
        endif
        call FileWriteBlank(this%errorsFile)

        ! Gradual insertion change fluctuating particle acceptance rates
        if( pc%ChemPotMethod .eq. ChemPotMethodGradIns ) then
          write(IOBuffer, '("Acceptance rate gradual insertion change fluctuating particle moves:")')
          call FileWrite(this%errorsFile)
          write(IOBuffer, '("  up        down (%)")')
          call FileWrite(this%errorsFile)
          write(IOBuffer, '("  --------  --------")')
          call FileWrite(this%errorsFile)

#if MPI_VER > 0
          call MPI_Reduce( pc%NFluctUpSuccesses(:),tempVec1(1:pc%NFluctMax), pc%NFluctMax, MPI_INTEGER, &
&              MPI_SUM, NRootProc, Communicator, ierror )
          call MPI_Reduce( pc%NFluctUpAttempts(:),tempVec2(1:pc%NFluctMax), pc%NFluctMax, MPI_INTEGER, &
&              MPI_SUM, NRootProc, Communicator, ierror )
          call MPI_Reduce( pc%NFluctDownSuccesses(:),tempVec3(1:pc%NFluctMax), pc%NFluctMax, MPI_INTEGER, &
&              MPI_SUM, NRootProc, Communicator, ierror )
          call MPI_Reduce( pc%NFluctDownAttempts(:),tempVec4(1:pc%NFluctMax), pc%NFluctMax, MPI_INTEGER, &
&              MPI_SUM, NRootProc, Communicator, ierror )

          if (Nproc == NRootProc) then
            write(IOBuffer, '(2F10.4)') 0._RK, real(tempVec3(pc%NFluctMax), RK) / &
&                 real(tempVec4(pc%NFluctMax), RK) * 100._RK
            call FileWrite(this%errorsFile)

           do j = pc%NFluctMax -1, 1, -1
             write(IOBuffer, '(2F10.4)') real(tempVec1(j+1), RK) / &
&                  real(tempVec2(j+1), RK) * 100._RK, real(tempVec3(j), RK) / &
&                  real(tempVec4(j), RK) * 100._RK
             call FileWrite(this%errorsFile)
           end do

           write(IOBuffer, '(2F10.4)') real(tempVec1(1), RK) / real(tempVec2(1), RK) * 100._RK, 0._RK
           call FileWrite(this%errorsFile)
           call FileWriteBlank(this%errorsFile)
           call FileWriteBlank(this%errorsFile)
          endif

#else
          write(IOBuffer, '(2F10.4)') 0._RK, real(pc%NFluctDownSuccesses(pc%NFluctMax), RK) / &
&               real(pc%NFluctDownAttempts(pc%NFluctMax), RK) * 100._RK
          call FileWrite(this%errorsFile)
          do j = pc%NFluctMax -1, 1, -1
            write(IOBuffer, '(2F10.4)') real(pc%NFluctUpSuccesses(j+1), RK) / &
&                 real(pc%NFluctUpAttempts(j+1), RK) * 100._RK, real(pc%NFluctDownSuccesses(j), RK) / &
&                 real(pc%NFluctDownAttempts(j), RK) * 100._RK
            call FileWrite(this%errorsFile)
          end do

          write(IOBuffer, '(2F10.4)') real(pc%NFluctUpSuccesses(1), RK) / &
&               real(pc%NFluctUpAttempts(1), RK) * 100._RK, 0._RK
          call FileWrite(this%errorsFile)
          call FileWriteBlank(this%errorsFile)
          call FileWriteBlank(this%errorsFile)

#endif
        end if
      end do

      ! Inserts and deletes acceptance rates
      if( OpenSystem .or. EnsembleType .eq. EnsembleTypeHA ) then
#if MPI_VER > 0
        if ( mpiMCCommonGroups > 0 ) then
          call MPI_Reduce( this%NInsertSuccesses,tempVal, 1, MPI_INTEGER, MPI_SUM, NRootProc_W, MPI_COMM_WORLD, ierror )
          call MPI_Reduce( this%NInsertAttempts,tempVal2, 1, MPI_INTEGER, MPI_SUM, NRootProc_W, MPI_COMM_WORLD, ierror )
        else
          call MPI_Reduce( this%NInsertSuccesses,tempVal, 1, MPI_INTEGER, MPI_SUM, NRootProc, Communicator, ierror )
          call MPI_Reduce( this%NInsertAttempts,tempVal2, 1, MPI_INTEGER, MPI_SUM, NRootProc, Communicator, ierror )
        endif
        if (Nproc == NRootProc) then
          write( IOBuffer, '("Acceptance rate inserts", T32, "in %:", F20.9)' ) &
&                100._RK * real( tempVal, RK ) / real ( tempVal2, RK )
        endif
#else
        write( IOBuffer, '("Acceptance rate inserts", T32, "in %:", F20.9)' ) &
&              100._RK * real( this%NInsertSuccesses, RK ) / real ( this%NInsertAttempts, RK )
#endif
        call FileWrite(this%errorsFile)

#if MPI_VER > 0
        if ( mpiMCCommonGroups > 0 ) then
          call MPI_Reduce( this%NDeleteSuccesses,tempVal, 1, MPI_INTEGER, MPI_SUM, NRootProc_W, MPI_COMM_WORLD, ierror )
          call MPI_Reduce( this%NDeleteAttempts,tempVal2, 1, MPI_INTEGER, MPI_SUM, NRootProc_W, MPI_COMM_WORLD, ierror )
        else
          call MPI_Reduce( this%NDeleteSuccesses,tempVal, 1, MPI_INTEGER, MPI_SUM, NRootProc, Communicator, ierror )
          call MPI_Reduce( this%NDeleteAttempts,tempVal2, 1, MPI_INTEGER, MPI_SUM, NRootProc, Communicator, ierror )
        endif
        if (Nproc == NRootProc) then
          write( IOBuffer, '("Acceptance rate deletes", T32, "in %:", F20.9)' ) &
&                100._RK * real(tempVal, RK ) / real ( tempVal2, RK )
        endif
#else
        write( IOBuffer, '("Acceptance rate deletes", T32, "in %:", F20.9)' ) &
&              100._RK * real( this%NDeleteSuccesses, RK ) / real ( this%NDeleteAttempts, RK )
#endif
        call FileWrite(this%errorsFile)
        call FileWriteBlank(this%errorsFile)
      end if

    end if



! Calculation of residence times
    if ( this%ResidenceTime ) then
      do i = 1, NBlockSizes
        do j = i, NBlocks, i
          if ( sum(this%SumResidenceDuration%NBlockSum(j - i + 1:j)) == 0 ) then
             this%SumResidenceDuration%NBlockSum(j - i + 1) = 1
             this%SumResidenceDuration%BlockSum(j - i + 1) = this%SumResidenceDuration%Average
          end if
        end do
      end do
      write(IOBuffer, '("Average pairs between")' )
      call FileWrite(this%errorsFile)
      write(IOBuffer, '("Comp.",I2," Site",I2,"  and Comp.",I2," Site",I2," =", F14.5)' ) &
&           this%ResidComp1, this%ResidSite1, &
&           this%ResidComp2, this%ResidSite2, this%SumResidencePairs%Average/this%Component(this%ResidComp1)%NPart
      call FileWrite(this%errorsFile)
      write(IOBuffer, '("Average residence time between")' )
      call FileWrite(this%errorsFile)
      call Error (this%SumResidenceDuration)

      if ( (this%SumResidenceDuration%NTotalsum .eq. 0) .and. (this%ResidPairs .ne. 0) ) then
         write(IOBuffer, '("Comp.",I2," Site",I2,"  and Comp.",I2," Site",I2," =", F20.5," fs")' ) &
&           this%ResidComp1, this%ResidSite1, &
&           this%ResidComp2, this%ResidSite2, Step*TimeStep* UnitTime * 1E15_RK
        call FileWrite(this%errorsFile)
        write(IOBuffer, '("No separation between the two components observed")' )

      else if ( (this%SumResidenceDuration%NTotalsum .eq. 0) .and. (this%ResidPairs .eq. 0) ) then
        write(IOBuffer, '("Comp.",I2," Site",I2,"  and Comp.",I2," Site",I2," =", F14.5," fs")' ) &
&           this%ResidComp1, this%ResidSite1, this%ResidComp2,this%ResidSite2,&
&           this%ResidenceDuration*UnitTime*1E15_RK
        call FileWrite(this%errorsFile)
        write(IOBuffer, '("No pairing between the two components observed")' )

      else
        write(IOBuffer, '("Comp.",I2," Site",I2,"  and Comp.",I2," Site",I2," =", F14.5," fs +-",F10.5)' ) &
&         this%ResidComp1,this%ResidSite1, &
&         this%ResidComp2,this%ResidSite2, this%SumResidenceDuration%Average*UnitTime*1E15_RK ,&
&         this%SumResidenceDuration%Variance*UnitTime*1E15_RK
      end if

      call FileWrite(this%errorsFile)
      write(IOBuffer, '("Critical distance: ",F10.5," A")' ) &
&           this%ResidLength*UnitLength/Angstroem
      call FileWrite(this%errorsFile)
    end if
    call FileWriteBlank(this%errorsFile)

#if MPI_VER > 0
    if ( mpiMCCommonGroups > 0 ) then
       if ( RootProc_MCCom ) then !=RootProc_W
         ! Close final result file
         call FileClose( this%errorsFile )
       endif
    else
       ! Close final result file
       call FileClose( this%errorsFile )
    endif
#else
    ! Close final result file
    call FileClose( this%errorsFile )
#endif

    ! Open ThermoInt result file
    if ( any(this%Component(:)%ChemPotMethod .eq. ChemPotMethodThermoInt)) then
      if (RootProc) then
        write( IOBuffer, '(I16)' ) this%EnsembleNumber
        call FileRewrite(this%thermointFile, trim( OutputNameTag )//'_'//trim( adjustl( IOBuffer ) )//ThermoIntFileExtension)
      end if

      t = this%NRealComponents+1
      do i=1,this%NRealComponents
         pc => this%Component(i)
        if (pc%ChemPotMethod .eq. ChemPotMethodThermoInt) then

          !first two lines
          if (RootProc) then
            write( IOBuffer, '(" Component:", T15, I3)' ) i
            call FileWrite(this%thermointFile)
            write( IOBuffer, '("currentlambda =", T20, F7.5)' ) this%Component(t)%lambda
            call FileWrite(this%thermointFile)
            write( IOBuffer, '(" BINID")' )
            call FileWriteNoAdvance(this%thermointFile)
            write( IOBuffer, '(" LAMBDA")' )
            call FileWriteNoAdvance(this%thermointFile)
            write( IOBuffer, '("            EPOT")' )
            call FileWriteNoAdvance(this%thermointFile)
            write( IOBuffer, '("    dEPOTdLAMBDA")' )
            call FileWriteNoAdvance(this%thermointFile)
            write( IOBuffer, '("   dEPOTdLAMBDAV")' )
            call FileWriteNoAdvance(this%thermointFile)
            write( IOBuffer, '("   dEPOTdLAMBDAH")' )
            call FileWriteNoAdvance(this%thermointFile)
            write( IOBuffer, '(" INTdEPOTdLAMBDA")' )
            call FileWriteNoAdvance(this%thermointFile)
            write( IOBuffer, '("       INTParVol")' )
            call FileWriteNoAdvance(this%thermointFile)
            write( IOBuffer, '("       INTParEnt")' )
            call FileWriteNoAdvance(this%thermointFile)
            write( IOBuffer, '("     VISITS")' )
            call FileWriteNoAdvance(this%thermointFile)
            call FileWriteBlank(this%thermointFile)
          end if

          call ErrorsUpdateThermoInt( this, i, pc%NBins )
          t = t+1
        end if

      end do

      ! Close final result file
      call FileClose(this%thermointFile)
    end if

    if( ALPHA2UpdateFrequency > 0 ) then !write *.a2rav
        if (RootProc) then
        write( IOBuffer, '(I16)' ) this%EnsembleNumber
        call FileRewrite(this%a2ravFile, trim( OutputNameTag )//'_'//trim( adjustl( IOBuffer ) )//ALPHA2ravFileExtension )
        write(IOBuffer, '(T8,"t*")')
        call FileWriteNoAdvance(this%a2ravFile)
        write(IOBuffer, '(T11,"t/fs")')
        call FileWriteNoAdvance(this%a2ravFile)
        write(IOBuffer, '(T11,"msd/sig^2")') !msd
        call FileWriteNoAdvance(this%a2ravFile)
        write(IOBuffer, '(T5,"alpha2")') !alpha2
        call FileWriteNoAdvance(this%a2ravFile)
        write(IOBuffer, '(T5,"gamma")') !gamma
        call FileWriteNoAdvance(this%a2ravFile)
        call FileWriteBlank(this%a2ravFile)
        do i=1,ALPHA2Length/ALPHA2UpdateFrequency
            write(IOBuffer, '(T2,F12.4)') i * ALPHA2UpdateFrequency * TimeStep
            call FileWriteNoAdvance(this%a2ravFile)
            write(IOBuffer, '(T2,F12.4)') i * ALPHA2UpdateFrequency * TimeStep * UnitTime * 1E15_RK
            call FileWriteNoAdvance(this%a2ravFile)
            write(IOBuffer, '(T4,F10.4)') this%dispR2Ave(i)*this%BoxLength**2 !msd
            call FileWriteNoAdvance(this%a2ravFile)
            write(IOBuffer, '(T4,F10.4)') 3_RK*this%dispR4Ave(i)/(5_RK*this%dispR2Ave(i)**2) - 1_RK !alpha2
            call FileWriteNoAdvance(this%a2ravFile)
            write(IOBuffer, '(T8,F10.4)') this%dispR2Ave(i)/this%dispR2invAve(i)/3_RK - 1_RK !gamma
            call FileWriteNoAdvance(this%a2ravFile)
            call FileWriteBlank(this%a2ravFile)
        end do
        write( IOBuffer, '("Number of records", T36, ":", I10)' ) this%alpha2aveCount
        call FileWriteNoAdvance(this%a2ravFile)
        call FileWriteBlank(this%a2ravFile)
        call FileClose(this%a2ravFile)
        end if
    end if

#if TRANS==1
    !EinsteinCoef ecoef output
    if(  (TransMethod .eq. Einstein) .or. (TransMethod .eq. GKEinstein)) then
       if (RootProc) then
         write( IOBuffer, '(I16)' ) this%EnsembleNumber
         call FileRewrite(this%ecoefFile, trim( OutputNameTag )//'_'//trim( adjustl( IOBuffer ) )//EinsteinCoefFileExtension)
         write(IOBuffer, '(T8,"t*")')
         call FileWriteNoAdvance(this%ecoefFile)
         write(IOBuffer, '(T12,"t")')
         call FileWriteNoAdvance(this%ecoefFile)
         do t=1,this%NComponents
            write( IOBuffer, '(T4,"Dself_",I1)' ) t
            call FileWriteNoAdvance(this%ecoefFile)
         end do

         if (this%NComponents > 1) then
            do t=1,this%NComponents
              do j=1,this%NComponents
                write( IOBuffer, '(T4,"Onsager_",2I1)' ) t,j
                call FileWriteNoAdvance(this%ecoefFile)
              end do
            end do
         end if

         write( IOBuffer, '(T4,"ShearV")' )
         call FileWriteNoAdvance(this%ecoefFile)

         call FileWriteBlank(this%ecoefFile)


        do i=1,this%NCorr
           value = (this%BoxLength**2)*(dsqrt(UnitEnergy/UnitMass)*UnitLength*1E10_RK)
           write(IOBuffer, '(T3,F12.4)') i * this%NStepCorr * TimeStep * UnitTime * 1E12_RK
           call FileWriteNoAdvance(this%ecoefFile)
           write(IOBuffer, '(T2,F12.4)') i * this%NStepCorr * TimeStep
           call FileWriteNoAdvance(this%ecoefFile)


           do t=1,this%NComponents
              write( IOBuffer, '(T4,F10.4)')  this%DselfEinsteinAve(i,t)*value
              call FileWriteNoAdvance(this%ecoefFile)
           end do

           if (this%NComponents > 1) then
            !I know, an extra information is here, it's just for checking
             do t=1,this%NComponents
               do j=1,this%NComponents
                  write( IOBuffer, '(T4,F10.4)') this%OnsagerEinsteinAve(i,t,j)*value
                  call FileWriteNoAdvance(this%ecoefFile)
               end do
             end do
           end if

           value = dsqrt(UnitEnergy*UnitMass)/UnitLength**2/1E-4_RK
           ! helpvar =  this%Density /(5._RK *this%NPart * this%Temperature)
            write( IOBuffer, '(T4,F10.4)')  this%EinsteinShearAve(i)*value*0.5/3.0*this%Density /(this%NPart * this%Temperature)
            call FileWriteNoAdvance(this%ecoefFile)
            call FileWriteBlank(this%ecoefFile)
        end do

        write( IOBuffer, '("Number of records", T36, ":", I10)' ) this%EinsteinCoefAveCount
        call FileWriteNoAdvance(this%ecoefFile)
        call FileWriteBlank(this%ecoefFile)
        write( IOBuffer, '("Coefficients are done in SI units*1E+10")' )
        call FileWriteNoAdvance(this%ecoefFile)
        call FileWriteBlank(this%ecoefFile)
        call FileClose(this%ecoefFile)
       end if
    end if
#endif
  end subroutine TEnsemble_ErrorsUpdate

!==============================================================!
!  Subroutine TEnsemble_ErrorsUpdateThermoInt                  !
!==============================================================!

  subroutine TEnsemble_ErrorsUpdateThermoInt( this, i, NBins )

    ! Include MPI header
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif
    ! Declare arguments
    type(TEnsemble)     :: this
    integer, intent(in) :: i
    integer, intent(in) :: NBins

    ! Declare local variables
    type(TComponent), pointer  :: pc
    integer                    :: j, LocalVisit
    real(RK)                   :: BinsEn(0:NBins-1), BinsdEndLa(0:NBins-1), BinsIntdEndLa(0:NBins-1)
    real(RK)                   :: BinsdEndLaV(0:NBins-1), BinsdEndLaH(0:NBins-1), BinsIntVW(0:NBins-1), BinsIntHW(0:NBins-1)
    integer                    :: BinsVisit(0:NBins-1)

    pc => this%Component(i)
    ! Average of each MPI process's histogram is saved in the thi file
#if MPI_VER > 0
    if (SimulationType .eq. MonteCarlo) then
      if ( mpiMCCommonGroups > 0 ) then
        call MPI_Reduce( pc%BinsEn(0: NBins-1)       *pc%BinsVisit(0: NBins-1), BinsEn(0: NBins-1), NBins, MPI_RK, MPI_SUM, NRootProc_W, MPI_COMM_WORLD, ierror )
        call MPI_Reduce( pc%BinsdEndLa(0: NBins-1)   *pc%BinsVisit(0: NBins-1), BinsdEndLa(0: NBins-1), NBins, MPI_RK, MPI_SUM, NRootProc_W, MPI_COMM_WORLD, ierror )
        call MPI_Reduce( pc%BinsdEndLaV(0: NBins-1)  *pc%BinsVisit(0: NBins-1), BinsdEndLaV(0: NBins-1), NBins, MPI_RK, MPI_SUM, NRootProc_W, MPI_COMM_WORLD, ierror )
        call MPI_Reduce( pc%BinsdEndLaH(0: NBins-1)  *pc%BinsVisit(0: NBins-1), BinsdEndLaH(0: NBins-1), NBins, MPI_RK, MPI_SUM, NRootProc_W, MPI_COMM_WORLD, ierror )
        call MPI_Reduce( pc%BinsIntdEndLa(0: NBins-1)                         , BinsIntdEndLa(0: NBins-1), NBins, MPI_RK, MPI_SUM, NRootProc_W, MPI_COMM_WORLD, ierror )
        call MPI_Reduce( pc%BinsIntVW(0: NBins-1)                             , BinsIntVW(0: NBins-1), NBins, MPI_RK, MPI_SUM, NRootProc_W, MPI_COMM_WORLD, ierror )
        call MPI_Reduce( pc%BinsIntHW(0: NBins-1)                             , BinsIntHW(0: NBins-1), NBins, MPI_RK, MPI_SUM, NRootProc_W, MPI_COMM_WORLD, ierror )
        call MPI_Reduce( pc%BinsVisit(0: NBins-1)                             , BinsVisit(0: NBins-1), NBins, MPI_INTEGER, MPI_SUM, NRootProc_W, MPI_COMM_WORLD, ierror )
        do j=0,pc%NBins-1
          if (BinsVisit(j) .eq. 0) then
            LocalVisit=1
          else
            LocalVisit=BinsVisit(j)
          end if
          BinsEn(j)        = BinsEn(j)/LocalVisit
          BinsdEndLa(j)    = BinsdEndLa(j)/LocalVisit
          BinsdEndLaV(j)   = BinsdEndLaV(j)/LocalVisit
          BinsdEndLaH(j)   = BinsdEndLaH(j)/LocalVisit
          BinsIntdEndLa(j) = BinsIntdEndLa(j)/NProcs_W
          BinsIntVW(j)     = BinsIntVW(j)/NProcs_W
          BinsIntHW(j)     = BinsIntHW(j)/NProcs_W
        end do
      else
        call MPI_Reduce( pc%BinsEn(0: NBins-1)       *pc%BinsVisit(0: NBins-1), BinsEn(0: NBins-1), NBins, MPI_RK, MPI_SUM, NRootProc, Communicator, ierror )
        call MPI_Reduce( pc%BinsdEndLa(0: NBins-1)   *pc%BinsVisit(0: NBins-1), BinsdEndLa(0: NBins-1), NBins, MPI_RK, MPI_SUM, NRootProc, Communicator, ierror )
        call MPI_Reduce( pc%BinsdEndLaV(0: NBins-1)  *pc%BinsVisit(0: NBins-1), BinsdEndLaV(0: NBins-1), NBins, MPI_RK, MPI_SUM, NRootProc, Communicator, ierror )
        call MPI_Reduce( pc%BinsdEndLaH(0: NBins-1)  *pc%BinsVisit(0: NBins-1), BinsdEndLaH(0: NBins-1), NBins, MPI_RK, MPI_SUM, NRootProc, Communicator, ierror )
        call MPI_Reduce( pc%BinsIntdEndLa(0: NBins-1)                         , BinsIntdEndLa(0: NBins-1), NBins, MPI_RK, MPI_SUM, NRootProc, Communicator, ierror )
        call MPI_Reduce( pc%BinsIntVW(0: NBins-1)                             , BinsIntVW(0: NBins-1), NBins, MPI_RK, MPI_SUM, NRootProc, Communicator, ierror )
        call MPI_Reduce( pc%BinsIntHW(0: NBins-1)                             , BinsIntHW(0: NBins-1), NBins, MPI_RK, MPI_SUM, NRootProc, Communicator, ierror )
        call MPI_Reduce( pc%BinsVisit(0: NBins-1)                             , BinsVisit(0: NBins-1), NBins, MPI_INTEGER, MPI_SUM, NRootProc, Communicator, ierror )
        do j=0,pc%NBins-1
          if (BinsVisit(j) .eq. 0) then
            LocalVisit=1
          else
            LocalVisit=BinsVisit(j)
          end if
          BinsEn(j)        = BinsEn(j)/LocalVisit
          BinsdEndLa(j)    = BinsdEndLa(j)/LocalVisit
          BinsdEndLaV(j)   = BinsdEndLaV(j)/LocalVisit
          BinsdEndLaH(j)   = BinsdEndLaH(j)/LocalVisit
          BinsIntdEndLa(j) = BinsIntdEndLa(j)/NProcs
          BinsIntVW(j)     = BinsIntVW(j)/NProcs
          BinsIntHW(j)     = BinsIntHW(j)/NProcs
        end do
      endif



    else
      BinsEn(:)        = pc%BinsEn(:)
      BinsdEndLa(:)    = pc%BinsdEndLa(:)
      BinsdEndLaV(:)   = pc%BinsdEndLaV(:)
      BinsdEndLaH(:)   = pc%BinsdEndLaH(:)
      BinsIntdEndLa(:) = pc%BinsIntdEndLa(:)
      BinsIntVW(:)     = pc%BinsIntVW(:)
      BinsIntHW(:)     = pc%BinsIntHW(:)
      BinsVisit(:)     = pc%BinsVisit(:)
    endif
#else
      BinsEn(:)        = pc%BinsEn(:)
      BinsdEndLa(:)    = pc%BinsdEndLa(:)
      BinsdEndLaV(:)   = pc%BinsdEndLaV(:)
      BinsdEndLaH(:)   = pc%BinsdEndLaH(:)
      BinsIntdEndLa(:) = pc%BinsIntdEndLa(:)
      BinsIntVW(:)     = pc%BinsIntVW(:)
      BinsIntHW(:)     = pc%BinsIntHW(:)
      BinsVisit(:)     = pc%BinsVisit(:)
#endif

    ! Rest.
    if (RootProc) then
      do j=0,pc%NBins-1
        write( IOBuffer, '(I6)' ) j
        call FileWriteNoAdvance(this%thermointFile)
        write( IOBuffer, '("  ",F5.3)' ) pc%LaMin+j*pc%deltaLa
        call FileWriteNoAdvance(this%thermointFile)
        write( IOBuffer, '(" ",E15.6)' ) BinsEn(j)
        call FileWriteNoAdvance(this%thermointFile)
        write( IOBuffer, '(" ",E15.6)' ) BinsdEndLa(j)
        call FileWriteNoAdvance(this%thermointFile)
        write( IOBuffer, '(" ",E15.6)' ) BinsdEndLaV(j)
        call FileWriteNoAdvance(this%thermointFile)
        write( IOBuffer, '(" ",E15.6)' ) BinsdEndLaH(j)
        call FileWriteNoAdvance(this%thermointFile)
        write( IOBuffer, '(" ",E15.6)' ) BinsIntdEndLa(j)
        call FileWriteNoAdvance(this%thermointFile)
        write( IOBuffer, '(" ",E15.6)' ) BinsIntVW(j)
        call FileWriteNoAdvance(this%thermointFile)
        write( IOBuffer, '(" ",E15.6)' ) BinsIntHW(j)
        call FileWriteNoAdvance(this%thermointFile)
        write( IOBuffer, '(" ",I10)' ) BinsVisit(j)
        call FileWriteNoAdvance(this%thermointFile)
        call FileWriteBlank(this%thermointFile)
      end do
    end if

  end subroutine TEnsemble_ErrorsUpdateThermoInt


!==============================================================!
!  Subroutine TEnsemble_SVCOutput                              !
!==============================================================!

  subroutine TEnsemble_SVCOutput( this )

    implicit none

    ! Declare arguments
    type(TEnsemble) :: this

    ! Declare local variables
    real(RK) :: value
    integer  :: i, j

    ! Open final result file
    write( IOBuffer, '(I16)' ) this%EnsembleNumber
    call FileRewrite(this%errorsFile, trim( OutputNameTag )//'_'//trim( adjustl( IOBuffer ) )//ErrorsFileExtension )

    call writeCitationHeader(this%errorsFile)

    ! Separator
    call FileWriteBlank(this%errorsFile)
    write( IOBuffer, '(76("="))' )
    call FileWrite(this%errorsFile)
    call FileWriteBlank(this%errorsFile)
    write( IOBuffer, '(T24, "SIMULATION RESULT FILE")' )
    call FileWrite(this%errorsFile)
    write( IOBuffer, '(T24, "----------------------")' )
    call FileWrite(this%errorsFile)
    call FileWriteBlank(this%errorsFile)

    ! Simulation type
    write( IOBuffer, '("Simulation type", T36, ":", 9X, A)' ) trim( SimulationTypeString )
    call FileWrite(this%errorsFile)

    ! Number of orientations
    write( IOBuffer, '("Number of orientations", T36, ":", I10)' ) NOrient
    call FileWrite(this%errorsFile)
    write( IOBuffer, '("Number of radial steps", T36, ":", I10)' ) NSteps
    call FileWrite(this%errorsFile)
    write( IOBuffer, '("Minimum radius", T29, "reduced:", F20.9)' ) MinRadius
    call FileWrite(this%errorsFile)
    write( IOBuffer, '(T32, "in A:", F20.9)' ) MinRadius * UnitLength / Angstroem
    call FileWrite(this%errorsFile)
    write( IOBuffer, '("Maximum radius", T29, "reduced:", F20.9)' ) MaxRadius
    call FileWrite(this%errorsFile)
    write( IOBuffer, '(T32, "in A:", F20.9)' ) MaxRadius * UnitLength / Angstroem
    call FileWrite(this%errorsFile)
    call FileWriteBlank(this%errorsFile)

    ! Temperature
    write( IOBuffer, '("Temperature", T29, "reduced:", F20.9)' ) this%Temperature
    call FileWrite(this%errorsFile)
    write( IOBuffer, '(T32, "in K:", F20.9)' ) this%Temperature * UnitTemperature
    call FileWrite(this%errorsFile)
    call FileWriteBlank(this%errorsFile)

    ! System of units
    write( IOBuffer, '("Unit of length", T36, ":", F20.9, " A")' ) UnitLength / Angstroem
    call FileWrite(this%errorsFile)
    write( IOBuffer, '("Unit of energy", T36, ":", F20.9, " K")' ) UnitEnergy / kBoltzmann
    call FileWrite(this%errorsFile)
    write( IOBuffer, '("Unit of mass", T36, ":", F20.9, " a.u.")' ) UnitMass * NAvogadro * 1000._RK
    call FileWrite(this%errorsFile)
    call FileWriteBlank(this%errorsFile)

    ! Separator
    call writeSeparator(this%errorsFile, noHline = .false., errorColumn = .false.)

    ! Second virial coefficient
    do i = 1, this%NComponents, 2
      do j = i + 1, this%NComponents, 2
        if( this%NMIEnmMax > 0 ) then
            value = this%Interaction(i, j)%IntFFunction(NSteps) + &
&               .5_RK * this%Interaction(i, j)%EPotCorrMIE / this%Temperature
        end if
        if( this%NTT68Max > 0 ) then
            value = this%Interaction(i, j)%IntFFunction(NSteps) + &
&               .5_RK * this%Interaction(i, j)%EPotCorrTT68 / this%Temperature
        end if
        if (EnsembleType .eq. EnsembleTypeNPTSVC) then
           ArrSVC(i, j, this%EnsembleNumber) = value
        end if
        write( IOBuffer, '("2. VC of ", A, "-", A, T29, "reduced:", F20.9)' ) &
&              trim( this%Component(i)%Molecule%PotModFileName ), &
&              trim( this%Component(j)%Molecule%PotModFileName ), value
        call FileWrite(this%errorsFile)
        write( IOBuffer, '(T28, "in l/mol:", F20.9)' ) value / UnitDensity
        call FileWrite(this%errorsFile)
      end do
    end do
    call FileWriteBlank(this%errorsFile)

    ! Temperature deviation of second virial coefficient
    do i = 1, this%NComponents, 2
      do j = i + 1, this%NComponents, 2
        value = ( this%Interaction(i, j)%IntFFunction2(NSteps) - this%Interaction(i,j)%IntFFunction1(NSteps) ) &
&               / ( .0002_RK * this%Temperature )
        if (EnsembleType .eq. EnsembleTypeNPTSVC) then
           ArrdBdT(i, j, this%EnsembleNumber) = value
        end if
        write( IOBuffer, '("dB/dT of ", A, "-", A, T29, "reduced:", F20.9)' ) &
&              trim( this%Component(i)%Molecule%PotModFileName ), &
&              trim( this%Component(j)%Molecule%PotModFileName ), value
        call FileWrite(this%errorsFile)
        write( IOBuffer, '(T24, "in l/(mol K):", F20.9)' ) value / ( UnitDensity * UnitTemperature )
        call FileWrite(this%errorsFile)
      end do
    end do
    call FileWriteBlank(this%errorsFile)

    ! Separator
    write( IOBuffer, '(76("="))' )
    call FileWrite(this%errorsFile)
    call FileWriteBlank(this%errorsFile)

    ! Close final result file
    call FileClose(this%errorsFile)

  end subroutine TEnsemble_SVCOutput



!==============================================================!
!  Subroutine TEnsemble_VisualOpen                             !
!==============================================================!

  subroutine TEnsemble_VisualOpen( this )

    implicit none

    ! Declare arguments
    type(TEnsemble) :: this

    ! Declare local variables
    integer                   :: i, j
    type(TSiteMIEnm), pointer :: psMIEnm
    type(TSiteTT68), pointer  :: psTT68

    ! Open visualization file
    write( IOBuffer, '(I16)' ) this%EnsembleNumber
    call FileRewrite(this%visualFile, trim( OutputNameTag )//'_'//trim( adjustl( IOBuffer ) )//VisualFileExtension )

    ! Create header
    do i = 1, this%NComponents
      if( this%NMIEnmMax > 0 ) then
        do j = 1, this%Component(i)%Molecule%NMIEnm
          psMIEnm => this%Component(i)%Molecule%SiteMIEnm(j)
          write( IOBuffer, '("~", I3, " ", A, 4F8.4, "  1")' ) i, trim(LJorMIE), psMIEnm%r(:) * UnitLength / Angstroem, &
&              psMIEnm%sig  * UnitLength / Angstroem
          call FileWrite(this%visualFile)
        end do
      end if
      if( this%NTT68Max > 0 ) then
        do j = 1, this%Component(i)%Molecule%NTT68
          psTT68 => this%Component(i)%Molecule%SiteTT68(j)
          write( IOBuffer, '("~", I3, " TT", 4F8.4, "  1")' ) i, psTT68%r(:) * UnitLength / Angstroem, &
&             UnitLength / Angstroem
          call FileWrite(this%visualFile)
        end do
      end if
    end do
    call FileWriteBlank(this%visualFile)

#if HBOND > 0
    !Open visualization file for H-bondings
    write( IOBuffer, '(I16)' ) this%EnsembleNumber
    call FileRewrite(this%visualHBFile, &
&     trim( OutputNameTag )//'_'//trim( adjustl( IOBuffer ) )//VisualHBFileExtension )
    write( IOBuffer, '("!"," Nr", " ", " MO_1", " MO_2")' )
    call FileWrite(this%visualHBFile)
    call FileWriteBlank(this%visualHBFile)
#endif

  end subroutine TEnsemble_VisualOpen


!==============================================================!
!  Subroutine TEnsemble_VisualUpdate                           !
!==============================================================!

  subroutine TEnsemble_VisualUpdate( this )

    implicit none

    ! Declare arguments
    type(TEnsemble) :: this

    ! Declare local variables
    integer  :: i, j
    logical  :: l
    real(RK) :: r(3), q(4)

    !DC NOTE this prevent update of data on stopped simulations
    if (this%isStopSimulation .eqv. .true.) then
      return
    endif
    ! Update visualization file
    write( IOBuffer, '("#", F10.4, "  new Frame")' ) this%BoxLength * UnitLength / Angstroem
    call FileWrite(this%visualFile)
    do i = 1, this%NComponents
      l = this%Component(i)%Molecule%isElongated
      do j = 1, this%Component(i)%NPart
        r(:) = this%Component(i)%P0(j, :)

        if( l ) then
          q(:) = this%Component(i)%Q0(j, :)
        else
          q(1) = 1._RK
          q(2:4) = 0._RK
        end if

        r(:) = r(:) + .5_RK
        write( IOBuffer, '("!", I3, 3I4, 4I5)' ) i, nint( r(:) * 999 ), nint( q(:) * 999 )
        call FileWrite(this%visualFile)
      end do
    end do
    call FileWriteBlank(this%visualFile)

  end subroutine TEnsemble_VisualUpdate


