  end subroutine TEnsemble_ProfileOpen


!==============================================================!
!  Subroutine TEnsemble_ProfileUpdate                          !
!==============================================================!

  subroutine TEnsemble_ProfileUpdate( this )

    implicit none

    ! Declare arguments
    type(TEnsemble) :: this

    ! Declare local variables
    integer  :: i, j
    real(RK) :: Variance, Average
    type(TComponent), pointer :: pc

    !DC NOTE this prevent update of data on stopped simulations
    if (this%isStopSimulation .eqv. .true.) then
      return
    endif
    ! Open profile file
    write( IOBuffer, '(I16)' ) this%EnsembleNumber
    call FileRewrite(this%dcpFile, trim( OutputNameTag )//'_'//trim( adjustl( IOBuffer ) )//DCPFileExtension )

    ! Create header
    write( IOBuffer, '("#", F10.4, "  BoxLength / A")' ) this%BoxLength * UnitLength / Angstroem
    call FileWrite(this%dcpFile)
    call FileWriteBlank(this%dcpFile)
    write( IOBuffer, '(" Bin")')
    call FileWriteNoAdvance (this%dcpFile)
    write( IOBuffer, '(" Position")')
    call FileWriteNoAdvance (this%dcpFile)
    do j=1,this%NComponents
      pc => this%Component(j)
      write( IOBuffer, '(" rho_", A)') trim( pc%PotModFileName )
      call FileWriteNoAdvance(this%dcpFile)
#if OSMOP == 2
      if ( pc%ChemPotMethod .eq. ChemPotMethodWidom ) then
        write( IOBuffer, '(" mueAvg_", A, " mueVar_", A)') trim( pc%PotModFileName ), trim( pc%PotModFileName )
        call FileWriteNoAdvance(this%dcpFile)
      end if
    end do
    write( IOBuffer, '(" PressureAvg PressureVar")')
    call FileWriteNoAdvance(this%dcpFile)
#else
    end do
#endif
    call FileWriteBlank(this%dcpFile)

    ! Update profile file
    do i = 1, NBinsDen
      write( IOBuffer, '( I3, F8.4)') i, real(i)/NBinsDen
      call FileWriteNoAdvance (this%dcpFile)
      do j = 1, this%NComponents
        pc => this%Component(j)
        write( IOBuffer, '(F10.4)') pc%SumDenProfile(i)%Average * UnitDensity
        call FileWriteNoAdvance(this%dcpFile)
#if OSMOP == 2
        if ( pc%ChemPotMethod .eq. ChemPotMethodWidom ) then
          Variance = pc%SumChemPotProfile(i)%Variance / pc%SumChemPotProfile(i)%Average
          Average = log( pc%SumDenProfile(i)%Average / pc%SumChemPotProfile(i)%Average )
          write( IOBuffer, '(F10.4, F10.4)') Average, Variance
          call FileWriteNoAdvance(this%dcpFile)
        end if
      end do
      Average = this%SumPressureProfile(i)%Average * UnitPressure * 1E-6_RK
      Variance = this%SumPressureProfile(i)%Variance * UnitPressure * 1E-6_RK
      write( IOBuffer, '(F11.4, F10.4)') Average, Variance
      call FileWriteNoAdvance(this%dcpFile)
#else
      end do
#endif
      call FileWriteBlank(this%dcpFile)
    end do
    call FileWriteBlank(this%dcpFile)

    call FileClose(this%dcpFile)

  end subroutine TEnsemble_ProfileUpdate


!==============================================================!
!  Subroutine TEnsemble_ProfileClose                           !
!==============================================================!

  subroutine TEnsemble_ProfileClose( this )

    implicit none

    ! Declare arguments
    type(TEnsemble) :: this

    write( IOBuffer, '("##")' )
    call FileWrite(this%dcpFile)
    call FileClose(this%dcpFile)

  end subroutine TEnsemble_ProfileClose
#endif

!==============================================================!
!  Subroutine TEnsemble_ODFOpen                                !
!==============================================================!
 subroutine TEnsemble_ODFOpen( this )

    implicit none

    ! Declare arguments
    type(TEnsemble) :: this

    ! Declare local variables
    integer                   :: i, j

    if( .not. Restart ) then
        ! initialize ODFSum and Error Sum
        do i=1, this%NComponents
          do j=i, this%NComponents
            if (((this%Component(i)%Molecule%NDipole .GE. 1) .or. (this%Component(i)%Molecule%NCharge .GE. 2)) .and. &
&               ((this%Component(j)%Molecule%NDipole .GE. 1) .or. (this%Component(j)%Molecule%NCharge .GE. 2)))then
                this%Interaction(i,j)%ODFErrSum = 0
                this%Interaction(i,j)%ODFSum(:,:,:,:) = 0
            end if
          end do
        end do
    end if

    ! Open visualization file
    write( IOBuffer, '(I16)' ) this%EnsembleNumber
    call FileRewrite(this%odfFile, trim( OutputNameTag )//'_'//trim( adjustl( IOBuffer ) )//ODFFileExtension )
    call FileWriteBlank(this%odfFile)
    call FileClose(this%odfFile)

  end subroutine TEnsemble_ODFOpen

!==============================================================!
!  Subroutine TEnsemble_ODFUpdate                              !
!==============================================================!

  subroutine TEnsemble_ODFUpdate( this )

    implicit none

    ! Declare arguments
    type(TEnsemble) :: this

    ! Declare local variables
    integer  :: i, j

    !DC NOTE this prevent update of data on stopped simulations
    if (this%isStopSimulation .eqv. .true.) then
      return
    endif
    ! Calculate ODFSum with ODFUpdateFrequency
    do i= 1, this%NComponents
      do j= i, this%NComponents
        if (((this%Component(i)%Molecule%NDipole .GE. 1) .or. (this%Component(i)%Molecule%NCharge .GE. 2)) .and. &
&           ((this%Component(j)%Molecule%NDipole .GE. 1) .or. (this%Component(j)%Molecule%NCharge .GE. 2)))then
            call Get_ODF( this%Interaction(i,j), this%dPhi, this%dGamma, this%dR/this%BoxLength )
        end if
      end do
    end do

    ! Rewrite ODF file with ODFOutputFrequency
    if ( mod( Step-1, ODFOutputFrequency ) == 0 .and. Step .gt. 1 ) then
        call ODFUpdateBlock (this)
    end if

  end subroutine TEnsemble_ODFUpdate


!==============================================================!
!  Subroutine TEnsemble_ODFUpdateBlock                         !
!==============================================================!

  subroutine TEnsemble_ODFUpdateBlock( this )

    implicit none

    ! Include MPI header
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif

    ! Declare arguments
    type(TEnsemble) :: this

    ! Declare local variables
    integer  :: i, j, o, p, q, r, ErrSum_hilf, ErrSum
    real(RK) :: ODFvalue_hilf, NormValue
    real(RK) :: ODFNorm_hilf(this%NComponents,this%NComponents,nR)

#if MPI_VER > 0
    real(RK) :: ODFNorm_out(this%NComponents,this%NComponents,nR)
    real(RK) :: ODFvalue_norm
#endif
    ! write header of *.odf file
    write( IOBuffer, '(I16)' ) this%EnsembleNumber
    call FileRewrite(this%odfFile, trim( OutputNameTag )//'_'//trim( adjustl( IOBuffer ) )//ODFFileExtension )
    ErrSum_hilf = 0
    do i= 1, this%NComponents
        do j= i, this%NComponents
            ErrSum_hilf = ErrSum_hilf + this%Interaction(i,j)%ODFErrSum
        end do
    end do
#if MPI_VER > 0
    if (mpiMCCommonGroups > 0 ) then
      call MPI_Reduce( ErrSum_hilf, ErrSum, 1, MPI_INTEGER, MPI_SUM, NRootProc_W, MPI_COMM_WORLD, ierror )
    else
      call MPI_Reduce( ErrSum_hilf, ErrSum, 1, MPI_INTEGER, MPI_SUM, NRootProc, Communicator, ierror )
    endif
#else
    ErrSum = ErrSum_hilf
#endif

    ! calculate average ODF value for normalization of ODF
    ODFNorm_hilf(:,:,:) = 0._RK
    do i= 1, this%NComponents
        do j= i, this%NComponents
            if (((this%Component(i)%Molecule%NDipole .GE. 1) .or. (this%Component(i)%Molecule%NCharge .GE. 2)) .and. &
&               ((this%Component(j)%Molecule%NDipole .GE. 1) .or. (this%Component(j)%Molecule%NCharge .GE. 2)))then
                do o = 1, nPhi
                    do p = 1, nPhi
                        do q = 1, nGamma
                            do r=1, nR
                                ODFNorm_hilf(i,j,r) = ODFNorm_hilf(i,j,r) &
&                                 + real(this%Interaction(i,j)%ODFSum(o, p, q, r))
                            end do
                        end do
                    end  do
                end do
            end if
        end do
    end do

    do i= 1, this%NComponents
        do j= i, this%NComponents
            if (((this%Component(i)%Molecule%NDipole .GE. 1) .or. (this%Component(i)%Molecule%NCharge .GE. 2)) .and. &
&               ((this%Component(j)%Molecule%NDipole .GE. 1) .or. (this%Component(j)%Molecule%NCharge .GE. 2)))then
                do r= 1, nR
                    ODFNorm_hilf(i,j,r) = ODFNorm_hilf(i,j,r) / ( nPhi * nPhi * nGamma)
                end do
            end if
        end do
    end do

#if MPI_VER > 0
    ODFNorm_out(:,:,:) = 0._RK
    do i= 1, this%NComponents
        do j= i, this%NComponents
            if (((this%Component(i)%Molecule%NDipole .GE. 1) .or. (this%Component(i)%Molecule%NCharge .GE. 2)) .and. &
&               ((this%Component(j)%Molecule%NDipole .GE. 1) .or. (this%Component(j)%Molecule%NCharge .GE. 2)))then
                do r= 1, nR
                    if (mpiMCCommonGroups > 0 ) then
                      call MPI_Reduce( ODFNorm_hilf(i,j,r), ODFNorm_out(i,j,r), 1, MPI_RK, MPI_SUM, &
&                                      NRootProc_W, MPI_COMM_WORLD, ierror )
                    else
                      call MPI_Reduce( ODFNorm_hilf(i,j,r), ODFNorm_out(i,j,r), 1, MPI_RK, MPI_SUM, &
&                                      NRootProc, Communicator, ierror )
                    endif
                end do
            end if
        end do
    end do
#endif
    write(IOBuffer, '("ODF Calculation failed ",I7, " times during simulation")') ErrSum
    call FileWriteNoAdvance(this%odfFile)
    call FileWriteBlank(this%odfFile)
    write(IOBuffer, '("Normalization values of ODF: ")')
    call FileWriteNoAdvance(this%odfFile)
    call FileWriteBlank(this%odfFile)

    do i= 1, this%NComponents
        do j= 1, this%NComponents
            if (((this%Component(i)%Molecule%NDipole .GE. 1) .or. (this%Component(i)%Molecule%NCharge .GE. 2)) .and. &
&               ((this%Component(j)%Molecule%NDipole .GE. 1) .or. (this%Component(j)%Molecule%NCharge .GE. 2)))then
                write(IOBuffer, '(I5,I5)') i, j
                call FileWriteNoAdvance(this%odfFile)
            end if
        end do
    end do

    call FileWriteBlank(this%odfFile)
    do r=1, nR
        write(IOBuffer, '("r = ",F10.6," ")') (r*this%dR-this%dR/2._RK)
        call FileWriteNoAdvance(this%odfFile)
        do i= 1, this%NComponents
            do j= 1, this%NComponents
                if (((this%Component(i)%Molecule%NDipole .GE. 1) .or. (this%Component(i)%Molecule%NCharge .GE. 2)) .and. &
&                   ((this%Component(j)%Molecule%NDipole .GE. 1) .or. (this%Component(j)%Molecule%NCharge .GE. 2)))then
#if MPI_VER > 0
                    if (i == j) then
                        NormValue = 2._RK*ODFNorm_out(i,j,r)
                    else if(i > j) then
                        NormValue = ODFNorm_out(j,i,r)
                    else
                        NormValue = ODFNorm_out(i,j,r)
                    end if
#else
                    if (i == j) then
                        NormValue = 2._RK*ODFNorm_hilf(i,j,r)
                    else if(i > j) then
                        NormValue = ODFNorm_hilf(j,i,r)
                    else
                        NormValue = ODFNorm_hilf(i,j,r)
                    end if
#endif
                    write(IOBuffer, '(" ",F16.6," ")') NormValue
                    call FileWriteNoAdvance(this%odfFile)
                end if
            end do
        end do
        call FileWriteBlank(this%odfFile)
    end do

    call FileWriteBlank(this%odfFile)
    write(IOBuffer, '("cos(phi1)    cos(phi2)   gamma12     r   ")')
    call FileWriteNoAdvance(this%odfFile)

    do i= 1, this%NComponents
        do j= 1, this%NComponents
            if (((this%Component(i)%Molecule%NDipole .GE. 1) .or. (this%Component(i)%Molecule%NCharge .GE. 2)) .and. &
&               ((this%Component(j)%Molecule%NDipole .GE. 1) .or. (this%Component(j)%Molecule%NCharge .GE. 2)))then
                write(IOBuffer, '(I5,I5)') i,j
                call FileWriteNoAdvance(this%odfFile)
            end if
        end do
    end do
    call FileWriteBlank(this%odfFile)

#if MPI_VER > 0
    do o = 1, nPhi
        do p = 1, nPhi
            do q = 1, nGamma
                do r=1, nR
                    write(IOBuffer, '(4F10.4)') (1._RK - o*this%dPhi+this%dPhi/2._RK), (1._RK - p*this%dPhi+this%dPhi/2._RK), &
                    & (q*this%dGamma-this%dGamma/2._RK), (r*this%dR-this%dR/2._RK)
                    call FileWriteNoAdvance(this%odfFile)
                    do i= 1, this%NComponents
                        do j= 1, this%NComponents
                            if (((this%Component(i)%Molecule%NDipole .GE. 1) .or. (this%Component(i)%Molecule%NCharge .GE. 2)) .and. &
&                               ((this%Component(j)%Molecule%NDipole .GE. 1) .or. (this%Component(j)%Molecule%NCharge .GE. 2)))then
                                if (i == j) then ! for i == j the fact that every pair of molecules is only sampled once needs to be made up for by manually adding the value of the missing interaction. this also enforces perfect symmetry
                                    ODFvalue_hilf = real(this%Interaction(i,j)%ODFSum(o, p, q, r)) &
&                                     + real(this%Interaction(i,j)%ODFSum(nPhi + 1 - p, nPhi + 1 - o, q, r))
                                else if (i > j) then ! ODF_ij for i > j is not sampled explicitly during simulation. Instead the data of ODF_ji is used to generate output for ODF_ij
                                    ODFvalue_hilf = real(this%Interaction(j,i)%ODFSum(nPhi &
&                                     + 1 - p, nPhi + 1 - o, q, r))
                                else
                                    ODFvalue_hilf = real(this%Interaction(i,j)%ODFSum(o, p, q, r))
                                end if
                                if (mpiMCCommonGroups > 0 ) then
                                  call MPI_Reduce( ODFvalue_hilf, ODFvalue_norm, 1, MPI_RK, MPI_SUM, &
&                                                  NRootProc_W, MPI_COMM_WORLD, ierror)
                                else
                                  call MPI_Reduce( ODFvalue_hilf, ODFvalue_norm, 1, MPI_RK, MPI_SUM, &
&                                                  NRootProc, Communicator, ierror)
                                endif
                                if (i == j) then
                                    this%ODFvalue(o,p,q,r) = ODFvalue_norm / (2._RK*ODFNorm_out(i,j,r)) ! 2*Norm because missing interactions have been added
                                else if(i > j) then
                                    this%ODFvalue(o,p,q,r) = ODFvalue_norm / ODFNorm_out(j,i,r)  ! indices i and j are changed here because norm_ij for i > j is not computed but should be identical to norm_ji
                                else
                                    this%ODFvalue(o,p,q,r) = ODFvalue_norm / ODFNorm_out(i,j,r)
                                end if
                                write(IOBuffer, '(F10.4)') this%ODFvalue(o,p,q,r)
                                call FileWriteNoAdvance(this%odfFile)
                                ODFvalue_norm = 0._RK
                            end if
                        end do
                    end do
                call FileWriteBlank(this%odfFile)
                end do
            end do
        end do
    enddo
#else
    do o = 1, nPhi
        do p = 1, nPhi
            do q = 1, nGamma
                do r=1, nR
                    write(IOBuffer, '(4F10.4)') (1._RK - o*this%dPhi+this%dPhi/2._RK), (1._RK - p*this%dPhi+this%dPhi/2._RK), &
                    & (q*this%dGamma-this%dGamma/2._RK), (r*this%dR-this%dR/2._RK)
                    call FileWriteNoAdvance(this%odfFile)
                    do i= 1, this%NComponents
                        do j= 1, this%NComponents
                            if (((this%Component(i)%Molecule%NDipole .GE. 1).or.(this%Component(i)%Molecule%NCharge .GE. 2)).and. &
&                               ((this%Component(j)%Molecule%NDipole .GE. 1) .or. (this%Component(j)%Molecule%NCharge .GE. 2)))then
                                if (i == j) then
                                    this%ODFvalue(o,p,q,r) = (real(this%Interaction(i,j)%ODFSum(o, p, q, r)) &
&                                     + real(this%Interaction(i,j)%ODFSum(nPhi + 1 - p, nPhi + 1 - o, q, r))) &
&                                     / (2._RK*ODFNorm_hilf(i,j,r))
                                else if (i > j) then
                                    this%ODFvalue(o,p,q,r) = real(this%Interaction(j,i)%ODFSum(nPhi + &
&                                     1 - p, nPhi + 1 - o, q, r))  / ODFNorm_hilf(j,i,r)
                                else
                                    this%ODFvalue(o,p,q,r) = real(this%Interaction(i,j)%ODFSum(o, p, q, r)) &
&                                     / ODFNorm_hilf(i,j,r)
                                end if
                                write(IOBuffer, '(F10.4)') this%ODFvalue(o,p,q,r)
                                call FileWriteNoAdvance(this%odfFile)
                            end if
                        end do
                    end do
                call FileWriteBlank(this%odfFile)
                end do
            end do
        end do
    enddo
#endif
    call FileClose(this%odfFile)


  end subroutine TEnsemble_ODFUpdateBlock



!==============================================================!
!  Subroutine TEnsemble_ODFClose                               !
!==============================================================!

  subroutine TEnsemble_ODFClose( this )

    implicit none

    ! Declare arguments
    type(TEnsemble) :: this

    ! Close visualization file
    write( IOBuffer, '("##")' )
    call FileWrite(this%odfFile)
    call FileClose(this%odfFile)

  end subroutine TEnsemble_ODFClose

!==============================================================!
!  Subroutine TEnsemble_RDFOpen                                !
!==============================================================!

  subroutine TEnsemble_RDFOpen( this )

    implicit none

    ! Declare arguments
    type(TEnsemble) :: this

    ! Declare local variables
    integer         :: i, j, s, t

    if( .not. Restart ) then
        ! initialize RDFSum
        do i=1, this%NComponents
          do j=i, this%NComponents
            if( this%NMIEnmMax > 0 ) then
              do s=1, this%component(i)%molecule%NMIEnm
                do t=1, this%component(j)%molecule%NMIEnm
                  this%Interaction(i,j)%PotMIEnmMIEnm(s, t)%RDFSum(:) = 0
                end do
              end do
            end if
            if( this%NTT68Max > 0 ) then
              do s=1, this%component(i)%molecule%NTT68
                do t=1, this%component(j)%molecule%NTT68
                  this%Interaction(i,j)%PotTT68TT68(s, t)%RDFSum(:) = 0
                end do
              end do
            end if
          end do
        end do
    end if

#if MPI_VER > 0
    if ( mpiMCCommonGroups > 0 ) then
       if ( .not. RootProc_MCCom ) return !=RootProc_W, only the head (RootProc_MCCom) of all RootProc (head of each group)
    endif
#endif

    ! Open visualization file
    write( IOBuffer, '(I16)' ) this%EnsembleNumber
    call FileRewrite(this%rdfFile, trim( OutputNameTag )//'_'//trim( adjustl( IOBuffer ) )//RDFFileExtension )
    call FileWriteBlank(this%rdfFile)
    call FileClose(this%rdfFile)

  end subroutine TEnsemble_RDFOpen


!==============================================================!
!  Subroutine TEnsemble_RDFUpdate                              !
!==============================================================!

  subroutine TEnsemble_RDFUpdate( this )

    implicit none

    ! Declare arguments
    type(TEnsemble) :: this

    ! Declare local variables
    integer  :: i, j

    !DC NOTE this prevent update of data on stopped simulations
    if (this%isStopSimulation .eqv. .true.) then
      return
    endif
    ! Calculate RDFSum with RDFUpdateFrequency
    do i= 1, this%NComponents
      do j= i, this%NComponents
        call Get_RDF( this%Interaction(i,j), this%RDFdr/this%BoxLength )
      end do
    end do

    ! Rewrite RDF file with ErrorsUpdateFrequency
    if ( mod( Step-1, ErrorsUpdateFrequency ) == 0 .and. Step .gt. 1 ) then
        call RDFUpdateBlock (this)
    end if

  end subroutine TEnsemble_RDFUpdate


!==============================================================!
!  Subroutine TEnsemble_RDFUpdateBlock                         !
!==============================================================!

  subroutine TEnsemble_RDFUpdateBlock( this )

    implicit none

    ! Include MPI header
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif

    ! Declare arguments
    type(TEnsemble) :: this

    ! Declare local variables
    integer  :: i, j, s, t, o
    real(RK) :: RDFRho, RDFRhoLocal
#if MPI_VER > 0
    real(RK) :: RDF_hilf(RDFNumberShells)
    integer  :: RDFSum_hilf(RDFNumberShells)
    integer  :: RDFSum_out(RDFNumberShells)
#endif

#if MPI_VER > 0
    if ( mpiMCCommonGroups > 0 ) then
       if ( RootProc_MCCom ) then !=RootProc_W, only the head (RootProc_MCCom) of all RootProc (head of each group)
         ! write header of *.rdf file
         write( IOBuffer, '(I16)' ) this%EnsembleNumber
         call FileRewrite( this%rdfFile, trim( OutputNameTag )//'_'//trim( adjustl( IOBuffer ) )//RDFFileExtension )
       endif
    else
       ! write header of *.rdf file
       write( IOBuffer, '(I16)' ) this%EnsembleNumber
       call FileRewrite( this%rdfFile, trim( OutputNameTag )//'_'//trim( adjustl( IOBuffer ) )//RDFFileExtension )
    endif
#else
    ! write header of *.rdf file
    write( IOBuffer, '(I16)' ) this%EnsembleNumber
    call FileRewrite( this%rdfFile, trim( OutputNameTag )//'_'//trim( adjustl( IOBuffer ) )//RDFFileExtension )
#endif

    write(IOBuffer, '(T5," r [A]")')
    call FileWriteNoAdvance(this%rdfFile)

    ! MIE
    if( this%NMIEnmMax > 0 ) then
      do i= 1, this%NComponents
        do j= i, this%NComponents
          do s=1, this%Component(i)%molecule%NMIEnm
            do t=1, this%Component(j)%molecule%NMIEnm
              write(IOBuffer, '(I5,I5)') i, j
              call FileWriteNoAdvance(this%rdfFile)
            end do
          end do
        end do
      end do
      call FileWriteBlank(this%rdfFile)
      write(IOBuffer, '(T5,"______")')
      call FileWriteNoAdvance(this%rdfFile)
      do i= 1, this%NComponents
        do j= i, this%NComponents
          do s=1, this%Component(i)%molecule%NMIEnm
            do t=1, this%Component(j)%molecule%NMIEnm
              write(IOBuffer, '(I5,I5)') s, t
              call FileWriteNoAdvance(this%rdfFile)
            end do
          end do
        end do
      end do
    end if
    ! TT68
    if( this%NTT68Max > 0 ) then
      do i= 1, this%NComponents
        do j= i, this%NComponents
          do s=1, this%Component(i)%molecule%NTT68
            do t=1, this%Component(j)%molecule%NTT68
              write(IOBuffer, '(I5,I5)') i, j
              call FileWriteNoAdvance(this%rdfFile)
            end do
          end do
        end do
      end do
      call FileWriteBlank(this%rdfFile)
      write(IOBuffer, '(T5,"______")')
      call FileWriteNoAdvance(this%rdfFile)
      do i= 1, this%NComponents
        do j= i, this%NComponents
          do s=1, this%Component(i)%molecule%NTT68
            do t=1, this%Component(j)%molecule%NTT68
              write(IOBuffer, '(I5,I5)') s, t
              call FileWriteNoAdvance(this%rdfFile)
            end do
          end do
        end do
      end do
    end if
    call FileWriteBlank(this%rdfFile)

    ! Calculate RDF
#if MPI_VER > 0
    if ( SimulationType .eq. MonteCarlo ) then
        do o = 1, RDFNumberShells
            write(IOBuffer, '(F10.4)') (o*this%RDFdr*UnitLength/Angstroem)
            call FileWriteNoAdvance(this%rdfFile)
            do i= 1, this%NComponents
                do j= i, this%NComponents
                  if( this%NMIEnmMax > 0 ) then
                    do s=1, this%Component(i)%molecule%NMIEnm
                        do t=1, this%Component(j)%molecule%NMIEnm
                            RDFRho = this%SumDensity%Average  * this%Component(j)%Fraction
                            if (i == j) then
                                RDFRhoLocal = 2.0 * real(this%Interaction(i,j)%PotMIEnmMIEnm(s,t)%RDFSum(o),RK) &
&                                       / (this%RDFVSchale(o) * ((Step-1)/RDFUpdateFrequency + 1) * this%Component(i)%NPart)
                            else
                                RDFRhoLocal = real(this%Interaction(i,j)%PotMIEnmMIEnm(s,t)%RDFSum(o),RK) &
&                                       / (this%RDFVSchale(o) * ((Step-1)/RDFUpdateFrequency + 1) * this%Component(i)%NPart)
                            end if
                            this%RDFValue(o) = RDFRhoLocal / RDFRho
                            ! Calculate average over all prozesses with MPI_Reduce
                            if ( mpiMCCommonGroups > 0 ) then
                              call MPI_Reduce( this%RDFValue(o), RDF_hilf(o), 1, MPI_RK, MPI_SUM, NRootProc_MCCom, MCCommonGroups_R, ierror )
                              this%RDFValue(o) = RDF_hilf(o) / mpiMCCommonGroups
                            else
                              call MPI_Reduce( this%RDFValue(o), RDF_hilf(o), 1, MPI_RK, MPI_SUM, NRootProc, Communicator, ierror )
                              this%RDFValue(o) = RDF_hilf(o) / NProcs
                            endif
                            write(IOBuffer, '(F10.4)') this%RDFValue(o)
                            call FileWriteNoAdvance(this%rdfFile)
                        end do
                    end do
                  end if
                  if( this%NTT68Max > 0 ) then
                    do s=1, this%Component(i)%molecule%NTT68
                        do t=1, this%Component(j)%molecule%NTT68
                            RDFRho = this%SumDensity%Average  * this%Component(j)%Fraction
                            if (i == j) then
                                RDFRhoLocal = 2.0 * real(this%Interaction(i,j)%PotTT68TT68(s,t)%RDFSum(o),RK) &
&                                       / (this%RDFVSchale(o) * ((Step-1)/RDFUpdateFrequency + 1) * this%Component(i)%NPart)
                            else
                                RDFRhoLocal = real(this%Interaction(i,j)%PotTT68TT68(s,t)%RDFSum(o),RK) &
&                                       / (this%RDFVSchale(o) * ((Step-1)/RDFUpdateFrequency + 1) * this%Component(i)%NPart)
                            end if
                            this%RDFValue(o) = RDFRhoLocal / RDFRho
                            ! Calculate average over all prozesses with MPI_Reduce
                            if ( mpiMCCommonGroups > 0 ) then
                              call MPI_Reduce( this%RDFValue(o), RDF_hilf(o), 1, MPI_RK, MPI_SUM, NRootProc_MCCom, MCCommonGroups_R, ierror )
                              this%RDFValue(o) = RDF_hilf(o) / mpiMCCommonGroups
                            else
                              call MPI_Reduce( this%RDFValue(o), RDF_hilf(o), 1, MPI_RK, MPI_SUM, NRootProc, Communicator, ierror )
                              this%RDFValue(o) = RDF_hilf(o) / NProcs
                            endif
                            write(IOBuffer, '(F10.4)') this%RDFValue(o)
                            call FileWriteNoAdvance(this%rdfFile)
                        end do
                    end do
                  end if
                end do
            end do
            call FileWriteBlank(this%rdfFile)
        enddo
    else
        do o = 1, RDFNumberShells
            write(IOBuffer, '(F10.4)') (o*this%RDFdr*UnitLength/Angstroem)
            call FileWriteNoAdvance(this%rdfFile)
            do i= 1, this%NComponents
                do j= i, this%NComponents
                  if( this%NMIEnmMax > 0 ) then
                    do s=1, this%Component(i)%molecule%NMIEnm
                        do t=1, this%Component(j)%molecule%NMIEnm
                            RDFSum_hilf(o) = this%Interaction(i,j)%PotMIEnmMIEnm(s,t)%RDFSum(o)
                            call MPI_Reduce( RDFSum_hilf(o), RDFSum_out(o), 1, MPI_INTEGER, MPI_SUM, NRootProc, Communicator, ierror )
                            RDFRho = this%SumDensity%Average  * this%Component(j)%Fraction
                            if (i == j) then
                                RDFRhoLocal = 2.0 * real(RDFSum_out(o),RK) &
&                                       / (this%RDFVSchale(o) * ((Step-1)/RDFUpdateFrequency + 1) * this%Component(i)%NPart)
                            else
                                RDFRhoLocal = real(RDFSum_out(o),RK) &
&                                       / (this%RDFVSchale(o) * ((Step-1)/RDFUpdateFrequency + 1) * this%Component(i)%NPart)
                            end if
                            this%RDFValue(o) = RDFRhoLocal / RDFRho
                            write(IOBuffer, '(F10.4)') this%RDFValue(o)
                            call FileWriteNoAdvance(this%rdfFile)
                        end do
                    end do
                  end if
                  if( this%NTT68Max > 0 ) then
                    do s=1, this%Component(i)%molecule%NTT68
                        do t=1, this%Component(j)%molecule%NTT68
                            RDFSum_hilf(o) = this%Interaction(i,j)%PotTT68TT68(s,t)%RDFSum(o)
                            call MPI_Reduce( RDFSum_hilf(o), RDFSum_out(o), 1, MPI_INTEGER, MPI_SUM, NRootProc, Communicator, ierror )
                            RDFRho = this%SumDensity%Average  * this%Component(j)%Fraction
                            if (i == j) then
                                RDFRhoLocal = 2.0 * real(RDFSum_out(o),RK) &
&                                       / (this%RDFVSchale(o) * ((Step-1)/RDFUpdateFrequency + 1) * this%Component(i)%NPart)
                            else
                                RDFRhoLocal = real(RDFSum_out(o),RK) &
&                                       / (this%RDFVSchale(o) * ((Step-1)/RDFUpdateFrequency + 1) * this%Component(i)%NPart)
                            end if
                            this%RDFValue(o) = RDFRhoLocal / RDFRho
                            write(IOBuffer, '(F10.4)') this%RDFValue(o)
                            call FileWriteNoAdvance(this%rdfFile)
                        end do
                    end do
                  end if
                end do
            end do
            call FileWriteBlank(this%rdfFile)
        enddo
    end if
#else
    do o = 1, RDFNumberShells
        write(IOBuffer, '(F10.4)') (o*this%RDFdr*UnitLength/Angstroem)
        call FileWriteNoAdvance(this%rdfFile)
        do i= 1, this%NComponents
            do j= i, this%NComponents
              if( this%NMIEnmMax > 0 ) then
                do s=1, this%Component(i)%molecule%NMIEnm
                    do t=1, this%Component(j)%molecule%NMIEnm
                        RDFRho = this%SumDensity%Average  * this%Component(j)%Fraction
                        if (i == j) then
                            RDFRhoLocal = 2.0 * real(this%Interaction(i,j)%PotMIEnmMIEnm(s,t)%RDFSum(o),RK) &
&                                       / (this%RDFVSchale(o) * ((Step-1)/RDFUpdateFrequency + 1) * this%Component(i)%NPart)
                        else
                            RDFRhoLocal = real(this%Interaction(i,j)%PotMIEnmMIEnm(s,t)%RDFSum(o),RK) &
&                                       / (this%RDFVSchale(o) * ((Step-1)/RDFUpdateFrequency + 1) * this%Component(i)%NPart)
                        end if
                        this%RDFValue(o) = RDFRhoLocal / RDFRho
                        write(IOBuffer, '(F10.4)') this%RDFValue(o)
                        call FileWriteNoAdvance(this%rdfFile)
                    end do
                end do
              end if
              if( this%NTT68Max > 0 ) then
                do s=1, this%Component(i)%molecule%NTT68
                    do t=1, this%Component(j)%molecule%NTT68
                        RDFRho = this%SumDensity%Average  * this%Component(j)%Fraction
                        if (i == j) then
                            RDFRhoLocal = 2.0 * real(this%Interaction(i,j)%PotTT68TT68(s,t)%RDFSum(o),RK) &
&                                       / (this%RDFVSchale(o) * ((Step-1)/RDFUpdateFrequency + 1) * this%Component(i)%NPart)
                        else
                            RDFRhoLocal = real(this%Interaction(i,j)%PotTT68TT68(s,t)%RDFSum(o),RK) &
&                                       / (this%RDFVSchale(o) * ((Step-1)/RDFUpdateFrequency + 1) * this%Component(i)%NPart)
                        end if
                        this%RDFValue(o) = RDFRhoLocal / RDFRho
                        write(IOBuffer, '(F10.4)') this%RDFValue(o)
                        call FileWriteNoAdvance(this%rdfFile)
                    end do
                end do
              end if
            end do
        end do
        call FileWriteBlank(this%rdfFile)
    enddo
#endif

#if MPI_VER > 0
    if ( mpiMCCommonGroups > 0 ) then
       if ( .not. RootProc_MCCom ) return !=RootProc_W, only the head (RootProc_MCCom) of all RootProc (head of each group)
    endif
#endif
    call FileClose(this%rdfFile)


  end subroutine TEnsemble_RDFUpdateBlock


