        write( restartFile%iounit, '(I10)' ) this%NRCutoffMax

        ! Save components
        do i = 1, this%NComponents
          call RestartSave( this%Component(i) )
        end do

        ! Save accumulators
        ! 1.) Basic sums
        call RestartSave( this%SumPressure )
        call RestartSave( this%SumDensity )
        call RestartSave( this%SumTemperature )
        call RestartSave( this%SumEPot )
        call RestartSave( this%SumEnthalpy )
        call RestartSave( this%SumConfEnthalpy )
        call RestartSave( this%SumVolume )
        call RestartSave( this%SumVirial )
        call RestartSave( this%SumdEpotdV )
        call RestartSave( this%Sumd2EpotdV2 )

        if( OpenSystem .or. EnsembleType .eq. EnsembleTypeHA ) then
          call RestartSave( this%SumNPart )
          do i = 1, this%NComponents
            pc => this%Component(i)
            call RestartSave( pc%SumFraction )
          end do
          if ( EnsembleType .eq. EnsembleTypeGE .or. EnsembleType .eq. EnsembleTypeMUVT ) then
            call RestartSave( this%SumNPart2 )
            call RestartSave( this%SumNPart3 )
            call RestartSave( this%SumEPotTot )
            call RestartSave( this%SumEPot2Tot )
            call RestartSave( this%SumdEPotdVTot )
            call RestartSave( this%SumdEPotdV2Tot )
            call RestartSave( this%SumUdEPotdVTot )
            call RestartSave( this%Sumd2EPotdV2Tot )
            call RestartSave( this%SumNPartEPot )
            call RestartSave( this%SumNPart2EPot )
            call RestartSave( this%SumNPartEpot2 )
            call RestartSave( this%SumNPartdEpotdV )
            call RestartSave( this%SumP100 )
            call RestartSave( this%SumP200 )
            call RestartSave( this%SumP001 )
            call RestartSave( this%SumP002 )
            call RestartSave( this%SumP020 )
            call RestartSave( this%SumP101 )
            call RestartSave( this%SumP010 )
            call RestartSave( this%SumP110 )
            call RestartSave( this%SumP011 )
            call RestartSave( this%SumCVsm )
            call RestartSave( this%SumBetaTsm )
            call RestartSave( this%SumGammaVsm )
            call RestartSave( this%SumCPsm )
            call RestartSave( this%SumAlphaPsm )
          end if
        end if

        ! 2.) Combined sums
        call RestartSave( this%SumEPotSquared )
        call RestartSave( this%SumEPotV )
        call RestartSave( this%SumEPotVirial )
        call RestartSave( this%SumEPotDeltaVirialDelta )
        call RestartSave( this%SumEnthalpySquared )
        call RestartSave( this%SumEnthalpyV )
        call RestartSave( this%SumVolumeSquared )
        call RestartSave( this%SumEPotCubic )
        call RestartSave( this%SumdEpotdVSquared )
        call RestartSave( this%SumEPotdEpotdV )
        call RestartSave( this%SumEPotSquareddEpotdV )
        call RestartSave( this%SumEPotdEpotdVSquared )
        call RestartSave( this%SumEPotd2EpotdV2 )
        if( EnsembleType .eq. EnsembleTypeNVE .and. LongRange .eq. Rfield) then
          call RestartSave( this%SumHmU )
          call RestartSave( this%SumHmUm1)
          call RestartSave( this%SumHmUm2 )
          call RestartSave( this%SumHmUm3 )
          call RestartSave( this%SumHmUm1dUdV )
          call RestartSave( this%SumHmUm1dUdV2 )
          call RestartSave( this%SumHmUm1d2UdV2 )
          call RestartSave( this%SumHmUm2dUdV )
          call RestartSave( this%SumHmUm2dUdV2 )
          call RestartSave( this%SumHmUm2d2UdV2 )
          call RestartSave( this%SumHmUm3dUdV )
          call RestartSave( this%SumHmUm3dUdV2 )
        end if
        ! 3.) Derived sums
        if( ConstantPressure ) then
          call RestartSave( this%SumBetaT )
          call RestartSave( this%SumdHdP )
          call RestartSave( this%SumCP )
          call RestartSave( this%SumAlphaP )
        else
          call RestartSave( this%SumdUdV )
          call RestartSave( this%SumCV )
          call RestartSave( this%SumCorCoefR )
        endif
        if( LongRange .eq. Rfield) then
          call RestartSave( this%SumCVsm )
          call RestartSave( this%SumBetaTsm )
          call RestartSave( this%SumGammaVsm )
          call RestartSave( this%SumCPsm )
          call RestartSave( this%SumAlphaPsm )
          if ( EnsembleType .eq. EnsembleTypeNVT ) then
            call RestartSave( this%SumA10resI )
            call RestartSave( this%SumA01resI )
            call RestartSave( this%SumA20resI )
            call RestartSave( this%SumA11resI )
            call RestartSave( this%SumA02resI )
            call RestartSave( this%SumA30resI )
            call RestartSave( this%SumA21resI )
            call RestartSave( this%SumA12resI )
          elseif ( EnsembleType .eq. EnsembleTypeNVE ) then
            call RestartSave( this%SumA10resI )
            call RestartSave( this%SumA01resI )
            call RestartSave( this%SumA20resI )
            call RestartSave( this%SumA11resI )
            call RestartSave( this%SumA02resI )
            call RestartSave( this%SumA30resI )
            call RestartSave( this%SumA21resI )
            call RestartSave( this%SumA12resI )
            call RestartSave( this%SumA10resII )
            call RestartSave( this%SumA01resII )
            call RestartSave( this%SumA20resII )
            call RestartSave( this%SumA11resII )
            call RestartSave( this%SumA02resII )
            call RestartSave( this%SumA30resII )
            call RestartSave( this%SumA21resII )
            call RestartSave( this%SumA12resII )
          elseif ( EnsembleType .eq. EnsembleTypeNPT ) then
            call RestartSave( this%SumConfEnthalpyTot )
            call RestartSave( this%SumConfEnthalpy2 )
            call RestartSave( this%SumConfEnthalpyV )
            call RestartSave( this%SumG10 )
            call RestartSave( this%SumG01 )
            call RestartSave( this%SumG11 )
            call RestartSave( this%SumG02 )
            call RestartSave( this%SumG20 )
          elseif ( EnsembleType .eq. EnsembleTypeNPH ) then
            call RestartSave( this%SumHmUmpV )
            call RestartSave( this%SumHmUmpVInv )
            call RestartSave( this%SumHmUmpVInvV )
            call RestartSave( this%SumHmUmpVInvV2 )
            call RestartSave( this%SumS10 )
            call RestartSave( this%SumS01 )
            call RestartSave( this%SumS11 )
            call RestartSave( this%SumS02 )
            call RestartSave( this%SumS20 )
          end if
        end if

        ! 4.) Chemical potential and partial molar volumes
        do i = 1, this%NRealComponents
          pc => this%Component(i)
          select case( pc%ChemPotMethod )
          case( ChemPotMethodGradIns )
            call RestartSave( pc%SumInvChemPotRho )
            call RestartSave( pc%SumInvChemPot )
          case( ChemPotMethodWidom )
            call RestartSave( pc%SumChemPotV )
            call RestartSave( pc%SumChemPotVV )
            call RestartSave( pc%SumHW_counter )
            call RestartSave( pc%SumHW_denom )
          case( ChemPotMethodThermoInt )
            call RestartSave( pc%SumChemPotV )
            call RestartSave( pc%SumChemPotVV )
            call RestartSave( pc%SumChemPotThermoIntWidom )
            call RestartSave( pc%SumChemPotThermoIntWidomV )
            call RestartSave( pc%SumHW_counter )
            call RestartSave( pc%SumHW_denom )
          end select
          if (EnsembleType .eq. EnsembleTypeGE) then
            call RestartSave( pc%SumChemPotGE )
          endif

          if( pc%ChemPotMethod .ne. ChemPotMethodNone .and. ConstantPressure .and. this%NRealComponents > 1 ) then
            call RestartSave( pc%SumVW )
           call RestartSave( pc%SumHM )
          end if
        end do

        ! 5.) Sampling of Dielectric Constant
        if( (this%NChargeMax > 0).or.(this%NDipoleMax > 0) ) then
            call RestartSave( this%SumTotalDipoleMoment )
            call RestartSave( this%SumTotalDipoleMomentSquared )
            call RestartSave( this%SumDielectricConstant )
        endif

        ! 6.) HBOND
#if HBOND > 0
        do i = 1, this%NComponents
          call RestartSave( this%SumHBond0(i) )
          do j = 1, this%NComponents
            call RestartSave( this%SumHBond1(i,j) )
            do k = j, this%NComponents
              call RestartSave( this%SumHBond2(i,j,k) )
              do l = k, this%NComponents
                call RestartSave( this%SumHBond3(i,j,k,l) )
                do m = l, this%NComponents
                  call RestartSave( this%SumHBond4(i,j,k,l,m) )
                end do
              end do
            end do
          end do
          call RestartSave( this%SumHBondN(i) )
        end do
#endif

    end if

#if MPI_VER > 0
    if ( mpiMCCommonGroups > 0 ) then
      call MPI_Gather( tpix, 1, MPI_K4B, &
&                       tpix_aux(1:NProcs), 1, MPI_K4B, NRootProc, Communicator, ierror )
      if( RootProc ) then
        ! write restart values for random number generator
        write(restartFile%iounit, '(I12)' ) ix
        write(restartFile%iounit, '(I12)' ) iy
        do i=1, NProcs
          write(restartFile%iounit, '(I12)' ) tpix_aux(i)
        end do
        write(restartFile%iounit, '(ES20.12E3)' ) am
      endif
    endif
#endif

    if (ODFUpdateFrequency > 0) then
        do i= 1, this%NComponents
            do j= i, this%NComponents
                if (((this%Component(i)%Molecule%NDipole .GE. 1) .or. (this%Component(i)%Molecule%NCharge .GE. 2)) .and. &
&                   ((this%Component(j)%Molecule%NDipole .GE. 1) .or. (this%Component(j)%Molecule%NCharge .GE. 2)))then
#if MPI_VER > 0
                    call MPI_Gather( this%Interaction(i,j)%ODFErrSum, 1, MPI_INTEGER, &
&                       ODFErrSum_hilf(1:NProcs), 1, MPI_INTEGER, NRootProc, Communicator, ierror )
                    if( RootProc ) then
                        do o = 1, NProcs
                            write(restartFile%iounit, '(I10)' ) ODFErrSum_hilf(o)
                        end do
                    end if
#else
                    write(restartFile%iounit, '(I10)' ) this%Interaction(i,j)%ODFErrSum
#endif
                end if
            end do
        end do

        do i= 1, this%NComponents
            do j= i, this%NComponents
                if (((this%Component(i)%Molecule%NDipole .GE. 1) .or. (this%Component(i)%Molecule%NCharge .GE. 2)) .and. &
&                   ((this%Component(j)%Molecule%NDipole .GE. 1) .or. (this%Component(j)%Molecule%NCharge .GE. 2)))then
                    do r = 1, nR
                        do s = 1, nGamma
                            do t = 1, nPhi
#if MPI_VER > 0
                                call MPI_Gather( this%Interaction(i,j)%ODFSum(1:nPhi,t,s,r), nPhi, MPI_INTEGER, &
&                                   ODFSum_hilf(1:nPhi*NProcs), nPhi, MPI_INTEGER, NRootProc, Communicator, ierror )
                                if( RootProc ) then
                                    do o = 1, nPhi*NProcs
                                        write(restartFile%iounit, '(I10)' ) ODFSum_hilf(o)
                                    end do
                                end if
#else
                                do o = 1, nPhi
                                    write(restartFile%iounit, '(I10)' ) this%Interaction(i,j)%ODFSum(o,t,s,r)
                                end do
#endif
                            end do
                        end do
                    end do
                end if
            end do
        end do
    end if


    if (RDFUpdateFrequency > 0) then
        do i= 1, this%NComponents
            do j= i, this%NComponents
              if( this%NMIEnmMax > 0 ) then
                 do s=1, this%Component(i)%molecule%NMIEnm
                     do t=1, this%Component(j)%molecule%NMIEnm
#if MPI_VER > 0
                        if ( .not. mpiMCCommonGroups > 0 ) then
                          call MPI_Gather( this%Interaction(i,j)%PotMIEnmMIEnm(s,t)%RDFSum(1:RDFNumberShells), RDFNumberShells, MPI_INTEGER, &
&                           RDFSum_hilf(1:RDFNumberShells*NProcs), RDFNumberShells, MPI_INTEGER, NRootProc, Communicator, ierror )
                        endif
                        if( RootProc ) then
                            if ( mpiMCCommonGroups > 0 ) then !every group writes its own *.rst in MC with mpiMCCommonGroups
                              do o = 1, RDFNumberShells
                                write(restartFile%iounit, '(I10)' ) this%Interaction(i,j)%PotMIEnmMIEnm(s,t)%RDFSum(o)
                              end do
                            else
                              do o = 1, RDFNumberShells*NProcs
                                write(restartFile%iounit, '(I10)' ) RDFSum_hilf(o)
                              end do
                            endif
                        endif
#else
                        do o = 1, RDFNumberShells
                            write(restartFile%iounit, '(I10)' ) this%Interaction(i,j)%PotMIEnmMIEnm(s,t)%RDFSum(o)
                        end do
#endif
                     end do
                 end do
              end if
              if( this%NTT68Max > 0 ) then
                 do s=1, this%Component(i)%molecule%NTT68
                     do t=1, this%Component(j)%molecule%NTT68
#if MPI_VER > 0
                        if ( .not. mpiMCCommonGroups > 0 ) then
                          call MPI_Gather( this%Interaction(i,j)%PotTT68TT68(s,t)%RDFSum(1:RDFNumberShells), RDFNumberShells, MPI_INTEGER, &
&                           RDFSum_hilf(1:RDFNumberShells*NProcs), RDFNumberShells, MPI_INTEGER, NRootProc, Communicator, ierror )
                        endif
                        if( RootProc ) then
                            if ( mpiMCCommonGroups > 0 ) then !every group writes its own *.rst in MC with mpiMCCommonGroups
                              do o = 1, RDFNumberShells
                                write(restartFile%iounit, '(I10)' ) this%Interaction(i,j)%PotTT68TT68(s,t)%RDFSum(o)
                              end do
                            else
                              do o = 1, RDFNumberShells*NProcs
                                write(restartFile%iounit, '(I10)' ) RDFSum_hilf(o)
                              end do
                            endif
                        end if
#else
                        do o = 1, RDFNumberShells
                            write(restartFile%iounit, '(I10)' ) this%Interaction(i,j)%PotTT68TT68(s,t)%RDFSum(o)
                        end do
#endif
                     end do
                 end do
              end if
            end do
        end do
    end if


    if (KBIUpdateFrequency > 0) then
        do i= 1, this%NRealComponents
            do j= i, this%NRealComponents
#if MPI_VER > 0
                if ( .not. mpiMCCommonGroups > 0 ) then
                    call MPI_Gather( this%Interaction(i,j)%KBISum(1:KBINShellsCubeEdge), KBINShellsCubeEdge, MPI_INTEGER8, &
&                     KBISum_hilf(1:KBINShellsCubeEdge*NProcs), KBINShellsCubeEdge, MPI_INTEGER8, NRootProc, Communicator, ierror )
                endif
                if( RootProc ) then
                    if ( mpiMCCommonGroups > 0 ) then !every group writes its own *.rst in MC with mpiMCCommonGroups
                        do o = 1, KBINShellsCubeEdge
                          write(restartFile%iounit, '(I10)' ) this%Interaction(i,j)%KBISum(o)
                        end do
                    else
                        do o = 1, KBINShellsCubeEdge*NProcs
                          write(restartFile%iounit, '(I10)' ) KBISum_hilf(o)
                        end do
                    endif
                end if
#else
                do o = 1, KBINShellsCubeEdge
                    write(restartFile%iounit, '(I10)' ) this%Interaction(i,j)%KBISum(o)
                end do
#endif
            end do
        end do
        if( RootProc ) then    ! Save mean RDF over all blocks for Gij extrapolation
            do i = 1, this%NRealComponents*(this%NRealComponents+1)/2
                do o = 1, KBINShellsCubeEdge
                    write(restartFile%iounit, '(ES20.12E3)' ) this%KBIRDFextra(o,i)
                    write(restartFile%iounit, '(ES20.12E3)' ) this%KBIRDFvdVextra(o,i)
                    write(restartFile%iounit, '(ES20.12E3)' ) this%KBIRDFvdVshfextra(o,i)
                end do
            end do
            write(restartFile%iounit, '(I10)' ) this%KBIBlockCount
        end if
        do i= 1, this%NRealComponents*(this%NRealComponents+1)/2!Number of comb., e.g. 11 12 22
            call RestartSave( this%SumKBIGij1(i), .false., .true. )
            call RestartSave( this%SumKBIGij2(i), .false., .true. )
            call RestartSave( this%SumKBIGij3(i), .false., .true. )
        end do
    end if

#if TRANS ==1
if( RootProc .and. this%CorrfunMode ) then

    !Reduced correlation steps
    StepCorr = (Step + this%NStepCorr -1) / this%NStepCorr

    !Calculate matrix indexes
    Mindex = mod(StepCorr, this%NCorr )
    if (Mindex .eq. 0) then
      Mindex = this%NCorr
    end if

    if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
      k=mod(Mindex,this%NSpanCF)
      this%a(:,Mindex + 1 - k:Mindex ) = this%A_SpanCF(:,1:k)
    end if

    write( restartFile%iounit, '(I10)' ) this%NCorr
    write( restartFile%iounit, '(I10)' ) this%Mmess

    if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
      do i = 1, 3*this%NPart
        do j = 1, this%NCorr
            write( restartFile%iounit, '(ES20.12E3)' )  this%a( i, j)
        end do
      end do
    end if

    do i = 1, this%NCorr
        write( restartFile%iounit, '(3(ES20.12E3, :, ";"))' ) this%vsk(i,:)
    end do
    do i = 1, this%NCorr
        write( restartFile%iounit, '(3(ES20.12E3, :, ";"))' ) this%vsp(i,:)
    end do
    do i = 1, this%NCorr
        write( restartFile%iounit, '(3(ES20.12E3, :, ";"))' ) this%vbk(i,:)
    end do
    do i = 1, this%NCorr
        write( restartFile%iounit, '(3(ES20.12E3, :, ";"))' ) this%vbp(i,:)
    end do
    do i = 1, this%NCorr
        write( restartFile%iounit, '(3(ES20.12E3, :, ";"))' ) this%vckt(i,:)
    end do
    do i = 1, this%NCorr
        write( restartFile%iounit, '(3(ES20.12E3, :, ";"))' ) this%vckr(i,:)
    end do
    do i = 1, this%NCorr
        write( restartFile%iounit, '(3(ES20.12E3, :, ";"))' ) this%vcpt(i,:)
    end do
    do i = 1, this%NCorr
        write( restartFile%iounit, '(3(ES20.12E3, :, ";"))' ) this%vcpr(i,:)
    end do
    do i = 1, this%NCorr
        write( restartFile%iounit, '(3(ES20.12E3, :, ";"))' ) this%vcmt(i,:)
    end do
    do i = 1, this%NCorr
        write( restartFile%iounit, '(ES20.12E3)' ) this%average_cf_c(i)
    end do
    do i = 1, this%NCorr
        write( restartFile%iounit, '(ES20.12E3)' )  this%average_cf_vb(i)
    end do

    if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
      do i = 1, this%NCorr
        write( restartFile%iounit, '(ES20.12E3)' )  this%average_cf_vs(i)
      end do
    end if

    do i = 1, this%NCorr
        write( restartFile%iounit, '(ES20.12E3)' ) this%average_cf_ec(i)
    end do

    if (this%NComponents .gt. 1) then
      do i = 1, this%NComponents
        do j = 1, this%NCorr
          write( restartFile%iounit, '(ES20.12E3)' ) this%average_cf_soret(i,j)
        end do
      end do

      if (TransMethod .eq. Einstein) then
        do i = 1, this%NComponents
          do j = 1, this%NCorr
            write( restartFile%iounit, '(ES20.12E3)' ) this%velcompX(i,j)
          end do
        end do
        do i = 1, this%NComponents
          do j = 1, this%NCorr
            write( restartFile%iounit, '(ES20.12E3)' ) this%velcompY(i,j)
          end do
        end do
        do i = 1, this%NComponents
          do j = 1, this%NCorr
            write( restartFile%iounit, '(ES20.12E3)' ) this%velcompZ(i,j)
          end do
        end do
      end if
    end if

    if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
      do i = 1, this%NComponents
        do j = 1, this%NCorr
          write( restartFile%iounit, '(ES20.12E3)' )  this%average_cf_d(i , j)
        end do
      end do

      if (this%NComponents > 1) then
        do i = 1, this%NComponents*this%NComponents
          do j = 1, this%NCorr
            write( restartFile%iounit, '(ES20.12E3)' ) this%average_lamda(i , j)
          end do
        end do
      end if
    end if

    write( restartFile%iounit, '(I10)' ) NBlocksMaxCF

    if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
      do i = 1, this%NComponents
       call RestartSave( this%Sumself_i(i), .true. )
      end do
    end if

    if(this%NComponents > 1) then
      if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
        do i = 1, this%NComponents
         do j = 1, this%NComponents
           call RestartSave( this%SumOnsager(i,j), .true. )
         end do
        end do
      end if
      do i = 1, this%NComponents
         call RestartSave( this%SumSoret(i), .true. )
      end do
    end if

     if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
       call RestartSave( this%SumVisco_s, .true. )
    end if

    call RestartSave( this%SumVisco_b, .true. )
    call RestartSave( this%SumConduct, .true. )
    call RestartSave( this%SumEConduct,.true. )

    do i = 1,3
      write( restartFile%iounit, '(ES20.12E3)' )  this%sp(i)
    end do

    do i = 1,3
      write( restartFile%iounit, '(ES20.12E3)' )  this%sc(i)
    end do

    if( (TransMethod .eq. Einstein) .or. (TransMethod .eq. GKEinstein) ) then
       write( restartFile%iounit, '(I10)' ) this%EinsteinCoefAveCount
       do j = 0, this%NCorr/this%NSpanCF-1
          write( restartFile%iounit, '(I10)' ) this%EinsteinCoefTimeStep(j)
       end do

       do s = 1, this%NComponents
         do i = 1, this%NCorr
            do j = 0, this%NCorr/this%NSpanCF-1
               write( restartFile%iounit, '((ES20.12E3))' ) this%DselfEinstein(i,j,s)
            end do
         end do
       end do

       if(this%NComponents > 1) then
         do s = 1, this%NComponents
           do t = 1, this%NComponents
              do i = 1, this%NCorr
                do j = 0, this%NCorr/this%NSpanCF-1
                   write( restartFile%iounit, '((ES20.12E3))' ) this%OnsagerEinstein(i,j,s,t)
                end do
              end do
           end do
         end do
       end if

       do s = 1, this%NComponents
          do i = 1, this%NCorr
             write( restartFile%iounit, '((ES20.12E3))' ) this%DselfEinsteinAve(i,s)  !memory access is probably stupid
          end do
       end do

       if(this%NComponents > 1) then
          do s = 1, this%NComponents
             do t = 1, this%NComponents
                do i = 1, this%NCorr
                   write( restartFile%iounit, '((ES20.12E3))' ) this%OnsagerEinsteinAve(i,s,t)
                end do
             end do
          end do
       end if

       do s = 1, this%NComponents
         write(restartFile%iounit,'(ES20.12E3)') this%DselfEinsteinCurrent(s)
       end do


       if(this%NComponents > 1) then
          do s = 1, this%NComponents
            do t = 1, this%NComponents
               write(restartFile%iounit,'(ES20.12E3)') this%OnsagerEinsteinCurrent(s,t)
            end do
         end do
       endif

       do s = 1, this%NComponents
          call RestartSave( this%EinsteinDSelfAcc(s), .true. )
       end do

       if(this%NComponents > 1) then
          do s = 1, this%NComponents
             do t = 1, this%NComponents
               call RestartSave( this%EinsteinOnsagerAcc(s,t), .true. )
             end do
          end do
        end if


        do i = 1, this%NCorr
          write( restartFile%iounit, '((ES20.12E3))' )  this%EinsteinShear(i)
        end do

        do i = 1, this%NCorr
          write( restartFile%iounit, '((ES20.12E3))' )  this%EinsteinShearAve(i)
        end do

        call RestartSave( this%EinsteinShearAcc, .true.)
    end if
 endif
#endif

#if MPI_VER > 0
    ! Saving ThermoInt parameters for MC with mpiMCCommonGroups>0 in *.rst file (in all other cases restart by *.thi file)
    if ( mpiMCCommonGroups > 0 ) then

        t = this%NRealComponents+1
        do i=1,this%NRealComponents
          pc => this%Component(i)
          if (pc%ChemPotMethod .eq. ChemPotMethodThermoInt) then
            NBins = pc%NBins

            ! Allocate arrays
            allocate(BinsEn       (0: NBins-1), stat=status)
            allocate(BinsdEndLa   (0: NBins-1), stat=status)
            allocate(BinsdEndLaV  (0: NBins-1), stat=status)
            allocate(BinsdEndLaH  (0: NBins-1), stat=status)
            allocate(BinsIntdEndLa(0: NBins-1), stat=status)
            allocate(BinsIntVW    (0: NBins-1), stat=status)
            allocate(BinsIntHW    (0: NBins-1), stat=status)
            allocate(BinsVisit    (0: NBins-1), stat=status)

            ! Average ThermoInt values for each mpiMCCommonGroup
            call MPI_Reduce( pc%BinsEn(0: NBins-1)       , BinsEn(0: NBins-1), NBins, MPI_RK, MPI_SUM, NRootProc, Communicator, ierror )
            call MPI_Reduce( pc%BinsdEndLa(0: NBins-1)   , BinsdEndLa(0: NBins-1), NBins, MPI_RK, MPI_SUM, NRootProc, Communicator, ierror )
            call MPI_Reduce( pc%BinsdEndLaV(0: NBins-1)  , BinsdEndLaV(0: NBins-1), NBins, MPI_RK, MPI_SUM, NRootProc, Communicator, ierror )
            call MPI_Reduce( pc%BinsdEndLaH(0: NBins-1)  , BinsdEndLaH(0: NBins-1), NBins, MPI_RK, MPI_SUM, NRootProc, Communicator, ierror )
            call MPI_Reduce( pc%BinsIntdEndLa(0: NBins-1), BinsIntdEndLa(0: NBins-1), NBins, MPI_RK, MPI_SUM, NRootProc, Communicator, ierror )
            call MPI_Reduce( pc%BinsIntVW(0: NBins-1)    , BinsIntVW(0: NBins-1), NBins, MPI_RK, MPI_SUM, NRootProc, Communicator, ierror )
            call MPI_Reduce( pc%BinsIntHW(0: NBins-1)    , BinsIntHW(0: NBins-1), NBins, MPI_RK, MPI_SUM, NRootProc, Communicator, ierror )
            call MPI_Reduce( pc%BinsVisit(0: NBins-1)    , BinsVisit(0: NBins-1), NBins, MPI_INTEGER, MPI_SUM, NRootProc, Communicator, ierror )
            do j=0,NBins-1
              BinsEn(j)        = BinsEn(j)/NProcs
              BinsdEndLa(j)    = BinsdEndLa(j)/NProcs
              BinsdEndLaV(j)   = BinsdEndLaV(j)/NProcs
              BinsdEndLaH(j)   = BinsdEndLaH(j)/NProcs
              BinsIntdEndLa(j) = BinsIntdEndLa(j)/NProcs
              BinsIntVW(j)     = BinsIntVW(j)/NProcs
              BinsIntHW(j)     = BinsIntHW(j)/NProcs
              BinsVisit(j)     = BinsVisit(j)/NProcs
            end do

            ! write ThermoInt parameters into *.rst file for each MCCommonGroup
            if (RootProc) then
              ! current lambda
              write( restartFile%iounit, '(E19.10)' ) this%Component(t)%lambda
              ! thermoint-profile
              do j = 0,NBins-1
                write( restartFile%iounit, '(7(E19.10, :, ";"), I10)' ) BinsEn(j), BinsdEndLa(j), BinsdEndLaV(j), BinsdEndLaH(j),&
&                      BinsIntdEndLa(j), BinsIntVW(j), BinsIntHW(j), BinsVisit(j)
              end do
            endif

            ! Deallocate arrays
            deallocate(BinsEn,        stat=status)
            deallocate(BinsdEndLa,    stat=status)
            deallocate(BinsdEndLaV,   stat=status)
            deallocate(BinsdEndLaH,   stat=status)
            deallocate(BinsIntdEndLa, stat=status)
            deallocate(BinsIntVW,     stat=status)
            deallocate(BinsIntHW,     stat=status)
            deallocate(BinsVisit,     stat=status)

            t = t+1

          end if
        end do

    endif
#endif


  end subroutine TEnsemble_RestartSave



!==============================================================!
!  Subroutine TEnsemble_RestartRead                            !
!==============================================================!

  subroutine TEnsemble_RestartRead( this )

    implicit none

    ! Include MPI header
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif

    ! Declare arguments
    type(TEnsemble) :: this

    ! Declare local variables
    type(TComponent), pointer :: pc
    integer                   :: i,j,r,s,t,o,stat,counter,k,Mindex,StepCorr
    real(RK)                  :: dummy, Factor
    real(RK)                  :: EPot, d2EdV2, Virial
#if MPI_VER > 0
    integer(KIND=8)           :: KBISum_hilf(KBINShellsCubeEdge*NProcs)
    integer                   :: RDFSum_hilf(RDFNumberShells*NProcs)
    integer                   :: ODFSum_hilf(nPhi*NProcs)
    integer                   :: ODFErrSum_hilf(NProcs)
    integer(KIND=4)           :: tpix_aux(1:NProcs)
#endif
#if HBOND > 0
    integer                   :: l, m
#endif

    if( RootProc ) then

      ! Read contents from restart file
      read( restartFile%iounit, '(I10)' ) this%NPart
      read( restartFile%iounit, '(ES20.12E3)' ) this%Volume0

      if( SimulationType .eq. MolecularDynamics ) then
        read( restartFile%iounit, '(ES20.12E3)' ) this%Volume1
        read( restartFile%iounit, '(ES20.12E3)' ) this%Volume2

        if( IntegratorType .eq. IntegratorTypeGear ) then
          read( restartFile%iounit, '(ES20.12E3)' ) this%Volume3
          read( restartFile%iounit, '(ES20.12E3)' ) this%Volume4
          read( restartFile%iounit, '(ES20.12E3)' ) this%Volume5
        end if

        if( ALPHA2UpdateFrequency > 0 ) then
            read( restartFile%iounit, '(I10)' ) this%alpha2aveCount
            do j = 0, ALPHA2Length/ALPHA2Shift-1
              read( restartFile%iounit, '(I10)' ) this%alpha2tempstep(j)
            end do
            do i = 1, ALPHA2Length/ALPHA2UpdateFrequency
              do j = 0, ALPHA2Length/ALPHA2Shift-1
                read( restartFile%iounit, '(3(ES20.12E3, :, 1X))' ) this%dispR2(i,j),this%dispR4(i,j),this%dispR2inv(i,j)
              end do
            end do
            do i = 1, ALPHA2Length/ALPHA2UpdateFrequency
              read( restartFile%iounit, '(3(ES20.12E3, :, 1X))' ) this%dispR2Ave(i),this%dispR4Ave(i),this%dispR2invAve(i)
            end do
        end if

      else
        read( restartFile%iounit, '(ES20.12E3)' ) this%DispVol
        read(restartFile%iounit, '(2I10)' ) this%NResizeAttempts, this%NResizeSuccesses
        if( OpenSystem .or. EnsembleType .eq. EnsembleTypeHA ) then
          read(restartFile%iounit, '(2I10)' ) this%NInsertAttempts, this%NInsertSuccesses
          read(restartFile%iounit, '(2I10)' ) this%NDeleteAttempts, this%NDeleteSuccesses
        end if
      end if
      read( restartFile%iounit, '(I10)' ) this%NRCutoffMax

    end if

#if MPI_VER > 0
    call MPI_Bcast( this%NPart, 1, MPI_INTEGER, NRootProc, Communicator, ierror )
    call MPI_Bcast( this%Volume0, 1, MPI_RK, NRootProc, Communicator, ierror )

    if( (SimulationType .eq. MonteCarlo) .or. (SimulationType .eq. Gibbs) ) then
      call MPI_Bcast( this%DispVol, 1, MPI_RK, NRootProc, Communicator, ierror )
      call MPI_Bcast( this%NResizeAttempts, 1, MPI_INTEGER, NRootProc, Communicator, ierror )
      call MPI_Bcast( this%NResizeSuccesses, 1, MPI_INTEGER, NRootProc, Communicator, ierror )

      if( OpenSystem .or. EnsembleType .eq. EnsembleTypeHA ) then
        call MPI_Bcast( this%NInsertAttempts, 1, MPI_INTEGER, NRootProc, Communicator, ierror )
        call MPI_Bcast( this%NInsertSuccesses, 1, MPI_INTEGER, NRootProc, Communicator, ierror )
        call MPI_Bcast( this%NDeleteAttempts, 1, MPI_INTEGER, NRootProc, Communicator, ierror )
        call MPI_Bcast( this%NDeleteSuccesses, 1, MPI_INTEGER, NRootProc, Communicator, ierror )
      end if
    end if

    call MPI_Bcast( this%NRCutoffMax, 1, MPI_INTEGER, NRootProc, Communicator, ierror )
#endif

    ! Read components
    do i = 1, this%NComponents
      call RestartRead( this%Component(i) )
    end do

    ! Read accumulators
    ! 1.) Basic sums
    call RestartRead( this%SumPressure )
    call RestartRead( this%SumDensity )
    call RestartRead( this%SumTemperature )
    call RestartRead( this%SumEPot )
    call RestartRead( this%SumEnthalpy )
    call RestartRead( this%SumConfEnthalpy )
    call RestartRead( this%SumVolume )
    call RestartRead( this%SumVirial )
    call RestartRead( this%SumdEpotdV )
    call RestartRead( this%Sumd2EpotdV2 )

    if( OpenSystem .or. EnsembleType .eq. EnsembleTypeHA ) then
      call RestartRead( this%SumNPart )
      do i = 1, this%NComponents
        pc => this%Component(i)
        call RestartRead( pc%SumFraction )
      end do
      if ( EnsembleType .eq. EnsembleTypeGE .or. EnsembleType .eq. EnsembleTypeMUVT ) then
        call RestartRead( this%SumNPart2 )
        call RestartRead( this%SumNPart3 )
        call RestartRead( this%SumEPotTot )
        call RestartRead( this%SumEPot2Tot )
        call RestartRead( this%SumdEPotdVTot )
        call RestartRead( this%SumdEPotdV2Tot )
        call RestartRead( this%SumUdEPotdVTot )
        call RestartRead( this%Sumd2EPotdV2Tot )
        call RestartRead( this%SumNPartEPot )
        call RestartRead( this%SumNPart2EPot )
        call RestartRead( this%SumNPartEpot2 )
        call RestartRead( this%SumNPartdEpotdV )
        call RestartRead( this%SumP100 )
        call RestartRead( this%SumP200 )
        call RestartRead( this%SumP001 )
        call RestartRead( this%SumP002 )
        call RestartRead( this%SumP020 )
        call RestartRead( this%SumP101 )
        call RestartRead( this%SumP010 )
        call RestartRead( this%SumP110 )
        call RestartRead( this%SumP011 )
        call RestartRead( this%SumCVsm )
        call RestartRead( this%SumBetaTsm )
        call RestartRead( this%SumGammaVsm )
        call RestartRead( this%SumCPsm )
        call RestartRead( this%SumAlphaPsm )
      end if
    end if

    ! 2.) Combined sums
    call RestartRead( this%SumEPotSquared )
    call RestartRead( this%SumEPotV )
    call RestartRead( this%SumEPotVirial )
    call RestartRead( this%SumEPotDeltaVirialDelta )
    call RestartRead( this%SumEnthalpySquared )
    call RestartRead( this%SumEnthalpyV )
    call RestartRead( this%SumVolumeSquared )
    call RestartRead( this%SumEPotCubic )
    call RestartRead( this%SumdEpotdVSquared )
    call RestartRead( this%SumEPotdEpotdV )
    call RestartRead( this%SumEPotSquareddEpotdV )
    call RestartRead( this%SumEPotdEpotdVSquared )
    call RestartRead( this%SumEPotd2EpotdV2 )
    if( EnsembleType .eq. EnsembleTypeNVE .and. LongRange .eq. Rfield) then
      call RestartRead( this%SumHmU )
      call RestartRead( this%SumHmUm1)
      call RestartRead( this%SumHmUm2 )
      call RestartRead( this%SumHmUm3 )
      call RestartRead( this%SumHmUm1dUdV )
      call RestartRead( this%SumHmUm1dUdV2 )
      call RestartRead( this%SumHmUm1d2UdV2 )
      call RestartRead( this%SumHmUm2dUdV )
      call RestartRead( this%SumHmUm2dUdV2 )
      call RestartRead( this%SumHmUm2d2UdV2 )
      call RestartRead( this%SumHmUm3dUdV )
      call RestartRead( this%SumHmUm3dUdV2 )
    end if

    ! 3.) Derived sums
    if( ConstantPressure ) then
      call RestartRead( this%SumBetaT )
      call RestartRead( this%SumdHdP )
      call RestartRead( this%SumCP )
      call RestartRead( this%SumAlphaP )
    else
      call RestartRead( this%SumdUdV )
      call RestartRead( this%SumCV )
      call RestartRead( this%SumCorCoefR )
    endif
    if( LongRange .eq. Rfield) then
      call RestartRead( this%SumCVsm )
      call RestartRead( this%SumBetaTsm )
      call RestartRead( this%SumGammaVsm )
      call RestartRead( this%SumCPsm )
      call RestartRead( this%SumAlphaPsm )
      if ( EnsembleType .eq. EnsembleTypeNVT ) then
        call RestartRead( this%SumA10resI )
        call RestartRead( this%SumA01resI )
        call RestartRead( this%SumA20resI )
        call RestartRead( this%SumA11resI )
        call RestartRead( this%SumA02resI )
        call RestartRead( this%SumA30resI )
        call RestartRead( this%SumA21resI )
        call RestartRead( this%SumA12resI )
      elseif ( EnsembleType .eq. EnsembleTypeNVE ) then
        call RestartRead( this%SumA10resI )
        call RestartRead( this%SumA01resI )
        call RestartRead( this%SumA20resI )
        call RestartRead( this%SumA11resI )
        call RestartRead( this%SumA02resI )
        call RestartRead( this%SumA30resI )
        call RestartRead( this%SumA21resI )
        call RestartRead( this%SumA12resI )
        call RestartRead( this%SumA10resII )
        call RestartRead( this%SumA01resII )
        call RestartRead( this%SumA20resII )
        call RestartRead( this%SumA11resII )
        call RestartRead( this%SumA02resII )
        call RestartRead( this%SumA30resII )
        call RestartRead( this%SumA21resII )
        call RestartRead( this%SumA12resII )
      elseif ( EnsembleType .eq. EnsembleTypeNPT ) then
        call RestartRead( this%SumConfEnthalpyTot )
        call RestartRead( this%SumConfEnthalpy2 )
        call RestartRead( this%SumConfEnthalpyV )
        call RestartRead( this%SumG10 )
        call RestartRead( this%SumG01 )
        call RestartRead( this%SumG11 )
        call RestartRead( this%SumG02 )
        call RestartRead( this%SumG20 )
      elseif ( EnsembleType .eq. EnsembleTypeNPH ) then
        call RestartRead( this%SumHmUmpV )
        call RestartRead( this%SumHmUmpVInv )
        call RestartRead( this%SumHmUmpVInvV )
        call RestartRead( this%SumHmUmpVInvV2 )
        call RestartRead( this%SumS10 )
        call RestartRead( this%SumS01 )
        call RestartRead( this%SumS11 )
        call RestartRead( this%SumS02 )
        call RestartRead( this%SumS20 )
      end if
    end if


    ! 4.) Chemical potential and partial molar volumes
    counter = this%NRealComponents+1
    do i = 1, this%NRealComponents
      pc => this%Component(i)
      select case( pc%ChemPotMethod )
      case( ChemPotMethodGradIns )
        call RestartRead( pc%SumInvChemPotRho )
        call RestartRead( pc%SumInvChemPot )
        pc%NFluctState = 0
        do j = counter,counter + this%Component(i)%Molecule%NFluct-1
          if (this%Component(j)%NPart .eq. 1) then
            pc%NFluctState = j-counter+1
          end if
        end do
        counter = counter + this%Component(i)%Molecule%NFluct

      case( ChemPotMethodWidom )
        call RestartRead( pc%SumChemPotV )
        call RestartRead( pc%SumChemPotVV )
        call RestartRead( pc%SumHW_counter )
        call RestartRead( pc%SumHW_denom )

      case( ChemPotMethodThermoInt )
        call RestartRead( pc%SumChemPotV )
        call RestartRead( pc%SumChemPotVV )
        call RestartRead( pc%SumChemPotThermoIntWidom )
        call RestartRead( pc%SumChemPotThermoIntWidomV )
        call RestartRead( pc%SumHW_counter )
        call RestartRead( pc%SumHW_denom )
      end select
      if (EnsembleType .eq. EnsembleTypeGE) then
        call RestartRead( pc%SumChemPotGE )
      endif

      if( pc%ChemPotMethod .ne. ChemPotMethodNone .and. ConstantPressure .and. this%NRealComponents > 1 ) then
        call RestartRead( pc%SumVW )
        call RestartRead( pc%SumHM )
      end if
    end do

    ! 5.) Sampling of Dielectric Constant
    if( (this%NChargeMax > 0).or.(this%NDipoleMax > 0) ) then
        call RestartRead( this%SumTotalDipoleMoment )
        call RestartRead( this%SumTotalDipoleMomentSquared )
        call RestartRead( this%SumDielectricConstant )
    endif

    ! 6.) HBOND
#if HBOND > 0
    do i = 1, this%NComponents
      call RestartRead( this%SumHBond0(i) )
      do j = 1, this%NComponents
        call RestartRead( this%SumHBond1(i,j) )
        do k = j, this%NComponents
          call RestartRead( this%SumHBond2(i,j,k) )
          do l = k, this%NComponents
            call RestartRead( this%SumHBond3(i,j,k,l) )
            do m = l, this%NComponents
              call RestartRead( this%SumHBond4(i,j,k,l,m) )
            end do
          end do
        end do
      end do
      call RestartRead( this%SumHBondN(i) )
    end do
#endif

#if MPI_VER > 0
    if ( mpiMCCommonGroups > 0 ) then
      if( RootProc ) then
        ! read restart values for random number generator
        read( restartFile%iounit, '(I12)' ) ix
        read( restartFile%iounit, '(I12)' ) iy
        do i=1, NProcs
          read( restartFile%iounit, '(I12)' ) tpix_aux(i)
        end do
        read(restartFile%iounit, '(ES20.12E3)' ) am
      endif
      call MPI_Scatter( tpix_aux(1:NProcs), 1, MPI_INTEGER4, &
&          tpix, 1, MPI_INTEGER4, NRootProc, Communicator, ierror )
      call MPI_Bcast( ix, 1, MPI_INTEGER4, NRootProc, Communicator, ierror )
      call MPI_Bcast( iy, 1, MPI_INTEGER4, NRootProc, Communicator, ierror )
      call MPI_Bcast( am, 1, MPI_RK,       NRootProc, Communicator, ierror )
    endif
#endif

    if (ODFUpdateFrequency > 0) then
        do i= 1, this%NComponents
            do j= i, this%NComponents
                if (((this%Component(i)%Molecule%NDipole .GE. 1) .or. (this%Component(i)%Molecule%NCharge .GE. 2)) .and. &
&                   ((this%Component(j)%Molecule%NDipole .GE. 1) .or. (this%Component(j)%Molecule%NCharge .GE. 2)))then
#if MPI_VER > 0
                    if( RootProc ) then
                        do o = 1, NProcs
                            read( restartFile%iounit, '(I10)' ) ODFErrSum_hilf(o)
                        end do
                    end if
                    call MPI_Scatter( ODFErrSum_hilf(1:NProcs), 1, MPI_INTEGER, &
&                       this%Interaction(i,j)%ODFErrSum, &
&                       1, MPI_INTEGER, NRootProc, Communicator, ierror )
#else
                    read( restartFile%iounit, '(I10)' ) this%Interaction(i,j)%ODFErrSum
#endif
                end if
            end do
        end do

        do i= 1, this%NComponents
            do j= i, this%NComponents
                if (((this%Component(i)%Molecule%NDipole .GE. 1) .or. (this%Component(i)%Molecule%NCharge .GE. 2)) .and. &
&                   ((this%Component(j)%Molecule%NDipole .GE. 1) .or. (this%Component(j)%Molecule%NCharge .GE. 2)))then
                    do r = 1, nR
                        do s = 1, nGamma
                            do t = 1, nPhi
#if MPI_VER > 0
                                if( RootProc ) then
                                    do o = 1, nPhi*NProcs
                                        read( restartFile%iounit, '(I10)' ) ODFSum_hilf(o)
                                    end do
                                end if
                                call MPI_Scatter( ODFSum_hilf(1:nPhi*NProcs), nPhi, MPI_INTEGER, &
&                                    this%Interaction(i,j)%ODFSum(1:nPhi,t,s,r), &
&                                    nPhi, MPI_INTEGER, NRootProc, Communicator, ierror )
#else
                                do o = 1, nPhi
                                    read( restartFile%iounit, '(I10)' ) this%Interaction(i,j)%ODFSum(o,t,s,r)
                                end do
#endif
                            end do
                        end do
                    end do
                end if
            end do
        end do
    end if


    if (RDFUpdateFrequency > 0) then
        do i= 1, this%NComponents
            do j= i, this%NComponents
               if( this%NMIEnmMax > 0 ) then
                  do s=1, this%Component(i)%molecule%NMIEnm
                      do t=1, this%Component(j)%molecule%NMIEnm
#if MPI_VER > 0
                        if( RootProc ) then
                            if ( mpiMCCommonGroups > 0 ) then
                              do o = 1, RDFNumberShells
                                read( restartFile%iounit, '(I10)' ) this%Interaction(i,j)%PotMIEnmMIEnm(s,t)%RDFSum(o)
                              end do
                            else
                              do o = 1, RDFNumberShells*NProcs
                                read( restartFile%iounit, '(I10)' ) RDFSum_hilf(o)
                              end do
                            endif
                        end if
                        if ( mpiMCCommonGroups > 0 ) then
                          call MPI_Bcast( this%Interaction(i,j)%PotMIEnmMIEnm(s,t)%RDFSum(1:RDFNumberShells), &
&                             RDFNumberShells, MPI_INTEGER, NRootProc, Communicator, ierror )
                        else
                          call MPI_Scatter( RDFSum_hilf(1:RDFNumberShells*NProcs), RDFNumberShells, MPI_INTEGER, &
&                             this%Interaction(i,j)%PotMIEnmMIEnm(s,t)%RDFSum(1:RDFNumberShells), RDFNumberShells, &
&                             MPI_INTEGER, NRootProc, Communicator, ierror )
                        endif
#else
                        do o = 1, RDFNumberShells
                            read( restartFile%iounit, '(I10)' ) this%Interaction(i,j)%PotMIEnmMIEnm(s,t)%RDFSum(o)
                        end do
#endif
                      end do
                  end do
               end if
               if( this%NTT68Max > 0 ) then
                  do s=1, this%Component(i)%molecule%NTT68
                      do t=1, this%Component(j)%molecule%NTT68
#if MPI_VER > 0
                        if( RootProc ) then
                            if ( mpiMCCommonGroups > 0 ) then
                              do o = 1, RDFNumberShells
                                read( restartFile%iounit, '(I10)' ) this%Interaction(i,j)%PotMIEnmMIEnm(s,t)%RDFSum(o)
                              end do
                            else
                              do o = 1, RDFNumberShells*NProcs
                                read( restartFile%iounit, '(I10)' ) RDFSum_hilf(o)
                              end do
                            endif
                        end if
                        if ( mpiMCCommonGroups > 0 ) then
                          call MPI_Bcast( this%Interaction(i,j)%PotMIEnmMIEnm(s,t)%RDFSum(1:RDFNumberShells), &
&                             RDFNumberShells, MPI_INTEGER, NRootProc, Communicator, ierror )
                        else
                          call MPI_Scatter( RDFSum_hilf(1:RDFNumberShells*NProcs), RDFNumberShells, MPI_INTEGER, &
&                             this%Interaction(i,j)%PotTT68TT68(s,t)%RDFSum(1:RDFNumberShells), RDFNumberShells, &
&                             MPI_INTEGER, NRootProc, Communicator, ierror )
                        endif
#else
                        do o = 1, RDFNumberShells
                            read( restartFile%iounit, '(I10)' ) this%Interaction(i,j)%PotTT68TT68(s,t)%RDFSum(o)
                        end do
#endif
                      end do
                  end do
               end if
            end do
        end do
    end if

    ! RestartRead of RDF for KBI
    if (KBIUpdateFrequency > 0) then
        do i= 1, this%NRealComponents
            do j= i, this%NRealComponents
#if MPI_VER > 0
                if( RootProc ) then
                    if ( mpiMCCommonGroups > 0 ) then
                        do o = 1, KBINShellsCubeEdge
                            read( restartFile%iounit, '(I10)' ) this%Interaction(i,j)%KBISum(o)
                        end do
                    else
                        do o = 1, KBINShellsCubeEdge*NProcs
                            read( restartFile%iounit, '(I10)' ) KBISum_hilf(o)
                        end do
                    endif
                end if
                if ( mpiMCCommonGroups > 0 ) then
                    call MPI_Bcast( this%Interaction(i,j)%KBISum(1:KBINShellsCubeEdge), &
&                     KBINShellsCubeEdge, MPI_INTEGER8, NRootProc, Communicator, ierror )
                else
                    call MPI_Scatter( KBISum_hilf(1:KBINShellsCubeEdge*NProcs), KBINShellsCubeEdge, MPI_INTEGER8, &
&                     this%Interaction(i,j)%KBISum(1:KBINShellsCubeEdge), KBINShellsCubeEdge, MPI_INTEGER8, &
&                     NRootProc, Communicator, ierror )
                endif
#else
                do o = 1, KBINShellsCubeEdge
                    read( restartFile%iounit, '(I10)' ) this%Interaction(i,j)%KBISum(o)
                end do
#endif
            end do
        end do
        if( RootProc ) then    ! Read mean RDF over all blocks for Gij extrapolation
            do i = 1, this%NRealComponents*(this%NRealComponents+1)/2
                do o = 1, KBINShellsCubeEdge
                    read( restartFile%iounit, '(ES20.12E3)' ) this%KBIRDFextra(o,i)
                    read( restartFile%iounit, '(ES20.12E3)' ) this%KBIRDFvdVextra(o,i)
                    read( restartFile%iounit, '(ES20.12E3)' ) this%KBIRDFvdVshfextra(o,i)
                end do
            end do
            read( restartFile%iounit, '(I10)' ) this%KBIBlockCount
        end if
#if MPI_VER > 0
        if ( mpiMCCommonGroups > 0 ) then
          do i = 1, this%NRealComponents*(this%NRealComponents+1)/2
            call MPI_Bcast(this%KBIRDFextra(1:KBINShellsCubeEdge,i),      KBINShellsCubeEdge, MPI_RK,NRootProc,Communicator,ierror)
            call MPI_Bcast(this%KBIRDFvdVextra(1:KBINShellsCubeEdge,i),   KBINShellsCubeEdge, MPI_RK,NRootProc,Communicator,ierror)
            call MPI_Bcast(this%KBIRDFvdVshfextra(1:KBINShellsCubeEdge,i),KBINShellsCubeEdge, MPI_RK,NRootProc,Communicator,ierror)
          end do
          call MPI_Bcast( this%KBIBlockCount, 1, MPI_INTEGER, NRootProc, Communicator, ierror)
        endif
#endif
        do i= 1, this%NRealComponents*(this%NRealComponents+1)/2!Number of comb., e.g. 11 12 22
            call RestartRead( this%SumKBIGij1(i), .true. )
            call RestartRead( this%SumKBIGij2(i), .true. )
            call RestartRead( this%SumKBIGij3(i), .true. )
        end do
    end if


#if TRANS ==1
    if( this%CorrfunMode ) then
      if( RootProc ) then
        read( restartFile%iounit, '(I10)' ) this%NCorr
        read( restartFile%iounit, '(I10)' ) this%Mmess
      end if
    end if

#if MPI_VER > 0
    call MPI_Bcast( this%NCorr, 1, MPI_INTEGER, NRootProc, Communicator, ierror )
    call MPI_Bcast( this%Mmess, 1, MPI_INTEGER, NRootProc, Communicator, ierror )
#endif

    if ( RootProc ) then

      !Reduced correlation steps
      StepCorr = (Step + this%NStepCorr -1) / this%NStepCorr

      !Calculate matrix indexes
      Mindex = mod(StepCorr, this%NCorr )
      if (Mindex .eq. 0) then
       Mindex = this%NCorr
      end if

      k=mod(Mindex,this%NSpanCF)

      if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
        do i = 1, 3*this%NPart
          do j = 1, this%NCorr
            read( restartFile%iounit, '(ES20.12E3)' )  this%a( i, j)
          end do
        end do

        this%A_SpanCF(:,1:k) =  this%a(:,Mindex + 1 - k:Mindex )
      end if

      do i = 1, this%NCorr
        read( restartFile%iounit, '(3(ES20.12E3, :, X))' ) this%vsk(i,:)
      end do
      do i = 1, this%NCorr
        read( restartFile%iounit, '(3(ES20.12E3, :, X))' ) this%vsp(i,:)
      end do
      do i = 1, this%NCorr
        read( restartFile%iounit, '(3(ES20.12E3, :, X))' ) this%vbk(i,:)
      end do
      do i = 1, this%NCorr
        read( restartFile%iounit, '(3(ES20.12E3, :, X))' ) this%vbp(i,:)
      end do
      do i = 1, this%NCorr
        read( restartFile%iounit, '(3(ES20.12E3, :, X))' ) this%vckt(i,:)
      end do
      do i = 1, this%NCorr
        read( restartFile%iounit, '(3(ES20.12E3, :, X))' ) this%vckr(i,:)
      end do
      do i = 1, this%NCorr
        read( restartFile%iounit, '(3(ES20.12E3, :, X))' ) this%vcpt(i,:)
      end do
      do i = 1, this%NCorr
        read( restartFile%iounit, '(3(ES20.12E3, :, X))' ) this%vcpr(i,:)
      end do
      do i = 1, this%NCorr
        read( restartFile%iounit, '(3(ES20.12E3, :, X))' ) this%vcmt(i,:)
      end do
      do i = 1, this%NCorr
        read( restartFile%iounit, '(ES20.12E3)' ) this%average_cf_c(i)
      end do
      do i = 1, this%NCorr
        read( restartFile%iounit, '(ES20.12E3)' )  this%average_cf_vb(i)
      end do

      if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
        do i = 1, this%NCorr
          read( restartFile%iounit, '(ES20.12E3)' )  this%average_cf_vs(i)
        end do
      end if

      do i = 1, this%NCorr
        read( restartFile%iounit, '(ES20.12E3)' )  this%average_cf_ec(i)
      end do

      if (this%NComponents .gt. 1) then
        do i = 1, this%NComponents
          do j = 1, this%NCorr
             read( restartFile%iounit, '(ES20.12E3)' ) this%average_cf_soret(i,j)
          end do
        end do

        if (TransMethod .eq. Einstein) then
          do i = 1, this%NComponents
            do j = 1, this%NCorr
              read( restartFile%iounit, '(ES20.12E3)' ) this%velcompX(i,j)
            end do
          end do
          do i = 1, this%NComponents
            do j = 1, this%NCorr
              read( restartFile%iounit, '(ES20.12E3)' ) this%velcompY(i,j)
            end do
          end do
          do i = 1, this%NComponents
            do j = 1, this%NCorr
              read( restartFile%iounit, '(ES20.12E3)' ) this%velcompZ(i,j)
            end do
          end do
        end if
      end if

      if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
        do i = 1, this%NComponents
          do j = 1, this%NCorr
            read( restartFile%iounit, '(ES20.12E3)' )  this%average_cf_d(i , j)
          end do
        end do
        if (this%Ncomponents>1) then
          do i = 1, this%NComponents*this%NComponents
            do j = 1, this%NCorr
              read( restartFile%iounit, '(ES20.12E3)' )  this%average_lamda(i , j)
            end do
          end do
        end if
      end if

      read( restartFile%iounit, '(I10)' ) NBlocksMaxCF

      if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
        do i = 1, this%NComponents
          call RestartRead( this%Sumself_i(i) )
        end do
      end if

      if(this%NComponents > 1) then
         if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
           do i = 1, this%NComponents
             do j = 1, this%NComponents
               call RestartRead( this%SumOnsager(i,j) )
             end do
           end do
         end if
         do i = 1, this%NComponents
          call RestartRead( this%SumSoret(i) )
         end do
      end if

      if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
        call RestartRead( this%SumVisco_s )
      end if
      call RestartRead( this%SumVisco_b )
      call RestartRead( this%SumConduct )
      call RestartRead( this%SumEConduct)

      do i = 1,3
        read( restartFile%iounit, '(ES20.12E3)' )  this%sp(i)
      end do

      do i = 1,3
        read( restartFile%iounit, '(ES20.12E3)' )  this%sc(i)
      end do

       if( (TransMethod .eq. Einstein) .or. (TransMethod .eq. GKEinstein) ) then
            read( restartFile%iounit, '(I10)' ) this%EinsteinCoefAveCount
            do j = 0, this%NCorr/this%NSpanCF-1
              read( restartFile%iounit, '(I10)' ) this%EinsteinCoefTimeStep(j)
            end do

            do s = 1, this%NComponents
                do i = 1, this%NCorr
                  do j = 0, this%NCorr/this%NSpanCF-1
                    !write( restartFile%iounit, '((ES20.12E3, :, ";"))' ) this%DselfEinstein(i,j,s)
                    read( restartFile%iounit, '((ES20.12E3))' ) this%DselfEinstein(i,j,s)
                  end do
                end do
            end do
            if(this%NComponents > 1) then
                do s = 1, this%NComponents
                do t = 1, this%NComponents
                    do i = 1, this%NCorr
                      do j = 0, this%NCorr/this%NSpanCF-1
                        !write( restartFile%iounit, '((ES20.12E3, :, ";"))' ) this%DselfEinstein(i,j,s)
                        read( restartFile%iounit, '((ES20.12E3))' ) this%OnsagerEinstein(i,j,s,t)
                      end do
                    end do
                end do
                end do
            end if
            do s = 1, this%NComponents
                do i = 1, this%NCorr
                    !write( restartFile%iounit, '((ES20.12E3, :, ";"))' ) this%DselfEinstein(i,j,s)
                    read( restartFile%iounit, '((ES20.12E3))' ) this%DselfEinsteinAve(i,s)  !memory access is probably stupid
                end do
            end do
            if(this%NComponents > 1) then
                do s = 1, this%NComponents
                do t = 1, this%NComponents
                    do i = 1, this%NCorr
                        !write( restartFile%iounit, '((ES20.12E3, :, ";"))' ) this%DselfEinstein(i,j,s)
                        read( restartFile%iounit, '((ES20.12E3))' ) this%OnsagerEinsteinAve(i,s,t)
                    end do
                end do
                end do
            end if
            do s = 1, this%NComponents
               read(restartFile%iounit,'(ES20.12E3)') this%DselfEinsteinCurrent(s)
            end do


        if(this%NComponents > 1) then
            do s = 1, this%NComponents
                do t = 1, this%NComponents
                    read(restartFile%iounit,'(ES20.12E3)') this%OnsagerEinsteinCurrent(s,t)
                end do
            end do
        endif
         do s = 1, this%NComponents
            call RestartRead( this%EinsteinDSelfAcc(s), .true. )
        end do

        if(this%NComponents > 1) then
          do s = 1, this%NComponents
             do t = 1, this%NComponents
               call RestartRead( this%EinsteinOnsagerAcc(s,t), .true. )
             end do
          end do
        end if

        do i = 1, this%NCorr
            read( restartFile%iounit, '((ES20.12E3))' )  this%EinsteinShear(i)
        end do

        do i = 1, this%NCorr
            read( restartFile%iounit, '((ES20.12E3))' )  this%EinsteinShearAve(i)
        end do

        call RestartRead( this%EinsteinShearAcc, .true.)
      end if
    end if
#endif

    ! Update density and box length
    call UpdateBoxLength( this )

    ! Update molar fractions
    call UpdateFractions( this )

    if (LongRange .eq. Ewald) then
    ! Calculate initial energies for the Ewald Summation
       this%Kappa = this%KappaL/this%BoxLength   !Boxlength bereits normiert
       do i=1,this%NComponents
         do j=1,this%NComponents
           this%Interaction(i,j)%Kappa = this%Kappa
         end do
       end do

      ! Calculate initial energies for the Ewald Summation
         nullify ( this%U_fourierLocal )
         nullify ( this%SSin )
         nullify ( this%SCos )
         nullify ( this%rold )
         nullify ( this%Vec2 )
         allocate(this%U_fourierLocal(this%BoxenAnzahlMax),STAT=stat)
         if(stat >0) write(*,*) 'Allocation Error U_fourier'
         allocate(this%SSin(this%BoxenAnzahlMax),STAT=stat)
         if(stat >0) write(*,*) 'Allocation Error SSin'
         allocate(this%SCos(this%BoxenAnzahlMax),STAT=stat)
         if(stat >0) write(*,*) 'Allocation Error SCos'
         allocate(this%Vec2(this%BoxenAnzahlMax),STAT=stat)
         if(stat >0) write(*,*) 'Allocation Error Vec2'
         allocate(this%rold(5,3),STAT=stat)
         if(stat >0) write(*,*) 'Allocation Error rold'
         DO i=1,5
           DO j=1,3
             this%rold(i,j) = 0._RK
             this%rold(i,j) = 0._RK
             this%rold(i,j) = 0._RK
           END DO
         END DO

#if SPME > 0
    else if (LongRange .eq. PME) then
    ! Calculate initial energies for the Ewald Summation
       this%Kappa = this%KappaL/this%BoxLength   !Boxlength bereits normiert
       do i=1,this%NComponents
         do j=1,this%NComponents
           this%Interaction(i,j)%Kappa = this%Kappa
         end do
       end do

! Allocation needed!
         allocate(this%bsp_arr(this%gridx+5),STAT=stat)
         if(stat >0) write(*,*) 'Allocation Error bsp_arr'
         allocate(this%bsp_modx(this%gridx+5),STAT=stat)
         if(stat >0) write(*,*) 'Allocation Error bsp_modx'
         allocate(this%bsp_mody(this%gridx+5),STAT=stat)
         if(stat >0) write(*,*) 'Allocation Error bsp_mody'
         allocate(this%bsp_modz(this%gridx+5),STAT=stat)
         if(stat >0) write(*,*) 'Allocation Error bsp_modz'

       call PMESetup(this)
#endif
    else if ( LongRange .eq. Rodgers ) then
       do i=1,this%NComponents
         do j=1,this%NComponents
           this%Interaction(i,j)%Kappa = this%Kappa
         end do
       end do
    end if

    ! Reading and broadcasting thi-file for ThermoInt
    t = this%NRealComponents+1
    write( IOBuffer, '(I16)' ) this%EnsembleNumber
    if ( any(this%Component(:)%ChemPotMethod .eq. ChemPotMethodThermoInt)) then
      call FileReset(this%thermointFile, trim(OutputNameTag)//'_'//trim( adjustl(IOBuffer) )//ThermoIntFileExtension )
    end if
    do i=1,this%NRealComponents
      pc => this%Component(i)
      if (pc%ChemPotMethod .eq. ChemPotMethodThermoInt) then

        call FileReadParameter( this%Component(t)%lambda, this%thermointFile%iounit , "currentlambda", .false. )
        pc%CalcChemPot = .true.
        if (RootProc) then
           !read empty line
           read( this%thermointFile%iounit, * )

           ! read thermoint-profile
           do j = 0,pc%NBins-1
             read( this%thermointFile%iounit, '(I6, 2X, F5.3,7(1X, E15.6),1X, I10)' )  k, dummy, pc%BinsEn(j), pc%BinsdEndLa(j), pc%BinsdEndLaV(j), pc%BinsdEndLaH(j), pc%BinsIntdEndLa(j), pc%BinsIntVW(j), pc%BinsIntHW(j), pc%BinsVisit(j)
           end do
        end if

#if MPI_VER > 0
        if ( mpiMCCommonGroups > 0 ) then
        ! reading in ThermoInt parameters from *.rst files for each MCCommonGroup
            if (RootProc) then
              ! read current lambda
              read( restartFile%iounit, '(E19.10)' ) this%Component(t)%lambda
              ! read thermoint-profile
              do j = 0,pc%NBins-1
                read( restartFile%iounit, '(7(E19.10, :, X), I10)' ) pc%BinsEn(j), pc%BinsdEndLa(j), pc%BinsdEndLaV(j), pc%BinsdEndLaH(j),&
&               pc%BinsIntdEndLa(j), pc%BinsIntVW(j), pc%BinsIntHW(j), pc%BinsVisit(j)
              end do
            endif
        endif
#endif

        t = t+1
      end if
    end do
    if ( any(this%Component(:)%ChemPotMethod .eq. ChemPotMethodThermoInt)) then
      call FileClose(this%thermointFile)
    end if

#if MPI_VER > 0
    t = this%NRealComponents+1
    do i=1,this%NRealComponents
        pc => this%Component(i)
        if (pc%ChemPotMethod .eq. ChemPotMethodThermoInt) then
          !The Broadcast of the following properties would not have been necessary for MD runs during the implementation of ThermoInt, but for MC required
          !call MPI_Bcast( this%Component(t)%lambda ... done during the preceding call FileReadParameter, but for MC with mpiMCCommonGroups>0 it is required
          call MPI_Bcast( this%Component(t)%lambda, 1, MPI_RK, NRootProc, Communicator, ierror )
          call MPI_Bcast( pc%BinsEn(0:pc%NBins-1), size( pc%BinsEn ), MPI_RK, NRootProc, Communicator, ierror )
          call MPI_Bcast( pc%BinsdEndLa(0:pc%NBins-1), size( pc%BinsdEndLa ), MPI_RK, NRootProc, Communicator, ierror )
          call MPI_Bcast( pc%BinsdEndLaV(0:pc%NBins-1), size( pc%BinsdEndLaV ), MPI_RK, NRootProc, Communicator, ierror )
          call MPI_Bcast( pc%BinsdEndLaH(0:pc%NBins-1), size( pc%BinsdEndLaH ), MPI_RK, NRootProc, Communicator, ierror )
          call MPI_Bcast( pc%BinsIntdEndLa(0:pc%NBins-1), size( pc%BinsIntdEndLa ), MPI_RK, NRootProc, Communicator, ierror )
          call MPI_Bcast( pc%BinsIntVW(0:pc%NBins-1), size( pc%BinsIntVW ), MPI_RK, NRootProc, Communicator, ierror )
          call MPI_Bcast( pc%BinsIntHW(0:pc%NBins-1), size( pc%BinsIntHW ), MPI_RK, NRootProc, Communicator, ierror )
          call MPI_Bcast( pc%BinsVisit(0:pc%NBins-1), size( pc%BinsVisit ), MPI_INTEGER, NRootProc, Communicator, ierror )
          t = t+1
        endif
    enddo
#endif

    t = this%NRealComponents+1
    do i=1,this%NRealComponents
      if (this%Component(i)%ChemPotMethod .eq. ChemPotMethodThermoInt) then
        Factor = this%Component(t)%lambda**this%Component(i)%LambdaExponent
        call ScaleInteractionThermoInt(this, t, Factor)
        t = t+1
      endif
    enddo
    ! End of reading and broadcasting thi-file for ThermoInt

    if( SimulationType .eq. MolecularDynamics ) then

      ! Calculate temperature and set up ndf
      call CalculateEKin( this, .false. )

    else

      ! Set temperature
      this%Temperature = this%RefTemperature

      ! Initialize energy matrix
      call Mol2Atom( this )
      call Energy( this, this%EPot, d2EdV2, Virial )

    end if

  end subroutine TEnsemble_RestartRead



!==============================================================!
!  Subroutine TEnsemble_DbgWrite                               !
!==============================================================!

  subroutine TEnsemble_DbgWrite( this )

    implicit none

    ! Include MPI header
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif

    ! Declare arguments
    type(TEnsemble) :: this

    ! Declare external procedures
    integer, external :: system

    ! Declare local variables
    type(TComponent), pointer :: pc
    integer                   :: nc, i, i1, i2, j, n, n2, n3
    real(RK)                  :: C(this%NPart * 3), Q(this%NPart * 4)

    if( .not. RootProc ) return

    n = this%NPart
    n2 = 2 * n
    n3 = 3 * n
    i1 = 1
    i2 = 0

    do nc = 1, this%NComponents
      pc => this%Component(nc)
      i2 = i2 + pc%NPart
      do i = i1, i2
        j = i - i1 + 1
        C(i) = pc%P0(j, 1)
        C(i+n) = pc%P0(j, 2)
        C(i+n2) = pc%P0(j, 3)
        Q(i) = pc%Q0(j, 1)
        Q(i+n) = pc%Q0(j, 2)
        Q(i+n2) = pc%Q0(j, 3)
        Q(i+n3) = pc%Q0(j, 4)
      end do
      i1 = i2 + 1
    end do

    open(996, file='EIN_1', status='REPLACE', action='WRITE')
    write(996, '(3ES22.12E3)') C
    write(996, '(4ES22.12E3)') Q
    write(996,*) this%Component(1)%NFLuctMax - this%Component(1)%NFluctState + 1
    write(996,*) ix, iy
    close(996)


  end subroutine TEnsemble_DbgWrite


!==============================================================!
!  Subroutine TSimulation_Ewald_SelfTerm                       !
!==============================================================!

  subroutine TEnsemble_EwaldSelfTerm( this )

    implicit none

    ! Include MPI header
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif

    ! Declare arguments
    type(TEnsemble)         :: this
    ! Declare local variables
    integer :: i,Si,Sj
    integer :: NX,NY,NZ
    real(RK):: USelbstTermKomp
    real(RK):: Faktor, NSQ
    real(RK):: RXi,RYi,RZi,RXj,RYj,RZj
    real(RK):: drxij,dryij,drzij,dr
    real(RK):: approx
    real(RK):: UIntraTermKomp
    real(RK):: twopi
    real(RK):: test

    twopi = 2._RK*PI

    i = 0
    DO NX = 0, this%NMAX, 1
       IF (NX .EQ.0) THEN
         Faktor = 1.0_RK
       ELSE
         Faktor = 2.0_RK
       END IF
       DO NY = -this%NMAX,this%NMAX,1
         DO NZ = -this%NMAX,this%NMAX,1
           NSQ = NX*NX + NY*NY + NZ*NZ
           IF ( (NSQ .LE. this%NSQMAX) .AND. (NSQ .NE. 0) ) THEN
             i = i+1
             IF (i .GT. this%NVecMax) STOP   'BoxAnzahl zu gross'
             this%Ewald_Prefac(i) = Faktor*exp(-(PI/this%KappaL)**2 * NSQ) / (Pi2 * NSQ * this%BoxLength)
             this%Ewald_Vec(1,i)  = twopi*NX
             this%Ewald_Vec(2,i)  = twopi*NY
             this%Ewald_Vec(3,i)  = twopi*NZ
           END IF
         END DO
       END DO
    END DO
    this%BoxenAnzahlMax = i

#if MPI_VER > 0
    this%NBox2 = i
    if ( (SimulationType .ne. MonteCarlo) .or. (Equilibration .and. CommonEqui) .or. (mpiMCCommonGroups > 0)) then
      call MPI_Bcast( this%Ewald_Vec(1,:), this%BoxenAnzahlMax, MPI_RK, NRootProc, Communicator, ierror )
      call MPI_Bcast( this%Ewald_Vec(2,:), this%BoxenAnzahlMax, MPI_RK, NRootProc, Communicator, ierror )
      call MPI_Bcast( this%Ewald_Vec(3,:), this%BoxenAnzahlMax, MPI_RK, NRootProc, Communicator, ierror )
      call MPI_Bcast( this%Ewald_Prefac, this%BoxenAnzahlMax, MPI_RK, NRootProc, Communicator, ierror )
    end if
#endif

! Selbstterm
    this%USelbstTerm = 0.0
    DO i=1,this%NComponents,1
       USelbstTermKomp = 0.0
       DO Si=1,this%Component(i)%Molecule%NCharge,1
         USelbstTermKomp = USelbstTermKomp + this%Component(i)%Molecule%SiteCharge(Si)%e**2
       END DO
       this%USelbstTerm = this%USelbstTerm + this%Component(i)%NPart * USelbstTermKomp
    END DO

    this%USelbstTerm = -this%USelbstTerm * this%Kappa / sqrt(Pi)

! intramolecular term
    this%UIntra = 0._RK
    DO i=1,this%NComponents,1
      UIntraTermKomp = 0.0
      DO Si = 1,this%component(i)%Molecule%NCharge-1
        DO Sj = Si+1,this%component(i)%Molecule%NCharge

          RXi  = this%Component(i)%Molecule%SiteCharge(Si)%r(1)
          RYi  = this%Component(i)%Molecule%SiteCharge(Si)%r(2)
          RZi  = this%Component(i)%Molecule%SiteCharge(Si)%r(3)
          RXj  = this%Component(i)%Molecule%SiteCharge(Sj)%r(1)
          RYj  = this%Component(i)%Molecule%SiteCharge(Sj)%r(2)
          RZj  = this%Component(i)%Molecule%SiteCharge(Sj)%r(3)

          drxij = (RXi-RXj)
          dryij = (RYi-RYj)
          drzij = (RZi-RZj)

          dr = sqrt(drxij*drxij + dryij*dryij + drzij*drzij)

          if (dr .ge. 0.0000001) then
            call ErrorApprox(this%interaction(i,i)%PotChargeCharge(Si,Sj), this%Kappa*dr, approx)

            UIntraTermKomp = UIntraTermKomp - this%Component(i)%Molecule%SiteCharge(Si)%e* &
&                            this%Component(i)%Molecule%SiteCharge(Sj)%e / dr * (1-approx)
          end if
        END DO
      END DO
      this%UIntra = this%UIntra + this%component(i)%NPart * UIntraTermKomp
    END DO

#if MPI_VER > 0
    this%NBox1  = ProcRange ( this%BoxenAnzahlMax, this%NBox0, this%NBox2 )
#endif
    end subroutine TEnsemble_EwaldSelfTerm



!==============================================================!
!  Subroutine TSimulation_Ewald_FourierTerm                    !
!==============================================================!

   subroutine TEnsemble_EwaldFourierTerm(this)

   implicit none

#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif
   ! Declare arguments
   type(TEnsemble)   :: this

   ! Declare local variables
   integer :: i,j,l,m
   integer :: molec

   real(RK),pointer, contiguous:: RX(:),RY(:),RZ(:)
   real(RK),pointer, contiguous:: PX(:),PY(:),PZ(:)
   real(RK),pointer, contiguous:: FX(:),FY(:),FZ(:)
   real(RK),pointer:: q(:)
   real(RK) :: RXloc(this%NPartMax),RYloc(this%NPartMax),RZloc(this%NPartMax)
   real(RK) :: PXloc(this%NPartMax),PYloc(this%NPartMax),PZloc(this%NPartMax)

   real(RK):: KVec(3), KVec05
   real(RK):: EPotLocal
   real(RK):: Viriallocal, VirIntra, VirIntraLocal
   real(RK):: SSinSum,SCosSum
   real(RK):: KappaL2, vorfac
   real(RK):: Facx,Facy,Facz
   real(RK):: BoxLength
   real(RK):: Faktor(1:this%NPart)
   real(RK):: HFac(1:this%NPart)
   real(RK):: HFacX(1:this%NPart), HFacY(1:this%NPart), HFacZ(1:this%NPart)
   real(RK):: distx(1:this%NPart),disty(1:this%NPart),distz(1:this%NPart)
   real(RK),allocatable:: qsinfac(:)
   real(RK),allocatable:: qcosfac(:)
   !real(RK):: qsinfac(1:this%NPart*this%NComponents*5)
   !real(RK):: qcosfac(1:this%NPart*this%NComponents*5)
   integer :: ChargeNumber
#if MPI_VER > 0
   integer, pointer:: i0,i1
#endif
#if  TRANS == 1
   real(RK),pointer, contiguous:: VSx(:),VSy(:),VSz(:)
   real(RK),pointer, contiguous:: VSux(:),VSuy(:),VSuz(:)
   real(RK),pointer, contiguous:: VBx(:),VBy(:),VBz(:)
   real(RK)        :: multiplicator
   real(RK)        :: Contrib

#endif

   type(TMolecule), pointer               :: mol
   integer:: stat

   EPotLocal = 0.0_RK
   VirialLocal = 0.0_RK
   KappaL2 = 1.0_RK/(2._RK*this%KappaL**2)
   BoxLength = this%BoxLength
   vorfac = 2._RK/BoxLength

   m = 0
   do i=1,this%NComponents
     m = m + this%Component(i)%NPart*this%Component(i)%Molecule%NCharge
   enddo
   allocate(qsinfac(1:m))
   allocate(qcosfac(1:m))
   qsinfac(1:m)=0
   qcosfac(1:m)=0

   ! Virial
   this%Vec2 = this%Ewald_Vec(1,:)**2 + this%Ewald_Vec(2,:)**2 + this%Ewald_Vec(3,:)**2
   VirIntraLocal = 0._RK

   this%SSin=0._RK
   this%SCos=0._RK

#if MPI_VER > 0
   i0 => this%NBox0
   i1 => this%NBox2
   DO i=i0,i1,1
#else
   DO i=1,this%BoxenAnzahlMax,1
# endif

     ChargeNumber = 0
     KVec = this%Ewald_Vec(:,i)
     KVec05 = sum(KVec)/2._RK
     SSinSum = 0._RK
     SCosSum = 0._RK
     DO j=1,this%NComponents,1
       mol => this%Component(j)%Molecule
       q => mol%SiteCharge(1:mol%NCharge)%e
       molec = this%Component(j)%NPart
       DO l=1,mol%NCharge
         RX => this%Component(j)%Molecule%SiteCharge(l)%RX(1:molec)
         RY => this%Component(j)%Molecule%SiteCharge(l)%RY(1:molec)
         RZ => this%Component(j)%Molecule%SiteCharge(l)%RZ(1:molec)
         PX => this%Component(j)%Molecule%SiteCharge(l)%PX(1:molec)
         PY => this%Component(j)%Molecule%SiteCharge(l)%PY(1:molec)
         PZ => this%Component(j)%Molecule%SiteCharge(l)%PZ(1:molec)

! Alte Version
         RXloc(1:molec) = RX(1:molec)
         RYloc(1:molec) = RY(1:molec)
         RZloc(1:molec) = RZ(1:molec)
         PXloc(1:molec) = PX(1:molec)
         PYloc(1:molec) = PY(1:molec)
         PZloc(1:molec) = PZ(1:molec)

         DO m=1,molec
           if (PX(m) < 0) RXloc(m) = RXloc(m) + 1._RK
           if (PY(m) < 0) RYloc(m) = RYloc(m) + 1._RK
           if (PZ(m) < 0) RZloc(m) = RZloc(m) + 1._RK
           if (PX(m) < 0) PXloc(m) = PXloc(m) + 1._RK
           if (PY(m) < 0) PYloc(m) = PYloc(m) + 1._RK
           if (PZ(m) < 0) PZloc(m) = PZloc(m) + 1._RK
         end DO
         Faktor(1:molec) = KVec(1) * RXloc + KVec(2)*RYloc + KVec(3)*RZloc
         qsinfac(ChargeNumber+1:ChargeNumber+molec) = q(l)*sin(Faktor)
         qcosfac(ChargeNumber+1:ChargeNumber+molec) = q(l)*cos(Faktor)
         SSinSum = SSinSum + sum(qsinfac(ChargeNumber+1:ChargeNumber+molec))
         SCosSum = SCosSum + sum(qcosfac(ChargeNumber+1:ChargeNumber+molec))

         ChargeNumber = ChargeNumber + molec
       END DO
     END DO

     this%SSin(i) = SSinSum
     this%SCos(i) = SCosSum

! Forces
     Facx = KVec(1)*this%Ewald_Prefac(i)*vorfac
     Facy = KVec(2)*this%Ewald_Prefac(i)*vorfac
     Facz = KVec(3)*this%Ewald_Prefac(i)*vorfac

     ChargeNumber = 0
     DO j=1,this%NComponents,1
       mol => this%Component(j)%Molecule
       molec = this%Component(j)%NPart
       DO l=1,mol%NCharge
         RX => this%Component(j)%Molecule%SiteCharge(l)%RX(1:molec)
         RY => this%Component(j)%Molecule%SiteCharge(l)%RY(1:molec)
         RZ => this%Component(j)%Molecule%SiteCharge(l)%RZ(1:molec)
         PX => this%Component(j)%Molecule%SiteCharge(l)%PX(1:molec)
         PY => this%Component(j)%Molecule%SiteCharge(l)%PY(1:molec)
         PZ => this%Component(j)%Molecule%SiteCharge(l)%PZ(1:molec)
         FX => this%Component(j)%Molecule%SiteCharge(l)%FX
         FY => this%Component(j)%Molecule%SiteCharge(l)%FY
         FZ => this%Component(j)%Molecule%SiteCharge(l)%FZ

         distx(1:molec) = (RX-PX)*BoxLength
         disty(1:molec) = (RY-PY)*BoxLength
         distz(1:molec) = (RZ-PZ)*BoxLength

         HFac(1:molec) = qsinfac(ChargeNumber+1:ChargeNumber+molec)*SCosSum - qcosfac(ChargeNumber+1:ChargeNumber+molec)*SSinSum
         HFacX(1:molec) = Facx*HFac(1:molec)
         HFacy(1:molec) = Facy*HFac(1:molec)
         HFacZ(1:molec) = Facz*HFac(1:molec)

         FX = FX + HFacX(1:molec)
         FY = FY + HFacY(1:molec)
         FZ = FZ + HFacZ(1:molec)

         VirIntraLocal = VirIntraLocal + sum(HFacX(1:molec)*distx(1:molec) &
   &                                   +     HFacY(1:molec)*disty(1:molec) &
   &                                   +     HFacZ(1:molec)*distz(1:molec))

#if  TRANS == 1
         ! Preparation for Transport properties
         VSx  => mol%SiteCharge(l)%vsCx
         VSy  => mol%SiteCharge(l)%vsCy
         VSz  => mol%SiteCharge(l)%vsCz
         VBx  => mol%SiteCharge(l)%vbCx
         VBy  => mol%SiteCharge(l)%vbCy
         VBz  => mol%SiteCharge(l)%vbCz

          ! Intramolecular Forces
         VSx  = VSx  - HFacX(1:molec)*disty(1:molec)
         VSy  = VSy  - HFacX(1:molec)*distz(1:molec)
         VSz  = VSz  - HFacY(1:molec)*distz(1:molec)
         VBx  = VBx  - HFacX(1:molec)*distx(1:molec)
         VBy  = VBy  - HFacY(1:molec)*disty(1:molec)
         VBz  = VBz  - HFacZ(1:molec)*distz(1:molec)

#endif

         ChargeNumber = ChargeNumber + molec

       END DO
     END DO

#if  TRANS == 1
     ! Force contribution due to the intermolecular long-range forces
     ! Since these properties are specific for the entire solution and not valid for individual
     ! components, these quantities are calculated once and added onto the contribution of
     ! the last component in the system
     multiplicator = (1._RK/this%Vec2(i) + 0.25_RK/this%KappaL**2)
     Contrib = -2._RK * multiplicator * this%Ewald_Prefac(i) * (SSinSum*SSinSum + SCosSum*SCosSum) / this%Volume0
     VSx(1) = VSx(1) + Contrib* (this%Ewald_Vec(1,i)*this%Ewald_Vec(2,i) )
     VSy(1) = VSy(1) + Contrib* (this%Ewald_Vec(1,i)*this%Ewald_Vec(3,i) )
     VSz(1) = VSz(1) + Contrib* (this%Ewald_Vec(2,i)*this%Ewald_Vec(3,i) )
     VBx(1) = VBx(1) + Contrib* (-0.5_RK/multiplicator + this%Ewald_Vec(1,i)*this%Ewald_Vec(1,i) )
     VBy(1) = VBy(1) + Contrib* (-0.5_RK/multiplicator + this%Ewald_Vec(2,i)*this%Ewald_Vec(2,i) )
     VBz(1) = VBz(1) + Contrib* (-0.5_RK/multiplicator + this%Ewald_Vec(3,i)*this%Ewald_Vec(3,i) )
#endif

   END DO ! Boxenschleife

! Finish Calculation
! STOP
! Energy
   this%U_fourierLocal = this%Ewald_Prefac * (this%SSin*this%SSin + this%SCos*this%SCos)


#if MPI_VER > 0
   call MPI_Reduce( sum(this%U_fourierLocal), EPotLocal, 1, MPI_RK, MPI_SUM, NRootProc, Communicator, ierror )
   call MPI_Reduce( EPotLocal - sum(this%U_fourierLocal*KappaL2*this%Vec2), VirialLocal, 1, MPI_RK, MPI_SUM, &
&                   NRootProc, Communicator, ierror )
   call MPI_Reduce( VirIntraLocal, VirIntra, 1, MPI_RK, MPI_SUM, NRootProc, Communicator, ierror )
#else
   EPotLocal = sum(this%U_fourierLocal)
   VirialLocal = EPotLocal - sum(this%U_fourierLocal *KappaL2*this%Vec2)
   VirIntra = VirIntraLocal

#endif
   if( RootProc ) then
     this%UFourier= EPotLocal
     this%EVirial = -(Viriallocal - VirIntra)*Third
   end if

   end subroutine TEnsemble_EwaldFourierTerm



!==============================================================!
!  Subroutine TSimulation_Ewald_SelfTerm_Energy                !
!==============================================================!

  subroutine TEnsemble_EwaldSelf_Energy( this )

    implicit none

    ! Declare arguments
    type(TEnsemble)            :: this
    type(TInteraction),pointer :: inter
    integer        :: np
    integer        :: processes

    ! Declare local variables
    integer :: Si,Sj,i
    real(RK):: RXi,RYi,RZi,RXj,RYj,RZj
    real(RK):: drxij,dryij,drzij,dr
    real(RK):: approx
    real(RK):: UIntraTermKomp, USelbstTermKomp


    ! Setting of the right scaling for MC
    if ((Equilibration .and. CommonEqui) .or. (mpiMCCommonGroups > 0)) then
      processes = NProcs
    else
      processes = 1
    end if


    ! Selbstterm
    this%USelbstTerm = 0.0_RK
    DO Sj=1,this%NComponents,1
       USelbstTermKomp = 0.0_RK
       DO Si=1,this%Component(Sj)%Molecule%NCharge,1
         USelbstTermKomp = USelbstTermKomp + this%Component(Sj)%Molecule%SiteCharge(Si)%e**2
       END DO
       this%USelbstTerm = this%USelbstTerm + this%Component(Sj)%NPart * USelbstTermKomp
    END DO

    this%USelbstTerm = -this%USelbstTerm * this%Kappa / sqrt(Pi) / processes


! intramolecular term
    this%UIntra = 0._RK
    DO i=1,this%NComponents,1
      UIntraTermKomp = 0.0
      DO Si = 1,this%component(i)%Molecule%NCharge-1
        DO Sj = Si+1,this%component(i)%Molecule%NCharge

          RXi  = this%Component(i)%Molecule%SiteCharge(Si)%r(1)
          RYi  = this%Component(i)%Molecule%SiteCharge(Si)%r(2)
          RZi  = this%Component(i)%Molecule%SiteCharge(Si)%r(3)
          RXj  = this%Component(i)%Molecule%SiteCharge(Sj)%r(1)
          RYj  = this%Component(i)%Molecule%SiteCharge(Sj)%r(2)
          RZj  = this%Component(i)%Molecule%SiteCharge(Sj)%r(3)

          drxij = (RXi-RXj)
          dryij = (RYi-RYj)
          drzij = (RZi-RZj)

          dr = sqrt(drxij*drxij + dryij*dryij + drzij*drzij)

          if (dr .ge. 0.0000001) then
            call ErrorApprox(this%interaction(i,i)%PotChargeCharge(Si,Sj), this%Kappa*dr, approx)

            UIntraTermKomp = UIntraTermKomp - this%Component(i)%Molecule%SiteCharge(Si)%e* &
&                            this%Component(i)%Molecule%SiteCharge(Sj)%e / dr * (1-approx)
          end if
        END DO
      END DO
      this%UIntra = this%UIntra + this%component(i)%NPart * UIntraTermKomp / processes
    END DO


    end subroutine TEnsemble_EwaldSelf_Energy



!==============================================================!
!  Subroutine TSimulation_Ewald_FourierTermEnergy              !
!==============================================================!

   subroutine TEnsemble_EwaldFourierEnergy(this)

   implicit none

#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif

   type(TMolecule), pointer               :: mol

   ! Declare arguments
   type(TEnsemble)   :: this

   ! Declare local variables
   integer :: i,j,l,m
   integer :: molec
#if MPI_VER > 0
   integer,pointer :: i0
   integer,pointer :: i1
#endif

   real(RK),pointer, contiguous:: RX(:),RY(:),RZ(:)
   real(RK),pointer, contiguous:: PX(:),PY(:),PZ(:)
   real(RK),pointer:: q(:)
   real(RK) :: RXloc(this%NPartMax),RYloc(this%NPartMax),RZloc(this%NPartMax)
   real(RK) :: PXloc(this%NPartMax),PYloc(this%NPartMax),PZloc(this%NPartMax)

   real(RK):: KVec(3)
   real(RK):: EPotLocal
   real(RK):: Viriallocal,VirIntra, VirIntraLocal
   real(RK):: BoxLength
   real(RK):: SSinSum,SCosSum
   real(RK):: KappaL2
   real(RK):: vorfac
   real(RK):: facx,facy,facz
   real(RK):: Faktor(1:this%NPart)
   real(RK):: HFac(1:this%NPart)
   real(RK):: distx(1:this%NPart),disty(1:this%NPart),distz(1:this%NPart)
   real(RK),allocatable:: qsinfac(:)
   real(RK),allocatable:: qcosfac(:)
   !real(RK):: qsinfac(1:this%NPart*this%NComponents*5)
   !real(RK):: qcosfac(1:this%NPart*this%NComponents*5)
   integer :: ChargeNumber


   EPotLocal = 0._RK
   VirialLocal = 0._RK
   KappaL2 = 1.0_RK/(2._RK*this%KappaL**2)
   BoxLength = this%BoxLength
   vorfac = 2._RK / this%BoxLength

   m = 0
   do i=1,this%NComponents
     m = m + this%Component(i)%NPart*this%Component(i)%Molecule%NCharge
   enddo
   allocate(qsinfac(1:m))
   allocate(qcosfac(1:m))
   qsinfac(1:m)=0
   qcosfac(1:m)=0

   VirIntraLocal = 0._RK

   this%SSin = 0._RK
   this%SCos = 0._RK
#if MPI_VER > 0
   i0 => this%NBox0
   i1 => this%NBox2
   DO i=i0,i1,1
#else
   DO i=1,this%BoxenAnzahlMax,1
#endif
     ChargeNumber = 0
     KVec = this%Ewald_Vec(:,i)
     SSinSum = 0._RK
     SCosSum = 0._RK
     DO j=1,this%NComponents,1
       mol => this%Component(j)%Molecule
       q => mol%SiteCharge(1:mol%NCharge)%e
       molec = this%Component(j)%NPart
       DO l=1,mol%NCharge
         RX => this%Component(j)%Molecule%SiteCharge(l)%RX(1:molec)
         RY => this%Component(j)%Molecule%SiteCharge(l)%RY(1:molec)
         RZ => this%Component(j)%Molecule%SiteCharge(l)%RZ(1:molec)
         PX => this%Component(j)%Molecule%SiteCharge(l)%PX(1:molec)
         PY => this%Component(j)%Molecule%SiteCharge(l)%PY(1:molec)
         PZ => this%Component(j)%Molecule%SiteCharge(l)%PZ(1:molec)

         RXloc(1:molec) = RX(1:molec)
         RYloc(1:molec) = RY(1:molec)
         RZloc(1:molec) = RZ(1:molec)
         PXloc(1:molec) = PX(1:molec)
         PYloc(1:molec) = PY(1:molec)
         PZloc(1:molec) = PZ(1:molec)

         DO m=1,molec
           if (PX(m) < 0) RXloc(m) = RXloc(m) + 1._RK
           if (PY(m) < 0) RYloc(m) = RYloc(m) + 1._RK
           if (PZ(m) < 0) RZloc(m) = RZloc(m) + 1._RK
           if (PX(m) < 0) PXloc(m) = PXloc(m) + 1._RK
           if (PY(m) < 0) PYloc(m) = PYloc(m) + 1._RK
           if (PZ(m) < 0) PZloc(m) = PZloc(m) + 1._RK
         end DO

         Faktor(1:molec) = KVec(1) * RXloc + KVec(2)*RYloc + KVec(3)*RZloc

         qsinfac(ChargeNumber+1:ChargeNumber+molec) = q(l)*sin(Faktor)
         qcosfac(ChargeNumber+1:ChargeNumber+molec) = q(l)*cos(Faktor)
         SSinSum = SSinSum + sum(qsinfac(ChargeNumber+1:ChargeNumber+molec))
         SCosSum = SCosSum + sum(qcosfac(ChargeNumber+1:ChargeNumber+molec))
         ChargeNumber = ChargeNumber + molec

       END DO
     END DO

     this%SSin(i) = SSinSum
     this%SCos(i) = SCosSum

! Forces
       Facx = KVec(1)*this%Ewald_Prefac(i)*vorfac
       Facy = KVec(2)*this%Ewald_Prefac(i)*vorfac
       Facz = KVec(3)*this%Ewald_Prefac(i)*vorfac

       ChargeNumber = 0
       DO j=1,this%NComponents,1
         mol => this%Component(j)%Molecule
         molec = this%Component(j)%NPart
         DO l=1,mol%NCharge
           RX => this%Component(j)%Molecule%SiteCharge(l)%RX(1:molec)
           RY => this%Component(j)%Molecule%SiteCharge(l)%RY(1:molec)
           RZ => this%Component(j)%Molecule%SiteCharge(l)%RZ(1:molec)
           PX => this%Component(j)%Molecule%SiteCharge(l)%PX(1:molec)
           PY => this%Component(j)%Molecule%SiteCharge(l)%PY(1:molec)
           PZ => this%Component(j)%Molecule%SiteCharge(l)%PZ(1:molec)

           HFac(1:molec) = qsinfac(ChargeNumber+1:ChargeNumber+molec)*SCosSum - qcosfac(ChargeNumber+1:ChargeNumber+molec)*SSinSum

           distx(1:molec) = (RXloc - PXloc)*BoxLength
           disty(1:molec) = (RYloc - PYloc)*BoxLength
           distz(1:molec) = (RZloc - PZloc)*BoxLength
           VirIntraLocal = VirIntraLocal + sum(Facx*HFac(1:molec)*distx(1:molec)) &
&                                        + sum(Facy*HFac(1:molec)*disty(1:molec)) &
&                                        + sum(Facz*HFac(1:molec)*distz(1:molec))
           ChargeNumber = ChargeNumber + molec
         END DO
       END DO
   END DO ! Boxenschleife


!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!1
! Finish Calculation

! Energy
   this%U_fourierLocal = this%Ewald_Prefac * (this%SSin*this%SSin + this%SCos*this%SCos)
! Virial
   this%Vec2 = this%Ewald_Vec(1,:)**2 + this%Ewald_Vec(2,:)**2 + this%Ewald_Vec(3,:)**2

#if MPI_VER > 0
   if ((Equilibration .and. CommonEqui) .or. (mpiMCCommonGroups > 0)) then
     call MPI_Allreduce( sum(this%U_fourierLocal), EPotLocal, 1, MPI_RK, MPI_SUM, Communicator, ierror )
     call MPI_Allreduce( sum(this%U_fourierLocal) - sum(this%U_fourierLocal*KappaL2*this%Vec2), Viriallocal, 1, &
&                           MPI_RK, MPI_SUM, Communicator, ierror )
     call MPI_Allreduce( VirIntraLocal, VirIntra, 1, MPI_RK, MPI_SUM, Communicator, ierror )
     this%EVirial = -(Viriallocal - VirIntra)*Third / NProcs
     this%UFourier= EPotLocal / NProcs

   else
     ! Energy
     EPotLocal = sum(this%U_fourierLocal)
     this%UFourier= EPotLocal
     ! Virial
     VirialLocal = EPotLocal - sum(this%U_fourierLocal *KappaL2*this%Vec2)
     VirIntra = VirIntraLocal
     this%EVirial = -(Viriallocal - VirIntra)*Third
   end if

#else
   ! Energy
   EPotLocal = sum(this%U_fourierLocal)
   this%UFourier= EPotLocal / NProcs
   ! Virial
   VirialLocal = EPotLocal - sum(this%U_fourierLocal *KappaL2*this%Vec2)
   VirIntra = VirIntraLocal
   this%EVirial = -(Viriallocal - VirIntra)*Third
#endif

  END subroutine TEnsemble_EwaldFourierEnergy


!==============================================================!
!  Subroutine TSimulation_Ewald_FourierTermEnergy1             !
!==============================================================!
   subroutine TEnsemble_EwaldFourierEnergy1(this,nc,np)

   implicit none

#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif

   ! Declare arguments
   type(TEnsemble)          :: this
   type(TMolecule), pointer :: mol

   real(RK):: RX,RY,RZ
   real(RK):: RX2,RY2,RZ2
   real(RK),pointer:: q(:)
   real(RK):: KVec(3)
   real(RK):: EPotLocal
   real(RK)::SSin_Vec,SCos_Vec
   real(RK):: KappaL2
   real(RK):: sinfac,cosfac
   real(RK)::Faktor,Faktor2

   integer :: i,l
   integer,intent(in)::nc,np

#if MPI_VER > 0
   integer,pointer :: i0, i1
#endif


! Declarations
   KappaL2 = 1.0_RK/(2._RK*this%KappaL**2)

! Calculation
#if MPI_VER > 0
   i0 => this%NBox0
   i1 => this%NBox2
   DO i=i0,i1,1
#else
   DO i=1,this%BoxenAnzahlMax,1
#endif

     KVec = this%Ewald_Vec(:,i)
     mol => this%Component(nc)%Molecule
     q => mol%SiteCharge(1:mol%NCharge)%e
     SSin_Vec =0._RK
     SCos_Vec =0._RK
       DO l=1,mol%NCharge
         RX = this%Component(nc)%Molecule%SiteCharge(l)%RX(np)
         RY = this%Component(nc)%Molecule%SiteCharge(l)%RY(np)
         RZ = this%Component(nc)%Molecule%SiteCharge(l)%RZ(np)
         RX2 = this%rold(l,1)
         RY2 = this%rold(l,2)
         RZ2 = this%rold(l,3)

         if (RX < 0) RX = RX + 1._RK
         if (RY < 0) RY = RY + 1._RK
         if (RZ < 0) RZ = RZ + 1._RK
         if (RX2< 0) RX2= RX2+ 1._RK
         if (RY2< 0) RY2= RY2+ 1._RK
         if (RZ2< 0) RZ2= RZ2+ 1._RK

         Faktor = KVec(1) * RX + KVec(2)*RY + KVec(3)*RZ
         Faktor2 = KVec(1) * RX2 + KVec(2)*RY2 + KVec(3)*RZ2

         sinfac = q(l)*(sin(Faktor)-sin(Faktor2))
         cosfac = q(l)*(cos(Faktor)-cos(Faktor2))

         SSin_Vec = SSin_Vec + sinfac
         SCos_Vec = SCos_Vec + cosfac
       END DO

     this%SSin(i) = this%SSin(i) + SSin_Vec
     this%SCos(i) = this%SCos(i) + SCos_Vec

   END DO ! Boxenschleife


!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!1
! Finish Calculation

! Energy
   this%U_fourierLocal = this%Ewald_Prefac * (this%SSin*this%SSin + this%SCos*this%SCos)
! Virial
   this%Vec2 = this%Ewald_Vec(1,:)**2 + this%Ewald_Vec(2,:)**2 + this%Ewald_Vec(3,:)**2

#if MPI_VER > 0
   if ( (Equilibration .and. CommonEqui) .or. (mpiMCCommonGroups > 0) ) then
     call MPI_Allreduce( sum(this%U_fourierLocal), EPotLocal, 1, MPI_RK, MPI_SUM, Communicator, ierror )
     this%UFourier= EPotLocal / NProcs
   else
     EPotLocal = sum(this%U_fourierLocal)
     this%UFourier= EPotLocal
   end if

#else
   EPotLocal = sum(this%U_fourierLocal)
     this%UFourier= EPotLocal
#endif

  END subroutine TEnsemble_EwaldFourierEnergy1


!==============================================================!
!  Subroutine TSimulation_Ewald_FourierTermEnergyCF            !
!==============================================================!
   subroutine TEnsemble_EwaldFourierEnergy_CF(this,nc,np,ncold,npold)

   implicit none

#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif

   ! Declare arguments
   type(TEnsemble)          :: this
   type(TMolecule), pointer :: mol
   type(TMolecule), pointer :: mol2

   real(RK):: RX,RY,RZ
   real(RK),pointer:: q(:)
   real(RK),pointer:: q2(:)
   real(RK):: KVec(3)
   real(RK):: EPotLocal
   real(RK)::SSin_Vec,SCos_Vec
   real(RK):: KappaL2
   real(RK):: sinfac,cosfac
   real(RK)::Faktor,Faktor2

   integer :: i,l
   integer,intent(in)::nc,np
   integer,intent(in)::ncold,npold

#if MPI_VER > 0
   integer,pointer :: i0
   integer,pointer :: i1
#endif

! Declarations
   KappaL2 = 1.0_RK/(2._RK*this%KappaL**2)

! Calculation
#if MPI_VER > 0
   i0 => this%NBox0
   i1 => this%NBox2
   DO i=i0,i1,1
#else
   DO i=1,this%BoxenAnzahlMax,1
#endif
     KVec = this%Ewald_Vec(:,i)
     mol => this%Component(nc)%Molecule
     mol2 => this%Component(ncold)%Molecule
     q => mol%SiteCharge(1:mol%NCharge)%e
     q2=> mol2%SiteCharge(1:mol2%NCharge)%e
     SSin_Vec =0._RK
     SCos_Vec =0._RK
       DO l=1,mol%NCharge
         RX = this%Component(nc)%Molecule%SiteCharge(l)%RX(np)
         RY = this%Component(nc)%Molecule%SiteCharge(l)%RY(np)
         RZ = this%Component(nc)%Molecule%SiteCharge(l)%RZ(np)

         if (RX < 0) RX = RX + 1._RK
         if (RY < 0) RY = RY + 1._RK
         if (RZ < 0) RZ = RZ + 1._RK

         Faktor = KVec(1) * RX + KVec(2)*RY + KVec(3)*RZ

         sinfac = q(l)*sin(Faktor)
         cosfac = q(l)*cos(Faktor)

         SSin_Vec = SSin_Vec + sinfac
         SCos_Vec = SCos_Vec + cosfac
       END DO
       DO l=1,mol2%NCharge
         RX = this%rold(l,1)
         RY = this%rold(l,2)
         RZ = this%rold(l,3)

         if (RX < 0) RX = RX + 1._RK
         if (RY < 0) RY = RY + 1._RK
         if (RZ < 0) RZ = RZ + 1._RK

         Faktor2 = KVec(1) * RX + KVec(2)*RY + KVec(3)*RZ

         sinfac = q2(l)*sin(Faktor2)
         cosfac = q2(l)*cos(Faktor2)

         SSin_Vec = SSin_Vec - sinfac
         SCos_Vec = SCos_Vec - cosfac
       END DO

     this%SSin(i) = this%SSin(i) + SSin_Vec
     this%SCos(i) = this%SCos(i) + SCos_Vec

   END DO ! Boxenschleife

! Energy
   this%U_fourierLocal = this%Ewald_Prefac * (this%SSin*this%SSin + this%SCos*this%SCos)

#if MPI_VER > 0
   if ( (Equilibration .and. CommonEqui) .or. (mpiMCCommonGroups > 0) ) then
     call MPI_Allreduce( sum(this%U_fourierLocal), EPotLocal, 1, MPI_RK, MPI_SUM, Communicator, ierror )
     this%UFourier= EPotLocal  / NProcs
   else
     EPotLocal = sum(this%U_fourierLocal)
     this%UFourier= EPotLocal
   end if

#else
   EPotLocal = sum(this%U_fourierLocal)
   this%UFourier= EPotLocal
#endif

  END subroutine TEnsemble_EwaldFourierEnergy_CF



!==============================================================!
!  Subroutine TSimulation_Ewald_FourierTermAddDel              !
!==============================================================!
   subroutine TEnsemble_EwaldFourierAddDel(this,nc,np,m)

   implicit none

#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif

   ! Declare arguments
   type(TEnsemble)          :: this
   type(TMolecule), pointer :: mol

   real(RK):: RX,RY,RZ
   real(RK),pointer:: q(:)
   real(RK):: KVec(3)
   real(RK):: EPotLocal
   real(RK):: SSin_Vec,SCos_Vec
   real(RK):: KappaL2
   real(RK):: sinfac,cosfac
   real(RK):: Faktor

   integer :: i,l
   integer,intent(in)::nc,np,m

#if MPI_VER > 0
   integer,pointer :: i0
   integer,pointer :: i1
#endif


! Declarations
   KappaL2 = 1.0_RK/(2._RK*this%KappaL**2)

! Calculation
#if MPI_VER > 0
   i0 => this%NBox0
   i1 => this%NBox2
   DO i=i0,i1,1
#else
   DO i=1,this%BoxenAnzahlMax,1
#endif
     KVec = this%Ewald_Vec(:,i)
     mol => this%Component(nc)%Molecule
     q => mol%SiteCharge(1:mol%NCharge)%e
     SSin_Vec =0._RK
     SCos_Vec =0._RK
       DO l=1,mol%NCharge
         RX = this%Component(nc)%Molecule%SiteCharge(l)%RX(np)
         RY = this%Component(nc)%Molecule%SiteCharge(l)%RY(np)
         RZ = this%Component(nc)%Molecule%SiteCharge(l)%RZ(np)

         if (RX < 0) RX = RX + 1._RK
         if (RY < 0) RY = RY + 1._RK
         if (RZ < 0) RZ = RZ + 1._RK

         Faktor = KVec(1) * RX + KVec(2)*RY + KVec(3)*RZ

         sinfac = q(l)*sin(Faktor)
         cosfac = q(l)*cos(Faktor)

         SSin_Vec = SSin_Vec + sinfac*m
         SCos_Vec = SCos_Vec + cosfac*m
       END DO

     this%SSin(i) = this%SSin(i) + SSin_Vec
     this%SCos(i) = this%SCos(i) + SCos_Vec

   END DO ! Boxenschleife


!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!1
! Finish Calculation

! Energy
   this%U_fourierLocal = this%Ewald_Prefac * (this%SSin*this%SSin + this%SCos*this%SCos)
! Virial
   this%Vec2 = this%Ewald_Vec(1,:)**2 + this%Ewald_Vec(2,:)**2 + this%Ewald_Vec(3,:)**2

#if MPI_VER > 0
   if ( (Equilibration .and. CommonEqui) .or. (mpiMCCommonGroups > 0) ) then
      call MPI_Allreduce( sum(this%U_fourierLocal), EPotLocal, 1, MPI_RK, MPI_SUM, Communicator, ierror )
      this%UFourier= EPotLocal  / NProcs
   else
      EPotLocal = sum(this%U_fourierLocal)
      this%UFourier= EPotLocal
   end if

#else
   EPotLocal = sum(this%U_fourierLocal)
   this%UFourier= EPotLocal
#endif


  END subroutine TEnsemble_EwaldFourierAddDel


!==============================================================!
!  Subroutine TSimulation_PME_FourierTerm                      !
!==============================================================!
#if SPME > 0
   subroutine TEnsemble_PMEFourierTerm(this)

   implicit none

    include 'fftw3.f'
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif

   ! Declare arguments
   type(TEnsemble) :: this

   ! Declare local variables
   type(TMolecule),pointer   :: pm
   real(RK):: EPotLocal, Viriallocal
   real(RK):: kap,fac
   real(RK):: boxl,vol
   real(RK):: manhx,manhy,manhz
   real(RK):: den
   real(RK):: mm,bb
   real(RK):: eterm,wterm
   real(RK):: qr,qi,struc
   real(RK):: energ
   real(RK),pointer:: FX, FY, FZ

   real(RK):: FXi, FYi, FZi
   real(RK):: FXcum, FYcum, FZcum
   real(RK):: q
   real(RK):: fac2,fac2s
   real(RK):: factor
   real(RK):: facx,facy,facz

   integer :: order
   integer :: NX,NY,NZ
   integer :: ngrid,ngridyz
   integer :: k1,k2,k3,k1bck
   integer :: m1,m2,m3
   integer :: index_loc

   integer :: counter
   integer :: i,j,k
   integer :: inter

!!!!!!!!!!!! Charge Grid
   real(RK),dimension(this%splineorder+5) ::  transf
   real(RK),dimension(this%splineorder+5) :: dtransf
   real(RK),dimension(this%splineorder+5) ::  splinex
   real(RK),dimension(this%splineorder+5) :: dsplinex
   real(RK),dimension(this%splineorder+5) ::  spliney
   real(RK),dimension(this%splineorder+5) :: dspliney
   real(RK),dimension(this%splineorder+5) ::  splineZ
   real(RK),dimension(this%splineorder+5) :: dsplinez

   real(RK)           :: RX,RY,RZ
   real(RK)           :: RXgit ,RYgit, RZgit
   real(RK)           :: RXgit1,RYgit1,RZgit1
   real(RK)           ::strucx,strucy,strucz
   real(RK)           :: VirLoc

   integer            :: xxo,yyo,zzo
   integer            :: yo,zo

   integer            :: xi,yi,zi
   integer            :: x,y,z

   real(RK)           :: err

   real(RK)           :: qgrid_safe


#if MPI_VER > 0
   integer:: i0,i1
   real(RK) :: mult(this%gridx*this%gridx*this%gridx+3)
   real(RK) :: mult2(this%gridx*this%gridx*this%gridx+3)
   real(RK),pointer, contiguous :: qgrid(:,:)

#endif

! Dimensions of charge
   fac2s= (ElementaryCharge / UnitCharge)
   fac2 = (fac2s)**2
   factor = 1._RK / (UnitLength/Angstroem)

   EPotLocal = 0.0_RK
   VirialLocal = 0.0_RK

   kap  = this%Kappa
   fac  = (PI/kap)**2
   boxl = this%boxlength
   vol  = boxl*boxl*boxl

   order = this%splineorder
   NX    = this%gridx
   NY    = this%gridY
   NZ    = this%gridz

   ngrid   = NX*NY*NZ
   ngridyz = NY*NZ

! Calculate the charges on the grid
   call charge_grid(this)

! Backward Transformation of the chargegrid
   call dfftw_execute(this%qgrid_backward)

! Parallelization
#if MPI_VER > 0
   qgrid => this%qgrida
   mult = 0._RK
   mult2 = 0._RK
   i0 = this%NBox0
   i1 = this%NBox2
   DO i=i0,i1,1
    if (i==1) cycle
#else
   DO i=2,ngrid
#endif
     k1    = int((i-1) / ngridyz)
     k1bck = int((i-1) - k1*ngridyz)
     k2    = int(k1bck / NZ)
     k3    = int(k1bck - k2*NZ)

     m1 = k1
     m2 = k2
     m3 = k3

     if (m1 > NX/2._RK) m1 = m1 - NX
     if (m2 > NY/2._RK) m2 = m2 - NY
     if (m3 > NZ/2._RK) m3 = m3 - NZ

     manhx = m1 / boxl
     manhy = m2 / boxl
     manhz = m3 / boxl

     mm = manhx*manhx + manhy*manhy + manhz*manhz

     bb = this%bsp_modx(k1+1)*this%bsp_mody(k2+1)*this%bsp_modz(k3+1)
     den = PI*vol*mm*bb

     eterm = exp(-fac*mm) / den
     wterm = -2._RK*(fac*mm + 1._RK)

     index_loc = k3 + k2*NZ + k1*NY*NZ + 1

     qr = this%qgrida(1,index_loc)
     qi = this%qgrida(2,index_loc)
     struc = qr*qr + qi*qi

     EPotLocal = EPotLocal + eterm*struc

     VirialLocal = VirialLocal + eterm*struc*(3._RK  + wterm)

#if MPI_VER > 0
     mult(index_loc)      =  eterm * factor
#else
     this%qgrida(1,index_loc) = this%qgrida(1,index_loc) * eterm * factor
     this%qgrida(2,index_loc) = this%qgrida(2,index_loc) * eterm * factor
#endif
   END DO

#if MPI_VER > 0
      call MPI_Reduce( EPotLocal, this%UFourier, 1, MPI_RK, MPI_SUM, NRootProc, Communicator, ierror )
      call MPI_Reduce( VirialLocal, this%EVirial, 1, MPI_RK, MPI_SUM, NRootProc, Communicator, ierror )
      call MPI_Reduce( mult, mult2, ngrid+1, MPI_RK, MPI_SUM, NRootProc, Communicator, ierror )

      this%UFourier = 0.5*this%UFourier * fac2
      this%EVirial  = -0.5*(this%EVirial)*fac2*Third

! Update of the charge vector on the grid, normally done in the loop above.
      this%qgrida(1,1:ngrid+1) = this%qgrida(1,1:ngrid+1)*mult2(1:ngrid+1)
      this%qgrida(2,1:ngrid+1) = this%qgrida(2,1:ngrid+1)*mult2(1:ngrid+1)

#else
   this%UFourier=  0.5*EPotLocal * fac2
   this%EVirial = -0.5*(Viriallocal)*fac2*Third
#endif

   call dfftw_execute(this%qgrid_forward)

! Last factor cause of multiplication with unitlength/angstroem in multiplication of this%qgrida! (look just some lines above this comment!)
  facx = NX / boxl * fac2s / factor
  facy = NY / boxl * fac2s / factor
  facz = NZ / boxl * fac2s / factor


!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!
!!!!!!!!!!!!! Calculation of the forces!!!!
!    counter = 1
   VirLoc = 0._RK
   DO i=1,this%NComponents
     DO j=1,this%Component(i)%Molecule%NCharge
       q =  this%Component(i)%Molecule%SiteCharge(j)%e
       DO k=1,this%Component(i)%NPart

       strucx = 0._RK
       strucy = 0._RK
       strucz = 0._RK

!!!!!!!!!!!!!!!!!!!!!
       q  = this%Component(i)%Molecule%SiteCharge(j)%e
       RX = this%Component(i)%Molecule%SiteCharge(j)%RX(k)
       RY = this%Component(i)%Molecule%SiteCharge(j)%RY(k)
       RZ = this%Component(i)%Molecule%SiteCharge(j)%RZ(k)

       RX     = RX - anint(RX)
       RY     = RY - anint(RY)
       RZ     = RZ - anint(RZ)

       RXgit1 = this%gridx*(RX+0.5_RK)
       RYgit1 = this%gridy*(RY+0.5_RK)
       RZgit1 = this%gridz*(RZ+0.5_RK)

       RXgit = (RXgit1 - floor( RXgit1 ))
       RYgit = (RYgit1 - floor( RYgit1 ))
       RZgit = (RZgit1 - floor( RZgit1 ))

! x-coordinate
       err=fillspline(RXgit,transf,dtransf)
         splinex  = transf
         dsplinex = dtransf

! y-coordinate
       err=fillspline(RYgit,transf,dtransf)
         spliney  = transf
         dspliney = dtransf

! z-coordinate
       err=fillspline(RZgit,transf,dtransf)
         splinez  = transf
         dsplinez = dtransf

       xxo = floor (RXgit1 - this%splineorder)
       yyo = floor (RYgit1 - this%splineorder)
       zzo = floor (RZgit1 - this%splineorder)

       DO xi=1,order,1
         xxo = xxo + 1
         x = xxo
         if (x < 0) x = x + NX
         yo   = yyo
         DO yi=1,order,1
           yo = yo + 1
           y   = yo
           if (y < 0) y = y + NY
           zo  = zzo
           DO zi=1,order,1
             zo = zo + 1
             z  = zo
             if (z < 0) z = z + NZ
             index_loc = z + y*NZ + x*NY*NZ + 1
             qgrid_safe = this%qgrida(1,index_loc)
               strucx = strucx - dsplinex(xi)*spliney(yi)*splinez(zi)*qgrid_safe
               strucy = strucy - splinex(xi)*dspliney(yi)*splinez(zi)*qgrid_safe
               strucz = strucz - splinex(xi)*spliney(yi)*dsplinez(zi)*qgrid_safe
           END DO
         END DO
       END DO
!!!!!!!!!1



         FX =>  this%Component(i)%Molecule%SiteCharge(j)%FX(k)
         FY =>  this%Component(i)%Molecule%SiteCharge(j)%FY(k)
         FZ =>  this%Component(i)%Molecule%SiteCharge(j)%FZ(k)

         FXi = strucx*facx*q
         FYi = strucy*facy*q
         FZi = strucz*facz*q

         FX    = FX + FXi
         FY    = FY + FYi
         FZ    = FZ + FZi

         FXcum = FXcum + FXi
         FYcum = FYcum + FYi
         FZcum = FZcum + FZi

         VirLoc = VirLoc + FXi*(this%Component(i)%Molecule%SiteCharge(j)%RX(k) - &
&                 this%Component(i)%Molecule%SiteCharge(j)%PX(k))*this%BoxLength
         VirLoc = VirLoc + FYi*(this%Component(i)%Molecule%SiteCharge(j)%RY(k) - &
&                 this%Component(i)%Molecule%SiteCharge(j)%PY(k))*this%BoxLength
         VirLoc = VirLoc + FZi*(this%Component(i)%Molecule%SiteCharge(j)%RZ(k) - &
&                 this%Component(i)%Molecule%SiteCharge(j)%PZ(k))*this%BoxLength

       END DO
     END DO
   END DO

   DO i=1,this%NComponents
     DO j=1,this%Component(i)%Molecule%NCharge
       pm=>this%Component(i)%Molecule
       DO k=1,this%Component(i)%NPart
         pm%SiteCharge(j)%FX(k) = pm%SiteCharge(j)%FX(k) - FXcum/this%NPart
         pm%SiteCharge(j)%FY(k) = pm%SiteCharge(j)%FY(k) - FYcum/this%NPart
         pm%SiteCharge(j)%FZ(k) = pm%SiteCharge(j)%FZ(k) - FZcum/this%NPart
       END DO
     END DO
   END DO

   call TEnsemble_VirialIntra(this)
   this%EVirial = this%EVirial + VirLoc*Third

contains

!!!!!!!!!!!!!!!!!!
! Calculate Spline function and Derivative of the spline function
    real(RK) function fillspline(w,spline,dspline)

    implicit none
      real(RK),intent(in) ::  w
      real(RK),dimension(this%splineorder+5),intent(in out) ::  spline
      real(RK),dimension(this%splineorder+5),intent(in out) :: dspline


      real(RK)            :: div
      real(RK)            :: dj,di,dorder
      integer             :: i,j,order

      order = this%splineorder

! Calculate the single spline function contributions
      spline    = 0._RK
      dspline   = 0._RK


      spline(1) = 1._RK - w
      spline(2) = w

      DO i=3,order-1,1
        div = 1._RK / (i-1)
        spline(i) = div * w * spline(i-1)
        di = real(i)

! Second Contribution
         DO j=1,i-2,1
           dj = real(j)
           spline(i-j) = div * ((w+dj)*spline(i-j-1) + (di-dj-w)*spline(i-j))
         END DO
       spline(1) = spline(1) * div * (1._RK-w)
       END DO

! Differential of the spline function
    dspline(1) = -spline(1)
      DO i=2,order,1
        dspline(i) = spline(i-1) - spline(i)
      END DO

! Generate order spline derivative
    div = 1._RK / (order - 1._RK)
    spline(order) = div * w * spline(order-1)
    dorder = real(order)
    DO i=1,order-2,1
      di = real(i)
      spline(order- i) = div*((w+di)*spline(order-i-1) + (dorder-di-w)*spline(order-i))
    END DO

    spline(1) = spline(1) * div* (1._RK-w)

    end function fillspline



   end subroutine TEnsemble_PMEFourierTerm


   subroutine charge_grid(this)

   implicit none
   type(TEnsemble)    :: this

   real(RK)           :: boxl
   real(RK),dimension(this%splineorder+5) ::  transf
   real(RK),dimension(this%splineorder+5) :: dtransf
   real(RK),dimension(this%splineorder+5) ::  splinex
   real(RK),dimension(this%splineorder+5) :: dsplinex
   real(RK),dimension(this%splineorder+5) ::  spliney
   real(RK),dimension(this%splineorder+5) :: dspliney
   real(RK),dimension(this%splineorder+5) ::  splineZ
   real(RK),dimension(this%splineorder+5) :: dsplinez

   real(RK)           :: RX,RY,RZ
   real(RK)           :: RXgit ,RYgit, RZgit
   real(RK)           :: RXgit1,RYgit1,RZgit1
   real(RK)           :: q

   integer            :: xxo,yyo,zzo
   integer            :: yo,zo

   integer            :: i,j,k
   integer            :: xi,yi,zi
   integer            :: x,y,z
   integer            :: order
   integer            :: NX,NY,NZ
   integer            :: index_loc

   real(RK)           :: err
   real(RK)           :: fac


   this%qgrida = 0._RK

   NX = this%gridx
   NY = this%gridy
   NZ = this%gridz

   boxl  = this%BoxLength
   order = this%splineorder


! Dimensions of charge
   fac = UnitCharge / ElementaryCharge

   DO i=1,this%NComponents
     DO j=1,this%Component(i)%Molecule%NCharge
      DO k=1,this%Component(i)%NPart

       q  = this%Component(i)%Molecule%SiteCharge(j)%e
       RX = this%Component(i)%Molecule%SiteCharge(j)%RX(k)
       RY = this%Component(i)%Molecule%SiteCharge(j)%RY(k)
       RZ = this%Component(i)%Molecule%SiteCharge(j)%RZ(k)

       RX     = RX - anint(RX)
       RY     = RY - anint(RY)
       RZ     = RZ - anint(RZ)

       RXgit1 = this%gridx*(RX+0.5_RK)
       RYgit1 = this%gridy*(RY+0.5_RK)
       RZgit1 = this%gridz*(RZ+0.5_RK)

       RXgit = (RXgit1 - floor( RXgit1 ))
       RYgit = (RYgit1 - floor( RYgit1 ))
       RZgit = (RZgit1 - floor( RZgit1 ))

! x-coordinate
       err=fillspline(RXgit,transf,dtransf)
         splinex  = transf
         dsplinex = dtransf

! y-coordinate
       err=fillspline(RYgit,transf,dtransf)
         spliney  = transf
         dspliney = dtransf

! z-coordinate
       err=fillspline(RZgit,transf,dtransf)
         splinez  = transf
         dsplinez = dtransf

       xxo = floor (RXgit1 - this%splineorder)
       yyo = floor (RYgit1 - this%splineorder)
       zzo = floor (RZgit1 - this%splineorder)

       if (xxo > NX-1) xxo = NX-1
       if (yyo > NY-1) yyo = NY-1
       if (zzo > NZ-1) zzo = Nz-1

       DO xi=1,order,1
         xxo = xxo + 1
         x = xxo
         if (x < 0) x = x + NX
         yo   = yyo
         DO yi=1,order,1
           yo = yo + 1
           y   = yo
           if (y < 0) y = y + NY
           zo  = zzo
           DO zi=1,order,1
             zo = zo + 1
             z  = zo
             if (z < 0) z = z + NZ
             index_loc = z + y*NZ + x*NY*NZ + 1
             this%qgrida(1,index_loc) = this%qgrida(1,index_loc) + splinex(xi)*spliney(yi)*splinez(zi)*q*fac
           END DO
         END DO
       END DO

      END DO ! Particles
     END DO  ! Charges
   END DO ! Components


contains

!!!!!!!!!!!!!!!!!!
! Calculate Spline function and Derivative of the spline function
    real(RK) function fillspline(w,spline,dspline)

    implicit none
      real(RK),intent(in) ::  w
      real(RK),dimension(this%splineorder+5),intent(in out) ::  spline
      real(RK),dimension(this%splineorder+5),intent(in out) :: dspline


      real(RK)            :: div
      real(RK)            :: dj,di,dorder
      integer             :: i,j,order

      order = this%splineorder

! Calculate the single spline function contributions
      spline    = 0._RK
      dspline   = 0._RK


      spline(1) = 1._RK - w
      spline(2) = w

      DO i=3,order-1,1
        div = 1._RK / (i-1)
        spline(i) = div * w * spline(i-1)
        di = real(i)
! Second Contribution
         DO j=1,i-2,1
           dj = real(j)
           spline(i-j) = div * ((w+dj)*spline(i-j-1) + (di-dj-w)*spline(i-j))
         END DO
       spline(1) = spline(1) * div * (1._RK-w)
       END DO

! Differential of the spline function
    dspline(1) = -spline(1)
      DO i=2,order,1
        dspline(i) = spline(i-1) - spline(i)
      END DO

! Generate order spline derivative
    div = 1._RK / (order - 1._RK)
    spline(order) = div * w * spline(order-1)
    dorder = real(order)
    DO i=1,order-2,1
      di = real(i)
      spline(order- i) = div*((w+di)*spline(order-i-1) + (dorder-di-w)*spline(order-i))
    END DO
    spline(1) = spline(1) * div* (1._RK-w)

    end function fillspline

   end subroutine charge_grid



!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!
! SPME for MonteCarlo Simulations
!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!

  subroutine TEnsemble_PME_Setup ( this )

    implicit none

    include 'fftw3.f'
    ! Declare arguments
    type(TEnsemble)         :: this

    real(RK)::bspx(this%splineorder)
    real(RK)::bspy(this%splineorder)
    real(RK)::bspz(this%splineorder)
    real(RK)::err

    integer :: NX,NY,NZ
    integer :: i
    integer :: k1,k1bck,k2,k3,ngrid,ngridyz
    integer :: stat
    integer :: manhx,manhy,manhz

    NX = this%gridx
    NY = this%gridy
    NZ = this%gridz

    if (SimulationType .eq. MolecularDynamics) then
    call dfftw_plan_dft_3d(this%qgrid_forward,NX,NY,NZ,this%qgrida,this%qgrida,FFTW_FORWARD,FFTW_PATIENT)
    call dfftw_plan_dft_3d(this%qgrid_backward,NX,NY,NZ,this%qgrida,this%qgrida,FFTW_BACKWARD,FFTW_PATIENT)

    else if (SimulationType .eq. MonteCarlo .or. SimulationType .eq. Gibbs ) then
    call dfftw_plan_dft_3d(this%qgrid_backward,NX,NY,NZ,this%qgrida,this%qgridb,FFTW_BACKWARD,FFTW_PATIENT)
    end if

    err = pme_bspline(NX,NY,NZ)

! Self Term
    call PMESelfTermMC (this )


! Allocation of bbtot
    allocate(this%bbtot(NX*NY*NZ+1),STAT=stat)
    if(stat >0) write(*,*) 'Allocation Error bbtot'
    allocate(this%mm2(NX*NY*NZ+1),STAT=stat)
    if(stat >0) write(*,*) 'Allocation Error mm2'
    allocate(this%EPotPME(NX*NY*NZ+1),STAT=stat)
    if(stat >0) write(*,*) 'Allocation Error EPotPME'
    allocate(this%VirialPME(NX*NY*NZ+1),STAT=stat)
    if(stat >0) write(*,*) 'Allocation Error VirialPME'

! Preparation of bb
   ngrid   = NX*NY*NZ
   ngridyz = NY*NZ

   DO i=2,ngrid
     k1    = int((i-1) / ngridyz)
     k1bck = int((i-1) - k1*ngridyz)
     k2    = int(k1bck / NZ)
     k3    = int(k1bck - k2*NZ)

! Further specifications
     manhx = k1
     manhy = k2
     manhz = k3

     if (manhx > NX/2._RK) manhx = manhx - NX ! manhx = manhx - ANINT(manhx/NX)*NX
     if (manhy > NY/2._RK) manhy = manhy - NY! manhy = manhy - ANINT(manhx/NY)*NY
     if (manhz > NZ/2._RK) manhz = manhz - NZ! manhz = manhz - ANINT(manhx/NZ)*NZ

     this%mm2(i) = manhx*manhx + manhy*manhy + manhz*manhz

     this%bbtot(i)= this%bsp_modx(k1+1)*this%bsp_mody(k2+1)*this%bsp_modz(k3+1)*this%mm2(i)

   END DO

#if MPI_VER > 0
    this%NBox1 = ProcRange( ngrid, this%NBox0, this%NBox2 )
#endif


contains

!!!!!!!!!!!!!!!!!!!!
    real(RK) function pme_bspline(NX,NY,NZ)

    implicit none
    integer,intent(in) :: NX,NY,NZ

    real(RK)    :: w
    real(RK)    :: err
    real(RK),dimension(this%splineorder+5):: spline,dspline
    integer     :: ngrid

    w = 0.0_RK
    ngrid = max(NX,NY,NZ) + 1

! Fill the spline function
    err =  fillspline(w,spline,dspline)

! Initialize the bsp_arrays
    DO i=1,ngrid
      this%bsp_arr(i) = 0.0_RK
    END DO
    DO i=2,this%splineorder
      this%bsp_arr(i) = spline(i-1)
    END DO

    this%bsp_modx = pme_dftmod(NX)
    this%bsp_mody = pme_dftmod(NY)
    this%bsp_modZ = pme_dftmod(NZ)

    end function pme_bspline




    function pme_dftmod (grid) result(bmod)

    implicit none

    real(RK),dimension(this%gridx) :: bmod
    real(RK),pointer, contiguous :: barr(:)
    integer  :: grid

    real(RK) :: twopi
    real(RK) :: tinys
    real(RK) :: sum1,sum2
    real(RK) :: arg
    integer  :: i,j

    twopi = 2._RK*PI
    tinys = 1.0E-7;

    barr => this%bsp_arr
    DO i=1,grid,1
      sum1 = 0._RK
      sum2 = 0._RK
      DO j=1,grid,1
        arg = twopi * (i-1)*(j-1) / grid
        sum1 = sum1 + barr(j) * cos(arg)
        sum2 = sum2 + barr(j) * sin(arg)
      END DO
      bmod(i) = sum1*sum1 + sum2*sum2
    END DO

    end function pme_dftmod



!!!!!!!!!!!!!!!!!!
! Calculate Spline function and Derivative of the spline function
    real(RK) function fillspline(w,spline,dspline)

    implicit none
      real(RK),intent(in) :: w
      real(RK),dimension(this%splineorder+5),intent(in out) ::  spline
      real(RK),dimension(this%splineorder+5),intent(in out) :: dspline

      real(RK)            :: div
      real(RK)            :: dj,di,dorder
      integer             :: i,j,order

      order = this%splineorder

      spline    = 0._RK
      dspline   = 0._RK

! Calculate the single spline function contributions
      spline(1) = 1._RK - w
      spline(2) = w

      DO i=3,order-1,1
        div = 1._RK / (i-1)
        spline(i) = div * w * spline(i-1)
        di = real(i)

! Second Contribution
         DO j=1,i-2,1
           dj = real(j)
           spline(i-j) = div * ((w+dj)*spline(i-j-1) + (di-dj-w)*spline(i-j))
         END DO
       spline(1) = spline(1) * div * (1._RK-w)
       END DO

! Differential of the spline function
    dspline(1) = -spline(1)
      DO i=2,order,1
        dspline(i) = spline(i-1) - spline(i)
      END DO

! Generate order spline derivative
    div = 1._RK / (order - 1._RK)
    spline(order) = div * w * spline(order-1)
    dorder = real(order)
    DO i=1,order-2,1
      di = real(i)
      spline(order- i) = div*((w+di)*spline(order-i-1) + (dorder-di-w)*spline(order-i))
    END DO
    spline(1) = spline(1) * div* (1._RK-w)

    end function fillspline

  end subroutine TEnsemble_PME_Setup





  subroutine TEnsemble_PMESelfTerm_MC( this )

    implicit none

    ! Include MPI header
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif
    ! Declare arguments
    type(TEnsemble)         :: this

    ! Declare local variables
    integer :: i,Si,Sj
    real(RK):: USelbstTermKomp, VirialLocal
    real(RK):: Faktor, NSQ
    real(RK):: approx
    real(RK):: twopi
    real(RK):: UIntraTermKomp
    real(RK):: dr, drxij,dryij,drzij
    real(RK):: RXi,RYi,RZi,RXj,RYj,RZj
    real(RK):: q1,q2

! Selbstterm
    this%USelbstTerm = 0.0_RK
    DO i=1,this%NComponents,1
       USelbstTermKomp = 0.0_RK
       DO Si=1,this%Component(i)%Molecule%NCharge,1
         USelbstTermKomp = USelbstTermKomp + this%Component(i)%Molecule%SiteCharge(Si)%e**2
       END DO
       this%USelbstTerm = this%USelbstTerm + this%Component(i)%NPart * USelbstTermKomp
    END DO
    this%USelbstTerm = -this%USelbstTerm * this%Kappa / sqrt(Pi)


! Intramolecular
    this%UIntra = 0._RK
    DO i=1,this%NComponents,1
      UIntraTermKomp = 0.0_RK
      DO Si = 1,this%component(i)%Molecule%NCharge-1
        q1 = this%Component(i)%Molecule%SiteCharge(Si)%e
        DO Sj = Si+1,this%component(i)%Molecule%NCharge
          q2 = this%Component(i)%Molecule%SiteCharge(Sj)%e
          RXi  = this%Component(i)%Molecule%SiteCharge(Si)%r(1)
          RYi  = this%Component(i)%Molecule%SiteCharge(Si)%r(2)
          RZi  = this%Component(i)%Molecule%SiteCharge(Si)%r(3)
          RXj  = this%Component(i)%Molecule%SiteCharge(Sj)%r(1)
          RYj  = this%Component(i)%Molecule%SiteCharge(Sj)%r(2)
          RZj  = this%Component(i)%Molecule%SiteCharge(Sj)%r(3)

          drxij = (RXi-RXj)
          dryij = (RYi-RYj)
          drzij = (RZi-RZj)

          dr = sqrt(drxij*drxij + dryij*dryij + drzij*drzij)

          if (dr .ge. 0.0000001) then
            call ErrorApprox(this%interaction(i,i)%PotChargeCharge(Si,Sj), this%Kappa*dr, approx)

            UIntraTermKomp = UIntraTermKomp - this%Component(i)%Molecule%SiteCharge(Si)%e* &
&                            this%Component(i)%Molecule%SiteCharge(Sj)%e / dr * (1-approx)
          end if
        END DO
      END DO
      this%UIntra = this%UIntra + this%component(i)%NPart * UIntraTermKomp
    END DO


    end subroutine TEnsemble_PMESelfTerm_MC



!==============================================================!
!  Subroutine TEnsemble_PME_FourierTerm MonteCarlo             !
!==============================================================!

   subroutine TEnsemble_PMEFourierTerm_MC(this)

   implicit none

    include 'fftw3.f'
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif

   ! Declare arguments

! Factors
   real(RK):: fac2, fac2s
   real(RK):: factor
   real(RK):: fac
   real(RK):: mult
! Energy
   real(RK):: EPotLocal
   real(RK):: Viriallocal
   real(RK):: boxl,boxl2,vol
   real(RK):: eterm,wterm
   real(RK):: struc
   real(RK):: energ
!Pointers
   real(RK),pointer, contiguous::lad(:,:)
   real(RK):: qr,qi
!Positioning
   integer :: order
   integer :: NX,NY,NZ
   integer :: ngrid,ngridyz
   integer :: k1,k2,k3,k1bck
   integer :: m1,m2,m3
   integer :: index_loc

   integer :: i,j,k

   type(TEnsemble)   :: this



#if MPI_VER > 0
   integer:: i0,i1
#endif

! Factors
   boxl = this%boxlength
   boxl2= boxl**2
   vol  = boxl**3

! Spline factors
   order = this%splineorder
   NX    = this%gridx
   NY    = this%gridY
   NZ    = this%gridz

   ngrid   = NX*NY*NZ
   ngridyz = NY*NZ

! Dimensions of charge
   fac  = (PI/this%Kappa)**2 / boxl2
   fac2s= (ElementaryCharge / UnitCharge)
   fac2 = (fac2s)**2 / (PI*boxl)
   factor = 1._RK / (UnitLength/Angstroem)

! Backward Transformation of the chargegrid
   call dfftw_execute(this%qgrid_backward)

   lad => this%qgridb

   EPotLocal = 0._RK
   VirialLocal = 0._RK

! Summation over all the Energies
#if MPI_VER > 0
   i0 = this%NBox0
   i1 = this%NBox2
   DO i=i0,i1,1
#else
   DO i=2,ngrid
#endif
! Positioning
     k1    = int((i-1) / ngridyz)
     k1bck = int((i-1) - k1*ngridyz)
     k2    = int(k1bck / NZ)
     k3    = int(k1bck - k2*NZ)

     index_loc = k3 + k2*NZ + k1*ngridyz + 1

! Charge contribution
     qr = lad(1,index_loc)
     qi = lad(2,index_loc)
     struc = qr*qr + qi*qi

! Distance contribution
     mult  = fac*this%mm2(i)
     eterm = exp(-mult) / this%bbtot(i)

! Energy
     energ = eterm*struc
     EPotLocal = EPotLocal + energ
     VirialLocal = VirialLocal + energ*(1._RK - mult)
   END DO

   this%UFourier =  0.5*EPotLocal*fac2
   this%EVirial  = -0.5*VirialLocal*fac2*Third + this%EVirialIntra
! STOP
! ForwardTransformation of the chargegrid

   end subroutine TEnsemble_PMEFourierTerm_MC



   subroutine charge_grid_MCall(this)

   implicit none
   type(TEnsemble)    :: this

   real(RK)           :: boxl
   real(RK),dimension(this%splineorder+5) ::  transf
   real(RK),dimension(this%splineorder+5) ::  splinex
   real(RK),dimension(this%splineorder+5) ::  spliney
   real(RK),dimension(this%splineorder+5) ::  splineZ

   real(RK)           :: RX,RY,RZ
   real(RK)           :: RXgit ,RYgit, RZgit
   real(RK)           :: RXgit1,RYgit1,RZgit1
   real(RK)           :: q

   integer            :: xxo,yyo,zzo
   integer            :: yo,zo

   integer            :: i,j,k
   integer            :: xi,yi,zi
   integer            :: x,y,z
   integer            :: order
   integer            :: NX,NY,NZ
   integer            :: index_loc

   real(RK)           :: err
   real(RK)           :: fac

   this%qgrida = 0._RK

   NX = this%gridx
   NY = this%gridy
   NZ = this%gridz

   boxl  = this%BoxLength
   order = this%splineorder


! Dimensions of charge
   fac = UnitCharge / ElementaryCharge

   DO i=1,this%NComponents
     DO j=1,this%Component(i)%Molecule%NCharge
      DO k=1,this%Component(i)%NPart

       q  = this%Component(i)%Molecule%SiteCharge(j)%e
       RX = this%Component(i)%Molecule%SiteCharge(j)%RX(k)
       RY = this%Component(i)%Molecule%SiteCharge(j)%RY(k)
       RZ = this%Component(i)%Molecule%SiteCharge(j)%RZ(k)

       RX     = RX - anint(RX)
       RY     = RY - anint(RY)
       RZ     = RZ - anint(RZ)

       RXgit1 = this%gridx*(RX+0.5)
       RYgit1 = this%gridy*(RY+0.5)
       RZgit1 = this%gridz*(RZ+0.5)

       RXgit = (RXgit1 - floor( RXgit1 ))
       RYgit = (RYgit1 - floor( RYgit1 ))
       RZgit = (RZgit1 - floor( RZgit1 ))

! x-coordinate
       err=fillspline(RXgit,transf)
         splinex  = transf

! y-coordinate
       err=fillspline(RYgit,transf)
         spliney  = transf

! z-coordinate
       err=fillspline(RZgit,transf)
         splinez  = transf

       xxo = floor (RXgit1 - this%splineorder)
       yyo = floor (RYgit1 - this%splineorder)
       zzo = floor (RZgit1 - this%splineorder)

       if (xxo > NX-1) xxo = NX-1
       if (yyo > NY-1) yyo = NY-1
       if (zzo > NZ-1) zzo = Nz-1

       DO xi=1,order,1
         xxo = xxo + 1
         x = xxo
         if (x < 0) x = x + NX
         yo   = yyo
         DO yi=1,order,1
           yo = yo + 1
           y   = yo
           if (y < 0) y = y + NY
           zo  = zzo
           DO zi=1,order,1
             zo = zo + 1
             z  = zo
             if (z < 0) z = z + NZ
             index_loc = z + y*NZ + x*NY*NZ + 1
             this%qgrida(1,index_loc) = this%qgrida(1,index_loc) + splinex(xi)*spliney(yi)*splinez(zi)*q*fac
           END DO
         END DO
       END DO

      END DO ! Particles
     END DO  ! Charges
   END DO ! Components


contains

!!!!!!!!!!!!!!!!!!
! Calculate Spline function and Derivative of the spline function
    real(RK) function fillspline(w,spline)

    implicit none
      real(RK),intent(in) ::  w
      real(RK),dimension(this%splineorder+5),intent(in out) ::  spline


      real(RK)            :: div
      real(RK)            :: dj,di,dorder
      integer             :: i,j,order

      order = this%splineorder

! Calculate the single spline function contributions
      spline    = 0._RK


      spline(1) = 1._RK - w
      spline(2) = w

      DO i=3,order-1,1
        div = 1._RK / (i-1)
        spline(i) = div * w * spline(i-1)
        di = real(i)
! Second Contribution
         DO j=1,i-2,1
           dj = real(j)
           spline(i-j) = div * ((w+dj)*spline(i-j-1) + (di-dj-w)*spline(i-j))
         END DO
       spline(1) = spline(1) * div * (1._RK-w)
       END DO

! Generate order spline
    div = 1._RK / (order - 1._RK)
    spline(order) = div * w * spline(order-1)
    dorder = real(order)
    DO i=1,order-2,1
      di = real(i)
      spline(order- i) = div*((w+di)*spline(order-i-1) + (dorder-di-w)*spline(order-i))
    END DO
    spline(1) = spline(1) * div* (1._RK-w)

    end function fillspline

   end subroutine charge_grid_MCall



   subroutine TEnsemble_PMChargeGrid_plus(this,nc,np)

   implicit none
   type(TEnsemble)    :: this
   integer,intent(in) :: nc
   integer,intent(in) :: np


   real(RK)           :: boxl
   real(RK),dimension(this%splineorder+5) ::  transf
   real(RK),dimension(this%splineorder+5) ::  splinex
   real(RK),dimension(this%splineorder+5) ::  spliney
   real(RK),dimension(this%splineorder+5) ::  splinez

   real(RK)           :: RX,RY,RZ
   real(RK)           :: RXgit ,RYgit, RZgit
   real(RK)           :: RXgit1,RYgit1,RZgit1
   real(RK)           :: q

   integer            :: xxo,yyo,zzo
   integer            :: yo,zo

   integer            :: i,j,k
   integer            :: xi,yi,zi
   integer            :: x,y,z
   integer            :: order
   integer            :: NX,NY,NZ
   integer            :: index_loc

   real(RK)           :: err
   real(RK)           :: fac

   NX = this%gridx
   NY = this%gridy
   NZ = this%gridz

   boxl  = this%BoxLength
   order = this%splineorder

   fac = UnitCharge / ElementaryCharge

   DO j=1,this%Component(nc)%Molecule%NCharge

       q  = this%Component(nc)%Molecule%SiteCharge(j)%e
       RX = this%Component(nc)%Molecule%SiteCharge(j)%RX(np)
       RY = this%Component(nc)%Molecule%SiteCharge(j)%RY(np)
       RZ = this%Component(nc)%Molecule%SiteCharge(j)%RZ(np)

       RX     = RX - anint(RX)
       RY     = RY - anint(RY)
       RZ     = RZ - anint(RZ)

       RXgit1 = this%gridx*(RX+0.5_RK)
       RYgit1 = this%gridy*(RY+0.5_RK)
       RZgit1 = this%gridz*(RZ+0.5_RK)

       RXgit = (RXgit1 - floor( RXgit1 ))
       RYgit = (RYgit1 - floor( RYgit1 ))
       RZgit = (RZgit1 - floor( RZgit1 ))

! x-coordinate
       err=fillspline(RXgit,transf)
         splinex  = transf

! y-coordinate
       err=fillspline(RYgit,transf)
         spliney  = transf

! z-coordinate
       err=fillspline(RZgit,transf)
         splinez  = transf

       xxo = floor (RXgit1 - this%splineorder)
       yyo = floor (RYgit1 - this%splineorder)
       zzo = floor (RZgit1 - this%splineorder)

       if (xxo > NX-1) xxo = NX-1
       if (yyo > NY-1) yyo = NY-1
       if (zzo > NZ-1) zzo = Nz-1

       DO xi=1,order,1
         xxo = xxo + 1
         x = xxo
         if (x < 0) x = x + NX
         yo   = yyo
         DO yi=1,order,1
           yo = yo + 1
           y   = yo
           if (y < 0) y = y + NY
           zo  = zzo
           DO zi=1,order,1
             zo = zo + 1
             z  = zo
             if (z < 0) z = z + NZ
             index_loc = z + y*NZ + x*NY*NZ + 1
             this%qgrida(1,index_loc) = this%qgrida(1,index_loc) + splinex(xi)*spliney(yi)*splinez(zi)*q*fac
           END DO
         END DO
       END DO

     END DO  ! Charges


contains

!!!!!!!!!!!!!!!!!!
! Calculate Spline function and Derivative of the spline function
    real(RK) function fillspline(w,spline)

    implicit none
      real(RK),intent(in) ::  w
      real(RK),dimension(this%splineorder+5),intent(in out) ::  spline


      real(RK)            :: div
      real(RK)            :: dj,di,dorder
      integer             :: i,j,order

      order = this%splineorder

! Calculate the single spline function contributions
      spline    = 0._RK


      spline(1) = 1._RK - w
      spline(2) = w

      DO i=3,order-1,1
        div = 1._RK / (i-1)
        spline(i) = div * w * spline(i-1)
        di = real(i)
! Second Contribution
         DO j=1,i-2,1
           dj = real(j)
           spline(i-j) = div * ((w+dj)*spline(i-j-1) + (di-dj-w)*spline(i-j))
         END DO
       spline(1) = spline(1) * div * (1._RK-w)
       END DO

! Generate order spline
    div = 1._RK / (order - 1._RK)
    spline(order) = div * w * spline(order-1)
    dorder = real(order)
    DO i=1,order-2,1
      di = real(i)
      spline(order- i) = div*((w+di)*spline(order-i-1) + (dorder-di-w)*spline(order-i))
    END DO
    spline(1) = spline(1) * div* (1._RK-w)

    end function fillspline

   end subroutine TEnsemble_PMChargeGrid_plus



   subroutine TEnsemble_PMChargeGrid_min(this,nc,np)

   implicit none
   type(TEnsemble)    :: this
   integer,intent(in) :: nc
   integer,intent(in) :: np

   real(RK)           :: boxl
   real(RK),dimension(this%splineorder+5) ::  transf
   real(RK),dimension(this%splineorder+5) ::  splinex
   real(RK),dimension(this%splineorder+5) ::  spliney
   real(RK),dimension(this%splineorder+5) ::  splineZ

   real(RK)           :: RX,RY,RZ
   real(RK)           :: RXgit ,RYgit, RZgit
   real(RK)           :: RXgit1,RYgit1,RZgit1
   real(RK)           :: q

   integer            :: xxo,yyo,zzo
   integer            :: yo,zo

   integer            :: i,j,k
   integer            :: xi,yi,zi
   integer            :: x,y,z
   integer            :: order
   integer            :: NX,NY,NZ
   integer            :: index_loc

   real(RK)           :: err
   real(RK)           :: fac

   NX = this%gridx
   NY = this%gridy
   NZ = this%gridz

   boxl  = this%BoxLength
   order = this%splineorder

! Dimensions of charge
   fac = UnitCharge / ElementaryCharge

   DO j=1,this%Component(nc)%Molecule%NCharge

       q  = this%Component(nc)%Molecule%SiteCharge(j)%e
       RX = this%Component(nc)%Molecule%SiteCharge(j)%RX(np)
       RY = this%Component(nc)%Molecule%SiteCharge(j)%RY(np)
       RZ = this%Component(nc)%Molecule%SiteCharge(j)%RZ(np)

       RX     = RX - anint(RX)
       RY     = RY - anint(RY)
       RZ     = RZ - anint(RZ)

       RXgit1 = this%gridx*(RX+0.5_RK)
       RYgit1 = this%gridy*(RY+0.5_RK)
       RZgit1 = this%gridz*(RZ+0.5_RK)

       RXgit = (RXgit1 - floor( RXgit1 ))
       RYgit = (RYgit1 - floor( RYgit1 ))
       RZgit = (RZgit1 - floor( RZgit1 ))

! x-coordinate
       err=fillspline(RXgit,transf)
         splinex  = transf

! y-coordinate
       err=fillspline(RYgit,transf)
         spliney  = transf

! z-coordinate
       err=fillspline(RZgit,transf)
         splinez  = transf

       xxo = floor (RXgit1 - this%splineorder)
       yyo = floor (RYgit1 - this%splineorder)
       zzo = floor (RZgit1 - this%splineorder)

       if (xxo > NX-1) xxo = NX-1
       if (yyo > NY-1) yyo = NY-1
       if (zzo > NZ-1) zzo = Nz-1

       DO xi=1,order,1
         xxo = xxo + 1
         x = xxo
         if (x < 0) x = x + NX
         yo   = yyo
         DO yi=1,order,1
           yo = yo + 1
           y   = yo
           if (y < 0) y = y + NY
           zo  = zzo
           DO zi=1,order,1
             zo = zo + 1
             z  = zo
             if (z < 0) z = z + NZ
             index_loc = z + y*NZ + x*NY*NZ + 1
             this%qgrida(1,index_loc) = this%qgrida(1,index_loc) - splinex(xi)*spliney(yi)*splinez(zi)*q*fac
           END DO
         END DO
       END DO

     END DO  ! Charges


contains

!!!!!!!!!!!!!!!!!!
! Calculate Spline function and Derivative of the spline function
    real(RK) function fillspline(w,spline)

    implicit none
      real(RK),intent(in) ::  w
      real(RK),dimension(this%splineorder+5),intent(in out) ::  spline


      real(RK)            :: div
      real(RK)            :: dj,di,dorder
      integer             :: i,j,order

      order = this%splineorder

! Calculate the single spline function contributions
      spline    = 0._RK


      spline(1) = 1._RK - w
      spline(2) = w

      DO i=3,order-1,1
        div = 1._RK / (i-1)
        spline(i) = div * w * spline(i-1)
        di = real(i)
! Second Contribution
         DO j=1,i-2,1
           dj = real(j)
           spline(i-j) = div * ((w+dj)*spline(i-j-1) + (di-dj-w)*spline(i-j))
         END DO
       spline(1) = spline(1) * div * (1._RK-w)
       END DO

! Generate order spline
    div = 1._RK / (order - 1._RK)
    spline(order) = div * w * spline(order-1)
    dorder = real(order)
    DO i=1,order-2,1
      di = real(i)
      spline(order- i) = div*((w+di)*spline(order-i-1) + (dorder-di-w)*spline(order-i))
    END DO
    spline(1) = spline(1) * div* (1._RK-w)

    end function fillspline

   end subroutine TEnsemble_PMChargeGrid_min


   subroutine TEnsemble_VirialIntra(this)

   implicit none
   type(TEnsemble)            :: this
   type(TMolecule),pointer    :: pm

   integer  :: i,j,jj,k
   real(RK) :: RX,RY,RZ
   real(RK) :: PX,PY,PZ
   real(RK) :: dx,dy,dz,dr
   real(RK) :: ex,ey,ez
   real(RK) :: qj,qjj
   real(RK) :: virloc
   real(RK) :: Kappa
   real(RK) :: kapparij,approx
   real(RK) :: fij
   real(RK) :: Faktor

   virloc = 0._RK
   Kappa  = this%Kappa
   Faktor = 2._RK/sqrt(Pi) * Kappa


   DO i=1,this%NComponents
     pm => this%Component(i)%Molecule
     DO j=1,pm%NCharge
      qj = pm%SiteCharge(j)%e

      DO jj=1,j-1
       qjj = pm%SiteCharge(jj)%e
       DO k=1,this%Component(i)%NPart
         RX = pm%SiteCharge(j)%RX(k)
         RY = pm%SiteCharge(j)%RY(k)
         RZ = pm%SiteCharge(j)%RZ(k)

         PX = pm%SiteCharge(jj)%RX(k)
         PY = pm%SiteCharge(jj)%RY(k)
         PZ = pm%SiteCharge(jj)%RZ(k)

         dx = (RX-PX) * this%BoxLength
         dy = (RY-PY) * this%BoxLength
         dz = (RZ-PZ) * this%BoxLength

         dr = sqrt(dx**2 + dy**2 + dz**2)

         KappaRij = Kappa*dr
!          !TODO: Check if this should be changed to ErrorApprox
!          call erfc_approx(KappaRij,approx)
         !Michael: For SPME correct?
         if (dr .ge. 0.0000001) then
           call ErrorApprox(this%Interaction(i,i)%PotChargeCharge(j,jj), KappaRij, approx)
           Fij  = (qj*qjj/dr*(1._RK-approx) - Faktor*exp(-KappaRij**2)*qj*qjj) /dr
         else
           Fij  = (qj*qjj/dr - Faktor*exp(-KappaRij**2)*qj*qjj) /dr
         end if

         eX = dx / dr
         eY = dy / dr
         eZ = dz / dr


         Virloc = Virloc + Fij* (eX * dx + eY * dy + eZ * dz)
        END DO
      ENd DO

      DO jj=j+1,pm%NCharge
       qjj = pm%SiteCharge(jj)%e
       DO k=1,this%Component(i)%NPart
         RX = pm%SiteCharge(j)%RX(k)
         RY = pm%SiteCharge(j)%RY(k)
         RZ = pm%SiteCharge(j)%RZ(k)

         PX = pm%SiteCharge(jj)%RX(k)
         PY = pm%SiteCharge(jj)%RY(k)
         PZ = pm%SiteCharge(jj)%RZ(k)

         dx = (RX-PX) * this%BoxLength
         dy = (RY-PY) * this%BoxLength
         dz = (RZ-PZ) * this%BoxLength

         dr = sqrt(dx**2 + dy**2 + dz**2)

         KappaRij = Kappa*dr
!          !TODO: Check if this should be changed to ErrorApprox
!          call erfc_approx(KappaRij,approx)
         !Michael: For SPME correct?
         if (dr .ge. 0.0000001) then
           call ErrorApprox(this%Interaction(i,i)%PotChargeCharge(j,jj), KappaRij, approx)
           Fij  = (qj*qjj/dr*(1._RK-approx) - Faktor*exp(-KappaRij**2)*qj*qjj) /dr
         else
           Fij  = (qj*qjj/dr - Faktor*exp(-KappaRij**2)*qj*qjj) /dr
         end if

         eX = dx / dr
         eY = dy / dr
         eZ = dz / dr

         Virloc = Virloc + Fij* (eX * dx + eY * dy + eZ * dz)
        END DO
       END DO
     END DO
   END DO

   end subroutine TEnsemble_VirialIntra

#endif


! TRANSPORT ab hier
#if TRANS==1
!==============================================================!
!  Subroutine TEnsemble_CalCorrFun                             !
!==============================================================!

    subroutine TEnsemble_CalCorrFun( this )

    implicit none

    ! Include MPI header
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif

    ! Declare arguments
    type(TEnsemble) :: this
    ! Declare local variables
    integer  :: nmess, i, j, j0, j1, j2, k, l, s, CFTMP
    integer  :: CFindex, Mindex
    integer  :: NPart, NPart2, StepCorr
    integer  :: np, nc, np1, np2, ncomp2
    real(RK) :: qi, qj
    real(RK) :: sx(this%NComponents), sy(this%NComponents)
    real(RK) :: sz(this%NComponents)
    real(RK) :: SXindex(this%NComponents),SYindex(this%NComponents),SZindex(this%NComponents)
    real(RK) :: Sindex(this%NComponents,3), ss(this%NComponents,3)
    real(RK) :: KinERot(this%NPart)
    real(RK) :: BoxLength_dt,BoxLength_dt2
    real(RK) :: tempf(3), virf(3)
    real(RK) :: Mass
    real(RK), pointer, contiguous :: pFB(:,:), pFS(:,:), pFTC(:,:), pFRC(:,:)
    type(TComponent),pointer :: pc
    logical  :: EConductivity, Bulkviscosity, MolarEnthConduct
!   logical  :: Conductivity

    NPart  = this%NPart
    NPart2 = 2*this%NPart
    BoxLength_dt       =  this%BoxLength/TimeStep
    BoxLength_dt2      =  BoxLength_dt**2
  ! Conductivity = this%Conductivity
    EConductivity = this%EConductivity
    Bulkviscosity = this%Bulkviscosity
    MolarEnthConduct = this%MolarEnthConduct
    ncomp2 = this%NComponents*this%NComponents


    !Reduced correlation steps
    StepCorr = (Step + this%NStepCorr -1) / this%NStepCorr


    !Calculate matrix indexes
    Mindex = mod(StepCorr, this%NCorr )
    if (Mindex .eq. 0) then
      Mindex = this%NCorr
    end if

    KinERot(:) = 0._RK
    !Write transport properties Matrixes (root Processor)
    this%vsk(Mindex,  :) = 0._RK
    this%vsp(Mindex,  :) = 0._RK
    this%vbk(Mindex,  :) = 0._RK
    this%vbp(Mindex,  :) = 0._RK
    this%vckt(Mindex, :) = 0._RK
    this%vcpt(Mindex, :) = 0._RK
    this%vckr(Mindex, :) = 0._RK
    this%vcpr(Mindex, :) = 0._RK
    this%vcmt(Mindex, :) = 0._RK

    !Evaluate FTC and FRC components (parallel version)
    do i = 1, this%NComponents
      call ForceTransport( this%Component(i) )
    end do


  if (RootProc) then
    ! Loop Variable
    j0 = 0
    do i = 1, this%NComponents
      pc => this%Component(i)
      np   = pc%NPart
      Mass =  pc%Molecule%Mass
#if MPI_VER > 0
      pFB => this%Component(i)%FBAll(:,:)
      pFS => this%Component(i)%FSAll(:,:)
#else
      pFB => this%Component(i)%FB(:,:)
      pFS => this%Component(i)%FS(:,:)
#endif


        pFTC => this%Component(i)%FTC(:,:)
        pFRC => this%Component(i)%FRC(:,:)
        do j = 1, np
          if ( pc%Molecule%IsElongated ) then
            KinERot(j)= sum( pc%W0(j,1:3) * pc%W0(j,1:3) * pc%Molecule%MOI(1:3))*0.5_RK
          end if
        end do

      do k =1, 3
        ! Calculate sum of terms of the pressure tensor (kinetic and potential)
        this%vsp(Mindex, k)  = this%vsp(Mindex, k) + sum(pFS (:, k)) ! potential part off-diagonal elements of pressure tensor
        this%vbp(Mindex, k)  = this%vbp(Mindex, k) + sum(pFB (:, k)) ! potential part diagonal elements of the pressure tensor
        this%vbk(Mindex, k)  = this%vbk(Mindex, k) + pc%KinETranTotal(k)!kinetic part diagonal elements of the pressure tensor

        if (Bulkviscosity) then
          this%sc(k) = this%sc(k) + pc%KinETranTotal(k)
          this%sp(k) = this%sp(k) + sum(pFB(:, k))
        end if


 !      if (Conductivity) then
          this%vcpr(Mindex, k) = this%vcpr(Mindex, k) + sum(pFRC(:, k))  !Thermal conductivity for mixtures
          this%vcpt(Mindex, k) = this%vcpt(Mindex, k) + sum(pFTC(:, k))
          this%vckt(Mindex, k) = this%vckt(Mindex, k) + sum( pc%P1(:, k)*pc%KinEPart(:) )*0.5_RK*BoxLength_dt
          if (MolarEnthConduct) then
            this%vcmt(Mindex, k) = this%vcmt(Mindex, k) + pc%PartialMolarEnthalpy*sum(pc%P1(:, k))* BoxLength_dt
          end if
          if ( pc%Molecule%IsElongated ) then
            this%vckr(Mindex, k)= this%vckr(Mindex, k) + sum( pc%P1(:, k) * KinERot(:) ) *BoxLength_dt
          end if
        !end if
      end do !k =1, 3


      !Diffusion matrix a (velocity matrix)
      if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
         k=mod(Mindex,this%NSpanCF)
         if (k==0) k=this%NSpanCF
         ! Multiplikation mit BoxLength_dt erst nach der Integration
         this%A_SpanCF(j0+1:j0+np              , k) = pc%P1(1:np,1)
         this%A_SpanCF(j0+NPart+1 :j0+NPart +np, k) = pc%P1(1:np,2)
         this%A_SpanCF(j0+NPart2+1:j0+NPart2+np, k) = pc%P1(1:np,3)
      end if

      !kinetic parts of the stress and energy tensors
      ! shear off diagonal terms
      this%vsk(Mindex, 1) = this%vsk(Mindex,1) + sum( pc%P1(:,1) * pc%P1(:,2) ) * Mass*BoxLength_dt2
      this%vsk(Mindex, 2) = this%vsk(Mindex,2) + sum( pc%P1(:,1) * pc%P1(:,3) ) * Mass*BoxLength_dt2
      this%vsk(Mindex, 3) = this%vsk(Mindex,3) + sum( pc%P1(:,2) * pc%P1(:,3) ) * Mass*BoxLength_dt2

      if (TransMethod .eq. Einstein) then
         this%velcompX(i, Mindex) = sum (pc%P1(:,1))*BoxLength_dt
         this%velcompY(i, Mindex) = sum (pc%P1(:,2))*BoxLength_dt
         this%velcompZ(i, Mindex) = sum (pc%p1(:,3))*BoxLength_dt
      end if

      j0 = j0 + np
    end do    ! Component

    if (Bulkviscosity) then
      tempf(:)  = this%sc(:)/StepCorr
      virf(:)   = this%sp(:)/StepCorr
    end if


     !!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!
    ! Calculate Auto Correlation Functions      !
    !!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!


    if ( mod(StepCorr, this%NSpanCF) .eq. 0 ) then
      if (StepCorr .gt. this%NCorr) then

       CFindex = Mindex +1

       if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
         this%a(:,CFindex - this%NSpanCF:CFindex-1) = this%A_SpanCF(:,1:this%NSpanCF)
       end if

       if (Mindex .eq. this%NCorr) then
         CFindex = 1                       !index of t = t0
       end if

     ! nullify the autocorrelation functions
       if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
         do i = 1, this%NComponents
           this%cf_d(i, :) = 0._RK
         end do
         this%cf_vs(:) = 0._RK
       end if

       this%cf_c(:)  = 0._RK
       this%cf_vb(:) = 0._RK
       this%cf_ec(:) = 0._RK

       if (this%NComponents .gt. 1) then
         if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
           do k = 1, ncomp2
             this%lamda(k,:) = 0._RK
           end do
         end if
         do k = 1, this%NComponents
            this%cf_soret(k,:) = 0._RK
         end do
       end if


       ! Preparation of the Autocorrelation function - safe the Startpoints
        j0 = 0
        if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
          do i = 1, this%NComponents
            np = this%Component(i)%NPart
            SXindex(i)  = sum(this%a(j0       +1:j0+np        , CFindex))
            SYindex(i)  = sum(this%a(j0+NPart +1:j0+NPart +np , CFindex))
            SZindex(i)  = sum(this%a(j0+NPart2+1:j0+NPart2+np , CFindex))
            j0 = j0 + np
          end do

          do i = 1, this%NComponents
            Sindex(i,1)=SXindex(i)*BoxLength_dt  !mass flux for thermal diffusion
            Sindex(i,2)=SYindex(i)*BoxLength_dt
            Sindex(i,3)=SZindex(i)*BoxLength_dt
          end do
        end if

         if (TransMethod .eq. Einstein) then
           do i = 1, this%NComponents
             Sindex(i,1)=this%velcompX(i,CFindex)  !mass flux for thermal diffusion
             Sindex(i,2)=this%velcompY(i,CFindex)
             Sindex(i,3)=this%velcompZ(i,CFindex)
           end do
        end if


        ! Calculation of all transport properties
        ! s .. matrix index of the corresponding values
        ! s = CFindex    Has to be set inside of the loop for OMP parallelisation

        CFtmp=CFindex

! Directive inserted by Cray Reveal.  May be incomplete.
!$OMP  parallel do default(none)                                         &
!$OMP&   private (i,j,j0,j1,j2,k,l,nc,nmess,np,np1,np2,qi,qj,s)          &
!$OMP&   shared  (this,cfindex,econductivity,npart,npart2,sxindex,       &
!$OMP&            syindex,szindex,tempf,unitcharge,virf,CFtmp,           &
!$OMP&            BoxLength_dt,Sindex,Bulkviscosity, TransMethod)        &
!$OMP&   private (sx,sy,sz,ss)


      do nmess= 1, this%NCorr
         ! Loop over particles
        s=CFtmp+nmess-1
        if (s > this%NCorr) s = s-this%NCorr

        if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
          j0 = 0
          do i = 1, this%NComponents
            np = this%Component(i)%NPart
            this%cf_d(i, nmess) = this%cf_d(i, nmess) + DOT_PRODUCT( this%a(j0+1 : j0+np,CFindex) , &
&                                                       this%a(j0+1: j0+np,s) ) &
&                               + DOT_PRODUCT( this%a(j0+NPart +1 : j0+NPart +np,CFindex) , &
&                                                       this%a(j0+NPart +1 : j0+NPart +np,s) ) &
&                               + DOT_PRODUCT( this%a(j0+NPart2+1 : j0+NPart2+np,CFindex) , &
&                                                       this%a(j0+NPart2+1 : j0+NPart2+np,s) )

            if ( this%NComponents .gt. 1 ) then
              sx(i)  = sum(this%a(j0       +1:j0+np        , s))
              sy(i)  = sum(this%a(j0+NPart +1:j0+NPart +np , s))
              sz(i)  = sum(this%a(j0+NPart2+1:j0+NPart2+np , s))
            end if
            j0 = j0 + np
          end do

          do i = 1, this%NComponents
            ss(i,1) = sx(i)* BoxLength_dt
            ss(i,2) = sy(i)* BoxLength_dt
            ss(i,3) = sz(i)* BoxLength_dt
          end do
        end if

         if (TransMethod .eq. Einstein) then
           do i = 1, this%NComponents
             ss(i,1) = this%velcompX(i,s)
             ss(i,2) = this%velcompY(i,s)
             ss(i,3) = this%velcompZ(i,s)
          end do
        end if

        ! Just loops over components!
        if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
          if (this%NComponents .gt. 1) then
            nc = this%NComponents
            k = 1
            do i = 1, nc
              do j = 1,nc
                this%lamda(k, nmess) = this%lamda(k, nmess) + SXindex(i)*sx(j) &
&                                                           + SYindex(i)*sy(j) &
&                                                           + SZindex(i)*sz(j)
                k = k + 1
              end do
            end do
          end if
        end if

        ! Calculated in general
        do k = 1, 3
          ! shear viscosity (off-diagonal elements)
          if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
            this%cf_vs(nmess) = this%cf_vs(nmess) + this%vsk(CFindex, k)*this%vsk(s, k) + &
&                                                   this%vsp(CFindex, k)*this%vsp(s, k) + &
&                                                   this%vsk(CFindex, k)*this%vsp(s, k) + &
&                                                   this%vsp(CFindex, k)*this%vsk(s, k)
          end if

          ! bulk viscosity
          if (Bulkviscosity) then
            do j = 1, 3
              this%cf_vb(nmess) =   this%cf_vb(nmess) + &
&                               ( this%vbk(CFindex, j)-tempf(j))*(this%vbk(s, k)-tempf(k)) + &
&                               ( this%vbp(CFindex, j)-virf(j)) *(this%vbp(s, k)-virf(k) ) + &
&                               ( this%vbk(CFindex, j)-tempf(j))*(this%vbp(s, k)-virf(k) ) + &
&                               ( this%vbp(CFindex, j)-virf(j))*(this%vbk(s, k)-tempf(k) )
            end do
          end if

          ! conductivity
            this%cf_c(nmess) =  this%cf_c(nmess) + this%vckt(CFindex, k)*this%vckt(s, k) + &
&                                                  this%vckt(CFindex, k)*this%vcpt(s, k) + &
&                                                  this%vckt(CFindex, k)*this%vckr(s, k) + &
&                                                  this%vckt(CFindex, k)*this%vcpr(s, k) - &
&                                                  this%vckt(CFindex, k)*this%vcmt(s, k) + &
&                                                  this%vckr(CFindex, k)*this%vckt(s, k) + &
&                                                  this%vckr(CFindex, k)*this%vcpt(s, k) + &
&                                                  this%vckr(CFindex, k)*this%vckr(s, k) + &
&                                                  this%vckr(CFindex, k)*this%vcpr(s, k) - &
&                                                  this%vckr(CFindex, k)*this%vcmt(s, k) + &
&                                                  this%vcpt(CFindex, k)*this%vckt(s, k) + &
&                                                  this%vcpt(CFindex, k)*this%vcpt(s, k) + &
&                                                  this%vcpt(CFindex, k)*this%vckr(s, k) + &
&                                                  this%vcpt(CFindex, k)*this%vcpr(s, k) - &
&                                                  this%vcpt(CFindex, k)*this%vcmt(s, k) + &
&                                                  this%vcpr(CFindex, k)*this%vckt(s, k) + &
&                                                  this%vcpr(CFindex, k)*this%vcpt(s, k) + &
&                                                  this%vcpr(CFindex, k)*this%vckr(s, k) + &
&                                                  this%vcpr(CFindex, k)*this%vcpr(s, k) - &
&                                                  this%vcpr(CFindex, k)*this%vcmt(s, k) - &
&                                                  this%vcmt(CFindex, k)*this%vckt(s, k) - &
&                                                  this%vcmt(CFindex, k)*this%vcpt(s, k) - &
&                                                  this%vcmt(CFindex, k)*this%vckr(s, k) - &
&                                                  this%vcmt(CFindex, k)*this%vcpr(s, k) + &
&                                                  this%vcmt(CFindex, k)*this%vcmt(s, k)

        end do !k = 1, 3

        if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
        ! include the digonal elements to the shear viscosity (Pxx-Pyy)/2 and (Pyy-Pzz)/2
          this%cf_vs(nmess) = this%cf_vs(nmess) + (1._RK/4._RK)* ((this%vbk(CFindex, 1)-this%vbk(CFindex, 2))*(this%vbk(s, 1)-this%vbk(s, 2)) + &
&                                                                (this%vbp(CFindex, 1)-this%vbp(CFindex, 2))*(this%vbp(s, 1)-this%vbp(s, 2)) + &
&                                                                (this%vbk(CFindex, 1)-this%vbk(CFindex, 2))*(this%vbp(s, 1)-this%vbp(s, 2)) + &
&                                                                (this%vbp(CFindex, 1)-this%vbp(CFindex, 2))*(this%vbk(s, 1)-this%vbk(s, 2)) + &
&                                                                (this%vbk(CFindex, 2)-this%vbk(CFindex, 3))*(this%vbk(s, 2)-this%vbk(s, 3)) + &
&                                                                (this%vbp(CFindex, 2)-this%vbp(CFindex, 3))*(this%vbp(s, 2)-this%vbp(s, 3)) + &
&                                                                (this%vbk(CFindex, 2)-this%vbk(CFindex, 3))*(this%vbp(s, 2)-this%vbp(s, 3)) + &
&                                                                (this%vbp(CFindex, 2)-this%vbp(CFindex, 3))*(this%vbk(s, 2)-this%vbk(s, 3)))
         end if

         !Thermal diffusivity
         if (this%Ncomponents .gt. 1) then
           do j = 1, this%NComponents
             do k = 1, 3
               this%cf_soret(j, nmess) =  this%cf_soret(j, nmess) + this%vckt(CFindex, k)*ss(j,k) + &
&                                                                   this%vckr(CFindex, k)*ss(j,k) + &
&                                                                   this%vcpt(CFindex, k)*ss(j,k) + &
&                                                                   this%vcpr(CFindex, k)*ss(j,k) - &
&                                                                   this%vcmt(CFindex, k)*ss(j,k) + &
&                                                                   Sindex(j,k)*this%vckt(s, k) + &
&                                                                   Sindex(j,k)*this%vckr(s, k) + &
&                                                                   Sindex(j,k)*this%vcpt(s, k) + &
&                                                                   Sindex(j,k)*this%vcpr(s, k) - &
&                                                                   Sindex(j,k)*this%vcmt(s, k)
             end do
           end do
         end if

        ! electric conductivity
        if (EConductivity) then
           j1 = 0
           do k = 1, this%NComponents
              np1 = this%Component(k)%NPart
              if( abs(this%Component(k)%Molecule%Charge) .gt. 1e-7) then !Electric conductivity only defined for charged particles
!             if((this%Component(k)%Molecule%Charge) .ne. 0._RK) then !Electric conductivity only defined for charged particles
                 qi = this%Component(k)%Molecule%Charge*UnitCharge/ElementaryCharge
                 do i = 1, np1
                    j2 = 0
                    do l = 1, this%NComponents
                       np2 = this%Component(l)%NPart
                       if( abs(this%Component(l)%Molecule%Charge) .gt. 1e-7) then !Electric conductivity only defined for charged particles
                           qj = this%Component(l)%Molecule%Charge*UnitCharge/ElementaryCharge
                           do j = 1, np2
                              this%cf_ec(nmess) = this%cf_ec(nmess) + qi * qj * this%a(j1+i, CFindex) * this%a(j2+j, s)
                              this%cf_ec(nmess) = this%cf_ec(nmess) + qi * qj * this%a(j1+NPart+i, CFindex) * this%a(j2+NPart+j, s)
                              this%cf_ec(nmess) = this%cf_ec(nmess) + qi * qj * this%a(j1+NPart2+i, CFindex) * this%a(j2+NPart2+j, s)
                           end do
                       endif
                       j2 = j2 + np2
                    end do
                 end do
              endif
              j1 = j1 + np1
           end do
        end if !if(EConductivity)

!mn        if (s == this%NCorr) s = 0
!mn        s = s+1

      end do  ! NMess
      this%Mmess  = this%Mmess +1

      if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
        do i = 1, this%NComponents
          this%average_cf_d(i, :) = (this%average_cf_d(i,:) + this%cf_d(i,:))
        end do
        this%average_cf_vs(:)= (this%average_cf_vs(:) + this%cf_vs(:))
      end if
      this%average_cf_vb(:)= (this%average_cf_vb(:) + this%cf_vb(:))
      this%average_cf_c(:) = (this%average_cf_c(:) + this%cf_c(:))
      this%average_cf_ec(:)= (this%average_cf_ec(:) + this%cf_ec(:))

      if (this%NComponents .gt. 1) then
        do k = 1, this%NComponents
          this%average_cf_soret(k,:)= (this%average_cf_soret(k,:) + this%cf_soret(k,:))
        end do
        if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
          do k = 1, ncomp2
            this%average_lamda(k,:) = (this%average_lamda(k,:) + this%lamda(k,:))
          end do
        end if
      end if


      ! Call integration for ACF
      call IntCorrFun ( this )

! -----------------------------------
     else ! if (Step .gt. this%NCorr)
        CFindex = Mindex +1
        if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
          this%a(:,CFindex - this%NSpanCF:CFindex-1) = this%A_SpanCF(:,1:this%NSpanCF)
        end if
     end if ! if (Step .gt. this%NCorr)
    end if ! if (mod(Step, this%NSpanCF).eq.0)

 end if ! RootProc
   end subroutine TEnsemble_CalCorrFun
#endif

#if TRANS==1
!==============================================================!
!  Subroutine TEnsemble_IntCorrFun                             !
!==============================================================!

  subroutine TEnsemble_IntCorrFun( this )

    implicit none

    ! Declare arguments
    type(TEnsemble) :: this
    ! Declare local varibles
    integer  :: i, j, k
    integer  :: ncomp2
    real(RK) :: helpvar
    real(RK) :: x1, x2, x3
    real(RK) :: BoxLength_dt2

    BoxLength_dt2      =  (this%BoxLength/TimeStep)**2
    ncomp2 = this%NComponents*this%NComponents

    if ((TransMethod .eq. GreenKubo) .or. (TransMethod .eq. GKEinstein)) then
       !Self-diffusion coefficients
      do i  = 1, this%NComponents
        helpvar =  1._RK /(3._RK *this%Component(i)%NPart) * BoxLength_dt2
        if (abs(this%cf_d(i, 1)) .gt. 1e-15) then
           this%sinte_i(i,:) = simpson( this%cf_d(i,:)/this%cf_d(i, 1), this%TimeStepCorr, this%NCorr )
           this%average_sinte_i(i,:) = simpson( this%average_cf_d(i,:)/this%average_cf_d(i, 1),this%TimeStepCorr, this%NCorr )
           this%average_sinte_i(i,:) = this%average_sinte_i(i,:)*this%average_cf_d(i, 1)*helpvar/this%Mmess
           this%selfd_i(i) = this%sinte_i(i, this%NCorr) * this%cf_d(i, 1) * helpvar
        end if
      end do

      !Onsager Coefficients
      if ( this%NComponents .gt. 1) then
        helpvar =  Third /(this%NPart) * BoxLength_dt2
        do k = 1, ncomp2
          if (abs(this%lamda(k, 1)) .gt. 1e-15) then
             this%sinte_lamda(k, :) = simpson(this%lamda(k,:)/this%lamda(k,1),this%TimeStepCorr, this%NCorr)
             this%average_sinte_lamda(k,:) = simpson(this%average_lamda(k,:)/this%average_lamda(k,1),this%TimeStepCorr, this%NCorr)
             this%average_sinte_lamda(k,:) = this%average_sinte_lamda(k,:)* this%average_lamda(k,1)*helpvar/this%Mmess
          end if
        end do

        k = 1
        do i = 1, this%NComponents
          do j = 1, this%NComponents
             this%Onsager(i,j) = this%sinte_lamda(k,this%NCorr)*this%lamda(k,1)*helpvar
             k = k +1
          end do
        end do
      end if

      !shear Viscosity
      helpvar =  this%Density /(5._RK *this%NPart * this%Temperature)
      this%sinte_vs = simpson( this%cf_vs(:)/this%cf_vs(1), this%TimeStepCorr, this%NCorr )
      this%average_sinte_vs = simpson( this%average_cf_vs(:)/this%average_cf_vs(1), this%TimeStepCorr, this%NCorr)
      this%average_sinte_vs = this%average_sinte_vs(:)*this%average_cf_vs(1)*helpvar/this%Mmess
      this%visco_s = this%sinte_vs( this%NCorr ) * this%cf_vs(1) * helpvar
    end if

    helpvar =  this%Density*Ninth/(this%NPart * this%Temperature)
    if (this%Bulkviscosity) then
      this%sinte_vb = simpson( this%cf_vb(:)/this%cf_vb(1),this%TimeStepCorr, this%NCorr )
      this%average_sinte_vb = simpson( this%average_cf_vb(:)/this%average_cf_vb(1),this%TimeStepCorr, this%NCorr)
      this%average_sinte_vb = this%average_sinte_vb(:)*this%average_cf_vb(1)*helpvar/this%Mmess
      this%visco_b = this%sinte_vb( this%NCorr ) * this%cf_vb(1) * helpvar
    end if

    helpvar = this%Density*Third/this%NPart
    if (abs(this%cf_c(1)) .gt. 1e-15) then
      this%sinte_c = simpson( this%cf_c(:)/this%cf_c(1), this%TimeStepCorr, this%NCorr )
      this%average_sinte_c = simpson( this%average_cf_c(:)/this%average_cf_c(1),this%TimeStepCorr, this%NCorr)
      this%average_sinte_c = this%average_sinte_c(:)*this%average_cf_c(1)*(helpvar/this%Mmess)
      this%conduct = this%sinte_c( this%NCorr ) * this%cf_c(1) * helpvar
    end if

    if ( this%NComponents .gt. 1 ) then
      do k = 1, this%NComponents
        if (abs(this%cf_soret(k,1)) .gt. 1e-15) then
           this%sinte_soret(k,:) = simpson (this%cf_soret(k,:)/this%cf_soret(k,1), this%TimeStepCorr, this%NCorr )
           this%average_sinte_soret(k,:) = simpson (this%average_cf_soret(k,:)/this%average_cf_soret(k,1), this%TimeStepCorr, this%NCorr)
           this%average_sinte_soret(k,:) = this%average_sinte_soret(k,:)*this%average_cf_soret(k,1)*helpvar*this%Component(k)%Molecule%Mass/(2._RK*this%Mmess)
           this%soret(k) =  this%sinte_soret(k, this%NCorr)*this%cf_soret(k,1)*this%Component(k)%Molecule%Mass*helpvar/2._RK
         end if
       end do
    end if

    helpvar = this%Density*Third /(this%NPart * this%Temperature)
    if (this%EConductivity) then
      this%sinte_ec = simpson( this%cf_ec(:)/this%cf_ec(1), this%TimeStepCorr, this%NCorr )
      this%average_sinte_ec = simpson( this%average_cf_ec(:)/this%average_cf_ec(1),this%TimeStepCorr, this%NCorr)
      this%average_sinte_ec = this%average_sinte_ec(:)*this%average_cf_ec(1)*(helpvar * BoxLength_dt2/this%Mmess)
      this%econduct = this%sinte_ec( this%NCorr ) * this%cf_ec(1) * (helpvar * BoxLength_dt2)
    end if

  contains

    function trapezoid(values, step, n) result(integral)

      ! Declare arguments
      real(RK), intent(in) :: values(:), step
      integer, intent(in)  :: n

      ! Declare result
      real(RK) :: integral(n)

      ! Declare local variables
      integer :: i

      ! Return if no values to integrate
      if( n < 1 ) return

      ! Initialize result
      integral = 0._RK


      ! Calculate integral via trapezoid method
      do i = 2, n
        integral(i) = integral(i-1) + values(i) + values(i-1)
      end do
      integral = integral * .5_RK * step

    end function



    function simpson(values, step, n) result(integral)

      ! Declare arguments
      real(RK), intent(in) :: values(:), step
      integer, intent(in)  :: n

      ! Declare result
      real(RK) :: integral(n)

      ! Declare local variables
      integer :: i

      ! Return if no values to integrate
      if( n < 1 ) return

      ! Initialize result
      integral = 0._RK

      ! Calculate integral via Simpson's rule
      do i = 3, n, 2
        integral(i) = integral(i-2) + values(i) + 4._RK * values(i-1) + values(i-2)
        integral(i-1) = .5_RK * (integral(i) + integral(i-2))
      end do

      if( mod(n, 2) == 0 .and. n > 2 ) integral(n) = integral(n-1) + .5_RK * values(n) + 2._RK * values(n-1) + .5_RK * values(n-2)
      integral = integral * step / 3._RK


    end function

  end subroutine TEnsemble_IntCorrFun
#endif


#if HBOND > 0
!==============================================================!
!  Subroutine TEnsemble_HBonding                               !
!==============================================================!

  subroutine TEnsemble_HBonding( this )

    implicit none

    ! Include MPI header
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif
    ! Declare arguments
    type(TEnsemble) :: this

    ! Declare local variables
    type(TComponent), pointer :: pacc, pdon
    type(TSiteCharge), pointer :: paccacc, pdonacc, pmixdon
    logical             :: MixTerm
    integer             :: h, i, i0, i1, j, k ,l, m, n
    real(RK)            :: BoxLengthInv
    real(RK)            :: LAA, LAD, LintraAD, CosAngle
    real(RK)            :: AngleCrit, DistCrit1, DistCrit2
    real(RK)            :: PXij, PYij, PZij
    real(RK)            :: drAA(3), drAD(3), drintraAD(3)
    integer,allocatable :: Counter(:,:), NHBAll(:)

    ! Initialize arrays
    this%NHBond0(:)         = 0
    this%NHBond1(:,:)       = 0
    this%NHBond2(:,:,:)     = 0
    this%NHBond3(:,:,:,:)   = 0
    this%NHBond4(:,:,:,:,:) = 0
    this%NHBondN(:)         = 0

    allocate( Counter(this%NComponents,this%NPart) )
    Counter(:,:) = 0
    allocate( NHBAll(this%NComponents) )
    NHBAll(:) = 0
    BoxLengthInv = 1._RK / this%BoxLength

    do h = 1, this%NHBondCrit

      !HBonding criteria
      DistCrit1 = this%DistCrit1(h)*BoxLengthInv
      DistCrit2 = this%DistCrit2(h)*BoxLengthInv
      AngleCrit = this%AngleCrit(h)

      !Definition of the H-Bonding components and sites
      pacc => this%Component(this%AccComp(h))
      pdon => this%Component(this%DonComp(h))

      paccacc => this%Component(this%AccComp(h))%Molecule%SiteCharge(this%AccAccSite(h))
      pdonacc => this%Component(this%DonComp(h))%Molecule%SiteCharge(this%DonAccSite(h))
      if ( this%AccDonSite(h) > 0 ) then
        pmixdon => this%Component(this%AccComp(h))%Molecule%SiteCharge(this%AccDonSite(h))
        MixTerm =.true.
      else
        pmixdon => this%Component(this%DonComp(h))%Molecule%SiteCharge(this%DonDonSite(h))
        MixTerm = .false.
      end if

      i0 = 1
      i1 = pacc%NPart
#if MPI_VER > 0
      if (SimulationType .eq. MolecularDynamics) then
        i0 = pacc%NPart0
        i1 = pacc%NPart2
      end if
#endif
      !Loop over all particles
      do i = i0, i1

        do j = 1,pdon%NPart

          !Minimum Image Convention
          PXij = pacc%P0(i, 1) - pdon%P0(j, 1)
          PYij = pacc%P0(i, 2) - pdon%P0(j, 2)
          PZij = pacc%P0(i, 3) - pdon%P0(j, 3)

          !Calculation of the distance vector Acc of AccComp and Acc of DonComp
          drAA(1)=(paccacc%RX(i)-pdonacc%RX(j)) - anint( PXij )
          drAA(2)=(paccacc%RY(i)-pdonacc%RY(j)) - anint( PYij )
          drAA(3)=(paccacc%RZ(i)-pdonacc%RZ(j)) - anint( PZij )
          LAA = SQRT( DOT_PRODUCT(drAA,drAA) )

          if (LAA .le. DistCrit1)then
            !Calculation of the distance vector Don of one Comp and  Acc of the other Comp
            if (MixTerm) then
              drAD(1)=(pmixdon%RX(i)-pdonacc%RX(j)) - anint( PXij )
              drAD(2)=(pmixdon%RY(i)-pdonacc%RY(j)) - anint( PYij )
              drAD(3)=(pmixdon%RZ(i)-pdonacc%RZ(j)) - anint( PZij )
            else
              drAD(1)=(paccacc%RX(i)-pmixdon%RX(j)) - anint( PXij )
              drAD(2)=(paccacc%RY(i)-pmixdon%RY(j)) - anint( PYij )
              drAD(3)=(paccacc%RZ(i)-pmixdon%RZ(j)) - anint( PZij )
            end if
            !Hier die Minimum Image-Convention
            LAD = SQRT( DOT_PRODUCT(drAD,drAD) )

            if (LAD .le. DistCrit2) then
              !Calculation of the angle between donor and acceptors
              if (MixTerm) then
                drintraAD(1)=pmixdon%RX(i)-paccacc%RX(i)
                drintraAD(2)=pmixdon%RY(i)-paccacc%RY(i)
                drintraAD(3)=pmixdon%RZ(i)-paccacc%RZ(i)
              else
                drintraAD(1)=pmixdon%RX(j)-pdonacc%RX(j)
                drintraAD(2)=pmixdon%RY(j)-pdonacc%RY(j)
                drintraAD(3)=pmixdon%RZ(j)-pdonacc%RZ(j)
              end if
              LintraAD = SQRT( DOT_PRODUCT(drintraAD,drintraAD) )
              CosAngle=abs( DOT_PRODUCT(drAA,drintraAD) / LAA / LintraAD )

              if (CosAngle .ge. AngleCrit) then
                ! not working for more than 99 species
                if ( Counter(this%AccComp(h),i) == 0 ) then
                  Counter(this%AccComp(h),i) = this%DonComp(h)
                elseif ( Counter(this%AccComp(h),i) < 100 ) then
                  Counter(this%AccComp(h),i) = Counter(this%AccComp(h),i) + this%DonComp(h)*100
                elseif ( Counter(this%AccComp(h),i) < 10000 ) then
                  Counter(this%AccComp(h),i) = Counter(this%AccComp(h),i) + this%DonComp(h)*10000
                elseif ( Counter(this%AccComp(h),i) < 1000000 ) then
                  Counter(this%AccComp(h),i) = Counter(this%AccComp(h),i) + this%DonComp(h)*1000000
                else
                  Counter(this%AccComp(h),i) = 100000000
                end if
              end if

            end if

          end if

        end do !do j=1,npDon
      end do !do i=1,npAcc
    end do ! NHBondCrit

    !HBonding statistics
    do h = 1, this%NComponents
      i0 = 1
      i1 = this%Component(h)%NPart
#if MPI_VER > 0
      if (SimulationType .eq. MolecularDynamics) then
        i0 = this%Component(h)%NPart0
        i1 = this%Component(h)%NPart2
      end if
#endif
      do i = i0, i1
        m = 0
        if ( Counter(h,i) == 0 ) then
          this%NHBond0(h)=this%NHBond0(h) + 1
        elseif ( Counter(h,i) == 100000000 ) then
          this%NHBondN(h)=this%NHBondN(h) + 1
        elseif ( Counter(h,i) < 100 ) then
          do while (Counter(h,i) > 0 )
            m = m + 1
            Counter(h,i) = Counter(h,i) - 1
          end do
          j = m
          this%NHBond1(h,j)=this%NHBond1(h,j) + 1
        elseif ( Counter(h,i) < 10000 ) then
          do while (Counter(h,i) > 100 )
            m = m + 1
            Counter(h,i) = Counter(h,i) - 100
          end do
          j = m
          m = 0
          do while (Counter(h,i) > 0 )
            m = m + 1
            Counter(h,i) = Counter(h,i) - 1
          end do
          if (j .le. m) then
            k = m
          else
            k = j
            j = m
          end if
          this%NHBond2(h,j,k)=this%NHBond2(h,j,k) + 1
        elseif (Counter(h,i) < 1000000 ) then
          do while (Counter(h,i) > 10000 )
            m = m + 1
            Counter(h,i) = Counter(h,i) - 10000
          end do
          j = m
          m = 0
          do while (Counter(h,i) > 100 )
            m = m + 1
            Counter(h,i) = Counter(h,i) - 100
          end do
          if (j .le. m) then
            k = m
          else
            k = j
            j = m
          end if
          m = 0
          do while (Counter(h,i) > 0 )
            m = m + 1
            Counter(h,i) = Counter(h,i) - 1
          end do
          if (k .le. m) then
            l = m
          else
            l = k
            if (j .le. m) then
              k = m
            else
              k = j
              j = m
            end if
          end if
          this%NHBond3(h,j,k,l)=this%NHBond3(h,j,k,l) + 1
        else
          do while (Counter(h,i) > 1000000 )
            m = m + 1
            Counter(h,i) = Counter(h,i) - 1000000
          end do
          j = m
          m = 0
          do while (Counter(h,i) > 10000 )
            m = m + 1
            Counter(h,i) = Counter(h,i) - 10000
          end do
          if (j .le. m) then
            k = m
          else
            k = j
            j = m
          end if
          m = 0
          do while (Counter(h,i) > 100 )
            m = m + 1
            Counter(h,i) = Counter(h,i) - 100
          end do
          if (k .le. m) then
            l = m
          else
            l = k
            if (j .le. m) then
              k = m
            else
              k = j
              j = m
            end if
          end if
          m = 0
          do while (Counter(h,i) > 0 )
            m = m + 1
            Counter(h,i) = Counter(h,i) - 1
          end do
          if (l .le. m) then
            n = m
          else
            n = l
            if (k .le. m) then
              l = m
            else
              l = k
              if (j .le. m) then
                k = m
              else
                k = j
                j = m
              end if
            end if
          end if
          this%NHBond4(h,j,k,l,n)=this%NHBond4(h,j,k,l,n) + 1
        end if

      end do
    end do

#if MPI_VER > 0
    if (SimulationType .eq. MolecularDynamics) then
      call MPI_Reduce( this%NHBond0(:), NHBAll(:), this%NComponents, MPI_INTEGER, MPI_SUM, NRootProc, Communicator, ierror )
      if (RootProc) this%NHBond0(:) = NHBAll(:)
      do j = 1, this%NComponents
        call MPI_Reduce( this%NHBond1(:,j), NHBAll(:), this%NComponents, MPI_INTEGER, MPI_SUM, NRootProc, Communicator, ierror )
        if (RootProc) this%NHBond1(:,j) = NHBAll(:)
        do k = j, this%NComponents
          call MPI_Reduce( this%NHBond2(:,j,k), NHBAll(:), this%NComponents, MPI_INTEGER, MPI_SUM, NRootProc, Communicator, ierror )
          if (RootProc) this%NHBond2(:,j,k) = NHBAll(:)
          do l = k, this%NComponents
            call MPI_Reduce( this%NHBond3(:,j,k,l), NHBAll(:), this%NComponents, MPI_INTEGER, MPI_SUM, NRootProc, Communicator, ierror )
            if (RootProc) this%NHBond3(:,j,k,l) = NHBAll(:)
            do n = l, this%NComponents
              call MPI_Reduce( this%NHBond4(:,j,k,l,n), NHBAll(:), this%NComponents, MPI_INTEGER, MPI_SUM, NRootProc, Communicator, ierror )
              if (RootProc) this%NHBond4(:,j,k,l,n) = NHBAll(:)
            end do
          end do
        end do
      end do
      call MPI_Reduce( this%NHBondN(:), NHBAll(:), this%NComponents, MPI_INTEGER, MPI_SUM, NRootProc, Communicator, ierror )
      if (RootProc) this%NHBondN(:) = NHBAll(:)
    end if
#endif
    !this%NHBondN(1)=this%NPart-this%NHBond0(1)-this%NHBond1(1,1)-this%NHBond2(1,1,1)-this%NHBond3(1,1,1,1)-this%NHBond4(1,1,1,1,1)

!      !Output of the H-bonded Molecules
!      if( (StepTotal > 1) .and. (mod( StepTotal - 1, VisualUpdateFrequency ) == 0) ) then
!        call VisualUpdate( this, np, MH(:), MO(:,:) )
!      endif

  end subroutine TEnsemble_HBonding
#endif

!==============================================================!
!  Subroutine clust crit helpers                               !
!==============================================================!

  subroutine TEnsemble_count_direct_atom3(this, NeighborCounter, pcur, DistCrit)
    ! this is a helper function that supply the regular counting method
    ! counting is performed from grid to each atom
    ! BEWARE the NEW_YORK metric is used as distance check

    implicit none
    ! Declare arguments
    type(TEnsemble), intent(in) :: this
    integer                     :: NeighborCounter(:) !DC NOTE- could be made global to save reallocation
    type(TComponent), pointer   :: pcur
    real(RK), intent(in)        :: DistCrit !DC NOTE- calculated critical distance for neighbour memebrship
    ! Declare local variables
    integer                     :: i, i_x, i_y, i_z, j  !DC NOTE- loop counters
    integer                     :: x_edge, y_edge, z_edge !DC NOTE- indicators if element is in edge of particular direction
    integer                     :: x_ind, y_ind, z_ind !DC NOTE- the idexes of cell the atom is inside
    integer                     :: xyz_ind !DC NOTE- the index into flattened NeihbourCounter array
    real(RK)                    :: grid_center, rim_radius
    integer                     :: x_min,x_max,y_min,y_max,z_min,z_max

    grid_center = (this%NGridPoints-1)*DistCrit/2.0 - 0.5 !DC NOTE- convert to -0.5,0.5 coords
    rim_radius = 0.5 - DistCrit - grid_center !DC NOTE- rim radius distance is box_length - DistCrit - grid_center in 0,1 coords

    !DC NOTE- Loop over all grid points in the considered parallel context
    do i = 1, this%NGridPoints1
      NeighborCounter(i) = 0 !DC NOTE- re/initialisation of the Neighbor counter
    end do

    do j = 1, pcur%NPart
      x_edge = int((pcur%P0(j, 1) - grid_center)/rim_radius)
      y_edge = int((pcur%P0(j, 2) - grid_center)/rim_radius)
      z_edge = int((pcur%P0(j, 3) - grid_center)/rim_radius)

      x_ind = floor( (0.5_RK + pcur%P0(j, 1))/DistCrit )
      y_ind = floor( (0.5_RK + pcur%P0(j, 2))/DistCrit )
      z_ind = floor( (0.5_RK + pcur%P0(j, 3))/DistCrit )

      !DC DEBUG- message below help with bug hunt in counitng method
      ! write( IOBuffer, '("DEBUG da3:",I4," edge:",3I3," ind:",3I3)')j, x_edge,y_edge,z_edge, x_ind,y_ind,z_ind
      ! call LogWrite

      if (x_ind < x_ind+x_edge) then
        x_min = x_ind
        x_max = x_ind+(this%NGridPoints-x_ind)
      else
        x_min = x_ind+x_edge
        x_max = x_ind+1
      end if

      if (y_ind < y_ind+y_edge) then
        y_min = y_ind
        y_max = y_ind+(this%NGridPoints-y_ind)
      else
        y_min = y_ind+y_edge
        y_max = y_ind+1
      end if

      if (z_ind < z_ind+z_edge) then
        z_min = z_ind
        z_max = z_ind+(this%NGridPoints-z_ind)
      else
        z_min = z_ind+z_edge
        z_max = z_ind+1
      end if

      !DC DEBUG- message below help with bug hunt in counitng method
      ! write( IOBuffer, '("x",2I3," y",2I3," z",2I3)') x_min, x_max, y_min, y_max, z_min, z_max
      ! call LogWrite

      do i_x = x_min, x_max
        do i_y = y_min, y_max
          do i_z = z_min, z_max
            xyz_ind = 1 + mod(i_x + this%NGridPoints,this%NGridPoints) &
                    &   + mod(i_y + this%NGridPoints,this%NGridPoints) *this%NGridPoints &
                    &   + mod(i_z + this%NGridPoints,this%NGridPoints) *this%NGridPoints*this%NGridPoints
#if MPI_VER > 0
            if (xyz_ind .ge. this%NGridPoints0 .and. xyz_ind .le. this%NGridPoints2) then
              xyz_ind = xyz_ind - this%NGridPoints0 + 1
            else
              cycle
            end if
#endif
            NeighborCounter(xyz_ind) = NeighborCounter(xyz_ind) + 1
          end do
        end do
      end do

    end do
  end subroutine TEnsemble_count_direct_atom3

  subroutine TEnsemble_ClustNeighbors_print(this, ClusterCounter, print_array )
  ! facilitates printing out array information to the file
  ! integrated into parallel version: TEnsemble_ClustNeighbors_gather_print
  ! BEWARE the cc (*.clust) file is used for output
  ! BEWARE is intended as single threaded nonparallel version
    implicit none

    ! Declare arguments
    type(TEnsemble)     :: this
    integer, intent(in) :: ClusterCounter
    ! Declare local variables
    integer             :: i
    integer, intent(in) :: print_array(:)

    !DC NOTE- only root PU output the header
    if( .not. RootProc ) return

    write( IOBuffer, '("# timestep: ", I8, " | edge ", I6, " | MolperCluster", I6, " | Clusters", I6 )' ) Step,  this%NGridPoints, this%Ccount, ClusterCounter
    call FileWrite (this%ccFile)

    do i= 1, this%NGridPointsAll - 1
      write( IOBuffer, '(I4,", ")' ) print_array(i)
      call FileWriteNoAdvance (this%ccFile)
    end do

    write( IOBuffer, '(I4)' )  print_array(this%NGridPointsAll)
    call FileWrite (this%ccFile)

  end subroutine TEnsemble_ClustNeighbors_print

  subroutine TEnsemble_ClustNeighbors_hprint(this, ClusterCounter)
  ! facilitates printing only the header without the neighbor list for methods that do not use neighbor list
  ! NOTE it is overloaded variant with only two parameters
  ! BEWARE the cc (*.clust) file is used for output
  ! BEWARE is intended as single threaded nonparallel version
    implicit none

    ! Include MPI header
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif

    ! Declare arguments
    type(TEnsemble)     :: this
    integer, intent(in) :: ClusterCounter

    !DC NOTE- only root PU output the header
    if( .not. RootProc ) return

    write( IOBuffer, '("# timestep: ", I8, " | edge ", I6, " | MolperCluster", I6, " | Clusters", I6 )' ) Step,  this%NGridPoints, this%Ccount, ClusterCounter
    call FileWrite (this%ccFile)

  end subroutine TEnsemble_ClustNeighbors_hprint

  subroutine TEnsemble_ClustNeighbors_gather_print(this, ClusterCounter, NeighborCounter)
  ! provides the printing out array information to the file
  ! while enveloping the gathering of the neighbour data from other processors
  ! BEWARE the cc (*.clust) file is used for output
  ! BEWARE the size of the grid is not homogeneous accross processors
  !        the last PU has different # of grid points -> gatherv is needed
    implicit none

    ! Include MPI header
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif

    ! Declare arguments
    type(TEnsemble)      :: this
    integer, intent(in)  :: ClusterCounter
    integer, intent(in)  :: NeighborCounter(:)
    ! Declare local variables
    integer              :: stat
    integer              :: i
    integer              :: stride
    integer              :: sendGridpointCount
    integer, allocatable :: GPCounter_all(:)
    integer, allocatable :: GPStrides_all(:)
    integer, allocatable :: NeighborCounter_all(:)

  if (RootProc) then !DC OPTIM- wasting space and allocation on nonroor PU
    allocate(GPCounter_all(NProcs), STAT = stat )
    call AllocationError( stat, 'ccrit GP counts root counter all', Nproc )
    allocate(GPStrides_all(NProcs), STAT = stat )
    call AllocationError( stat, 'ccrit GP strides root counter all', Nproc )
    allocate(NeighborCounter_all(this%NGridPointsAll), STAT = stat )
    call AllocationError( stat, 'ccrit Neighbor root counter all', Nproc )
  else
    allocate(GPCounter_all(1), STAT = stat )
    call AllocationError( stat, 'ccrit GP counts rest counter all', Nproc )
    allocate(GPStrides_all(1), STAT = stat )
    call AllocationError( stat, 'ccrit GP strides rest counter all', Nproc )
    allocate(NeighborCounter_all(1), STAT = stat )
    call AllocationError( stat, 'ccrit Neighbor rest counter all', Nproc )
  end if

#if MPI_VER > 0
  !DC NOTE- gather the allocated grid sizes
  sendGridpointCount = this%NGridPoints1
  if (sendGridpointCount<1) then
    sendGridpointCount = 0
  endif
  call MPI_Gather(sendGridpointCount , 1 , MPI_INT, GPCounter_all,  1, MPI_INT, NRootProc, Communicator, ierror ) ! BEWARE if every processor sends same length

  !DC NOTE- gather the strides for the gatherv call
  if (RootProc) then
    stride = 0
    do i=1,NProcs
      GPStrides_all(i) = stride
      stride = stride + GPCounter_all(i)
    end do
  end if

  !DC HELP- on gatherv:
  !    MPI_GATHERV(SENDBUF         , SENDCOUNT         , SENDTYPE, RECVBUF           , RECVCOUNTS   ,DISPLS        , RECVTYPE, ROOT    , COMM        , IERROR)
  call MPI_Gatherv(NeighborCounter , sendGridpointCount , MPI_INT, NeighborCounter_all, GPCounter_all, GPStrides_all, MPI_INT, NRootProc, Communicator, ierror )

  !DC NOTE- print of the collected information
  if (RootProc) then
    write( IOBuffer, '("# timestep: ", I8, " | edge ", I6, " | MolperCluster", I6, " | Clusters", I6 )' ) Step,  this%NGridPoints, this%Ccount, ClusterCounter
    call FileWrite (this%ccFile)
    do i= 1, this%NGridPointsAll - 1
      write( IOBuffer, '(I4,", ")' ) NeighborCounter_all(i)
      call FileWriteNoAdvance (this%ccFile)
    end do
    write( IOBuffer, '(I4)' )  NeighborCounter_all(this%NGridPointsAll)
    call FileWrite (this%ccFile)
  end if

#else
  !DC NOTE- single thread variant
  write( IOBuffer, '("# timestep: ", I8, " | edge ", I6, " | MolperCluster", I6, " | Clusters", I6 )' ) Step,  this%NGridPoints, this%Ccount, ClusterCounter
  call FileWrite(this%ccFile)
  do i= 1, this%NGridPointsAll - 1
    write( IOBuffer, '(I4,", ")' ) NeighborCounter(i)
    call FileWriteNoAdvance(this%ccFile)
  end do
  write( IOBuffer, '(I4)' )  NeighborCounter(this%NGridPoints1)
  call FileWrite(this%ccFile)

#endif
  end subroutine TEnsemble_ClustNeighbors_gather_print

!==============================================================!
!  Subroutine TEnsemble_ClustCrit                              !
!==============================================================!


  function TEnsemble_ClustCrit_vapgrid( this, DistCrit ) result(ClusterCounter)
  ! this fucntion calculate neighbour entities on the regular grid and check if the grid
  ! points have GRATER (.gt.) tham specified number of elements
  ! -> implementation of the Neighbor counting within grid points
  !   |- the Check distance is given parameter
  !   |- NeighborCounter array is allocated to the size of NGridPoints1
  !   |- expect that the grid distance is known in advance but does not require grid points positions
  !   |- calulate the grid point occupancies
  !   |- accumulate the cluster count suspected grid points
  ! -> print information header and neighbors array into .clust file
  ! -> return the ClusterCounter that represent number of suspected clusters found

    implicit none

  ! Include MPI header
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif
    type(TEnsemble)           :: this
    real(RK)                  :: DistCrit
    ! Declare result
    integer                   :: ClusterCounter
    ! Declare local variables
    integer                   :: stat
    integer, allocatable      :: NeighborCounter_da3(:)
    type(TComponent), pointer :: pcur
    integer                   :: i

    allocate(NeighborCounter_da3(this%NGridPoints1), STAT = stat )
    call AllocationError( stat, 'Neighbor counter allocation in TEnsemble_ClustCrit', Nprocs )

    ClusterCounter = 0

    !DC TODO- calculate components in parallel -based on assumption that components form independent clusters
    pcur => this%Component(1)

    call TEnsemble_count_direct_atom3(this, NeighborCounter_da3, pcur, DistCrit)

    do i = 1,this%NGridPoints1
      !DC NOTE- this is the decision part of the criteria where potential clusters are counted
      if (NeighborCounter_da3(i) .ge. this%Ccount) then
        ClusterCounter = ClusterCounter + 1
      end if
    end do

#if MPI_VER > 0
    call MPI_Allreduce( MPI_IN_PLACE, ClusterCounter, 1, MPI_INTEGER, MPI_SUM, Communicator, ierror )
    call TEnsemble_ClustNeighbors_gather_print(this, ClusterCounter,NeighborCounter_da3)
#else
    call TEnsemble_ClustNeighbors_print(this, ClusterCounter, NeighborCounter_da3)
#endif

  end function TEnsemble_ClustCrit_vapgrid

  function TEnsemble_ClustCrit_liqgrid( this, DistCrit ) result(ClusterCounter)
  ! this fucntion calculate neighbour entities on the regular grid and check if the grid
  ! points have LOWER (.lt.) tham specified number of elements
  ! -> implementation of the Neighbor counting within grid points
  !   |- the Check distance is given parameter
  !   |- NeighborCounter array is allocated to the size of NGridPoints1
  !   |- expect that the grid distance is known in advance but does not require grid points positions
  !   |- calulate the grid point occupancies
  !   |- accumulate the cluster count suspected grid points
  ! -> print information header and neighbors array into .clust file
  ! -> return the ClusterCounter that represent number of suspected clusters found

    implicit none

  ! Include MPI header
#if MPI_VER > 0 && !defined(MPI_USE_MODULE)
    include 'mpif.h'
#endif
    ! Declare arguments
    type(TEnsemble)           :: this
    real(RK)                  :: DistCrit
    ! Declare result
    integer                   :: ClusterCounter
    ! Declare local variables
    integer                   :: stat
    integer, pointer          :: NeighborCounter_da3(:)
    type(TComponent), pointer :: pcur
    integer                   :: i

    allocate(NeighborCounter_da3(this%NGridPoints1), STAT = stat )
    call AllocationError( stat, 'Neighbor counter allocation in TEnsemble_ClustCrit', Nprocs )

    ClusterCounter = 0

    !DC TODO- calculate components in parallel -based on assumption that components form independent clusters
    pcur => this%Component(1)

    call TEnsemble_count_direct_atom3(this, NeighborCounter_da3, pcur, DistCrit)

    do i = 1,this%NGridPoints1
      !DC NOTE- this is the decision part of the criteria where potential clusters are counted
      if (NeighborCounter_da3(i) .le. this%Ccount) then
        ClusterCounter = ClusterCounter + 1
      end if
    end do

#if MPI_VER > 0
    call MPI_Allreduce( MPI_IN_PLACE, ClusterCounter, 1, MPI_INTEGER, MPI_SUM, Communicator, ierror )
    call TEnsemble_ClustNeighbors_gather_print(this, ClusterCounter, NeighborCounter_da3)
#else
    call TEnsemble_ClustNeighbors_print(this, ClusterCounter, NeighborCounter_da3)
#endif

  end function TEnsemble_ClustCrit_liqgrid

  subroutine TEnsemble_ClustCrit( this )
  ! this subroutine calls the cluster criteria variants and terminates the simulation if necesarry
  ! NOTE - this metod is effective only in VisualCCUpdate frequency specified by user
  ! BEWARE - this should not be called during equilibration procedures
  !   - higher level check should be implemented
  ! -> should enable switching for the CC method employed
  ! -> contain exit flag set up for simulation termination

    implicit none

    ! Declare arguments
    type(TEnsemble) :: this
    ! Declare local variables
    real(RK)                  :: DistCrit
    integer                   :: ClusterCounter

    !DC NOTE- skip execution if it is not valid anymore (not valid simulation .or. already stopped due to the error or CC)
    !DC NOTE- this is handled by the TSimulation_RunMDStep to save initialization of functions

    !DC NOTE- skip execution if it is equilibration or not time to update
    !DC NOTE- this is handled by the TEnsemble_RunMDStep to save this function launch

    !DC NOTE- calculate the scaled critical cluster check distance
    DistCrit = this%Ccritdist*(1._RK / this%BoxLength)

    select case( this%Ccrittype )
      case( CCritTypeGridvap )
        ClusterCounter = TEnsemble_ClustCrit_vapgrid(this, DistCrit)
        if (ClusterCounter .gt. this%Cmax) then
          this%isStopSimulation = .true.
          write( IOBuffer, '("!Cluster count limit ", I6, " exceeded with: ", I6, " clusters. ~ ", E10.2, " % of grid")' ) int(this%Cmax), ClusterCounter, (100.0*ClusterCounter)/this%NGridPointsAll
          call FileWrite (this%ccFile)
        end if
      case( CCritTypeGridliq )
        ClusterCounter = TEnsemble_ClustCrit_liqgrid(this, DistCrit)
        if (ClusterCounter .gt. this%Cmax) then
          this%isStopSimulation = .true.
          write( IOBuffer, '("!Void count limit ", I6, " exceeded with: ", I6, " clusters. ~ ", E10.2, " % of grid")' ) int(this%Cmax), ClusterCounter, (100.0*ClusterCounter)/this%NGridPointsAll
          call FileWrite (this%ccFile)
        end if
    end select

    !DC DEBUG- message below for proper multiensemble case stopping validation
    ! write (*, '("Step:",I4,"Ensemble:",I4,"Ncluster:", I4, "isStopSimulation:", L2)') Step, this%EnsembleNumber, ClusterCounter, this%isStopSimulation

    if (this%isStopSimulation .eqv. .true.)  then
      write( IOBuffer, '("!Calculation is stopped by criteria id: ", I2," at ensemble: ", I2)' ) this%Ccrittype, this%EnsembleNumber
      call FileWrite (this%ccFile)
      call LogWriteBlank
      write( IOBuffer, '("Calculation is stopped by criteria id: ", I2," at ensemble: ", I2)' ) this%Ccrittype, this%EnsembleNumber
      call LogWrite

      !DC NOTE- prevent future calculation and update of this simulation and prevent the repeated writing of previous message
      this%isCCSimulation = .false.
    end if

  end subroutine TEnsemble_ClustCrit

!==============================================================!
!  Subroutine TEnsemble_vlecalcsvc
!==============================================================!
! Subroutine for finding the solutions of the nonlinear equations
! describing the chemical potential. This solver combines the fast
! convergence of the Newton-Method and a globally convergend line
! search method.  IN: Initial guess vector. OUT: Initial
! guess vector overwritten with final results; vector f of
! the chemical potential functions.
!==============================================================!

subroutine TEnsemble_vlecalcsvc (x, f, conv, this)

implicit none

type(TEnsemble)        :: this

real(RK), intent(inout) :: x(:)
real(RK), intent(out) :: f(:)
logical, intent(out) :: conv

! Variables for the solver
real(RK), dimension(:,:), allocatable :: J , jac
real(RK), dimension(:), allocatable :: p, c, xneu, g
real(RK), dimension(:), allocatable :: xnewt, fn

integer :: n, i, fehler, errCode

! Stopping and scaling criteria
integer :: itercount, stopcode
real(RK)  :: xtest, ftest, typx

! Solver parameters (fixed)
integer, parameter :: itermax = 1000
real(RK), parameter :: tolf = 1e-8, tolx = 1e-8, alpha = 1.0e-4
real(RK), parameter :: maxlambda = 0.5, minlambda = 0.1

! Solver parameters
real(RK) :: lambda, lambdamin, lambdaprev, lambdaprev2, lambdaprevsq
real(RK) :: fprim, fnewt, fobj, fobj2, lambdanew, lambdaq
real(RK) :: a1,b1,b2,a,b, disc

! Size of the input vector of initial guesses
n = size(x)

! Allocating memory for dynamic array
allocate(J(n,n), jac(n,n), p(n), c(n), xneu(n), g(n), xnewt(n), fn(n))
fehler = 0 !No error calculation
typx = 1 !Scaling value for x

f = TEnsemble_fun( x, fehler, this) !First function evaluation
call TEnsemble_jacobi(x ,f, J, fehler)
jac = J

! Iterations

itercount = 0
lambda = 1  !The first iteration is the basic Newton step (steplength = 1).
stopcode = 0

do while (itercount < itermax .and. stopcode == 0 )

  if (lambda == 1) then

    ! Convergence test / stopping criteria for the basic Newton-Step.

    ftest= dot_product(f,f) !vectors
    xtest = maxval(abs(x-xnewt)/max(abs(x),typx))
    if (xtest < tolx .or. ftest < tolf) then
      stopcode = 2
    end if
    if (stopcode > 0) then
      conv = .true.
      return

    end if

    ! Solving the linear equation p = -J^(-1)*F ---> p = -J \ F
    ! ---> by rewriting the matrix equation : J*p = -F.
    ! J is the Jacobian, F ist the vector of function values, p is the step in descent direction.
    ! Like Matrix equation Ax = c;  c is -F, A is J, and p the searched step.
    c = -f

    ! LU-Decomposition + partial pivoting.

    call TEnsemble_solvelinsys(J, c, errcode) ! in this place J matrix is decomposed into another form (modified values)
    p = c
    ! IN: Jacobian J and right side of the equation -f.
    ! OUT: overwritten c -> step p in descent direction

    ! Line search method
    g = matmul(f,jac) !!gradient g' = F*J, cf. Eq. (3.15) in Saric, Bachelorthesis.
    fprim = dot_product(g,p) ! product g'*p, cf. Eq. (3.14).
    fnewt = dot_product(f,f) ! Minimizing the norm for the Newton step, cf. Eq. (3.13).
    xnewt = x ! x value in Newton direction
    lambdamin = (epsilon(lambda)**(0.6666) )/ maxval( abs(p) / max(abs(xnewt),typx) )
    if (lambdamin > 1e-5) lambdamin = 1e-10 !correcting lambdamin
  endif  !Getting out of the full Newton step

  itercount = itercount + 1
  lambdaprev = lambda !Save previous lambda
  x = xnewt + p*lambda ! New value of x, cf. eq. (3.17) in thesis
  f = TEnsemble_fun(x, fehler, this)
  call TEnsemble_jacobi(x,f,J, fehler) !New Jacobi-Matrix
  jac = J !Save jacobi matrix temporarily
  fobj = dot_product(f , f) !Minimizing the new function

  if (lambda < lambdamin) then
    stopcode = 3
  end if

  if (fobj <= fnewt+alpha*lambda*fprim ) then ! Armijo-Rule, Eq. (3.17) in thesis
    lambda = 1 ! if going in the steepest direction, use lambda = 1 and try the full Newton step again.
  else ! Reduce lambda with quadratic or cubic fit.
    if (lambda == 1) then ! quadratic fit.
      lambdaq = -fprim /2/(fobj-fnewt-fprim)
      lambdanew = lambdaq
    else !cubic fit, see [1].
      a1 = 1 / (lambdaprev - lambdaprev2)
      lambdaprevsq = lambdaprev*lambdaprev
      b1 = (1/lambdaprevsq)*(fobj-fnewt*lambdaprev*fprim)+(-1/lambdaprevsq)*(fobj2-fnewt-lambdaprev2*fprim)
      b2 = (-lambdaprev2/lambdaprevsq)*(fobj-fnewt*lambdaprev*fprim) &
          + (lambdaprev/lambdaprevsq)*(fobj2-fnewt-lambdaprev2*fprim)
      a = a1*b1
      b = a1*b2
      disc = b*b - 3*a*fprim

      if (a == 0) then
        lambdanew = -fprim /2/(fobj-fnewt-fprim) !quadratic fit
      else
        lambdanew = (-b + sqrt(disc)) / (3*a) !cubic fit
      end if

    endif

    if (lambdanew > maxlambda*lambda) then     !if lambdanew > 0.5*lambda, then set to 0.5*lambda
      lambdanew = maxlambda*lambda
    elseif (lambdanew > minlambda*lambda) then !if lambdanew < 0.1*lambda, then set to 0.1*lambda
      lambda = lambdanew
    else
      lambda = minlambda*lambda
    end if

    lambdaprev2 = lambdaprev !Save second previous lambda (for the cubic fit)
    fobj2 = fobj !save minimized function value
  end if

end do
deallocate(J, jac, p, c, xneu, g, xnewt, fn)
end subroutine

!==============================================================!
! Function TEnsemble_fun
!==============================================================!
! The chemical potential function of the liquid and
! vapor phase. Iteration of these functions up to the equality of
! the chemical potential functions in both phases
! yields the final results of the NpT + SVC method.
!==============================================================!

function TEnsemble_fun(x, fehler, this)

implicit none

type(TEnsemble) :: this

real(RK), intent(in) :: x(:) !Initial guess vector
integer, intent(in) :: fehler
real(RK), dimension(size(x)) :: TEnsemble_fun !Output

!Temporary values of x, SVC and dBdT matrix
real(RK), allocatable :: xstart(:)
real(RK) :: X1

! Temporary variables for generating the SVC matrix and equations for the vapor chemical potential
real(RK) :: Bdummy, BmixSVC, dBdTdummy, dBdTmixSVC, ystart
real(RK) :: VapPressSVC, VapDensSVC, t_subs
real(RK), allocatable:: ydummy(:), ymix(:)

! Partial molar volume, liquid chemical potential for p_0
real(RK), allocatable:: ChemPotVapSVC(:),ChemPotLiqSVC(:)

integer :: i, n, nprobe, j, k, s

n = size(x)

t_subs = x(1) ! t for better initial guesses [Bachelorthesis, Saric].

allocate(xstart(n),ymix(n), ydummy(n))
allocate(ChemPotVapSVC(n), ChemPotliqSVC(n)) !

! Generate the initial guess vector using the identity that the sum of mole fractions is == 1.

if (n == 1) then !n = n
  xstart = 1
else
  do i = 1, n
    if (i == n) then
      xstart(n) = 1 -  &
      & sum(xstart(1:(n-1)))
    else
      xstart(i) = x(i+1)
    end if
  end do
end if

! 2. VC of the mixture, eq. (3.2) in thesis.
BmixSVC = 0
dBdTmixSVC = 0
ystart = 0

do i = 1, n
  do j = 1, n
    Bdummy = xstart(i)*xstart(j)*ArrSVC(i*2-1, j*2, EnsembleNum)
    dBdTdummy = xstart(i)*xstart(j)*ArrdBdT(i*2-1, j*2, EnsembleNum)
    BmixSVC = Bdummy + BmixSVC
    dBdTmixSVC = dBdTdummy + dBdTmixSVC
    ydummy(j) = xstart(j)* ArrSVC(i*2-1, j*2, EnsembleNum)
    ystart = ystart + ydummy(j)
  end do
  ymix(i) = ystart !y_mix = y1B11 + 2y1y2B12 + y2B22... (for binary mixtures)
  ystart = 0
end do

if (fehler == 1) then !for error calculation,
  VapPressSVC = x(1)
  VapDensSVC = (SQRT((4*BmixSVC*VapPressSVC/StartTemperature)+1) - 1) / (2*BmixSVC) !thesis, Eq. (2.17)
  else !icalculations with x(1), see thesis Eq. (3.21) and (3.22).
  VapPressSVC = (StartTemperature*(t_subs-1)) / (4*BmixSVC)
  VapDensSVC =  (SQRT(t_subs) - 1) / (2*BmixSVC)
end if

! Chemical potential on the liquid side, see thesis Eq. (3.1).
do i = 1, n
  ChemPotLiqSVC(i) = ArrChemPot(i) + (ArrPartMolVol(i) /  StartTemperature) * (VapPressSVC - StartPressure)
end do

! Chemical potential on the vapor side, see thesis Eq. (3.2).
do i = 1, n
  ChemPotVapSVC(i) =  log(xstart(i)) + log(VapDensSVC) + 2*VapDensSVC*ymix(i)
end do

TEnsemble_fun(:) = 0d0 ! Allocate zeroes
do i = 1, n
  TEnsemble_fun(i) = ChemPotLiqSVC(i) - ChemPotVapSVC(i)
  ! In the VLE, fun(i) goes to zero.
end do

! Saving mixture SVC and dBdT at the VLE
 do i = 1 , n
   if (abs(TEnsemble_fun(i)) < 1e-4) then
   BmixSVCtemp = BMixSVC
   dBdTmixtemp = dBdTmixSVC
   end if
 end do

 deallocate(xstart,ymix, ydummy)
 deallocate(ChemPotVapSVC, ChemPotliqSVC)

end function TEnsemble_fun

subroutine TEnsemble_jacobi(x,f, df, fehler)

!==============================================================!
!  Subroutine TEnsemble_jacobi
!==============================================================!
!  Calculating the Jacobi matrix of functions
!  using the central difference approximation.
!==============================================================!

implicit none

type(TEnsemble) :: this


! Input, output
real(RK), intent(inout) :: x(:)
real(RK), intent(out) :: f(:)
real(RK), intent(out) :: df(: , :)
integer, intent(in) :: fehler

real(RK) :: stepsizej, tempj
real(RK), DIMENSION(size(x)) :: df_p,df_m
integer :: j, s, k, n

n=size(x)
f = TEnsemble_fun(x, fehler, this)
stepsizej = epsilon(x)**(0.6666) !stepsize h

do j=1, n
  tempj = x(j) !start with x
  x(j) = x(j) + stepsizej !x+h
  stepsizej = x(j) - tempj
  df_p(:) = TEnsemble_fun(x, fehler, this)  !fun(x+h)
  x(j) = tempj - stepsizej !x-h
  df_m(:) = TEnsemble_fun(x, fehler, this)  !fun(x-h)
  df(:,j) = (df_p-df_m)/ (2*stepsizej)
  x(j)=tempj !get back to x
end do

end subroutine

!==============================================================!
! TEnsemble_solvelinsys
!==============================================================!
! Solves the linear system of equations Ax = b through
! LU-Decomposition with partial pivoting.
! b is the input (right side of the Ax = b),
! but also the output of this subroutine overwritten by x.
! Pivot is the index of the changing rows!
!==============================================================

subroutine TEnsemble_solvelinsys(a, b, errCode)

implicit none

type(TEnsemble) :: this

real(RK),intent(inout),dimension(:,:) :: a ! matrix
real(RK),intent(inout),dimension(:) :: b !solution vector
real(RK):: t_s

integer,dimension(:), allocatable :: pivot
integer,intent(out):: errCode ! =0 OK; =1 singular
integer:: j,k,m,i
integer,dimension(1) :: kmax ! location of the max value
integer:: n

errCode=0
n=size(a,1)
allocate(pivot(n))

if (n <= 1) then
  if (a(1,1) == 0.0) then
    errCode=1
  end if
  return ! singular matrix
end if

do k=1,n-1 ! LU Decomposition with pivoting
  kmax= maxloc(abs(a(k:n,k)))   ! pivot row
  m=k-1+kmax(1)

  pivot(k)=m
  if (m /= k) pivot(n)=-pivot(n)

  ! Changing the position of pivot
  t_s=a(m,k)
  a(m,k)=a(k,k)
  a(k,k)=t_s
  if (a(k,k) == 0.0) a(k,k) = 1.0e-10 !to avoid singularity
  if (t_s /= 0.0) then
    t_s=1.0/t_s
    a(k+1:n,k)=-t_s*a(k+1:n,k)
    do j=k+1,n   ! form the A = LU matrix
      t_s=a(m,j)
      a(m,j)=a(k,j)
      a(k,j)=t_s
      if (t_s /= 0.0) a(k+1:n,j) =a (k+1:n,j) + t_s*a(k+1:n,k)
    end do
  end if
end do

!Forward elimination Ly = b
n=size(a,1)
do k=1,n-1
  m=pivot(k)
  t_s=b(m)
  b(m)=b(k)
  b(k)=t_s
  b(k+1:n)=b(k+1:n) + t_s*a(k+1:n,k)
end do

!Backward substitution Ux = y
do k=n,1,-1
  b(k)=b(k)/a(k,k)
  t_s=-b(k)
  do i=1,k-1
    b(i)=b(i)+a(i,k)*t_s
  end do
end do

end subroutine TEnsemble_solvelinsys

subroutine TEnsemble_infnan(f, flag)

!==============================================================!
! TEnsemble_infnan
!==============================================================!
! Check if the value of solution vector is equal NaN or Inf.
! If false, the range of validity of the NpT + SVC method
! was left by the solver.
!==============================================================!

implicit none
real(RK), intent(in) :: f
logical, intent(out) :: flag
real(RK) :: inf
flag = .true.
inf = huge(f)
if (f > inf .or. f /= f) then
flag = .false.
end if
end subroutine  TEnsemble_infnan


end module ms2_ensemble
